window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["ca-ES"]={"ICON-0001":{"nm":"Petjada","de":"Una petjada terrosa que ha quedat al terra de fusta. Algú va fer voltes una bona estona i, finalment, va fer un pas més. Una petjada no marca el temps que s'hi ha quedat, sinó l'instant precís en què algú va decidir marxar."},"ICON-0002":{"nm":"Fanal","de":"Quan la flama toca el ble, la foscor retrocedeix en silenci, pam a pam. Amb la petita escalfor que abriga la punta dels dits, la gent d'abans hi escrivia desitjos i els deixava anar a la deriva. Un fanal no s'encén per fer llum, sinó per fer-te companyia."},"ICON-0003":{"nm":"Llaç","de":"Amb un sol nus, el cor queda embolicat amb delicadesa. Fàcil de desfer per a la mà que el dona, però lent de desnuar per a la mà que el rep. El que un llaç lliga no és la caixa, sinó el batec nerviós de just abans de donar-la."},"ICON-0004":{"nm":"Bústia","de":"Es planta a la boca del carreró amb la seva boca vermella ben oberta. Fins i tot en una època en què les cartes escrites a mà s'han tornat rares, aquesta capsa petita espera fins al final les notícies d'algú. Un recipient entranyable que brilla més justament quan queda buit."},"ICON-0005":{"nm":"Minimapa de l'illa privada","de":"Un sol full de paper: cap dins la butxaca quan es plega, mar i carena esteses una al costat de l'altra quan es desplega. Per a qui hi arriba per primer cop, cada racó és una promesa encara sense obrir. En el moment en què es desplega, fins i tot una illa petita esdevé un món immens."},"ICON-0006":{"nm":"Micròfon","de":"Aquell mig batec en què retens l'alè just abans de la primera nota. Saber que els ulls del públic esperen la teva primera paraula fa tremolar les puntes dels dits. Un micròfon no amplifica el so: acompanya aquell tremolor fins al final."},"ICON-0007":{"nm":"Rellotge","de":"La busca dels segons no descansa mai, però ningú no t'apressa. Tantes nits fins al debut, tants minuts fins a l'escenari—sobre l'esfera, l'espera i l'emoció giren a la mateixa velocitat. Mirar l'hora és, en el fons, calmar el cor."},"ICON-0008":{"nm":"Llibreta","de":"L'objecte amb més espai en blanc de tots. Els passos de coreografia, els propòsits de matinada, les paraules que mai es van arribar a enviar—tot s'hi acumula. En el moment d'obrir-la, el jo d'ahir parla, en veu baixa, al jo d'avui."},"ICON-0009":{"nm":"Segell","de":"Xopat en tinta vermella i premut amb fermesa, una promesa queda gravada amb claredat. Una marca més feixuga que l'escriptura, més clara que les paraules. Al final de cada document, la gent hi confiava el cor, en lloc del nom, a aquest petit segell."},"ICON-0010":{"nm":"Suport","de":"S'abaixa tant com pot per sostenir una altra cosa. Al fons de tot, aguantant el pes en silenci perquè allò que hi reposa a sobre no vacil·li. Encara que no llueixi, aquí hi ha la tendresa que evita que tot s'ensorri."},"ICON-0011":{"nm":"Segell postal","de":"Un petit dibuix al qual llepaves una cantonada i el premies fort. El preu més honest que es posa a un cor enviat lluny. Un sol quadrat de paisatge agafa la mà de la carta i la porta a l'altra banda del mar."},"ICON-0012":{"nm":"Xinxeta de bandera","de":"Clavada al mapa, diu \"he arribat fins aquí\". No és una conquesta, sinó un registre, i un ànim per a qui vindrà després. Un senyal que empeny l'esquena sense paraules: en veure aquesta bandera, només un pas més."},"ICON-0013":{"nm":"Branca","de":"Una branca que ja s'ha doblegat un cop oblida com es trenca. A cada indret on es va corbar davant el vent, hi arrela un nus ferm i dur, i la força veritable ve de les marques d'haver resistit—així t'ho conta el vell bosc al vent."},"ICON-0014":{"nm":"Botó","de":"Desfermat i cordat una vegada i una altra, tanca el coll de la roba. Un petit cercle atura, en silenci, tant el fred de la matinada com una vergonya sobtada. Només quan cau, un dia, adones com era de gran el seu lloc."},"ICON-0015":{"nm":"Sobre","de":"En el moment que se'n sella la boca, esdevé per fi un secret. Només qui el rep sap què s'hi amaga a dins. Una sola capa de paper posada entre el cor i el món—la porta més fina i més tendra de totes."},"ICON-0016":{"nm":"Caixa","de":"Té els quatre cantons ben quadrats, per això acull qualsevol cosa amb generositat. Records en temporada de mudança, regals per festes, andròmines la resta de l'any. A dins la tapa tancada, sempre hi ha ple el \"més endavant\" de qualcú."},"ICON-0017":{"nm":"Nansa","de":"Entre una porta i una persona, és el primer a estendre la mà. Només quan s'estira un cop, dins i fora queden per fi connectats. Cada decisió d'entrar o sortir passa un instant per aquesta mà freda."},"ICON-0018":{"nm":"Cullera","de":"Amb la seva boca còncava, alça amb calma el brou calent. Una eina que recorda l'escalfor de la primera cullerada que la mare bufava per refredar i oferia primer. A taula, és la mà més afable, la que toca els llavis més sovint."},"ICON-0019":{"nm":"Xancletes de casa","de":"En el moment de creuar el llindar, els peus són els primers a alenar. El so del vespre, un caminar suau just després de despullar-se d'un dia de passos secs. Un parell ben endreçat a l'entrada et diu: \"ja ets a casa\"."},"ICON-0020":{"nm":"Clau","de":"S'aprèn abans a obrir que no pas a tancar. Un petit tros de metall que s'escalfa dins la palma i que, un dia, s'atura en silenci davant d'una porta nova i desconeguda. L'objecte que guarda més temps l'escalfor de qui se'n va."},"ICON-0021":{"nm":"Copa","de":"Discreta quan és buida, càlida com res quan és plena. En el so clar de dues copes que es toquen cara a cara, hi queda una promesa sense paraules. Un recipient nascut per brillar amb dos, més que no pas sol."},"ICON-0022":{"nm":"Plat","de":"Dins la seva vora rodona s'hi aboca tota la cura d'un dia. Buidat, eixugat i tornat a omplir tota una vida—el més sovint lluent i el més sovint oblidat dels estris de casa. L'escenari de la taula es para sempre a sobre seu."},"ICON-0023":{"nm":"Llum","de":"Amb un sol interruptor, l'expressió de l'habitació canvia. Si és intensa, és la vida quotidiana; si és suau, és el consol. Un punt de llum deixat encès fins al final per algú que arriba tard esdevé la benvinguda més càlida del món."},"ICON-0024":{"nm":"Cullereta de te","de":"Fes-la voltar a poc a poc per sobre de l'infusió i les fulles i l'aigua s'amaren l'una de l'altra. Un gest sense pressa, una petita espera fins que l'aroma s'escampa. Una mà platejada alenteix, amb tendresa, el ritme de la tarda."},"ICON-0025":{"nm":"Punt de llibre","de":"Una promesa que es deixa, en silenci, al lloc on la lectura es va aturar. El propòsit de \"m'he aturat aquí, així que tornaré segur\" s'adorm entre les pàgines. La història es pot tancar, però el cor queda marcat amb claredat en aquella línia."},"ICON-0026":{"nm":"Coixí","de":"Rep, sense dir res, l'esquena i els genolls que necessiten on recolzar-se. S'enfonsa profund i després s'infla a poc a poc, absorbint el cansament del dia. L'objecte que permet, amb la generositat més gran, la postura més mandrosa."},"ICON-0027":{"nm":"Marc","de":"Una vora quadrada lliga un paisatge a l'eternitat. Just per aquell instant que va capturar, el temps no s'esvaeix per molt que passi. Una elecció entranyable, menys sobre què contenir que sobre què es va decidir conservar."},"ICON-0028":{"nm":"Mapa","de":"A cada plec hi ha impresa l'empremta d'haver-se perdut i haver tornat a trobar el camí. Desplegat, permet caminar amb els dits fins i tot llocs mai visitats. Tota aventura comença amb el petit coratge de desplegar aquest sol full."},"ICON-0029":{"nm":"Postal","de":"Mig revers és una foto, mig és en blanc. Qui ha marxat lluny envia \"estic bé\" en poques paraules, acompanyades del paisatge d'aquell lloc. El full de paper més honest, on les notícies no necessiten sobre per no sentir-se avergonyides."},"ICON-0030":{"nm":"Targeta d'accés","de":"En el moment de penjar-te'l al coll, entres per fi al món de dins. El teu nom, escrit en aquesta petita targeta, t'atorga en silenci: \"aquí, aquest és el teu lloc\". No és un requisit per passar, sinó la prova que pertanys a algun lloc."},"ICON-0031":{"nm":"Lletra B","de":"La lletra que se sol·licita més sovint al mig d'una paraula. Cal tancar els llavis un instant i deixar-los esclatar perquè en surti el so. Ni principi ni final, però un segon lloc de confiança que marca el ritme."},"ICON-0032":{"nm":"Targeta de visita","de":"Es dona amb totes dues mans i es rep mirant als ulls. El dia i l'orgull d'una persona queden comprimits, en silenci, en un sol full de paper. En el marge estret entre el nom i el càrrec, la primera impressió d'aquell dia s'hi instal·la amb suavitat."},"ICON-0033":{"nm":"Coberta","de":"A la part més exterior de la història, és la primera a rebre el vent i la pluja. Protegint les lletres de dins, es desgasta pels seus propis cantons. El breu batec d'emoció just abans d'obrir sempre comença amb aquest full."},"ICON-0034":{"nm":"Llibre de text","de":"L'esforç d'una persona hi queda escrit, dens, amb subratllats i retolador fluorescent. Desconcertant quan és nou, esdevé l'amic més fiable quan s'ha acabat. Les traces d'haver après allò que abans no se sabia queden plegades amb cura a cada pàgina."},"ICON-0035":{"nm":"Passi de ball","de":"Aquest sol full obre de bat a bat la porta de la sala d'assaig. Una habitació plena de miralls, el so dels peus picant a terra, els primers vuit temps que mai s'han après. No passa res si el ball encara és maldestre—un petit full de paper empeny amb suavitat una esquena que tremola."},"ICON-0036":{"nm":"Carpeta de documents","de":"Fulls solts que anaven a la deriva queden ben enfilats en un sol llom i, per fi, hi trobem un ordre. Amb l'ordre arriba una història, i com més gruixuda es fa, més tendra és la prova que algú ha viscut tant, pàgina a pàgina."},"ICON-0037":{"nm":"Full d'examen","de":"Les puntes dels dits tremolen un instant sobre les línies en blanc. Més por que una resposta equivocada fa afrontar de cara allò que no se sap. Un cop acabada la correcció, a cada error hi queda, en silenci, un marge per créixer la propera vegada."},"ICON-0038":{"nm":"Lletra A","de":"El primer so que només surt quan obres ben la boca. Sovint es col·loca al capdavant d'una línia, al mateix inici d'un nom. Sempre que es comença alguna cosa, es comença per aquesta lletra—per això és sempre una mica més valenta."},"ICON-0039":{"nm":"Lletra D","de":"Amb l'esquena suaument corbada, sosté una paraula amb delicadesa. El seu costat rodó penja amb pulcritud al final del nom d'algú. No és vistosa, però es troba a faltar quan no hi és—una companya silenciosa entre les lletres."},"ICON-0040":{"nm":"Full de pràctiques","de":"L'únic paper del món on està bé equivocar-se. Deixa escriure el mateix moviment, la mateixa frase, desenes de vegades. Per cada full arrugat i llençat, algú, sens dubte, anava una mica millor."},"ICON-0041":{"nm":"Full de composició","de":"Les dues de la matinada, i un simple taral·leig et desperta del son. El llapis vacil·la sobre el pentagrama perquè la melodia va més ràpida que la mà. A cada marca esborrada i tornada a escriure, una cançó encara sense nom va creixent a poc a poc."},"ICON-0042":{"nm":"Passi d'accés","de":"En el moment de penjar-te'l al coll, un passadís qualsevol es transforma en un altre món. Els cables serpentegen per la foscor com si fossin serps, i més enllà de l'escenari comença un compte enrere que ningú no sent. El dret a entrar aquí, aquest sol full el parla en nom teu."},"ICON-0043":{"nm":"Full de contactes","de":"A cada petit requadre hi queda aturada una expressió diferent. Rient, girant-se, amb els ulls tancats. Assenyala una foto rere l'altra i el batec de l'obturador d'aquell dia torna a les puntes dels dits. Fins i tot triar una sola imatge ja és, en si mateix, un registre."},"ICON-0044":{"nm":"Full de rodatge","de":"Demà, a quina hora, on i què. Un sol full dibuixa per endavant tot el recorregut d'un dia. Entre les caselles atapeïdes minut a minut, algú segueix l'ordre escrit aquí, caminant pas a pas cap a un somni."},"ICON-0045":{"nm":"Etiqueta","de":"Darrere el preu hi penja, en silenci, el temps de qui l'ha fet. Només amb aquell breu gest de tallar-la, el petit paper esdevé, per fi, teu. El que resta al tall és l'olor de nou i un grapat d'il·lusió."},"ICON-0046":{"nm":"Portafolis","de":"Gira la coberta i tot el camí recorregut s'obre de cop. Al costat d'un full de què n'estàs orgullós, un primer intent maldestre hi seu, tímid. Quan et presentes per primer cop a algú, no hi ha presentació més honesta que aquesta."},"ICON-0047":{"nm":"Agenda","de":"Escrius avui, dibuixes la setmana que ve, i de tant en tant enfosqueixes una casella. Encara que res no surti com estava previst, la mà que omple les caselles no s'atura mai. Una mena de petit ritual per viure el futur una vegada per endavant."},"ICON-0048":{"nm":"Llista de reproducció","de":"Entre cançons lentes i ritmes ràpids, s'hi alineen les cançons segons el temps del cor d'aquell dia. Si penses que el dia d'algú flueix exactament en aquest ordre, fins i tot el silenci entre cançons es torna tendre."},"ICON-0049":{"nm":"Carnet d'estudiant","de":"Un nom, una foto i uns quants números. Una sola targeta que dona fe dels temps d'anar i venir entre l'aula i la sala d'assaig. En la targeta gastada pels cantons d'entrar i sortir de la butxaca, hi queda gravat un dia a dia fresc que ja no tornarà."},"ICON-0050":{"nm":"Polsera","de":"Recordes el moment de lligar-te el color d'aquell dia al canell? El crit compartit, la nit de concert que us va amarar junts. Encara que la cinta es desgasti i el color es descolori, no la deslligues—vols que aquell estiu continuï vivint al teu canell."},"ICON-0051":{"nm":"Braçalet de comandament","de":"En el moment d'enrotllar-te'l al braç, el pes anomenat responsabilitat s'hi afegeix amb discreció. La marca de qui es posa al capdavant de la fila i és el darrer a abandonar el seu lloc. Un simple tros de roba fa créixer algú un pam més."},"ICON-0052":{"nm":"Anell","de":"Una sola línia que forma un cercle sense cap tall. Perquè el principi i el final es toquen, la gent hi veu la forma de l'eternitat. Uneix dues mans amb calma i, abans que les paraules, una promesa hi queda com a forma."},"ICON-0053":{"nm":"Medalla","de":"Al petit tros de metall clavat al pit hi ha gravats els dies resistits. El que brilla no és el metall, sinó les incomptables nits d'assaig amagades darrere. El que puja abans que l'orgull és, d'alguna manera, la gratitud."},"ICON-0054":{"nm":"Davantal","de":"Lligues les cintes al coll i les dues mans queden lliures. Un senyal que estàs a punt de submergir-te de cap en alguna cosa—sigui farina o pintura. Com més taques s'hi acumulen una a una, més intensa es torna la cura abocada aquell dia."},"ICON-0055":{"nm":"Escalfaorelles","de":"Embolica bé les orelles i els sorolls de fora s'allunyen un pas. En el camí a l'escola amb un vent que talla, un petit refugi on amagar-se a l'interior tou. L'escalfor de l'hivern, de vegades, comença així, per la punta de les orelles."},"ICON-0056":{"nm":"Vestuari","de":"Abans que s'aixequi el teló, un vestit penja de la percha, contenint l'alè. A cada costura hi ha plegada una coreografia. En el moment que un braç s'hi enfila, la persona esdevé personatge, i l'escenari, la segona pell del vestit."},"ICON-0057":{"nm":"Corona","de":"En el moment de posar-se-la al cap, una esquena corbada s'endreça tota sola. El seu resplendor daurat murmura, abans que poder, responsabilitat. El pes fresc que toca el front ho diu tot: com més brillant és el lloc, més feixuc és."},"ICON-0058":{"nm":"Capa","de":"Posa-te-la a les espatlles i el vent hi oneja darrere. Aquella sensació d'un tros de tela que et segueix a cada cursa. Menys un emblema d'heroi que el cor d'un infant que només volia semblar guai."},"ICON-0059":{"nm":"Careta","de":"Cobreix la cara i, curiosament, et tornes més sincer. Com els vells jocs de pati on es reia i es plorava lliurement darrere la careta. Més enllà de l'expressió amagada, la veu de debò, la que solem empassar-nos, s'escapa encara més forta."},"ICON-0060":{"nm":"Pintallavis","de":"Gira el tap, traça un cop, i als llavis s'hi assenta una petita decisió. L'última revisió davant el mirall, una línia vermella pintada sobre la vacil·lació. En aquell breu instant en què el color s'hi aplica, la por s'aparta en silenci."},"ICON-0061":{"nm":"Jaqueta","de":"Quan la línia de les espatlles encaixa a la perfecció, la persona es torna una mica més ferma. Arremanga't i és un cor que treballa; alça't el coll i és un cor a punt de sortir. Un sol vestit fixa, en silenci, l'actitud de tot el dia."},"ICON-0062":{"nm":"Cinturó de taekwondo","de":"Cada vegada que el color puja un graó, també canvia la quantitat de suor acumulada a sota. El matí al dojang de cordar el nus fort i fer la reverència. Amb les puntes dels dits que lliguen el cinturó, l'esperit dispers es torna a reunir."},"ICON-0063":{"nm":"Ulleres protectores","de":"Posa-te-les i el món s'aclareix un to. Més enllà de l'escut rodó que bloqueja tant el vent com la pols, fins i tot el camí de sempre lluu, per algun motiu, com una línia de sortida."},"ICON-0064":{"nm":"Guant","de":"Posa-te'l a la mà i broll el coratge de subjectar qualsevol cosa amb fermesa. Els dits que s'arronsaven, temorosos de deixar caure coses, s'obren per fi de bat a bat. El que protegeix és la mà, però el que de debò es guarda és el repte que vindrà després."},"ICON-0065":{"nm":"Mascareta","de":"Cobreix la part inferior de la cara i els ulls parlen encara més. Al carrer ple de gent, una petita llibertat d'anonimat que es gaudeix darrere una lleugera coberta. Per això, el somriure que hi queda quan tot es treu s'escampa encara més lluminós."},"ICON-0066":{"nm":"Barret","de":"Ajup lleugerament la visera i tant el sol com les mirades s'esquiven un pam. Sota el petit teulat posat al cap, avui almenys es pot caminar amb una expressió tranquil·la. La transformació més lleugera sempre comença aquí."},"ICON-0067":{"nm":"Camisa","de":"Un cruixit, i el coll acabat de planxar fa olor de matí. Mentre es corden els botons en ordre des de dalt, un cor arrugat també s'endreça un punt cada vegada. Un sol full blanc obre la primera frase del dia."},"ICON-0068":{"nm":"Fulard","de":"Enrotlla'l un cop al coll i el pas del vent queda tallat. Mentre els extrems onegen a l'espatlla, el fred ja no arriba fins a dins. Un tros de tela situat en algun punt entre l'estil i l'escalfor."},"ICON-0069":{"nm":"Guants","de":"Embolicats fins a la punta dels dits, ni el fred fa por. El petit luxe de l'hivern, quan les mans que abans es bufaven es tornen còmodes en silenci. Un guant tret i donat pot escalfar també la mà d'algú altre."},"ICON-0070":{"nm":"Placa d'identificació","de":"Dues plaques primes es miren cara a cara en silenci. Tres síl·labes d'un nom i uns quants números—això és el que manté algú recordat fins al final. Metall fred, però que, curiosament, s'assembla a la promesa més càlida."},"ICON-0071":{"nm":"Anella de subjecció","de":"Passa-hi un dit i la por de deixar-lo caure s'esvaeix a poc a poc. Una petita tranquil·litat, prou perquè es pugui aguantar i agitar amb una sola mà. Quan estires el braç ben lluny per deixar una foto de record, sosté la palma en silenci."},"ICON-0072":{"nm":"Corona de flors","de":"Posa-te-la al cap i tota una braçada de primavera et segueix. Flors collides al camp i entrellaçades en cercle envolten el front amb suavitat. Damunt el somriure lluminós de la foto, hi resta llarg temps una lleu olor d'herba."},"ICON-0073":{"nm":"Antifaç","de":"Cobreix els ulls i llum i soroll s'allunyen alhora. Sense veure-hi, l'única cosa que se sent és la pròpia respiració. Apaga per un moment el món i entra en la quietud de dins, i darrere teu una petita porta es tanca amb suavitat."},"ICON-0074":{"nm":"Bufanda","de":"Una volta, dues voltes—cada tomb al voltant del coll suavitza l'hivern una mica. En algun punt entre la llana, potser, hi ha barrejat el cor que algú hi va teixir. Enfonsa-t'hi fins al nas i el món es torna molt més acollidor."},"ICON-0075":{"nm":"Careta de mitja lluna","de":"Cobrint només mig rostre, comença la nit del ball de màscares. Els llavis al descobert somriuen, els ulls amagats guarden un secret. Aquell estret marge d'un gairebé-saber-qui fa esgarrifar l'aire de mitjanit."},"ICON-0076":{"nm":"Boina","de":"Posa-la de biaix i un dia qualsevol guanya, amb discreció, un toc d'encant. Un sol tros de tela rodó i pla vesteix les espatlles, amb suavitat, d'un aire d'artista. Fins i tot aquell instant breu de triar l'angle davant el mirall és un plaer."},"ICON-0077":{"nm":"Gargantilla","de":"Cenyeix-la just al coll i les mirades s'hi apleguen cap amunt de manera natural. Una simple cinta prima canvia tot l'ambient. Petita però clara, com un fermall que omple la confiança d'avui."},"ICON-0078":{"nm":"Anorac","de":"Puja la cremallera fins dalt de tot i fins i tot la tempesta de neu retrocedeix un pas. Fica les mans ben endins de l'interior gruixut i tot l'aldarull del món s'apaivaga. Una petita casa que roman càlida fins al final, fins i tot enmig del vent més aspre."},"ICON-0079":{"nm":"Pantalons","de":"Fica-hi els peus, corda't la cintura, i per fi estàs a punt per sortir. A cada pas, la tela es mou amb suavitat seguint el seu propi teixit. Entre la comoditat i la pulcritud, en algun punt del mig, comença el dia."},"ICON-0080":{"nm":"Pírcing","de":"Fins i tot afegir un sol punt petit demana una mica de coratge. Un sol reflex de metall marca un punt final ben clar en una orella qualsevol. Molt petit, però una llum que reflecteix un jo d'avui que sens dubte ha canviat."},"ICON-0081":{"nm":"Forma d'ona","de":"Per a un enginyer, una cançó no se sent, es veu. Des de la carena que puja i baixa a la pantalla, hi llegeix on va tremolar l'alè aquell dia. Una veu abans invisible s'estén com una serralada, desplegant el relleu d'una sola peça."},"ICON-0082":{"nm":"Afinador","de":"Just abans del concert, acaricies les sis cordes una a una i assentes al seu lloc les notes desafinades. Amb només mig grau de desviació, el públic ho detecta com si fossin fantasmes. Afinar-ho amb tanta precisió que ningú no ho pugui notar—això és una tendresa cap a l'escenari."},"ICON-0083":{"nm":"Corretja","de":"Enrotlla-la un cop al canell i la por de deixar caure les coses es desfà. El més temut a dalt de l'escenari és perdre alguna cosa de la mà, i per això, amb aquesta petita corretja, el cor per fi es tranquil·litza."},"ICON-0084":{"nm":"Plat de bateria","de":"En l'instant d'un sol xoc, un punt final clar es marca a l'última frase de la cançó. El disc daurat sap ressonar el temps més curt i deixar el ressò més llarg. Un final ha de tancar-se així, ben lluminós."},"ICON-0085":{"nm":"Guitarra","de":"Quan els dits llisquen sobre les sis cordes, una habitació petita es converteix del tot en escenari. La primera melodia d'algú, els monòlegs d'una matinada sense son—tot va agafar el primer alè dins aquest cos rodó de fusta."},"ICON-0086":{"nm":"Núvol de so","de":"A un costat del cel, les notes s'apleguen com cotó i suren a la deriva. Diuen que quan el vent hi passa un cop, en lloc de gotes de pluja en cauen melodies, i els infants de l'illa surten a rebre'l sense ni tan sols un paraigua."},"ICON-0087":{"nm":"Pas","de":"El recorregut de l'escenari és una aritmètica que es resol amb la punta dels peus. Un pas aquí, mig temps allà—no passa res si t'equivoques, així que a poc a poc. Les caselles trepitjades centenars de vegades i gravades al cos s'ajunten per completar, per fi, el mapa d'una cançó."},"ICON-0088":{"nm":"Amplificador","de":"Una caixa que converteix un xiuxiueig en un clam. Tot i així, abans de pujar el volum un sol punt, la mà sempre s'atura. Que un so més precís, no pas més fort, arribi fins a l'última fila, això ho sap aquesta caixa."},"ICON-0089":{"nm":"Cotó de notes","de":"Quan els caps rodons de les notes s'apleguen en una bola de cotó, queda tan tou com un coixí. Diuen que si hi recolzes el cap i t'hi ajeus en silenci, en surt una cançó de bressol a penes audible—el rumor més tendre de l'illa."},"ICON-0090":{"nm":"Cassette","de":"Prem el botó de rebobinar i, amb un cruixit, la cinta torna a poc a poc a la primera cançó d'aquell estiu. Dins la petita caixa on hi ha enrotllada tota una època, hi dorm intacte un temps que ja no es pot tornar a tocar."},"ICON-0091":{"nm":"Diapasó","de":"Colpeja lleugerament les dues puntes de metall i, a l'aire, neix una nota de referència. Davant aquest petit tremolor, tots els instruments inclinen el cap en silenci per afinar-s'hi. El principi de qualsevol cosa ve d'una vibració tan tènue com aquesta."},"ICON-0092":{"nm":"Xip d'ona sonora","de":"Un fragment de so queda tancat amb suavitat dins un xip de la mida d'una ungla. Una exclamació mai gravada expressament, la rialla d'algú que es creia perduda—aquí dins encara viu i respira, càlida com sempre."},"ICON-0093":{"nm":"Vinil","de":"Quan l'agulla fa el primer pas seguint el solc, primer se sent un lleuger crepitar. Estimant fins i tot aquell petit soroll, hi ha qui no pot deixar mai anar del tot aquest disc negre."},"ICON-0094":{"nm":"Butxaca","de":"El que més s'estima, sempre es guarda al lloc més proper al pit. Una petita bossa de tela de la mida d'una palma esdevé, un dia, escalfamans; un altre dia, amulet; i encara un altre, guardià de secrets."},"ICON-0095":{"nm":"Tireta","de":"En les nits en què l'assaig s'allarga, a cada taló s'hi enganxa una petita medalla. Una tireta posada per empassar-se la paraula \"fa mal\"—una promesa silenciosa que ningú coneix, de ballar demà igualment, passi el que passi."},"ICON-0096":{"nm":"Coixí","de":"El lloc on finalment es deixa anar tot l'escenari d'un dia sencer és, al capdavall, aquest tros tou i quadrat. Recolza-hi el cap amb calma i els aplaudiments que restaven a l'oïda s'esvaeixen a poc a poc, i finalment la nit també cau sobre l'illa."},"ICON-0097":{"nm":"Timbre","de":"Dring, un so breu, i algú empeny la porta i entra. Un senyal que ha arribat un client, una salutació que el dia ha començat. Un petit tros de metall passa tot el dia dedicat, només, a sonar de benvinguda."},"ICON-0098":{"nm":"Estoig","de":"Com més preuada és una cosa, més se li construeix una casa sòlida a part. Les mans que l'obren i el tanquen es tornen curoses cada vegada, perquè el que hi ha a dins no és simplement un objecte, sinó un cor que no es vol perdre."},"ICON-0099":{"nm":"Raspall","de":"Passa'l seguint el sentit del pèl fins a l'última cerra i la pols enganxada als racons es retira amb discreció. Gràcies a un gest que no defuig ni els llocs invisibles, l'habitació rep cada dia un matí nou."},"ICON-0100":{"nm":"Esbós","de":"Les línies d'abans d'estar acabades no s'esforcen a amagar la vacil·lació. A cada marca esborrada i tornada a traçar, hi queda, sense mentida, allò que volia arribar a ser. Com més maldestre és el començament, més sincer és."},"ICON-0101":{"nm":"Nina","de":"Hi ha éssers que reconforten només per ser abraçats, sense dir cap paraula. L'amic de cotó que tremolava vora el coixí les nits en què les mans et tremolaven rere l'escenari—tothom en guarda un semblant en algun racó del cor."},"ICON-0102":{"nm":"Campana","de":"La campana del temple de muntanya sona una vegada i travessa tota una vall. És el cor del metall, que anhela arribar lluny i més lluny encara, plorant llarg—i així el so es va assentant a poc a poc al pit de qui l'escolta."},"ICON-0103":{"nm":"Paraigua","de":"Si el compartiu, una espatlla sempre acaba mullant-se. Sota el paraigua lleugerament inclinat, l'espatlla xopa és la prova més clara de la tendresa. El curt camí de compartir un mateix sostre roman llarg temps al cor."},"ICON-0104":{"nm":"Estora","de":"Esteneu-ne una sobre el terra nu i aquell racó es converteix a l'instant en una sala d'assaig. Un lloc que us acull sense dir res quan rodoleu i caieu—incomptables moviments hi van aprendre per primer cop el camí del cos."},"ICON-0105":{"nm":"Cascavell","de":"Agiteu-lo suaument i un so clar i dringant rodola a la mà. La petita alegria rodona que els infants d'antany penjaven a la vora dels seus jupetins de colors i amb què corrien pel pati desperta de nou sobre el palmell."},"ICON-0106":{"nm":"Serp de joguina","de":"La seva forma allargada i penjant esparvera la gent d'una manera entremaliada. Espantar-se, fugir i acabar esclatant a riure—una broma com aquesta també és, al capdavall, una branca més de la tendresa mútua."},"ICON-0107":{"nm":"Joguina","de":"Tothom té una capsa que, ni de gran, no gosa llençar. A dins, el riure dels dies més lluminosos encara hi roman ben enrotllat, com una molla que mai no s'ha desfet."},"ICON-0108":{"nm":"Taula plegable","de":"Desplegueu-ne les potes plegades i qualsevol lloc es converteix de seguida en el racó de la família. El so de les culleres que xoquen quan tothom s'asseu al voltant—aquell humil concert sona com la cançó més càlida de tot el dia."},"ICON-0109":{"nm":"Sabó","de":"Es fa cada cop més petit a la mà mentre, en silenci, neteja algú. Gastar-se un mateix per rentar l'altre—només molt després que la bombolla s'ha esvaït del tot es descobreix, per fi, aquest cor callat."},"ICON-0110":{"nm":"Pinta","de":"Igual que deslliga els cabells embullats fil a fil, un dia arrugat també es va endreçant a poc a poc. Un breu gest davant el mirall arregla, sense fer soroll, més enllà dels cabells, fins i tot la compostura del cor."},"ICON-0111":{"nm":"Gàbia d'ocell","de":"Hi ha un ocell que canta sense marxar encara que la porta romangui ben oberta. Un cor que es queda no perquè estigui pres, sinó perquè vol romandre-hi—aquesta subtil diferència, aquesta gàbia la percep abans que ningú."},"ICON-0112":{"nm":"Escalfamans","de":"A la cua d'hivern davant la sala de concerts, una petita escalfor dins la butxaca desglaça a poc a poc els dits enravenats. És una tendresa de la mida d'un palmell que algú va sacsejar per escalfar-la abans, pensant en tu tremolant al fred."},"ICON-0113":{"nm":"Mocador","de":"Un sol tros de tela que rep llàgrimes i suor sense queixar-se. La petita brodada de la cantonada hi roman, delicada, com un darrer comiat que va deixar algú que va marxar abans, dient-te que no ho oblidis."},"ICON-0114":{"nm":"Esprai","de":"Un sol polvoritzat i la textura de l'aire canvia a l'instant. La boira que s'escampa per l'escenari, la planta a la finestra del matí—dins d'aquestes gotetes fines esdevenen per un moment un altre món i resplendeixen."},"ICON-0115":{"nm":"Tira olfactiva","de":"Triar una fragància s'assembla, d'alguna manera, molt a triar un record. Un sol fil d'aroma tocant la punta d'un paper prim porta suaument fins al nas una estació que crèieu oblidada."},"ICON-0116":{"nm":"Taula","de":"A cada veta de fusta gastada hi ha gravat, en silenci, el nombre d'àpats compartits. Els sopars sorollosos, les nits tardanes rebudes tot sol—aquest quadrat ho ha acollit tot sense dir res, i n'ha tret lluïssor."},"ICON-0117":{"nm":"Cabdell de fil","de":"Estireu suaument un extrem i es desfà sense esforç; un sol punt i torna a lligar-se. Recosir allò trencat sempre comença així, en silenci, des d'un únic fil prim."},"ICON-0118":{"nm":"Impermeable","de":"Fins i tot els dies de pluja intensa, és aquesta única peça la que finalment et treu al carrer. Només qui coneix el plaer de caminar xipollejant sota la pluja no fa servir la pluja com a excusa per quedar-se a casa."},"ICON-0119":{"nm":"Bosseta","de":"Arrodoniu la boca i tot allò que hi ha a dins queda, per fi, a resguard. Dins un petit sac gastat per l'ús, monedes, el record d'un dia i paraules que mai no es van arribar a dir es bressolen juntes."},"ICON-0120":{"nm":"Prestatgeria","de":"Passeu el dit lentament pel llom dels llibres alineats i les estacions que heu travessat es fan sentir a la punta dels dits. Que no gosis llençar un llibre acabat és perquè allà encara hi viu el tu d'aquell temps."},"ICON-0121":{"nm":"Pila de llibres","de":"Els llibres llegits reposen ajaguts de costat; els que encara no s'han llegit s'apilen amunt. Encara que la promesa de llegir-los tots algun dia oscil·li una mica prop del sostre, t'agrada fins i tot aquest balanceig, i per això avui n'afegeixes un volum més."},"ICON-0122":{"nm":"Roda de córrer","de":"Encara que corris amb totes les forces, sembla que et quedis al mateix lloc, però els peuets petits aprenen abans que res el ritme de les puntes. Els ahirs que mai no es van aturar s'ajunten i, un dia, brillen radiants en un camí de veritat."},"ICON-0123":{"nm":"Funda","de":"Perquè no s'hi posi la pols, perquè no es descolori al sol—fins i tot l'acte de cobrir demana la cura de la punta dels dits. Com més estimes una cosa, més tendrament és protegida en els llocs que no es veuen."},"ICON-0124":{"nm":"Fil de llana","de":"Un sol fil que es desenrotllava, rodolant, de la falda de l'àvia. Pot semblar embullat, però si en trobes l'extrem i estires suaument, sempre et segueix. Així és com les nits d'hivern s'anaven allargant, un punt cada vegada."},"ICON-0125":{"nm":"Necesser","de":"Un pintallavis, una goma dels cabells, una carta plegada amb cura—per petit que sembli, a dins hi cap el cor d'un dia sencer. Amb el so de la cremallera en tancar-se, totes les andròmines precioses queden, d'una vegada, a resguard."},"ICON-0126":{"nm":"Reposabraços","de":"Una tarda adormida a mig llegir, un vespre passejant amunt i avall parlant per telèfon. Al racó que s'enfonsa cada vegada més com més temps hi seus, tot el descans que recorda el colze s'hi acumula, tranquil, l'amplada d'un pam."},"ICON-0127":{"nm":"Paquet","de":"Fins que no s'obre, encara no és de ningú. Un sobre segellat és ple d'una expectativa encara tancada, i per això la punta dels dits que n'agafa la cantonada tremola lleugerament. Això és l'emoció d'obrir-lo."},"ICON-0128":{"nm":"Paper de regal","de":"Un cor que arriba un pas abans que el regal. Mentre plegues les cantonades ben ajustades i el lligues amb un llaç, el somriure de qui el rebrà ja s'esplaia, radiant, dins les teves mans."},"ICON-0129":{"nm":"Comandament de videojocs","de":"Botons que els polzes recorden abans que el cap. Has perdut, però una partida més—i aquesta partida acaba fent-te vetllar tota la nit. El pes que s'ajusta just a la mà alça, tranquil·lament, l'aventura d'aquesta nit."},"ICON-0130":{"nm":"Semàfor","de":"El vermell diu atura't un moment, el verd diu que ja pots passar. Amb una sola promesa senzilla, incomptables camins flueixen sense embolicar-se. Que fins i tot l'espera té el seu torn, el llum que parpelleja t'ho diu amb tendresa."},"ICON-0131":{"nm":"Fletxa","de":"La forma més amable per a qui ha perdut el camí. Quan no saps cap on anar, una sola direcció que algú ja va traçar abans torna a fer ferm el pas que s'havia aturat."},"ICON-0132":{"nm":"Coordenades","de":"Amb només dos números pots assenyalar qualsevol punt del món. El lloc on vau quedar per trobar-vos, la platja de sorra on vau enterrar un tresor. Perquè una promesa no perdi el camí, un petit punt la sosté fins al final."},"ICON-0133":{"nm":"Rajola","de":"Sola, no és més que una peça quadrada. En el moment en què reposen l'una al costat de l'altra, espatlla contra espatlla, esdevenen terra i paret. Les coses petites s'ajunten per crear un lloc on algú pugui posar el peu amb confiança."},"ICON-0134":{"nm":"Rellotge de sorra","de":"Quan la cambra de dalt es buida, la de baix s'omple a poc a poc. Mirant la sorra caure suaument, creiem que el temps flueix. Gireu-lo i torna a començar—aquesta és la petita mentida amable de la sorra."},"ICON-0135":{"nm":"Pilota","de":"Llançada, torna; xutada, rodola. Ser rodona i no saber mai cap on rebotarà és el seu encant més gran. Al bell mig del pati, els rialles sempre han començat, rodones, des d'aquesta petita esfera."},"ICON-0136":{"nm":"Interruptor","de":"Clic, s'encén d'un cop i s'apaga d'un cop. Aquell petit so que fas en entrar en una habitació fosca divideix, en una línia clara, el començament i la fi d'un dia dispers."},"ICON-0137":{"nm":"Signe d'interrogació","de":"No saber la resposta no és cap vergonya. És la prova benvinguda que la curiositat encara és viva. Quan aquest petit ganxo toca suaument dins el cap, l'aprenentatge fa, per fi, el primer pas."},"ICON-0138":{"nm":"Llumí","de":"Un sol bastonet que es grata a si mateix per lliurar el foc. Crema breument i desapareix en silenci, però en aquell instant s'encén una espelma i s'escalfa una llar. Un petit sacrifici esdevé el primer botó de l'escalfor."},"ICON-0139":{"nm":"Escambell","de":"Puja un sol esglaó i la mà arriba fins i tot al prestatge que abans no tocaves. La feina d'allargar per un moment l'alçada d'algú. Aquí hi ha un lloc amable que s'ajup ben baix per alçar-nos suaument."},"ICON-0140":{"nm":"Rellotge de polsera","de":"El primer que et vas posar al canell el dia que vas decidir fer exercici. Un petit entrenador que compta els batecs del cor i les passes et toca l'espatlla per dir-te que avui has caminat una mica més que ahir."},"ICON-0141":{"nm":"Alarma","de":"L'amic més fidel, i cada matí el més odiat. Gràcies que lluita, cada vegada, en el teu lloc contra la temptació dels cinc minuts més sota les mantes, ni les promeses ni els somnis arriben tard. Aquell so que sona amb aparent mala fe és, en realitat, un ànim."},"ICON-0142":{"nm":"Nucli","de":"La part més interna que roman fins al final quan tot l'exterior s'ha desprès. La llavor de la poma, la veritat del cor—sigui el que sigui, al mig de tot hi ha sempre la cosa més ferma. L'únic punt que, per molt que et sacsegin, sempre resta."},"ICON-0143":{"nm":"Ploma","de":"La taca que abans que la tinta s'assequés s'escampava lleugerament pel cantell de la mà. S'escrigui bé o no, el primer traç davant un full en blanc sempre demana una mica de coratge. És el pont pel qual el pensament travessa fins a la punta dels dits."},"ICON-0144":{"nm":"Pinzell","de":"Quan porta tinta i passa sobre el paper hanji, fins i tot un sol tremolor de dubte hi queda gravat sencer. Si t'afanyes amb ambició per escriure de pressa, de seguida es nota. El pinzell és el primer a conèixer l'honestedat que habita a la punta dels dits."},"ICON-0145":{"nm":"Bafarada","de":"El lloc que sorgeix, rodó, damunt el cap abans que les paraules acabin de sortir de la boca. Aquí s'hi guarda allò que vols dir. Quan és buida, encara està triant amb què omplir-se."},"ICON-0146":{"nm":"Casella de verificació","de":"Traça dues ratlles dins el quadrat buit i el cor es torna una mica més lleuger. Una petita medalla que et concedeixes tu mateix per una tasca acabada. Al final del dia, mirant les caselles plenes, ens tranquil·litzem pensant que avui també hem viscut bé."},"ICON-0147":{"nm":"Tauleta digital","de":"Els dibuixos s'escampen i les lletres flueixen allà on toquen els dits. Poseu-la suaument sobre la falda i tot un món s'encén, lluminós. És lleugera, però la possibilitat que hi cap dins no és, ni de bon tros, prima."},"ICON-0148":{"nm":"Comandament a distància","de":"Té un talent innat per amagar-se entre els coixins del sofà. El poder de canviar de canal sempre és de qui el té a la mà. La baralla més petita i entranyable en família passa sempre sobre aquest pam d'espai."},"ICON-0149":{"nm":"Contrapès","de":"Un pes que ha baixat fins al punt més baix per aguantar allò que oscil·la. Per molt que dalt tot es belluguin, si baix hi ha prou pes, al final no cau. L'equilibri sempre aguanta en els llocs que no es veuen."},"ICON-0150":{"nm":"Trencaclosques","de":"La nit que vas buscar a les palpentes fins sota el sofà l'última peça que faltava. Aquell plaer silenciós de l'instant en què encaixa perfectament. Quan les coses disperses troben el seu lloc, la imatge, per fi, es completa."},"ICON-0151":{"nm":"Regle","de":"Mesurar una llargada també és una manera de complir una promesa. Perquè un pam sigui el mateix per a tothom, les marques s'alineen amb honestedat. Una sola línia recta pot arribar a endreçar fins i tot un cor tort."},"ICON-0152":{"nm":"Llenç","de":"Una superfície blanca sense res és el que fa més por, i alhora la que emociona més. Fins que no hi poses el primer punt, pot esdevenir qualsevol cosa. El buit no és una fi, sinó un altre nom per al començament."},"ICON-0153":{"nm":"Cub de Rubik","de":"Més d'una persona ha passat la nit en blanc intentant encaixar les sis cares. La tenacitat de la punta dels dits que gira i regira. En l'instant en què els colors barrejats troben el seu lloc, un petit univers s'ordena amb pulcritud."},"ICON-0154":{"nm":"Consola portàtil","de":"Una petita pantalla al voltant de la qual els cosins ajuntaven els caps durant les vacances. Un món d'aventura que cap perfectament dins el palmell. Amb sentir només un compàs de la melodia d'engegada, tot aquell estiu torna sencer."},"ICON-0155":{"nm":"Empunyadura","de":"La sensació d'encaixar just a la mà quan l'estrenys ferm et dóna, en silenci, confiança. Perquè no relliscui, perquè no se t'escapi. En el moment més crucial, és el punt d'unió que lliga la mà i l'eina en un sol tot ferm."},"ICON-0156":{"nm":"Ploma estilogràfica","de":"Mentre escrius amb la tinta reomplerta, fins i tot la lletra es torna una mica més polida. Serenant el cor amb el rasclet del plumí, s'assembla, en silenci, a la cura de començar lentament la primera línia d'una carta escrita a mà."},"ICON-0157":{"nm":"Paleta","de":"Blau al costat del vermell, verd damunt el groc. Sobre aquesta petita tauleta on els colors reposen endreçats l'un al costat de l'altre, un dibuix guanya, per fi, expressió. Tota aventura de barrejar i superposar hi fa el primer pas, aquí mateix."},"ICON-0158":{"nm":"Conjunt","de":"Cadascuna, per separat, és senzilla, però juntes i alineades esdevenen tota una història. La tranquil·litat de quan no falta cap peça i tot està al seu lloc. Reunir en un mateix punt coses disperses porta amb si la petita alegria de la totalitat."},"ICON-0159":{"nm":"Volant de bàdminton","de":"El so suau del vent que fan les plomes en enlairar-se colpejades per la raqueta. Sembla massa lleuger per arribar lluny, però si el colpeges amb decisió, vola recte fins a l'altre extrem de la pista. La lleugeresa també és, ben mirat, una forma de força."},"ICON-0160":{"nm":"Antena","de":"S'alça, quieta, cap al cel, mirant d'atrapar senyals invisibles. La paciència d'atreure fins i tot veus llunyanes. Els dies que no s'hi sent bé, n'hi ha prou de girar-ne una mica l'angle perquè torni a ser clara."},"ICON-0161":{"nm":"Estetoscopi","de":"L'extrem rodó fred contra el pit, i un alè que s'atura un instant. Concentres l'oïda en un sol petit batec de tambor, i el ritme més antic d'estar viu arriba fins a la punta dels dits. Una eina on escoltar ve primer."},"ICON-0162":{"nm":"Peó d'escacs","de":"Un peonet que caminava, lent, una sola casella cada vegada. Tot i així, en l'instant en què arriba a l'última fila, pot esdevenir qualsevol cosa. Aquell moviment que capgira tot el tauler amb un pas maldestre, el vell tauler d'escacs el vetlla en silenci."},"ICON-0163":{"nm":"Comandament","de":"Recordes les nits que recorríeu l'univers amb dos polzes? L'empunyadura gastada que vas llençar per haver perdut i que vas tornar a recollir, tot avergonyit. La conversa més llarga i càlida que vas compartir en silenci amb algú a l'altre costat de la pantalla."},"ICON-0164":{"nm":"Consola","de":"Encens l'aparell i un petit so d'arrencada sona com una salutació. La caixa quadrada que encenies i apagaves dins el llit durant tot el descans escolar; la primera aventura de la infància sempre començava en la llum d'aquesta pantalla."},"ICON-0165":{"nm":"Línia de temps","de":"L'extrem esquerre és el principi, l'extrem dret és un dia que encara no ha arribat. Arrossega un sol punt a qualsevol lloc entremig, i un moment que crèieu oblidat torna a desplegar-se. Un lloc on el temps queda ajagut en una sola línia."},"ICON-0166":{"nm":"Prisma","de":"Qui hauria dit que la llum, tan simplement clara, guardava en realitat set colors. El secret que es desfà en un arc de Sant Martí en el moment de travessar un tros de vidre. Com més ordenada sembla una cosa, més colors s'hi amaguen a dins."},"ICON-0167":{"nm":"Tee de golf","de":"Un petit suport per posar-hi la bola amb cura. Com més lluny la vols enviar, més fermament necessites, primer, alguna cosa que la sostingui. Aquest petit clau damunt la gespa sosté el primer pas."},"ICON-0168":{"nm":"Agulla de fer mitja","de":"Un punt, i un altre. Si en deixes anar un, l'has de desfer tot i tornar al principi. La bufanda que s'allargava a poc a poc sobre la falda al llarg d'un hivern, el lloc on la paciència de la punta dels dits es teixia en escalfor."},"ICON-0169":{"nm":"Línia melòdica","de":"Un sol compàs que s'escapava dels llavis, taral·lejat, abans que hi posessin la lletra. Dins aquella tonada encara boirosa, sense paraules, hi ha la cara més sincera i primera d'una cançó."},"ICON-0170":{"nm":"Radar","de":"Dispara un senyal cap a la foscor invisible i espera, en silenci, un sol punt que torni. La paciència de la llum verda i rodona que creu que hi ha alguna cosa allà, encara que no es vegi res."},"ICON-0171":{"nm":"Pad de ritme","de":"Toc, toc, un cop lleuger i la llum i el so salten alhora. Un lloc que fa que les mans memoritzin el compàs abans que el cap. El petit escenari més tendre, desplegat damunt el palmell."},"ICON-0172":{"nm":"Pintura","de":"Els vells artesans molien pedra i terra per obtenir-ne color. L'anyil, de l'herba; el vermell, de la terra. En aquesta sola gota que ara s'esprem a la punta dels dits també hi flueix la cura antiga de traslladar amb esment la natura a un recipient."},"ICON-0173":{"nm":"Línia","de":"Allò que neix només en l'instant en què decideixes unir un punt amb un altre. Curta o llarga, corba o recta, és el rastre més simple que deixa la voluntat d'anar cap a algun lloc. El començament de tot dibuix."},"ICON-0174":{"nm":"Obturador","de":"Clic, aquella breu foscor d'un instant reté una escena per sempre. Fins i tot una expressió que estava a punt d'escapar-se en un parpelleig, talla una mica de llum i la converteix en record. Una petita fulla d'esclat."},"ICON-0175":{"nm":"Corda de seguretat","de":"La corda que es lliga ben ferma un pas abans que la persona que puja a un lloc alt. Sosté en el teu lloc el cor que patia per si caies, vetllant-te sense veure's, un lligam de promesa. Sempre és darrere teu."},"ICON-0176":{"nm":"Cadenat","de":"El pesant cadenat de ferro que tancava el graner. No era per empresonar res, sinó el desig de deixar allò preciós ben resguardat. Fins i tot en la mà que el tancava hi havia cura, la fermesa acollidora d'una casa antiga."},"ICON-0177":{"nm":"Balança","de":"Quan un costat es fa més feixuc, l'altre s'alleugereix tot sol. En aquell instant de dubte sobre què posar-hi i quant, una persona aprèn l'equitat. Dos braços que ensenyen l'equilibri balancejant-se."},"ICON-0178":{"nm":"Separador","de":"Fins i tot allò ben enganxat, si en segueixes la veta, acaba partint-se. Una eina petita per dividir qualsevol cosa en dues i mirar-ne a dins. La punta dels dits, curiosa, que vol tornar a desfer allò que s'havia ajuntat."},"ICON-0179":{"nm":"Comptador","de":"U, dos, tres. Un petit amic que compta els números en silenci en lloc dels teus dits. Un company amable del recompte que transforma, clic a clic, el neguit de perdre el compte en tranquil·litat."},"ICON-0180":{"nm":"Cursor","de":"Una petita fletxa que parpelleja en algun lloc de la pantalla, esperant la propera ordre. Fins i tot mentre dubtes, no es mou d'aquell lloc, la punta de llum que et fa senyal, en silenci, perquè comencem ja."},"ICON-0181":{"nm":"Presa d'escalada","de":"L'últim punt que agafes just abans que la força se t'escapi de la punta dels dits. Que hi ha moments que resistim només amb la voluntat de no deixar-nos anar, el petit sortint de la paret t'ho diu en silenci."},"ICON-0182":{"nm":"Còdol","de":"Una pedra que ha rodolat molt de temps al rierol, cedint totes les seves arestes. Tornar-se rodona és un altre nom del temps que s'ha anat desgastant. Agafa-la suaument al palmell i hi sentiràs la paciència del riu que hi ha corregut."},"ICON-0183":{"nm":"Blasó","de":"Les cases antigues gravaven bèsties i estels en un sol drap per fer-se conèixer. Un dibuix que transmetia el cor abans que les paraules. Una marca antiga que comprimeix, amb cura, l'orgull d'una persona en un petit espai."},"ICON-0184":{"nm":"Escut","de":"Interposar-se sempre va ser una cosa feta per algú que quedava al darrere. Rebent en lloc seu les fletxes que arribaven, protegia el dia corrent d'algú, un mur feixuc i alhora tendre."},"ICON-0185":{"nm":"Resurrecció","de":"Hi ha un cor que s'apaga i torna a encendre's. Només després d'haver caigut un cop s'aprèn, per fi, com tornar a aixecar-se. Un segon alè que s'omple, en silenci, allà mateix on es creia que tot s'havia acabat."},"ICON-0186":{"nm":"Arc","de":"La mà que vol enviar lluny primer estira la corda fins al final. Que per deixar anar cal, abans, abraçar-ho ben a prop, l'arc tibant i corbat t'ho diu, en silenci, sense paraules."},"ICON-0187":{"nm":"Cor (símbol)","de":"La paraula «m'agrades» es va encongint sempre en una forma petita. Aquesta forma que es dibuixa d'esquitllentes tant a la punta d'un llumener com entre dos dits que es toquen. L'abreviatura més comuna i sincera del cor."},"ICON-0188":{"nm":"Núvol","de":"Flotant lentament cap on bufa el vent, es va convertint cada vegada en una cara diferent. Ara conill, ara cotó, sense retenir res gaire temps i deixant-ho passar tot—el cor més lleuger del cel."},"ICON-0189":{"nm":"Laberint","de":"Un lloc on aprens a girar cua davant un mur sense sortida. Fins i tot mentre erres, els passos creixen a poc a poc cap a la sortida. Cal perdre's un cop per guanyar bon sentit d'orientació."},"ICON-0190":{"nm":"Dent","de":"Hi havia el costum de llançar la dent perduda al terrat. Un petit desig perquè la dent nova sortís ben dreta. Una tendra promesa de la infància: cal perdre alguna cosa un cop, en créixer, per guanyar-ne una de més forta."},"ICON-0191":{"nm":"Planeta","de":"Un cos rodó que gira al voltant d'un estel sense sortir mai del seu camí. Encara que sembli solitari, la seva gravetat sempre fa girar alguna cosa al costat. Mantenir el propi lloc en silenci esdevé, per si mateix, tot un món."},"ICON-0192":{"nm":"Estrella","de":"Les nits de camí perdut, la gent alçava els ulls cap al punt més brillant. Una llum massa lluny per tocar-la, però prou clara per assenyalar la direcció. Una promesa que es fa més ferma pel fet mateix de ser llunyana."},"ICON-0193":{"nm":"Silueta","de":"Estar-se d'esquena a la llum fa que d'una persona només en resti el contorn. Una sola forma negra, sense nom ni expressió. Un espai buit que, precisament per estar-ho, et fa imaginar encara més."},"ICON-0194":{"nm":"Orella","de":"Per cantar bé, primer cal escoltar bé. Tant el ritme com el cor, al capdavall, comencen escoltant. Una petita porta oberta i rodona on tots els sons del món arriben primer i s'hi queden."},"ICON-0195":{"nm":"Fulla caiguda","de":"Hi ha fulles que brillen més belles just en l'instant de caure. La lleugeresa de cremar del tot en vermell el verd d'una temporada i deixar-lo anar suaument. La tardor ens mostra que fins i tot un final pot ser així de bell."},"ICON-0196":{"nm":"Lluna","de":"Hi havia nits de juntar les mans i demanar un desig sota la llum rodona de la lluna de tardor. Una cara que, minvant i creixent una vegada i una altra, mai no va ser la mateixa. Un fanal que canvia i, tanmateix, il·lumina sempre el mateix lloc."},"ICON-0197":{"nm":"Cor","de":"Fins i tot dalt de l'escenari, allò més honest és, al capdavall, aquest batec. No s'atura encara que tremoli, i batega més fort quan el cor s'omple d'emoció. Un petit tambor vermell que batega en el teu lloc l'ànim que les paraules no van poder acabar de dir."},"ICON-0198":{"nm":"Ombra","de":"Un company que mai no se separa mentre hi hagi llum. Es fa més fosca com més clar és el dia i més pàl·lida com més ennuvolat, un altre jo que m'ha seguit més temps que ningú. Algú que roman al meu costat fins i tot els dies de solitud."},"ICON-0199":{"nm":"Cua","de":"S'agita tota sola quan hi ha alegria, i s'arronsa d'amagat quan hi ha por. La punta honesta que, per molt que la boca es mantingui closa, no pot amagar del tot el cor. El sentiment interior que el cos deixa anar primer."},"ICON-0200":{"nm":"Llaç de cua","de":"Un petit cordó lligat a l'extrem per acabar-ho, com una cinta. El cor que en va fer un nus una vegada més, ben fort, perquè no es desfés. Un lligam tendre que reuneix i calma juntes les coses que tendeixen a escampar-se."},"ICON-0201":{"nm":"Pupil·la","de":"Les paraules es poden triar, però la mirada no es pot amagar. És el lloc on primer se t'escapa un sentiment descobert, a l'interior d'aquell cercle negre. Encara que et calis les paraules «m'agrades», les pupil·les ja tremolen cap a tu."},"ICON-0202":{"nm":"Ferradura","de":"Un tros de ferro que es va tornar més resistent com més es desgastava la punta en córrer llargs camins. Penjada del revés sobre la porta, deien que la sort, anant i venint, s'hi acumulava a dins. Sosté en silenci el retorn segur d'algú a casa."},"ICON-0203":{"nm":"Pedra d'escut","de":"Encara que el vent i la pluja esborrin les lletres fins fer-les gairebé invisibles, si les ressegueixes amb la punta dels dits, el relleu gravat torna a la vida amb nitidesa. És el pes d'un cor que no volia ser oblidat. Així, una pedra guarda un nom durant molt de temps."},"ICON-0204":{"nm":"Peu palmat","de":"Amb una fina membrana que uneix els dits, aprèn a empènyer l'aigua. Un petit rem que la natura posa d'amagat a la mà de qui neda amb feines. Un disseny tendre que, per lent que sigui, acaba portant-te a l'altra riba del riu."},"ICON-0205":{"nm":"Purpurina","de":"Tothom es queixa que, si se t'enganxa a les mans, et segueix uns quants dies, però el dia de festa és el primer que es busca, aquests granets de llum. Escampa'n un grapat, d'aquesta pols d'estels, i fins i tot un paper corrent brillarà, i avui es tornarà especial."},"ICON-0206":{"nm":"Urpa","de":"Les bèsties del bosc graten la terra amb les urpes per deixar el seu camí. No és una amenaça sinó un rastre, una signatura silenciosa que diu «per aquí he passat». Una punta esmolada pot esdevenir, per a algú, un tendre senyal de camí."},"ICON-0207":{"nm":"Llamp","de":"En l'instant en què el cel obre per un moment el palmell de la mà, la llum arriba abans que el tro. Com si digués que agafis alè abans que el gran soroll t'arribi. La por i la fascinació neixen sempre juntes de la mateixa espurna."},"ICON-0208":{"nm":"Talismà","de":"Una sola línia de desig premuda amb tinta sobre paper vermell. Deien que, posat sota el coixí, allunyava els mals somnis. Un cor que prega per la seguretat d'algú és així de càlid, fins i tot en un full de paper tan prim."},"ICON-0209":{"nm":"Ala de pinzell","de":"Hi ha moments en què la punta del pinzell es torna ala. Aquella lleugeresa de lliscar sobre el paper en traçar un sol traç. Que escriure és, en el fons, una forma de volar, la mà antiga que molia la tinta ho devia saber, vagament."},"ICON-0210":{"nm":"Os","de":"Allò que resta només després que tota la carn s'ha esfondrat. L'esquelet blanc que va resistir fins al final perquè era el més dur. Una prova silenciosa que recorda, almenys, la forma, encara que el temps s'ho endugui tot."},"ICON-0211":{"nm":"Nas","de":"L'olor és el camí més curt cap al record. L'olor d'oli a la cuina en dia de festa, l'aire fred d'un matí després de la primera neu: la punta del nas ho capta primer, i el cor la segueix amb un batec de retard."},"ICON-0212":{"nm":"Torrada","de":"El menjar més ràpid d'agafar en un matí atrafegat. Mossega la superfície ben torrada i tot el coratge del dia esclata cruixent. Les coses que no cal que siguin grandioses, però sí saciants, tornen a posar algú dempeus."},"ICON-0213":{"nm":"Galeta","de":"Qui espera més estona davant el forn es guanya la primera mossegada. L'escalfor d'una vora acabada de coure, una dolçor breu. Les que es couen pensant en algú són, estranyament, encara més dolces."},"ICON-0214":{"nm":"Berenar","de":"En una tarda en què l'assaig s'allarga, una bosseta petita treta del fons de la motxilla. Parteix-la per la meitat i la sacietat, curiosament, es duplica. Un grapat de tendresa que omple el cor abans que la gana."},"ICON-0215":{"nm":"Càpsula","de":"Ningú no ho pot saber fins que la gira i l'obre. El que hi ha dins de la closca rodona és sempre el mateix aleteig del cor. L'emoció més honesta del món, on es compra i es ven una petita casualitat."},"ICON-0216":{"nm":"Pom de porta","de":"El punt que toquen primer les incomptables mans que obren i tanquen una porta. La primera salutació de la llar, que comença freda i s'escalfa a la palma. Com més petjades de mans s'hi acumulen, més aquella cambra es va convertint, a poc a poc, en la casa d'algú."},"ICON-0217":{"nm":"Passeig","de":"Fins i tot caminar sense destinació té la seva raó. Un temps per desfer, fil a fil, els pensaments enredats en cada passa. Torna d'una volta i la resposta és la mateixa, però el cor, només ell, es queda molt més lleuger."},"ICON-0218":{"nm":"Escúter","de":"Dues rodes que travessen carrerons estrets. No és ràpid, però rep tot el vent amb el cos sencer. Hi ha dies en què, encara que no arribis lluny, només vols sortir a rodar amb aquesta frescor."},"ICON-0219":{"nm":"Barra de seguretat","de":"Abans de pujar, una sola barra que baixa fermament davant del pit. Una promesa reconfortant que aguanta amb tu, fins al final, el tram que fa por. Et diu, freda i sense paraules, que està bé agafar-s'hi fort."},"ICON-0220":{"nm":"Escales","de":"Pujar esglaó a esglaó, i sense adonar-te'n el paisatge ja ha canviat. La planta del peu aprèn primer que cap alçada no s'assoleix d'un sol salt. Pujar i baixar era, per a algú, tota una jornada de passes."},"ICON-0221":{"nm":"Terrari","de":"No és empresonar un bosc dins d'un vidre, sinó cuidar amb dedicació tot un món. Un univers de la mida d'una palma on la molsa s'escampa i es formen gotes d'aigua. Com més hi mires, més el cor se't tenyeix, a poc a poc, de verd."},"ICON-0222":{"nm":"Tarima","de":"Puja a un lloc un pam més alt i el paisatge que veus canvia. Un espai on la por i l'orgull es troben a la mateixa alçada. Segons qui hi trepitgi, aquell únic esglaó es converteix cada vegada en un escenari diferent."},"ICON-0223":{"nm":"Avió","de":"En l'instant en què els núvols s'estenen sota els peus, per fi enyores el lloc que has deixat enrere. No és allunyar-se, sinó que el món es fa més ampli. Fins i tot un somni criat en una petita illa travessa el cel així."},"ICON-0224":{"nm":"Monopatí","de":"Un objecte que només pots muntar de debò després d'haver après primer a caure. Cada vegada que et raspalles el genoll, l'equilibri es va gravant, a poc a poc, al cos. Quatre rodes honestes que roden més lluny com més bones caigudes s'han fet."},"ICON-0225":{"nm":"Passaport","de":"Passa la coberta i és ple de pàgines en blanc. Cada segell que s'hi anirà posant es convertirà en la prova d'una vida viscuda. Un llibret petit que no guarda tant on has arribat com la possibilitat d'anar a qualsevol lloc."},"ICON-0226":{"nm":"Mapa dibuixat a mà","de":"No té ni distàncies ni escales exactes, però com que és un camí dibuixat a mà, no hi ha por de perdre's. Un paper on els carrerons i els noms de les botigues s'entrellacen amb tendresa. Una indicació feta amb cor és sempre més càlida que el camí mateix."},"ICON-0227":{"nm":"Full de moviments","de":"Un paper on cada passa a l'escenari queda dibuixada com una línia. On aturar-se, on girar, les fletxes ja ho prometen d'antuvi. Fins i tot un ball que sembla lliure comença, en realitat, en aquest únic full."},"ICON-0228":{"nm":"Guia de seients","de":"En un espai desconegut, el primer que es busca a les palpentes és el propi seient. La filera i el número et porten, finalment, fins a aquell únic espai. Un sol full de paper asseu, ordenadament, milers d'aletejos, cadascun al seu lloc."},"ICON-0229":{"nm":"Targeta de camí del carreró","de":"Una indicació escrita a mà per algú, pensada per a qui pogués perdre's en carrerons com un laberint. La lletra amable que diu a quina cantonada s'ha de girar. L'hospitalitat d'un barri, escrita amb claredat en una petita targeta."},"ICON-0230":{"nm":"Passi de seguretat","de":"Només quan et penges aquesta targeta al coll s'obre, per fi, la porta del món de dins. Un petit permís que et concedeix l'entrada, i alhora un testimoni silenciós que hi pertanys. Només qui sap el temps que ha costat guanyar-la en coneix el pes."},"ICON-0231":{"nm":"Braçalet d'un dia","de":"Cordat una vegada al canell, ets membre d'aquell dia fins que te'l treguis. Una simple cinta de paper separa el de dins del de fora, i esdevé la marca d'haver passat el mateix dia junts. Fins i tot després d'arrencar-la, el rastre hi queda una bona estona."},"ICON-0232":{"nm":"Etiqueta de convidat","de":"Amb una petita etiqueta enganxada al pit, un lloc desconegut es converteix en el teu racó. Quan la paraula «benvingut/da» es transmet en un sol full de paper, fins i tot qui hi ve per primera vegada esdevé, per fi, un convidat."},"ICON-0233":{"nm":"Tub per a pòsters","de":"Un cilindre resistent que guarda un pòster enrotllat sense ni una sola arruga. Perquè com més preuat és el dibuix, més cal enviar-lo ben estirat. No es veu per dins, però surt de viatge carregant amb cura el mim d'algú."},"ICON-0234":{"nm":"Coberta de dossier","de":"El primer full que embolcalla un gruixut fardell de documents. La cara que toca la mà abans que el contingut. Quan la coberta és polida, fins i tot l'actitud de dins sembla polida: el començament tendre d'una petita formalitat."},"ICON-0235":{"nm":"Postal de record","de":"Escrius unes paraules d'afecte sobre un fragment de paisatge llunyà i les envies. Quan arriba, el sentiment que hi vas posar també ha envellit una mica, i es fa encara més entranyable. La lenta escalfor d'una carta escrita a mà, que un missatge de pantalla mai no acaba d'atrapar."},"ICON-0236":{"nm":"Etiqueta de regal","de":"Un petit tros de paper lligat sobre un regal. Amb només les paraules «per a tu», l'embolcall ja queda complet. La carta més curta del món, que no escriu què es dóna sinó en qui s'ha pensat."},"ICON-0237":{"nm":"Rotlle d'adhesius d'embolicar","de":"Cada vegada que n'arrenques un tros per fer-lo servir, l'acabat queda molt més polit. Un petit nus que subjecta amb pulcritud l'extrem que amenaça de desfer-se. L'últim gest d'un embolcall fet amb cura sempre surt d'aquesta cinta enrotllada."},"ICON-0238":{"nm":"Funda de carta transparent","de":"Una capa transparent que embolcalla una carta escrita a mà perquè no s'esgrogueeixi amb els anys. Les lletres queden visibles, però la marca de tocar-la no hi arriba. Una membrana invisible custodia en silenci el cor de qui la guarda amb estima."},"ICON-0239":{"nm":"Segell de cera","de":"L'últim punt que tanca un sobre: com més viu és el color, menys s'escapa el sentiment. Una promesa que cap mà no l'ha tocat abans que s'obri. Fins i tot un secret necessita un nus així de bonic."},"ICON-0240":{"nm":"Llibret de notes","de":"Un petit llibre que lliga juntes notes breus. Cada full és una paraula per lliurar a algú. Si vas guardant, a poc a poc, les paraules que no vas poder dir, algun dia hi creixerà el coratge de fer-les arribar."},"ICON-0241":{"nm":"Rètol plegable","de":"Obert diu «per aquí», plegat diu «per avui, prou». Amb les cames obertes a la boca d'un carreró, es passa el dia sencer dempeus per qui pugui perdre's. El vespre en què es plega és, per a mi, el descans més tendre."},"ICON-0242":{"nm":"Cinta postal","de":"Quan abraces un munt de postals cenyint-les per la cintura, les salutacions a punt d'escampar-se es converteixen, per fi, en un sol feix de sentiment. Una simple cinta lleugera lliga amb ordre les paraules que aniran lluny, i acomiada, en silenci, l'esquena que emprèn el camí."},"ICON-0243":{"nm":"Fardell de notes d'agraïment","de":"Com que la paraula «gràcies» sempre s'escapa dels llavis, l'escrius en un paper de la mida d'una palma i el lligues amb calma. Com més gruixut es fa el fardell, més gruixut, alhora, creix el deute de cor que tens amb algú."},"ICON-0244":{"nm":"Full de crits d'ànim","de":"Un full de mostra on hi diu «crideu-ho així». Un crit d'ànim que encara no té veu posada a sobre només conté un aleteig silenciós, com una partitura en blanc que espera el primer compàs."},"ICON-0245":{"nm":"Nota de sol·licitud de pregravació","de":"La nota que demana reservar una pregravació sempre queda a la casella de les cinc del matí. El petit paper ho apunta en silenci, com si ho entengués tot, el cor que retalla la son per guardar-se un lloc."},"ICON-0246":{"nm":"Tiquet de torn de fan-sign","de":"Un sol full que fixa en quin torn saludaràs. Fer cua no és esperar el teu moment: és, per un instant, demanar prestat un torn perquè no es pot posar número al que sents."},"ICON-0247":{"nm":"Braçalet de número","de":"Un sol número decideix en quin ordre faràs cua avui. Al davant o al darrere, els qui porten aquesta cinta petita i lleugera al canell són, al capdavall, companys d'un mateix cor reunits per veure el mateix escenari."},"ICON-0248":{"nm":"Full de classificar photocards","de":"Encara que sigui la mateixa cara, dius que totes són diferents i les anotes casella per casella. Com més ple queda el full, més s'ordena el cor, i l'única casella buida fa bategar el pit amb les ganes d'omplir-la avui."},"ICON-0249":{"nm":"Full de control d'àlbums","de":"Versió, photocard, fins i tot si porta segell: una llista d'afecte escrita en xifres. Imaginant per endavant l'orgull del dia en què tot quedi complet, avui també dibuixes amb pulcritud un cercle en una línia."},"ICON-0250":{"nm":"Nota de guia d'ànims","de":"Les formes de les mans, el compàs de crit, fins i tot els punts on agafar alè. Perquè fins i tot algú que ve per primera vegada s'hi fongui de seguida en una sola veu, la petita nota es converteix en una guia amable que passa de mà en mà."},"ICON-0251":{"nm":"Bloc de notes privat","de":"Aquí només hi escrius les frases que no ensenyaràs a ningú. Que la pàgina mai oberta és la més sincera, aquest bloc ho custodia en silenci, amb la coberta ben tancada."},"ICON-0252":{"nm":"Full de segells d'aniversari","de":"El premeu, i un altre dia es torna especial. Amb un sol petit segell marcat sobre una data corrent, «avui» s'apunta, d'amagat, a la llista dels dies que val la pena recordar."},"ICON-0253":{"nm":"Coberta de portapapers","de":"Encara que bufi el vent, encara que caigui la pluja de costat, protegeix fins al final el paper que hi ha subjectat. Jo, que m'he fet càrrec de ser l'armadura de la tauleta, sóc el guardaespatlles de confiança de les lletres escrites."},"ICON-0254":{"nm":"Pestanya índex","de":"Perquè no et perdis enmig d'un gruixut document, treu una petita llengua i assenyala «aquí». Un sol full de colors governa, d'un sol cop d'ull, cent pàgines."},"ICON-0255":{"nm":"Etiqueta de pestanya","de":"Això en aquesta casella, allò en aquella altra. La meva feina és endreçar, línia a línia, el desori del món. En el moment en què s'hi enganxa una etiqueta, les coses barrejades troben, per fi, el seu lloc."},"ICON-0256":{"nm":"Mini tauleta d'aprovació","de":"En l'instant en què hi estampes el segell, d'alguna manera et sents com si t'haguessis fet, de debò, gran. Petita de mida però amb una autoritat esmolada: un sol segell d'aprovat i la feina acumulada s'acaba, ràpida i neta."},"ICON-0257":{"nm":"Sobre transparent de documents","de":"Es veu tot per dins, no hi ha res a amagar. Portant paper important a sobre, l'embolcalla amb el seu propi cos transparent perquè no es mulli amb la pluja ni s'arrugui, i el porta fins al lloc de la cita."},"ICON-0258":{"nm":"Cinta d'assistència","de":"He vingut, i s'omple una altra casella. Quan les petjades de cada dia s'amunteguen en fila al llarg de la cinta, una constància invisible es converteix, per fi, en un dibuix visible d'un sol cop d'ull."},"ICON-0259":{"nm":"Quadern d'errors","de":"Escriure el que has fallat no és acumular vergonya. És, perquè no ensopeguis dues vegades al mateix lloc, reescriure l'error d'ahir com a guia d'avui."},"ICON-0260":{"nm":"Tauleta de segells d'agenda","de":"Estampa un sol segell sobre una agenda en blanc i hi neix un «compromís». La màgia d'un dia decidit amb un sol gest de canell: aquella màgia és, en realitat, un altre nom per a la diligència de preparar-ho tot amb temps."},"ICON-0261":{"nm":"Etiqueta de llom","de":"L'etiqueta dels llibres que es dreçen amb el llom girat cap a la prestatgeria. Les poques lletres escrites en aquell llom estret criden, d'un sol gest, el volum que buscaves entre centenars."},"ICON-0262":{"nm":"Protector de fotografies","de":"Mans nues, prohibides. Dient-te que no hi deixis ni una empremta, es posa amb suavitat el seu propi cos sobre una imatge preuada. Un cor que estima així dura molt de temps gràcies a aquest tacte tan curós."},"ICON-0263":{"nm":"Full d'índex de negatius","de":"Si poses un número a cada tira de negatiu, els moments que s'havien dispersat recuperen el seu torn en la història. Un petit guia que té cura que els records escrits amb llum no es confonguin."},"ICON-0264":{"nm":"Funda de fotografies","de":"Una casa transparent on es guarden, una a una, petites felicitats quadrades. Sense por que se n'aixafin les cantonades, la cara més estimada brilla amb pulcritud aquí dins durant les quatre estacions."},"ICON-0265":{"nm":"Minisobre de fotos","de":"Abans que es refredi del tot l'escalfor d'una fotografia acabada de revelar, un petit sobre obre els dos braços per rebre-la. Una imatge que entra per una boca de la mida d'una palma esdevé, sense adonar-te'n, un tresor dins la bossa d'algú."},"ICON-0266":{"nm":"Coberta lenticular","de":"La meva missió és protegir, sense ni una ratllada, una fotografia difícil que canvia d'expressió si la inclines. Per protegir totes les cares diferents en cada angle, jo tampoc no puc ser gens mandrosa."},"ICON-0267":{"nm":"Etiqueta de classificació de fotos","de":"De les quatre fotos, l'etiqueta assenyala per tu quina és la millor. Aquesta petita tasca de separar, l'una al costat de l'altra, la ben sortida i la divertida, és el secret per gaudir dues vegades d'un mateix record."},"ICON-0268":{"nm":"Cinta de tira de fotos","de":"Envolta i lliga amb ordre un record estret i llarg de quatre fotogrames. Abraçant fermament en un sol feix el riure d'aquell dia, que amenaçava d'escampar-se, el porta sa i estalvi fins al fons de la bossa."},"ICON-0269":{"nm":"Adhesiu de cantonada","de":"Quan enganxes una foto a l'àlbum, una petita mà que li subjecta, amb suavitat, les quatre cantonades. Perquè no caigui sense haver-hi d'embadalir-la de cola, la delicadesa comença, així, per les cantonades."},"ICON-0270":{"nm":"Full de correcció d'impressió","de":"Una mica més càlid, un pèl menys clar. Un sol full amb què vas retocant les xifres fins que surt el color que t'agrada, converteix, en silenci, una foto corrent en una obra d'art."},"ICON-0271":{"nm":"Clip de tiquets","de":"Mossega amb pulcritud els tiquets arrugats i no els deixa anar. Amb la seva petita boca guarda amb fermesa la despesa d'un dia, de manera que el balanç de final de mes surt molt més lleuger."},"ICON-0272":{"nm":"Full de confirmació de reserva","de":"Amb la línia «reserva confirmada», el cor es calma de mica en mica. Un full de paper es converteix en la prova d'una promesa, i guarda l'emoció, endreçada, fins al dia esperat."},"ICON-0273":{"nm":"Justificant de devolució","de":"Una prova petita però honorable que allò que havies agafat prestat ha tornat al seu lloc. En l'instant en què aquest paper et cau a la mà, un deute que et pesava en un racó del cor s'esborra, lleuger."},"ICON-0274":{"nm":"Portador de resguard","de":"Perquè no perdis el tiquet per recuperar allò que has deixat en dipòsit, jo el retindré ben fort en el teu lloc. Perquè on va a parar un petit paper pot decidir, també, com acaba el dia d'algú."},"ICON-0275":{"nm":"Cua d'etiqueta de préstec","de":"Una petita etiqueta que oneja en cada objecte prestat. Segueix aquesta cua i de seguida es revela qui s'ha endut què, i així fins i tot el misteri d'una pèrdua es resol de pressa."},"ICON-0276":{"nm":"Full de verificació","de":"Ho repasses tot, un per un, amb els ulls, per veure que no falti res. Quan les marques de verificació s'omplen en fila, una minuciositat invisible guanya, per fi, el nom de confiança."},"ICON-0277":{"nm":"Sobre de quadrament de comptes","de":"Si escrius els diners que han entrat i els que han sortit a sobre del sobre, les xifres desordenades es posen tranquil·lament en fila. El final del quadrament sempre el marca, amb calma, aquesta petita nota."},"ICON-0278":{"nm":"Etiqueta d'enviament","de":"Surt de viatge amb escrit al seu propi cos on va i a qui arribarà. En l'instant en què s'hi enganxa aquesta etiqueta, la caixa es converteix en una viatgera amb destinació i marxa plena d'emoció."},"ICON-0279":{"nm":"Cinta de confirmació de recepció","de":"Lliga en una sola cinta la paraula «ho he rebut bé» i la retorna. L'alleujament de qui ho ha rebut i la tranquil·litat de qui ho ha enviat s'agafen les mans, en silenci, sobre aquest petit cordill."},"ICON-0280":{"nm":"Anella de targetes de vocabulari","de":"Les paraules que es perdrien si quedessin escampades com fulls solts, una petita anella les ensarta totes i les reté. Passa-les full a full, una vegada i una altra, i les paraules abans desconegudes es tornen, sense adonar-te'n, amigues ben conegudes a la llengua."},"ICON-0281":{"nm":"Cinta de notes de pronunciació","de":"Al punt on la punta de la llengua no para de relliscar, hi pengem una petita etiqueta. Fins i tot un so estrany que es perdia dins la boca troba, sense adonar-te'n, la seva pronunciació correcta si segueix aquesta nota. La primera pàgina per domar, a poc a poc, un so encara maldestre."},"ICON-0282":{"nm":"Capsa de notes de traducció","de":"Petits ponts que travessen d'una paraula a l'altra hi jeuen plegats amb cura, un a cada casella. Escrius una frase triada amb esforç i la passes d'amagat, i fins i tot un cor que no es feia entendre s'apropa amb una sola nota pel mig."},"ICON-0283":{"nm":"Full de retalls de frases","de":"Una frase que toca just al cor només perdura si la copies a mà. Enganxa davant l'escriptori una línia retallada del racó d'un llibre, i aquelles lletres sostenen, en silenci, el dia que s'anava enfonsant."},"ICON-0284":{"nm":"Pestanyes d'índex","de":"Petites banderes de colors clavades perquè no et perdis dins d'un llibre gruixut. Que només et pots perdre més lluny si saps el lloc on tornar, ho diuen en silenci, des d'entre les pàgines, les pestanyes que sobresurten."},"ICON-0285":{"nm":"Fitxa de memorització","de":"Una sola marca posada al costat d'allò que has après. Sent una petita àncora que reté les coses que passen un instant pel cap i intenten desaparèixer, cada casella ennegrida porta a dins, en silenci, l'esforç vessat la nit anterior."},"ICON-0286":{"nm":"Paquet de sobres de qüestionari","de":"Fins que no obres el sobre, ningú no sap què en sortirà. Aquells segons en què els dits juguetegen amb el segell: un paquet d'emoció on una sola pregunta jeu plegada amb cura, amb el batec del cor segellat també a dins."},"ICON-0287":{"nm":"Quadern de pestanyes de gramàtica","de":"Les regles no es memoritzen amb el cap, sinó que s'aprenen amb la mà. Des de la pestanya de color de la pàgina que obres més sovint fins al quadern que es va estovant i gastant, aquella cantonada gastada esdevé el cercle de creixement del temps que has resistit."},"ICON-0288":{"nm":"Full de pràctica de parla","de":"Un sol full per a qui li costa més que res al món obrir la boca. Si vas resseguint les caselles amb el dit, fins i tot les primeres paraules que tremolaven a la gola troben, sense adonar-te'n, la seva pròpia veu. Perquè fins i tot el coratge té els seus torns."},"ICON-0289":{"nm":"Full d'esbós de color","de":"Els colors, encara sense acabar, jeuen escampats i respiren fondo. No és la resposta correcta, sinó encara una possibilitat: en aquest full poc polit ondula, més que cap altra cosa, un munt de demàs."},"ICON-0290":{"nm":"Fragment de mood board","de":"Si reculls i enganxes en un sol lloc les impressions escampades una a una, un ambient que costava d'agafar treu, difuminat, la seva silueta. Els fragments, recolzant-se els uns en els altres, assenyalen en silenci una sensació que encara no té nom."},"ICON-0291":{"nm":"Llibre de mostres de patrons","de":"La quadrícula d'un embolcall i el teixit d'una gelosia hi queden endreçats, pàgina a pàgina, en un sol volum. Allà on el mateix motiu es repeteix fins al final, no hi ha mandra sinó una promesa: el cor ferm que manté un mateix traç."},"ICON-0292":{"nm":"Full de mostres de vestuari","de":"Encara que sigui la mateixa llum, la textura i l'ombra s'hi posen de manera diferent en cada retall de tela. Abans de triar un vestit d'escenari, aquella nit passada dubtant, resseguint-lo amb els dits una vegada i una altra, queda tota preservada en una petita mostra."},"ICON-0293":{"nm":"Full de restriccions del logotip","de":"Paper que primer escriu, amb claredat, allò que no s'ha de fer. Dins d'un contorn ratllat amb una creu vermella, la llibertat es fa encara més nítida, i just on semblava un camí sense sortida, s'obre, en canvi, un camí nou."},"ICON-0294":{"nm":"Fitxa de referència de color","de":"Un retall de mostra fet a part perquè el color no es pot explicar mai del tot amb paraules. Atrapa, en una petita palma, un cert instant en què el capvespre era més roig que mai, perquè es pugui donar a la persona següent, exactament, «és aquest color»."},"ICON-0295":{"nm":"Targeta d'esbós de disposició","de":"El primer dibuix traçat amb lleugeresa sobre què posar i on. Decidir el lloc és, en el fons, decidir el cor, de manera que entre les línies maldestrament escampades, l'equilibri del conjunt obre, a poc a poc, els ulls."},"ICON-0296":{"nm":"Tauler de notes de materials","de":"Fusta, terra, pedra: els noms de les coses que es poden tocar hi són escrits densament. Un secret que només coneix qui comença llegint el gra amb les mans, allò amb què es construeix ja decideix, a mig camí, en què es convertirà."},"ICON-0297":{"nm":"Paper de calcar","de":"Poses un paper prim sobre l'esbós i resegueixes en silenci les línies. Mentre prens prestat, per un moment, el camí d'un altre, la teva mà aprèn aquell camí, i entre les línies copiades, sense adonar-te'n, hi creix d'amagat una línia ben teva."},"ICON-0298":{"nm":"Cinta de recorregut d'entrada","de":"La gent entra en fila seguint la cinta enganxada llarga a terra. Una sola línia que guia en silenci perquè les passes excitades no s'embolicin: una mà tendra i invisible que sosté l'emoció perquè no s'esfondri."},"ICON-0299":{"nm":"Cartell de guia de l'esdeveniment","de":"Un rètol dret que sosté, en lloc teu, les paraules «per aquí». Una petita amabilitat plantada a cada cruïlla perquè ningú es perdi, que agafa de la mà el dia desconegut de qui hi ve per primera vegada i l'acompanya caminant, en silenci."},"ICON-0300":{"nm":"Etiqueta de número d'estand","de":"Un sol número assignat a cada estand en determina amb claredat el propietari d'aquell espai. Un número petit, però com que és la promesa de «aquí és el teu lloc», dóna un lloc on tornar en un recinte desconegut."},"ICON-0301":{"nm":"Full de conformitat de l'equip","de":"Una única signatura deixada allà on els cors es van posar d'acord per treballar plegats. És només un full prim de paper, però hi porta el pes d'haver triat confiar l'un en l'altre, i cada mà que ajuda a l'esdeveniment comença precisament aquí."},"ICON-0302":{"nm":"Feix de vals de prova","de":"Un feix ben gruixut de vals de prova, lligat per encaixar còmodament en una mà. Com més se'n reparteixen, menys minva i més \"primeres vegades\" continua regalant als altres; un feix de bona voluntat que s'escalfa cada cop que el toques."},"ICON-0303":{"nm":"Full marcador de cua","de":"\"Espereu des d'aquí\", murmura suaument el terra. Quan els cors que respecten el seu torn s'apleguen, fins i tot una llarga cua esdevé un paisatge propi, i un petit senyal converteix la impaciència en calma."},"ICON-0304":{"nm":"Etiqueta de recollida en el lloc","de":"Una petita etiqueta que s'enganxa lleugerament allà on reculls el que vas encarregar per endavant. En l'instant que la tens a la mà, aquell alleujament suau et llisca de les espatlles, un nus on un cor que ha esperat molt finalment pren forma."},"ICON-0305":{"nm":"Tiquet de capsa misteriosa","de":"El goig de triar-ne una sense saber què hi ha dins. Sacseja-la i el cor et batega abans, en sentir-ne el traqueteig, i aquell instant just abans d'obrir-la esdevé el moment del dia més inflat d'esperança."},"ICON-0306":{"nm":"Adhesiu d'intercanvi completat","de":"Un petit segell rodó que anuncia que el bescanvi s'ha fet sense entrebancs. És el punt final llis que queda entre les mans que donen i reben, i un cop enganxat, el tracte per fi s'arrodoneix amb calidesa."},"ICON-0307":{"nm":"Cinta de segellat de registres","de":"Una capsa preciosa es cenyeix amb una cinta que hi dona una volta i la segella en silenci. És una petita súplica de no obrir-la a la lleugera, i la cortesia més silenciosa d'estimar tant allò que hi ha a dins, tot contingut en una sola cinta."},"ICON-0308":{"nm":"Càpsula de nota secreta","de":"Una paraula que volies dir, guardada amb cura dins d'un petit pot. Tanca-la fort com qui sepulta un sentiment que no va poder enviar, i una petita caixa forta al palmell vetlla el temps fins al dia que la tornis a obrir."},"ICON-0309":{"nm":"Petita targeta de retalls","de":"Un retall enganxat que porta impregnat, suaument, l'humor d'aquell dia. Més lleuger que un diari i més artesanal que una fotografia, un full de la mida d'un palmell aferra amb força un dia que altrament se t'escaparia entre els dits."},"ICON-0310":{"nm":"Full de registre de la primera visita","de":"El calfred del dia que vas trepitjar per primera vegada aquesta illa queda en una línia breu. Just abans que l'estranyesa es tornés afecte, el paper guarda en el teu lloc aquell primer sentiment, el més pur, i el conserva llarg temps."},"ICON-0311":{"nm":"Quadre de classificació de records","de":"Un quadre on els records es divideixen amb cura per gra i per branca, anotats un a un. Si amunteguem tots els records en un sol calaix, fins i tot el dia més estimat acaba sepultat; per això, com més preciós és, amb més delicadesa se li reserva el seu lloc."},"ICON-0312":{"nm":"Xip de nota en forma de bafarada","de":"Les paraules que volies dir s'inflen rodones com un globus i floten sobre el paper. Fins i tot una frase que no vas gosar dir en veu alta troba, dins d'aquesta vora rodona, un lleu coratge: un petit passadís càlid perquè el cor s'escapoleixi."},"ICON-0313":{"nm":"Suport de data","de":"Un petit peu que dreça la data d'avui perquè et miri de cara. Tria un sol dia entre els que passen en fila i seu'l al davant i al centre, i fins i tot una data corrent guanya una calidesa que val la pena celebrar."},"ICON-0314":{"nm":"Etiqueta de número de col·lecció","de":"Un número únic assignat a cada cosa que estimes. Col·leccionar és jurar que anomenaràs aquella cosa com l'única del seu tipus al món, de manera que el número a la petita etiqueta porta gravat, ben clar, el pes del cor."},"ICON-0315":{"nm":"Funda d'arxiu","de":"Una fina funda interior on hi vas lliscant, d'un en un, cada objecte que vols guardar molt de temps. Posar alguna cosa a només una capa de distància de la llum i del temps: estimar alguna cosa és, al capdavall, saber-la conservar bé."},"ICON-0316":{"nm":"Cordó de toploader per a photocards","de":"Un cordó prim que permet penjar-se un toploader al coll. És una manera de viure el fandom, caminant tot el dia amb el teu bias a prop del pit, i en aquest fil tan fi hi va lligada tota una jornada de companyia tendra."},"ICON-0317":{"nm":"Suport d'agulla per a photocards","de":"Amb una petita agulla, la photocard es dreça damunt la taula. Estirada és només un full de paper, però dreta esdevé un rostre que et mira als ulls, i crea en silenci un racó on la mirada s'hi pot quedar molta estona."},"ICON-0318":{"nm":"Làmina holo per a photocards","de":"Una única làmina fina on l'arc de Sant Martí regalima segons l'angle. Una capa que atrapa una mica de llum vesteix una carta corrent amb resplendor d'estrelles, una petita màgia on una expressió diferent s'encén cada vegada que et gires el canell."},"ICON-0319":{"nm":"Càpsula protectora per a photocards","de":"Una sola pressió a la cantonada i sembla que fins i tot el cor que hi tens dedicat se't doblega. Una armadura transparent que abraça amb fermesa un full preciós; aquesta mena de cura sempre acompanya el fet d'estimar de debò alguna cosa."},"ICON-0320":{"nm":"Safata d'ordenació per a photocards","de":"Una safata poc profunda on desenes de photocards s'ajeuen ben arrenglerades, veta a veta. Escampades, no són res més que un munt, però alineades es converteixen en una col·lecció, i l'ordre de l'afecte queda gravat a cada gest d'endreçar."},"ICON-0321":{"nm":"Sobre d'intercanvi de photocards","de":"Quan fiques una photocard dins un sobre per lliurar-la, els dits vacil·len un instant. No és acomiadar-la, sinó demanar-li que esdevingui el bias d'algú altre. En l'instant de plegar la solapa, un petit vincle canvia silenciosament de mans."},"ICON-0322":{"nm":"Retolador de decoració per a photocards","de":"El que omple l'espai en blanc no és l'escriptura, sinó el sentiment. Allà on passa la punta, hi brollen petits cors i estrelles, i un full corrent es desperta com un ànim únic al món. Decorar no és res més que un altre nom per confessar."},"ICON-0323":{"nm":"Anella clip per a photocards","de":"Clic, el so d'una pinça que mossega i tanca. Amb aquest únic petit tancament, les cartes que gairebé s'escampaven s'apleguen en una sola filera. Encara que es bellugui tot el dia dins la bossa, ni una sola cantonada es fa malbé. La fermesa és tan silenciosa com això."},"ICON-0324":{"nm":"Bossa de transport per a photocards","de":"Un hàbit s'ha instal·lat, sense adonar-se'n, en la mà que obre i tanca la cremallera. Encara que arribi un ruixat o l'embat de la multitud, només l'interior es manté sec. Guardar el que més estimes al lloc més profund, això és el treball tendre de transportar."},"ICON-0325":{"nm":"Cordó de polsera de trobada de fans","de":"Una fan va recordar molt de temps com de càlides eren les mans del personal en lligar-li el cordó al canell. Un sol nus és el senyal de pertànyer, avui, en aquest lloc. Aquest cordó, enrotllat dues voltes perquè no s'afluixi, reté tot un dia d'emoció."},"ICON-0326":{"nm":"Polsera d'entrada","de":"En el mateix instant de travessar l'entrada, per fi el dins i el fora es divideixen amb claredat. Portada tot el dia, aviat s'acostuma a la pell, i quan arriba l'hora de treure-la deixa una marca fina, com una prova del lloc on has estat."},"ICON-0327":{"nm":"Xip del racó de conversa","de":"Quan s'obre el racó de conversa, un xip rodola. Qui parlarà primer, quina pregunta sortirà, aquest petit atzar canvia tot l'ambient. El caprici d'un sol xip és més entranyable que qualsevol guió escrit."},"ICON-0328":{"nm":"Tiquet de cua per a la signatura","de":"T'agafes el teu lloc a la cua amb un paperet numerat a la mà. Número 142. Mentre comptes els 141 que et precedeixen, el cor ja compta el seu torn abans. L'espera és llarga, però gràcies a aquest paperet fins i tot aquell temps esdevé part de l'emoció."},"ICON-0329":{"nm":"Guant de hi-touch","de":"En l'instant que dues palmes es toquen, el guant rep en el teu lloc aquella calidesa breu. Una mà escalfada tot el dia per a un contacte de mig segon. Ni la roba pot aturar aquell tremolor, i tothom només se n'adona llavors."},"ICON-0330":{"nm":"Agulla per a fotos de record","de":"Clic, i amb un sol so avui queda preservat tal com és. Dins el marc que subjecta l'agulla, fins i tot un somriure incòmode esdevé, algun dia, l'escena més trobada a faltar. Un registre és la cobdícia més tendra per retenir un instant."},"ICON-0331":{"nm":"Etiqueta de llaç per al seient","de":"Un petit llaç penjat al respatller d'un seient oneja encara que no hi hagi vent. Un senyal que algú hi va lligar, un rastre que algú hi va ser. Fins i tot al seient buit després de l'espectacle, només el llaç sembla recordar encara el compàs."},"ICON-0332":{"nm":"Etiqueta de revisió de regals","de":"Una etiqueta s'enganxa a cada regal, un per un. Si s'ha enviat, si s'ha comprovat, si no hi falta res. Fins i tot rebre el cor d'algú necessita la seva pròpia governança de casa, i aquest petit adhesiu enllaça la cura amb la cura sense deixar cap buit."},"ICON-0333":{"nm":"Full commemoratiu","de":"Un full de paper escrit per guardar-lo i tornar-hi molt de temps. El temps que feia aquell dia, el número de seient, fins i tot el títol de l'última cançó. El record es va esborrant, però aquest full, ell sol, no s'esborra. Fins i tot guardar un record necessita una petita fitxa."},"ICON-0334":{"nm":"Anella per a tovallola d'ànim","de":"Passa una anella per la punta de la tovallola i ja no llisca de l'espatlla. Entre eixugar la suor, fer-la voleiar per damunt del cap i tornar-se-la a passar pel coll, un petit enllaç manté els gestos d'animar sense interrupció."},"ICON-0335":{"nm":"Pinça per a pancarta d'eslògan","de":"Unes pinces sostenen fermament els dos extrems d'un eslògan. Així, encara que els dos braços s'aixequin ben alts, les lletres no es plegaran ni voletejaran. Aquí hi ha el secundari més callat, aquell que endreça el missatge lluny de qualsevol mirada."},"ICON-0336":{"nm":"Bossa silenciadora","de":"La cremallera llisca a poc a poc, sense fer soroll. Un silenci dissenyat perquè ni un sol soroll escapi allà on la calma és promesa. La consideració és, de vegades, fer-se inaudible, diu suaument aquesta bossa."},"ICON-0337":{"nm":"Xip de ritme d'aplaudiments","de":"Cada cop que les palmes es toquen, el xip compta el compàs. Clap, clap, clap, i els aplaudiments dispersos, en un instant, s'apleguen en un sol ritme. A la màgia que fa que milers d'aplaudiments esdevinguin un sol alè, un petit xip hi dona un cop de mà en silenci."},"ICON-0338":{"nm":"Carpeta de guia d'ànims","de":"Obre-la i hi trobaràs el mètode d'animar escrit pas a pas. Quin color alçar a cada estrofa, quan afegir un crit. Fins i tot algú que ve per primer cop es fa de la família de seguida amb aquesta única carpeta. Una petita guia per compartir una promesa."},"ICON-0339":{"nm":"Cordó per a ventall de seient","de":"Lliga un cordó al mànec d'un ventall i no caurà encara que se t'escapi de la mà. En un dia calorós, quan les dues mans queden lliures per animar després d'haver ventat, penja balancejant-se del canell. Un sol cordó refresca alhora la calor i l'excitació."},"ICON-0340":{"nm":"Tros de làmina de purpurina","de":"Rep la llum i cada tros la trenca en un angle diferent. Posa'l al palmell i un petit arc de Sant Martí hi tremola, i els colors prenen vida a cada sacsejada. Potser brillar és, al capdavall, repartir la llum en trossets ben menuts."},"ICON-0341":{"nm":"Vareta de pancarta petita","de":"Estén la petita vareta i la tela s'estira tibant amb el vent. Alça-la ben alt amb les dues mans i les lletres arriben més enllà dels seients; plega-la i cap dins un racó de la bossa. La mida d'un cor no es mesura pel llarg d'una vareta."},"ICON-0342":{"nm":"Paquet d'adhesius d'ànim","de":"Cada adhesiu porta gravada una frase d'ànim. A l'agenda, al mòbil, a la cantonada del portàtil: allà on l'enganxis, el dia a dia es tenyeix d'ànim. Un cor afectuós deixa així rastres per tot arreu."},"ICON-0343":{"nm":"Funda protectora d'àlbum","de":"La mà que embolica un àlbum amb una funda ho fa amb cura. Perquè les cantonades no es desgastin, perquè no es descolori al sol. La música s'escolta amb les orelles, però aquest full el recorden les mans. Una armadura del cor per mantenir a prop, molt de temps, allò que estimes."},"ICON-0344":{"nm":"Anella de fundes per a discos","de":"Fica els discos dins les fundes i lliga-les amb una anella, i esdevenen un àlbum de fitxes. El cruixit del paper cada cop que en passes una pàgina és un plaer. Aplegar la música dispersa, ben arrenglerada a la mà: aquesta és la felicitat callada d'un col·leccionista."},"ICON-0345":{"nm":"Separador organitzador d'articles","de":"Amb un sol separador, els articles que gairebé es barrejaven troben el seu lloc. Aquí les photocards, allà els portaclaus, al costat els bastons lluminosos. Endreçar és construir cases per a les coses. En l'instant que es divideixen els compartiments, el desordre es torna ordre."},"ICON-0346":{"nm":"Cordó de segellat per a paquet sorpresa","de":"Lliga la boca d'un paquet sorpresa amb un cordó i el destí de ningú encara està decidit. Fins que no el deslligues, tothom és el protagonista de la seva pròpia esperança. El tremolor dels dits en desfer el segell és, precisament, el goig que aquest cordó ha custodiat."},"ICON-0347":{"nm":"Caixa d'endreçar extres","de":"Els extres es posen en fila per tipus dins una caixa. Postals amb postals, punts de llibre amb punts de llibre. Mira els compartiments que s'omplen cada cop més plens a mesura que creixen, i tot el temps que has anat recollint es veu d'un cop d'ull. Endreçar és, en el fons, fer la llista dels records."},"ICON-0348":{"nm":"Etiqueta de distinció de versió","de":"Hi ha coses que semblen iguals però no ho són. Una etiqueta separa la versió A de la versió B, la primera edició de la reedició. Gràcies a un petit senyal, la confusió desapareix, i al món del col·leccionisme s'hi afegeix una etiqueta ben clara."},"ICON-0349":{"nm":"Nota de control de vendes de primera setmana","de":"La setmana de llançament, i un sol número fa oscil·lar el cor. Marques de comprovació escrites, ben clares, en un bloc de notes. Aplega uns quants dies de registres i esdevé un petit butlletí de notes de suport. Un hàbit curós de traduir un cor afectuós en números."},"ICON-0350":{"nm":"Tap fixador de pòster","de":"Posa un tap a la punta d'un pòster enrotllat i es queda tranquil·lament desplegat. Perquè no s'arrugui mentre dubtes si penjar-lo a la paret o emmarcar-lo. Un petit tap que manté ben recta l'escena que més t'agrada."},"ICON-0351":{"nm":"Peu per a foto dreta","de":"Una foto es manté dreta, una mica inclinada, damunt el peu. En un racó de la taula, a l'angle just per a l'alçada dels ulls. Un invent que fa que la mirada s'hi trobi cada cop que hi passes pel davant. La manera més senzilla de portar un rostre estimat al paisatge de cada dia."},"ICON-0352":{"nm":"Rotlle de cinta d'assaig","de":"S'enganxa cinta al terra per marcar on cal aturar-se. Una marca, dues marques, exactament aquí. Trepitjant els mateixos punts desenes de vegades, el recorregut es grava en el cos. Sota un escenari lluent hi ha, sempre, aquestes marques de cinta tan honestes."},"ICON-0353":{"nm":"Xinxeta de recorregut d'escenari","de":"Una sola xinxeta clavada al terra de l'escenari indica el següent pas. Fins i tot en la foscor, la punta del peu hi troba abans el lloc. Un camí exacte que no es veu, un mapa invisible dibuixat per incomptables assaigs."},"ICON-0354":{"nm":"Tap d'orella per al personal","de":"Posa't el tap d'orella i el clam del públic s'esvaeix una capa, mentre només la veu que transmet les senyals es manté clara. Les orelles del personal, darrere l'escenari, sempre escolten dos mons alhora. Una petita eina per triar el senyal enmig de l'aldarull."},"ICON-0355":{"nm":"Etiqueta de penjador de camerino","de":"Una etiqueta amb nom penja de cada penjador. Vestit 1, vestit 2, vestit del bis. Mira aquest full que enumera l'ordre dels canvis, i l'escenari del dia es dibuixa per endavant en l'ordre de la roba. Un ordre callat que domestica el rebombori."},"ICON-0356":{"nm":"Etiqueta de revisió d'utillatge","de":"Abans de pujar a escena, cada utillatge, un per un, s'omple d'una etiqueta. Si no falta res, si tot està en condicions. El públic no ho sap, però aquest petit control evita accidents. Darrere un escenari que sembla perfecte, hi ha sempre una mà minuciosa."},"ICON-0357":{"nm":"Xip de senyal d'escena","de":"Un xip de senyal passa de mà en mà. Ara, entra. Un moment en què el ritme es transmet sense dir ni una paraula. En la foscor al costat de l'escenari, aquest petit senyal manté tothom sense perdre el compàs."},"ICON-0358":{"nm":"Pedaç de rerescenari","de":"Hi ha una porta per on només pot passar qui porti aquest pedaç. Darrere l'escenari, on els aplaudiments arriben a través de la paret. Un petit tros de roba divideix el davant lluent i el darrere atrafegat. El senyal de la gent que sosté l'escenari."},"ICON-0359":{"nm":"Pantalla d'ocultació de prompter","de":"Una pantalla evita que la llum del prompter s'escapi cap al públic. Només ho veu qui és a l'escenari, sense que qui mira se n'adoni. Un guardià discret del secret de l'escenari, que amaga en silenci una ajuda que no s'ha de descobrir."},"ICON-0360":{"nm":"Funda per al mirall del camerino","de":"Al camerino, un cop acabat l'espectacle, el mirall es cobreix amb una tela. El vidre que ha reflectit incomptables expressions durant tot el dia tanca els ulls per un temps. Allò que un rostre nu, ja sense maquillatge, es troba de cara per últim, no és el mirall, sinó la fosca tranquil·la."},"ICON-0361":{"nm":"Polsera d'entrada per a l'enregistrament previ","de":"Una petita cinta que, un cop cordada, no es desfà fins que la tallen. Per l'única credencial per entrar al públic de l'enregistrament previ, algú va pujar al primer tren en la foscor de la matinada. El pes al canell esdevé tota l'emoció d'un dia."},"ICON-0362":{"nm":"Etiqueta d'espera d'enregistrament","de":"Just abans que s'encengui el llum vermell, la meva feina és lligar en una sola fila l'alè de tothom. En el silenci que espera el senyal, resisteixo callada fins a l'últim moment. En l'instant que em despreneu, per fi s'alça el teló de l'emissió en directe."},"ICON-0363":{"nm":"Xip de posició de càmera","de":"Una petita marca gravada al terra fixa amb precisió el recorregut de sis càmeres. On cal captar la imatge perquè brilli al màxim, el director ja ho sap abans de l'assaig. Una mà que dibuixa per endavant l'interior del pla des de fora d'ell."},"ICON-0364":{"nm":"Etiqueta de prova de so","de":"Colpeges lleugerament el micròfon cap als seients buits. Si la ressonància dura massa, una capa més de material absorbent al sostre. La cura d'afinar la textura del so sense que el públic se n'adoni comença, en silenci, en aquesta petita etiqueta."},"ICON-0365":{"nm":"Llibret de segells del recinte","de":"Cada vegada que passes pel recinte, recolleixes un segell més en un compartiment. A cada taca de tinta escampada hi ha impresos, també, el temps i el batec del cor d'aquell dia. Una pàgina plena esdevé un mapa de passes que ningú més pot imitar, només meu."},"ICON-0366":{"nm":"Cordó de visitant de l'emissora","de":"Sense aquest cordó, la porta del vestíbul no s'obre. Penjat al coll, mentre camines pel passadís pas a pas, el món que fins ahir només vèies en pantalla s'acosta a poc a poc fins a l'abast de la mà."},"ICON-0367":{"nm":"Paquet de cobrepeus d'estudi","de":"El terra de l'estudi és sempre fred i relliscós. Treu-te les sabates, posa't uns cobrepeus fins, i les passes desapareixen sense fer soroll. La càmera capta el ball, no les passes, així que esborrar el so també és una cortesia envers l'escenari."},"ICON-0368":{"nm":"Etiqueta de berenar de camerino","de":"Entre l'assaig i l'emissió en directe, la gana arriba de la manera més honesta. Una petita etiqueta amb el nom a cada aperitiu del camerino, dient de qui és. Aquesta tendresa de reservar-lo és el que fa aguantar tot el dia, llarg i llarg, fins al final."},"ICON-0369":{"nm":"Cinta de notes de visionat","de":"Mires la reproducció i vas anotant. Aquí, la mirada; allà, mig compàs. L'escriptura atapeïda és una carta secreta per al jo de demà. La cinta enganxada al final és una promesa callada de ser una mica millor que ahir."},"ICON-0370":{"nm":"Full d'invitació al showcase","de":"Un sol full de paper pot ser, per a algú, tot un any d'espera. Una frase breu convidant al showcase, nascuda com la invitació més petita del món, portant fins i tot el tremolor dels dits en obrir el sobre."},"ICON-0371":{"nm":"Cordó d'acreditació de premsa","de":"Penjat al coll dels periodistes, es mou pel bell mig del retruny dels obturadors. Les passes que corren atrafegades a la recerca del millor angle, i aquesta mateixa velocitat esdevé el passadís que trasllada la calor de l'escenari cap al món de fora."},"ICON-0372":{"nm":"Quadre d'ordre de salutació final","de":"Perquè ningú no perdi el compàs ni tan sols en l'instant en què els aplaudiments cauen a raig, s'escriu en una línia qui va primer i qui després. L'alineació de la salutació final es prepara amb tanta cura com la primera entrada."},"ICON-0373":{"nm":"Marca de terra per al photowall","de":"Davant el photowall, el terra ja té marcat per endavant on posar les puntes dels peus. Un sol pas de més i el logotip del fons queda tallat. El secret de la posició on surts més radiant queda marcat, en silenci, sota els peus."},"ICON-0374":{"nm":"Polsera d'estrena","de":"Una petita cinta que et corden al canell just abans que s'apaguin els llums del cinema. Quan s'aixeca el teló, tothom coneix, per primer cop a la vida, la mateixa escena en la mateixa foscor. Un petit senyal d'haver estat present en aquell primer instant."},"ICON-0375":{"nm":"Tros de teló commemoratiu","de":"El dia de l'última funció, el teló va baixar a poc a poc després de la darrera reverència. Un tros retallat d'aquella tela, emmarcat. Encara hi persisteix, tebi i sense refredar-se del tot, l'escalfor dels focus i el tremolor dels aplaudiments."},"ICON-0376":{"nm":"Segell de primera aparició pública","de":"Un segell gravat per al dia que et mostres per primer cop al món, per a aquell únic instant. No hi ha una segona primera aparició, així que fins i tot el breu moment en què s'asseca la tinta és un temps que no tornarà mai més."},"ICON-0377":{"nm":"Targeta d'instant escènic","de":"El fotograma més brillant d'un escenari, retallat i posat en una targeta. La música i els llums s'han aturat, però en l'instant de tenir-la a la mà, els aplaudiments d'aquell dia tornen a inflar-se a les orelles. Una petita màgia on una escena aturada torna a la vida."},"ICON-0378":{"nm":"Nota de pose final","de":"Una nota que dibuixa l'angle dels dits i de la mirada que ha de quedar congelat just quan acaba l'última nota. Només qui sap que un sol fotograma final pot marcar dies sencers guarda aquest petit dibuix plegat amb cura."},"ICON-0379":{"nm":"Xinxeta de ciutat de gira","de":"Al mapa, una xinxeta es clava a cada ciutat visitada. El vent de mar de Busan i el migdia de Gwangju queden tots dos clavats a la punta d'aquests petits claus. Uneix els punts en silenci i hi veuràs la llarga línia d'un viatge que va travessar tota una estació."},"ICON-0380":{"nm":"Clip de secció de seients","de":"Divideix desenes de milers de seients en seccions i guia el camí. Perquè ningú s'extraviï, perquè ningú topi amb ningú. Segueix-me i tothom arriba al seu lloc. L'ordre és, al capdavall, una petita amabilitat per a tothom."},"ICON-0381":{"nm":"Etiqueta de porta d'entrada","de":"A la porta, un per un, la gent passa la comprovació al seu torn. L'últim portal que deixa entrar una mà que estreny el tiquet i un cor que batega fort. En l'instant que em travesses, la llarga espera s'acaba i comença l'escenari d'avui."},"ICON-0382":{"nm":"Càpsula guarda-polseres","de":"Encara que el color s'esvaeixi, aquell clam d'aquell dia queda segellat igual. Incapaç de llençar la cinta del canell, l'enrotlles amb cura dins una petita càpsula. Perquè fins i tot un record preciós es mereix un petit racó on ajeure's."},"ICON-0383":{"nm":"Vareta d'intercanvi al recinte","de":"Entre el fan i l'escenari, alguna cosa passa de mà en mà. Pot ser una carta, pot ser un petit regal. Jo obro el camí perquè aquest sentiment arribi sa i estalvi, el pont més atrafegat del recinte."},"ICON-0384":{"nm":"Segell de data de la funció","de":"La data d'aquell dia queda gravada dins un segell rodó i s'atura per sempre. El calendari passa full, però aquest petit cercle, ell sol, es queda en aquell dia. Quan un dia no es vol oblidar, la gent sempre acaba segellant alguna cosa."},"ICON-0385":{"nm":"Pedaç de bossa de gira","de":"Una bossa que ha fet la gira guanya un pedaç més per cada ciutat. Els noms de lloc cosits sobre la tela esdevenen, sense adonar-se'n, un currículum. Fins i tot les cantonades gastades i desfilades queden com a prova d'haver anat plegats a tot arreu."},"ICON-0386":{"nm":"Cordó de rètol de tiquets","de":"Un rètol que oneja al final de la cua d'entrada, la punta ben lligada per un sol cordó. Enmig del paisatge de mans que alcen tiquets, formant una llarga filera, jo marco en silenci el capdavant d'una processó on l'emoció fa cua."},"ICON-0387":{"nm":"Tros de llaç del bis","de":"La nit en què les veus que cridaven per un bis van ser més fortes, un tros del llaç que decorava l'escenari va caure. Com una cançó cantada més llarga perquè feia pena que s'acabés, en aquest tros també hi ha nuada la mala gana de marxar."},"ICON-0388":{"nm":"Ampolla càpsula de missatge","de":"Una sola paraula, plegada amb cura dins una ampolla de vidre. Com un petit vaixell llançat a l'aigua amb l'esperança d'arribar a algú algun dia, jo porto un sentiment i vago a poc a poc sobre el temps. Fins al dia que s'obri, la promesa dorm en silenci a dins."},"ICON-0389":{"nm":"Etiqueta de petita confessió","de":"Unes paraules que no vas poder dir en veu alta, escrites en una petita etiqueta i deixades furtivament al seu lloc. La lletra tremolava, però només la sinceritat era ben clara. Hi ha vegades en què el paper més petit conté el coratge més gran."},"ICON-0390":{"nm":"Bústia de notes d'ànim anònimes","de":"Encara que no hi escriguis el nom, el cor arriba igualment. A cada nota que entra a la bústia s'hi apila, un full a la vegada, l'ànim anònim d'algú. Un recull de tendresa sense rostre, on només la calidesa queda clara encara que no sàpigues qui l'ha escrita."},"ICON-0391":{"nm":"Paper de plecs per a desitjos","de":"Un quadrat de paper es converteix en grua, es converteix en estrella, seguint la punta dels dits. A cada plec, el desig també es plega una capa més. En la forma plegada amb esment hi habita una sinceritat que dura més que les paraules."},"ICON-0392":{"nm":"Cera de segellat amb llaç","de":"Deixa caure la cera i prem el segell amb força, i la carta finalment queda segellada. Ni més ni menys que l'antiga manera de fermar un cor. Sobre la cera vermella que es va refredant, un secret es tanca en silenci."},"ICON-0393":{"nm":"Paper amortidor per a regals","de":"Temerós que el regal es faci mal, l'envolta amb suavitat tot al voltant. A cada plec arrugat hi ha impregnada una súplica de no trencar-se. Una capa de cura, en un lloc que no es veu, que qui rep el regal probablement no notarà mai."},"ICON-0394":{"nm":"Cordó de colors per a cartes","de":"Fins i tot el cordó que lliga una carta té color. El groc és per animar, el blau és per l'enyor. Sentiments que les paraules no poden dir del tot es trien per tonalitat i es nuen. Abans fins i tot de deslligar-lo, la temperatura del cor ja arriba primer a la punta dels dits."},"ICON-0395":{"nm":"Cinta d'ocultació d'escriptura","de":"Una sola cinta que amaga l'escriptura fins al mateix instant de lliurar-la. Guarda una confessió amoïnada de ser descoberta fins a l'últim segon. La sinceritat que es revela quan s'aixeca lleugerament, el pes d'aquell tremolor, jo el conec més de prop que ningú."},"ICON-0396":{"nm":"Xip de frase d'ànim","de":"La nit en què els bastons lluminosos onegen com onades, una sola frase per cridar a una sola veu queda gravada dins el xip. Paraules de promesa que apleguen cors dispersos en una sola línia. Quan es canta tots junts, aquesta frase brilla més que mai."},"ICON-0397":{"nm":"Portaclaus vell de sala d'assaig","de":"Un portaclaus que ha obert i tancat centenars de vegades la porta de la sala d'assaig. La pintura s'ha esquerdat i l'anella s'ha afluixat, però hi queda, com una pàtina de mans, la suor de l'època més barroera. Estar gastat vol dir haver-hi romàs tant de temps."},"ICON-0398":{"nm":"Tros de llapis de maquillatge d'escenari","de":"El maquillatge d'escenari només queda acabat sota els focus. Un tros d'aquell color intens. En el rastre aplicat amb fermesa perquè no s'escampés amb la suor hi ha impregnada, intacta, la cura de fer arribar l'expressió fins als seients més llunyans."},"ICON-0399":{"nm":"Estoig per a olives d'auricular","de":"Les petites olives que et deixaven sentir la teva pròpia veu dalt de l'escenari. Quan s'acaba l'espectacle, les ajeus amb cura dins l'estoig. Com més a prop t'ha portat la música alguna cosa, més ganes tens de guardar-la amb cura."},"ICON-0400":{"nm":"Etiqueta de taquilla personal","de":"Al final del passadís de la residència, una etiqueta amb nom a cada taquilla. Una lletra petita que diu de qui és el lloc converteix un espai desconegut en una llar. Tenir el teu propi compartiment és un permís tendre per quedar-t'hi."},"ICON-0401":{"nm":"Flascó portàtil de cura de la gola","de":"Entre assaig i assaig, s'empassa a poc a poc un glop d'aigua tèbia. La gola és un instrument que la cantant té en préstec, i aquest petit flascó, omplert abans que es refredi, guarda per endavant la primera nota de demà. Un cor que estima sempre és així de silenciós."},"ICON-0402":{"nm":"Xinxeta d'avís d'horari","de":"Sobre un dia atapeït minut a minut, una xinxeta assenyala la casella següent. Entre aquelles files denses, el més benvingut és una casella buida. El temps en què es pot mirar per la finestra s'hi amaga, ben petit."},"ICON-0403":{"nm":"Clip de manta del camerino","de":"Una tarda en què, amb el maquillatge ja fet, et vas endormiscar recolzada a la cadira, algú et va posar suaument una manta a les espatlles. Aquest clip, mossegant-la perquè no llisqués, sosté en silenci l'escalfor d'aquell gest fins que arriba l'hora de pujar a l'escenari."},"ICON-0404":{"nm":"Mostra petita de perfum","de":"Si el toques lleugerament a l'interior del canell, l'aroma floreix només dins un pam de distància. No cal que s'escampi lluny. És un rastre que només noten els qui s'hi han acostat, més secret per això, i per això més meu."},"ICON-0405":{"nm":"Etiqueta de bugada de la roba d'assaig","de":"Per més vegades que la rentis, l'olor de suor que ha calat endins de la roba mai no acaba de desaparèixer. Mentre pleguis la roba d'assaig estesa al sol i ja seca i tova, penses que aquella marca que no s'esborra és, en realitat, el rastre més honest."},"ICON-0406":{"nm":"Làmina de gel d'il·luminació","de":"Si hi encaixes un full de film de color prim, la llum blanca s'escampa com una posta de sol, i si n'hi afegeixes un altre a sobre, hi baixa l'alba. Rere el teló, una mà que conté l'alè vesteix fins i tot la llum, decidint amb quina estació tenyirà l'escenari."},"ICON-0407":{"nm":"Tapa de lent de focus","de":"Fins i tot amb la càmera apagada, algú obre aquesta petita tapa per netejar la lent. Per a la propera escena que encara no s'ha filmat. Sobre el temps que no queda captat a la pantalla, la mà més atrafegada ja hi ha ajustat l'enfocament."},"ICON-0408":{"nm":"Panell reflector d'escenari","de":"Hi ha un panell que, sense brillar per si mateix, torna la llum rebuda cap a un rostre ombrejat. El centre de l'escenari és tan lluminós perquè, a la vora, hi ha el braç d'algú que, en silenci, en fixa l'angle i la reflecteix."},"ICON-0409":{"nm":"Funda de filtre de color","de":"Si encaixes una llum blava dins la funda transparent, tot el pati de butaques es converteix en mar, i si la canvies per vermella, hi cau una posta de sol. La màgia que fa que el mateix escenari es converteixi en una altra estació amb un sol color comença en aquesta prima capa única."},"ICON-0410":{"nm":"Agulla numerada de llum","de":"Cada un dels nombrosos focus porta un petit número. Quin s'encén i quin es queda adormit, el flux de l'espectacle d'aquesta nit ja està organitzat per endavant segons l'ordre d'aquests números. Rere un teló enlluernador sempre hi ha estesa una llista minuciosa."},"ICON-0411":{"nm":"Marcador de cinta lluminosa","de":"A terra, amb l'escenari a les fosques, una cinta fluorescent il·lumina en silenci el lloc on el peu s'ha d'aturar. Invisible des de les butaques, però les puntes dels peus de l'intèrpret palpen aquesta llum feble per trobar el seu lloc. Fins i tot en la foscor hi ha un guia tendre."},"ICON-0412":{"nm":"Panell de bloqueig d'ombres","de":"Un panell que bloqueja la llum que s'escola per deixar caure una ombra ben nítida. Manejar la foscor és, al capdavall, manejar la llum, així que què s'ha de mostrar es decideix primer per què s'amaga en silenci."},"ICON-0413":{"nm":"Xip mesurador de lluminositat","de":"Un petit xip que mesura la claror d'un espai llegeix xifres sobre la palma de la mà. Perquè massa llum, o massa foscor, fan mal als ulls. Aquest xip guarda en silenci aquell punt just invisible on una persona es troba més còmoda."},"ICON-0414":{"nm":"Pantalla de focus puntual","de":"Una pantalla que s'afegeix perquè el focus puntual no s'escapi cap a un lloc equivocat. Concentrar la llum en una sola persona és una atenció tendra. En l'instant en què hi entres, dins d'aquell cercle de llum, el món mira, per un moment, només aquesta persona."},"ICON-0415":{"nm":"Joc de puntes per a auriculars","de":"Un parell de puntes que encaixen just a l'orella. Si la mida s'allunya encara que sigui una mica, el so s'escapa, i tan bon punt s'escapa, es perd el compàs. Una cançó sobre l'escenari, sense la més mínima vacil·lació, de vegades comença precisament en aquest petit parell de goma."},"ICON-0416":{"nm":"Velcro per a cables","de":"Una tira de velcro que lliga en un sol feix els fils enredats. Com menys ningú no ho veu, rere l'escenari, més brilla l'ordre. La netedat d'un feix de cables sosté en silenci el so que flueix, sense tremolar, davant del públic."},"ICON-0417":{"nm":"Etiqueta de comprovació de línies","de":"Etiquetes escrites a mà en desenes de fils, dient quin instrument és cadascun. Només quan cada lletra torçada d'aquella escriptura guarda el seu lloc, els sons que sonaven separats acaben fluint junts en una sola cançó."},"ICON-0418":{"nm":"Coixinet de silenci","de":"Un únic coixinet de silenci que engoleix en calma tant les passes com els tremolors. Es col·loca allà on cal, de debò, la quietud. El so més clar de vegades neix només sobre aquest terra silenciós d'on no s'escapa cap soroll."},"ICON-0419":{"nm":"Fitxa de prova de so","de":"Una fitxa que s'escalfa a la mà mentre s'ajusta el so abans de l'espectacle. Cada vegada que s'acaba de revisar un micròfon, un altaveu, canvia de mà. La perfecció de l'escenari principal es forja pas a pas dins d'aquest assaig silenciós."},"ICON-0420":{"nm":"Tapa protectora de micròfon","de":"Com que és el lloc on han tocat tantes veus, netejas amb més cura aquesta tapa que envolta la punta del micròfon. És el recipient que acull la cançó, així que per a la cantant és com una altra mà. Mentre la neteges, ja t'imagines la primera estrofa de demà."},"ICON-0421":{"nm":"Clip de filtre antipop","de":"Una fina malla estesa entre els llavis i el micròfon. Gràcies al petit clip que sosté aquesta pantalla, l'alè que s'escapava aspre acaba polit en una veu rodona i suau que flueix."},"ICON-0422":{"nm":"Etiqueta de rack de so","de":"Rere l'escenari fosc, entre prestatgeries d'equip apilades una damunt l'altra, una petita etiqueta penja per no perdre's. L'origen del so esplèndid que omple les butaques sempre està, així, ben ordenat en aquests racons ombrívols."},"ICON-0423":{"nm":"Agulla de reixeta d'altaveu","de":"Una agulla que fixa amb fermesa la malla de l'altaveu. La finestra per on surt el so és la primera a rebre la pols, així que una fina malla en guarda el to. Tot el que arriba a l'orella porta a sobre una capa invisible de protecció."},"ICON-0424":{"nm":"Adhesiu marcador de passos","de":"Adhesius de posicionament enganxats punt per punt a terra. El secret perquè una coreografia de grup encaixi com una fulla d'espasa s'amaga, en realitat, sota els peus. Damunt d'incomptables marques promeses on desenes de balladors trepitgen el mateix punt, es dispersen i es tornen a reunir."},"ICON-0425":{"nm":"Disc de pràctica de girs","de":"Un disc de pràctica que gira i gira sobre si mateix. Per vèncer el marejament, primer s'aprèn a clavar la mirada en un sol punt. Per molt de pressa que giri, per no deixar mai aquell punt, l'equilibri es grava a poc a poc dins el cos."},"ICON-0426":{"nm":"Rotlle de cinta per al genoll","de":"Un rotlle de cinta que embolica fermament el genoll. Les articulacions que han saltat i aterrat milers de vegades acaben callades, però aquesta capa sosté en silenci aquest silenci. Rere un cos que resisteix fins al final, sempre hi ha la cura d'algú."},"ICON-0427":{"nm":"Placa d'alineació de puntes","de":"Una placa que fixa amb ordre l'angle de les puntes dels peus. Diuen que la dansa es completa més a les puntes dels peus que a les dels dits. Desenes de puntes esteses en la mateixa direcció es reuneixen i teixeixen la màgia de fer que molts semblin un de sol."},"ICON-0428":{"nm":"Estora antilliscant de sala d'assaig","de":"Una estora antilliscant estesa al terra de la sala d'assaig. Per ballar amb tota llibertat, primer cal sentir-se segur. Només sobre un terra on es pot rodolar sense por de caure floreixen, finalment, els moviments més audaços i sense por."},"ICON-0429":{"nm":"Targeta de descomposició de moviments","de":"Una targeta que dibuixa la coreografia trossejada compàs a compàs. Per difícil que sigui un moviment, si es divideix casella per casella, acabes seguint-lo sense adonar-te'n. El flux tan suau com l'aigua sobre l'escenari és fet d'aquests dibuixos apresos a trossos i reunits."},"ICON-0430":{"nm":"Agulla de cortina cobre-mirall","de":"Una agulla que sosté la cortina que tapa per un moment el mirall de la sala d'assaig. Cal també un temps per ballar només amb el sentit del cos, sense cap reflex. Se sap que, en el moment de tapar el mirall, la música per fi penetra fins a la pell."},"ICON-0431":{"nm":"Perla de comptar el compàs","de":"Toc, toc: a cada compàs, empenys una perla amb la punta dels dits mentre comptes. Tangible, com un mètode antic de comptar. El compàs, l'esquelet de la música, només arrela ferm al cos quan s'aprèn a través d'una cosa que es pot tocar així."},"ICON-0432":{"nm":"Cinta de control d'escalfament","de":"Una cinta de control que marca si ja t'has escalfat del tot. Abans de l'assaig de debò sempre ve primer una preparació serena. Més que penedir-se després d'una lesió, lligar-se una cinta i despertar el cos a poc a poc fa que, al final, es pugui ballar més temps."},"ICON-0433":{"nm":"Pinça numerada de vestuari","de":"Una pinça que mossega un número a cada vestit perquè els diversos conjunts no es barregin. Entremig d'un canvi de roba sense alè, confondre'n només un ja és un desastre, així que cada peça té el seu torn escrit ben clar. Fins i tot el bullici és elegant quan l'ordre el sosté."},"ICON-0434":{"nm":"Coixinet d'agulles del taller de costura","de":"Un coixinet d'agulles deixat en un racó del taller de costura. Aquí s'hi atura la mà que ha reomplert en silenci costures esquinçades i botons caiguts. Rere una roba impecable sobre l'escenari s'amaga la cura de punts de cosir que mai no han vist l'escenari."},"ICON-0435":{"nm":"Anella de retalls de roba","de":"Una anella que enfila en una peça sola retalls de tela sobrants. Es guarda per endavant el mateix teixit per si el vestit principal es fes malbé. Aquesta petita previsió, guardada amb l'esperança que no passi res, salva el vestit d'escenari precisament quan arriba un contratemps."},"ICON-0436":{"nm":"Paquet de botons de recanvi ràpid","de":"Un paquet de botons que es poden cosir a l'instant en cas d'urgència. Just abans de l'espectacle, si un botó salta, tot el camerino s'esvalota d'un plegat. És un petit però fiabilíssim estoig de primers auxilis que apaga en un instant aquella emergència breu i vertiginosa."},"ICON-0437":{"nm":"Subjector de cinturó d'escenari","de":"Un subjector que aguanta amb fermesa el cinturó del vestit d'escenari. Perquè la roba no es desfaci per molt que es salti i es giri. La llibertat que es gaudeix plenament sobre l'escenari ve, al capdavall, d'haver cordat amb cura allò que ningú no veu."},"ICON-0438":{"nm":"Plomall de plomes","de":"Com que sota els llums fins i tot una petita pelussa destaca, es passa suaument el plomall de plomes pel vestit. Just abans de posar el peu a l'escenari, aquell darrer gest tendre d'arreglar la roba sempre pertany a aquesta ploma suau."},"ICON-0439":{"nm":"Etiqueta de xancletes del camerino","de":"Una etiqueta amb el nom a cada xancleta del camerino. En aquell petit rètol que diu de qui és, hi cap, en silenci, l'alleujament de saber que formem el mateix equip. Aquella habitació on es descalcen i estiren els peus es converteix en la llar més còmoda darrere l'escenari."},"ICON-0440":{"nm":"Placa de pinces d'estilisme","de":"Una placa de pinces que subjecta els mechons mentre es pentina. Mentre s'allisa cabell a cabell, els dits confien per un moment a aquesta pinça els cabells que volen escampar-se. L'ordre, al capdavall, és fet d'aquestes petites pauses reunides."},"ICON-0441":{"nm":"Càpsula organitzadora d'agulles imperdibles","de":"En una matinada amb una costura esquinçada, obres la tapa de la càpsula i hi trobes un argent petit i fred, ben arrenglerat. La mà que sosté el vestit amb més fermesa des de dins, invisible, l'agulla imperdible sempre treballa en silenci darrere l'escenari."},"ICON-0442":{"nm":"Drap de neteja de lents","de":"Buf, un alè i frega en cercles, i el món entelat es torna clar. T'agrada tant aquell instant breu que no pares de netejar la lent. Un petit tros de sol de primavera que aclareix la vista d'algú en el seu lloc."},"ICON-0443":{"nm":"Peus de goma per a trípode","de":"Encaixa goma a les tres puntes i el terra deixa de cruixir. Mentre aquells petits punts engoleixen el tremolor, el paisatge de la pantalla es torna quiet com si fos mentida. L'estabilitat sempre comença en silenci sota els peus."},"ICON-0444":{"nm":"Funda impermeable per a càmera","de":"Encara que les gotes de pluja regalimin, la lent capta el món seca. En una tarda ennuvolada de rodatge a l'aire lliure, un impermeable transparent es col·loca suaument sobre la càmera. Perquè el que és preciós s'ha d'embolicar abans que es mulli."},"ICON-0445":{"nm":"Cinta marcadora de rodatge","de":"Posa't aquí, gira't cap allà, marques curtes i de colors assenyalen el camí clarament sense dir cap paraula. Encara que es despenja sense enyorança quan acaba l'espectacle, les puntes dels peus, ja acostumades, recorden aquell lloc molt de temps."},"ICON-0446":{"nm":"Clip separador de talls","de":"Una petita pinça que mossega d'un cop els papers que volen escampar-se. Amb un clic alegre, l'ahir i l'avui queden ben lligats. Ordenar és un hàbit tendre de retenir en silenci allò que gairebé s'havia perdut."},"ICON-0447":{"nm":"Placa de balanç de blancs","de":"Si mostres una placa blanca a la pantalla, els colors troben el seu lloc sense fer soroll. Ni la posta groguenca, ni l'alba blavosa, cap mentida. Una placa que coneix el blanc de veritat fa que la resta de colors parlin amb honestedat."},"ICON-0448":{"nm":"Llauna de memòries","de":"Dins d'una petita llauna, xips de records dormen plàcidament. Obres la tapa i, clic, escenes de l'estació passada vessen a la palma de la mà. El record roman guardat amb cura dins d'una llauna tan sòlida com aquesta."},"ICON-0449":{"nm":"Visera per a monitor","de":"Envolta el monitor amb una visera negra i el reflex s'atura de cop. Fins i tot a la vora d'una finestra inundada de sol, la pantalla no perd el seu color. Per veure-hi bé cal primer bloquejar la llum parasita, això és el que ens diu, en silenci, la visera."},"ICON-0450":{"nm":"Agulla insonoritzant de plató","de":"Una petita agulla encaixada a l'escletxa de la porta talla en silenci el soroll de fora. Ni les passes del passadís ni el riure de l'habitació del costat arriben fins aquí. Perquè per captar un so net, primer cal construir el silenci."},"ICON-0451":{"nm":"Paquet d'esponges de maquillatge","de":"Un feix d'esponges suaus i toves apilades ben ordenades. Si hi dónes uns copets de pols amb la punta dels dits, la cara s'il·lumina un to més clar. Rere cada somriure radiant sobre l'escenari s'amaguen sempre aquests gestos suaus."},"ICON-0452":{"nm":"Estoig d'agulles de cabell","de":"Una llar endreçada per a les petites agulles que es perden tan fàcilment. Obres la tapa i files d'argent et donen la benvinguda, ben arrenglerades. Disperses, es tornen invisibles, però reunides, donen seguretat: fins i tot les coses més petites necessiten casa pròpia."},"ICON-0453":{"nm":"Estoig esterilitzador de pinzells","de":"Pinzells que han sostingut color tot el dia prenen una dutxa de llum ultraviolada dins l'estoig. Mentre una llum invisible neteja el que ja era vell, les cerres de demà surten fresques com noves. La neteja també és un plec de la cura."},"ICON-0454":{"nm":"Bossa de malla per a borles","de":"Borles rodones recuperen l'alè, en calma, dins la bossa de malla. Quan l'aire hi circula per la trama, la suavitat dura més temps. Una borla ben eixuta ja porta a dins, per endavant, la lluentor de demà al matí."},"ICON-0455":{"nm":"Tap d'esprai fixador","de":"Xxx— un sol raig i ni el vent no mou un sol cabell. Un petit tap que aguanta tota la nit un pentinat treballat amb cura. Sobre els cabells fixats amb fermesa, la llum radiant hi vessa com si s'hi trenqués."},"ICON-0456":{"nm":"Tapa de pinzell de llavis","de":"Una petita tapa que embolica suaument la fina punta de cerres. Sacsejat dins la bossa, el pinzell es manté recte i net. Cuidar un pinzell tan petit completa un sol traç de color sobre els llavis."},"ICON-0457":{"nm":"Mirall de número d'espera","de":"Al costat del número que anuncia el teu torn, hi ha, discret, un miralleret. Just abans de pujar a l'escenari, és el lloc per arreglar per última vegada un mechó despentinat. Fins i tot els nervis s'alleugereixen una mica en veure's reflectits."},"ICON-0458":{"nm":"Tovallola de canell","de":"Una banda suau que eixuga la suor del front amb un sol gest del canell. Com més intensa és la coreografia, més sovint hi va la mà. Un petit consol sobre el canell que t'acompanya en cada instant sense alè."},"ICON-0459":{"nm":"Etiqueta de bossa d'atrezzo","de":"Encara que deu bosses idèntiques facin cua al camerino, no hi ha confusió possible. Cada bossa porta una etiqueta amb el nom que en diu clarament el propietari. Escriure 'meu' en alguna cosa és una marca petita però tendra."},"ICON-0460":{"nm":"Xinxeta de reserva de sala d'assaig","de":"Qui farà servir avui aquesta sala d'assaig? Una petita xinxeta clavada al tauler de la porta reparteix el temps en silenci. Els cors que esperen el següent torn fan cua, tranquils, darrere aquesta única xinxeta."},"ICON-0461":{"nm":"Anella cobridora de rellotge de paret","de":"Una tapa transparent es posa suaument sobre el rellotge de paret per aturar la pols. Les busques que faciloneixen no s'entelen i el temps flueix clar. Les coses precioses sempre necessiten una capa invisible de protecció."},"ICON-0462":{"nm":"Coixinet protector de terra","de":"Un coixinet prim enganxat sota la pota d'una cadira evita per endavant les ferides del terra de fusta. Arrossegar-la no la ratlla, moure-la no hi deixa cap marca. Cuidar el terra sense que es vegi és el secret perquè duri molt de temps."},"ICON-0463":{"nm":"Xip senyalitzador de zona sense begudes","de":"Deixem aquí les begudes per un moment, demana amb dolçor el petit xip. Perquè les partitures i l'equip queden fets malbé si es mullen. Fins i tot una paraula com 'prohibit' es converteix en una atenció càlida quan es diu així."},"ICON-0464":{"nm":"Etiqueta del botó de ventilació","de":"Quan vulguis canviar l'aire carregat, prem aquí, indica el petit rètol al costat del botó. Poder respirar de nou, sorprenentment, comença en silenci amb un senyal tan petit com aquest."},"ICON-0465":{"nm":"Peu de goma per a altaveu","de":"Un peu de goma sota l'altaveu engoleix suaument la vibració sorda. Com els greus ja no s'escampen pel terra, el so es fa molt més nítid. Una bona ressonància només s'aclareix sobre una base ben ferma."},"ICON-0466":{"nm":"Imant numerat de taquilla","de":"Un petit imant numerat que s'enganxa d'un cop a la porta de la taquilla. En quin compartiment dormiran avui les meves coses? Encara que el lloc canviï cada dia, un sol imant fa que un compartiment sigui meu en un moment. La pertinença ve d'una marca tan lleugera com aquesta."},"ICON-0467":{"nm":"Eixugamirall","de":"Un sol gest sobre el mirall i el baf desapareix net del tot. L'instant en què el meu rostre, entelat, es torna clar de sobte. Per veure'm de debò, primer cal netejar amb calma el que enfosqueix la vista."},"ICON-0468":{"nm":"Coixinet amortidor de porta","de":"Un amortidor tou encaixat a l'escletxa d'una porta que es tanca de cop. Amorteix suaument tant el cop sec com un pessic de mà. Una petita seguretat que insereix, d'amagat, una capa de tendresa entre els xocs bruscos."},"ICON-0469":{"nm":"Bloc cobre-cables","de":"Una tapa robusta fa de pont amb fermesa sobre els cables que travessen el terra. Ni els peus ensopeguen ni ningú trepitja els fils. La quietud ferma d'un bloc que guarda el camí sense bloquejar-lo."},"ICON-0470":{"nm":"Con d'avís de terra lliscant","de":"Un con groc s'alça sol sobre el terra mullat, avisant en silenci. Camina amb compte, a poc a poc. Rere l'escenari lluminós hi ha sempre dret aquest petit vigilant que vetlla, callat, per cada passa."},"ICON-0471":{"nm":"Barra de llum d'emergència","de":"Un sol raig de llum s'encén de cop en un passadís sense electricitat. Perquè no et perdis ni en la foscor, la claror d'emergència et queda a la mà. Al món hi ha, sens dubte, coses que brillen més fort en el moment més fosc."},"ICON-0472":{"nm":"Tapa protectora de barana","de":"Una tapa arrodonida posada a l'extrem d'una barana d'escala embolica suaument la cantonada esmolada. Fins i tot un cop de mà distret no farà mal. Cobrir amb calma allò que és afilat també és una atenció cap a algú."},"ICON-0473":{"nm":"Coixí de vora d'escenari","de":"Un coixí tou envolta la vora de l'escenari. Perquè, tot i el contacte d'una punta de peu en una coreografia intensa, no en surti cap blau. Rere cada moviment resplendent, una protecció invisible balla al mateix compàs."},"ICON-0474":{"nm":"Disc marcador de terra","de":"Un disc rodó posat a terra diu, en silenci, 'posa't aquí'. Tant qui fa cua com qui busca el seu lloc s'atura, tranquil, en veure aquest únic punt. L'ordre creix a partir d'una marca petita."},"ICON-0475":{"nm":"Corretja de llanterna","de":"Enrotlla un cop al canell la corretja que penja de la llanterna, i no perdràs la llum ni en la foscor. Sense la por de deixar-la caure, les dues mans queden lliures: un petit però fiable llaç d'una volta."},"ICON-0476":{"nm":"Corda de tall de pas","de":"Si us plau, no passeu d'aquí, traça amb suavitat una sola corda la línia. Una frontera amable que separa en silenci el que és perillós del que és segur. Aturar algú també és una manera de protegir-lo."},"ICON-0477":{"nm":"Xinxeta de verificació de seguretat","de":"A cada lloc on acaba la inspecció, una petita xinxeta hi deixa el seu 'verificat'. Un punt com el segell d'una ment que ho ha repassat tot sense deixar-se res. La seguretat no és res de grandiós, sinó la suma de marques deixades una a una."},"ICON-0478":{"nm":"Miniclaqueta","de":"Amb el clac sec que talla el primer compàs, l'alè de tots els presents s'ajusta d'un cop. Per petita que sigui, la línia de sortida de cada escena és sempre aquest únic compàs. Aquí s'obre l'inici emocionant del rodatge."},"ICON-0479":{"nm":"Coberta de micròfon de taula","de":"Una coberta suau es posa suaument sobre el micròfon de la taula. Fins i tot un alè que esclata bruscament arriba net, sense soroll de fons. El que embolica una veu amb més escalfor és aquesta capa petita i suau."},"ICON-0480":{"nm":"Peça de panell acústic","de":"Una peça de panell absorbent de so encastada a la paret recull en silenci l'eco. Com que el so ja no rebota i s'escampa, la cançó s'hi acumula molt més clara. Una bona ressonància neix de perfeccionar el silenci amb cura."},"ICON-0481":{"nm":"Ganxo per a auriculars","de":"Penjar els auriculars aquí és una petita promesa. Deslligar el cable i deixar-lo endreçat perquè la propera persona el pugui agafar de seguida. Un sol ganxo porta un ordre serè a una cabina atrafegada."},"ICON-0482":{"nm":"Llum d'enregistrament","de":"En l'instant en què s'encén la llum vermella, tots els alens dins la cabina s'aturen. Un senyal que fa parar fins i tot les passes rere la porta. Captar el so comença per guardar aquest silenci profund."},"ICON-0483":{"nm":"Estoig organitzador de pues","de":"Pues endreçades en compartiments segons el color. El gruix i el pes forgen els costums de la punta dels dits. Just abans de l'escenari, aquella precisió d'agafar-ne una a la primera sense mirar creix aquí."},"ICON-0484":{"nm":"Etiquetadora de cables","de":"Per no perdre's entre desenes de fils enredats a terra, cal escriure un nom a cada extrem. Només qui ha marcat d'on ve i cap on va no vacil·la amb la mà en la foscor."},"ICON-0485":{"nm":"Botó giratori de minimescladora","de":"Gira'l l'amplada d'un dit i la textura de la veu canvia. Puja'l i es fa aspra, baixa'l i s'esvaeix; és qüestió de palpar aquell únic punt entremig. El toc més delicat forja el canvi més gran."},"ICON-0486":{"nm":"Volandera de fixació de peu","de":"El que sosté l'escenari no són els llums esplendorosos sinó aquest petit anell. Aguantant fermament la vibració, resisteix en silenci al seu lloc, sense que ningú el vegi."},"ICON-0487":{"nm":"Etiqueta de desmuntatge de decorat","de":"Fins i tot tornar a ajeure amb cura tot el que s'havia aixecat segueix un ordre clar. Un full que indica on afluixar i on traslladar. Les mans que ho desmunten són tan hàbils com les que ho van construir."},"ICON-0488":{"nm":"Xip de sobre d'objectes perduts","de":"Cada objecte que algú ha deixat caure porta la seva pròpia història. Guardar-lo en un petit sobre a l'espera del nom del propietari és una tendresa que, per un moment, també acull el cor de qui l'ha perdut."},"ICON-0489":{"nm":"Marcador de recorregut de neteja","de":"Segueix les fletxes dibuixades a terra i tot queda net sense buits. Fins i tot una escombra necessita un camí per no girar en va. El racó més brillant es troba al final de les passes millor traçades."},"ICON-0490":{"nm":"Vareta guia de sortida","de":"Quan s'apaga l'últim aplaudiment, aquesta vareta obre el camí. Una mà que deixa anar, a poc a poc i sense fer mal, els cors encara excitats. Fins i tot en guiar el final hi ha una atenció càlida."},"ICON-0491":{"nm":"Bola de retalls de cinta","de":"Enrotlla en una bola els retalls que sobren i tornen a tenir utilitat. Igual que un caparró a punt de llençar-se s'ajunta fins a formar una bola ferma, un cor estalviador creix des de la punta dels dits."},"ICON-0492":{"nm":"Tap numerat de cadira","de":"Cada cadira del pati de butaques ha de portar un número perquè ningú no es perdi. Un petit tap que assigna un lloc converteix el neguit de qui arriba per primer cop en un alleujament tranquil."},"ICON-0493":{"nm":"Xinxeta classificadora de residus","de":"Una petita xinxeta per separar i encaixar el paper i el plàstic. Barrejats, són només escombraries; separats, es converteixen en recursos que es poden reutilitzar. Classificar és un gest tendre que torna als objectes una segona vida."},"ICON-0494":{"nm":"Etiqueta de retorn d'equip","de":"Allò que es demana prestat ha de tornar sempre al seu lloc. A cada gest de retornar-ho amb l'etiqueta posada, la confiança s'acumula capa a capa. Qui ho retorna bé, la propera vegada torna a demanar prestat amb el cor tranquil."},"ICON-0495":{"nm":"Clau de sortida del camerino","de":"Et treus tot el maquillatge i el vestuari d'avui i, per últim, tornes aquesta clau. Retornar en sortir allò que vas rebre en entrar. El principi i el final d'un dia queden guardats a la mateixa mà."},"ICON-0496":{"nm":"Estoig de borla","de":"Una borla suau perd el seu gra si es prem. Per això s'ajeu amb cura dins d'una llar rodona. Per conservar la suavitat molt de temps, primer cal tractar-la amb suavitat."},"ICON-0497":{"nm":"Xip d'ombra d'ulls","de":"Un únic punt de color posat a la parpella canvia del tot l'expressió. El to adormit dins d'un petit xip només es desperta sota els llums, i afegeix profunditat a la mirada girada cap a l'escenari."},"ICON-0498":{"nm":"Tapa de pinzell de coloret","de":"Quan la punta de les cerres es fa malbé, també s'ensorra el color que dona. Posar-hi un petit capell per protegir aquest gra és l'hàbit silenciós de qui vol tenir a prop, molt de temps, una bona eina."},"ICON-0499":{"nm":"Paleta de llavis prima","de":"Una paleta gruixuda ocupa tot l'espai dins la bossa. Una mà que sap que n'hi ha prou amb una única línia fina retallada. És el moment en què retallar es converteix, precisament, en l'acte de saber què endur-se."},"ICON-0500":{"nm":"Protector de màscara de pestanyes","de":"Perquè les pestanyes aixecades una a una no s'escampin, un petit protector en guarda amb suavitat la corba. El que s'ha alçat amb cura s'ha de guardar amb cura, ens recorda el temps davant el mirall."},"ICON-0501":{"nm":"Estoig de bastonets de cotó","de":"Una petita llar perquè els bastonets de cotó blancs no s'escampin per tot arreu. Un gest que sempre es té a prop per a un darrer retoc. Els preparatius més menuts omplen els buits del gran escenari."},"ICON-0502":{"nm":"Recanvi de goma per a rínxol de pestanyes","de":"Quan la goma s'endureix, arrissar les pestanyes fa una petita punxada. Tenir a mà recanvis per canviar-la neix d'una tendresa que té en compte fins i tot els dolors més petits."},"ICON-0503":{"nm":"Pinzell de corrector","de":"Amb la punta fina del pinzell esborra suaument les ombres. És portar claredat allà on la llum no arribava. Una mà que afegeix llum en lloc de tapar defectes acaba l'obra amb molta més gràcia."},"ICON-0504":{"nm":"Sedàs de pólvores","de":"Tamisar un cop la pols fina fa que s'estengui suau, sense grumolls. Aquell esforç de passar-la un cop més pel sedàs. La dedicació, al final, es nota en el dit que fa un pas més."},"ICON-0505":{"nm":"Pinça enrotlladora de serrell","de":"Una pinça que enrotlla el serrell i el manté un moment. Mentre s'espera, la forma s'assenta amb calma. L'elegància floreix allà on hom sap esperar sense pressa."},"ICON-0506":{"nm":"Cullereta de cera per als cabells","de":"Abans que la cera toqui les mans, es recull amb aquesta petita cullera. La mesura de prendre exactament el que cal. Una mà que sap usar sense excés crea la textura més natural."},"ICON-0507":{"nm":"Estora per a la planxa rissadora","de":"Una planxa rissadora ben calenta no es pot deixar en qualsevol lloc. Una sola estora que la sosté protegeix tant la taula com les mans. Allà on es maneja la calor, sempre cal un racó segur per reposar."},"ICON-0508":{"nm":"Mostra d'oli per als cabells","de":"Una sola gota basta per a la brillantor, i queda ben guardada en un petit flascó de mostra, ficat discretament en un racó de la bossa. Un flascó petit, més que un de gran, acaba a l'abast de la mà molt més sovint."},"ICON-0509":{"nm":"Pinta netejadora de raspalls","de":"Amb el rasclet es pentina a poc a poc els cabells enredats al raspall. Tenir cura de les eines és un ritual silenciós després de la feina feta. Un raspall ben cuidat modela amb bellesa la textura de demà."},"ICON-0510":{"nm":"Bobina per a gomes de cabell","de":"Amb només enrotllar-les al voltant d'un carret, es veuen totes d'una ullada. Aquest petit farcell endreçat en rodona és un respir tendre per a aquells matins ajetjats en què les gomes rodolaven cap a tot arreu."},"ICON-0511":{"nm":"Paquet de guants per a tint","de":"Uns guants prims que es posen perquè la mà que aplica el color no es tenyeixi. El desig de rebre el següent moment amb mans netes fins i tot després d'acabar la feina. La protecció no és sinó un altre nom per a aquesta previsió."},"ICON-0512":{"nm":"Bosseta per a la xarxa de cabells","de":"Una petita bossa on es plega amb cura la xarxa que manté el pentinat en el seu lloc. Com més petit i sense volum és un objecte, més fàcil és que es perdi, per això és tan d'agrair el gest atent que li dona una llar pròpia."},"ICON-0513":{"nm":"Llapis fixador de cabells rebels","de":"Un llapis que, amb un petit toc, torna al seu lloc els cabells rebels. L'últim gest, després d'haver acabat tot el pentinat gran. Acabar sempre vol dir acaronar el racó més petit."},"ICON-0514":{"nm":"Tap per a provar perfums","de":"Per triar una fragància, no cal acostar-la directament al nas. Cal impregnar-la en un petit tap i deixar-la escampar-se per l'aire perquè es reveli la seva veritable essència. Fins i tot el perfum només és honest quan es flaira des d'un pas de distància."},"ICON-0515":{"nm":"Ampolla de perfum de bola","de":"Una boleta rodona rodola suaument i dibuixa el perfum sobre el canell. A diferència dels antics flascons que s'aplicaven amb un toc, ara és una línia que s'escampa lliscant. La fragància deixa una història diferent segons com toca."},"ICON-0516":{"nm":"Tap per a boira corporal","de":"Un petit tap que reté la fragància que s'escampa com boira. És tancar i guardar allò que només es dispersa quan s'obre. Un cor que en desa una mica fa que aquell perfum es quedi al costat més temps."},"ICON-0517":{"nm":"Clauer de crema de mans","de":"Si es lliga un anell a la petita crema de mans, aquesta t'acompanya a tot arreu. Aquell company que balanceja penjant fora de la bossa es converteix en una tendra abraçada per als dits ressecs."},"ICON-0518":{"nm":"Penjador d'esponja de dutxa","de":"Després de fer una escuma esponjosa, cal deixar-la assecar bé. L'esponja de xarxa penjada d'un ganxo en un racó del bany sacseja les gotes d'aigua i espera fresca el matí següent."},"ICON-0519":{"nm":"Bosseta per a pilota de massatge","de":"En una petita bossa es guarda la pilota ferma que desfà les espatlles agarrotades. Un breu descans darrere l'escenari, un moment per acariciar en silenci el cos entumit. La cura sempre comença per un mateix."},"ICON-0520":{"nm":"Pot de pegats refrescants","de":"Un pot que aplega els pegats que refresquen en aplicar-los. La nit en què acaba un escenari abrandat, hi dorm a dins un petit consol que apaivaga a poc a poc el cos i el cor que han cremat."},"ICON-0521":{"nm":"Llapis d'oli per a ungles","de":"Prem, frega, brilla. Una sola gota basta per als dits ressecs. Sense necessitat de cap remei sofisticat, una lluentor suau que s'escampa des de la punta d'un petit llapis envolta amb gràcia les ungles. La cura comença així, en una petita gota."},"ICON-0522":{"nm":"Clip per a saquet aromàtic","de":"Un petit nus que lliga la fragància a un paper. Cada cop que s'obre el calaix, un grapat subtil saluda abans que la mà. Una tendresa que roman al costat encara que no es vegi: un sol clip guarda en silenci el consol d'un dia sencer."},"ICON-0523":{"nm":"Safata de puntes d'ungles","de":"Un petit escenari on s'exhibeixen per endavant els colors dels deu dits. Quin to escaurà avui? Sobre la safata s'obre una audició silenciosa. Aquell breu instant de triar és, per algun motiu, emocionant, i el dia dels dits comença aquí."},"ICON-0524":{"nm":"Tap per a repujador de cutícules","de":"Fins i tot en el gest d'empènyer hi ha tendresa. Una petita repelosa, suaument amb la punta arrodonida, sense pressa. Una mà que s'apressa sempre deixa alguna cosa de banda, per això endreçar s'assembla més a un cor que mira amb calma."},"ICON-0525":{"nm":"Mini llima polidora","de":"Una cara rugosa i una cara fina, dues faces en una sola mà. Llimar suaument les arestes fins a deixar-les llises és una cosa petita, però la perfecció sempre ve d'aquests gestos menuts. L'últim mot, al final, pertany a la suavitat."},"ICON-0526":{"nm":"Full d'adhesius per a ungles","de":"Estrelles, flors, cors: només cal triar amb un toc l'adhesiu que s'escau a l'humor d'avui i enganxar-lo. En un full ple de petits dibuixos de la mida d'una ungla, un sol adhesiu brilla com una signatura tendra deixada a la punta del dit."},"ICON-0527":{"nm":"Pantalla per a làmpada de gel","de":"Una fina pantalla que reté la llum per un instant. Mentre s'endureix, els ulls descansen i només els dits s'enforteixen en silenci. Fins i tot esperar necessita un bri d'ombra: en un temps sense pressa, els dits d'avui arriben a la seva forma acabada."},"ICON-0528":{"nm":"Pot de peces decoratives per a ungles","de":"Peces brillants dormen a cada compartiment. Strasses, perles, pols d'estels: la tapa s'obre amb l'emoció de descobrir un cofre de joies sense etiqueta. Quina llum posar sobre les ungles? Aquell moment de triar és el que brilla més."},"ICON-0529":{"nm":"Paquet de guants per a cura de mans","de":"Unes petites vacances que les mans prenen mentre dorms. Dins els guants, la pell seca es va humitejant a poc a poc durant tota la nit. La cura, al final, és una cosa que passa on no es veu; al matí, els dits són els primers a conèixer aquella tendresa."},"ICON-0530":{"nm":"Ampolla dosificadora de llevaesmalt","de":"Un sol clic, i just la quantitat justa. Una fragància fresca s'impregna al cotó i esborra amb netedat l'ahir sobre les ungles. Fins i tot buidar té el seu ritme, i un sol impuls de la bomba obre en silenci l'espai per pintar de nou."},"ICON-0531":{"nm":"Pinces per a strass","de":"Per agafar una gemma més fina que la punta d'un dit, cal una mà encara més fina. La punta de la pinça que trasllada un punt sense el més mínim tremolor: la delicadesa és tant cosa del cor com de l'eina. Una petita llum troba el seu lloc."},"ICON-0532":{"nm":"Placa organitzadora d'arracades","de":"Perquè cap arracada mai més es perdi sense parella al fons d'un calaix. Si es col·loquen les parelles al seu lloc, el temps de triar en un matí ajetjat es fa molt més lleuger. Endreçar és una petita amabilitat que oferim al nostre jo futur."},"ICON-0533":{"nm":"Anelles per mesurar la talla d'anells","de":"Un manat de petites anelles que converteixen el contorn del dit en un número. Provar-les una per una fins trobar la mida justa s'assembla a conèixer a poc a poc allò que t'escau exactament. Com aquell alleujament quan encaixa a la perfecció."},"ICON-0534":{"nm":"Passador de corretja de rellotge","de":"Quan la corretja del rellotge s'afluixa, un petit passador torna a subjectar el temps al canell. Que la peça més amagada és la que aguanta més temps, un rellotge que fa molt que es porta ho sap en silenci."},"ICON-0535":{"nm":"Placa antiembulls per a collarets","de":"Compartiments separats perquè les cadenetes fines no s'enredin entre elles. Un matí sense embulls comença en les petites divisions preparades la nit anterior. La tranquil·litat, al final, és un cor endreçat abans que la mà hi arribi."},"ICON-0536":{"nm":"Tancament posterior de broquet","de":"Com més lluent és el davant, més callat és el darrere. Un petit tancament que sosté amb fermesa el broquet clavat a la vora d'un vestit: darrere de tota resplendor visible sempre hi ha una mà anònima que aguanta. Un lloc encara més fiable per ser invisible."},"ICON-0537":{"nm":"Bosseta per a ulleres de sol","de":"Un teixit suau embolcalla amb cura les lents que van aturar la llum de l'estiu. Una petita bossa que protegeix un parell de mirades dels cops dins la bossa. El cor que estima alguna cosa sempre arriba així, com una capa suau."},"ICON-0538":{"nm":"Punxó per a forats de cinturó","de":"Tant per a una cintura minvada un forat com per a una estació que n'ha guanyat un. Amb només foradar un forat més, el cinturó torna a ajustar-se al cos. El que canvia sempre soc jo, i qui s'adapta en silenci és aquesta petita eina."},"ICON-0539":{"nm":"Anella clip per a fulard","de":"Un clip que aplega el fulard que llisca en un sol punt i el reté. L'elegància que el vent desfeia, finalment troba el seu lloc. Fins i tot la gràcia, de vegades, es recolza en aquesta petita pinça, que cus amb pulcritud un dia a punt de desfer-se."},"ICON-0540":{"nm":"Joc d'anelles per a penjolls","de":"Petites anelles per penjar en un costat de la bossa han arribat en un joc. El cor de portar sempre a prop allò que t'agrada: penjar l'humor del dia en un sol penjoll és com un ritual menut que només tu coneixes, i per algun motiu resulta divertit."},"ICON-0541":{"nm":"Removedor de pilotetes de roba","de":"Quan un jersei sembla haver envellit d'una nit per a l'altra amb pilotetes, fent rodar suaument aquest aparell, recupera l'aspecte de nou. El lleuger brunzit que retira el desgast resulta, per algun motiu, reconfortant. Una peça estimada torna així a reviure un cop més."},"ICON-0542":{"nm":"Targeta perfumada per a roba","de":"Ficada al fons de l'armari, omple en silenci els dies de fragància. Una carta escrita amb perfum en lloc de lletres, un full que es llegeix sense necessitat d'obrir-lo. Cada matí que es treu una peça de roba, primer s'escampa la tendresa escrita ahir."},"ICON-0543":{"nm":"Agulla antiestàtica","de":"En un matí d'hivern en què la faldilla s'enganxa a les cames, una agulla desfà amb discreció aquella adherència. Una petita pau que apaivaga fins i tot la fricció invisible: quan desapareix una menuda molèstia, el dia flueix molt més suau."},"ICON-0544":{"nm":"Raspall de roba portàtil","de":"Just abans de sortir per la porta, una ratlla de pols s'ha posat suaument a l'espatlla. Amb desplegar el raspall una sola vegada, la primera impressió torna a ser polida. L'acabat sempre passa a la porta, i la pulcritud es completa amb aquell únic gest."},"ICON-0545":{"nm":"Etiqueta per a bossa de bugada","de":"Les coses que no s'han de barrejar queden tancades dins la xarxa, i l'etiqueta hi escriu en silenci el nom. Fins i tot la bugada té el seu lloc, i cada lloc va acompanyat d'una petita marca. L'ordre d'un dia fàcil de desendreçar creix a partir d'aquesta petita etiqueta."},"ICON-0546":{"nm":"Llapis llevataques","de":"Fins i tot la marca que una gota de cafè ha deixat en una camisa es retira discretament amb uns quants tocs. Un llapis que no tapa un error sinó que l'esborra amb suavitat. Tothom necessita una oportunitat per començar de nou el dia net."},"ICON-0547":{"nm":"Drap per enllustrar sabates","de":"Amb un sol passat del drap, la pell recupera la seva lluentor. Com més temps s'ha portat una sabata, més profunda hi cala la brillantor. La lluïssor és la recompensa del temps caminat plegats: la sabata grava en silenci aquells anys damunt l'empenya."},"ICON-0548":{"nm":"Tap per a punta de cordó de vambes","de":"Una petita capsa col·locada a la punta d'un cordó deslligat. Perquè no es distregui abans d'arribar a la meta, en tanca fermament l'extrem. Un cordó ben lligat porta una passa més enllà: una petita precaució es converteix en el coratge de córrer fins al final."},"ICON-0549":{"nm":"Xip identificador de penjador","de":"Entre penjadors semblants, aquest petit xip indica en silenci 'el meu lloc'. Un guia silenciós que redueix la confusió d'un matí ajetjat: com menys costa buscar, més lleuger comença el dia."},"ICON-0550":{"nm":"Pot de pinces per a lents de contacte","de":"Hi ha moments en què cal una punta més precisa que la del dit. Les pinces que aixequen una petita lent sense el més mínim tremolor esperen el seu torn dins el pot. La precisió sempre dorm preparada en silenci, i es desperta a l'instant quan se la crida."},"ICON-0551":{"nm":"Paquet mini de discos de cotó","de":"Un petit farcell que conté just la quantitat per a un sol ús. Redueix el volum dins la bossa sense perdre res de la suavitat. Portar poc també és una forma de tendresa: en l'espai alliberat s'hi instal·la un dia lleuger."},"ICON-0552":{"nm":"Estoig de paper mata-greix","de":"Amb un sol full prim, es prem i s'eixuga la brillantor escampada al nas al bell mig del dia. Els fulls dormen ordenats dins l'estoig: en el moment de treure'n un, tothom s'atura un instant per mirar-se amb tendresa davant el mirall."},"ICON-0553":{"nm":"Mirall plegable amb pinta","de":"Plegat, cap a la mida d'una palma; obert, un mirall i una pinta. Un petit tot-en-un que, des d'un racó de la bossa, s'encarrega d'un arranjament urgent. La pulcritud no és res de grandiós; és més aviat un cor que pot obrir-se en qualsevol lloc per fer-se un cop d'ull ràpid."},"ICON-0554":{"nm":"Tap per a maquineta d'afaitar de viatge","de":"Adorm de manera segura la fulla esmolada dins la maleta de viatge. Gràcies a aquest tap, entre despuntat i ferm, ni tan sols els dits que hi busquen a les palpentes en un matí ajetjat s'arriben a tallar. Tenir cura és sempre cobrir el perill un pas per endavant."},"ICON-0555":{"nm":"Anella per a bàlsam de llavis","de":"Un petit escut que oscil·la penjat de la corretja de la bossa. Sense por que rodoli dins una butxaca i es trenqui, manté sempre a l'abast els llavis eixuts. Tenir cura, al final, és un cor que posa allò necessari a la distància més propera."},"ICON-0556":{"nm":"Suport per a gel hidroalcohòlic","de":"Amb una sola mà que prem, cau un grapat de netedat. Penjat a la porta, sobre l'escriptori, a qualsevol lloc, el desig de rentar-se les mans es fa igual de proper. Un bon hàbit no és res de grandiós; comença allà on la mà hi arriba."},"ICON-0557":{"nm":"Bosseta prima per a mocadors de paper","de":"Un cos esvelt que guarda un grapat de mocadors de paper. Sense inflar la butxaca, sempre resta preparada en silenci per a un nas que degoti de sobte o unes llàgrimes. Un full per allargar discretament a algú: com més prima és la previsió, més elegant resulta."},"ICON-0558":{"nm":"Ampolleta de col·lutori","de":"En un dia que cal veure algú després de menjar ramen picant, aquesta petita ampolla s'encarrega discretament de refrescar la boca. Un glop de frescor esdevé, de vegades, una gran confiança, i fa molt més lleugera una salutació que dubtava."},"ICON-0559":{"nm":"Xip de pólvores brillants","de":"Impregnat amb un toc a la punta del dit i posat a la galta, s'escampa com si es dispersés pols d'estels sota els focus. Que una galta corrent brilli en un instant és la màgia d'aquest petit xip. La llum sempre arriba així, amb una mica de pols enganxada a la punta del dit."},"ICON-0560":{"nm":"Adhesiu atenuador de purpurina","de":"Allà on hi ha massa brillantor per resultar còmode, aquest adhesiu n'atenua lleugerament la llum. Treure una capa d'esplendor també forma part de l'ornament: la subtilesa que resta en l'espai retirat, de vegades, esdevé un altre sentit."},"ICON-0561":{"nm":"Llapis recollidor de pedres","de":"Una petita pedra que ha ensopegat als peus mentre es camina pel carrer. Un llapis que es vincla expressament per recollir-la. El cor que arreplega amb suavitat, amb la punta del dit, allò que podria haver-se deixat passar de llarg: la tendresa sempre comença per aturar-se."},"ICON-0562":{"nm":"Placa per guardar pestanyes postisses","de":"Una petita placa on es reclina cada pestanya ordenadament, una a una. Fins i tot després de treure-les, aquella corba delicada no perd la forma. El consol silenciós i pulcre d'un desat que diu que fins i tot les coses posades a un costat per un moment recorden el seu lloc."},"ICON-0563":{"nm":"Tap per a talladora de cinta de parpella doble","de":"Dues fulles s'encaixen i tallen un nus d'un sol cop. Com més net és el tall, més polit resulta el nus següent. D'un dit que sap lligar bé i tallar bé, també un nou començament es desfà amb molta més lleugeresa."},"ICON-0564":{"nm":"Cinta per a línia facial","de":"Una ratlla al llarg de la línia de la mandíbula, aplicada amb cura, sense alè. El contorn no és dibuixar una línia que no hi era, sinó assenyalar allò que ja era bonic. Un gest que ressegueix amb tendresa la línia que sempre hi havia estat."},"ICON-0565":{"nm":"Pólvores reflectores de llum","de":"Una pols que absorbeix la llum al màxim i la retorna amb gràcia. Encara que no brilli per si mateixa, s'il·lumina escampant en petits fragments la llum rebuda. Com transmetre a algú altre la tendresa que s'ha rebut, la brillantor creix com més se la comparteix."},"ICON-0566":{"nm":"Ventilador fixador de maquillatge","de":"Un airet de ventilador que reté un maquillatge acurat fins al final del dia. Perquè no s'ensorri, perquè no llisqui, el refreda i l'endureix en silenci. Perquè un rostre cuidat amb dedicació resti nítid fins que cau el teló de l'escenari."},"ICON-0567":{"nm":"Xip de paleta correctora de color","de":"Petits fragments que apaivaguen i corregeixen, compartiment per compartiment, un color desajustat. Fins i tot un color que surava sol s'il·lumina per fi quan al costat s'hi posa un to que hi escau. Només quan color i color s'agafen de la mà esdevenen un quadre net."},"ICON-0568":{"nm":"Paquet de fulard per al coll","de":"Posat al coll, l'aire fred de la sala d'assaig de matinada s'estova considerablement. Càlid com aquell gest de l'àvia embolicant el coll del nét. El fred sempre arriba primer als llocs més prims, per això s'abraça primer la nuca."},"ICON-0569":{"nm":"Sobre per a antifaç tèrmic","de":"Un petit sobre que guarda un antifaç escalfat. En el moment d'obrir-lo, una calidesa somnolenta s'escampa lentament sobre les parpelles. Un ritual tendre abans de dormir, que segella per un moment un dia esgotador i després el deixa anar."},"ICON-0570":{"nm":"Filtre humidificador portàtil","de":"Una petita membrana filtrant que retorna la humitat a una habitació ben seca. Des de l'interior invisible, filtra en silenci allò que enterboleix. La humitat que omple l'habitació és una claredat que l'esforç invisible d'algú ha protegit."},"ICON-0571":{"nm":"Organitzador de vitamines","de":"Un pot que divideix les pastilles d'un dia compartiment per compartiment. Prendre-les fidelment cada dia és una promesa de tornar a pujar demà a l'escenari. En cada petit compartiment hi ha, ordenat amb pulcritud, el cor que s'estima a si mateix."},"ICON-0572":{"nm":"Estoig de taps per a les orelles","de":"Una llar per als taps que tanquen per un moment els sorolls del món. Fins i tot el silenci necessita cura, i per això reposen amb delicadesa dins l'estoig. El descans sap bé que només una nit de son profund fa que la veu de l'endemà es desperti clara."},"ICON-0573":{"nm":"Clip per a tovallola refrescant","de":"Una pinça que mossega amb fermesa l'espatlla perquè la tovallola refredada no llisqui. En un dia xafogós, un fil de frescor a la nuca ajuda a resistir una llarga tarda. Fins i tot una petita frescor, si es reté, perdura molt de temps."},"ICON-0574":{"nm":"Bossa per a pilota d'estiraments","de":"Una bossa on es torna a guardar la pilota que ha destensat el cos. Estirar-se al màxim i després recollir-se petit s'assembla a una inspiració i una espiració. Entre l'obertura i el recolliment, tant el cos com el cor s'enforteixen a poc a poc."},"ICON-0575":{"nm":"Rotlle de benes de compressió","de":"Una benda que embolica volta a volta un turmell entortolligat. No és estrènyer, és sostenir en silenci. Com més forçat és un lloc, més necessita una mà que aguanti al costat sense dir res, xiuxiueja mentre s'enrotlla."},"ICON-0576":{"nm":"Etiqueta de control de l'estat","de":"Una etiqueta que es penja amb l'estat d'avui escrit en una línia. Penjar amb honestedat el bo i el dolent és un petit coratge. Si en lloc de fingir que tot va bé s'hi escriu el jo d'avui, algú llegirà aquella línia i tindrà cura de tu en silenci."},"ICON-0577":{"nm":"Càpsula ambientadora per a sabates","de":"Una càpsula aromàtica que es fica dins la sabata amb un simple gest. Un consol petit i subtil per als peus que han recorregut l'escenari tot el dia. La millor fragància per al lloc que més s'ha esforçat: la tendresa arriba fins a la punta dels peus, sense deixar-se res."},"ICON-0578":{"nm":"Taula de talles de plantilles","de":"Una taula que grava amb claredat la talla del peu, fins i tot en una sola plantilla. Un parell que encaixa a la perfecció fa lleugeres les passes sobre l'escenari. Tenir en compte cada gambada diferent: un bon ajust és, al final, un cor que mira profundament l'altre."},"ICON-0579":{"nm":"Clauer amb calçador","de":"Un clauer amb un calçador reduït a la mida d'una palma. Una petita atenció que facilita el breu instant de calçar-se les sabates. Als peus que emprenen el camí sempre hi va penjada, en silenci, l'ajuda tendra d'algú."},"ICON-0580":{"nm":"Funda antipols per a bossa","de":"Un teixit que cobreix suaument una bossa estimada perquè no li arribi la pols. Fins i tot mentre no s'usa, l'adorm amb delicadesa i li preserva el gra. En les coses on el cor s'hi atura, encara que la mà no hi vagi sovint, hi habita una cura tan silenciosa com aquesta."},"ICON-0581":{"nm":"Passador ajustador de tirants","de":"Un passador que ajusta un tirant afluixat perquè s'adapti bé al cos. Si va massa fluix, llisca de l'espatlla; si va massa estret, talla la respiració. En el petit ajust d'un sol pas per trobar la mesura justa, tant el vestit d'escenari com el cor troben per fi la comoditat."},"ICON-0582":{"nm":"Llapis lubricant per a cremalleres","de":"Amb un sol traç sobre una cremallera encallada, torna a lliscar amb suavitat. Que refrescant és el so d'una cosa bloquejada que es deixa anar de sobte. El que fa fluir de nou un lloc aturat és un simple raig de suavitat."},"ICON-0583":{"nm":"Punta netejadora de vambes","de":"La punta d'un raspall que neteja punt per punt unes vambes tacades de pols. Fora de l'escenari, esborra amb dedicació les traces invisibles de la pràctica. En veure la puntera novament blanca, sembla que demà es podrà córrer amb un cor renovat."},"ICON-0584":{"nm":"Tap per a esprai impermeabilitzant","de":"Un tap impermeabilitzant que fa rodar les gotes de pluja en boletes i les deixa caure. Afegir per endavant una capa perquè res es mulli és una tendresa que mira molt lluny. Sabent que vindran dies de pluja, s'envolta avui, un dia clar, amb una capa de protecció."},"ICON-0585":{"nm":"Drap protector de pell","de":"Un teixit que es posa amb suavitat sobre la pell per evitar-hi arrugues. Preserva el gra com aquella mà antiga que embolicava un paravent amb paper hanji. Com més temps es vol tenir una cosa a prop, més a poc a poc: domesticar no és sinó un altre nom per al temps dedicat a tenir cura."},"ICON-0586":{"nm":"Cinta identificadora per a maleta","de":"Una cinta amb un nom que permet reconèixer d'un cop d'ull la teva pròpia bossa entre moltes altres. Entre l'equipatge que dona voltes a la cinta transportadora, aixeca la mà amb una sola lletra. Per lluny que es viatgi, un sol nom és la tranquil·litat de retrobar-se de nou."},"ICON-0587":{"nm":"Clip per a bossa de compressió","de":"Una pinça que premsa l'equipatge inflat fins a aplanar-lo i el tanca. Més que buidat, és ben plegat i endreçat. Que en el dit que redueix amb pulcritud les pertinences, també la cobdícia es fa més petita, ho diu en silenci l'equipatge fermament premsat."},"ICON-0588":{"nm":"Fulla de detergent de viatge","de":"Una fulla de detergent amb què, amb un sol tros, es pot fer la bugada en un lavabo. S'assembla a la saviesa dels qui, lluny de casa, rentaven la roba a mà al llarg del camí. Viatjar lleuger sense deixar de portar l'endreçament: la vella actitud del viatger de camí."},"ICON-0589":{"nm":"Funda per a coixí de coll","de":"Una funda neta que es canvia al coixí que sostenia el coll. El lloc on es recolza sempre ha de ser net perquè el cor estigui tranquil. Deixar el lloc suau i lliure perquè algú s'hi pugui recolzar còmodament: l'hospitalitat comença allà."},"ICON-0590":{"nm":"Corretja de bàscula per a equipatge","de":"Una corretja que aixeca la bossa amunt per calcular-ne el pes. Abans de marxar, s'abraça per endavant amb la mà el pes de l'equipatge. Entre el que s'endurà i el que es deixarà, és un moment de pesar en silenci també el pes del cor."},"ICON-0591":{"nm":"Parell de bosses per a sabates","de":"Esquerra i dreta, un parell de bosses que guarden costat a costat dues sabates. El que fàcilment es perd si es deixa separat, aparellat resulta reconfortant. Les coses que sempre van juntes tenen el poder de vetllar l'una per l'altra en silenci."},"ICON-0592":{"nm":"Anella addicional per a bossa","de":"En un dia que falta una mà, una petita anella per penjar-hi discretament una bossa. Un espai de marge per als dies amb més equipatge del que es pot portar. Només saber que hi ha un lloc on penjar-la un moment ja fa les espatlles molt més lleugeres."},"ICON-0593":{"nm":"Xip d'itinerari de viatge","de":"Grava amb claredat el recorregut d'un dia en un sol xip. On trobar-se i cap a on continuar, una línia guia traçada per endavant per a passes que s'orienten malament. Un camí recorregut junts, anotat pas a pas, difícilment es perd."},"ICON-0594":{"nm":"Tap per a adaptador multi","de":"Un tap que encaixa a la perfecció fins i tot en les preses d'un país desconegut. Encara que la forma sigui diferent, al final tot queda connectat com un de sol. Unir coses vingudes de llocs diferents: l'harmonia comença en silenci amb una petita conversió."},"ICON-0595":{"nm":"Funda per a targeta de transport","de":"Un full transparent que protegeix la targeta cada cop que roça el torn. Embolcalla amb cura el trajecte diari, fins i tot les marques gastades de tant tocar-la. Que fins i tot un camí corrent es converteix en record si es tracta amb cura, això ho demostra aquesta fina capa."},"ICON-0596":{"nm":"Clip per a bitllet","de":"Una pinça que subjecta amb pulcritud un bitllet que s'arruga de seguida. Si es perd el bitllet pel camí, fins i tot el cor tremola sencer. Com més petit és el paper, més cal retenir-lo fermament: la tranquil·litat del viatge ve precisament d'aquest petit espai."},"ICON-0597":{"nm":"Xip de nota de transbordament","de":"Un petit xip amb el lloc de transbordament anotat en una línia. A cada cruïlla confusa, una paraula escrita per endavant obre el camí amb claredat. Una nota és una pista tendra deixada discretament per al jo futur que podria perdre's."},"ICON-0598":{"nm":"Etiqueta de pas de porta","de":"Una etiqueta de pas que es reconeix en silenci en travessar la porta. Fins i tot un camí que semblava tancat s'obre suaument si es porta la qualificació pròpia. Presentar-la sense recances és avançar amb lleugeresa cap a l'espai següent, sense la més mínima vacil·lació."},"ICON-0599":{"nm":"Suport per a rebuts de taxi","de":"Cada petit paper porta gravada amb claredat la petjada del camí recorregut aquell dia. Si s'apleguen ordenadament els rebuts que rodolaven cap a tot arreu, fins i tot un dia sense importància s'acumula, paper a paper, fins convertir-se en un viatge de ple dret."},"ICON-0600":{"nm":"Banda reflectora per a bicicleta","de":"Una banda que, en un camí fosc, rep la llum que passa i brilla en silenci. Encara que no s'il·lumini per si mateixa, s'omple de claror amb la llum d'algú altre. Fer-se visible és la petició tendra d'un camí nocturn perquè, si us plau, es torni sa i estalvi."},"ICON-0601":{"nm":"Funda per a rodes de maleta","de":"Que les cantonades de la maleta segueixin intactes després de rodar mil vegades per les cintes de l'aeroport es deu a aquesta petita funda que embolcalla les rodes. És la part que primer toca el camí més aspre —cuidar algú en silenci sempre s'amaga en llocs que ningú no nota."},"ICON-0602":{"nm":"Funda de reposacaps","de":"En un llarg viatge amb bus, la poses sobre el reposacaps i t'hi recolzes mirant per la finestra. Ni la fragància del passatger anterior ni el cansament d'ahir arriben fins aquí. Tenir un lloc net on descansar el cap és un consol sorprenentment gran en un camí desconegut."},"ICON-0603":{"nm":"Xinxeta de plaça d'aparcament","de":"«A quin pis, a quina plaça era?» Qui ha vagat una bona estona per un pàrquing buit sap com de reconfortant és aquesta xinxeta. Un sol marcador clavat en lloc d'una memòria que s'esvaeix, que fixa per endavant el camí de tornada."},"ICON-0604":{"nm":"Cordó porta-claus d'habitació","de":"Com pot desaparèixer tan fàcilment la clau d'una habitació? Enfila-la en un cordó i lliga-te'l al canell, i mai oblidaràs quina habitació t'espera aquesta nit. Fins i tot en una ciutat estranya, el petit alleujament de tenir el teu propi racó et penja del canell."},"ICON-0605":{"nm":"Xip de senyal de porta","de":"Quan comença l'assaig, es penja un xip a la porta. No molestar —ara és temps de concentració absoluta. El silenci profund de darrere l'escenari el vetllen, sense paraules, senyals petits com aquest."},"ICON-0606":{"nm":"Necesser de bany","de":"Raspall de dents, netejador facial, una tovallola de la mida d'una mà. Vagis on vagis, n'hi ha prou d'emportar-te aquest necesser perquè el final i l'inici de cada dia quedin endreçats per les mateixes mans de sempre. Un petit grapat de casa que converteix un llit estrany en quelcom familiar."},"ICON-0607":{"nm":"Clip per a tovallola de recanvi","de":"Al costat del lavabo, aquella tovallola de recanvi sempre quedava humida sense lloc on anar. Amb un clip que la subjecta i la penja, finalment troba el seu lloc. Donar un espai perquè s'assequi —la tendresa sol tenir més o menys aquesta mida."},"ICON-0608":{"nm":"Funda per a regleta elèctrica","de":"Cada vegada que obries la bossa, els carregadors eren un embolic fet un sol nus. Enrotlla la regleta sencera i fica-la a dins, i tot queda molt més endreçat. Que un cable es desenredi vol dir que un racó del cor també es desfà una mica abans del viatge."},"ICON-0609":{"nm":"Etiqueta numerada de llitera","de":"Un número enganxat a cada llitera de la residència. Amb una sola etiqueta que et diu quin és el teu lloc, fins i tot una habitació nova i desconeguda es converteix en casa a la nit. L'inici sempre és així de petit."},"ICON-0610":{"nm":"Estenedor de butxaca","de":"Penja'l entre els marcs de la finestra i es converteix en un estenedor. Un dia assolellat, uns quants mitjons rentats a mà oscil·len tous i secs amb el vent. Fins i tot lluny de casa, la vida quotidiana s'asseca així, penjada d'un fil."},"ICON-0611":{"nm":"Etiqueta identificadora de xancletes","de":"Quan les xancletes s'amunteguen a l'entrada, no hi ha manera de saber de qui són. Amb una petita etiqueta enganxada, fins i tot el calçat reconeix el seu propietari. Viure amuntegats amb molta gent necessita, precisament, aquesta mena de marques amables."},"ICON-0612":{"nm":"Suport per a val d'esmorzar","de":"Un suport per guardar el tiquet de l'esmorzar. En una matinada amb gana, aquest paperet promet un bol de sopa fumejant. El dia d'un viatge sempre s'obre a poc a poc amb un àpat calent."},"ICON-0613":{"nm":"Banda reflectora de turmell","de":"Cordada al turmell, reflecteix la llum en la foscor. En un passeig nocturn, saluda en silenci un cotxe que s'acosta de lluny —«aquí hi ha algú». La seguretat brilla així de senzilla."},"ICON-0614":{"nm":"Tapa per a tovalloletes","de":"Una tapa que encaixa perfectament a la boca del paquet de tovalloletes. Cada full surt suaument i la resta no s'asseca. Pot semblar insignificant, però les coses que fas servir cada dia sempre amaguen una bona raó."},"ICON-0615":{"nm":"Cinta per a estora de pícnic","de":"Enrotlla l'estora fent un cercle i lliga-la amb una cinta. La riba del riu, l'ombra dels cirerers en flor —allà on l'estenguis, aquell lloc esdevé nostre. Una cinta que porta a sobre tot un territori d'herba de la mida d'una mà."},"ICON-0616":{"nm":"Estoig de pegats antimosquits","de":"Un estoig per guardar els pegats antimosquits, imprescindibles a les nits d'estiu. Dins d'aquest petit compartiment hi cap tota la previsió de preparar-los abans que arribi la picor. Les últimes files d'un escenari a l'aire lliure sempre es fan més segures amb petites precaucions com aquesta."},"ICON-0617":{"nm":"Ganxo per a cantimplora de passeig","de":"Un ganxo per penjar la cantimplora a la bossa quan surts a passejar. Tenir aigua a l'abast quan arriba la set vol dir que pots caminar molt més lluny. Una petita connexió que no deixa parar qui camina."},"ICON-0618":{"nm":"Cistella de compra plegable","de":"Oberta, és una cistella de compra; plegada, cap a la palma de la mà. Perfecta per posar-hi un manoll de verdures a què has agafat afecte tot voltant pels carrerons del mercat. La saviesa de la llar sempre ha crescut cap a menys volum, cap a portar les coses més lleugeres."},"ICON-0619":{"nm":"Clip subjecta-vent","de":"Un dia de vent, agafa fermament la vora d'una lona que oneja. Un sol clip manté al seu lloc allò que no parava de sacsejar-se. A l'aire lliure, el més fiable resulta ser, sorprenentment, una cosa de la mida d'un dit."},"ICON-0620":{"nm":"Agulla parasol","de":"Una agulla que es clava a la finestra per esbiaixar la llum del sol. Quan la llum del migdia és massa forta, projecta discretament un grapat d'ombra. Alleujar la lluïssor també pot ser, per a algú, el gest més tendre que hi ha."},"ICON-0621":{"nm":"Tapa de xiulet d'emergència","de":"Una tapa que cobreix la boca d'un xiulet d'emergència. Mantenint la pols fora, perquè soni d'un sol cop quan realment calgui. Hi ha coses que donen tranquil·litat només d'estar a prop, encara que esperis no haver-les de fer servir mai."},"ICON-0622":{"nm":"Protector de punta de paraigua","de":"Una petita tapa que es posa a la punta del paraigua. Quan l'extrem afilat s'esmussa, ni la persona del costat ni la teva pròpia bossa es fan mal. Les bones maneres dels dies de pluja comencen en silenci embolcallant una punta afilada perquè torni rodona i tova."},"ICON-0623":{"nm":"Bossa per a impermeable","de":"Una bossa per enrotllar l'impermeable plegat i guardar-lo. Espera en silenci en un racó de la bossa fins al proper xàfec. La previsió és, al capdavall, un bocinet de cor que empaqueta per endavant allò que potser mai no faràs servir."},"ICON-0624":{"nm":"Funda impermeable per a sabates","de":"Posa-te-les sobre les sabates i la pluja ja no hi pot penetrar. Fins i tot en un camí a l'escola sota el monsó, els mitjons queden secs. Un dia en què no et mulles fins als dits del peu et canvia l'humor molt més del que et pensaries."},"ICON-0625":{"nm":"Adhesiu antilliscant per a la neu","de":"Enganxat sota les sabates, els camins gelats fan molta menys por. Aquell hivern en què creuaves amb passets ràpids els carrerons coberts de neu, aquest adhesiu et sostenia en silenci perquè no relliscessis. La fortalesa fiable amagada sota passos cautelosos."},"ICON-0626":{"nm":"Anella refrescant per al coll","de":"Posada al voltant del coll, un corrent fresc s'hi instal·la en silenci. La saviesa d'estiu de dur un raig de frescor al clatell fins i tot en la calorada més sufocant. Cada any aprenem a suportar la calor una mica més amb enginy."},"ICON-0627":{"nm":"Suport per a ventilador de mà","de":"Un suport per posar dret el ventilador de mà. Amb les dues mans lliures, pots passar pàgines i fins i tot escriure en comptes de ventar-te. Un petit corrent d'aire fa que un llarg estiu davant l'escriptori sigui just prou suportable."},"ICON-0628":{"nm":"Bossa per a escalfador de mans","de":"Una bossa per portar un escalfador de mans. Quan fiques els dits gelats a la butxaca per escalfar-los, ja hi ha una petita calidesa esperant-te allà. Les sortides d'hivern se suporten amb aquest únic grapat de calor."},"ICON-0629":{"nm":"Estoig per a orelleres","de":"Un estoig per guardar les orelleres. Un lloc on desar-les amb cura fins que torni el proper fred. Les coses que no acabem de llençar quan canvien les estacions porten dins una fe tranquil·la en l'hivern que tornarem a trobar."},"ICON-0630":{"nm":"Xip mesurador d'UV","de":"Apropa'l lleugerament a la llum i el xip et diu la intensitat dels rajos UV d'avui en color. Finalment fa visible allò que la intensitat de la llum del sol tenia d'invisible. És com posar-te al canell un petit ull per llegir el cel."},"ICON-0631":{"nm":"Tauler de segells de barri","de":"Un tauler que vas omplint recollint segells de cada botiga del carreró. Amb cada quadre segellat, un mapa del barri es dibuixa amb claredat dins el cor. Els records reunits a peu queden així, com marques de tinta."},"ICON-0632":{"nm":"Tauler de xinxetes de viatge","de":"Un petit tauler on claves una xinxeta per cada lloc que has visitat. A mesura que els punts s'acumulen, el perímetre del teu món també s'eixampla. Cada xinxeta és un rastre que diu en silenci: «Jo, aquí vaig ser.»"},"ICON-0633":{"nm":"Cordó de brúixola petita","de":"Per molt que et perdis, el nord sempre roman fidel al seu lloc. La petita brúixola penjada a l'alçada del pit, quan no saps cap on anar, primer serena amb suavitat el cor que et tremola."},"ICON-0634":{"nm":"Anella de notes d'orientació","de":"Les notes que vas escriure mentre buscaves el camí, enfilades en una anella. «Gira a l'esquerra a la bústia vermella.» La lletra maldestra d'algú guia en silenci un carreró desconegut. Un camí escrit en paper difícilment s'esborra."},"ICON-0635":{"nm":"Àlbum d'adhesius de monuments","de":"Un àlbum que omples amb un adhesiu comprat a cada destinació. Torres, ponts, velles muralles s'apilen pàgina rere pàgina. Recollir els llocs on has estat s'assembla a tornar a tocar amb els dits el temps que has viscut."},"ICON-0636":{"nm":"Xip de transbord de metro","de":"Un xip que agafes fort a l'estació de transbord on les línies se separen. Aquell breu instant de decidir on canviar de tren de vegades capgira del tot la direcció d'un dia sencer. Amb una petita tria, la ciutat mostra una cara diferent."},"ICON-0637":{"nm":"Carta d'exploració del barri","de":"«Avui, fins al forn d'aquest barri.» Treus una carta i queda fixada la destinació del dia. Fins i tot un carreró conegut de sempre esdevé un camí nou quan apareix una missió. Una carta que et recorda que l'aventura no és tan lluny."},"ICON-0638":{"nm":"Portatarges de botigues","de":"Un portador per guardar les targetes que t'han donat a les teves botigues preferides. El local on es menjava tan bé, l'amo de tracte tan afable —es van acumulant, un compartiment cada vegada. Agafar afecte a una ciutat comença amb papers petits com aquests."},"ICON-0639":{"nm":"Tauler d'insígnies de recorregut complet","de":"Un tauler on completar tot un recorregut de passeig et guanya una insígnia. La recompensa d'haver arribat fins al final es queda a la mà com un disc de metall. La satisfacció que només coneixen els qui han caminat fins al final queda aquí gravada amb claredat."},"ICON-0640":{"nm":"Clauer amb cadenat per a bossa","de":"Un petit cadenat amb clauer que es tanca a la cremallera de la bossa. Guarda amb fermesa allò preciós mentre dringa a la vora de la bossa. Un company força enginyós del viatger, en què seguretat i decoració es fonen en un."},"ICON-0641":{"nm":"Etiqueta antipèrdua","de":"S'arrauleix en la foscor més profunda de la bossa, i just quan tothom ja s'ha rendit, parpelleja tènuement. «Aquí sóc.» El so d'allò que creies perdut tornant a la punta dels teus dits. Per petita que sigui, es queda al costat del seu amo fins al final."},"ICON-0642":{"nm":"Anella de bloqueig de cremallera","de":"Clic. Un cop tancada, cap mà normal no la pot obrir. Una tossuderia que atura per igual una ungla apressada i un dit que s'hi acosta furtiu. La seguretat, amb el seu pes feixuc, ens recorda que de tant en tant no fa res que costi una mica de moure."},"ICON-0643":{"nm":"Corretja antifurt amb campaneta","de":"Un guardià invisible que impedeix que els articles de la prestatgeria surtin abans d'hora sense pagar. Quan hi passa a frec una mà honesta, calla fins al final. Una campana que no sona és la campana més tranquil·la de totes."},"ICON-0644":{"nm":"Etiqueta cobre-dades","de":"Es col·loca en silenci sobre el nom i el número escrits a la caixa del paquet. Qui hi viu, on va —només cal que ho sàpiga el destinatari. Amagar bé també és una mena de tendresa, diu ella, quedant-se al seu lloc en silenci."},"ICON-0645":{"nm":"Cinta per a funda de passaport","de":"Un aeroport desconegut, desenes de tapes idèntiques girant per la cinta a trenc d'alba. Enmig de totes, aquesta fa senyes «per aquí» en un color que només tu reconeixes. Un petit abric que vesteix el document que emprèn un llarg viatge. Encara que la coberta es gasti, el trajecte segueix lluminós."},"ICON-0646":{"nm":"Moneder separador","de":"Els bitllets a l'esquerra, les monedes a la dreta, els diners d'emergència en un compartiment que ningú coneix. És el primer lloc que toca una mà acabada d'arribar del mercat. Fins i tot un dia embolicat troba aquí, endreçat i dringant, el seu lloc."},"ICON-0647":{"nm":"Segell adhesiu de seguretat","de":"Un cop l'arrenques, en queda la marca. Una petita consciència honesta que mai no pot amagar del tot que «algú m'ha obert». Sota cada caixa que arriba precintada i intacta hi ha el silenci inalterable d'aquest amic."},"ICON-0648":{"nm":"Xip de contacte d'emergència","de":"La butxaca d'un infant perdut, l'interior d'una bossa d'ordinador, l'extrem d'una corretja de gos. Fins i tot quan el moment no pot parlar, ell crida el número ben clar en el seu lloc. Un petit xip que conté sencer un «porteu-me a casa»."},"ICON-0649":{"nm":"Tapa comandament per a pal de selfie","de":"Fotos de grup on sempre algú quedava tallat per falta de braç. Ara, un simple toc al botó de l'extrem fa entrar tota la família en un sol fotograma. En aquell instant en què tothom somriu, jo, prement discretament el disparador, hi salto a dins."},"ICON-0650":{"nm":"Cordó de funda per a objectiu","de":"Un cordó que abraça els objectius de recanvi perquè no xoquin dins la bossa. Com que un tros de vidre és tot un paisatge, no es sacseja aquest pes a la lleugera. La cura del fotògraf queda lligada a cada nus."},"ICON-0651":{"nm":"Anella d'estoig per a filtres","de":"Un full prim canvia el mateix cel en una llum diferent. Un lloc que guarda aquestes petites màgies ben ordenades en un niu rodó. Cada cop que obres l'estoig, els dits s'emocionen un instant: quina posta de sol atraparé avui?"},"ICON-0652":{"nm":"Funda per a trípode","de":"Plegat, cap a un pam; desplegat, tres potes sense el més mínim tremolor. Enrotlles amb cura l'amic que sostindrà el paisatge en lloc de les teves mans que tremolen. Com més pesant l'equip, més suau ha de ser la tela on el deixes reposar."},"ICON-0653":{"nm":"Coixinet per a corretja de càmera","de":"Caminant tot el dia, arriba el moment en què la càmera pesa sobre l'espatlla. Llavors un pedaç en reparteix el pes en silenci. Un consol petit i tou posat sobre l'espatlla que camina lluny per una sola bona instantània."},"ICON-0654":{"nm":"Targeta classificadora de memòria","de":"En nits en què no recordes en quina targeta dormen centenars de records, marques de colors et tracen el camí. Viatge de primavera en blau, primer concert en groc. Un bibliotecari petit i amable que dona també un prestatge a cada record."},"ICON-0655":{"nm":"Enrotllador de cable de càrrega","de":"Abans que els cables muntin tot un espectacle de nusos dins la bossa, els enrotlles bé i els deixes dormir endreçats. Endreçar un cable desfà, d'alguna manera, també un fil del cor. Veure'ls ben cargolats resulta, només de mirar-los, tranquil·litzador."},"ICON-0656":{"nm":"Etiqueta de còpia de seguretat","de":"«Aquestes fotos, les vaig fer còpia?» Una petita nota que respon per endavant a aquell neguit que sorgeix de sobte a altes hores de la nit. Com més preciós és el moment, més cal que visqui en dos llocs o més, escriu clarament l'etiqueta."},"ICON-0657":{"nm":"Marc de composició","de":"Mira el món a través de la finestra quadrada i veuràs de seguida què hi vols posar i què hi vols deixar fora. Una bona fotografia no consisteix a afegir-hi més, sinó a saber treure bé —el marc buit és el primer a ensenyar-ho."},"ICON-0658":{"nm":"Penjoll moneder","de":"Penja dringant a la vora de la bossa, guardant unes quantes monedes. El petit tresor que s'obre el primer davant d'una màquina expenedora o d'una parada de peixets fumejants. Aquell dringar és l'efecte sonor de la felicitat menuda."},"ICON-0659":{"nm":"Punxó recol·lector de tiquets","de":"Els papers que gairebé llençaves s'hi van enfilant un darrere l'altre. Què has menjat i comprat avui —el tiquet és un diari més sincer que qualsevol llibre de comptes. Reunits d'un mes sencer, esdevenen un registre de vida força gruixut."},"ICON-0660":{"nm":"Etiqueta de cistella de mercat","de":"Penjada al canell que surt a fer la compra, recorre amb tu els carrers del mercat. Un bloc de tofu, un manoll de ceballots, i fins i tot la simpatia que t'han regalat de propina. Rep tot aquest pes sense queixar-se. Una amiga que s'entusiasma més omplint-se que buidant-se."},"ICON-0661":{"nm":"Imant de record","de":"Tria'n un a cada destinació i enganxa'l a la nevera, i la cuina es converteix en un petit mapamundi. Les ciutats visitades pengen l'una al costat de l'altra, xiuxiuejant «tornem-hi». Fins i tot una simple planxa d'acer té el poder de retenir records."},"ICON-0662":{"nm":"Llibret de segells regionals","de":"Un segell per pàgina, i els carrerons caminats reviuen amb tinta. Les marques vermelles reunides recorrent tot el país són un mapa de les teves petjades. Com menys caselles buides queden, més fa senyes en silenci el proper viatge."},"ICON-0663":{"nm":"Bobina de cordill per embolicar","de":"Una paciència llarga, llarguíssima, que es desenrotlla sense fi per lligar una sola capsa de regal. Només concedeix un nus impecable a les mans que saben quan tallar. Enrotllada, espera en silenci el seu proper torn."},"ICON-0664":{"nm":"Coixí protector de regal","de":"Embolcalla amb tovesa un cor fràgil. Fins i tot en un vagó de repartiment que trontolla, es manté ferm i tou —«tranquil, jo t'aguanto». Vetlla per endavant fins i tot pel somriure lluminós de qui obrirà la capsa."},"ICON-0665":{"nm":"Adhesiu cobre-etiquetes de preu","de":"Una petita mentida pietosa que tapa discretament el preu d'un regal. «No cal que sàpigues quant costa, agafa'n només el sentiment», diu, assentant-se suaument sobre l'etiqueta. No és amagar, és fer brillar encara més aquell sentiment."},"ICON-0666":{"nm":"Xip miniatura de carretó de compra","de":"No pots empènyer un carretó de veritat, però aquest petit amic que dringa a la punta del dit conté tota l'emoció d'una sortida al súper. Per petit que sigui, aquell batec de «què compro avui?» pesa igual que el de debò."},"ICON-0667":{"nm":"Clip fosforescent per a sabatilles","de":"Una espurna a la punta de la sabatilla que surt a passejar de nit, enviant a un cotxe que passa el senyal «aquí hi ha algú». La primera llumeta que et surt a rebre en un carreró fosc. La seguretat sempre comença en silenci des de la punta del peu."},"ICON-0668":{"nm":"Tapa per a llanterna petita","de":"Posa-la sobre el cap de la llanterna i la llum s'escampa més lluny, més suau. Un petit mag que pinta un estol d'estrelles al sostre d'una tenda fosca. En nits en què la foscor fa una mica de por, no hi ha millor amic que aquest."},"ICON-0669":{"nm":"Botó d'avís d'arribada a casa","de":"Prem-lo i la frase «he arribat bé» vola cap a la família, lluny. En comptes del so de la porta d'entrada a altes hores de la nit, un petit botó porta la notícia. Algú s'adorm esperant aquest senyal."},"ICON-0670":{"nm":"Rotlle d'adhesius reflectants","de":"Talla'n un quadre i enganxa'l a la bossa, a la bicicleta, al paraigua, i el camí nocturn es fa molt menys perillós. Un dormilega que es desperta lluminós just quan es troba amb els fars d'un cotxe. Enrotllat, espera que arribi la propera foscor."},"ICON-0671":{"nm":"Targeta de taxi d'emergència","de":"Guardada en un compartiment de la cartera, fins i tot una parada buida a altes hores de la nit fa menys angoixa. Un número, una línia d'adreça escrita com una promesa —«et portaré a casa». Qui hauria dit que la paraula emergència podia ser tan reconfortant."},"ICON-0672":{"nm":"Braçalet mapa de camí nocturn","de":"Camines amb ell lligat al canell pels carrers on els fanals escassegen. Quin carreró és lluminós i quin és fosc —et xiuxiueja la drecera que només coneix la nit. Un braçalet que es lliga al teu costat perquè no perdis mai el rumb, ni tan sols en la foscor."},"ICON-0673":{"nm":"Funda d'alarma de seguretat","de":"Estirat en una emergència, crida tan fort que sobresalta tot el carreró. La resta del temps s'amaga tranquil dins la funda, estalviant la veu per a aquell únic instant. El crit més gran, guardat dins la bossa més petita."},"ICON-0674":{"nm":"Clauer amb llum per a la porta","de":"Adeu a les nits palpant a les fosques buscant el forat del pany al fons del passadís. Penjat a la porta, rep la mà que torna a casa amb una llum rodona. «Bona feina, ja ets a casa», diu primer el clauer."},"ICON-0675":{"nm":"Nota de recordatori de tornada","de":"«Agafa el paraigua, apaga el llum en sortir.» Un breu recordatori enganxat a la nevera vetlla l'allotjament buit. Una petita nota per a qui hi tornarà. La tendresa continguda en un full de paper acompanya en silenci fins a la porta."},"ICON-0676":{"nm":"Pinta ordenadora de cables","de":"Pentina els cables enredats amb suavitat, com qui pentina cabells. La selva de cables darrere l'escriptori es torna endreçada amb unes quantes passades. No només s'enreda el cabell, recorda en silenci la pinta."},"ICON-0677":{"nm":"Separador de portallapis","de":"El llapis aquí, el fluorescent allà, les tisores al darrer compartiment. Divideix un petit poble dins un sol got i dona a cada bolígraf el seu lloc. Amb compartiments, la mà ja no vaga perduda. L'inici d'un petit ordre sobre l'escriptori."},"ICON-0678":{"nm":"Clip de notes per a monitor","de":"Penjat al costat del monitor, posa «les tasques d'avui» just a l'alçada dels ulls. Un petit tauler d'avisos que es veu de cara, sense donar temps a oblidar. Un sol clip enganxa amb suavitat una ment que sempre vol ajornar les coses."},"ICON-0679":{"nm":"Safata organitzadora de calaix","de":"Clips i gomes elàstiques, xinxetes i gomes d'esborrar. Dona a cada petita tribu del calaix la seva pròpia habitació. Quan la mà arriba a compartiments ben separats, el temps de buscar es redueix i un racó del cor s'alleugereix."},"ICON-0680":{"nm":"Tub per a raspall de pols","de":"Un sol gra de pols sobre l'objectiu es converteix en una taca gegant a la fotografia. Per això el raspall espera sempre a punt i impecable dins el tub. Una punta de dit diligent que preserva una netedat que ningú no arriba a notar."},"ICON-0681":{"nm":"Cantonera de catifa d'escriptori","de":"Un pam de suavitat estès en una cantonada de l'escriptori. Els bolígrafs no cauen rodolant, i en comptes del vidre fred, una veta càlida sosté el canell. Una superfície amable que cedeix el seu lloc la primera, perquè l'escriptura d'una nit llarga no trontolli."},"ICON-0682":{"nm":"Subjecta-cable de ratolí","de":"Quan el cable s'enreda, en algun racó el cor també s'enreda. Un gest que atrapa per endavant el fil que es desviava i el deixa ben estirat i endreçat. Gairebé imperceptible, endreça en silenci la veta de l'escriptori —una cura petita i diligent."},"ICON-0683":{"nm":"Suport per a base de càrrega","de":"Alça inclinat un aparell que jeia pla i la pantalla per fi et mira als ulls. Fins i tot l'espera mentre es carrega es torna un moment endreçat. Sostenir alguna cosa és donar, fins i tot a allò que descansa, la seva postura pròpia."},"ICON-0684":{"nm":"Etiqueta per a paperera petita","de":"Fins i tot el pot més petit té el seu nom enganxat. Una sola línia, «llenceu aquí», crida un ordre tranquil sobre un escriptori desendreçat. Una etiqueta és, al capdavall, una petita salutació que diu a l'objecte: la teva utilitat és aquí."},"ICON-0685":{"nm":"Xinxeta de tauler separador","de":"Prem un full de paper contra el tauler. És confiar per un moment a la paret un sentiment que no vols oblidar. El propòsit d'avui, penjat a la punta de la xinxeta, es gronxa lleugerament amb l'aire i et reté cada vegada que hi passes."},"ICON-0686":{"nm":"Xip marc per a etiquetes","de":"Una vora quadrada converteix una escriptura corrent en una frase clara i única. Un xip que envolta amb una dignitat endreçada notes que fàcilment es dispersen. No és tancar-les, és abraçar les paraules importants perquè no es perdin."},"ICON-0687":{"nm":"Tirador per a calaix transparent","de":"Posa un tirador a un calaix transparent i podràs veure què hi ha sense obrir-lo a la lleugera. Un pam de distància —visible, però no aproximada. Fins i tot la transparència necessita bones maneres, xiuxiueja així el calaix."},"ICON-0688":{"nm":"Clip de tancament de tapa","de":"Deixat obert, l'aroma i el color s'escapen a poc a poc. Amb una petita pinça que mossega ben fort la tapa, el color d'ahir arriba intacte fins demà. Tancar és, en realitat, la feina de protegir allò que estimes."},"ICON-0689":{"nm":"Suport per a assecant","de":"Un petit sentinella que detesta la humitat i vigila el seu lloc en silenci. Que l'aire sec sigui a prop és la primera condició per conservar les coses molt de temps, recorda en silenci aquest suport endreçat. Així es preserva la sequedat."},"ICON-0690":{"nm":"Etiqueta de cistella d'endreça","de":"Una petita etiqueta amb nom a cada cistella. Decideix quin compartiment guarda què, i el temps que abans es perdia buscant es transforma directament en temps de descans. Endreçar és una nota amable que et deixes preparada, per endavant, al teu jo futur."},"ICON-0691":{"nm":"Petit tauler separador","de":"Un petit separador que aixeca en un tres i no res una habitació acollidora sobre l'escriptori. Amb aquest únic tauler apareix una cantonada tranquil·la lleugerament d'esquena al món. Un racó acollidor tot teu, fet a mida perquè hi arreli la concentració."},"ICON-0692":{"nm":"Suport per a bosses","de":"Un suport que sosté amb suavitat l'esquena de bosses que no paraven de bolcar-se. Només amb estar-se dretes i alineades, escollir la que toca es fa molt més fàcil. Mantenir les coses dretes és tenir cura, per endavant, de la propera mà que hi arribi."},"ICON-0693":{"nm":"Xip marcador de casella buida","de":"Un xip que marca deliberadament el buit. Deixar un lloc per omplir també és, ben mirat, un pla. Una casella buida no és peresa, sinó un pam de marge deixat cortesament obert per a alguna cosa que aviat hi arribarà."},"ICON-0694":{"nm":"Tapa protectora per a raspall de dents","de":"Amb el raspall que toca la boca es fa un cas més exigent. Un petit capell que bloqueja fins i tot un sol gra de pols. Cuidar una netedat invisible és precisament la petita dedicació que obre cada matí de manera fresca."},"ICON-0695":{"nm":"Xarxa portasabons","de":"Una xarxa que aixeca suaument el sabó perquè no es reblaneixi immers en l'aigua. El principi que deixar escórrer l'aigua allarga la vida d'una cosa, ho demostra cada dia, en silenci, des del racó més baix i petit del bany."},"ICON-0696":{"nm":"Clip per a dosificador de xampú","de":"Subjecta amb suavitat el cap del dosificador, perquè una sola pressió deixi anar just la quantitat justa. L'hàbit de fer-ne un ús mesurat és el fonament d'una llar que dura. Un petit clip posa límit, amb tendresa, al malbaratament."},"ICON-0697":{"nm":"Tapa penjadora per a maquineta d'afaitar","de":"Les coses afilades tenen la seva pròpia caseta a part. Encaixa la maquineta dins la tapa i penja-la, i tant la humitat com el perill s'escorren junts. Tractar amb cura l'afilat és també, al capdavall, una manera de cuidar-se un mateix."},"ICON-0698":{"nm":"Anella per a tovallola de dutxa","de":"Una tovallola llarga forma un llaç i arriba fins a l'esquena que la mà no podia tocar. Seguint aquesta única veta on la escuma llisca, una calidesa afable que renta la teva pròpia esquena s'escampa càlida per tot el bany."},"ICON-0699":{"nm":"Filtre de desguàs","de":"Una petita xarxa que deixa passar l'aigua i reté les restes. En un lloc que ningú veu, evita en silenci els embussos. Les coses que treballen al lloc més baix mantenen el flux de la casa, recorda sense paraules el desguàs."},"ICON-0700":{"nm":"Ganxo de ventosa","de":"Crea un lloc nou a la paret sense clavar-hi ni un sol clau. Prem-lo fort i enganxa'l, arrenca'l després, i ni tan sols en queda rastre. L'art de quedar-se una estona i marxar sense deixar marca —la ventosa el coneix molt bé, aquest tacte lleuger."},"ICON-0701":{"nm":"Etiqueta de xancletes de bany","de":"Un parell col·locat ben arrenglerat davant del llindar. La cura d'una llar on es descalcen les sabates s'estén amb dedicació fins a la porta del bany. Una etiqueta assenyala en silenci el lloc d'aquesta petita acollida que escalfa els dits freds dels peus."},"ICON-0702":{"nm":"Got de rentar les dents","de":"Un got petit i rodó que conté un glop per rentar-se les dents. En el breu instant d'esbandir-se, acull en silenci el començament i el final del dia. No és vistós, però hi és cada dia al teu costat: la senzillesa és la manera de fer casa que dura més."},"ICON-0703":{"nm":"Funda per al plomall","de":"Una funda que es posa sobre les plomes d'un plomall que recull la pols com si l'acariciés. Com un ocell que plega dolçament les ales quan no vola, una eina que sap on descansar es queda al teu costat molt de temps."},"ICON-0704":{"nm":"Recanvi de rodet antipèl·lusa","de":"Es despega una capa i, a sota, en sorgeix una de nova, ben suau. Les fulles enganxoses de dins recullen pelussa i cabells. Dins d'un recanvi rodó que es torna a omplir quan s'acaba, hi va enrotllada la virtut de la repetició diligent."},"ICON-0705":{"nm":"Pinça per a la baieta","de":"Una pinça que mossega ferma la baieta en lloc de la teva mà. Manté un pam de distància entre el terra fred i els teus dits. Un sol mànec que assumeix la feina bruta fa que netejar sigui molt més lleuger."},"ICON-0706":{"nm":"Tapa per al raspall de racons","de":"Una petita capsa que protegeix la punta tendra d'un raspall prim fet per endinsar-se en escletxes estretes. Un cor que atén fins i tot els racons on la mà no arriba. Qui neteja allò que no es veu fa créixer, un pam més, l'abraçada de la llar."},"ICON-0707":{"nm":"Anella etiquetadora per a polvoritzador","de":"Una petita etiqueta reposa suaument a l'espatlla d'un polvoritzador. Digui aigua clara o detergent el que conté, ho indica amb claredat en una sola línia. Una etiqueta que esborra la confusió per endavant és el vell costum d'una persona hàbil en les feines de casa."},"ICON-0708":{"nm":"Cinta de recanvi per a paper higiènic","de":"Una cinta que encaixa un rotlle nou al lloc buit i el lliga ben fort. El toc més senzill que torna a unir allò que s'havia tallat. El cor d'algú que reomple abans que s'acabi queda enrotllat, en rodona, en aquest petit llaç."},"ICON-0709":{"nm":"Ganxo per a guants de neteja","de":"Un ganxo que penja els guants humits a assecar just després d'acabar la feina d'aigua. Ofereix a les mans que han treballat un lloc on descansar una estona. Mentre la humitat s'asseca a poc a poc, un breu respir recupera l'alè per a la propera feina."},"ICON-0710":{"nm":"Xinxeta penja-escombres","de":"Si es penja l'escombra cap per avall, les cerres es mantenen rectes en lloc de vinclar-se. Una postura que espera dreta la propera feinada. Un racó petit però ferm que l'ajuda a conservar la seva forma fins i tot després d'haver complert la seva tasca."},"ICON-0711":{"nm":"Clip per a bosses d'escombraries","de":"Mossega la boca de la bossa amb fermesa i la sega ben tancada perquè no s'escapi res. Un sol gest que en tanca l'extrem fa que la recollida final sigui molt més neta. Acabar bé, al capdavall, comença sempre per saber tancar bé."},"ICON-0712":{"nm":"Pot de pinces d'estendre","de":"Un pot on viuen juntes les pinces d'estendre, tan fàcils de perdre quan queden escampades. Ofereix a aquestes coses petites una llar comuna on quedar-se. Aplega en un sol lloc els petits soldats dels teus dits i podràs trobar-los d'un cop d'ull quan els necessitis."},"ICON-0713":{"nm":"Anella per aparellar mitjons","de":"Un mitjó sense parella sempre s'escapa cap a algun lloc. Lliga cada parell amb una anella abans de rentar-los i, encara que quedin ben eixuts i tous, els dos no se separaran. Classificar és una petita promesa feta per endavant contra la desaparició."},"ICON-0714":{"nm":"Bossa per a bola de rentat","de":"Roda i roda dins la rentadora, colpejant suaument per despertar la brutícia impregnada a la roba. Un ritme que acaricia la bugada amb el seu cos rodó. Enmig de l'aigua que brama, porta enrotllat dins una bosseta l'antic instint de la bugada: el copeteig."},"ICON-0715":{"nm":"Tap dosificador per a detergent de llana","de":"A la roba delicada, la quantitat justa i delicada. Un tap dosificador que mesura amb precisió una sola tapa de detergent per a la llana. En una petita marca s'hi guarda el tacte curós de tractar la llana. Retallar l'excés també és una forma de devoció."},"ICON-0716":{"nm":"Pedaç adhesiu per a roba","de":"Un petit pedaç que es posa suaument damunt d'una zona desgastada. El cor dels dits que té cura d'un lloc gastat en lloc de llençar-lo sense miraments. A cada marca sargida hi queda, delicadament, el dibuix dels anys viscuts al costat d'aquella peça."},"ICON-0717":{"nm":"Xinxeta subjectadora per a estenedor","de":"Una xinxeta que subjecta en silenci l'estenedor perquè la roba no s'emporti el vent. Fins i tot els dies en què la bugada oneja al sol, ajuda a mantenir-la al seu lloc enmig del balanceig. La feina d'un petit però fiable contrapès."},"ICON-0718":{"nm":"Etiqueta per a bossa de rentat de roba interior","de":"La roba interior delicada es renta a part, dins d'una xarxa. Una xarxa que abraça ben protegides les coses toves de l'aigua que brama. Una petita bosseta amb etiqueta ens recorda que tenir cura amb precaució d'allò fràgil també és fer de casa."},"ICON-0719":{"nm":"Ganxo per a cullera de detergent","de":"Penja ben endreçada a la paret la cullera del detergent en pols. Sense el destorb de deixar-la caure dins el pot i mullar-te la mà. El costum polit de tenir sempre la mateixa eina al mateix lloc queda recollit, ben ferm, en aquest petit ganxo."},"ICON-0720":{"nm":"Topall per a corda d'estendre","de":"Mossega ben fort l'extrem de la corda d'estendre perquè, encara que hi carreguin la roba pesant, no es deslligui a poc a poc. El nus final que resisteix fins al final perquè una corda tibant no s'afluixi. D'aquí en depèn un acabat ben ferm."},"ICON-0721":{"nm":"Etiqueta de funda de coixí","de":"El lloc on cada nit la galta toca primer, amb una etiqueta cosida a l'interior, no més gran que una ungla. Qui llegeix mai la lletra menuda que indica la temperatura de rentat? Tot i així, és la guia més propera de totes, vetllant al costat d'una cara adormida."},"ICON-0722":{"nm":"Pinça per a l'edredó","de":"En una nit amb la finestra oberta, l'edredó no fuig encara que entri la brisa. Perquè una pinça amb la boca ben tancada agafa la cantonada. Una mà silenciosa que sosté la vora en lloc de qui dorm."},"ICON-0723":{"nm":"Pantalla per a llum de nit","de":"\"Si la llum arriba als ulls, el son s'allunya.\" Amb una sola pantalla que algú va col·locar sense fer soroll, la llum recula i només banya, difusa, els peus del llit. Una petita separació que presta un pam de foscor."},"ICON-0724":{"nm":"Butxaca per a l'escletxa del llit","de":"Pensa en aquella escletxa entre el matalàs i la paret que mai la mà podia tocar. El comandament que hi havia caigut, les ulleres també, ara s'apleguen aquí. Una butxaca que el llit desplega discretament per recollir les coses que gairebé havies perdut."},"ICON-0725":{"nm":"Safata per a ulleres","de":"Et lleves les lents i el món es difumina suaument, i un plat poc profund recull aquesta breu indefensió. Al matí, encara que els dits no vagin a les palpentes, les ulleres sempre t'esperen al mateix lloc."},"ICON-0726":{"nm":"Peanya per a despertador","de":"A les sis del matí, damunt d'una base ferma sona el so més odiat de tots. Sense trontollar, sosté el rellotge i, al final, obre el dia d'algú. Aguanta, sense dir res, la promesa seca de despertar-se."},"ICON-0727":{"nm":"Subjectador de cable de capçalera","de":"El cable de càrrega que abans lliscava fins a terra des del capçal ja no hi cau més. Perquè un petit subjectador aguanta suaument l'extrem del fil. A l'abast de la mà, un toc que ha endreçat el recorregut de la nit."},"ICON-0728":{"nm":"Cinta per guardar pijama","de":"Una cinta que envolta un cop i lliga el pijama, ben plegat. Fins i tot la suavitat que s'arruga fàcilment necessita compostura. Per al jo de demà a la nit, el jo d'avui l'enrotlla amb pulcritud, una petita preparació."},"ICON-0729":{"nm":"Suport per a targeta perfumada","de":"Col·loca una targeta perfumada de biaix i, com qui passa una pàgina, passes l'estació amb el nas. De lavanda a cítric: es converteix en el diari d'aquell dia escrit amb olors."},"ICON-0730":{"nm":"Coixinet per a plat de claus","de":"Un racó a l'entrada on les claus solien caure amb un dring. Un plat encoixinat amb un tou suau engoleix aquell so agut. Un petit suport rep en silenci el primer gest de qui torna a casa."},"ICON-0731":{"nm":"Tapa recull-gotes per a paraigua","de":"L'aigua de la pluja regalima gota a gota des de la punta del paraigua que has portat a dins. Una tapa recull aquest degoteig amb precisió, així que algú s'ha avançat a preveure i evitar el petit bassal que s'hauria escampat pel terra."},"ICON-0732":{"nm":"Xip penja-mascaretes","de":"Un xip no més gran que una ungla enganxat a la paret vora la porta. Com l'últim ritual abans de sortir, aquí hi penja la mascareta. Un petit dispositiu de memòria que manté l'alçada dels ulls a la porta perquè no oblidis què t'has d'endur."},"ICON-0733":{"nm":"Funda per a cutter de paquets","de":"Una funda protectora que es posa sobre la fulla que obre les capses dels paquets. Cobreix en silenci el risc d'un tall amagat darrere l'emoció de desembalar. Una atenció discreta que obre amb seguretat el final d'una espera."},"ICON-0734":{"nm":"Suport per a raspall de sabates","de":"El lloc on descansa, encara humit, el raspall de sabates acabat de fer servir. Encara que retingui la humitat, el terra es manté sec i net. Fins i tot una eina que crea netedat necessita un lloc on descansar, ens fa saber aquest petit suport."},"ICON-0735":{"nm":"Tauler de notes per a visitants","de":"\"He passat un moment.\" Una breu línia escrita al tauler de notes de l'entrada. Una petita plaça on persones que s'han creuat sense trobar-se comparteixen a través del temps. En un sol requadre de paper, s'hi acumulen encavalcats una salutació, un prec i un cor."},"ICON-0736":{"nm":"Rotlle tapa-corrents per a porta","de":"El corrent d'aire que s'esmunyia per l'escletxa, no més ampla que un dit, sota la porta. Un tapaforats enrotllat bloqueja en silenci aquell pas. Reté una capa més de calor a l'habitació que s'anava escapant sense veure's."},"ICON-0737":{"nm":"Penjoll topall per a porta","de":"Un petit penjoll que aguanta la base d'una porta ben oberta perquè no es torni a tancar. Manté el seu pes ferm per a la brisa i les passes que hi entren i surten. Una tossuderia amable que fa durar l'obertura."},"ICON-0738":{"nm":"Funda fosforescent per a interruptor d'entrada","de":"L'interruptor de l'entrada que buscaves a les palpentes a altes hores de la nit. Una funda fosforescent assenyala amb suavitat el seu lloc en la foscor. Perquè la mà no s'esgarriï, un petit guia que brilla abans que la llum s'encengui."},"ICON-0739":{"nm":"Estoreta per a got","de":"L'instant en què un got deixat a taula comença a lliscar, una estoreta aguanta suaument el seu peu. Un sotagot que manté el seu lloc amb calma, sense deixar ni una marca encara que hi condensin gotes d'aigua."},"ICON-0740":{"nm":"Clip aromàtic per a cotxe","de":"Un petit clip perfumat penjat dins del cotxe. Muntant l'aire de la ventilació, una olor tènue omple a poc a poc l'espai reduït. Un consol amable al seient del conductor que escalfa amb aroma fins i tot l'avorriment d'esperar en un semàfor."},"ICON-0741":{"nm":"Funda per a cinturó de seguretat","de":"Una funda tova que es col·loca sobre el cinturó que et travessa l'espatlla. L'aspror que tocava el clatell s'esvaeix suaument. Fins i tot una corretja pensada per a la seguretat pot dur-hi afegida dolçor, diu aquest pam de roba."},"ICON-0742":{"nm":"Tauler ocultador de número d'aparcament","de":"Un tauler que amaga discretament, abans de fer una foto, el rètol que indicava la teva plaça a l'aparcament soterrani. Tothom té alguna informació que preferiria no deixar enrere. Una capa esborrada amb cura d'una escena de la vida quotidiana."},"ICON-0743":{"nm":"Tapa per a timbre de bicicleta","de":"Dring-dring. La salutació lluminosa que una bicicleta ofereix a la cantonada d'un carreró. Una tapa sobre el timbre en preserva el so fins i tot sota la pluja. Amb un sol dringar petit, la gent somriu i fa un pas de costat."},"ICON-0744":{"nm":"Anella d'agafador per a manillar","de":"Una anella que embolcalla suaument el tacte del manillar contra el palmell. Encara que s'hi aguanti molta estona pedalant, les mans no s'entumeixen. Com més llarg és el camí, més la comoditat de l'agafador n'escurça la distància."},"ICON-0745":{"nm":"Adhesiu identificador per a casc","de":"Un adhesiu amb el nom enganxat a l'interior d'un casc. Entre cascos idèntics, crida fluixet: \"aquest és el meu\". La marca més personal, gravada damunt la duresa que protegeix el cap."},"ICON-0746":{"nm":"Tapa reflectora per a roda","de":"Una tapa que només comença la seva feina quan es pon el sol. Capta la llum que passa i reflecteix la roda amb nitidesa. En la foscor, envia amb llum el petit senyal: \"aquí hi ha algú\"."},"ICON-0747":{"nm":"Funda protectora per a clau de cotxe","de":"Una clau de cotxe que solia ratllar-se en topar amb altres claus a la butxaca. Una funda tova n'embolcalla la superfície ben ajustada. Hi ha el desig que allò que agafes cada dia duri molt de temps sense esgarrinxades."},"ICON-0748":{"nm":"Xinxeta de ventosa per a prestatge","de":"Una xinxeta de ventosa per a prestatge que s'enganxa a la paret sense clavar-hi cap clau. Fins i tot una paret on no vols deixar-hi marca guanya un compartiment d'endreça. La destresa de penjar-hi coses de casa en una habitació que només tens de pas, sense deixar rastre."},"ICON-0749":{"nm":"Tauler de ganxos sense forats","de":"Imagina poder penjar-hi alguna cosa sense foradar la paret. Un tauler de ganxos sense forats assumeix discretament una càrrega lleugera. El desig de no fer malbé un espai prestat queda recollit, amb delicadesa, en un sol ganxo petit."},"ICON-0750":{"nm":"Barra magnètica organitzadora","de":"El so d'un metall que fa tec i s'enganxa al seu lloc. Aplega amb un imant, d'una escombrada, les eines menudes escampades pertot arreu, i un plaer petit acompanya com una taula de treball desendreçada s'arrengla en una sola filera."},"ICON-0751":{"nm":"Barra organitzadora per a escletxes","de":"Pensa en aquella escletxa estreta i oblidada entre la nevera i la paret. Una barra prima omple aquell buit amb utilitat. Una idea estalviadora que treu profit d'un espai que es donava per inútil."},"ICON-0752":{"nm":"Làmina de coixinets adhesius","de":"Una làmina de coixinets adhesius que, un cop enganxada, aguanta amb facilitat fins i tot coses pesants. Es despega i, curiosament, no hi queda ni una sola marca. Una força silenciosa i tenaç que suporta el pes des d'un lloc que no es veu."},"ICON-0753":{"nm":"Ganxo penjador per a porta","de":"Un ganxo que només cal penjar suaument a la part de dalt d'una porta. Bosses i tovalloles hi pengen a l'alçada de la mà. Un penjador nascut sense clavar-hi ni un clau afegeix un racó més d'espai en una habitació estreta."},"ICON-0754":{"nm":"Clip de paret per a cables","de":"Un clip que aplega en una sola línia els cables que penjaven per la paret. La madeixa embullada darrere l'escriptori s'estira en un traç net. Una endreça invisible que fa que fins i tot l'aire de l'habitació se senti més lleuger."},"ICON-0755":{"nm":"Coixinet per a base de làmpada","de":"Un coixinet que es posa suaument sota el peu d'una làmpada de peu. No deixa cap ratllada a l'escriptori i calma fins i tot el tremolor més subtil. Fins i tot alçar la llum comença per un terra que no vacil·la."},"ICON-0756":{"nm":"Placa adhesiva antilliscant","de":"L'estora que s'anava escapant a poc a poc sota els peus, per fi s'atura al seu lloc, perquè la placa adhesiva mossega ben fort el terra. Una xarxa de seguretat invisible que allunya per endavant l'ensopegada que gairebé passa."},"ICON-0757":{"nm":"Tapa per a destornillador de precisió","de":"\"Aquest cargolet no vol amollar.\" Una tapa posada a la punta d'un destornillador de precisió en protegeix la fulla. L'eina més delicada dels dits, que obre el món no més gran que un palmell dins d'una màquina."},"ICON-0758":{"nm":"Anella per a claus Allen","de":"Una anella que enfila diverses claus Allen en un sol cèrcol. El metall, arrenglerat per mides, s'obre en ventall amb un so sec. El ritme endreçat d'una mà que tria d'un sol cop l'única que necessita."},"ICON-0759":{"nm":"Penjoll de cinta mètrica","de":"Un penjoll fixat a una cinta mètrica en miniatura que cap perfectament al palmell. Penja d'un clauer i t'acompanya arreu. Un petit amic que mesura i respon, allà mateix, qualsevol llargada que de sobte et desperti curiositat."},"ICON-0760":{"nm":"Capsa classificadora de cargols","de":"Una capsa classificadora on cada cargol despariat troba el seu propi compartiment. Fins i tot les peces menudes que abans rodolaven barrejades hi guanyen ordre. La mà que aprèn primer a endreçar abans d'arreglar qualsevol cosa."},"ICON-0761":{"nm":"Tapa de broquet per a cola","de":"Tancada no m'endureixo, oberta m'asseco: visc en aquest espai intermedi. Cada gota que cau és, en algun lloc, alguna cosa trencada que es torna a unir. Una petita tapa vetlla en silenci la frontera entre la quietud i el flux."},"ICON-0762":{"nm":"Clauer amb nivell","de":"Una honestedat de mida palmell que balla a l'extrem d'un manoll de claus. Sempre és aquesta petita bombolla la primera a adonar-se d'un prestatge tort. Duc a la butxaca un amic que em diu, en silenci, que el món s'ha decantat una mica."},"ICON-0763":{"nm":"Tapa protectora per a pinces","de":"Com més punxegut és quelcom, més necessita una vestimenta que el calmi. Cobreix les puntes amb suavitat i ni la mà ni les peces es fan mal. La primera cortesia per tractar allò esmolat és cobrir-ne suaument la punta, i aquesta petita tapa n'assumeix la gentilesa."},"ICON-0764":{"nm":"Estoreta de tall petita","de":"Una planxa les cicatrius de la qual es curen soles, fins i tot després de milers de passades de fulla. Sobre el tall hi torna a posar-se la propera feina, i torna a cicatritzar. Un terra silenciós que dona el seu propi cos perquè altres coses es puguin tallar amb pulcritud."},"ICON-0765":{"nm":"Bosseta de peces de recanvi","de":"Una bosseta que tanca ben bé la boca perquè un sol cargol, una sola molla, no desapareguin per sempre. Les coses petites que sobren després d'una reparació esperen aquí, en silenci, el seu proper torn. Sempre són compartiments humils com aquest els que impedeixen que es perdin les coses."},"ICON-0766":{"nm":"Clip per a bossa d'aperitius","de":"Mantenir cruixent una bossa oberta es redueix, al final, a un sol pessic decidit. Una petita promesa de no donar cap oportunitat perquè es reblaneixi. El costum de tancar bé l'extrem salva el berenar de demà."},"ICON-0767":{"nm":"Got de racions per a gelees","de":"Per compartir una bossa entre molts, primer cal repartir-la amb justícia. El cor que reparteix la mateixa porció a cada got petit. Compartir, crec, comença sempre amb la mateixa quantitat exacta, perquè ningú se senti deixat de banda."},"ICON-0768":{"nm":"Retall de paper de xocolata","de":"L'argent que embolicava la dolçor s'arruga fàcilment als dits. S'estira i brilla un instant; es doblega i esdevé record. Un retall de llum que es fa més bonic només després d'haver-se'l menjat tot: fes-hi una ullada més abans de llençar-lo."},"ICON-0769":{"nm":"Tira etiquetadora per a aperitius","de":"Què conté, fins quan és bo: parlo jo en lloc de la bossa muda. En el moment en què s'hi enganxa una sola tira, fins i tot un aperitiu guanya un nom i una promesa. Classificar és, en realitat, la manera més tendra de recordar."},"ICON-0770":{"nm":"Capsa classificadora de caramels","de":"No poses els àcids i els dolços al mateix compartiment. La feina de separar-los per endavant perquè la mà no dubti. Quan les capsetes s'arrengleren en fila, el plaer de triar es dobla sense fer-se notar."},"ICON-0771":{"nm":"Paper encoixinador per a galetes","de":"Paper prim que s'intercala entre galetes perquè no es facin blaus pel camí. Com més fràgil és una cosa, més suau ha de ser la companyia que necessita. De vegades la tovor protegeix millor que la fermesa."},"ICON-0772":{"nm":"Cordill per a caixa de donuts","de":"Un sol nus creuat es fa responsable del bon viatge del pastís dins de la caixa. Es converteix en nansa, en segell, en senyal d'una espera plena d'il·lusió. El moment en què aquest cordill es deslliga és el d'un aniversari d'algú."},"ICON-0773":{"nm":"Tancament per a bossa de pa","de":"Tòrceu-me un cop, plegueu i col·loqueu-me, i la tendresa del pa quedarà segellada fins demà al matí. Una petita tossuderia obstinada a bloquejar l'aire. Mantenir suau alguna cosa durant molt de temps sempre és feina d'alguna cosa ferma."},"ICON-0774":{"nm":"Etiqueta d'intercanvi d'aperitius","de":"La teva part per a mi, la meva part per a tu. Recordes l'emoció d'escriure noms en petites etiquetes i intercanviar aperitius aquell dia? El paper enganxat a un cor que comparteix sempre porta escrit, amb lletra clara, el nom d'un amic."},"ICON-0775":{"nm":"Tap per a canyeta","de":"Quan et prens un respir entre glop i glop, em tanques. Perquè no vessi, perquè no es refredi, perquè esperi tranquil·lament allà mateix. La feina d'un petit tap que vigila l'obertura fins que els llavis hi tornin."},"ICON-0776":{"nm":"Anella identificadora per a got tèrmic","de":"Una petita anella que diu \"aquest és el meu\" entre una filera de gots tèrmics arrenglerats. Un sol color i la confusió es dissol suaument. Una sola anella basta per marcar, amb claredat, allò que és teu."},"ICON-0777":{"nm":"Màniga per a got","de":"Una sola capa de cartró ondulat que s'esmuny entre un got calent i el palmell de la mà. Un gest d'atenció que s'hi col·loca perquè no et cremis ni se t'escapi de les mans. Vetllar l'espai intermedi és el que completa un got segur i sencer."},"ICON-0778":{"nm":"Etiqueta per a cubitera","de":"Hi ha qui apunta la data en què va fer cada tanda de gel. Amb la creença que fins i tot el fred té un ordre. Una sola etiqueta petita fa que el temps del congelador flueixi amb honestedat, un torn rere l'altre."},"ICON-0779":{"nm":"Pinces per a bossetes de te","de":"Vigilant el temps d'infusió, el treus just en el moment precís. El bon ofici de saber aturar-se abans que agafi massa gust. La profunditat d'un te la decideix més el moment de treure'l que el temps que hi ha estat en remull."},"ICON-0780":{"nm":"Suport per a filtre de degoteig","de":"Sosté el filtre i es queda dret i callat perquè l'aigua calenta baixi a poc a poc. Sap bé que si s'apressa, l'aroma queda superficial. Fins i tot la feina de sostenir l'espera necessita una postura que no vacil·li."},"ICON-0781":{"nm":"Corretja per a ampolla","de":"Una corretja que penja l'ampolla d'aigua del canell o de l'espatlla per caminar plegats. Una manera de fer companyia que la manté sempre a prop sense haver-la de recordar expressament. De vegades, lligar-la lleugerament és la manera més tendra de no oblidar-la."},"ICON-0782":{"nm":"Tapa per a llauna","de":"Cobreix la boca d'una llauna a mig acabar per evitar la pols i que perdi el gas. Un petit capell que es fa càrrec de la frescor fins al proper glop. Fins i tot cobrir amb calma allò que ha quedat obert un moment porta la seva dosi de dedicació."},"ICON-0783":{"nm":"Fundeta per a targeta de fidelitat de begudes","de":"El desè got gratuït: acull la targeta de segells perquè aquesta promesa no es perdi. Perquè els dies omplerts caselleta a caselleta no es facin malbé arrugats. Dins d'aquesta fundeta s'hi acumulen les passes diligents d'un client habitual."},"ICON-0784":{"nm":"Cinta per a carmanyola","de":"Una cinta que envolta un cop la carmanyola per abraçar-la perquè la tapa no s'obri. Una petita tranquil·litat que assegura que el brou no vessarà dins la bossa. El bon viatge fins a l'hora de dinar és responsabilitat d'aquesta única volta ben ajustada."},"ICON-0785":{"nm":"Joc de gots per a acompanyaments","de":"Dona a cada acompanyament el seu propi lloc i els gustos no es barregen. El quimchi com a quimchi, les verdures com a verdures, cadascú net i clar. Els compartiments que fan aquests gots petits són l'ordre de la carmanyola, i una tendresa per sobre del bon fer de qui cuina."},"ICON-0786":{"nm":"Estoig per a bastonets","de":"Una petita llar que porta nets els bastonets que han compartit els tres àpats del dia. Un company silenciós que manté la pulcritud fins i tot dins d'una motxilla escolar. La cura de portar-los sempre a sobre és, al final, allò que fa un àpat polit."},"ICON-0787":{"nm":"Etiqueta per a ampolla de salsa","de":"Salsa de soja o vinagre? Dona claredat a l'ampolla que abans confonies. En el moment en què s'hi enganxa una sola línia, la vacil·lació dels dits desapareix. El ritme d'una cuina atrafegada el creen, en silenci, petites marques com aquesta."},"ICON-0788":{"nm":"Full per enrotllar gimbap","de":"Un full prim d'alga que enrotlla l'arròs i el farciment en un sol cos. Cal embolicar-lo amb fermesa perquè no es desfaci en tallar-lo. L'emoció d'un matí de sortida al camp surt enrotllada, ben rodona, d'aquesta única capa."},"ICON-0789":{"nm":"Pot per a escuradents i broquetes","de":"Posa dretes les broquetes i els escuradents en un sol lloc, i la mà no s'esgarriarà quan arribi el moment. Donar, fins i tot a les coses punxegudes, una llar pròpia. Endreçar és, al final, una petita amabilitat per a la propera mà que hi haurà de venir a buscar."},"ICON-0790":{"nm":"Funda per a plaqueta refrigerant","de":"Embolica la plaqueta refrigerant amb una capa més per retenir el fred una mica més de temps. Alhora, evita que la bossa es mulli per la condensació. Mantenir la frescor fins al final és sempre feina d'aquesta capa gruixuda."},"ICON-0791":{"nm":"Separador per a carmanyola","de":"Un petit mur alçat perquè l'arròs i els acompanyaments no envaeixin el lloc de l'altre. La pau d'un compartiment on el brou no traspassa. Una carmanyola dividida en caselles conserva intacte, dins seu, el cor meticulós de qui l'ha preparada."},"ICON-0792":{"nm":"Targeta d'ordre del menjar","de":"Sopa primer o arròs primer? Una targeta que suggereix amb suavitat el menú d'avui. Una guia amable que diu que sap millor menjat en ordre. Ens fa saber, en silenci, que fins i tot un àpat té un fil narratiu, com una història."},"ICON-0793":{"nm":"Adhesiu per a got mesurador","de":"Un petit adhesiu enganxat vora les marques assenyala amb precisió \"fins aquí\". Una marca que encerta d'un sol cop la quantitat que sempre et feia dubtar. La precisió neix, així, d'una sola línia de guia tan petita."},"ICON-0794":{"nm":"Agafador de silicona per a tapa","de":"Una petita nansa que et permet aixecar una tapa calenta sense cremar-te els dits. Presta discretament el coratge d'obrir una olla que fumeja. La seguretat sempre neix de preparar per endavant un lloc on agafar-se."},"ICON-0795":{"nm":"Penjador amb pinça petita","de":"Una petita pinça que dona un lloc a draps de cuina o bosses que no tenien on penjar-se. Converteix un racó desordenat de paret en un paisatge endreçat. Un sol costum de penjar les coses fa la cuina molt més lleugera."},"ICON-0796":{"nm":"Tapa per a pinzell d'oli","de":"Cobreix la punta del pinzell d'untar oli i tant la pols com l'enduriment el passen de llarg. Un capell que en conserva la suavitat fins al proper plat. Una petita cura per les eines pròpies acaba per preservar durant molt de temps el sabor."},"ICON-0797":{"nm":"Pot amb culleró per a sal","de":"Un petit culleró que viu clavat dins del pot de la sal. Recull, cada vegada, amb cura, la precisió d'un pessic. El bon ofici d'assaonar és el cor que aquest petit culleró recorda amb exactitud."},"ICON-0798":{"nm":"Placa magnètica amb temporitzador","de":"Enganxada a la porta de la nevera, compta els 3 minuts del fideus instantani i marca els 30 segons d'exercici. Amb un sol imant, el temps a punt d'escolar-se es queda una estona davant dels teus ulls. Un cercle diligent que fixa un moment a la paret abans que passi de llarg."},"ICON-0799":{"nm":"Funda per a mànec de cassola","de":"Una capa que envolta el mànec escalfat perquè no l'agafis amb la mà nua. Un petit escut que es planta entre la calor i el palmell. Transportar-la sana i estàlvia comença sempre amb aquest embolcall suau."},"ICON-0800":{"nm":"Goma antilliscant per a tauler de tallar","de":"Quan m'estenc sota seu, el tauler de tallar ja no llisca més. Un tros de goma que aguanta des de sota cada vegada que el ganivet fa trontollar. L'estabilitat és la feina de mossegar fort en un lloc que no es veu."},"ICON-0801":{"nm":"Pinça per a manyoples de cuina","de":"Un lloc on la mà que es movia sense parar davant el foc s'atura un instant. Si pengeu una manyopla que oneja a la paret, comença una breu pausa per respirar fins al pròxim àpat. Endreçar és, al capdavall, un altre nom per a la tendresa."},"ICON-0802":{"nm":"Suport per a agitadors de cafè","de":"Al costat del taulell, un racó on els bastonets prims s'arrengleren espatlla contra espatlla, ben apilats. A punt per dibuixar un remolí a la tassa del matí d'algú, alineats en files com un cor a punt de començar a cantar."},"ICON-0803":{"nm":"Cinta per a joc de sotagots","de":"Una cinta que acull amb suavitat aquell petit tic-tic d'un got en tocar la taula. Si lligueu els sotagots rodons junts, la benvinguda als convidats ja és a punt. L'hospitalitat sempre comença, així, en els llocs més petits."},"ICON-0804":{"nm":"Fitxa etiqueta per a xarop","de":"Un sol nom enganxat a l'ampolla. Dolç, intens: aquesta paraula breu apaivaga un matí atrafegat i el fa una mica més ordenat. L'etiqueta és paper on s'anota per endavant una petita promesa."},"ICON-0805":{"nm":"Pot per a punxons de postres","de":"Un pot on viuen junts els bastonets punxeguts que clavaran un tros de fruita. Abans de plantar-se com banderetes damunt un plat de postres, hi esperen en silenci el seu torn. Fins i tot el dolç té el seu ordre."},"ICON-0806":{"nm":"Fundeta per a agitador de còctel","de":"Un vestit de paper que abraça un grapat de bastonets d'agitar. Absorbeix la humitat que deixa anar una beguda freda, mantenint eixuts els dits que sostenen el got. L'atenció invisible sempre arriba des dels marges."},"ICON-0807":{"nm":"Etiqueta per a portagots per emportar","de":"Quan dues mans no basten, una petita nansa porta els gots per tu. Sosté l'escalfor embolicada perquè no en caigui ni una gota, i acompanya aquesta calidesa fins al cantó del carrer d'algú."},"ICON-0808":{"nm":"Funda per a avisador de cafeteria","de":"Un vestit que embolcalla amb calma l'espera fins que sona el brunzit. Custodiant el número lluminós del teu torn en un racó de la cafeteria, també guarda l'emoció que aviat cridaran el teu número."},"ICON-0809":{"nm":"Anella per a targetes de segells","de":"Un paper on omplir les deu caselles et regala una tassa de propina. Amb cada segell que s'hi afegeix, també creix una mica el nom de «habitual». Una alegria senzilla, ensartada en una petita anella."},"ICON-0810":{"nm":"Bosseta de mostra de grans de cafè","de":"Una bosseta que conté un grapat de grans i n'ofereix l'aroma abans que res. L'acidesa i la dolçor que passen fregant el nas, aquesta primera impressió decideix el destí d'una tassa. L'aroma arriba més de pressa que qualsevol explicació."},"ICON-0811":{"nm":"Imant etiqueta per a nevera","de":"Una petita etiqueta imantada que s'enganxa a la porta de la nevera amb un toc. Si hi anoteu què hi ha entrat i quan, fins i tot un plat gairebé oblidat recupera el seu torn. Portar la casa és la feina de fixar el record que s'escola."},"ICON-0812":{"nm":"Fitxa de data de conservació","de":"Un fragment que grava amb claredat el dia que es va guardar alguna cosa. Un petit testimoni que, en silenci, diu que encara està bé fins i tot dies després. La frescor es preserva gràcies als dits que recorden la data."},"ICON-0813":{"nm":"Cinta per a envàs de racions","de":"Una cinta que abraça tot al voltant la cintura d'un envàs repartit. Estreny fort la tapa que trontollava, mantenint un petit ordre dins la nevera. Lligar alguna cosa s'assembla a la feina d'endreçar el cor."},"ICON-0814":{"nm":"Tira de clips de colors per tancar bosses","de":"Clips de colors que mosseguen ben ajustats la boca d'una bossa. Vermell per al picant, groc per al dolç: la mà ho sap només de veure el color. Els semàfors de la cuina guien el camí així, sense dir ni una paraula."},"ICON-0815":{"nm":"Etiqueta per a paquets congelats","de":"Una etiqueta posada suaument damunt d'alguna cosa congelada. Reconforta la bossa coberta de gebre perquè no oblidi què va ser. Una petita salutació enviada als ingredients que han entrat en el seu son hivernal."},"ICON-0816":{"nm":"Xarxa per a conservar verdures","de":"Una xarxa esponjosa que acull amb generositat les verdures tacades de terra. La cuina de l'àvia ja sabia fa temps que deixar-los espai per respirar les fa durar més. La ventilació és un marge tendre que s'ofereix a les verdures."},"ICON-0817":{"nm":"Tap classificador de taps d'ampolla","de":"Un tap classificador que aparella, un per un, taps segons la mida. Retrobar una parella perduda és més tendre del que sembla. Si acobleu una parella escaient, la cuina també cau en un ordre més net."},"ICON-0818":{"nm":"Etiqueta per a safata d'ous","de":"Una marca ben ordenada assignada a cadascun dels deu petits nius. La saviesa domèstica que diu de fer servir primer els ous més vells. Fins i tot un simple ou ferrat del matí porta dins el cor de tenir cura de l'ordre."},"ICON-0819":{"nm":"Adhesiu per a restes de menjar","de":"Escriviu «Això és meu!» i enganxeu-ho, i fins i tot la nevera troba un moment de pau. Una declaració de guerra ben tendra que reclama per endavant qui és l'amo del piscolabis nocturn. La família continua rodant, avui també, gràcies a petits tractats com aquest."},"ICON-0820":{"nm":"Reposacoberts","de":"Un petit fragment que sosté amb suavitat la cullera i les bastonets perquè no toquin directament la taula. Aquesta petita polidesa eleva, sense fer soroll, la categoria d'un àpat. Els bons modals a taula creixen, sense adonar-nos-en, en llocs com aquest."},"ICON-0821":{"nm":"Anella subjectaservilletes","de":"Una anella que s'hi encaixa amb calma i reté una tovalló que el vent faria volar. Aplega el paper blanc que espera el seu torn per desplegar-se, gravant amb pulcritud un petit ordre damunt la taula."},"ICON-0822":{"nm":"Cantonera per a estora de taula","de":"Un fragment que pressiona amb suavitat i calma la cantonada aixecada d'una estora. La taula ensenya cada dia que només quan es reté un extrem tot el conjunt queda pla. Fins i tot una cantonada té la seva part de responsabilitat."},"ICON-0823":{"nm":"Safata petita per a condiments","de":"Una safata petita que sosté, l'una al costat de l'altra, una escudelleta de salsa de soia i un pessic de sal. La generosa cabuda d'una taula que dona el seu propi lloc fins i tot a un acompanyament. La cuina coreana s'aprofundeix en el cor que té cura dels petits complements."},"ICON-0824":{"nm":"Fitxa de número de taula","de":"El número que criden com «taula tal!» en un restaurant atrafegat. Assigna un ordre a l'espera i manté la justícia per a tothom. El que porta aquesta única fitxa és una petita promesa, i un bol calent que arribarà ben aviat."},"ICON-0825":{"nm":"Cinta identificadora de got d'aigua","de":"Una cinta que s'enrotlla al got d'aigua per dir en veu baixa de qui és. Una petita bandera que marca el teu lloc entre gots que s'assemblen. En una taula compartida, aquesta petita atenció evita confusions innecessàries."},"ICON-0826":{"nm":"Agulla classificadora de platets","de":"Una agulla que distingeix per colors els platets on cadascú se serveix. Traça amb tendresa la frontera entre el que és teu i el que és meu, fent més neta encara l'alegria de compartir. L'afecte es reparteix, però la higiene es guarda amb cura."},"ICON-0827":{"nm":"Faristol de carta","de":"El temps de rumiar que s'amaga rere una carta oberta. Fins i tot aquesta breu vacil·lació sobre què menjar és, en realitat, part de l'àpat. Què tastarem avui: guarda amb discreció aquesta petita emoció."},"ICON-0828":{"nm":"Suport per a targetó de lloc","de":"Un petit suport que manté dreta una targeta amb un nom. Sigui en un esdeveniment o en un banquet, anuncia amb claredat que aquí hi ha el teu lloc. L'hospitalitat només es completa en el moment que es pronuncia un nom."},"ICON-0829":{"nm":"Fundeta per a magdalena","de":"Un vestit de paper que abraça ben ajustat la cintura rodanxona d'una magdalena acabada de fer. Sosté el cos calent perquè no rellisqui de la mà, i en guarda l'escalfor fins al mateix instant de la primera mossegada. Fins i tot les postres necessiten un vestit."},"ICON-0830":{"nm":"Tap per a mànega pastissera","de":"Un tap que manté ben tancada la punta d'una mànega pastissera. Segella la boca amb fermesa perquè no s'escapi ni una gota mentre reposa. La petita flor damunt d'un pastís floreix d'aquesta contenció."},"ICON-0831":{"nm":"Anella de talladors de galetes","de":"Un joc rodó de motlles que retallen la massa en forma d'estrelles i óssos. La mateixa farina es desperta en desenes d'expressions a través dels dits. Es cuini el que es cuini, el primer que toca la massa és sempre la dedicació."},"ICON-0832":{"nm":"Penjoll de rascador de massa","de":"Una mà plana que arreplega la massa amb mesura i la parteix amb netedat. Aquella diligència de tenir cura fins i tot del grapat enganxat al bol decideix el volum d'una peça de pa. Fer pa és la feina d'una mà estalviadora."},"ICON-0833":{"nm":"Taulell per a culleres mesuradores","de":"Una tauleta que estén amb ordre, sense un sol balanceig, les culleres mesuradores: una cullereta, mitja cullerada. Una mesura exacta posa dreta la balança del sabor. Darrere l'expressió «mà bona» s'amaga, de fet, una mesura acurada."},"ICON-0834":{"nm":"Ganxo per a manyopla de forn","de":"Un ganxo per penjar la manyopla que muntava guàrdia davant un forn ardent. La mà gruixuda que evitava les cremades roman a l'abast fins i tot mentre descansa. La seguretat sempre comença amb allò que es queda al seu lloc."},"ICON-0835":{"nm":"Pinça per a reixa de refredar","de":"Unes pinces que mosseguen amb pulcritud la reixa on refreden els dolços acabats de fer. Els retenen perquè no es moguin mentre s'escapa el vapor, esperant plegats que la cruixença arribi a la seva plenitud. Fins i tot refredar demana un grapat de paciència."},"ICON-0836":{"nm":"Pica per a topper de pastís","de":"Una pica que enlaira damunt un pastís les cinc lletres de «Molts anys». Just abans que s'apaguin les espelmes, aquesta petita bandera il·lumina el dia d'algú amb la llum més viva. Una celebració es veu millor com més amunt s'aixequi."},"ICON-0837":{"nm":"Ensucrador","de":"Un ensucrador que guarda l'últim esquitx lleuger. Es diposita com neu blanca damunt d'unes postres acabades de fer, i converteix un tros ordinari en un petit regal. El toc final arriba sempre de la mà més lleugera."},"ICON-0838":{"nm":"Etiqueta per a onigiri triangular","de":"Peleu el plàstic en l'ordre 1, 2, 3 i l'alga torna cruixent en aquell triangle. Una sola línia que permet reconèixer d'una ullada l'amic reconfortant de la botiga oberta les vint-i-quatre hores a trenc d'alba. Les nits de gana després d'hores d'estudi s'hi aferren, justament aquí."},"ICON-0839":{"nm":"Subjectatapes per a got de fideus instantanis","de":"Un suport que pressiona amb calma perquè la tapa no s'aixequi durant els tres minuts d'espera. Substitueix el lloc dels bastonets que abans es posaven a sobre perquè el vapor no s'escapés. Aquesta breu estona en què els fideus couen és el moment més emocionant d'un àpat nocturn."},"ICON-0840":{"nm":"Tap per a broqueta de hot bar","de":"Un petit tap que abraça amb fermesa la punta d'una broqueta. Vigila perquè sigui fàcil de mossegar, sense que caigui ni una gota de salsa a la mà. El plaer de mossegar davant d'una parada de bunsik sempre es completa amb aquestes petites coses."},"ICON-0841":{"nm":"Nansa per a bossa de plàstic","de":"Si l'enganxeu als dits, el plàstic cruix fluixet. El pes de la compra s'inclina cap a un costat, i el camí fins a casa deixa una marca vermella al palmell. Dins d'aquell so lleuger, la feina de tota una jornada de casa s'hi endinsa, pesant, i s'hi balanceja."},"ICON-0842":{"nm":"Clip plegador de tiquets","de":"Plegueu pel mig un tiquet llarg i desenrotllat, tanqueu-lo amb un clic, i la despesa del dia esdevé un fardell endreçat. Mentre el paper amb olor de tinta s'apila, els petits records de la vida domèstica també van caient en ordre."},"ICON-0843":{"nm":"Etiqueta per a microones","de":"Abans que soni el «ping», l'etiqueta calcula amb calma el temps d'escalfar. Un petit rètol que anota quants minuts i segons, i el nom del que cal escalfar. Fins i tot el cor que espera el seu torn per escalfar-se té marques com aquestes."},"ICON-0844":{"nm":"Rotlle d'adhesius de descompte","de":"Cada cop que s'arrenca un quadret, un petit xerric enganxós fa pessigolles als dits. Quan els números vermells es van desenrotllant en fila, la cistella de la compra d'algú s'alleugereix una mica. Un rotlle de petita amabilitat, enrotllat i a l'espera."},"ICON-0845":{"nm":"Anella per a sobre de salsa","de":"Alguna cosa agredolça esclata a la comissura de la boca i un dia qualsevol es torna una mica més dolç. Quan el sobre penjat d'una anella rodona es balanceja a cada pas, una petita dolçor em segueix tot el dia, a la butxaca."},"ICON-0846":{"nm":"Fitxa de cistella de botiga de conveniència","de":"Agafeu-la i el plàstic flexeix lleugerament. Una botiga il·luminada a altes hores de la nit, amb prou fondària per contenir un parell d'onigiris triangulars i una beguda. Un recipient tendre d'exactament un àpat, on fins i tot sol no se sent sol."},"ICON-0847":{"nm":"Cinta per a capsa de macarons","de":"Una sola cinta abraça amb calma la capsa perquè els macarons acolorits no es desordenin. Qui ha rebut mai un regal ho sap amb la punta dels dits: l'emoció just abans de desfer el llaç és, de fet, la més dolça de totes."},"ICON-0848":{"nm":"Clip per a xarxa de fruita","de":"Apleguem la boca de la xarxa i la pincem, i l'aroma de poma s'escola suaument entre els forats. Una petita mà que la reté perquè no caigui rodolant. Un prec tendre i sense paraules perquè es mengi aviat, abans que es torni tova."},"ICON-0849":{"nm":"Tela per a tapa de pot de melmelada","de":"Evoca la cuina d'estiu de l'àvia, cobrint tapes de pots amb una tela rodona i lligant-les amb una goma elàstica. Un sol tros de roba de quadres segella el temps dolç i la dedicació que fa madurar la melmelada. La mà bona es guarda així, coberta i protegida."},"ICON-0850":{"nm":"Llaç per a bossa de galetes","de":"Poseu les galetes acabades de fer dins d'un cel·lofana i torceu el llaç per tancar-lo, i l'olor de mantega penetra fins a les puntes de la cinta. La mà que ofereix a algú alguna cosa feta amb les pròpies mans sempre tremola una mica. Un nus que també lliga el cor."},"ICON-0851":{"nm":"Separador per a bombons","de":"Casella per casella, assigna un lloc perquè les xocolates no es toquin entre elles. Perquè no es fonguin, perquè no s'esmicolin. El que un petit separador custodia fins a l'últim moment és, al capdavall, un tros sencer de cor per oferir a algú."},"ICON-0852":{"nm":"Etiqueta de regal per a bosseta de te","de":"Damunt l'etiqueta que envolta la bosseta de te, un nom escrit amb pulcritud a mà. Un petit paper avança per endavant que, en infusionar-la, l'aroma d'herba puja junt amb el vapor. Una tassa que escalfa les mans fins i tot abans de beure-la."},"ICON-0853":{"nm":"Collaret d'ampolla de caramels","de":"Un collaret fet enrotllant un cordó al coll d'una ampolla plena de caramels de colors. A cada pas, un so com de boletes rodolant es mou per dins. Un tresor orgullós de la infància, portant la dolçor penjada del coll."},"ICON-0854":{"nm":"Penjoll per a cullera de regal","de":"Amb un sol penjoll balancejant-se a la punta del mànec, una cullera qualsevol es converteix en un regal sense adonar-se'n. Un dring lleuger i clar a cada culleretada. Un petit ornament que afegeix una mica de gràcia al cor que s'ofereix."},"ICON-0855":{"nm":"Etiqueta d'agraïment per a piscolabis","de":"El desig de tornar, encara que sigui una mica, allò que s'ha rebut. Una etiqueta d'agraïment penjada amb suavitat en una bossa de piscolabis. En lloc del «gràcies» que no es va arribar a dir del tot, una petita salutació passa en silenci de mà en mà."},"ICON-0856":{"nm":"Anella de mostres de cinta washi","de":"Estampats retallats i enganxats pam a pam s'arrengleren en una petita tira. Mentre trieu a poc a poc amb els dits quin color us agrada més, només de pensar a decorar el dia ja s'acoloreix. Una tira de mostres on fins i tot dubtar és un plaer."},"ICON-0857":{"nm":"Tap per a pinces d'adhesius","de":"Poseu un tap a la punta afilada de les pinces i fins i tot un adhesiu de la mida d'una ungla queda intacte. Una mà precisa que aixeca amb suavitat cantonades que els dits mai no podrien atènyer. Tractar allò que t'agrada sempre porta associada una mica de cautela."},"ICON-0858":{"nm":"Adhesiu per a cantonada d'agenda","de":"Enganxeu adhesius a les quatre cantonades d'una agenda i les pàgines que oneja el vent es calmen com per art de màgia. La sensació del paper lleument premut, un petit ritual que segella amb cura el dia d'avui. Un registre agafa fermesa començant per les cantonades."},"ICON-0859":{"nm":"Plantilla guia per a perforadora","de":"Una plantilla que indica per endavant on cal fer el forat. Alineeu-la amb calma seguint la línia de punts i no hi haurà cap desviació. El cor que calcula un cop més sense afanyar-se: la precisió sempre arriba en silenci des d'aquest lleuger marge d'un instant."},"ICON-0860":{"nm":"Safata per a retalls de paper","de":"Les engrunes de paper que sobren de retallar amb les tisores s'apleguen suaument dins la safata. Un aixopluc breu per als petits retalls, perquè l'escriptori no es desordeni. El rastre que deixa la manualitat s'endreça així, sense fer soroll."},"ICON-0861":{"nm":"Coixinet de tinta de colors","de":"Premeu el coixinet amb suavitat i aixequeu-lo, i el color s'estén humit sobre els dits. Vermell, groc, blau: un petit arc de Sant Martí que queda imprès en un sol segell. Un raconet tou per plantar color, toc a toc, damunt del paper blanc."},"ICON-0862":{"nm":"Rotlle de cinta decorativa","de":"L'estampat que es desenrotlla sense parar no té final. Arrenqueu un tros i enganxeu-lo, i floreixen flors en un racó que abans era anodí. Un rotlle de petita màgia, enrotllat i a l'espera, que embelleix cada cop més allà on va la mà."},"ICON-0863":{"nm":"Tap per a segell temàtic","de":"Un barretet que abraça ben ajustat el cap del segell perquè la tinta no s'assequi. Vetlla en silenci perquè el pròxim estampat quedi nítid. Un color ben conservat floreix igual de viu en el pròxim full de paper."},"ICON-0864":{"nm":"Retall de perforadora decorativa","de":"Les petites peces que la perforadora deixa caure amb un clic. Confeti de paper de colors retallat en estrelles, cors i pètals s'apila suaument al palmell. Petites joies massa boniques per llençar, que acaben enganxades en algun altre lloc."},"ICON-0865":{"nm":"Anella d'etiquetes per a canonet de fil","de":"Una petita etiqueta amb el nom de cada fil de color, escrita en cada canonet. Una marca tendra que indica el seu lloc abans que s'enredi. El fil embolicat, i també el cor, es desfan molt més fàcilment amb una sola etiqueta."},"ICON-0866":{"nm":"Funda per a llibret d'agulles","de":"Una funda tova per al llibret de fulls de feltre on hi ha les agulles clavades ben atapeïdes. Obriu-lo i les eines de costura hi jeuen en ordre, esperant-me. Un petit volum que adorm amb tendresa les coses punxegudes, perquè els dits no es facin mal."},"ICON-0867":{"nm":"Anella de mostres de teixit","de":"Aspre o suau, el temps lent de resseguir amb els dits, un per un, el gra de la tela per triar-la. Entre els retalls aplegats amb cura per colors, abans de convertir-se en una peça de roba, el teixit espera en silenci que el toquin primer."},"ICON-0868":{"nm":"Bastidor de brodar","de":"Col·loqueu la tela dins el bastidor rodó i estrenyeu, i queda tibant com la pell d'un tambor. Un petit senyal que indica que ja esteu a punt per brodar, punt a punt. El que el bastidor reté amb fermesa no és la tela, sinó la concentració."},"ICON-0869":{"nm":"Càpsula classificadora de botons","de":"Els botons que rodolaven amunt i avall s'asseuen dòcilment per colors dins cada casella de la càpsula. La saviesa domèstica de repartir-los en petites porcions perquè no se'n perdi cap. Fins i tot recollir el que està escampat requereix tanta dedicació com aquesta."},"ICON-0870":{"nm":"Suport per a guix de sastre","de":"Un suport que sosté còmodament a la mà el guix que traça línies sobre la roba. Referma amb fermesa una cosa que es trenca amb facilitat. El primer propòsit tranquil abans d'agafar les tisores: que la primera línia sigui recta perquè la peça de roba també ho sigui."},"ICON-0871":{"nm":"Pot d'agulles de cap","de":"Dins el pot transparent, les agulles de cap xoquen i dringuen entre elles. Poseu-lo a contrallum i una petita lluïssor s'assenta a la punta de cada agulla. Un recipient discret que aplega en un sol lloc, i adorm amb dolcesa, allò que és perillós quan es dispersa."},"ICON-0872":{"nm":"Rotlle de cinta pedaç","de":"Una cinta màgica que s'enganxa en silenci quan es passa la planxa sobre un estrip. Sense una sola puntada, una peça gastada es guareix amb calma. El cor que apedaçava i continuava portant la roba en lloc de llençar-la queda enrotllat, capa rere capa, dins el rotlle."},"ICON-0873":{"nm":"Full plantilla per a pedaços","de":"Un full de plantilla amb la forma del pedaç ja dibuixada per endavant. Una línia de punts guia amb amabilitat el camí que seguiran les tisores. Dibuixar primer el contorn del que es vol fer: l'emoció sempre comença en aquest esbós tènue."},"ICON-0874":{"nm":"Tap per a pot d'aigua d'aquarel·la","de":"Poseu-lo a la boca del pot i, per molt que l'aigua acolorida es remogui, no vessa ni una gota. Cobreix fins i tot la preocupació que l'aigua tèrbola d'esbandir el pinzell tacaria l'escriptori. Un tap silenciós que vetlla sense dir res pel racó on es pinta."},"ICON-0875":{"nm":"Cinta protectora per a pastel","de":"Enrotlleu una cinta al voltant d'un pastel que deixa una pols blanquinosa, i els dits queden menys tacats. Un paper que embolica amb calma el color delicat perquè no s'esmicoli. Com més fràgil, amb més suavitat cal agafar-lo, perquè també s'apliqui amb dolcesa sobre el paper."},"ICON-0876":{"nm":"Tap allargador per a llapis de colors","de":"Enganxeu un tap a la punta d'un llapis de colors gastat i el tros torna a créixer. El cor que no llença fàcilment només perquè s'ha fet curt. Dels dits que l'aprofiten fins al final, el color del dibuix es completa més intens fins a l'última casella."},"ICON-0877":{"nm":"Ganxo per a got de rentar pinzells","de":"Pengeu el got de rentar en un ganxo i les gotes d'aigua caigudes del pinzell regalimen a poc a poc. Abans de pintar el color següent, la quietud breu i clara d'esbandir el pinzell. Fins i tot en aquell so de tornar-se net hi flueix un ritme tranquil."},"ICON-0878":{"nm":"Tap per a espàtula de paleta","de":"Un petit tap que cobreix ben ajustat la fulla de l'espàtula que estén i rasca la pintura. Vetlla amb calma perquè la punta esmolada no es faci mai roma. La textura d'un color aplicat gruixut neix d'aquesta única punta ben cuidada."},"ICON-0879":{"nm":"Pinça per a llenç","de":"Una pinça robusta que estira amb força la tela de llenç sobre el bastidor i la fixa. Si mossega ben fort, la superfície per pintar s'estén tibant. Només amb una base que no trontolla, les pinzellades que hi corren al damunt es tornen del tot lliures."},"ICON-0880":{"nm":"Corretja per a tauleta de dibuix","de":"Passeu-vos la corretja per l'espatlla i la tauleta us segueix a l'esquena. Instal·leu-vos on sigui i aquell lloc esdevé, a l'instant, el vostre propi taller. Un petit estudi que es porta a l'esquena, i que marxa lleuger a la recerca d'un paisatge per dibuixar."},"ICON-0881":{"nm":"Tub de pintura acrílica","de":"Afegiu una gota d'aigua més i és l'alba; una gota menys i és mitjanit. El mateix blau obre un cel diferent cada vegada als dits. En l'instant que es prem un tub, el color d'ànim d'avui s'escampa pel paper."},"ICON-0882":{"nm":"Full de mostra de degradat","de":"Aquest paper va saber abans que ningú que un capvespre no s'envermelleix d'un sol cop. Petits esglaons que passen del clar al fosc. L'ull hi camina a poc a poc, tot seguint amb calma el temps en què el color va madurant."},"ICON-0883":{"nm":"Tap protector per a ganxet","de":"Un escut petit com un didal que es col·loca abans que el fil s'endinsi als dits. Una mà que fa temps que fa punt de ganxet ho sap. Només restant il·lesa es pot arribar amb tendresa fins a l'últim punt."},"ICON-0884":{"nm":"Marcador anella per a punt de mitja","de":"Amb un sol marcador, torna a quedar clar fins on s'ha arribat. L'alleujament de no haver de comptar mai dues vegades el mateix punt. El cor també, només així, quan algú assenyala amb suavitat el lloc d'on ve, no perd mai el camí."},"ICON-0885":{"nm":"Penjoll comptavoltes","de":"La prova silenciosa d'una volta acabada s'apila, casella rere casella. Fins i tot una feina que semblava no tenir fi, comptada d'una en una, de sobte ha superat la meitat. Un petit recompte sosté el cor d'avui fins al final."},"ICON-0886":{"nm":"Agulla endreçadora de puntes de fil","de":"Deixeu tal qual la punta d'un fil deslligat i no hi ha manera de saber on s'enredarà el pròxim nus. Un toc que endreça, per endavant, un lloc que no es veurà. La tendresa, la majoria de vegades, es mou primer en llocs que no criden l'atenció, com aquest."},"ICON-0887":{"nm":"Cordó de pràctica de nusos","de":"Nus pla, nus de llaç, nus d'anell. Es lliga i es deslliga el mateix cordó fins que la mà en memoritza la forma. Quan uns dits maldestres esdevenen àgils de sobte una nit, aquell únic fil és el primer a saber-ho."},"ICON-0888":{"nm":"Cinta etiqueta per a cabdell de llana","de":"Una petita tira que anota, en cada cabdell, el gruix i el color. És un costum nascut de nits passades cercant en va el mateix fil un cop ja s'havia acabat. Un registre és una nota tendra adreçada al jo del futur."},"ICON-0889":{"nm":"Regla de mostra per a punt","de":"Quants punts caben en 10 centímetres: aquell petit número decideix la mida de tota una peça de roba. Que un fragment de la mida d'un palmell contingui la mesura del conjunt és, si el sospeseu, una cosa força feixuga."},"ICON-0890":{"nm":"Marcador d'ullal de botó","de":"Abans de cosir un botó, es marca primer un sol punt on cal obrir el forat. Gràcies a aquesta marca que aviat desapareixerà, la solapa no queda torta. La dedicació, la majoria de vegades, roman amagada en un lloc que al final no es veu."},"ICON-0891":{"nm":"Anella amb borla petita","de":"Com la borla al capdavall d'un norigae, una petita anella crea el balanceig. La mirada sempre s'atura en allò que penja i s'ondula amb calma. Un teixit que cobra vida en silenci cada cop que passa el vent."},"ICON-0892":{"nm":"Ampolleta de pintura","de":"No es tracta d'estalviar-la, sinó d'usar-la amb precisió: així es tracta bé la pintura. Un color en què una sola gota ja basta, calculat amb la mà a prop de la petita ampolla. La contenció ve de deixar anar la cobdícia, encara que només sigui un cop."},"ICON-0893":{"nm":"Llima de paper de vidre petita","de":"Es comença per la cara aspra i es passa a poc a poc a la fina. No hi ha enlloc cap superfície que quedi llisa d'una sola passada. Dels dits que rebaixen el gra pas a pas, un lloc antigament aspre es torna suau a poc a poc."},"ICON-0894":{"nm":"Suport amb pinces per a maquetes","de":"Sostenir amb la mà una peça acabada d'enganxar hi deixa empremtes. Si la subjecteu amb suavitat a la pinça, les mans queden lliures i l'assecatge s'acaba tot sol, en silenci. Fins i tot l'espera es fa més lleugera quan algú la sosté per tu."},"ICON-0895":{"nm":"Base per a treballar amb cola","de":"Si cau una gota de cola sobre l'escriptori, la marca hi perdura molt de temps. L'hàbit de posar-hi primer una placa a sota. La meitat de la feina, potser, comença precisament en aquell desig de no embrutar el lloc."},"ICON-0896":{"nm":"Safata classificadora de peces","de":"Barregeu desenes de peces de la mateixa forma i el muntatge de seguida es converteix en un laberint. El gest de repartir-les en cada compartiment redueix per endavant el temps que us hi perdríeu. Endreçar és una amabilitat que s'ofereix al jo del futur."},"ICON-0897":{"nm":"Fitxa d'ordre de muntatge","de":"Una petita fitxa que anota quina peça numerada cal encaixar primer. Si es respecta l'ordre, no s'ensorra amb facilitat. Una maqueta, i qualsevol dia construït pas a pas amb cura, s'enforteixen damunt aquesta promesa silenciosa."},"ICON-0898":{"nm":"Penjador petit per a pinzells","de":"Deixeu estirat un pinzell usat i les cerres queden premudes i corbades. Un racó per penjar-lo de cap per avall i escórrer-ne la humitat. Qui manté les eines a prop durant molt de temps és, si de cas, encara més atrafegat i tendre un cop acabada la feina."},"ICON-0899":{"nm":"Pot per a retalls de plàstic","de":"Un pot on s'apleguen en silenci les retallades desprendudes del motlle. Semblen rebuig, però algun dia tornen convertides en un petit detall. El pot sap, mentre espera sense dir res, que fins i tot allò que sobra té el seu torn."},"ICON-0900":{"nm":"Tap per a esprai de vernís","de":"L'última capa, ruixada massa d'a prop, regalima tal qual cap avall. Des d'una distància d'un pam, lleugerament, lleugerament. Aplicar la brillantor és, potser, també una pràctica de deixar anar la cobdícia del cor, encara que només sigui un cop."},"ICON-0901":{"nm":"Estoig de mines de recanvi","de":"Les mines primes de llapis es trenquen fàcilment dins la butxaca. Ben arrenglerades dins un petit tub, ni una sola es fa malbé. Ordenar és, al capdavall, una manera silenciosa de tenir cura del jo de demà per endavant."},"ICON-0902":{"nm":"Funda de goma d'esborrar","de":"Un petit vestit de paper que es posa a la goma d'esborrar. Com més negra es torna amb l'ús, més traces de correccions ha acumulat. Esborrar és també un permís tendre per tornar a començar des del principi."},"ICON-0903":{"nm":"Tub per a plomins","de":"Els plomins s'esquerden quan s'assequen i es corben quan reben un cop. Un petit tub on deixar-los ajaguts a part en preserva el traç durant molt de temps. Una eina tractada amb suavitat, al final, llisca amb suavitat com a recompensa."},"ICON-0904":{"nm":"Mostres de tinta per a estilogràfica","de":"Tintes que es proven gota a gota. Un color que semblava blau verdós es converteix en un mar profund sobre el paper. El color és una cosa que sempre s'ha de conèixer en persona; el to que t'imagines al cap sovint no encerta."},"ICON-0905":{"nm":"Capsa de marcapàgines de fletxa","de":"Una petita bandera que es clava suaument al punt on has deixat la lectura. La propera vegada que obris el llibre, el teu jo d'ahir et saluda i t'espera. Fins i tot el lloc on t'has aturat esdevé una promesa, la feina tendra d'aquesta petita marca."},"ICON-0906":{"nm":"Paquet de banderetes adhesives","de":"Arrenca'n un full i enganxa'l, i la història torna a començar just des d'allà. Quan les petites banderes s'arrengleren pel cantó del llibre, els pensaments dispersos s'apleguen ordenadament en un sol mapa."},"ICON-0907":{"nm":"Imant recollidor de clips","de":"Un petit imant que aplega d'una revolada els clips escampats. Com més petita és una cosa, més fàcil es perd, així que una sola força d'atracció rescata en silenci un escriptori desendreçat. Fins i tot en el fet d'atreure hi ha tendresa."},"ICON-0908":{"nm":"Joc de caputxons per a llapis","de":"Petits barrets que embolcallen la punta del llapis i protegeixen l'interior de la motxilla. Tot allò que és punxegut acaba punxant alguna cosa, per això necessita una mà que el cobreixi amb suavitat. Que no perdi el fil, però que no faci mal."},"ICON-0909":{"nm":"Adhesiu de placa nominativa per a l'escriptori","de":"El moment en què escrius el teu nom i l'enganxes a l'escriptori, aquell racó esdevé finalment d'algú. Quan fins i tot un pam d'espai té un propietari, la manera d'assentar-hi el cor canvia del tot."},"ICON-0910":{"nm":"Caputxó per a mànec de corda de saltar","de":"Un caputxó que es posa abans que els extrems del mànec es gastin i s'esquerdin. El ritme d'una corda girada més de mil vegades, el recorda abans la palma de la mà que el cap. Un compàs gravat al cos no s'oblida fàcilment."},"ICON-0911":{"nm":"Corretja amb anella de ioga","de":"Agafa l'anella i obre el cos a poc a poc. Com més s'estira la corretja, més es van desfent, capa a capa, les espatlles encarcarades. Estirar-se no és forçar una estrebada, sinó esperar en silenci fins que el cos s'obri."},"ICON-0912":{"nm":"Estoig per a pilotes de ping-pong","de":"Una pilota blanca tan lleugera que rodola lluny i que, si la trepitges, s'esclafa a l'instant. Un petit estoig protegeix aquesta pilota tan fràgil fins al pròxim partit. La fermesa sovint ve d'un embolcall suau."},"ICON-0913":{"nm":"Cinta d'agafador per a bàdminton","de":"Enrotlla una capa polida al voltant d'un mànec que llisca amb la suor. Sobre un agafador ben embenat, la raqueta esdevé una part de la mà. El secret de jugar amb sensibilitat i no amb força s'amaga en aquesta fina capa."},"ICON-0914":{"nm":"Fitxa de punts petita","de":"Un punt, i un altre. Movent petites fitxes, vas acumulant la puntuació a poc a poc. Quan el compte es veu clar, el partit es fa més nítid, i el coratge de remuntar un punt sorgeix també discretament."},"ICON-0915":{"nm":"Clip d'orientació per a vambes","de":"Les puntes de les sabates, ben col·locades, sempre miren cap a la mateixa direcció. Un petit gir de la mà quan te les treus. Un simple ordre fa que els passos del matí de demà siguin una mica més lleugers."},"ICON-0916":{"nm":"Cordó per a xiulet","de":"Penja't un xiulet al coll i guanyes el dret de dir que s'aturi tothom. L'estampa d'un camp sencer aturant-se de cop amb un únic xiulet curt. Els cors que confien en aquell so petit s'apleguen i es converteixen en una promesa."},"ICON-0917":{"nm":"Tub per a agulles d'inflar pilotes","de":"Fins i tot una pilota desinflada torna a quedar tibant amb una sola agulla prima. Aquella agulla, ben guardada dins un petit tub, deixa inservible tota la bomba en el moment que es perd. Quan la cosa més petita és la que més importa."},"ICON-0918":{"nm":"Con marcador petit","de":"D'aquí fins allà, un petit con dibuixa una frontera que no es veia. Sense cap línia, la gent es posa en fila de manera natural seguint la marca. L'ordre creix en silenci a partir de senyals petits com aquest."},"ICON-0919":{"nm":"Bosseta per a fitxes","de":"Una bosseta que aplega les fitxes dringadisses en un sol lloc. Si li estrenys la boca, no se n'escapa cap. Fins i tot les coses petites i insignificants necessiten un lloc on ser contingudes abans de complir el seu paper; la bosseta ho mostra sense dir ni una paraula."},"ICON-0920":{"nm":"Estora per barrejar cartes","de":"Sobre un escriptori llis, les cartes no s'agafen bé a la mà. Amb un sol tapet, tant barrejar-les com recollir-les es fa molt més suau. Fins i tot en el fet de jugar bé, hi ha una preparació tendra que consisteix a triar primer la superfície."},"ICON-0921":{"nm":"Protector de cantonades per a tauler","de":"Quan acaba una nit de jocs de taula, algú s'ocupa en silenci primer de les quatre cantonades del tauler. Perquè sap que un plec profund torça la partida següent. En els dits que allisen les vores hi ha el desig de tornar a jugar junts demà."},"ICON-0922":{"nm":"Tapa per a got de daus","de":"Aquell instant breu en què tothom sacseja, llança i aguanta l'alè alhora. És un petit sostre que evita que els daus surtin disparats. Sota la tapa, la sort d'avui recupera l'alè un moment abans de sortir rodolant amb un cliqueig."},"ICON-0923":{"nm":"Tauler alineador de fitxes","de":"Com més emocionada està una persona amb el joc, més torçada li queda la filera. Empènyer suaument les fitxes torçades fins tornar-les a alinear. Alinear és una mà que acull amb tendresa la impaciència eufòrica d'algú."},"ICON-0924":{"nm":"Llauna de fitxes de puntuació","de":"Com més s'omple una llauna de fitxes, més s'escalfa també la partida. Quan les puntuacions rodones s'entrexoquen dins la palma de la mà, aquell so esdevé una alegria abans que guanyar o perdre."},"ICON-0925":{"nm":"Anell marcador de torn","de":"Un petit anell que t'avisa que ara és el teu torn. Durant aquell instant en què el desplaces una mossa, tots els ulls s'aturen tranquil·lament en mi. Un cercle que gira lentament entre l'espera i el neguit."},"ICON-0926":{"nm":"Peanya per a fitxa de joc","de":"Com més fàcil és que una fitxa caigui, més ferm ha de ser el seu suport. Una sola peanya aguanta el seu lloc fins i tot sobre un tauler lleugerament inestable. Cal que allò petit resisteixi perquè allò gran de sobre pugui erigir-se."},"ICON-0927":{"nm":"Clip per a llibre d'instruccions","de":"Un llibret d'instruccions, deixat obert, sempre acaba girant les pàgines pel seu compte. Abans que el vent faci fugir els fulls, aquest clip en mossega una amb suavitat. Cal retenir les regles perquè el joc arribi fins al final."},"ICON-0928":{"nm":"Cordó per a estoig de púa","de":"La púa de la guitarra sempre s'escapa dels dits just en el moment més emocionant. Un cordó penjat de l'estoig evita aquella petita fugida. Només qui ha viscut una nit en què la música es va aturar sap agrair aquest cordó."},"ICON-0929":{"nm":"Tub per a canyes","de":"Una canya perd la seva veu tan bon punt s'asseca. Dins un tub humit, un fi tros de canya espera la propera actuació. Un lloc on adormir primer l'alè, abans de tornar-lo a bufar."},"ICON-0930":{"nm":"Enrotllador de cordes","de":"Quan una corda es destensa, el to també s'ensorra en silenci. Girar lentament la maneta per recuperar la tensió; la cura sempre ve del canell. Un so polit comença amb petits actes d'ordre com aquest."},"ICON-0931":{"nm":"Drap de neteja per a instruments","de":"Quan acaba una actuació, també queda una suor lleugera a l'instrument. Un sol passat amb un drap suau en retorna la brillantor i deixa que les notes d'avui es calmin. Un cor que estima sempre es mostra en l'acabat."},"ICON-0932":{"nm":"Coberta per a clavilles d'afinació","de":"Deixades a la intempèrie, les clavilles d'afinació es rovellen abans que te n'adonis. Una petita coberta endarrereix un compàs les estacions del metall. Qui té cura primer dels racons invisibles és qui toca durant molt de temps."},"ICON-0933":{"nm":"Llum de pinça per a faristol","de":"Rere l'escenari fosc, hi ha moments en què només la partitura ha de brillar. Un petit llum enganxat al faristol que deixa caure suaument la seva llum. Un grapat de claror que il·lumina el terra perquè les notes no perdin el camí."},"ICON-0934":{"nm":"Sordina de pràctica","de":"L'assaig de matinada sempre discuteix en silenci amb la son dels veïns. Amb un sol caputxó posat, el so estrepitós es redueix a un xiuxiueig. Hi ha música que creix mentre vetlla el son plàcid d'algú."},"ICON-0935":{"nm":"Adhesius per a pad de bateria","de":"Petites marques enganxades sobre el pad de bateria. On colpejar per treure quin so; els ulls n'aprenen el camí abans que les mans ho memoritzin. El ritme es grava així, lentament, al cos."},"ICON-0936":{"nm":"Xip per apuntar melodies","de":"Una melodia taral·lejada s'esvaeix de seguida si no la retens. Uns quants compassos apuntats de pressa en un xip de vegades creixen fins a esdevenir una cançó sencera. La inspiració sempre torna a la mà que apunta amb constància."},"ICON-0937":{"nm":"Cinta per a coberta de llibre","de":"És un fàstic quan un llibre a mig llegir s'obre sol dins la motxilla. Una sola cinta lliga suaument les pàgines perquè es quedin quietes. Una promesa de plegar-ho tot ordenadament per a la propera pàgina."},"ICON-0938":{"nm":"Anella subjectapàgines","de":"Un dia en què vols tenir el llibre obert amb una mà i fer glops de cafè calent. Una anella que et poses al dit et subjecta les pàgines. Un petit desfogament comença amb invents senzills com aquest."},"ICON-0939":{"nm":"Xip temporitzador de lectura","de":"Asseure't per llegir només un capítol i, sense saber com, la nit s'ha fet fonda. Prémer el xip per fixar un temps fa que fins i tot la lectura tingui una pausa. Com més estimes una cosa, més necessites el coratge tendre de saber aturar-te."},"ICON-0940":{"nm":"Caputxó protector de cantonades de llibre","de":"Com més estimat és un llibre, més aviat se li gasten en silenci les cantonades. Amb un caputxó posat, les puntes de la coberta queden arrodonides i protegides. Una petita armadura que et poses per retenir a prop allò que vols guardar durant molt, molt de temps."},"ICON-0941":{"nm":"Faixa per a notes de lectura","de":"Hi ha moments en què una sola frase et fa caure el pit. Una impressió copiada a la faixa es queda en aquella pàgina com un punt de llibre. La temperatura càlida d'un subratllat, que només coneix qui l'ha llegit."},"ICON-0942":{"nm":"Etiqueta de devolució de biblioteca","de":"El dia de retorn sempre arriba un dia massa d'hora. Quan la data escrita a l'etiqueta t'empeny en silenci per l'esquena, fins i tot un llibre prestat guanya la cortesia d'un final. Per a les mans de la persona següent, la biblioteca espera així."},"ICON-0943":{"nm":"Llum de pinça per a llibres","de":"Una nit en què et quedes despert llegint sol al costat de la família adormida. Un petit llum enganxat amb pinça al cantó del llibre ja n'hi ha prou. No cal apartar tota la foscor; per a una pàgina, ja basta una estona de silenci."},"ICON-0944":{"nm":"Targeta d'aroma de llibre","de":"Els llibres antics fan una olor de sol i paper barrejats. Aquesta targeta, que diu que guarda aquell perfum en un sol full, s'obre i reviu per un moment, al capdamunt del nas, un carreró de llibreria de vell. La memòria també fa punts de llibre amb l'olor."},"ICON-0945":{"nm":"Agulla marcadora de pàgina llegida","de":"On m'he quedat? Una petita agulla que esborra aquella pregunta desemparada. Clavada a l'última frase, el teu jo de demà ja no vagareja més. Una marca tendra que recorda per tu el lloc on t'has aturat."},"ICON-0946":{"nm":"Penjoll per a corretja de mòbil","de":"Un sol penjoll a la corretja del mòbil fa que una persona sembli una mica diferent. Un color preferit, una forma preferida. Un petit gust tingut a la mà bressola suaument l'humor del dia."},"ICON-0947":{"nm":"Tapa protectora d'objectiu","de":"El destí de les fotos de viatge depèn d'un sol vidre. El moment de treure la tapa protectora és la preparació del cor per prémer el disparador. Un petit ritual, el primer a obrir els ulls abans de capturar un paisatge."},"ICON-0948":{"nm":"Tap per a port de càrrega","de":"La pols de la motxilla sempre apunta primer cap al forat de càrrega. Amb un sol tap tapant aquella petita obertura, el connector es manté net durant molt de temps. Aquí hi ha una diligència que cuida fins i tot els escletxos invisibles."},"ICON-0949":{"nm":"Anella pop de suport per a mòbil","de":"Inclinar el mòbil només per veure còmodament un vídeo. Desplegar l'anella enganxada al darrere fa que la mà i la pantalla respirin més tranquil·les. Un petit suport alçat allarga una vetllada tranquil·la."},"ICON-0950":{"nm":"Pegat per netejar la pantalla","de":"Una pantalla plena d'empremtes enterboleix, d'alguna manera, també el cor. Una passada amb el pegat i el món torna a fer-se nítid. La netedat és, de vegades, una tasca breu d'un sol dit."},"ICON-0951":{"nm":"Estoig per a agulla SIM","de":"L'agulla d'extreure la SIM és un follet que només desapareix quan de veritat la necessites. Guardada en un compartiment d'un estoig, ja no cal escorcollar tota la casa buscant una agulla de cabell. Un petit ordre rescata en silenci un moment urgent."},"ICON-0952":{"nm":"Adhesiu per a base de càrrega sense fil","de":"Una nit en què el mòbil s'omple sol només de deixar-lo reposar sobre la base. Un adhesiu enganxat marca suaument el lloc on ha de jeure el mòbil. Un corrent invisible omple sense soroll l'energia d'un dia sencer."},"ICON-0953":{"nm":"Adhesiu tapa-notificacions","de":"Algunes notificacions és millor deixar-les tapades, així el cor descansa. Un sol adhesiu apaivaga la petita llum de la matinada. De vegades, no mirar també és una manera tendra de protegir-se un mateix."},"ICON-0954":{"nm":"Anell protector d'objectiu","de":"L'instant en què l'objectiu de la càmera toca el terra, el cor et cau amb un sobresalt. Un anell que l'envolta frena discretament aquella petita caiguda. Una vora que protegeix, abans que res, l'ull que capta els records."},"ICON-0955":{"nm":"Etiqueta per a cables","de":"Distingir finalment el teu cable dins un munt enredat i embullat. Una sola etiqueta fa que fins i tot el cable de càrrega tingui, per fi, un nom propi. Una petita bandera que assenyala el camí enmig de cordons desordenats."},"ICON-0956":{"nm":"Nécesser per a carregadors","de":"Els carregadors dins una maleta de viatge sempre es barallen enredats entre ells. Aplegar-los ordenadament en un compartiment d'un nécesser i, per fi, fan les paus. L'art d'endreçar consisteix a cridar amb tendresa allò dispers cap a un sol lloc."},"ICON-0957":{"nm":"Etiqueta per a regleta elèctrica","de":"Els forats d'una regleta elèctrica són tots iguals i sempre confonen. Etiquetar-los per assignar de qui és cada lloc fa que un matí atrafegat flueixi molt més fàcil. Una petita etiqueta redueix les petites baralles quotidianes."},"ICON-0958":{"nm":"Bobina enrotlladora de cables","de":"Desenrotllat per fer-se servir, tornat a enrotllar després, el dia endreçat d'un cable. Enrotllat capa a capa en una sola bobina, l'embull desapareix del tot. La mà que torna les coses al seu lloc després d'usar-les fa demà més lleuger."},"ICON-0959":{"nm":"Caputxó per a connector magnètic","de":"Un connector magnètic va acumulant, sense adonar-te'n, una fina pols metàl·lica. Tapa'l amb un caputxó i la brutícia enganxosa no s'hi agafa. Un aparell tocat per una mà que en té cura una vegada més et dura més temps al costat."},"ICON-0960":{"nm":"Cinta per a bateria portàtil","de":"Deixa la bateria portàtil i el cable per separat i sempre un dels dos desapareix. Lliga'ls amb una cinta i finalment es converteixen en una parella. Un petit nus que lligues amb suavitat just abans de sortir, dient-los que viatgin junts."},"ICON-0961":{"nm":"Tap antipols per a endoll","de":"Un forat d'endoll buit deixa que la pols hi munti casa en silenci en pocs dies. Quan aquesta petita tapa el guarda en el seu lloc, el carregador que hi endollaràs després pot fer un primer respir net. Un porter que manté impecable el temps en què resta buit."},"ICON-0962":{"nm":"Anell de colors per a cables","de":"La nit que vas passar palpant per trobar el teu cable enmig d'un embull, qui va dir que els donéssim colors? Blau ets tu, groc soc jo. Amb un sol anellet, ja no ens confonem mai més l'un amb l'altre. Un rastre d'una promesa entranyable que ha quedat en un racó de la sala d'assaig."},"ICON-0963":{"nm":"Xip classificador d'adaptadors","de":"Potes rodones i potes planes, 110 i 220. Un xip que ha memoritzat en silenci les cares dels endolls que canvien de país en país. En un racó de la maleta d'aquell primer viatge a l'altra banda del mar cap a l'escenari, sempre hi anava aquesta petita targeta classificadora."},"ICON-0964":{"nm":"Safata classificadora de puntes d'auricular","de":"Diuen que el canal de l'orella varia de fondària i d'amplada segons la persona. Deixar ajagudes en fila les mides gran, mitjana i petita, i triar la parella que t'encaixa just a l'orella. Un procediment tendre d'ajustar primer el cos, abans d'escoltar el so."},"ICON-0965":{"nm":"Anell de silicona per a funda","de":"Al vestit d'escenari s'hi para atenció fins a la darrera puntada, però les cantonades de la funda sempre xoquen amb la pell nua. Quan aquesta fina vora de silicona n'embolcalla suaument el contorn, fins i tot en una matinada en què s'escapa de la mà, la pantalla rep el matí sencera."},"ICON-0966":{"nm":"Adhesiu de cancel·lació de soroll","de":"Hi ha dies en què vols apagar per un moment els sorolls del món. Aquest petit adhesiu enganxat a l'orella de l'auricular és una marca que encén el silenci. Un amulet que s'endú a distància tant els crits del públic com el soroll del metro, només fins que s'acaba una cançó."},"ICON-0967":{"nm":"Joc de ganxos per a auriculars","de":"Quan balles, un dels auriculars sempre fuig primer. Penja't aquests ganxos que abracen suaument el pavelló de l'orella, i fins i tot enmig d'una coreografia intensa la música es queda a l'orella fins al final. Un petit descobriment que la gent de la sala d'assaig es va anar passant."},"ICON-0968":{"nm":"Caputxó per a raspall de neteja","de":"Un petit barret que es posa perquè la pols de les cerres no torni a escampar-se. Que fins i tot una eina de neteja necessita neteja, ja ho sabia des de fa temps la mà que deixava l'escombra capgirada després d'escombrar."},"ICON-0969":{"nm":"Coixinet de base per a càrrega de peu","de":"El carregador de peu llisca'va sense parar sobre l'escriptori perquè no tenia peus. Quan aquest fi coixinet posat a sota fa de peus en lloc seu, l'aparell es queda quiet al seu lloc i omple d'energia en silenci tota la nit."},"ICON-0970":{"nm":"Marcador d'esquerra i dreta","de":"Esquerra L, dreta R. S'hi marca un punt de més perquè es reconegui fins i tot palpant a les fosques. El desig de no confondre mai el peu esquerre i el dret sobre l'escenari queda gravat, intacte, en aquesta petita marca."},"ICON-0971":{"nm":"Tapa per a jack repartidor d'àudio","de":"Aquell jack pel qual una sola veu de so es repartia entre molts, cal tapar-ne l'extrem mentre descansa. Perquè la pols no s'infiltri al circuit. Una mà petita i curosa que vol que la cançó que vau escoltar junts torni a fluir clara la propera vegada també."},"ICON-0972":{"nm":"Enrotllador de cable d'auriculars","de":"Com el gest antic d'enrotllar un cabdell de fil, el cable dels auriculars, enrotllat aquí en rodona, es fa polit. El moment en què la música que rodolava enredada dins la motxilla queda posada en ordre. El demà de desenrotllar-lo serà molt més lleuger."},"ICON-0973":{"nm":"Cordó subjectatapes d'objectiu","de":"Cada vegada que obries l'objectiu, la tapa sempre perdia el rumb. Lligant-la amb un cordó al costat de la càmera, ja no cal remenar la butxaca en va. Per no perdre una cosa, cal lligar-la a prop; la mà ho va aprendre primer."},"ICON-0974":{"nm":"Penjoll cobre-sabata calenta","de":"Al buit de la sabata calenta damunt la càmera, hi encaixes discretament un petit adorn. Aquell penjoll sense cap funció fa que, sense saber com, l'equip pesat i sec sembli entranyable, com una cosa ben teva. L'acte d'agafar afecte a una eina."},"ICON-0975":{"nm":"Sivella d'ajust de corretja","de":"Cada vegada que la corretja de la motxilla se't clava a l'espatlla, afluixes i estrenys una mica aquesta sivella. Un sol pas dels dits per triar una llargada que s'adapti al teu cos. Fins i tot carregar pes és, al capdavall, tenir cura de tu mateix, t'ho diu en silenci la sivella."},"ICON-0976":{"nm":"Estoig apilador de filtres","de":"Una petita casa on es deixen ajagudes, capa rere capa, les peces de vidre que parteixen la llum. Boira i claredat, capvespre i nit. Com un calaix on el temps es tria i es guarda per endavant, el fotògraf sempre obre primer aquest estoig abans de sortir de viatge."},"ICON-0977":{"nm":"Tapa antipols per a bufador","de":"Una pera de goma que bufa aire per foragitar la pols és, a la seva pròpia boca, igual de vulnerable a la pols. Mentre descansa, tapa-la amb aquesta. Hi ha una cosa tendra en una eina que neteja els altres i que, primer de tot, es tapa en silenci la pròpia boca."},"ICON-0978":{"nm":"Coberta per a botó del disparador","de":"El disparador que es prem sol dins la motxilla, disparant cent fotos de cel buit, és una cosa que tothom viu algun cop. Aquesta petita coberta damunt el botó evita aquell esforç en va. Un petit bloqueig, per retenir només els moments que de debò vols conservar."},"ICON-0979":{"nm":"Adhesiu classificador de bateries","de":"Sempre és un desastre quan les gastades i les plenes es barregen en una sola butxaca. Un adhesiu de color a cada bateria endreça en silenci aquell caos. El vermell vol dir buida, el verd vol dir fiable. Un semàfor mut encès en un rodatge."},"ICON-0980":{"nm":"Separador per a motxilla de càmera","de":"Divideix la motxilla en compartiments perquè l'objectiu, el cos i la bateria de recanvi no xoquin entre ells. L'acte de fer diverses petites cambres dins un sol equipatge. Cada lloc té el seu amo, així que res no perd mai el seu lloc encara que es mogui."},"ICON-0981":{"nm":"Coixinet per a guant de rodatge","de":"Un rodatge d'hivern a l'exterior on només la punta del dit que prem el disparador no ha de passar fred. Un coixinet gruixut a la palma, uns guants que deixen sensibilitat a les puntes dels dits. El compromís tendre del terreny, per tenir en una sola mà l'escalfor i la precisió alhora."},"ICON-0982":{"nm":"Tub per a puntes de llapis de tauleta","de":"Que la punta del llapis també es gasta com una mina de llapis, ho sap qui ha agafat molt de temps una tauleta. Aquest petit tub on s'apleguen puntes de recanvi rodolant és com un fons d'emergència a la punta dels dits, que reomple les línies que no poden quedar tallades."},"ICON-0983":{"nm":"Safata per a tecles de teclat","de":"El dia que vas treure les tecles una per una, rentar-les i tornar-les a posar, aquesta safata es va convertir en un petit fangar. L'estampa de consonants i vocals ajagudes compartiment a compartiment, assecant-se. Hi ha cura que només es veu quan has desmuntat alguna cosa."},"ICON-0984":{"nm":"Paquet de peus per a ratolí","de":"El secret perquè el ratolí llisqui com si volés per l'escriptori rau en aquests petits peus enganxats a la seva base. Un lot per canviar quan es gasten. L'esforç de les coses que sostenen en silenci la suavitat des d'un lloc invisible."},"ICON-0985":{"nm":"Suport de goma per a portàtil","de":"S'assembla a una llibreta, però en realitat és un suport de goma que aixeca un portàtil. Alçar lleugerament la pantalla a l'alçada dels ulls per redreçar un coll encorbat. Una atenció que endreça la postura, per a qui escriu i mira durant estones llargues."},"ICON-0986":{"nm":"Corredissa tapa-webcam","de":"Empènyer amb el dit per tapar l'objectiu, i tornar a empènyer per obrir-lo. El desig de deixar-se veure només quan un vol ser vist. En aquesta petita corredissa hi habita el gran alleujament anomenat privacitat. El so de tancar-se és, d'alguna manera, tranquil·litzador."},"ICON-0987":{"nm":"Etiqueta classificadora d'USB","de":"Cinc barretes negres semblants i cap manera de saber què conté cadascuna. Enganxar-hi una petita etiqueta i posar-los nom, i només aleshores esdevenen dels teus. Cal tenir un nom per cridar-los abans que sigui fàcil trobar-los."},"ICON-0988":{"nm":"Cantoneres per a estora d'escriptori","de":"Quan les cantonades d'una estora d'escriptori s'arruguen cap amunt, fins i tot la lletra es fa torçada. Aquestes petites peces que premen amb suavitat les quatre cantonades guarden la pau plana damunt l'escriptori. La superfície ha d'estar quieta perquè els dits també estiguin calmats."},"ICON-0989":{"nm":"Clip per a suport de concentrador USB","de":"Una pinça que dreça de biaix, a la vora de l'escriptori, un concentrador on s'apleguen molts cables. L'estampa de cables desordenats que s'apleguen i s'endrecen en un sol punt. El do d'unir en un sol feix allò embullat també viu aquí."},"ICON-0990":{"nm":"Tap per a esprai netejador de pantalles","de":"Un petit tap per a la boca d'un esprai que neteja les empremtes de la pantalla. Sempre s'ha de tancar bé perquè el líquid no s'escapi ni s'assequi. Per veure-hi clar, primer cal estalviar els mitjans de netejar; l'ordre humil de les feines de casa."},"ICON-0991":{"nm":"Cartera per a targetes de memòria","de":"Dies sencers d'imatges d'escenari dormen en silenci dins una targeta no més grossa que una ungla. Perdre-la fa desaparèixer tot un dia sencer, per això la guardes amb cura dins una petita cartera. Una casa que conté el record més petit i alhora el més gran."},"ICON-0992":{"nm":"Etiquetes per a discos durs externs","de":"Cinc discos durs externs negres dormen dins un calaix amb la mateixa cara idèntica. L'acte d'enganxar-hi una etiqueta i posar-los nom, 'aquell estiu', 'clips inèdits'. Una feina de posar un índex clar a un record entelat."},"ICON-0993":{"nm":"Fitxa de verificació de còpia de seguretat","de":"Si la còpia de seguretat s'ha acabat o no, el cor s'encongeix per aquella diferència mínima. Aquesta petita fitxa, ficada al lloc acabat, et diu 'fins aquí és segur'. La tranquil·litat ve de deixar-hi una marca."},"ICON-0994":{"nm":"Testimoni de nota al núvol","de":"Un testimoni que envola una sola línia de nota cap a un magatzem suspès en algun lloc del cel. Una petita màgia per la qual, allà on l'engegis, aquell escrit surt a rebre't. El cel nocturn on volaves un estel i hi escrivies un desig sembla, ara, haver baixat suaument fins a la palma de la mà."},"ICON-0995":{"nm":"Joc de caputxons protectors per a USB","de":"Deixat rodolant dins la motxilla amb el connector a la vista, els contactes acaben fent-se malbé. Es tapa cada extrem amb un petit barret i es guarda com un sol joc. L'acte de fer adormir amb cura el temps en què no s'usa. La preparació més silenciosa per a la propera connexió."},"ICON-0996":{"nm":"Cinta per a estoig de dades","de":"Una cinta que embolcalla i cenyeix bé un aparell que conté dades preuades. Es fa una volta i es lliga fort perquè no colpegi res dins una motxilla que trontolla. La mà que un dia nuava amb cura un farcell continua ben viva, ara, també en el digital."},"ICON-0997":{"nm":"Etiqueta d'ordenació d'arxius","de":"Quan centenars d'arxius s'amunteguen sense nom, buscar-los esdevé un extraviament. En el moment d'enganxar-hi etiquetes de colors i obrir-hi branques, s'obre un camí enmig del munt desordenat. Endreçar, al capdavall, és obrir un camí."},"ICON-0998":{"nm":"Targeta de pista de contrasenya","de":"Escriure la contrasenya sencera és perillós, no escriure-la mai és oblidar-la. Per això només hi deixes un indici que només tu entens. Com 'aquella ciutat del primer escenari'. Una manera de recordar, intel·ligent i tendra, que apunta el camí, no la resposta."},"ICON-0999":{"nm":"Adhesiu de data d'emmagatzematge","de":"Si no apuntes el dia que ho vas desar, guardar esdevé aviat oblidar. Un adhesiu de data a cada capsa grava clarament el 'des de quan'. El cor del vell rebost que apuntava el dia que es feia la pasta de soja continua, ara, en aquest petit paper."},"ICON-1000":{"nm":"Tapa per a mini llum d'anell","de":"Un petit llum que fa una llum rodona, i la tapa que en cobreix el forat de llum. Deixa la llum adormida una estona perquè l'objectiu no es ratlli dins la motxilla. Guardar amb cura la foscor abans d'encendre's és també una manera d'estalviar claror."},"ICON-1001":{"nm":"Cargol d'ajust del suport","de":"Només una volta més. L'escletxa que s'havia afluixat desapareix, i sota la palma s'hi asseu una tranquil·litat feixuga. Darrere d'un escenari que no trontolla sempre hi ha amagat un gest ferm del canell d'algú. El que sosté un cargol petit és una fermesa que no es veu."},"ICON-1002":{"nm":"Fitxa d'emissió en directe","de":"En el moment en què s'encén el llum vermell, les passes del passadís es tornen de puntetes sense adonar-se'n. En directe: davant d'aquestes paraules, tothom conté l'alè. Fins i tot el silenci més enllà de la porta és un cor girat cap a algú, i això és el que aquesta petita fitxa anuncia en silenci."},"ICON-1003":{"nm":"Bloc de notes del xat","de":"Amb la punta dels dits atrapa els ànims que d'altra manera fugirien per la pantalla. Un temps en què cada paraula que s'hauria escolat queda ben clara i quieta sobre el paper. Escriure és el lloc on s'atura la tendresa que vol arribar, encara que sigui tard."},"ICON-1004":{"nm":"Funda silenciosa de teclat","de":"A les dues de la matinada, el soroll de prémer les tecles desapareix com si fos mentida. Una fina membrana perquè no desperti la respiració d'un company de pis profundament adormit. La consideració més silenciosa sempre comença en un lloc sense so."},"ICON-1005":{"nm":"Clip de braç de micròfon","de":"Entre els llavis i el micròfon, exactament la distància perquè la cançó no trontolli. Aquest petit clip manté ferma aquesta promesa. Darrere l'escenari sempre hi ha, arribada abans que ningú, una mà que aguanta amb fermesa com aquesta."},"ICON-1006":{"nm":"Pinça de teló de fons","de":"Encara que bufi el vent, el teló de fons no es mou ni un mil·límetre. Perquè una petita mandíbula que mossega fort la cantonada sosté tota l'escena. Darrere un paisatge que no trontolla, algú, en un lloc que no es veu, hi és amb les dents ben serrades."},"ICON-1007":{"nm":"Etiqueta de Stream Deck","de":"Damunt de desenes de botons, gràcies a una petita etiqueta la mà no es perd. Una sola línia esborra per endavant un error de la retransmissió en directe. La serenor ve de les lletres que s'han escrit abans que arribi el tremolor."},"ICON-1008":{"nm":"Botó de marca horària","de":"Si es prem fort, una petita bandera es planta damunt del temps que s'escola. És l'acte de segellar un ara que mai no tornarà. Molt més tard, en mirar enrere, aquella marca s'ha convertit en una porta cap al record."},"ICON-1009":{"nm":"Clauer lector de targetes","de":"N'hi ha prou d'acostar-lo: un bip, i la informació es desperta. Un petit company que penja del clauer i dringa dins la butxaca. Un dia qualsevol continua sa i estalvi gràcies a senyals sonors tan minsos com aquest."},"ICON-1010":{"nm":"Etiqueta d'endoll intel·ligent","de":"Si es posa un nom a cada endoll, ja no cal perdre's esbrinant quin cable és quin. Un cor que dona nom fins i tot a l'electricitat invisible. L'ordre és una altra cara que la tendresa es posa prestada per un moment."},"ICON-1011":{"nm":"Suport de sensor de temperatura i humitat","de":"Un vigilant de la mida d'una palma que observa en silenci la temperatura i la humitat de l'habitació. El benestar no obre mai la boca, però aquest suport vetlla quietament, a cada instant, pel teu estat. Així es guarda el benestar, en silenci."},"ICON-1012":{"nm":"Tapa de sensor de porta","de":"Un ull petit que no deixa escapar l'instant en què la porta s'obre suaument. Transmet sense soroll el senyal que algú ha tornat. Qui vetlla una casa buida són sempre coses callades com aquesta."},"ICON-1013":{"nm":"Suport per a comandaments","de":"Els comandaments que rodolaven per tot arreu troben, per fi, cadascun el seu lloc. Un petit racó que reté tranquil·lament allò que gairebé s'havia perdut, una mà que grava per endavant la promesa de tornar-se a trobar."},"ICON-1014":{"nm":"Fitxa de l'app de son","de":"Cada nit que dorms bé, una satisfacció rodona s'hi va afegint de mica en mica. L'app t'assenyala amb tendresa que el son també s'acumula, capa a capa, com una pràctica. És el premi més petit del món, ofert a un tu que ha descansat bé."},"ICON-1015":{"nm":"Base per a cub temporitzador","de":"Mentre els tres minuts passen amb precisió, el cub compta el seu temps sense vacil·lar. Un racó de la mida d'una palma que el sosté per sota amb quietud. Fins i tot l'espera necessita un terra on trepitjar amb el cor tranquil."},"ICON-1016":{"nm":"Cobertor de llum d'avís","de":"Perquè no sigui massa intensa, embolcalla la llum amb una capa suau. Que l'avís pugui ser urgent, però que almenys els ulls estiguin tranquils. La consideració és un cor que calcula amb cura fins i tot la intensitat de la llum."},"ICON-1017":{"nm":"Targeta de canvi de pila","de":"Si apareix aquesta targeta, vol dir que ha arribat el moment de canviar el petit cor del dispositiu. Un avís tendre perquè hi paris atenció abans que s'aturi. El secret d'una companyia llarga sempre és una cura avançada un compàs."},"ICON-1018":{"nm":"Joc de tapes per a joystick","de":"Petits barrets que s'encaixen suaument perquè el polze no rellisqui. La sensibilitat de la punta dels dits es torna més nítida. Aquesta petita tapa pot arribar a decidir la victòria o la derrota d'una partida jugada amb les mans suades."},"ICON-1019":{"nm":"Funda de base de consola","de":"Cobreix suaument, protegint-lo de la pols, el lloc on descansa la consola. Perquè fins i tot un aparell que dorm només una estona necessita un llençol. L'afecte es mostra més clar, precisament, quan una cosa no s'utilitza."},"ICON-1020":{"nm":"Funda per a consola portàtil","de":"Quan es viatja, sempre a dins d'aquesta. Una funda que abraça tovament la consola portàtil. Perquè resisteixi els cops de dins la motxilla sense immutar-se, val la pena embolicar una vegada més allò que és preciós."},"ICON-1021":{"nm":"Rotllo d'enganxines per a botons","de":"N'hi ha prou de posar un petit dibuix damunt d'un botó insípid perquè, en aquell instant, passi a ser del tot meu. L'acte de deixar la meva pròpia marca sobre un aparell idèntic a tots els altres. La personalitat sempre floreix, tranquil·la, en racons tan petits com aquest."},"ICON-1022":{"nm":"Estoig de cartutx de joc","de":"Una partida en la qual et vas enfonsar tota la nit dorm profundament dins d'aquest petit estoig. Si en tornes a obrir la tapa, aquella nit es desperta intacta. Els records, sorprenentment, sovint caben en una capsa no més gran que una palma."},"ICON-1023":{"nm":"Suport de ventilador refrigerant","de":"Mentre el vent refreda l'escalfor, un racó que aguanta el dispositiu lleugerament inclinat. Fa lloc perquè un cos escalfat pugui respirar un moment. Per córrer lluny, cal saber també aturar-se un instant per refredar-se."},"ICON-1024":{"nm":"Passador de corretja de canell","de":"Si te la poses al canell i tanques el passador, per molt violent que sigui el moviment, el comandament no es separarà de tu. Aquesta corretja que sembla una nosa és, en realitat, la tranquil·litat que et permet jugar amb el cor lliure."},"ICON-1025":{"nm":"Funda de palanca analògica","de":"Vesteix amb roba nova un agafador tornat llis i brillant de tant subjectar-lo. Deixa intacta la sensació que la mà ja coneix, i només la superfície com si fos nova. Un instant en què la familiaritat i l'entusiasme reposen junts en una mateixa mà."},"ICON-1026":{"nm":"Etiqueta de ranura de partida","de":"A cada ranura de partida hi escrius, ben clar, de qui és l'aventura. Una sola línia vetlla en silenci pel viatge dels darrers dies. Els records preciosos és millor gravar-los amb un nom, perquè ningú els sobreescrigui."},"ICON-1027":{"nm":"Funda per a gravadora","de":"Un aparell que guarda sons es fa més preciós per allò que conté a dins. Es porta ben posat dins d'una funda tova que el protegeix dels cops. Potser hi dorm la veu d'algú, així que amb encara més cura."},"ICON-1028":{"nm":"Protector de vent per a micròfon","de":"Aparta el soroll del vent i deixa només la veu. Una capucha esponjosa que es cobreix suaument sobre el micròfon en els enregistraments a l'aire lliure. És un petit filtre que, enmig del soroll desordenat, tria i recull només la sinceritat."},"ICON-1029":{"nm":"Etiqueta de nota de veu","de":"Aquesta és una lletra que va venir al cap, aquesta una melodia taral·lejada. A cada nota de veu s'hi enganxa una etiqueta de color. Els fragments d'inspiració que estaven escampats arreu troben, per fi, el seu lloc i es posen en fila."},"ICON-1030":{"nm":"Xip de botó de mostreig","de":"Si es prem fort, salta un fragment de so guardat per endavant. Una gota de pluja, un aplaudiment, el riure d'algú: fragments del món es desperten a la punta dels dits. La música és el cor tendre d'aquests petits xips."},"ICON-1031":{"nm":"Sobre de recollida de sons","de":"En aquest sobre hi guardes amb cura els sons que has anat recollint tot caminant. La textura del vent, fins i tot el silenci d'un carreró a trenc d'alba. Els materials que algun dia esdevindran una cançó sempre s'apleguen així, amb humilitat."},"ICON-1032":{"nm":"Peus de trípode mini","de":"Tres potes despleguen un petit escenari damunt la taula. En lloc d'una mà tremolosa, es planten fermes i sostenen l'escena. Una imatge nítida neix, per fi, de tres peus que s'han aturat en silenci."},"ICON-1033":{"nm":"Etiqueta d'arxiu de gravació","de":"A centenars d'arxius de gravació hi vas posant una petita etiqueta, un per un. Perquè d'un cop d'ull sàpigues quin va ser el primer vers que va sortir, i quin dia. És una petita fita que ajuda a retrobar veus disperses."},"ICON-1034":{"nm":"Cinta adhesiva d'ona sonora","de":"Una cinta de dibuix ondulat modelada exactament amb la forma del so. Si l'enrotlles al voltant d'una llibreta o d'un estoig, és com si la música es fes visible davant teu. És una enganyifa tendra que converteix allò que se sent en allò que es veu."},"ICON-1035":{"nm":"Ganxo per a auriculars","de":"Quan acaba l'assaig, prepara en silenci un lloc de descans per als auriculars cansats. Un petit ganxo clavat a la cantonada de la taula. Una taula endreçada és el lloc on es penja per endavant l'entusiasme de demà."},"ICON-1036":{"nm":"Cinta per a capsa de regal petita","de":"L'última volta que s'enrotlla al voltant de la cintura de la capsa de regal. Amb aquesta única cinta, el cor per fi queda complet. La cura sovint es transmet abans per la mà que n'allisa la superfície que pel que hi ha a dins."},"ICON-1037":{"nm":"Tapa de punta de llaç","de":"Embolcalla suaument la punta del llaç i l'acaba perquè no es desfaci. Un detall que gairebé no crida l'atenció canvia tranquil·lament la primera impressió d'un regal. Quan l'acabat és polit, el cor també hi arriba polit."},"ICON-1038":{"nm":"Cera de segellar","de":"Deixa caure una gota calenta per segellar el sobre. Com en una carta antiga, una promesa feixuga de no obrir-lo a la lleugera. La formalitat, de vegades, guarda un pes càlid com aquest."},"ICON-1039":{"nm":"Suport per a targetes d'agraïment","de":"Sosté ben dreta una targeta que porta paraules d'agraïment perquè no s'arrugui. Perquè el cor s'hi mantingui erecte en ser lliurat. L'agraïment queda més temps al cor quan fins i tot la seva forma és polida."},"ICON-1040":{"nm":"Paper de farciment en forma d'estrella","de":"Papers retallats en forma d'estrella omplen tovament els buits de la capsa. És el cotó d'un cor que desitja que res no es faci mal encara que el moguin. Fins i tot en la foscor de l'embolcall, hi flota una petita estrella."},"ICON-1041":{"nm":"Etiqueta de llista de regals","de":"Davant la casella del destinatari, la ploma s'atura una bona estona. Mentre s'escriu el nom, el rostre que ve al cap, les estacions viscudes plegats. En el moment de fermar-la, aquest petit paper esdevé un secret que ningú no pot llegir fins que no es desfà."},"ICON-1042":{"nm":"Segell rodó de felicitació","de":"Si es prem fort, surt marcada amb claredat una felicitació rodona. Mentre s'espera l'instant que triga a assecar-se la tinta, el cor que imagina a qui la donarà és el més càlid de tot. Si té un defecte, és que fa venir ganes de tornar-la a estampar."},"ICON-1043":{"nm":"Bobina de cordill de regal","de":"Enrotllat amb cura, es desenrotlla joiosament a la punta dels dits emocionats d'algú. En aquest breu instant d'enrotllar-se i desenrotllar-se, un cor lligat al fil esdevé, per fi, un regal."},"ICON-1044":{"nm":"Penjoll de nus (que no és una flor)","de":"No és una imitació d'una flor, sinó la forma que pren un sol fil quan s'abraça a si mateix una vegada i una altra fins a florir tot sol. La paciència dels dits que van triar nusos tota la nit ha quedat, així, com un petit capoll."},"ICON-1045":{"nm":"Bosseta de monedes de la sort","de":"El gest de deixar caure d'amagat unes quantes monedes a la butxaca de qui emprèn un camí llarg. No és omplir de pes, sinó de tendresa. El dring a cada pas fa de comiat: que et vagi bé."},"ICON-1046":{"nm":"Penjoll de càpsula de desig","de":"Dins una closca rodona hi dorm plàcidament un desig plegat. Que obrir-la el faci realitat és una mentida, però que mantenir-lo tancat i abraçat el mantingui viu per sempre, això és cert."},"ICON-1047":{"nm":"Cordó protector de nus","de":"Un cordó teixit fort amb fils dels cinc colors, que gira les males energies i les deixa enrere. Com la mà de l'àvia que lligava un nus al canell quan érem petits, a cada punt lligat hi ha, ben clavada, la pregària d'algú."},"ICON-1048":{"nm":"Estoig de grua de paper petita","de":"Una petita casa que guarda intacta, sense fer-li mal, una sola grua de paper d'entre les mil que calen per fer realitat un desig. Perquè si s'arruga fins i tot una sola ala, es desfà de mica en mica tota la dedicació d'aquella nit."},"ICON-1049":{"nm":"Bosseta de pedretes brillants","de":"Petits grans de llum caiguts del vestit d'escena, un racó on els reculls perquè no ets capaç de llençar-los. Fins i tot la lluentor que un cop se t'enganxa et segueix una setmana sencera, aquí dorm tan tranquil·la com sobre la teva palma."},"ICON-1050":{"nm":"Segell de bon auguri","de":"Una petita fitxa que s'afegeix d'amagat quan es tria un bon dia. No al llindar d'una endevina, sinó damunt la meva pròpia taula, un fragment de tendra superstició que s'estampa suaument desitjant que avui, només avui, passin coses bones."},"ICON-1051":{"nm":"Targeta de polsera de desig","de":"Un sol full imprès amb forma de polsera guarda el desig callat d'algú. Encara que no es pugui cordar al canell, si es guarda ben endins de la cartera, aquell cor queda sempre lligat al costat, caminant plegats."},"ICON-1052":{"nm":"Pot de sal del llindar","de":"Sal grossa dins d'un pot petit, deixat en silenci davant la porta. Un vell càlcul per allunyar les males energies i deixar entrar només els visitants benvinguts. Cada gra salat és un petit porter que vetlla per casa nostra."},"ICON-1053":{"nm":"Etiqueta cobre-número de la sort","de":"Just abans de gratar-la, tothom és, per un instant, el primer. Aquesta etiqueta que amaga suaument el número de la sort protegeix l'últim segon en què l'esperança s'infla més. Encara que la punta del dit tremoli en gratar, ella fa els ulls clucs i dissimula."},"ICON-1054":{"nm":"Tapa guarda-espelmes d'aniversari","de":"Un cor curós que guarda amb primor, fins al pròxim aniversari, una espelma que ja s'ha encès un cop. Si el desig demanat l'any passat encara no s'ha complert, aquest any n'hi ha prou de continuar demanant-lo des d'allà mateix: un tendre càlcul."},"ICON-1055":{"nm":"Anell de compte enrere d'aniversari","de":"Un objecte agosarat que et posa el dia D al dit. Cada vegada que el nombre de dies restants avança una xifra, el cor també s'estira una mica endavant. Insisteix, tot sol, que el dia que arribi a zero brillarà per si mateix."},"ICON-1056":{"nm":"Cordó de barret de festa","de":"Un cordó prim que fixa amb suavitat el barret de festa al cap. El protagonista, de fet, aviat es queixarà que li molesta i se'l traurà, però a la fotografia aquell instant el porta posat per sempre. Amb això ja n'hi ha prou de missió."},"ICON-1057":{"nm":"Pica petita per a pastís","de":"Una petita marca clavada en un pastís no més gran que dos artells d'un dit. Fins i tot damunt d'una dolçor que desapareixerà en una mossegada, la celebració s'aguanta ben dreta. Per petit que sigui, un aniversari és un aniversari, i avui la protagonista ets tu."},"ICON-1058":{"nm":"Etiqueta de cotilló","de":"No fa cap esclat, però visualment és el petard de paper més vistós. En el moment que s'enganxa al sobre, un correu qualsevol es transforma en una carta arribada d'una festa. Molta gent la deixa posada, perquè fa pena arrencar-la."},"ICON-1059":{"nm":"Pinça penjafotos","de":"Per por de deixar caure els records penjats del fil, sempre mantinc la boca ben tancada. Mentre tingui una fotografia agafada, ni el vent que entra per l'escletxa de la finestra no farà caure aquells dies."},"ICON-1060":{"nm":"Pegat de globus amb data","de":"Un pegat en forma de globus amb un número escrit. Si l'enganxes a la roba, tot el veïnat sabrà quin dia especial és avui. En arrencar-lo queda una marca, i fins i tot aquesta marca esborradissa esdevé un altre record."},"ICON-1061":{"nm":"Marca d'intercanvi de regals","de":"Una marca entremaliada que confon lleugerament qui ha rebut i qui ha donat. És una petita norma, tendra, de les taules on s'intercanvien regals: recorda més aviat què va passar de mà en mà que no pas qui el va donar."},"ICON-1062":{"nm":"Número de taula de celebració","de":"Un petit número plantat a cada taula del convit. Guarda la saviesa tendra de gent que ha organitzat moltes festes: si es decideix per endavant qui seu on, ningú no passa vergonya."},"ICON-1063":{"nm":"Bossa de regal per al pom de la porta","de":"Una manera de lliurar un cor sense tocar el timbre. Si la pengeu d'amagat al pom de la porta i desapareixeu com fugint, la cara de sorpresa de qui la trobi es converteix en el regal més gran que torna a qui l'ha enviat."},"ICON-1064":{"nm":"Etiqueta de repartiment secret","de":"A la cara no hi ha res escrit. Amagar fins al final qui l'ha enviat és el petit orgull d'aquesta etiqueta. Com més estona el destinatari es quedi somrient amb el cap decantat, més perfecta esdevé la seva missió secreta."},"ICON-1065":{"nm":"Fitxa de nota per al timbre","de":"Una petita nota que s'enganxa quan falta el coratge per trucar a la porta. Una sola línia curta com «he passat un moment» dura més que el so del timbre. Perquè una lletra maldestra i torta té una expressió pròpia."},"ICON-1066":{"nm":"Tapa de seguretat per a cúter","de":"Quan la fulla del cúter apunta descuidadament cap al dit, un petit heroi s'hi interposa d'amagat. Protegeix sans i estalvis fins a l'últim tall els dits, apressats per l'emoció d'un objecte nou."},"ICON-1067":{"nm":"Tros de plàstic de bombolles","de":"Vaig néixer per ser premuda. Amb aquest so sec de rebentar-se, la tensió del dia es va desfent sense saber com. Sovint hi ha dies en què m'estimen més a mi, durant més temps, que no pas l'objecte que abraçava a dins."},"ICON-1068":{"nm":"Agulla d'hora d'arribada","de":"Una agulla que marca amb precisió a quina hora arribarà. Fins i tot una espera imprecisa es fa més suportable quan té una sola coordenada. Quantes vegades es mirarà pel forat de la porta fins a aquella hora és cosa exclusivament de cadascú."},"ICON-1069":{"nm":"Clauer de taquilla de paqueteria","de":"Un petit company per a qui sempre oblida la contrasenya de la taquilla de paqueteria. Penja balancejant-se del clauer, i el seu talent discret és fer sortir, en el moment decisiu, un «ah, és clar»."},"ICON-1070":{"nm":"Etiqueta de cistella d'entrada","de":"Una etiqueta enganxada a la cistella d'un racó de l'entrada. Hi ha escrita la promesa muda: «deixa-ho aquí». Encara que estigui buida, un lloc que espera el cor d'algú mai no és sol."},"ICON-1071":{"nm":"Enganxina de tapar adreça","de":"Sobre una capsa que es llença, deixa el nom però esborra només l'adreça. Fins al nom és bo que ho sàpiga tothom; on visc, que sigui només secret meu. En el moment d'enganxar aquesta única capa, neix una petita tranquil·litat."},"ICON-1072":{"nm":"Etiqueta de pot de llaminadures","de":"Una etiqueta que diu d'un cop d'ull què hi ha dins el pot. Però el parany és que, si hi escrius «llaminadures», ja et sents reconfortat encara que no obris la tapa. L'etiqueta, però, no es fa responsable de la gana."},"ICON-1073":{"nm":"Penjoll petit de collaret","de":"Un petit gra que comparteix en silenci la calor del cos sota la roba. Sempre en contacte amb un lloc que ningú no veu, i per això mateix encara més entranyable. El company més proper, que camina a l'altura del pit."},"ICON-1074":{"nm":"Estora de segell de petjades","de":"Si l'estampes damunt la potota, queda una fila de petites petjades. Un diari de passeig d'un dia sencer, escrit ben clar sobre el paper: qui ha caminat cap a on. El primer pas tacat de tinta és sempre el més nítid."},"ICON-1075":{"nm":"Tapa de raspall de pèl","de":"Una petita tapa que s'ocupa netament del pèl embolicat al raspall. En l'època de la muda, quan un sol raspallat n'ajunta un grapat, sense aquesta tapa tota la casa esdevindria un camp de neu esponjosa. Una netejadora diligent que no es fa notar."},"ICON-1076":{"nm":"Estoig de bosses de passeig","de":"Una petita casa que porta ben endreçades les bosses necessàries per al passeig. Aquest estoig demostra cada dia, en silenci, que només qui les porta preparades pot caminar tranquil. Aquell full que, si l'oblides, et posa en un compromís."},"ICON-1077":{"nm":"Etiqueta cobre-nom","de":"Una etiqueta que amaga d'amagat el nom veritable i deixa només el sobrenom. En aquest món hi ha també una tendresa que un no vol mostrar a qualsevol. Aquella manera de cridar que només coneixen els qui saben, s'hi amaga aquí, suaument."},"ICON-1078":{"nm":"Estora per a bol d'aigua","de":"Jo, estesa sota el bol d'aigua, estic sempre humida. Rebo en el seu lloc les gotes que esquitxen a tot arreu, i mantinc el terra eixut i sec. Ningú no em lloa mai, però jo tampoc no em queixo."},"ICON-1079":{"nm":"Fil de reparació de joguines","de":"Un ninot amb una costura descosida no es llença, es torna a cosir. A cada punt que s'omple, el temps passat amb aquell nen es torna a fer fort. Reparar és, al capdavall, ajornar en silenci un comiat."},"ICON-1080":{"nm":"Collaret de foto commemorativa","de":"El cor de portar penjada al coll la instantània en què somreies més radiant. Aquell dia de la fotografia, en lloc de quedar dissecat, es balanceja a cada pas i arriba fins avui. Aquell moment feliç no s'atura mai."},"ICON-1081":{"nm":"Xip de color d'estat d'ànim","de":"Si el cor també tingués colors, quin seria avui el teu? En el moment de triar un xip i deixar-lo damunt la taula, l'ànim que les paraules no van saber dir del tot s'escampa en silenci. Va bé la llum del capvespre, va bé la llum de l'alba: és un petit mirall que reflecteix tranquil·lament el jo d'aquell dia."},"ICON-1082":{"nm":"Bola del registre d'avui","de":"Quan cau la nit, dins la bola s'hi condensa avui, rodó. Tant allò que va anar bé com allò que va sortir maldestre s'hi recull i hi roda plegat. Si te la poses a la palma, el tu d'ahir s'escalfa una mica i et dona uns copets a l'esquena, dient-te que avui també has viscut bé."},"ICON-1083":{"nm":"Pot de notes d'elogi","de":"Les bones paraules es dispersen amb massa facilitat, així que se'n plega una i s'hi guarda dins d'aquest pot. Quan els elogis s'hi acumulen com una fragància, s'obre la tapa les nits que el cor se sent buit. En treure de nou i llegir una tendresa que algú va oferir, la calidesa d'aquell dia reviu."},"ICON-1084":{"nm":"Cordó de llaç de reconciliació","de":"Un cor embolicat s'assembla a un nus: també cal cura per desfer-lo. Si dues persones agafen els dos extrems del cordó i estiren a poc a poc, sense adonar-se'n en surt un llaç bonic. La reconciliació no és tallar sinó tornar a lligar, com aquest cordó ens diu en silenci."},"ICON-1085":{"nm":"Fitxa de gratitud","de":"Els dies en què les paraules «gràcies» no volen sortir dels llavis, en lloc d'elles es lliura d'amagat una fitxa. La mà que la rep en llegeix tot el cor només per aquell petit pes. Una sinceritat que arriba abans que les paraules: l'afecte hi viatja dins d'un únic gra rodó."},"ICON-1086":{"nm":"Marca de descans","de":"Fins i tot una sala d'assaig que ha corregut tot el dia necessita un compàs per recuperar l'alè. Si es penja aquesta marca a la porta, el temps s'alenteix un moment. Qui ha viscut un dia sense respir sap que una cançó necessita silencis per poder respirar."},"ICON-1087":{"nm":"Calaix de sentiments secrets","de":"Hi ha dies en què no es pot mostrar del tot allò que un porta a dins. En aquests moments, es guarda amb calma tant la tristesa com l'entusiasme dins d'un petit calaix del cor, i es tanca. Ara ja pots deixar-ho estar; algun dia arribarà el moment d'obrir-lo a poc a poc i posar-hi ordre."},"ICON-1088":{"nm":"Rotllo d'enganxines de somriure","de":"Si n'arrenques una a una, un somriure se't queda enganxat a la punta del dit. Una petita alegria que s'enganxa suaument a la cantonada d'una llibreta o a la taquilla d'un amic. Quan surt un petit sol sobre el paper, el dia de qui el troba es fa una mica més lluminós."},"ICON-1089":{"nm":"Penjoll de campaneta de bons desitjos","de":"El desig d'arribar fins a tu, que estàs lluny, s'ha condensat en una sola campaneta. Si la sacsegen, un so clar transmet la salutació en el seu lloc. Els dies que no vaig gosar preguntar «com estàs», aquest petit dring viatja amb el vent i hi arriba primer."},"ICON-1090":{"nm":"Agulla protectora contra la pluja de primavera","de":"Els dies de pluja de primavera, com més s'estima una cosa, més fàcilment es mulla. Si tanques la coberta amb aquesta agulla, les gotes de pluja llisquen de costat. El gest d'abraçar contra el pit un llibre preciós: una petita agulla substitueix aquesta tendresa."},"ICON-1091":{"nm":"Enganxina refrescant d'estiu","de":"Un tros, aplicat suaument, sobre el dors de la mà cansada per la calor de ple estiu. Una frescor s'escampa com la menta i la suor s'esvaeix una mica. Aquella frescor de jaure a la galeria fent-se vent amb un ventall, un paper de mida palma la imita amb cura."},"ICON-1092":{"nm":"Retall de tela de quadres de tardor","de":"Un tros de tela de quadres que s'assembla a un camp de tardor. És el rastre d'algú que va apedaçar amb cura un lloc gastat. El gest de cosir en lloc de llençar: petits retalls que s'ajunten i tornen a donar calidesa a allò que s'havia gastat."},"ICON-1093":{"nm":"Clip de guant d'hivern","de":"Els guants d'hivern, no se sap com, sempre acaben fugint d'un en un. Si els uneixes amb aquest clip, les mans gelades no es perden. El desig de no perdre'ls habita en una petita peça de metall, i manté els dos guants junts."},"ICON-1094":{"nm":"Etiqueta impermeable de la temporada de pluges","de":"En la temporada de pluges, fins i tot l'etiqueta del nom es difumina amb la pluja. Aquesta etiqueta recoberta impermeable protegeix l'escriptura fins i tot sota una pluja torrencial. Una línia que continua clara després que escampi: perquè no s'oblidi mai de qui és."},"ICON-1095":{"nm":"Pot per guardar la primera neu","de":"La primera neu desapareix en tocar la mà, així que almenys aquell entusiasme es va guardar dins d'un pot. Allò que hi ha tancat dins el vidre no és neu, sinó el cor que bategava aquell dia. Si el sacsegen, tot un hivern torna a caure en volves i et porta de nou a aquell matí."},"ICON-1096":{"nm":"Cinta per a sobre de festa","de":"Una sola cinta vermella enrotllada al voltant d'un sobre de festa. Tothom sap que l'afecte de la mà que el dona pesa més que allò que conté a dins. El cor que embolica junts els desitjos de benestar i la bona sort queda lligat, polidament, dins d'aquesta cinta prima."},"ICON-1097":{"nm":"Cinta per a estris de pícnic","de":"En estendre l'estora i obrir la fiambrera, el vent no para d'aixecar la tapa. Si es tanquen els estris fermament amb aquesta cinta, el pícnic no es desordena. El desig de protegir fins al final un àpat preparat amb cura queda contingut en una sola cinteta."},"ICON-1098":{"nm":"Targeta de mostra d'aroma estacional","de":"Perquè es pugui reconèixer l'estació sense ni obrir-la, en una sola targeta hi ha guardada la fragància d'aquell temps de l'any. A la primavera, flors; a la tardor, olor de fulles seques. En l'instant en què frega la punta del nas, tota l'estació torna a la ment: «això és l'aire d'abril»."},"ICON-1099":{"nm":"Tauleta de pinça per a preus","de":"El maldecap de la parada, amb les etiquetes de preu que sempre volaven, aquesta única tauleta de pinces l'ha apaivagat. Mossega fermament els números i els presenta ben drets davant del client. La primera salutació d'un negoci comença amb una sola línia honesta que mai no es desordena."},"ICON-1100":{"nm":"Cartell giratori d'obert","de":"Si es gira aquest cartell i es penja davant la porta, la botiga es desperta per fi. De «en preparació» a «benvinguts». Un petit senyal que anuncia el començament del dia: el lloc que la mà del propietari toca primer cada matí."},"ICON-1101":{"nm":"Targeta de segells de fidelitat","de":"Quan s'omplen les deu caselles, per algun motiu passa alguna cosa bona. Cada segell és el pas d'un client habitual, l'afecte acumulat amb el temps. En cada marca impresa fins que s'asseca la tinta, hi viu i hi respira una petita promesa de tornar."},"ICON-1102":{"nm":"Protector de nansa de bossa de paper","de":"La nansa d'una bossa de paper sempre és feble davant el pes. Poseu-hi aquest protector i el cordill a punt de trencar-se es torna resistent. El desig de portar allò que hi ha a dins sanament fins a casa: una petita peça que sosté aquest camí fins al final."},"ICON-1103":{"nm":"Safata de monedes del taulell","de":"Aquesta safata alleuja en silenci la vacil·lació de passar el canvi de mà en mà. El so de les monedes dringant fins a trobar el seu lloc. Donar i rebre es torna més càlid gràcies a aquesta rodona petita atenció."},"ICON-1104":{"nm":"Fitxa de punts acumulats","de":"Els passos fets avui s'acumulen amb cura en una sola fitxa. Un càlcul curiós on com més se n'aplega, més lleuger es torna el cor. La joia d'omplir-se a poc a poc s'assembla al plaer de veure com un pot buit es va omplint sense adonar-te'n."},"ICON-1105":{"nm":"Agulla de número de prestatge","de":"A cada prestatge hi ha clavat, amb afecte, un petit número. Un guia silenciós que indica on és cada cosa. La voluntat de marcar el lloc per endavant perquè ningú s'hi perdi: fins i tot l'ordre pot tenir aquesta calidesa."},"ICON-1106":{"nm":"Got de broqueta de tast","de":"Un petit got que ofereix una mossegada per tastar. Fins i tot el client indecís obre el cor davant aquest bocí. La generositat de dir «tasteu-ne un», penjada de la punta de la broqueta, reté els passos de qui hi ve per primer cop."},"ICON-1107":{"nm":"Suport de llista de reserves","de":"Els noms dels clients d'avui s'alineen ordenadament en aquest suport. Una promesa tendra que diu que fins i tot l'espera té el seu torn. Mantenir dret un full de paper esdevé el primer pas, fet amb cura, per acollir el dia d'algú."},"ICON-1108":{"nm":"Pinça de fil per a fotos de paret","de":"Es passa un fil per la paret i s'hi pengen les fotos una a una amb pinces. Els moments de somriure hi pengen l'un al costat de l'altre, com bugada, assecant-se. Si esteneu els records allà on cau el sol, cada vegada que hi passeu, el riure d'aquell dia torna a onejar."},"ICON-1109":{"nm":"Racó de catifa petita","de":"Una petita catifa estesa a la vora de l'habitació. Un lloc que escampa calidesa primer sobre el terra fred. El pam que els peus descalços toquen primer, on la punta dels peus de qui torna a casa finalment es tranquil·litza i s'abandona a una dolça peresa."},"ICON-1110":{"nm":"Tela per cobrir la placa del nom","de":"Un tros de tela que cobreix suaument la placa del nom. Amagar el nom per un temps també és una mena d'encant de la llar. Un plec preciós que cau sobre la frontera entre dins i fora, penjat amb suavitat amb el desig de descansar tranquil·lament avui."},"ICON-1111":{"nm":"Clip per a fil de llums","de":"Aquest clip manté ben endreçat el fil de llums que penjava. Una mà que endreça el camí perquè la llum no es dispersi. Quan arriba el vespre, si allises un fil desendreçat, tant la llum de l'habitació com el cor es tornen més tranquils."},"ICON-1112":{"nm":"Imant per a pòsters","de":"Un petit imant per enganxar un pòster a la paret. El paper es manté al seu lloc sense fer ni un sol forat de xinxeta. La mà que tracta allò que estima sempre és suau, i aquí hi ha el desig de no fer-li mal."},"ICON-1113":{"nm":"Cordó amb borla per a cortines","de":"Un cordó amb borla que lliga la cortina a un costat. Obre un camí preciós perquè hi entri la llum del matí. Estireu una vegada el cordó amb borla i un dia lluminós s'abraona dins l'habitació i s'hi queda."},"ICON-1114":{"nm":"Etiqueta de suport per a espelmes","de":"Una petita etiqueta enganxada al suport d'una espelma. Anota amb cura quina flaire crema i quan es va encendre per primer cop. Posar nom a una olor que estimes: aquesta pulcritud fa l'aire de l'habitació encara més tendre."},"ICON-1115":{"nm":"Potes de goma per a prestatge decoratiu","de":"Quatre potes de goma que sostenen un prestatge perquè no trontolli. Des d'un lloc invisible, suporten el pes en silenci. Petites i baixes, fàcils de passar per alt, però allò que aguanta ferm al fons és, al final, allò que dura més."},"ICON-1116":{"nm":"Penjoll de fletxa indicadora","de":"Per a qui dubta sobre quin camí seguir, una sola fletxa assenyala en silenci la direcció. Un gest tendre que diu: no perdis el teu camí. Gràcies al cor que algú hi va posar abans a cada cruïlla, avui també avancem sense perdre'ns."},"ICON-1117":{"nm":"Cordó de clau d'invitació a l'illa","de":"Un cordó de clau que es posa a la mà de qui et convida a l'illa. Agafa'l i ara tu també ets de la família d'aquí. L'hospitalitat d'acollir un convidat estrany cap a l'interior càlid queda ben ferma en la petita promesa que penja de la punta del cordó."},"ICON-1118":{"nm":"Fitxa de temperatura de la relació","de":"Una sola fitxa revela, d'esquitllentes, la temperatura entre dues persones. Si encara és d'un blau distant o si ja s'ha tornat d'un càlid vermell viu. La velocitat amb què s'aprofundeix l'afecte és difícil de mesurar, però la palma de la mà en nota primer la calidesa."},"ICON-1119":{"nm":"Caixa de mostres de gustos","de":"Quan encara no se sap què li agrada a algú, s'apleguen petites mostres en una caixa i se li ofereixen. Dins la joia de triar, el gust creix a poc a poc. Quina serà la teva: la caixa és plena d'una possibilitat emocionant."},"ICON-1120":{"nm":"Agulla de reserva de cura","de":"La promesa de tenir cura d'algú queda clavada, ben clara, en aquesta sola agulla. Escriu-hi el nom i l'hora i el cor no perdrà el camí. Aquell tendre intercanvi de vigilar per torns els fills els uns dels altres hi viu i hi respira, aquí mateix."},"ICON-1121":{"nm":"Càpsula de registre de creixement","de":"Igual que les marques d'alçada s'acumulen línia rere línia al marc de la porta, aquesta càpsula segella en silenci el tu d'ahir. Obre'n la tapa d'aquí a molt de temps i ho sabràs: fins on han caminat aquells passos, abans tan petits."},"ICON-1122":{"nm":"Cinta record del primer trobament","de":"El calfred d'agafar-se les mans per primera vegada queda lligat, suaument, en una sola cinta. El nus no hi és per desfer-se, sinó per mantenir viva al canell la calidesa d'aquell dia."},"ICON-1123":{"nm":"Etiqueta decorativa de la meva habitació","de":"«Aquí és el meu lloc.» En el moment en què una petita etiqueta s'enganxa a la cantonada de l'escriptori, l'habitació fins ara estranya finalment respira i esdevé la Meva Habitació. Una etiqueta de nom és el primer lloc on el cor s'hi asseu."},"ICON-1124":{"nm":"Pot de boles de vincle","de":"Sacseja'l i, amb un lleuger repiqueig, rodola el so de com dues persones s'apropen un graó més. Quan el pot estigui a punt de vessar, només dient el teu nom, el riure ja haurà sortit a rebre't primer."},"ICON-1125":{"nm":"Segell de preparació per al debut","de":"El darrer full que tanca el sobre. Fins aquí és la preparació; passa la pàgina següent i és l'escenari. Prement-lo fort amb la punta dels dits, l'aprenent recupera l'alè. Per fi, ara comença."},"ICON-1126":{"nm":"Aigua","de":"El més comú, per això el més preciós. En una sala d'assaig a trenc d'alba amb els llums apagats, un sol glop aixeca de nou algú que havia caigut. Una tendresa sense forma pròpia que s'escola dins qualsevol recipient."},"ICON-1127":{"nm":"Aigua clara","de":"Una transparència que fa brillar fins i tot els còdols del fons. Una font de muntanya mai no presumeix de la seva pròpia claredat. Un cor que no té res a amagar es veu sempre així, fins al fons."},"ICON-1128":{"nm":"Aigua de mar","de":"En el mateix instant que toca la llengua, arriben onades llunyanes. En un sol glop salat s'hi dissolen sencers l'horitzó, les gavines i el port que vas deixar enrere. El mar sempre roman a la memòria amb un gust salat."},"ICON-1129":{"nm":"Gel","de":"Es va fent petit lentament sobre la palma, desapareixent tant com el prems. Encara que sembli dur, sap que al final tornarà a ser aigua. El gel és un riu que ha aturat l'alè per un instant."},"ICON-1130":{"nm":"Bola de neu","de":"Una bola ben prensada vola blanca tallant el carreró. Rialles esbojarrades i galtes vermelloses de fred. La joguina més blanca que l'hivern posa, d'amagat, a les mans dels infants."},"ICON-1131":{"nm":"Terra","de":"Acull les llavors, beu la pluja i rep en silenci les petjades que hi passen. Una pell negra que abraça tot. Al primer lloc de tot allò que creix hi ha aquest grapat."},"ICON-1132":{"nm":"Terra fèrtil","de":"Fica-hi els dits i un greix negre i tou t'envolta suaument. El secret que feia que l'hort de l'àvia fos verd any rere any era just aquí. La terra ben curada xiuxiueja d'una collita abundant amb l'olor de l'adob."},"ICON-1133":{"nm":"Argila","de":"Tan bon punt s'amara d'aigua, accepta obedientment qualsevol forma. Una carn tendra que es fa ocell, es fa bol, seguint el gest de la mà. Mentre gira el torn, un grapat de terra somia per fi."},"ICON-1134":{"nm":"Sorra","de":"Grans menuts que s'escapen suaument entre els dits. Com més fort els aguantes, més de pressa s'escolen, i cada cop s'assemblen més al temps. En un grapat de platja hi dormen incomptables ahirs."},"ICON-1135":{"nm":"Còdols","de":"Pedres arrodonides a la vora del rierol. Són el rastre de l'aigua que les ha acariciat llarga, llargament, fins que n'han desaparegut les arestes. Com més lluny han rodolat, més suaument s'acomoden a la mà."},"ICON-1136":{"nm":"Pedra","de":"Un tros deixat sense pensar-hi vora el camí. Algú li fa una guitza en passar; algú altre l'aixeca amb cura i hi basteix una torre. La mateixa pedra esdevé càrrega o desig, segons el cor."},"ICON-1137":{"nm":"Llosa","de":"Una pedra plana i ampla que travessa el pati d'un antic palau. Centenars d'anys de sabates hi han trepitjat fins a fer-hi una lleugera depressió al mig. Cada persona que hi posa un peu, un pas rere l'altre, hi afegeix una capa més de temps."},"ICON-1138":{"nm":"Pedra calcària","de":"Les petxines dels seus dies de mar es van endurir capa rere capa fins a fer-se pedra blanca. Posa-la al forn i es desfà en calç, que pinta les parets d'un blanc immaculat. Per tranquil·la que sembli, és una pedra que porta dins tota una època."},"ICON-1139":{"nm":"Carbó","de":"Un antic bosc adormit en la negror. Falgueres de centenars de milions d'anys enrere, compactades ben endins de la terra. Encén-lo i la llum del sol, guardada tant de temps, es desperta de nou, ardent."},"ICON-1140":{"nm":"Carbó vegetal","de":"Reté el foc però engoleix el fum en silenci. La fusta prensada i ennegrida dins el forn floreix vermella, sense dir res, sobre el braser. Com més silenciosa és una cosa, més temps es manté càlida."},"ICON-1141":{"nm":"Branqueta","de":"Una branca que, per no trencar-se, s'ha anat corbant en silenci sap el camí de cedir. A cada lloc que ha resistit un vent dur s'hi forma un nus, i la fermesa autèntica és, al capdavall, la marca d'haver-se sabut corbar bé."},"ICON-1142":{"nm":"Tronc","de":"Dins els seus anells tallats, cent primaveres i hiverns s'apilen en cercles concèntrics. Els anys que un sol arbre va viure hi jeuen sencers, esperant en silenci que li arribi el torn de ser el pilar d'una casa."},"ICON-1143":{"nm":"Fusta serrada","de":"Cada vegada que hi passa la ribot, apareix una veta perfumada, capa rere capa. Mentre la fusta rugosa es torna llisa, la serradura s'apila al terra com neu groga. La mà que la treballa desperta la seva utilitat."},"ICON-1144":{"nm":"Post","de":"Fa el terra d'un rebedor, arma un banc, tanca una tanca. Quan s'apleguen, una rere l'altra, les taules tallades a escaire, finalment s'aixeca un lloc on viure. Coses ordinàries que s'amunteguen fins a fer-se una llar."},"ICON-1145":{"nm":"Bambú","de":"Buit per dins, però dret davant el vent. Els vells savis desitjaven assemblar-s'hi, a aquesta resolució que talla a cada nus i torna a brotar. Aquí hi ha una cosa encara més dreta pel fet de ser buida."},"ICON-1146":{"nm":"Suro","de":"Prem-lo i deixa'l anar, i torna a inflar-se fins al seu gruix original. Mirant aquesta veta, lleugera però tenaç, s'aprèn que ser tou no és pas ser feble. Des de taps d'ampolla fins a taulers d'anuncis, sosté les coses en silenci."},"ICON-1147":{"nm":"Herba","de":"Trepitjada, torna a alçar-se amb la pluja següent. Una tenacitat verda que cobreix tot un camp sense tenir ni un sol nom. No la subestimis per petita: qui anuncia primer la primavera és sempre aquest lloc humil."},"ICON-1148":{"nm":"Palla","de":"Allò que resta groc al camp després de la collita de tardor. Trenada, es feia teulada; estesa, es feia jaç càlid. És el cor que, després d'haver donat cada gra, cobreix la gent fins al final."},"ICON-1149":{"nm":"Canyís","de":"Quan el vent hi passa, un lleu xiuxiueig, i tota la vora del riu es posa a cantar. Una tija buida per dins que plora encara més lluny. El canyís no s'avergonyeix ni una mica que el seu bressolar sigui, ell mateix, el seu cant."},"ICON-1150":{"nm":"Cotó","de":"Quan la beina madura esclata, en floreix un petit núvol. Aquesta borra lleugera i suau esdevé fil i esdevé roba, i escalfa en silenci les espatlles d'algú en una freda nit d'hivern."},"ICON-1151":{"nm":"Llana","de":"Fregueu-la a les mans i hi queda un lleu greix i una calidesa que perdura. L'abric que l'ovella es cenyia per resistir les muntanyes fredes. Aquella calidesa retallada ara passa a l'hivern d'una persona."},"ICON-1152":{"nm":"Fil","de":"Prim, gairebé invisible, però és sempre ell qui torna a unir dos extrems separats. Feble en un sol fil, teixit esdevé tota una peça de tela. En la feina d'unir, el gruix no importa."},"ICON-1153":{"nm":"Teixit","de":"Trama i ordit s'encreuen incomptables vegades per formar una peça sencera. És el resultat de fils que, sols, es desfarien, aferrant-se amb força els uns als altres. Que com més tupida és la teixidura, més escalfa, també és cert entre les persones."},"ICON-1154":{"nm":"Cuir","de":"Com més s'usa, més s'hi impregna la marca de les mans i més s'assembla, a poc a poc, al seu amo. Mentre la rigidesa inicial es va suavitzant, el color s'aprofundeix i la textura es torna més tova. Aquella lluïssor gravada pel temps no la pot imitar res."},"ICON-1155":{"nm":"Ploma","de":"Tan lleugera que ni tan sols es nota el pes quan la poses a la palma de la mà. Un sol fil que guarda intacte el record d'haver volat pel cel. No oblidis mai que la cosa més lleugera va ser la que va volar més amunt."},"ICON-1156":{"nm":"Petxina","de":"Torna de sobte a la memòria allò que deia l'àvia, d'acostar-se-la a l'orella. En el seu interior d'irisacions hi ha gravat sencer el mar que vas deixar enrere, de manera que fins i tot una petxina buida deixa sentir l'onatge d'una època passada."},"ICON-1157":{"nm":"Corall","de":"Endurit com la pedra, però una vegada va ser, ben segur, una colònia que respirava. En el mar lent hi passa centenars d'anys estenent les seves branques. La branca més sòlida només creix després de la més llarga espera."},"ICON-1158":{"nm":"Perla","de":"Incapaç de suportar la molèstia d'un sol gra de sorra, l'ostra el va embolcallar en silenci amb llum. Que abraçar el dolor i arrodonir-lo el torna així de lluminós: és un petit consol que ofereix el mar."},"ICON-1159":{"nm":"Alga marina","de":"Una cinta verda que penja relliscosa sobre les roques de la costa amb la marea baixa. Agafeu-la amb la mà i us envaeix de cop una olor de mar. Sense arrels, confiant el cos al corrent, el mar cultiva en silenci el seu jardí."},"ICON-1160":{"nm":"Alga nori","de":"Acosteu un full negre breument al foc i es torna verdós mentre s'hi escampa una olor torrada. Aquell matí d'enrotllar-la al voltant de l'arròs acabat de fer. Per prim que sigui, abraça amb escreix la felicitat d'un àpat."},"ICON-1161":{"nm":"Sal","de":"Sóc el cristall blanc que el mar va deixar al sol. Un sol pessic aprofundeix una sopa massa fluixa, però una mà que es descuida sepulta tots els sabors. Només la punta dels dits que coneix la mesura justa em sap fer servir com cal."},"ICON-1162":{"nm":"Tros de vidre","de":"Només allà on es va trencar aconsegueix, per fi, corbar la llum i fer-hi florir un arc de Sant Martí. Un talent que no coneixia mentre era sencer. Fins i tot allò trencat guarda una porció de sol per donar, com xiuxiueja en silenci el tros que jeu vora la finestra."},"ICON-1163":{"nm":"Vidre","de":"Ser transparent no vol dir només no tenir res a amagar. Vol dir haver esborrat la pròpia forma per deixar passar la llum sencera. Fins i tot en el fet de romandre-hi invisible, hi ha una pulcritud freda quan una mà el toca."},"ICON-1164":{"nm":"Ampolla de vidre","de":"Ha de ser buida per dins per poder contenir alguna cosa. Melmelada, un grapat de flors silvestres o una carta plegada: el nom li canvia segons què hi entri. El recipient que no tem la buidor és el més generós."},"ICON-1165":{"nm":"Ampolla buida","de":"M'agrada la quietud que arriba després de l'últim glop begut. Algú em llença; algú altre m'esbandeix i em posa a l'ampit de la finestra per omplir-me de sol. Trobar de nou un ús allà on les coses han acabat: aquesta és la segona vida de tot allò que ha estat buidat."},"ICON-1166":{"nm":"Paper","de":"Estic estès, blanc, a punt per acollir qualsevol cosa. Sóc sempre jo qui mira més estona dins el cor de qui dubta davant la primera línia. La paciència d'un full en blanc arriba un pam més endins que la tinta."},"ICON-1167":{"nm":"Paper vell","de":"Groguejar no és envellir, és resistir. A cada plec hi ha impregnada la calidesa de les mans que l'obrien per llegir-lo. El paper vell, per no ser oblidat, anota amb el seu propi color el temps que ha passat."},"ICON-1168":{"nm":"Tinta","de":"Comença amb una sola gota, es fa frase, i un cop seca queda com una promesa. Escampada, és el rastre exacte d'aquell dia, tal com es va escampar. Com que la meva feina és fer les coses irreversibles, la gent em prem una vegada més, amb cura."},"ICON-1169":{"nm":"Mena de ferro","de":"Sóc una pedra que dormia un somni vermell sota terra. Només després de travessar el foc lliura per fi el ferro que porta a dins. La duresa no és dura des del principi; és un nom que es rep després de passar per la calor."},"ICON-1170":{"nm":"Lingot de ferro","de":"Només després que la mena resistís el foc es va refredar en un sol bloc. Aquesta forma freda i pesant es fa pont, es fa fulla, es fa aixada. Com que el meu ús encara no està decidit, puc esdevenir qualsevol cosa."},"ICON-1171":{"nm":"Mena de coure","de":"Vaig sortir de la terra amb un vestit d'òxid verd poma. Fon-me i sonen campanes, s'alcen estàtues, flueixen cables. Fins i tot mentre dormia en la terra fosca, sempre esperava el meu torn per ser cridada a esdevenir alguna cosa."},"ICON-1172":{"nm":"Lingot de coure","de":"Deixat a la vora molt de temps, es cus amb les seves pròpies mans un vestit blau. N'hi ha que anomenen aquesta tonalitat defecte, i n'hi ha que l'acaronen com el dibuix dels anys. El metall que no s'avergonyeix del seu color canviant és el que es vol més temps."},"ICON-1173":{"nm":"Mena d'or","de":"Una sola mica trobada després de garbellar i tornar a garbellar sorra de riu. No és preciosa perquè sigui rara, sinó perquè no canvia mai. La gent d'abans la posava a les mans com a penyora, dient que fos com un cor que no es rovella."},"ICON-1174":{"nm":"Lingot d'or","de":"Jeu com un sol bloc, sense enterbolir-se ni rovellar-se mai. Ha escoltat més cobdícia humana que ningú, i tanmateix jo mateix no cobejo res. Només un silenci pesant, fidel únicament a la feina de brillar."},"ICON-1175":{"nm":"Ferralla","de":"No he esgotat la meva utilitat: n'espero la següent. Claus trencats i llaunes bonyegudes s'apleguen per tornar a trobar-se amb el foc calent. Per a mi, la paraula rebutjat vol dir descansar per un temps."},"ICON-1176":{"nm":"Cargol","de":"Sol no puc fer res. Només quan em cargolen ben endins per unir dues taules amb força faig, finalment, la meva part. L'habilitat d'un cos petit per sostenir una cosa gran; fins i tot en aquesta força d'estrenyement hi ha cura."},"ICON-1177":{"nm":"Clau","de":"Un cop clavat, difícilment em faig enrere. Cada cop del martell no aprofundeix una ferida sinó una promesa. Si es tracta d'unir alguna cosa amb fermesa, ofereixo de bon grat el meu cap."},"ICON-1178":{"nm":"Engranatge","de":"Empenyo les dents del veí i girem junts. No intento anar sol i ràpid, sinó que sé com ajustar-me al ritme del costat. Com un rellotge on el temps només flueix quan les dents encaixen, crec que la concordança és, ella mateixa, moviment."},"ICON-1179":{"nm":"Molla","de":"Com més la premen, més força acumula a dins per tornar al seu lloc. Corbar-se no és rendir-se, és preparar-se per tornar a estendre's. Una petita espiral que retorna tant com ha absorbit el cop, on la flexibilitat és, ella mateixa, fermesa."},"ICON-1180":{"nm":"Cable","de":"Per fora, una funda discreta; per dins, un camí que flueix sense parar. Des de llocs invisibles, transporta llum i so. Com una mà que uneix en silenci el darrere de l'escenari, és un passatge que inspira encara més confiança per no mostrar-se."},"ICON-1181":{"nm":"Pila","de":"Guarda amb cura, dins el seu cos petit, la llum brillant de mig dia. Diu que, un cop gastada, només cal tornar-la a omplir, i mai no considera la buidor com una fi. Porta a dins un petit vespre per il·luminar la llarga nit d'algú."},"ICON-1182":{"nm":"Bombeta","de":"Un sol filament prim s'encén vermell i empeny la foscor enrere. No crema el seu cos per escalfar l'habitació, sinó per il·luminar-la. Més calent en l'instant que s'encén, i per això més lluminós: un petit sol d'un sol instant."},"ICON-1183":{"nm":"Lent","de":"Aplega la llum dispersa i la posa nítida en un sol punt. Convoca en silenci tant l'estrella llunyana com la lletra petita sobre la palma de la mà. Ajudant l'acte de veure, amaga precisament la seva pròpia forma: una alcavota clara i rodona."},"ICON-1184":{"nm":"Goma","de":"Prem-la o estira-la, torna sempre al seu lloc. Fins i tot els qui la titllaven de tova em trien per calçar els dies de pluja. La feina de rebre suaument un cop dur: en aquesta tovor també hi viu la tenacitat."},"ICON-1185":{"nm":"Tros de plàstic","de":"Sóc un petit tros desprès del cos principal. Estava a punt de ser llençat, però si se n'apleguen molts, torna a ser una cosa nova. No sóc lleuger perquè sigui petit, sinó capaç d'arribar lluny perquè sóc lleuger: una part de quelcom més."},"ICON-1186":{"nm":"Corda","de":"Només trenant diversos filaments esdevé, per fi, una sola línia. Sola es desfà amb facilitat, però teixida arrossega vaixells i lliga càrregues. Un nus antic de cooperació, aspre a la palma, fet més resistent per haver-se retorçat junt."},"ICON-1187":{"nm":"Tela de vela","de":"No odia el vent, sinó que se l'empassa ben endins del pit. Només quan s'infla tibant envia el vaixell lluny, de manera que fins i tot un vent de cara em dona força. La manera d'avançar abraçant, sense resistir-se, allò que és violent: ho vaig aprendre al mar."},"ICON-1188":{"nm":"Fragment d'àncora","de":"Sóc només una cantonada d'una àncora, però recordo sencer aquell pes. Els dies d'aferrar-me al fons profund i aturar un vaixell. Fins i tot ara, desprès, sóc un fragment feixuc que coneix el pes de quedar-se."},"ICON-1189":{"nm":"Clau de vaixell","de":"Un clau que subjectava, punt per punt, la coberta que es gronxava amb les onades. Encara que la sal el rovellés de vermell, mai no va deixar anar el seu lloc fins al final. Aferrar amb fermesa allò que flota també demana tossuderia."},"ICON-1190":{"nm":"Tela impermeable","de":"No es queixa mai de la feina de frenar la pluja. Rep en silenci allò que cau des de dalt i manté sec allò que hi ha a sota. Sense ser vistosa, és una capa sòlida que cobreix la càrrega d'algú perquè no es mulli."},"ICON-1191":{"nm":"Tint","de":"Només quan s'impregna en silenci dins un teixit senzill esdevé, per fi, color. Fos índigo o fos rubia, les mares d'abans es tenyien la punta dels dits mentre vestien la roba de color. Fins i tot en la feina d'enfonsar-se i amarar-se hi ha una profunditat que costa molt d'esvair."},"ICON-1192":{"nm":"Oli aromàtic","de":"Amb una sola gota, un ampli camp s'estén de sobte, omplint tota l'habitació. Un convidat invisible que hi arriba sempre el primer. Un paisatge que toca primer el nas, estirant d'amagat la vora del vestit dels records adormits."},"ICON-1193":{"nm":"Cera","de":"Amb calor flueix; en refredar-se s'endureix i conserva la forma. Movent-se entre la suavitat i la fermesa, dona forma en silenci a qualsevol cosa. Un material tendre que tanca, segella i abrillanta, canviant d'expressió segons la temperatura."},"ICON-1194":{"nm":"Espelma","de":"Es fon lentament el seu propi cos per il·luminar un racó de foscor. Quan s'ha cremat del tot, només en queda l'alçada retallada, però el temps que va escalfar la nit d'algú no desapareix mai. Un ble dret que sap com brillar mentre es fa petit."},"ICON-1195":{"nm":"Compost","de":"Coses que es podreixen s'apleguen totes juntes per fer-se la terra més fèrtil. Pells llençades i fulles seques cauen i esdevenen, en cert sentit, l'aliment dels nous brots de primavera. Al mateix lloc que es creia acabat, la vida següent recupera en silenci el seu primer alè."},"ICON-1196":{"nm":"Arròs","de":"Fan falta vuitanta-vuit gestos de la mà per tenir un sol gra a la palma. Des de plantar-lo fins a batre'l, tot un any de pagès queda contingut sencer en aquest petit gra. Un bol d'arròs que fumeja és, ell mateix, les quatre estacions d'algú."},"ICON-1197":{"nm":"Arròs integral","de":"Amb només la closca exterior lleugerament pelada, conserva intacte el seu color original. Que es faci més saborós com més es mastega és el gust d'una honestedat que no s'apressa. La ferma tossuderia del gra, que refusa ser polit fi i conserva la seva textura rugosa."},"ICON-1198":{"nm":"Blat","de":"Recorda el camp daurat que abaixava el cap tot alhora amb el vent. Fet pa, fet fideus, fet massa de sopa, escalfa taules arreu del món. Un gra que, per ser tan comú, s'ha infiltrat encara més endins en la vida de les persones."},"ICON-1199":{"nm":"Farina","de":"Només després de convertir-se en una pols blanca i fina es prepara per fi per esdevenir qualsevol cosa. Troba l'aigua i s'infla; troba el foc i es cou. Sense forma fixa, és una base dòcil que pren la forma que li donen les mans."},"ICON-1200":{"nm":"Massa","de":"Farina i aigua s'ajunten en un sol bloc sota la palma de la mà. Com més es treballa, més elàstica es torna; com més s'espera, més s'infla arrodonida. Si t'afanyes es torna dura, així que el temps de la fermentació és l'únic que no es pot apressar, diu el vell forn."},"ICON-1201":{"nm":"Pa ratllat","de":"Si sacsegeu la pols blanca que se us enganxa als dits, abans que us n'adoneu ja teniu les mànigues tacades de blanc. Convertida en arrebossat es torna cruixent; amuntegada tova, sembla la primera neu. És el rastre més lleuger que deixa un pa en coure's, però fins i tot les coses petites arriben a ser útils."},"ICON-1202":{"nm":"Pasta","de":"En el moment que escampeu un grapat en ventall dins l'aigua bullent, un sol llunyà travessa la cuina. Els fils llargs són cosa dels canells, i l'al dente és el cor que sap esperar quan encara li falta un punt de cocció. Mireu aquella brillantor que s'enrotlla i s'enrotlla a la forquilla."},"ICON-1203":{"nm":"Fideus instantanis","de":"Un paquet que es posa a coure d'amagat a l'alba, amb tot el maquillatge de l'escenari ja net. Els tres minuts que els fideus triguen a estovar-se són el moment més íntim de tot el dia. La tensió es refreda alhora que l'alè quan hi bufeu, i darrere de les ulleres entelades, avui s'acaba en silenci."},"ICON-1204":{"nm":"Pastís d'arròs","de":"Només quan l'arròs resisteix els cops del morter es converteix, per fi, en tteok. Simple, com injeolmi, com songpyeon: el mateix gra guanya cent noms segons les mans que el donen forma. Servit a la taula de festa, crida primer l'afecte i després la gana; és un menjar que sap millor si es comparteix."},"ICON-1205":{"nm":"Pastís d'arròs per a sopa","de":"Talleu un cilindre de tteok en diagonal i les rodanxes surten com petites monedes. És pastís d'arròs, allò que sura al brou blanc, o és un desig rodó? Buidar un bol el primer matí d'any nou hi afegeix un any a la teva edat: aquesta és, tendrament, la manera de comptar d'aquest país."},"ICON-1206":{"nm":"Patata","de":"Sacseja la terra i apareix una cara rodona. Un tubercle que va engreixar-se en silenci amb el vent dels vessants de Gangwon: farinós al vapor, saborós fregit. Fins i tot en els dies de butxaca lleugera, aquesta arrel honesta va omplir sempre la panxa de la família."},"ICON-1207":{"nm":"Moniato","de":"Quan el bidó de moniatos torrats apareixia a l'entrada del carreró, allò volia dir que l'hivern començava. Traieu el paper d'alumini i el vapor groc us escalfa primer els dits; aquella dolçor és la recompensa de l'arrel per haver aguantat el fred. Una escalfor perfecta per bufar-hi, partir-la per la meitat i compartir-la."},"ICON-1208":{"nm":"Pastanaga","de":"Una llança taronja que baixa recta dins la terra. Es pensava que només agradava als conills, però al saltar-la desperta una dolçor amagada, i dins la sopa hi afegeix també el color. El que deien els vells, que era bona per als ulls, tenien raó, en general."},"ICON-1209":{"nm":"Rave","de":"Amb una sola arrel blanca i feixuga, la taula d'hivern queda ben proveïda. Glaçat com a dongchimi, refrescant en sopa de rave, cruixent com a kkakdugi. No es llença res: fins i tot les fulles verdes s'assequen sota el ràfec i es guarden com a siraegi; una hortalissa estalviadora."},"ICON-1210":{"nm":"Ceba","de":"Peleu-la i una llàgrima cau rodolant. La carn picant i coenta es torna dolça com una mentida en tocar l'oli calent. El seu nom s'escriu a la primera línia de gairebé tots els plats coreans: la protagonista callada que estén, en silenci, la base de tot el gust."},"ICON-1211":{"nm":"Ceballot","de":"Escampeu la base blanca tallada fina i les fulles verdes per damunt del brou, i només aleshores el bol sembla de debò acabat. Si claveu la base que sobra en un got d'aigua torna a créixer de seguida: un petit hort de finestra per a qui té cura de la llar."},"ICON-1212":{"nm":"All","de":"Sis grans s'agrupen en cercle i formen un cap. L'arrel picant que, diuen, va convertir una óssa en dona. Picada amb el dors del ganivet, l'aroma esclata a l'instant; sense un grapat d'all, ni el kimchi ni el guisat tenen cap sentit."},"ICON-1213":{"nm":"Gingebre","de":"Una arrel petita i nuosa, com un embolic de nusos. Amb una sola llesca ja calma l'olor de peix i escalfa des de dins un cos refredat. Les nits que gemegàveu amb febre, aquella tassa calenta infusionada amb mel començava amb aquest picant lleuger."},"ICON-1214":{"nm":"Col xinesa","de":"Saleu les fulles ben atapeïdes i només llavors s'obre el primer capítol del kimchi. A la tardor tardana s'amuntegava com muntanyes a cada pati. Que tota la família s'assegués en rotllana per preparar-ne una tina era una promesa: passar juntes el llarg hivern."},"ICON-1215":{"nm":"Col","de":"Peleu les fulles arrodonides i superposades una a una i sembla que no s'acabin mai, així que el cor, sense adonar-vos-en, s'afluixa i s'assossega. Escaldada, és tendra; saltada, dolça. Sota una aparença tosca, aquesta hortalissa amaga una tendresa inesperada."},"ICON-1216":{"nm":"Enciam","de":"Poseu un tros de carn sobre la fulla còncava, hi afegiu un toc de ssamjang i us ompliu la boca d'un mos. En una rotllana on tothom embolica i menja, qualsevol deixa caure, sense adonar-se'n, les formalitats: això no és sinó l'hospitalitat del verd."},"ICON-1217":{"nm":"Enciam de fulla","de":"La primera fulla que apunta en un racó de l'hort. Per molt que se n'arrenqui, en torna a créixer, i omple la taula tot l'estiu. Aquella olor fresca i herbàcia, esbandida amb aigua freda i embolicada amb les mans, és per a algú tot sencer el gust de casa."},"ICON-1218":{"nm":"Espinacs","de":"Aquell verd de dibuixos animats que donava una força de sobte en buidar la llauna. Escaldat es redueix a un grapat, però l'aroma i l'energia hi resten intactes. Bo amanit a mà o desfet en sopa de soja: una hortalissa que mai s'ha de menysprear només perquè és comuna."},"ICON-1219":{"nm":"Falguera","de":"Es trenquen els brots tendres que la muntanya de primavera ofereix, i es bullen i s'asseca. Només després de tant esforç arriba, per fi, a la taula dels avantpassats i al bibimbap. Impregnada de dedicació en cada capa, tanta com la feina que costa, és una herba preciosa que la muntanya ha criat durant tota una estació."},"ICON-1220":{"nm":"Herbes silvestres","de":"Semblen sense nom, però cadascuna porta una olor pròpia: un regal de la primavera. Les mans de l'àvia reconeixen d'un sol cop d'ull, pel camí de muntanya, quina fulla es pot menjar. En un cistell d'herbes, tota una estació hi ve amb ella, amb aroma i tot."},"ICON-1221":{"nm":"Artemisa","de":"L'herba amarga i aromàtica alhora, la primera a foradar la terra gelada. Feta pastís, la llum de la primavera entra directament a la boca. Al primer mes de l'any es creia que bullir-la en sopa allunyava la mala sort de tot l'any, així que la primavera sempre arribava amb aquesta olor."},"ICON-1222":{"nm":"Fulla de perilla","de":"Una sola fulla n'hi ha prou per tenyir la boca sencera amb la seva olor intensa. Acompanyant panxa de porc daurada, o marinada capa a capa amb salsa de soja, un bol d'arròs desapareix en un instant. Aquesta aroma tan singular només és entranyable a la taula d'aquesta terra."},"ICON-1223":{"nm":"Pebrot verd","de":"Un fruit verd, buit per dins, que es trenca amb un cruixit. Un lleuger regust amarg desperta una gana adormida, i saltat amb oli el color es fa encara més viu. Només tallant-lo fi i escampant-lo, qualsevol plat es refresca a l'instant."},"ICON-1224":{"nm":"Pebrot","de":"Vermell, groc, taronja: colors com un semàfor omplint tota una cistella. Mossegat cru, en raja un suc dolç, i només el color ja il·lumina la taula. La dita que una hortalissa que fa goig també desperta la gana s'ajusta aquí a la perfecció."},"ICON-1225":{"nm":"Tomàquet","de":"El vermell rodó que sempre s'ha discutit si és fruita o hortalissa. Cuit a foc lent, el gust s'aprofundeix; cru, no hi ha res més fresc. És el fruit que recull amb més honestedat el sol de ple estiu, així que un sol mos fa esclatar tot un migdia."},"ICON-1226":{"nm":"Cogombre","de":"El verd que refresca millor que ningú la calor de l'estiu. Fent-lo surar en sopa freda, la boca es glaça; en conserva com a sobagi, el cruixent reviu. Els dies de xafogor, també va bé tallar-lo fi i posar-se'l sobre els ulls: una hortalissa fresca per dins i per fora."},"ICON-1227":{"nm":"Carbassa","de":"Penjada rodona a l'extrem de la lliana, es va omplint lentament de dolçor fins ben entrada la tardor. Cuita a foc lent es converteix en unes farinetes grogues que assossegen l'estómac; fregida, en una crep daurada. Penjada sota el ràfec, fa de rebost fiable durant tot l'hivern."},"ICON-1228":{"nm":"Carbassó","de":"El verd clar que engreixa dia rere dia a l'hort d'estiu. Tallat a daus en el guisat de soja, daurat en forma de crep: tan tou que és suau fins i tot per a la boca d'un infant petit. Comú, i per això mateix més agraït: un habitual de la taula de ple estiu."},"ICON-1229":{"nm":"Albergínia","de":"Un fruit allargat cobert d'una lluïssor porpra. Beu oli i es torna infinitament tou; cuit al vapor a fons, la seva textura es fa fina com la seda. Encara que sembli discret, s'avé bé amb qualsevol cosa: el segon actor entranyable de la taula."},"ICON-1230":{"nm":"Blat de moro","de":"Grans grocs alineats un rere l'altre, ben endreçats. Un mos d'estiu cuit al vapor, bufat i mossegat, i alhora el senyal benvingut que els camps ja han madurat. Dins aquell floc de fils suaus, la dolçor hi és present de dalt a baix."},"ICON-1231":{"nm":"Soja","de":"Uns grans petits i durs beuen aigua tota la nit i s'inflen. Mòlta fina esdevé llet de soja; fermentada esdevé jang: la major part de la proteïna d'aquesta taula va començar aquí. Enterreu-ne un gra a la terra i torna a ser una planta sencera."},"ICON-1232":{"nm":"Tofu","de":"Quan la soja beu aigua, es mol i quaja, es converteix en un bloc blanc de cantells rectes. Suau i discret, mai no imposa el seu color en cap sopa. Es desfà tendrament amb el simple contacte de la cullera: un aliment la virtut del qual és la senzillesa mateixa."},"ICON-1233":{"nm":"Mongeta vermella","de":"Bulliu bé els petits grans vermells i en surt, ben concentrada, una dolçor vermell fosc. La nit més llarga de l'any, un bol calent de gachas de mongeta vermella allunyava alhora el fred i els mals esperits; aquell sentiment encara hi viu. En les capes del pastís al vapor, aquell vermell no era res més que devoció."},"ICON-1234":{"nm":"Pasta de mongeta vermella","de":"Un farciment tou fet de mongeta vermella bullida, esclafada fina i reduïda una vegada i una altra. Una cullerada entre pa, dins d'un pastís d'arròs, sobre gel raspat: un sol fil de dolçor escalfa fins i tot els records més antics. Tot aquell temps llarg de colar i reduir esdevé, ell mateix, la dolçor."},"ICON-1235":{"nm":"Bolet","de":"Després de la pluja, treu el cap sense fer soroll a l'ombra fosca del bosc. És l'ofici de la terra: fer créixer la seva pròpia olor sense ni un raig de sol. Amb només un grapat a la sopa, en surt un gust profund i saborós sense necessitat de carn: un secret que el bosc guarda amagat."},"ICON-1236":{"nm":"Bolet shiitake","de":"Un paraigua marró completament obert. Ben eixugat al sol, l'aroma es fa moltes vegades més intensa, i un sol bolet sec pot fer-se càrrec, sense esforç, d'una olla sencera de brou. Un pilar sòlid de la taula vegetariana, i un habitual de sempre per a qui coneix el gust profund."},"ICON-1237":{"nm":"Bolet de pi","de":"Al cor d'un pinar de tardor, aixeca el cap discretament només al costat dels pins. No es pot cultivar i s'ha de trobar caminant, i per això la seva olor és encara més preciosa. Torrat lleugerament i sucat només amb un pessic de sal, tot un tros de bosc entra a la boca."},"ICON-1238":{"nm":"Bolet rei","de":"Estireu el peu gruixut seguint la veta i la textura xicladissa us queda a la mà. Creix ferm en totes les estacions, i mai no s'allunya de la taula. A la graella o saltat: dins aquella carn generosa hi ha una fermesa sense pes que ho omple tot."},"ICON-1239":{"nm":"Maduixa","de":"A l'extrem d'un hivernacle que ha resistit l'hivern, és la primera a madurar de vermell. Un mos i és agredolça, com la primera salutació de la primavera primerenca. Poseu-ne una de rodona sobre un pastís i fins i tot un dia qualsevol es converteix en un aniversari."},"ICON-1240":{"nm":"Nabiu","de":"Fa un petit esclat i una acidesa lluminosa s'escampa per tota la boca. Agafeu les petites boles porpres una a una i, sense adonar-vos-en, el pot ja és buit; escampades sobre llet blanca, s'hi desplega tot un petit cel nocturn."},"ICON-1241":{"nm":"Poma","de":"Un mos, un crec, i la tardor es fa a trossos. Aquell vermell que l'àvia de l'hort netejava amb un drap i us donava és un color que només s'aconsegueix guardant molt de temps el sol. Com més ferma, més sap mantenir-se dolça fins a l'última mossegada."},"ICON-1242":{"nm":"Pera","de":"Peleu-la i les puntes dels dits es refreden primer que res. Al capdavant de la taula de Chuseok, en el moment que el suc dolç i glaçat us omple la boca, una mica de la brisa nocturna de tardor ve i s'asseu discretament al costat vostre."},"ICON-1243":{"nm":"Préssec","de":"En cada lloc on ha caigut una flor de préssec, hi neix un estiu tou i pelut. Premeu-la lleugerament i primer s'escampa l'aroma; en el moment que hi mossegueu, tota l'estació us segueix dins la boca."},"ICON-1244":{"nm":"Raïm","de":"Grans porpres pengen en un sol raïm, recolzant-se espatlla contra espatlla. En esclatar, l'acidesa arriba primer i la dolçor mig compàs després: com un cor endreçat que canta l'estiu que s'acaba."},"ICON-1245":{"nm":"Raïm blanc","de":"El verd clar deixa passar la llum del sol tal com és, i cada gra s'encén com un llum. Sense pinyol, net i refrescant, és una dolçor sense cap excés, com la primera frase acabada de treure."},"ICON-1246":{"nm":"Llimona","de":"Rasqueu la pell groga amb l'ungla i l'aroma esclata, despertant la punta del nas. Una sola gota fa arrufar els llavis tot sol, però al final d'aquesta acidesa hi ha, estranyament, un racó que il·lumina tot el dia."},"ICON-1247":{"nm":"Llima","de":"Més petita i d'un verd més intens que la llimona, aquesta fruita saluda primer amb la seva olor punxant. Una sola llesca desperta a l'instant fins i tot l'aigua tèbia: un grapat de frescor, petit però decidit."},"ICON-1248":{"nm":"Taronja","de":"En el moment de pelar-la, l'olor del sol s'enganxa als dits. Poseu cada grill a la boca i esclaten, un rere l'altre, petits globus de suc dolç: allò rodó fa rodar fins i tot l'estat d'ànim."},"ICON-1249":{"nm":"Mandarina","de":"Recordeu aquell gust, pelant-les amb els peus ficats sota el cobrellit calent a l'hivern? L'aroma que s'escampava per sota les ungles tenyia de groc tota l'habitació. Una bossa n'hi ha prou perquè la família s'assegui en rotllana."},"ICON-1250":{"nm":"Plàtan","de":"Hi va haver dies que un àpat es va resoldre amb una peça groga que va rodolar fora de la bossa, en un racó de la sala d'assaig, a l'alba, mort de gana. Tova, dolça i que omple: el pedaç més tendre de tots."},"ICON-1251":{"nm":"Pinya","de":"Cal travessar una pell coberta d'espines abans que aparegui la carn groga. Mossegueu-ne un tros i l'agredolç pica a la llengua, mentre l'olor d'un mar del sud roman als llavis sense adonar-vos-en."},"ICON-1252":{"nm":"Mango","de":"Obriu la polpa madura amb les mans i una olor dolça i enganxosa us mulla els dits. Quan el groc intens es fon i desapareix a la boca, hi passa un somni dolç, com una breu migdiada d'estiu."},"ICON-1253":{"nm":"Coco","de":"Sacsegeu la closca dura i se sent, a dins, el xipolleig de l'aigua. Trenqueu-la i hi trobareu polpa blanca i suc fresc: un petit gerro que conté, sencer, un mar llunyà que oscil·la a dins."},"ICON-1254":{"nm":"Pitaia","de":"El seu aspecte, cobert d'escates roses, fa dubtar al primer moment, però en partir-la, el blanc de dins és puntejat de llavors petites. De gust discret i vestit vistós: un murri l'exterior del qual és exactament el contrari de l'interior."},"ICON-1255":{"nm":"Kiwi","de":"Talleu per la meitat aquell marró cobert de pèl fi i apareix una joia verda. Preneu amb la cullera una tallada on les llavors negres estan clavades com estrelles, i una cullerada àcida us sacseja i desperta de la son."},"ICON-1256":{"nm":"Pollastre","de":"Poseu-la a la paella untada d'oli i primer cou el xiuxiueig daurat. Suau i tendra, s'asseu sense problemes a la taula de qualsevol: l'habitual d'un àpat tranquil."},"ICON-1257":{"nm":"Porc","de":"A la graella grinyola, el greix esquitxa i es va daurant. En aquelles nits de sopar d'empresa, embolicant-la amb una fulla d'enciam i un toc de ssamjang i omplint-se la boca, la seva riquesa saborosa escalfava tota la taula."},"ICON-1258":{"nm":"Vedella","de":"En cada veta vermella, el greix hi és marmoritzat finament i brilla. Poseu-la sobre una pedra calenta i primer és l'aroma qui omple l'espai; en el moment que un tros entra a la boca, el cansament del dia s'afluixa discretament."},"ICON-1259":{"nm":"Cansalada","de":"A la paella del matí es fa cruixent, el greix balla. Amb aquella olor salada n'hi ha prou perquè fins i tot qui dormia fins tard es fregui els ulls i vingui cap a la cuina: un àpat que crida primer amb l'olfacte."},"ICON-1260":{"nm":"Salsitxa","de":"Els talls s'obren de bat a bat i el suc de la carn esclata. La forma de pop vermell que ocupava un racó de la carmanyola era un petit luxe que gaudien les hores de dinar de la infància."},"ICON-1261":{"nm":"Pepperoni","de":"Una rodanxa rodona i picant s'arruga per les vores damunt del formatge calent. Quan hi queda un bassalet d'oli, aquest és el punt culminant de tota la pizza: petita, però amb una presència rodona i intensa."},"ICON-1262":{"nm":"Hamburguesa","de":"Modelada gruixuda i posada a la graella, es va enrossint des de les vores cap endins. Enganxeu-hi hortalisses entre el disc premsat i torrat, i queda completa una consistència que cap perfectament en una mà."},"ICON-1263":{"nm":"Ou","de":"Trenqueu-lo i el rovell llisca com un petit sol rodó. Igual de bé si es barreja amb arròs acabat de fer que si esdevé la línia groga dins d'un gimbap: la proteïna més comuna i, per això, la més entranyable."},"ICON-1264":{"nm":"Llet","de":"Una ampolla freda deixada a la porta a l'alba: el dia sovint s'obria amb aquella frescor a la palma de la mà. Fumeja en escalfar-se, és saborosa en refredar-se: un blanc que sempre queda al costat, a qualsevol hora."},"ICON-1265":{"nm":"Formatge","de":"Una llesca groga es va desfent lentament sobre el pa calent. El cor que espera aquell instant en què s'estira i s'estira: com més es fon, més profunda i intensa es fa la seva riquesa saborosa."},"ICON-1266":{"nm":"Formatge cheddar","de":"El seu taronja intens ja anuncia, d'una sola ullada, un gust salat. Tallat fi i posat dins una torrada, el gust saborós s'escampa per tota la boca: tan clar de color com de sabor."},"ICON-1267":{"nm":"Mantega","de":"Deixeu caure un tros a la paella calenta i es fon suaument, alçant un vapor saborós. Untada al pa, barrejada amb l'arròs: una màgia groga que fa una mica més tou tot allò que toca."},"ICON-1268":{"nm":"Nata muntada","de":"Com més batem, més el blanc líquid s'infla fins a esdevenir núvols ferms. En el moment que se n'afegeix una cullerada sobre un pastís, una tarda qualsevol s'il·lumina com un petit aniversari."},"ICON-1269":{"nm":"Iogurt","de":"Enfonseu-hi la cullera i el blanc àcid s'alça suaument. Barregeu-hi un tros de fruita i el matí es fa més lleuger; un got n'hi ha prou perquè l'estómac s'assossegui: el gust d'un començament suau."},"ICON-1270":{"nm":"Verat","de":"Posat a la graella, el greix esquitxa i un fum entre marí i saborós omple la cuina. Aquelles mans que en treien les espines i el posaven sobre l'arròs: la devoció més profunda dins una taula quotidiana."},"ICON-1271":{"nm":"Salmó","de":"Vetes rosades jeuen apilades una sobre l'altra. Servit fred, es desfà tou a la boca; a la graella, el greix hi amara i el fa saborós: un gust ferm que ha nedat contracorrent des d'un mar llunyà."},"ICON-1272":{"nm":"Tonyina","de":"Obriu la llauna i una olor salada puja de sobte. Hi va haver un temps en què, a les nits d'un pis de lloguer, una sola llauna barrejada amb arròs o embolicada en alga es convertia en un àpat consistent."},"ICON-1273":{"nm":"Bacallà","de":"La seva carn clara és tan suau que, en bullir-la, el brou surt refrescant des del primer moment. Un peix blanc que ha resistit el vent tallant d'un port d'hivern: un bol calent de sopa i fins i tot les mans glaçades es desfan a poc a poc."},"ICON-1274":{"nm":"Gamba","de":"Corba l'esquena i, en coure's, el gris es tenyeix de rosat. Un esclat de fermesa i una olor saborosa: peleu-les i mengeu-les una a una, i sense adonar-vos-en el plat ja és buit."},"ICON-1275":{"nm":"Cranc","de":"Treure la carn blanca de la closca dura és un petit exercici de paciència. El tros que us poseu a la boca al final d'aquest esforç és dolç: tot un mar de tardor entra sencer a la boca."},"ICON-1276":{"nm":"Calamar","de":"A la graella s'arrissa en cercles, alçant una olor saborosa. Un tros que es mastega xicladís, sucat en salsa de xili i posat a la boca, i el mar salat el segueix."},"ICON-1277":{"nm":"Cloïssa","de":"Dins el brou clar, obren la boca i cedeixen discretament el seu perfum. Amb el bull xerricant s'escampa l'olor del mar, i una xuclada n'hi ha prou perquè un estómac glaçat s'escalfi i s'afluixi."},"ICON-1278":{"nm":"Pastís de peix","de":"Submergit amb tot i broqueta en un brou calent, el vapor s'alça en volutes. Davant una parada del carrer en un dia fred, aquelles mans rebent el brou en un got de paper i bufant-hi: un petit consol que ofereix el carreró."},"ICON-1279":{"nm":"Kimchi","de":"Madura lentament dins la gerra, fent créixer una olor àcida i profunda. Només cal esquinçar-lo amb les mans i posar-lo sobre arròs acabat de fer; el gust, diferent a cada casa, és la mateixa història d'aquella llar."},"ICON-1280":{"nm":"Rave encurtit","de":"Un tros groc es trenca amb un cruixit alegre a la boca. El company inseparable que acompanya un rotllo de gimbap o un plat de menjar de carrer: el seu agredolç esbandeix i refresca una boca greixosa."},"ICON-1281":{"nm":"Cogombres en vinagre","de":"El cogombre conté la respiració un instant en la sal i després obre els ulls dins el vinagre. Per no perdre el moment en què torna el cruixent, el pot de vidre no es mou mai de l'ampit assolellat. El temps que passa marinant a poc a poc és el que porta el gust."},"ICON-1282":{"nm":"Gochujang","de":"Un vermell que ha resistit tot un any dins la gerra. Darrere el picant s'hi amaga discretament la dolçor del soja, així que una sola cullerada fa que el guisat esdevingui, per fi, la cara pròpia de casa nostra. Una profunditat que les gerres de jang del pati han criat amb el sol."},"ICON-1283":{"nm":"Doenjang","de":"El bloc de meju va abraçar el floridura i va passar tot un hivern. La seva sapidesa és un equilibri arriscat entre el punt just i l'excés de maduració: l'àvia coneixia aquella línia amb una sola olorada als dits. Un gust que s'aprofundeix tant com s'espera."},"ICON-1284":{"nm":"Salsa de soja","de":"Com més negre es torna el soja, més profund es fa el seu interior. Una sola gota revifa una amanida d'herbes i dona brillantor a un guisat, així que tots els colors de la cuina comencen, al final, en aquest marró càlid. Un gust saborós més enllà del salat."},"ICON-1285":{"nm":"Pasta de mongeta negra","de":"Encara que sigui el mateix negre, la textura és diferent. Un regust agredolç, fregit un cop més amb caramel; barrejat amb els fideus, aquella lluïssor negra sacseja i desperta la gana. El primer botó que engega el gust del foc xinès."},"ICON-1286":{"nm":"Pols de curri","de":"Una pols groga on diverses espècies s'entenen en pau dins una sola cullerada. Dissolta en aigua, bull xerricant i escalfa tota la casa: es converteix en el tràiler del bol més reconfortant d'un vespre de pluja."},"ICON-1287":{"nm":"Pebre","de":"Només mòlt sencer conserva l'aroma; mòlt amb antelació, l'aroma fuig discretament. L'última volta de molinet es dona sempre just abans d'apagar el foc: un petit punt final que la mà que cuina posa amb mesura."},"ICON-1288":{"nm":"Pebre vermell picant en pols","de":"Els pebrots assecats al sol de tardor completen, per fi, el seu vermell. Segons si es mol fi o gruixut, el caràcter del kimchi canvia, així que el toc personal d'un cuiner ve, al final, de triar la mida d'aquesta pols."},"ICON-1289":{"nm":"Sal","de":"Assaonar és apropar-se, pessic a pessic, cap al costat que en falta. El salat, un cop hi és, no es pot desfer, així que una mà experta sempre en posa una mica menys al final i tasta. Allò que es reté és el marge de respirar."},"ICON-1290":{"nm":"Sucre","de":"Calma l'amarg i arrodoneix les arestes de l'àcid. Però la dolçor no s'ha de deixar descobrir mai, així que com millor és un adob, més discretament el sucre desapareix al final. Una dolçor que sap amagar-se."},"ICON-1291":{"nm":"Mel","de":"Un pot que les abelles van recollir anant i venint milers de vegades pel camp de flors. Si es solidifica, es reviu al bany maria amb aigua calenta; dissolt en te, embolcalla suaument la gola. Una cullerada daurada on tota una estació sencera ha quedat reduïda."},"ICON-1292":{"nm":"Oli de cuina","de":"Fem-ne una volta a la paella calenta i els ingredients obliden que s'hi poden enganxar. Massa aviat es crema, massa tard s'enganxa, així que el compàs just quan el fum comença a alçar-se és la regla d'or de fregir. El moment es mesura pel so."},"ICON-1293":{"nm":"Oli d'oliva","de":"En el verd del primer premsat hi conviuen una olor d'herba i un lleuger picant. Cal afegir-lo al final més que no pas posar-lo al foc perquè aquella aroma sobrevisqui fins al final; deixar-lo cru és el seu ús més honest."},"ICON-1294":{"nm":"Oli de sèsam","de":"Deixeu-ne caure una sola gota al final i les herbes amanides declaren, per fi, la seva finalització. La seva riquesa saborosa és de mena que s'escapa fàcilment sobre el foc, així que sempre és el punt final que s'afegeix discretament un cop acabada tota la cocció."},"ICON-1295":{"nm":"Beina de vainilla","de":"Obriu una beina i en raspeu les llavors negres, i el postre canvia de vestit amb l'aroma. No llençar mai ni la closca ja gastada, sinó enterrar-la en sucre: un vell estalvi que els pastissers han heretat."},"ICON-1296":{"nm":"Cacau","de":"Polpa blanca i llavors amargues dins el fruit. Només després de la fermentació i l'assecat al sol es tradueixen en la dolçor que coneixem. Abans de convertir-se en xocolata, porta la seva primera cara, la més propera al salvatge."},"ICON-1297":{"nm":"Xocolata","de":"Una naturalesa exigent que es fon només amb l'escalfor de la palma de la mà. Cal deixar-la solidificar a prop dels 28 graus perquè visqui aquell trencament net i brillant, així que darrere la dolçor s'hi amaga, sorprenentment, una regla de temperatura força maniàtica."},"ICON-1298":{"nm":"Gra de cafè","de":"Abans de moldre's, un gra és gairebé un silenci dur. Però en trobar-se amb l'aigua calenta s'infla i vessa la seva aroma, així que el primer senyal que desperta el matí comença sempre en aquest petit gra."},"ICON-1299":{"nm":"Fulles de te","de":"Si es queda massa temps en aigua calenta es fa aspre; si és massa poc, resulta insípid. Calcular en silenci el temps que triguen les fulles a obrir-se a poc a poc: infusionar te és mesurar l'espera amb la punta dels dits."},"ICON-1300":{"nm":"Menta","de":"Esclafada, en surt un gust amarg, així que és una fulla tendra que sempre cal tractar amb cura. Colpegeu-la lleugerament per despertar l'aroma adormida i, en un dia xafogós, feu-la surar en un got: el ple estiu s'assossega un to més fresc."},"ICON-1301":{"nm":"Herbes","de":"Si les afegeixes amb tija i tot, l'aroma és profunda; si només fas servir les fulles, és neta i clara. Assecades es tornen més intenses, fresques queden lleugeres, i tot l'ampli ventall d'olors que amaga un sol manat fa créixer, alhora, l'expressió de la cuina."},"ICON-1302":{"nm":"Castanya","de":"Dins la closca punxeguda s'amaga una polpa brillant. Si li fas un tall i la torres, s'obre amb un espetec i escampa una olor dolça, tant que sembla que puguis tocar amb la mà l'escalfor d'un cucurutxo de castanyes torrades en un carreró de vent fred."},"ICON-1303":{"nm":"Cacauet","de":"El seu gust torrat es completa al foc que el rosteix. És un gra petit que, pelat un a un, et fa perdre la noció del temps; si te'l comparteixes assegut en rotllana al terra de fusta, també les converses es van pelant, xerrada rere xerrada."},"ICON-1304":{"nm":"Ametlla","de":"Escaldada lleugerament i pelada, la seva carn queda més blanca i tendra. Triturada i mòlta esdevé com la llet, torrada sencera es fa cruixent: l'ampli ventall de transformacions que amaga un sol gra eixampla al màxim la imaginació del pastisser."},"ICON-1305":{"nm":"Sèsam","de":"Si el remous suaument a foc baix, en un moment comença a saltar amb petits espetecs. L'instant just abans que aquest so s'aturi és quan té el millor gust torrat: torrar sèsam acaba sent, al capdavall, una feina que es fa amb l'orella."},"ICON-1306":{"nm":"Canya de sucre","de":"Mastega un nus i en brollarà un suc dolç barrejat amb olor d'herba. És una tija que cal reduir i tornar a reduir per convertir-se en la dolçor que coneixem: l'origen del sucre és, sorprenentment, així de verd i així d'alt."},"ICON-1307":{"nm":"Sucre integral","de":"Una dolçor tosca que conserva el seu color propi per haver passat per menys refinatge. Hi resta, tènue, una profunditat terrosa, i per això les mans que estimen l'honestedat d'una cosa abans de ser polida la busquen expressament."},"ICON-1308":{"nm":"Grans de cacau","de":"Les llavors just tretes de la beina són amargues i astringents. L'aroma només floreix després de suportar en silenci uns quants dies de fermentació, així que la dolçor és el petit premi que aquest gra rep després d'una llarga paciència."},"ICON-1309":{"nm":"Nibs de cacau","de":"En els bocins triturats del gra torrat no hi ha ni un gra de sucre. A la boca arriba primer l'amargor i després, tard, el gust torrat, de manera que hi trobes el cacau abans de la dolçor, de la manera més honesta."},"ICON-1310":{"nm":"Cafè en verd","de":"Petits grans verds que encara fan olor de cru. Tal com són, l'aroma hi dorm profundament, i fins que no rebin el baptisme del foc resten quiets, com una possibilitat que encara no sap què arribarà a ser."},"ICON-1311":{"nm":"Cafè torrat","de":"A la superfície bruna, on ha suat un rastre d'oli, l'aroma s'hi ha acumulat sencera. Cal moldre'l abans que es refredi perquè aquesta olor quedi intacta, de manera que el destí d'una tassa es decideix, en silenci, pocs dies després de torrar-lo."},"ICON-1312":{"nm":"Vainilla en tija","de":"Una sola tija d'aroma tenyeix per complet tota una olla de llet. Fins i tot la beina ja esprémuda, si la claves en un pot de sucre, al cap d'uns dies n'aromatitza tot el contingut: és un luxe sense cap part que es pugui llençar."},"ICON-1313":{"nm":"Pebre","de":"L'aroma d'un gra de pebre negre comença a minvar des del moment en què el mols. Per això es deixa sencer sobre la taula i es tritura al moment: la frescor floreix d'un cor que no deixa les coses per després."},"ICON-1314":{"nm":"Pebre blanc","de":"El gra, més llis un cop pelat, és discret més que no pas picant. Va néixer de la delicadesa de no voler deixar ni un sol punt negre en una salsa blanca: és la subtilesa d'un lloc que no es veu."},"ICON-1315":{"nm":"Canyella","de":"Si n'infusiones un tros, una calidesa lleugerament picant s'escampa a poc a poc per la infusió. L'aroma dura més si s'afegeix sencera que no pas mòlta, de manera que la profunditat d'una beguda d'hivern ve de la perseverança d'aquesta escorça seca."},"ICON-1316":{"nm":"Clau d'espècia","de":"En un sol capoll de flor amb forma de clauet petit s'hi concentra tota l'aroma. Si n'hi poses massa, s'empassa el plat sencer, així que la mesura d'un únic clau manté, en silenci, l'equilibri del sabor."},"ICON-1317":{"nm":"Nou moscada","de":"La llavor es guarda sencera i se'n ratlla un pessic just en el moment de fer-la servir. Té la natura de perdre l'aroma de seguida si es mol amb antelació, de manera que aquell darrer tret ràpid de ratlladura fa encara més profunda l'olor de la llet."},"ICON-1318":{"nm":"Cardamom","de":"Trenca la beina verda amb un lleuger espetec i en brollarà una aroma fresca i intensa. N'hi ha prou d'esclafar-ne un o dos grans dins la infusió perquè una tassa qualsevol adquireixi, de sobte, la fragància d'un país llunyà."},"ICON-1319":{"nm":"Safrà","de":"Fils vermells dels quals amb prou feines se'n recullen tres de cada flor. Dissolts en aigua calenta, una llum groga s'hi escampa lentament, de manera que la seva raresa és també el pes del temps esmerçat a triar-los un a un, a mà."},"ICON-1320":{"nm":"Cúrcuma","de":"Mol l'arrel arrencada de la terra i et tenyirà de groc fins a la punta dels dits. Té la natura que l'aroma només desperta si es sofregeix lleugerament amb oli, de manera que el color daurat del curri és el que aquesta petita arrel ha fet florir sobre el foc."},"ICON-1321":{"nm":"Fulla de llorer","de":"La fulla que, diuen, coronava el front del vencedor. Si en fas flotar una a l'aigua bullent, entre el vapor s'hi alça un instant el clam d'una antiga arena. Fins i tot en els dies en què no has guanyat, respirar-ne l'aroma esdevé un consol verd que t'abraça, en silenci, tal com ets avui."},"ICON-1322":{"nm":"Llet de coco","de":"Un suc blanc que només raja quan es trenca la closca dura. En un racó del mercat d'un país càlid, clava-hi una palla i fes-ne un glop, i la set del migdia es refreda del tot. La dolçor fresca que s'escampa per tota la boca porta amb ella l'ombra dels tròpics."},"ICON-1323":{"nm":"Oli de coco","de":"Sòlid, és blanc com la primera neu; escalfat al palmell, l'aroma s'hi escampa suaument. En aquest pot rodó hi reposa intacta la tendra saviesa domèstica d'una àvia illenca, que el donava tot dient que un sol pot bastava de cap a peus."},"ICON-1324":{"nm":"Plàtan assecat","de":"Estesa uns quants dies al sol, la polpa groga es torna enganxosa i sucosa. Si te la vas mastegant tros a tros amb mesura, aquella olor dolça i enganxosa de la temporada de collita plujosa reviu suaument a la boca. Una dolçor madurada a poc a poc guarda així tota una estació."},"ICON-1325":{"nm":"Mango assecat","de":"La polpa tendra, concentrada sota el sol, ha renascut com una gelatina color ambre. Àcid, dolç i gomós, els tres gustos hi són tots junts en un sol tros, i si el fas rodar a poc a poc dins la boca, una sola bossa allarga la tarda."},"ICON-1326":{"nm":"Pinya assecada","de":"A diferència del seu aspecte punxegut per fora, la polpa de dins és tan groga i lluminosa com pot ser-ho. Assecada al sol, l'acidesa s'hi concentra, de manera que amb un sol mos les comissures dels llavis se t'aixequen soles. El regust fresc que queda al final d'un tros hi perdura molta estona."},"ICON-1327":{"nm":"Cistella de fruites tropicals","de":"Colors acabats de collir es fonen tots en una sola cistella. El taronja del mango, el groc del plàtan, el daurat de la pinya: abans fins i tot d'allargar la mà per triar, l'estiu ja arriba primer per la punta del nas. Una braçada que il·lumina el cor només de mirar-la."},"ICON-1328":{"nm":"Farcell d'algues","de":"Els cabells del mar, collits a les roques nues per la marea baixa. En la seva olor salabrosa hi ha enredat el so de les onades, i si es deixen remullar tranquil·lament en aigua freda, una olor de mar lleugerament peixosa avança a poc a poc fins a la cuina. Un grapat n'estén un petit fangar a taula."},"ICON-1329":{"nm":"Peix i marisc assecats","de":"Un grapat de mar assecat fins a fer-se dur i correós. Estripa'l a mà seguint la fibra i, juntament amb la sal, s'hi allibera el vent salabrós d'un port antic. Un vell amic al costat de la taula càlida i familiar, que et fa pensar de seguida en un bol de makgeolli."},"ICON-1330":{"nm":"Calamar assecat","de":"Amb els deu braços estesos ben endreçats, s'ha assecat al sol. Es torra lleugerament al foc fins que puja l'olor torrada, i llavors es va estripant seguint la fibra. Amb aquest gust gomós de mastegar, un plat de sopar de mitjanit puja un graó en distinció."},"ICON-1331":{"nm":"Peix salat","de":"Sepultat en sal grossa, el peix aprèn a resistir el pas del temps. N'hi ha prou d'un tros de carn profundament salada perquè un bol d'arròs es buidi en un instant: és el tendre secret que una àvia de vora mar transmetia amb la punta dels seus dits."},"ICON-1332":{"nm":"Gambetes salades","de":"Petites gambes maduren lentament dins la sal i renaixen com a saboria profunda. En el moment d'afegir-ne una cullerada al cor de la col en temporada de fer kimchi, aquella olor salabrosa s'escampava per tot el pati. Aquesta única cullerada decideix el gust del kimchi de tot un any."},"ICON-1333":{"nm":"Seitó assecat","de":"Un cos de la mida d'un dit es fa responsable de tota la profunditat d'una olla de brou. La cuina de la infància, on es xerrava fluixet mentre s'arrencaven caps i budells: un peix petit però agraït, plantat amb fermesa al bell mig de la llar."},"ICON-1334":{"nm":"Kombu","de":"Una cinta negra que ha crescut llarga al fons del mar. Posar-la en aigua freda i treure-la delicadament just abans que arrenqui el bull és una promesa que les mans que fan brou han guardat de generació en generació. La saboria profunda no s'apressa mai."},"ICON-1335":{"nm":"Hijiki","de":"La textura granellosa esclata amb petits espetecs a la boca. És l'alga que, a la primavera, tenyia de verd les roques de la costa; amanida amb un massatge suau de les mans, estén un petit mar fresc en un racó de la taula. És el gust de mastegar la primavera."},"ICON-1336":{"nm":"Ostra perlera","de":"Una llum rodona forjada de tant abraçar-la entre dues valves fermes. Fins a convertir la molèstia d'un sol gra de sorra en una joia, el mar no va apressar-se mai. Posa-la al palmell i el pes d'aquella llarga paciència hi reposa també."},"ICON-1337":{"nm":"Ornament de corall","de":"La branca d'arbre del mar, polida per les onades durant centenars d'anys. Quan hi toca el sol, s'hi escampen roses i taronges, i només de deixar-la reposar en un prestatge, tota una habitació es tenyeix d'una illa càlida. Fins i tot la textura rugosa sota la punta dels dits resulta entranyable."},"ICON-1338":{"nm":"Botó de nacre","de":"Del lloc que ha deixat la carn del musclo, se n'ha retallat en rodona la cara interior, irisada. Cosit a la solapa, cada vegada que el corda, un petit arc de Sant Martí brilla a la punta dels dits. És l'últim regal tendre que el mar deixa en marxar, després d'haver-ho donat tot."},"ICON-1339":{"nm":"Bala de vidre","de":"Fes-la rodar al palmell i la llum atrapada a dins rodola amb ella. En aquells dies asseguts a la gatzoneta al carreró, jugant sense adonar-se que es feia fosc, la butxaca del nen que en guanyava una més era especialment pesant i orgullosa."},"ICON-1340":{"nm":"Talla de fusta d'enebre","de":"A cada veta tallada hi sua una aroma subtil. La gent d'abans cremava aquesta fusta per posar ordre en un cor esvalotat. Sostén-ne un tros en silenci i una calma s'omple lentament, començant per la punta dels dits."},"ICON-1341":{"nm":"Encens","de":"Una vareta prima crema a poc a poc i obre un camí cap amunt. Segueix amb els ulls la corba que dibuixa el fum i el cor que ha corregut tot el dia, sense adonar-se'n, afluixa el pas i s'atura, quiet, en aquell mateix lloc."},"ICON-1342":{"nm":"Flor per a tint","de":"Allibera el color amagat als pètals dins una olla bullint, i una tela clara es tenyeix a poc a poc d'aquell mateix to. Manllevar per un instant el color que la natura ja hi havia pintat: tenyir era, en el fons, una salutació tendra adreçada a les flors."},"ICON-1343":{"nm":"Tint d'indi","de":"Un blau profund i serè obtingut de fermentar i tornar a fermentar la planta d'indi. Cada vegada que se submergeix i s'aixeca la tela, aquesta passa lentament del color del cel al color del mar. És el color de l'espera, que només floreix quan es deixa de banda la impaciència."},"ICON-1344":{"nm":"Tint carmesí","de":"Infusiona l'arrel de rogeta i la posta de sol que dormia dins la terra desperta dins l'olla. Era el color més festiu i lluminós del poble, el que tenyia amb delicadesa la faldilla de la nova núvia el dia de les noces."},"ICON-1345":{"nm":"Fil d'or","de":"S'estira l'or més prim que un cabell i es fila fil a fil amb dedicació. A cada racó brodat hi conté llum, de manera que fins i tot en una cambra fosca amb el llum apagat, només aquell dibuix s'hi alça, suau i lluminós per si sol."},"ICON-1346":{"nm":"Seda","de":"El fil que escup el cuc de seda s'ha de teixir i teixir de nou fins a fer amb prou feines una peça. Un tacte que llisca com aigua de primavera sobre el revers de la mà: una tela de gra fi que la gent d'abans va abraçar durant tota una estació i va criar a poc a poc."},"ICON-1347":{"nm":"Botó de perla","de":"Se n'ha triat només la llum interior de la perla i s'ha polit en rodona. Cada vegada que se'n corda un a la solapa del jeogori, la punta dels dits esdevé, per un instant, elegant. Petit, però un gra polit que aixeca discretament la distinció d'un vestit."},"ICON-1348":{"nm":"Fragment de mapa nàutic","de":"Més enllà de la vora estripada, una costa desconeguda es talla en sec. Diuen que només qui aplega la resta de fragments arriba fins al tresor, però potser el propi viatge de vagar-lo a buscar seguint el vent ja era, ell mateix, el tresor."},"ICON-1349":{"nm":"Carta marina antiga","de":"Rutes escampades per l'aigua de mar i un dibuix de brúixola desdibuixat. Segueix amb la punta del dit la línia que algun mariner va traçar en una nit fosca guiant-se només per les estrelles, i una illa desapareguda fa temps torna a alçar-se, lentament, sobre el paper vell."},"ICON-1350":{"nm":"Missatge en una ampolla","de":"Dins una ampolla de vidre arrossegada per les onades, un sol full de paper enrotllat. Una salutació de la qual ningú sap qui la va enviar ni quan ha arribat, finalment, a la mà d'algú. Si té prou cor, fins i tot el mar es converteix en un carter tan lent com aquest."},"ICON-1351":{"nm":"Caixa a la deriva","de":"L'aventura dura fins al mateix instant de forçar la tapa, enravenada d'haver-se inflat amb l'aigua salada. Sigui tresor o simplement sorra buida el que hi hagi a dins, una caixa que ha arribat a la deriva de lluny sempre porta encallada, amb ella, la història d'algú de rostre desconegut."},"ICON-1352":{"nm":"Clau petita","de":"Un tros de metall vell que encaixa just al palmell de la mà. Encara que s'hagi oblidat del tot quina porta obre, hi resta, pesant, a la punta dels dits, un pes tendre que fa pensar abans en obrir que no pas en tancar."},"ICON-1353":{"nm":"Moneda de plata","de":"Una rodona de plata amb el dibuix esvaït pel tacte de tantes mans. Una moneda que un dia potser va ser el passatge d'algú o un jaç per a una nit esgotadora; passa-hi els dits per la superfície ara freda i la calidesa d'una antiga transacció reviu, difusa, a la punta dels dits."},"ICON-1354":{"nm":"Moneda d'or","de":"Posa-la al palmell i el primer que et commou és el seu pes feixuc. Una peça que brilla groga sota el sol, com si tenir-la et fes ric, però el que en realitat brilla més és el batec del cor just abans que et caigui a la mà."},"ICON-1355":{"nm":"Segell del capità","de":"La promesa del capità, premuda amb fermesa sobre lacre vermell. Amb un sol dibuix es dictava una ordre i es traçava una ruta perillosa. L'autoritat era, al final, un únic segell petit i sòlid que tots els qui anaven en el mateix vaixell havien acordat creure junts."},"ICON-1356":{"nm":"Micròfon de mà","de":"En el moment d'agafar-lo, un pes estranyament reconfortant t'omple el palmell. Tant quan fas una primera salutació tremolosa com quan finalment llances un agut, aquesta petita vareta li posa ales, amb suavitat, a la teva veu."},"ICON-1357":{"nm":"Micròfon sense fil","de":"En desaparèixer el cable, l'escenari sencer es va fer més ampli. Encara que corris fins al fons de la sala, la veu no s'interromp mai, com si algú et donés una empenta suau a l'esquena dient-te que corris i cantis tant com vulguis."},"ICON-1358":{"nm":"Micròfon de peu","de":"Ferm sobre els seus peus, espera en silenci el cantant. Quan les dues mans queden lliures, la cançó s'escampa per tot el cos en lloc de només per les puntes dels dits. Aquesta vareta diu, en silenci, que hi ha també un encant clar en el fet de mantenir un mateix lloc fins al final."},"ICON-1359":{"nm":"Filtre antipop","de":"Una sola capa de tela que tanca en rodona el davant del micròfon. Filtra amb suavitat els sospirs més forts i deixa passar només la veu clara. Fer que se senti bé vol dir protegir, en silenci, des d'un lloc que roman invisible fins al final."},"ICON-1360":{"nm":"In-ear","de":"Just dins l'orella, la teva pròpia cançó torna a sonar clara més enllà del clam de desenes de milers de veus. És el company més petit i secret, el que et manté sense perdre el ritme sobre un escenari inundat de llum i so."},"ICON-1361":{"nm":"Auriculars","de":"En el moment de tapar-te les orelles, el món s'encongeix un pam i només queda gran la cançó. Una cambra rodona on ningú pot intervenir-hi. Dins uns auriculars que et poses tot sol, curiosament, no estàs sol."},"ICON-1362":{"nm":"Partitura","de":"Quan els punts negres es posen quiets damunt les línies, el paper que callava comença a retenir el so. Una escriptura que no es llegeix, sinó que s'escolta. En obrir-la, una cançó que s'havia aturat torna a respirar."},"ICON-1363":{"nm":"Partitura vocal","de":"A cada lloc on cal respirar s'hi dibuixa un petit cercle. Inspira aquí, deixa-la anar suaument allà. Un mapa tendre que obre un camí perquè la veu no es faci mal."},"ICON-1364":{"nm":"Partitura de piano","de":"Una pàgina on els deu dits pregunten el camí alhora. La mà esquerra sosté les arrels, la mà dreta dibuixa la melodia. Dues mans que explicaven històries diferents s'acaben plegant en una de sola al darrer compàs."},"ICON-1365":{"nm":"Diagrama d'acords de guitarra","de":"La primera llengua estrangera que aprenen els dits, la seva primera paraula, hi és escrita aquí. Quan sis punts s'apleguen en cercles, només llavors plora una nota. Cada nit de prémer i tornar a prémer, a la punta li creix un call."},"ICON-1366":{"nm":"Metrònom","de":"Tic, tic: un pas inamovible batega al teu costat. Quan el cor corre per davant, et retindrà, lent, lentament, des de darrere. Perquè el ritme, al capdavall, és una promesa de caminar junts."},"ICON-1367":{"nm":"Afinador","de":"Quan l'agulla llisca fins al bell mig, la nota troba per fi el seu lloc. Aquell únic punt, ni massa alt ni massa baix. Així que estar afinat és això: deixar de tremolar i aturar-se, en silenci."},"ICON-1368":{"nm":"Targeta de teclat de piano","de":"Cada vegada que en gires un full, les tecles caminen fins al teu palmell. Del do al si, un petit univers de set caselles. Fins i tot en nits sense un piano de veritat, la cançó hi creix aquí, en silenci."},"ICON-1369":{"nm":"Pua de guitarra","de":"Un tros petit i dur que s'encaixa entre el polze i l'índex. Si te la deixes caure, desapareix per sempre sota la cadira, però en el moment d'agafar-la, les sis cordes ressonen totes alhora."},"ICON-1370":{"nm":"Baquetes","de":"Quan les dues es troben a mig aire, allà mateix cau el senyal. U, dos, tres, quatre. Tots els cors dispersos comencen a bategar a la mateixa velocitat, ajustats a aquells quatre temps."},"ICON-1371":{"nm":"Pandereta","de":"D'un sol cop, un so clar s'escampa en totes direccions, com raigs de sol que s'esmicolen. Per lleugera que sembli, és el primer instrument al qual la mà va quan l'entusiasme comença a apagar-se. Ningú pot menysprear-la per petita."},"ICON-1372":{"nm":"Sabatilles de ball","de":"Per als peus que giren lliscant pel terra, el fregament esdevé una arma. A cada sola gastada hi ha gravats els girs, un darrere l'altre. El moviment més espectacular sempre comença amb un parell de sabates ben ferm."},"ICON-1373":{"nm":"Genolleres","de":"Només qui s'ha agenollat innombrables vegades i s'ha tornat a aixecar coneix l'agraïment cap a aquesta prima capa de roba. Allò que fa que el terra ja no faci por: el valor, de vegades, s'enrotlla així al voltant dels genolls."},"ICON-1374":{"nm":"Canellera","de":"Si s'embolica per endavant el punt que es doblega, fins i tot un moviment forçat es fa una mica més indulgent. El canell no diu res i aguanta sol fins que li fa mal. Aquest llarg silenci, una sola capa el sosté en el seu lloc."},"ICON-1375":{"nm":"Turmellera","de":"Al final d'un salt alt hi ha l'aterratge, i al final d'aquest aterratge hi ha el turmell. El lloc més baix, on es rep tot el pes del cos. Aquesta petita cinta vetlla, en silenci, per l'assaig de demà."},"ICON-1376":{"nm":"Banda elàstica","de":"Com més s'estira, més resisteix per tornar al seu lloc. Mentre s'aguanta aquesta resistència, el cos s'allarga a poc a poc sense adonar-se'n. Estirar-se, al final, és la marca que deixa el temps d'aguantar."},"ICON-1377":{"nm":"Estora de ioga","de":"En el moment de desenrotllar-la, apareix sobre el terra un tros de terra que és tot meu. Un petit territori per ajeure's, estirar-se i regular la respiració. El començament i el final del dia es recullen, en silenci, sobre aquest únic full."},"ICON-1378":{"nm":"Corró de foam","de":"Prem amb fermesa el lloc encongit i al principi fa mal, però de seguida s'hi sent alleujament. Deslliurar allò que s'ha endurit sempre porta una mica de dolor. Perquè tant el cos com la ment, per amollar-se, han de ser premuts un cop."},"ICON-1379":{"nm":"Mancorna","de":"Aixeca el mateix pes, i torna a aixecar-lo. Exactament una vegada més que ahir, això és tot. Enmig d'una repetició sense res d'espectacular, el braç s'engrandeix sense dir res. Un simple bloc de ferro que només sap ser honest."},"ICON-1380":{"nm":"Kettlebell","de":"Amb una sola nansa, tot el cos hi gira arrossegat. Quan el pes rodó descriu un cercle, l'equilibri de qui l'aguanta es posa a prova. Per no vacil·lar, primer cal conèixer el propi centre."},"ICON-1381":{"nm":"Corda de saltar","de":"Salta la corda que passa xiulant sota els peus, i torna-la a saltar. Com aquell joc de comptar amb els amics al pati, com més s'amunteguen els números, més s'ofega l'alè i més creix el riure."},"ICON-1382":{"nm":"Sabatilles de córrer","de":"Un parell del qual només se sap el veritable valor un cop es puja al camí. Travessa l'aire de l'alba i corre de nou el mateix trajecte, i la cantonada que ahir semblava lluny avui és allà mateix. La distància, els peus la recorden."},"ICON-1383":{"nm":"Tovallola d'entrenament","de":"Un cop eixugada la suor del front, hi ha impregnada una línia de l'esforç d'avui. Encara que el rentat en faci desaparèixer el rastre, el que s'ha vessat s'acumula, endreçat, en algun lloc. L'ànim més honest sempre s'asseca al teu costat."},"ICON-1384":{"nm":"Cantimplora","de":"Buida, s'omple; seca, se'n beu un glop. Aquest simple anar i tornar sosté el dia en silenci. Com el poal que pujava i baixava vora el pou, el dia torna a començar amb l'acte d'omplir."},"ICON-1385":{"nm":"Batut de proteïnes","de":"Agita-la bé, passa'n un glop, i el múscul trencat avui torna a omplir-se demà. Encara que el gust no sigui espectacular, el cos sap que aquesta és la llengua de la recuperació. El creixement sempre es beu en silenci."},"ICON-1386":{"nm":"Barreta energètica","de":"Una barra aixafada dins la butxaca. Ració d'emergència que omple el temps buit entre àpat i àpat. Sense res de grandiós, aquesta petita mossegada permet aguantar un moviment més durant la tarda."},"ICON-1387":{"nm":"Caramel per a la gola","de":"Fes-lo rodar per la boca i una menta fresca acaricia suaument una gola aspra. En dies de parlar molt, en nits de cantar molt, una sola pastilla petita calma un camí eriçat. La dolçor també té, sens dubte, la seva utilitat."},"ICON-1388":{"nm":"Infusió per a la veu","de":"El vapor calent escalfa la gola, i amb un sol glop la tensió de les espatlles s'afluixa suaument. Un remei antic, com la infusió de gingebre que preparava l'àvia. Una salutació tendra que s'adreça a la veu abans de cantar."},"ICON-1389":{"nm":"Aigua amb mel","de":"Es dissol lentament una cullerada de mel en aigua tèbia. És aquell got que els grans preparaven sempre que la gola picava. Ni medicina ni beguda, només una dolçor que acaricia el cos, en silenci, des de dins."},"ICON-1390":{"nm":"Dipòsit d'humidificador","de":"Un recipient que allibera una petita boira dins l'habitació. En nits d'hivern en què l'aire sec esgarrapa la gola, reparteix humitat sense que es vegi. Tenir cura d'algú sol fluir, la majoria de vegades, així de silenciós."},"ICON-1391":{"nm":"Val de descans","de":"Un sol full de paper que diu que ja pots descansar. En el moment de rebre'l a la mà, la càrrega del cor es fa un graó més lleugera. Que aturar-se també és una pràctica: aquest petit tiquet t'en dona permís en el seu lloc."},"ICON-1392":{"nm":"Horari d'assaig","de":"Sobre el temps escrit casella per casella, el dia s'hi va assentant, endreçat. Al matí, tècnica vocal; a la tarda, coreografia; al vespre, descans. Fins i tot un demà que semblava inabastable, un cop dividit amb línies, esdevé, sense adonar-se'n, un camí que val la pena recórrer."},"ICON-1393":{"nm":"Segell d'assistència","de":"S'hi prem amb força una marca que diu que avui també has vingut. A mesura que els cercles, una mica escampats de tinta, s'acumulen casella rere casella, una constància que semblava insignificant s'ha convertit, sense adonar-se'n, en un camí. Una petita prova de cada dia."},"ICON-1394":{"nm":"Adhesiu d'elogi","de":"En lloc de dir que ho has fet bé, s'hi enganxa amb suavitat una estrella. És una espurna de la mida d'una ungla, però en el moment de posar-se al racó d'un quadern, tot el dia s'il·lumina. L'elogi és petit, però curiosament brilla molt de temps."},"ICON-1395":{"nm":"Quadern mental","de":"Una pàgina on el cor que tremolava rere l'escenari s'ha deixat anar en paraules. Fins i tot els dies que no han anat bé, si s'escriuen amb honestedat, alguna cosa es fa més lleugera. El cor s'enforteix en la mateixa mesura que s'hi mira dins."},"ICON-1396":{"nm":"Targeta de visualització","de":"Tanca els ulls i sostén-la, i un escenari s'estén, quiet, dins el cap. Caminar per endavant, una volta, per un lloc on encara no has posat els peus. El recorregut dibuixat per la imaginació hi arriba un pas abans que les puntes dels peus reals."},"ICON-1397":{"nm":"Mirall de pràctica d'expressions","de":"Davant del mirall somrius, et quedes seriós, i fas la mateixa cara més de cent vegades. Aquí s'aprèn que tant l'alegria com la tristesa necessiten pràctica. Perquè una expressió és l'acte de copiar el cor cap enfora."},"ICON-1398":{"nm":"Quadern de coreografia","de":"Una pàgina on el camí que recorreran els peus i els braços s'ha traspassat en dibuixos. A cada vuit temps, unes fletxes indiquen en silenci cap on ha d'anar el cos. Fins i tot un pas que costava molt de memoritzar es va domesticant, a poc a poc, sobre aquesta pàgina."},"ICON-1399":{"nm":"Xip de vídeo de coreografia","de":"En un sol xip petit s'hi guarden intactes centenars de moviments. Reprodueix-lo un cop més abans de dormir i la punta dels dits es mou tota sola seguint aquell camí. La repetició és un altre registre, traspassat aquest cop pel cos."},"ICON-1400":{"nm":"Full de moviments d'escenari","de":"Un únic mapa de l'escenari vist des de dalt. Qui es troba amb qui, on i cap a on es dispersen, tot ja pactat per endavant amb línies i punts. Per dibuixar una sola imatge entre molts, primer cal repartir els camins."},"ICON-1401":{"nm":"Passi d'assaig","de":"La platea és buida i els focus encara dormen. Aquest passi et deixa entrar en aquesta quietud. L'escenari quan ningú no mira -i per això aquí comença el moment de trobar-te amb la teva versió més sincera."},"ICON-1402":{"nm":"Llibre d'estil","de":"Amb quin ànim vestir avui? Fins i tot una simple camisa té un sentiment que li escau, aquest llibre t'ho recorda en veu baixa. Com més pàgines fulleges, més s'acumula, a poc a poc, un petit bon gust a la punta dels dits que abans dubtaven davant el mirall."},"ICON-1403":{"nm":"Laca per als cabells","de":"Xxxt, un sol raig i ni el vent gosa desfer-lo. Una petita ambició de retenir impecables aquells pocs minuts sobre l'escenari. El moment perfecte sempre s'acaba de construir sobre tossuderies tan menudes com aquesta."},"ICON-1404":{"nm":"Paleta de maquillatge","de":"Dotze caselles de color són dotze estats d'ànim diferents. Amb quina expressió cantar avui, ho trien primer els dits i el cor els segueix després. En cada casella que es buida hi queden, en silenci, els dies deixats sobre l'escenari."},"ICON-1405":{"nm":"Agulla de vestuari","de":"En el moment més enlluernador, hi ha una petita agulla que sosté la roba des d'un lloc que mai no es veu. Perquè no llisqui, perquè no es desfaci. La brillantor damunt l'escenari sempre reposa sobre la fermesa d'algú."},"ICON-1406":{"nm":"Rètol de nom","de":"En el moment que un nom omple el rètol que abans era buit, una promesa boirosa es torna nítida. Qui ocuparà aquest lloc, ho decideix una sola línia escrita. Un nom és la resolució més curta i més ferma que hi ha."},"ICON-1407":{"nm":"Targeta d'agraïment als fans","de":"Qui la rep és una sola persona, i per a aquesta persona és el món sencer. L'acte de comprimir la gratitud de moltes nits en una salutació breu. El cor vessa així fins i tot sobre un paper de la mida d'una palma de la mà."},"ICON-1408":{"nm":"Full de pràctica de signatura","de":"Al principi, fins i tot el propi nom es dibuixa estrany. A través d'albades traçant-lo cent vegades i polint-lo mil, fins que la mà en memoritza el traç abans que el cor. Així és com un nom esdevé, finalment, una signatura."},"ICON-1409":{"nm":"Full de preguntes d'entrevista","de":"«Què responc a aquesta pregunta?» La punta dels dits que sostenen el paper tremola una mica. No es tracta de memoritzar respostes sinó d'ordenar la sinceritat una a una, perquè una entrevista, com una confessió, al capdavall no és més que una pregunta sobre l'ordre del cor."},"ICON-1410":{"nm":"Quadern de vocabulari","de":"El cantó més gastat assenyala la paraula que més estona s'ha mirat. El temps que triga un so estrany a assentar-se a la llengua és el mateix que fa apropar, pam a pam, la distància fins a un món que mai no s'ha visitat."},"ICON-1411":{"nm":"Targeta de correcció de pronúncia","de":"La erra que rodola, la essa que s'escapa. Hi ha albades que es passen movent les targetes una a una, domesticant la llengua. Com més clara es torna la parla, més clar es torna també el rostre d'algú a qui es vol arribar amb aquestes paraules."},"ICON-1412":{"nm":"Llista de comprovació en directe","de":"Micròfon engegat, in-ears comprovats, desplaçaments revisats. Cada quadre que s'omple buida, alhora, una mica del neguit que hi ha al pit. Abans de pujar a l'escenari, la minuciositat és la forma més silenciosa de valentia."},"ICON-1413":{"nm":"Pegat de condició física","de":"Hi ha un punt que s'escampa càlid just quan s'hi enganxa. Una espatlla forçada, un panxell endurit -un consol de la mida d'una palma que respon en silenci als petits senyals que envia el cos. Descansar bé també forma part de l'entrenament."},"ICON-1414":{"nm":"Bossa de gel","de":"Es posa suaument sobre un turmell inflat. Només mentre el fred hi penetra a poc a poc s'arriba a saber realment quant s'ha corregut avui. La recuperació darrere l'escenari sempre arriba així, sense fer soroll."},"ICON-1415":{"nm":"Nécesser de primers auxilis","de":"Tiretes, analgèsics, un mirallet de mà. Arriba un moment en què aquesta petita bossa plena de coses sense importància esdevé la més reconfortant de totes. La delicadesa preparada per endavant brilla més forta davant una crisi inesperada."},"ICON-1416":{"nm":"Targeta d'indicacions","de":"Algú l'aixeca discretament des de darrere la càmera. Aquella frase que gairebé s'havia oblidat hi és escrita amb lletra clara. Darrere un programa que flueix sense entrebancs, sempre hi ha una mà com aquesta, mai capturada per la pantalla."},"ICON-1417":{"nm":"Sobre de missió","de":"L'instant just abans d'obrir el sobre és el que fa bategar més el cor. Sigui el que sigui el que hi ha a dins, aquell breu interval d'emoció encara ignorant. L'encant dels programes d'entreteniment viu sencer dins d'aquest sol instant segellat."},"ICON-1418":{"nm":"Targeta identificativa","de":"Un petit nom enganxat al pit fa de primera salutació. Entre persones que encara no es coneixen, una simple targeta trenca el gel de la incomoditat. Des del moment que es pronuncia un nom, comença una relació."},"ICON-1419":{"nm":"Adhesiu de penyora","de":"Un sol adhesiu enganxat al front del qui ha perdut fa esclatar les rialles de tothom. És tan tendre que costa dir-li càstig, i fins i tot perdre acaba convertint-se en un record perdurable. Una marca petita i afectuosa feta perquè tothom rigui plegat."},"ICON-1420":{"nm":"Targeta de penyora aleatòria","de":"Fins que no es treu, ningú no ho sap. Deu voltes de trompa d'elefant, o una ronda d'aegyo. En el moment que es confia tot el destí a un simple full de paper, són les rialles les primeres a deslligar-se."},"ICON-1421":{"nm":"Targeta de pista","de":"Com una mà que s'ofereix en silenci a algú encallat. No dona tota la resposta, però indica el camí. Una bona pista no és la solució, sinó l'acte de lliurar suaument el coratge de tornar-hi a pensar un cop més."},"ICON-1422":{"nm":"Targeta d'oportunitat","de":"Una sola ocasió per capgirar d'un cop un tauler inclinat. El moment en què es treu aquesta targeta decideix la partida. La sort estalviada i estalviada només demostra el seu valor en l'instant més decisiu."},"ICON-1423":{"nm":"Targeta de temps mort","de":"Que està bé aturar-se un moment, això és el que diu aquesta targeta en nom teu. Alçar la mà amb decisió quan calen unes quantes alenades -aturar-se també és una estratègia legítima, i descansar bé també ocupa un lloc dins l'habilitat."},"ICON-1424":{"nm":"Botó de rialles","de":"Clic, i just en prémer-lo esclata a vessar un allau de rialles alegres. Una escena veritablement còmica sempre agraeix que un efecte sonor com aquest hi doni un cop de mà. L'escalfor d'una reunió s'encén així, a partir d'una petita broma."},"ICON-1425":{"nm":"Comandament d'efectes sonors","de":"Un botó per als aplaudiments, un altre per als xiulets. Un mag que dona forma a l'ambient amb només la punta dels dits seu en silenci a la sala de control. La direcció que mai no capta la càmera és el que fa que aquella escena respiri de veritat."},"ICON-1426":{"nm":"Claqueta","de":"Clac, i amb aquest so nítid comença un pla. Entre desenes de preses fallides i un únic bé, aquesta placa negra compta cada instant amb precisió. És el primer compàs que marca el camí del gravat."},"ICON-1427":{"nm":"Cinta de marcatge","de":"En l'instant que la punta del peu toca aquella línia, els focus baixen suaument com si haguessin estat esperant. Aquella única casella memoritzada fins a gastar-la -l'escenari es completa, finalment, amb una petita franja de color traçada al terra."},"ICON-1428":{"nm":"Filtre de llum","de":"El mateix rostre queda del tot transformat pel color de la llum. En un filtre blau hi habita l'albada, en un de vermell, la posta de sol. L'atmosfera mai no és lluny -està plegada, tranquil·lament, dins un sol full prim de paper de color."},"ICON-1429":{"nm":"Bateria de càmera","de":"Quan la llum vermella comença a parpellejar, el cor s'inquieta abans que res. Perquè la millor escena sempre arriba just amb l'u per cent de càrrega restant. Una bateria de recanvi a la butxaca esdevé, tot d'una, l'alleujament de respirar tranquil."},"ICON-1430":{"nm":"Targeta de memòria","de":"Tot un dia de rialles i suor s'acumula compacte dins un xip de la mida d'una ungla. És tan petit que es perd amb facilitat, i per això mateix és encara més preciós. El pes dels records que conté mai no es pot mesurar per la mida."},"ICON-1431":{"nm":"Pel·lícula Polaroid","de":"Clic, i després una espera tranquil·la. Aquells pocs segons en què un rostre emergeix a poc a poc sobre la superfície que abans era blanca resulten estranyament emocionants. Fins i tot una foto instantània a la mà necessita, sens falta, una cullerada de paciència."},"ICON-1432":{"nm":"Pel·lícula per a fotocards","de":"Quina expressió quedarà impresa en aquest sol full és un secret fins al mateix instant abans de la impressió. El rostre que esdevindrà el preferit d'algú neix precisament aquí. Un petit full de paper conté un cor tan gran."},"ICON-1433":{"nm":"Funda per a fotocard","de":"Una fotocard mai no es toca amb les mans nues. Si es prem un sol cantó, fins i tot el somriure d'aquell dia se n'ressent. Embolicar el preferit amb cura dins d'un sol full transparent -fins i tot estimar requereix una dedicació com aquesta."},"ICON-1434":{"nm":"Toploader","de":"Encaixat entre dos fulls rígids, ni el temps gosa arrugar-lo sense permís. Que no es corbi, que no es plegui. Guardar amb cura alguna cosa preciosa sempre significa manllevar-li una capa més de fermesa."},"ICON-1435":{"nm":"Paquet d'adhesius","de":"Se n'arrenca un per un i s'enganxen al cantó d'una agenda, al darrere d'un portàtil. Amb un sol dibuixet, un dia que era gris queda tenyit de tots els colors. El desig de decorar allò que t'envolta no té edat."},"ICON-1436":{"nm":"Retolador","de":"Al so de la tinta relliscant suaument pel paper, la cua es fa cada vegada més llarga. Sobre un àlbum estès amb la mà tremolosa, una trobada de només uns segons perdura per molt de temps. El cor travessa a l'altre costat resseguint la punta del retolador."},"ICON-1437":{"nm":"Àlbum signat","de":"En obrir la coberta, una signatura de corbes conegudes saluda primer. Un vincle nascut de la música s'acosta un pam més sobre el paper. Guardar-lo és, senzillament, l'acte de mantenir aturat, en silenci, aquell instant."},"ICON-1438":{"nm":"Bateria per a bastó lluminós","de":"«Encén-te, si us plau.» Just abans d'entrar, les mans es mouen atrafegades canviant les piles. Perquè, entre desenes de milers de llums, la meva no s'apagui -una petita bateria il·lumina amb claredat aquella nit tan immensa."},"ICON-1439":{"nm":"Funda per a bastó lluminós","de":"Guardat amb cura sense ni un sol rascada, a punt fins i tot per als crits de la nit vinent. Encara que el lloc que ardia s'hagi refredat del tot, es porta a casa desat amb tendresa. Fins i tot un estri d'ànim té el seu propi lloc, i hi ha un cor que en té cura."},"ICON-1440":{"nm":"Pancarta de lema","de":"Una frase escrita sobre una tela llarga es desplega a través de la platea. En el moment que un ànim massa difícil de dir en veu alta s'obre de bat a bat, la sinceritat d'una sola persona esdevé el crit de tothom. Aquella tela es converteix, tal qual, en una veu."},"ICON-1441":{"nm":"Mini pancarta","de":"Un petit ànim que cap just a la palma de la mà. La pancarta penjada lluny pertany a tothom, però aquesta només oneja a la vora del teu escriptori. Onejant en silenci, demostra que ser petit de mida no vol dir tenir el cor petit."},"ICON-1442":{"nm":"Carta de fan","de":"Vaig reescriure el nom del destinatari tres vegades i vaig esborrar la primera frase set. Que la punta dels dits tremoli just abans de tancar el sobre és perquè el cor és massa sincer. A dins hi ha plegada una sinceritat més pesada que un sol segell."},"ICON-1443":{"nm":"Paper de regal","de":"El paper de regal sap millor que ningú que l'instant més emocionant és aquell segon just abans d'obrir-lo. Encara sabent que està destinat a esquinçar-se aviat, s'embolica amb la textura més fina, semblant-se al cor de qui el regala."},"ICON-1444":{"nm":"Llaç","de":"Si es lliga massa fort ofega, i si es fa massa fluix es desfà, així que trobar just el punt intermedi és la dedicació. La forma del cor queda continguda en un sol nus triat per la punta dels dits. L'última línia d'un regal sempre l'escriu el llaç en lloc nostre."},"ICON-1445":{"nm":"Targeta d'agraïment","de":"Un «gràcies» dit en veu alta s'esvaeix amb el vent, però escrit a mà perdura molt de temps. L'acte de retornar la bondat rebuda, amb una mica més afegida al damunt. Mentre s'estampa cada lletra, el cor s'aprofundeix el doble."},"ICON-1446":{"nm":"Val de dinar","de":"Amb aquest sol full de paper, la preocupació pel dinar s'esvaeix a poc a poc. Perquè hi ha promès un àpat d'arròs acabat de fer amb vapor pujant-hi, amb cada compartiment ple d'acompanyaments. Un petit amulet que protegeix amb fermesa una tarda de gana."},"ICON-1447":{"nm":"Val de berenar","de":"Va néixer per treure's a les tres de la tarda, quan la gana comença a fer un senyal discret. Un val que sap que una petita llepolia aixeca l'ànim mig pam. No és una gran recompensa, però arriba en silenci exactament en el moment que cal."},"ICON-1448":{"nm":"Val de cafè","de":"Una tassa calenta i un seient vora la finestra, això és tot el que promet aquest val. Pot semblar poca cosa, però per a algú esdevé un petit premi per haver aguantat el dia. Una invitació tendra l'aroma de la qual arriba un pas abans."},"ICON-1449":{"nm":"Val de neteja de l'allotjament","de":"Finestres obertes de bat a bat, mantes espolsades a fons, un dia en què ni un gra de pols s'escapa. Qui havia de dir que no haver-ho de fer amb les pròpies mans seria un luxe així. Quan l'habitació brilla, el cor també s'ordena en silenci."},"ICON-1450":{"nm":"Kit de reparació","de":"Un tornavís, cinta adhesiva, unes quantes peces d'identitat incerta. Un cop reunides sembla que no hi hagi res que no puguin arreglar, però en obrir-lo sempre falta alguna peça. Tot i així, una caixa de confiança que, no se sap per què, tranquil·litza només d'agafar-la."},"ICON-1451":{"nm":"Tiquet de sort","de":"Un tiquet en blanc, sense seient ni número. El punt clau és que no hi ha escrit quina cosa bona vindrà avui. Omplir aquest buit és cosa de qui el porta a la butxaca."},"ICON-1452":{"nm":"Dau","de":"L'amic que coneix millor que ningú la paraula justícia. No es posa de part de ningú i estima per igual les sis cares. Just en aquell instant que abandona la palma de la mà i roda fent tombs, fins i tot l'habilitat i els contactes cedeixen per un moment el seu lloc a la sort."},"ICON-1453":{"nm":"Passi de trasllat","de":"Una promesa que d'aquí fins allà, n'hi ha prou amb un sol pas. Un paper màgic que plega un camí llarg fins a fer-lo petit i el desa a la butxaca. En els dies que costa decidir-se a marxar, no hi ha millor tallador d'excuses que aquest."},"ICON-1454":{"nm":"Passi de nou intent","de":"En lloc d'allargar la mà a qui ha caigut, un tiquet que empeny suaument l'esquena i diu prova-ho de nou. Diu, amb la veu més suau, que el fracàs no és el final sinó una simple coma. Aquí és on es va omplint el coratge d'un cop més."},"ICON-1455":{"nm":"Passi de finalització ràpida","de":"Un truc tendre que s'estalvia una mica l'espera. Qui pot retreure-li a un cor que no aguanta ni tres minuts? Aquí hi ha un plaer una mica de trampa, com empènyer amb el dit la sorra d'un rellotge de sorra."},"ICON-1456":{"nm":"Potenciador de producció","de":"Les mateixes mans, el mateix temps, i tanmateix el doble de resultat. Gira alegre, brunzint, sobre la taula de treball, com si digués no preguntis el secret. Un petit dispositiu que posa ales, suaument, a dues mans que es mouen amb diligència."},"ICON-1457":{"nm":"Caramel d'afinitat","de":"Fins i tot la incomoditat difícil de desfer amb paraules es desfà tota sola davant d'alguna cosa dolça. Un vincle que s'acosta un pam més que ahir gràcies a un sol caramel compartit. Un petit descobriment adorable: que la dolçor és la velocitat amb què es creix la proximitat."},"ICON-1458":{"nm":"Gelea de recuperació d'ànim","de":"En un dia trist, alguna cosa freda i tova fa l'efecte just. Amb una sola mossegada, una expressió ennuvolada s'afluixa en silenci. Reparar el cor és, per naturalesa, una cosa preciosa, i no és casualitat que porti la classificació R."},"ICON-1459":{"nm":"Pols brillant","de":"Escampada lleugerament sobre alguna cosa corrent, de sobte la torna especial. En realitat només és pols que brilla, però en l'instant que es diposita el món sembla una mica més eufòric, quina cosa més curiosa. Com un condiment de felicitat esquitxat sobre el dia a dia."},"ICON-1460":{"nm":"Cinta d'escenari","de":"En pujar a l'escenari, incomptables focus et troben tots alhora. Una petita X al terra marca aquell lloc en silenci. El que és més precís des d'un lloc invisible acaba sostenint, al capdavall, l'escenari més gran."},"ICON-1461":{"nm":"Brida per a cables","de":"Un petit heroi que ordena en un instant cables enredats. Que un cop estrenyuda no es pugui desfer és tant el seu defecte com el seu encant. Un imprescindible que guarden en silenci els qui es prenen l'ordre seriosament."},"ICON-1462":{"nm":"Cable de recanvi","de":"Un objecte sense presència quan es té, i que només es troba a faltar de debò quan falta. Adormit al fons de la bossa darrere l'escenari, es desperta d'un cop en l'instant decisiu. Demostra amb el propi cos la paraula previsió."},"ICON-1463":{"nm":"Full de comprovació d'assaig","de":"Un paper ple, casella per casella, de desplaçaments, indicacions, fins i tot canvis de vestuari. Si en falta una sola marca, el cor d'algú s'enfonsa d'un cop. Un escenari perfecte només aixeca el teló després que aquest full quedi ple del tot."},"ICON-1464":{"nm":"Rètol de plató","de":"Aquí un cafè, allà un carreró, seguint les fletxes s'entra en un món completament diferent. És una mentida pintada sobre fusta contraxapada, i tanmateix davant la càmera es fa real. Un guia honest que ha dedicat tota la vida a assenyalar el camí."},"ICON-1465":{"nm":"Mini trofeu","de":"Un tros daurat que fa sentir, no se sap com, un pam més alt just en el moment de rebre'l. Brilla damunt l'escriptori dient que està bé de veritat no ser el primer, que sap tot el que t'has esforçat avui. El gran consol que ofereix una petita recompensa."},"ICON-1466":{"nm":"Motxilla","de":"En el moment de carregar-se-la a l'esquena, sembla que es podria partir cap a qualsevol lloc. A dins no hi ha gaire cosa, però de possibilitats en va plena de gom a gom. L'aventura sempre comença amb l'acte d'estrènyer bé aquestes corretges."},"ICON-1467":{"nm":"Brúixola","de":"No espantar-se ni quan es perd el camí és perquè la punta de l'agulla sempre assenyala el nord. La manera com trontolla una bona estona fins que finalment troba el seu lloc s'assembla molt al cor de les persones. Diu, amb la seva punta tremolosa, que no passa res per perdre's."},"ICON-1468":{"nm":"Llibreta","de":"La primera pàgina sempre és en blanc. Només qui sosté el bolígraf sap què hi escriurà. Jo només espero, que els pensaments d'avui es facin lletra i es posin en silenci damunt meu. La classificació R és el pes de la possibilitat encara per omplir."},"ICON-1469":{"nm":"Llapis","de":"Que estigui bé equivocar-se és el vessant més tendre d'aquesta eina. Mentre l'amic goma es mantingui a prop, es pot tornar a començar tantes vegades com calgui. Es fa més curt com més se l'esmola, però l'escurçament és la prova que ha estat estimat durant molt de temps."},"ICON-1470":{"nm":"Pel·lícula fotogràfica","de":"En l'instant que la llum hi travessa, el color d'aquell dia queda fixat intacte. Que un cop passa un fotograma mai més no es pugui desfer és tant la tensió com l'encant. L'elecció de qui, deliberadament, en una època ràpida, vol recordar amb un compàs més lent."},"ICON-1471":{"nm":"Càmera instantània","de":"Clic, i després una breu espera. Sostinguda a la mà i agitada suaument, un instant borrós es va tornant nítid a poc a poc. Una màquina una mica màgica que atrapa aquest mateix lloc, intacte, sobre un sol full de paper."},"ICON-1472":{"nm":"Foto antiga","de":"Com més esvaït és el color, més temps ha passat. En cada cantó gastat hi ha romàs la carícia de mans d'algú. Que la foto més antiga sigui la que guarda el record més nítid deu ser, potser, per culpa d'aquelles carícies."},"ICON-1473":{"nm":"Àlbum de retalls","de":"Retalls massa preuats per llençar es van aplegant fins a fer-se un volum sencer. Una entrada de cinema descolorida, un pètal assecat, una breu nota. Als ulls dels altres és un munt de coses soltes, però per a qui l'obre torna a la vida, sencera, tota una etapa."},"ICON-1474":{"nm":"Diari de navegació","de":"El vent i les onades d'avui, i una línia del cor. Escriure-ho amb fidelitat fins i tot en els dies sense res és la regla de la navegació. La prova d'haver arribat sa i estalvi sempre és escrita en algun racó d'aquest gruixut registre."},"ICON-1475":{"nm":"Fragment de mapa","de":"És només una cantonada del conjunt, però sense ell mai s'acaba trobant el camí. Quin plaer, quan una vora esquinçada encaixa perfectament amb un altre fragment. La classificació R té la presència de l'última peça d'un trencaclosques."},"ICON-1476":{"nm":"Missatge dins una ampolla","de":"Sense saber qui la llegirà, s'entrega en silenci a les onades. No espera cap resposta, només desitja que aquest cor arribi enlloc. La manera de fer arribar correu més lenta, però també la més romàntica."},"ICON-1477":{"nm":"Dau","de":"Sis cares que somriuen arrodonides com si diguessin, un altre cop tu? La mateixa forma, i tanmateix donant una resposta diferent a cada tirada -aquesta és la immutable capritxositat d'aquest amic. En l'instant que deixa la mà, per un moment es confia l'elecció al destí."},"ICON-1478":{"nm":"Molinet de vent","de":"Només quan bufa el vent cobra vida de debò. Deixat quiet, no és res més que ales de paper, però si algú hi bufa comença a girar amb alegria. No avergonyir-se de rebre ajuda és la saviesa d'aquesta petita flor."},"ICON-1479":{"nm":"Cistella de pícnic","de":"En obrir la tapa, l'olor de gimbap saluda primer. Gespa verda, una estora estesa, i mans que comparteixen menjar amb altres mans. Els dies que aquesta cistella es va omplir del tot, curiosament, sempre feia un cel clar."},"ICON-1480":{"nm":"Gerro","de":"Amb només posar-hi una tija, l'aire mateix de l'habitació canvia. Quan és buit, esperar en silenci és el seu deure propi. El decorat d'escena més humil de l'habitació, que rebaixa suaument la seva pròpia presència perquè la flor brilli encara més."},"ICON-1481":{"nm":"Pètal","de":"Quan el vent se n'emporta un, la primavera es fa una mica més lleugera. El vell arbre del pati fa cada any la mateixa salutació: que caure també és un fragment de l'acte de florir. Escampar-se no és el final, sinó una carta enviada per endavant a la propera primavera."},"ICON-1482":{"nm":"Rosa","de":"Alçar primer les espines és una promesa de no ser tocada a la lleugera. Al seu interior s'hi amaga el cor més vermell. Algú va deixar una sola tija en silenci als peus i se'n va anar, escrivint el seu sentiment només en color, en lloc d'un nom."},"ICON-1483":{"nm":"Lliri","de":"Al costat de la porcellana blanca i polida, sempre s'hi va posar aquesta flor blanca. Que la fragància viatgi lluny però el port mai no es desfaci. Des d'aquell lloc on va triar la puresa abans que l'esplendor, el lliri custodia en silenci una mesura de dignitat."},"ICON-1484":{"nm":"Tulipa","de":"Amb el cap una mica inclinat i formant fila, la imatge resulta, no se sap com, tan endreçada. La flor que ocupa sempre la primera filera del parterre de primavera. Aquesta honestedat de florir tots a la vegada i marcir-se tots a la vegada tenyeix més intensament una estació tan breu."},"ICON-1485":{"nm":"Jacint","de":"En una sola tija hi penja un enfilall dens de petites campanes. Encara que se sacsegi no fa cap so, però és la fragància qui, en el seu lloc, fa ressonar l'habitació. A l'entrada de la primavera, un luxe tendre que canvia de dalt a baix l'aire de l'habitació amb un sol gerro."},"ICON-1486":{"nm":"Espècimen de granota","de":"Un cos petit on el temps s'ha aturat dins una caixa de vidre. L'etiqueta diu: «Arrossars i basses; el moment de més vitalitat és l'endemà de la pluja.» Només després d'aturar-se queda registrada, fins i tot, la temperatura de la ribera on va viure aquest ésser."},"ICON-1487":{"nm":"Espècimen de sargantana","de":"Fins i tot fet espècimen, no s'esborra l'astúcia de tallar-se la cua i fugir. Un petit hoste a qui li agradaven els murs de pedra escalfats pel sol. A la nota del costat hi ha escrita, amb lletra clara, la direcció del racó assolellat que li agradava enfilar."},"ICON-1488":{"nm":"Registre de talp","de":"El diari de qui viatja per sota terra s'escriu en el gra de la terra. Per on va cavar i on es va aturar, un mapa de camins invisibles. El temps viscut d'esquena a la llum esdevé, per a algú, el registre més diligent que hi pugui haver."},"ICON-1489":{"nm":"Espècimen de petxina","de":"Un dibuix sòlid que les onades han polit i enviat milers de vegades. La gent del fangar sabia de quin mar venia només mirant el gra de la closca. La forma d'un mar que un dia va viure i va respirar es conserva intacta dins un espècimen de la mida d'una palma."},"ICON-1490":{"nm":"Espècimen de corall","de":"Al fons del mar, creix a penes un pam al llarg de centenars d'anys. Sembla una branca, però en realitat és una casa construïda plegades per innombrables vides petites. Com més lenta és una cosa, més perdura, ho demostra el corall en silenci."},"ICON-1491":{"nm":"Pista d'Aidong","de":"Un fragment d'una història escampada en algun lloc de l'illa. Un petit tros de paper assenyala en silenci el següent pas. Tota aventura, al capdavall, comença arreplegant petjades tan insignificants com aquesta, diu el vell guia."},"ICON-1492":{"nm":"Peça de signatura","de":"Quan el dibuix escampat troba el seu lloc, finalment es completa una sola marca. Una peça gravada amb el traç únic d'algú. Amaga el seu significat fins que s'encaixa, i just en l'instant que s'encaixa, esdevé al fi un nom."},"ICON-1493":{"nm":"Fragment de memòria d'escenari","de":"Encara que una cançó s'acabi, a la platea hi queda calor residual. Si es desprèn aquesta escalfor i s'endureix, es converteix en un petit fragment com aquest. Fragments dispersos d'aplaudiments i crits, aplegats en silenci, tornen a fer reviure sencera aquella nit."},"ICON-1494":{"nm":"Segell de debut","de":"El dia que van cridar el teu nom per primer cop, aquella marca de tinta estampada al dors de la mà. Fins i tot la cura d'assecar-la a poc a poc perquè no s'escampés formava part de la línia de sortida. Un petit segell fa que un cert dia no s'esborri mai més."},"ICON-1495":{"nm":"Medalla de top idol","de":"Un pes que només es permet a qui arriba al lloc més alt. Però aquesta medalla no pesa per culpa del metall. És perquè el pes d'incomptables mans que van omplir l'escenari plegades s'hi acumula, intacte, en un sol punt."},"ICON-1496":{"nm":"Clauet petit","de":"La primera clau de l'allotjament sempre era la de l'habitació més interior. Un lloc on es va aprendre abans a obrir que no pas a tancar. El dia de marxar, l'escalfor que deixa una palma perdura una bona estona sobre el metall fred."},"ICON-1497":{"nm":"Cofre del tresor","de":"Fins que no s'obre, ningú no sap què hi ha a dins. Aquesta ignorància és, precisament, el veritable tresor del cofre del tresor. En el breu instant d'aixecar-ne la tapa, tothom torna per un moment a l'emoció dels dies d'infantesa."},"ICON-1498":{"nm":"Plànol","de":"Sobre línies traçades caixa per caixa, hi viu un edifici encara per aixecar. Desplegar el plànol és caminar per endavant, un cop, dins el demà. Una sola línia ben traçada sosté un demà que no s'ensorrarà."},"ICON-1499":{"nm":"Targeta de recepta","de":"En una sola targeta gastada pel tacte, el saber fer de l'àvia hi és escrit en mesures. Paraules ambigües com «un pessic de sal» són el secret més precís. Com més esvaïda queda la lletra, més nítida ve al cap la cuina on aquell plat es va coure a foc lent."},"ICON-1500":{"nm":"Permís d'instal·lació","de":"Un sol full de paper transforma un solar buit en «un lloc que es pot fer servir.» Un edifici nou sempre necessitava primer el segell del poble. El permís és, al capdavall, un segell càlid que diu que és lícit començar aquí alguna cosa."},"ICON-1501":{"nm":"Permís portuari","de":"Abans que un vaixell pogués fondejar, calia primer aquest únic full. El segell descolorit del port és la primera salutació per a qui arriba de lluny. Entre la partida i l'arribada, el port sempre obre el cor amb un sol full de paper."},"ICON-1502":{"nm":"Distintiu d'admissió a l'illa","de":"Un petit certificat que demostra que ja formes part de la família de l'illa. Quan arribava un veí nou, el vell poble afegia el seu nom al registre i repartia pastissos d'arròs calents. És només un full de paper, però hi ha escrita la benvinguda més lluminosa: 'ara tu també ets dels nostres'."},"ICON-1503":{"nm":"Placa nominativa de l'allotjament","de":"Amb un sol nom penjat vora la porta, una cambra buida esdevé per fi la llar d'algú. Fins i tot a les antigues cases d'hostes, el primer que es penjava era el rètol amb el nom del mestre. La placa és petita, però hi és plena la calidesa de 'aquí hi viu algú'."},"ICON-1504":{"nm":"Segell de fandom","de":"Fins i tot la delicadesa de xopar-lo de saliva i prémer-lo bé formava part d'una carta sencera. L'acte d'enganxar un sentiment estimat a un petit tros de paper i enviar-lo lluny. Fins i tot a l'era digital, algú encara envia el seu cor per correu, a mà."},"ICON-1505":{"nm":"Insígnia de l'Illa Brillant","de":"Prens-la al coll del vestit i una petita llum et segueix allà on vas. Trobar algú amb la mateixa insígnia pel carrer i entendre's sense dir cap paraula. La resplendor no és una fanfarronada, sinó un senyal silenciós: 'estimem la mateixa illa'."},"ICON-1506":{"nm":"Banc de treball","de":"Un tauler ple de cicatrius dona testimoni de les mans que més coses han fet. El lloc on s'arreglava, s'unia i es polia alguna cosa. Més que un escriptori net, un banc de treball desordenat guarda, de fet, moltes més històries."},"ICON-1507":{"nm":"Caixa d'emmagatzematge","de":"Com més preuada és una cosa, més aviat se li decideix el lloc. La gent d'abans també guardava els documents valuosos a part, en arques de fusta de paulònia. Guardar bé alguna cosa és, al capdavall, plegar amb cura el dia d'avui per a algú del futur."},"ICON-1508":{"nm":"Caixa de subministraments","de":"Quan sobra, es reserva; quan falta, es treu. Aquí hi ha la saviesa d'una època en què un rebost ben proveït volia dir un cor tranquil. Fer provisions és lliurar per endavant un àpat generós al teu jo futur."},"ICON-1509":{"nm":"Caixa refrigeradora","de":"Una arca plena de gel conservava la frescor fins i tot en ple estiu. És com si l'antiga saviesa de la glaçera s'hagués traslladat a la mida d'una palma de la mà. Mantenir el fred és deixar que l'instant més fresc perduri una mica més."},"ICON-1510":{"nm":"Bomba d'aigua","de":"Si es mou el mànec amunt i avall, l'aigua profunda de sota terra brolla cap amunt. Una màquina honesta que només rajava després que hi aboquessis un primer poal per encebar-la. Que cal donar abans de rebre és una veritat que el pou va aprendre ben aviat."},"ICON-1511":{"nm":"Purificador d'aigua","de":"Un petit miracle en què l'aigua tèrbola es va aclarint capa a capa. La gent d'abans filtrava l'aigua apilant sorra i carbó dins de gerres de fang. La claredat no s'obté de franc; és la cura de filtrar a poc a poc."},"ICON-1512":{"nm":"Suport per a la regadora","de":"En el moment que la regadora troba el seu racó de repòs, el dia del parterre s'endreça. Decidir on penjar una eina és el costum de qui estima la seva feina. Un cop es fixa un sol lloc, tot el pati es torna una mica més ordenat."},"ICON-1513":{"nm":"Suport per a la canya de pescar","de":"Encara que la persona marxi fins que arribi la picada, la canya manté el seu lloc. Aquí queda gravada tal qual la postura pacient de qui pesca els anys vora el riu. Un suport és, al capdavall, un recolzament per deixar de banda una estona la impaciència."},"ICON-1514":{"nm":"Cistell de recol·lecció","de":"El feix de la mare, que duia un grapat d'herbes silvestres i una sola flor de camp. Entre les escletxes del bambú trenat s'escola, discret, l'olor de la terra. Segons què s'hi posi, un cistell buit pot esdevenir tant primavera com tardor."},"ICON-1515":{"nm":"Morter","de":"Tum, tum, moldre el gra amb un ritme constant despertava el dia del poble. Una eina el bategar de la qual omplia els carrerons en els dies de festa. Per tornar tou allò que és dur cal el ritme constant d'una mà que treballa."},"ICON-1516":{"nm":"Post de tallar","de":"Cada marca que hi deixa el ganivet grava la història d'un àpat. Una post de fusta plena de talls és la medalla de la cuina per a les mans més diligents. Tallar alguna cosa comença amb el desig de servir-la amb cura."},"ICON-1517":{"nm":"Olla","de":"El borbolleig de l'aigua bullint és més tendre que qualsevol música. En una matinada amb gana, els tres minuts d'esperar que es coguin els fideus són el consol més íntim. Al fons rodó, s'hi escalfa la calidesa de qui vol donar de menjar a algú."},"ICON-1518":{"nm":"Paella","de":"L'ofici de coure alguna cosa en un instant sobre el foc depèn d'aquesta sola paella. Com més ben curada és la superfície, menys s'enganxa i més lluu. Una paella de ferro colat de molts anys és, ella mateixa, la prova dels anys que ha viscut la cuina."},"ICON-1519":{"nm":"Forn","de":"Mentre tanques la porta i esperes, a dins hi passa la màgia en silenci. El temps en què la massa creix i el color va coent-se. Encara que no es vegi, si s'espera amb fe, un resultat calent obre la porta i surt."},"ICON-1520":{"nm":"Batedora","de":"Fins i tot allò que és dur, en posar-ho aquí dins, esdevé en un instant una copa suau. Un petit remolí on ingredients diferents es barregen i neix un gust nou. L'harmonia és, al capdavall, que cadascú cedeixi una mica de les seves pròpies arestes."},"ICON-1521":{"nm":"Batedor manual","de":"Amb un sol gest del canell l'aire queda atrapat, i com més ràpid remous, més ferm es dreça allò que era líquid. Mentre les bombolles s'alcen com cims, no és només la massa el que s'infla. També s'infla el desig d'algú de donar de menjar avui."},"ICON-1522":{"nm":"Molinet de cafè","de":"Un grapat de grans i, en girar el mànec, l'aroma es trenca primer entre les dents. Quan el braç comença a fer mal, la mòlta és per fi fina, i el primer glop s'aprofundeix tant com l'esforç. La cura sempre comença al canell."},"ICON-1523":{"nm":"Molí de farina","de":"El gra entra entre les pedres i en surt convertit en farina blanca. No importa si a la primera no queda fina; n'hi ha prou de moldre-la dues vegades més. Que fins i tot fer fi allò que és aspre té un ordre, el molí de farina ho recorda en silenci."},"ICON-1524":{"nm":"Banc de serra","de":"Quan puja un tronc, la serra en llegeix primer la veta. Cal esquivar els nusos i tallar només seguint el camí recte perquè la post no es guerxi. Tallar la fusta és, al capdavall, estendre ben endreçat el temps que un arbre va viure."},"ICON-1525":{"nm":"Màquina de cosir","de":"Rat-a-tat—el so de l'agulla que mossega la tela i corre omple la nit avançada. Una sola costura uneix dos panys en un sol cos, i a cada punt amagat dins d'un vestit d'escenari hi queden fermament cosides les hores d'insomni d'algú."},"ICON-1526":{"nm":"Taula de tenyir","de":"Sucar la tela blanca i treure-la: al principi és verd pàl·lid, i només en trobar-se amb l'aire es torna blava del tot. Aquell color que diuen que només surt després de tres remulls d'indi. Que l'espera mateixa es converteix en color, ho vaig aprendre per primer cop davant d'aquesta taula de tenyir."},"ICON-1527":{"nm":"Trípode de càmera","de":"En el moment que les tres potes s'obren i toquen terra, el món que trontollava s'atura. Una presa que hauria tremolat a la mà es fa nítida sobre la promesa d'aquests tres punts. Per contemplar alguna cosa llargament, cal primer saber estar-se quiet."},"ICON-1528":{"nm":"Suport de llum","de":"Poses un llum dalt d'un sol pal, i qualsevol racó de l'habitació es converteix en un petit escenari. Gires lleugerament l'angle i les ombres s'allarguen, les expressions cobren vida. No esborra la foscor, sinó que fins i tot la foscor l'acomoda amb amabilitat."},"ICON-1529":{"nm":"Suport de micròfon","de":"En el moment que en fixes l'alçada, queda establerta la distància entre la boca i la cançó. Encara que hi treguis les mans, la veu es queda allà mateix. Només en un escenari on les dues mans queden lliures comença de veritat la cançó cantada amb tot el cos."},"ICON-1530":{"nm":"Faristol","de":"Quan el full obert s'inclina de biaix, les notes es posen en filera a l'alçada dels ulls de qui toca. Encara que arribi el compàs següent amb un sol gest, el faristol no vacil·la. Darrere la interpretació de qualsevol, sempre hi ha un lloc silenciós."},"ICON-1531":{"nm":"Hort","de":"Es llaura la terra i s'obren els solcs, i sobre la terra apareixen petites línies de promesa. Els dies després de sembrar la llavor semblen no passar res, però un matí uns cotiledons tendres empenyen la terra cap amunt. És un paisatge que només veu qui ha esperat."},"ICON-1532":{"nm":"Hort fèrtil","de":"És la mateixa llavor, però en aquesta terra les fulles creixen el doble de grans. Fiques un dit i una terra negra i suau et segueix fins sota les ungles. Créixer bé va ser, al capdavall, la feina que la terra invisible va fer en silenci sota els peus."},"ICON-1533":{"nm":"Hivernacle","de":"Sota un sostre de vidre, les estacions flueixen un compàs més a poc a poc. Encara que fora caigui la gebrada, a dins tot és humit com un ple estiu. Per a les coses que no resisteixen el fred, algú ha atrapat amb suavitat la llum del sol sota el sostre."},"ICON-1534":{"nm":"Parterre d'herbes","de":"En fregar les fulles amb la punta dels dits, l'aroma et saluda primer. Alfàbrega, romaní, menta—cada cop que en dius el nom, una olor diferent s'enganxa als dits. Un sol petit parterre transforma amb dolçor tota la cuina."},"ICON-1535":{"nm":"Verger","de":"A la primavera, per l'ombra de les flors; a la tardor, pel pes del fruit, les branques es vinclen. Puges l'escala, en cull un, hi fiques la queixalada, i tota la dolçor que el sol ha anat aplegant durant un any esclata a la boca. És com una resposta que l'arbre lliura a la persona."},"ICON-1536":{"nm":"Tronc de bolets","de":"Perfores un tronc tallat i hi plantes el miceli, i l'arbre mort torna a fer créixer alguna cosa. Uns dies després, al matí que els barrets broten en pomells, en el lloc que semblava el final, comença en silenci una vida nova."},"ICON-1537":{"nm":"Rusc","de":"Acostes l'orella i sents a dins una vibració baixa i atrafegada. Milers de batecs d'ales s'apleguen per fer amb prou feines una cullerada de dolçor. La feina d'un dia sencer anant i venint pel camp de flors reposa aquí, enganxosa i daurada."},"ICON-1538":{"nm":"Galliner","de":"Abans que trenqui l'alba, els que són al perxa ja remoregen primer. Fiques la mà dins la palla calenta i atrapes un ou que encara guarda escalfor. El lloc que anuncia el matí primer és el primer a parar la taula del matí."},"ICON-1539":{"nm":"Pastura","de":"Un ampli prat on es barregen l'olor de l'herba i l'olor del sol. Sobre els lloms que remuguen a poc a poc dins la tanca, passen les ombres dels núvols. En aquest lloc on no hi ha res a apressar, fins i tot el temps flueix a poc a poc, com qui pastura."},"ICON-1540":{"nm":"Formatgeria","de":"La llet just munyida s'endureix a poc a poc a través de la coagulació i la maduració. Espera uns mesos en un prestatge fresc com una cova, i un sabor profund amara la massa blanca. El formatge és un nom que només es dona a la llet que no ha tingut pressa."},"ICON-1541":{"nm":"Obrador de tofu","de":"Remulles les faves de soja, les mols i les bulls, i la llet crua de soja es torna torrada. Una sola gota de nigari aplega allò dispers en tofu tou, i, premut amb suavitat, pren forma quadrada. Aquí hi ha una mà que apaivaga un cor dispers fins a donar-li forma."},"ICON-1542":{"nm":"Terrassa de gerres","de":"En un racó assolellat del pati, gerres baixetes s'apleguen ben arrenglerades, prenent el sol. Alces la tapa i l'olor del temps envellit surt de cop. El gust de la pasta que l'àvia fermentava és, en veritat, menjar-se els anys a cullerades."},"ICON-1543":{"nm":"Molí","de":"Quan les pedres giren amb un traqueteig, el gra es desfà en farina. La pols blanca sura enmig de la llum del sol, i la gent que espera el seu torn per fer una safata de pastissos d'arròs fa cua. El dia de festa del poble sempre semblava començar en aquest llindar."},"ICON-1544":{"nm":"Fleca","de":"Per l'escletxa de la porta del forn s'escapa l'olor de mantega i sucre. Quan la massa alçada es torna daurada, els passos de qui passa per davant de la botiga s'alenteixen sense adonar-se'n. Un sol pa acabat de coure té una tendresa que ningú no pot resistir."},"ICON-1545":{"nm":"Parada de menjar ràpid","de":"La lona de plàstic voleia al vent i el brou de tteokbokki es va reduint a borbolls. Un vespre d'empassar-se el brou d'un got de paper amb un sol pinxo de pastís de peix, un lloc que fon fred i gana alhora. Un petit consol instal·lat al capdavall del carreró."},"ICON-1546":{"nm":"Cuina occidental","de":"La paella s'escalfa i l'oli d'oliva xiuxiueja. Amb un sol gir del foc, una salsa pot espessir-se o cremar-se. Aquí, on fins i tot es pesa l'equilibri dels colors al plat, un àpat es converteix en una posada en escena feta amb cura."},"ICON-1547":{"nm":"Cuina xinesa","de":"Sobre un foc violent, el wok gira d'una banda a l'altra com si ballés. En l'instant breu que les flames s'alcen, l'aroma dels ingredients hi queda tancat sencer. Ràpid i calent: el secret de la cuina xinesa s'amaga en aquell sol alè que es perd si dubtes."},"ICON-1548":{"nm":"Cafeteria","de":"Empenys la porta i l'olor de cafè i una música suau et reben primer. Una taula a la finestra, una llet amb cafè que es refreda i una llibreta oberta. Perquè puguis agafar alè un instant enmig d'un dia atrafegat, la ciutat ha amagat petites cambres com aquesta arreu."},"ICON-1549":{"nm":"Botiga de postres","de":"Dins l'aparador de vidre, pastissos de colors fan filera esperant els clients. En l'instant que la punta de la forquilla parteix la crema, les comissures dels llavis s'alcen primer. Una petita recepta dolça que fa suportable fins i tot un dia trist amb un sol tros."},"ICON-1550":{"nm":"Carnisseria","de":"Sota la llum vermella, la carn jeu endreçada seguint la veta. Amb una sola frase—«avui aquesta és bona»—el ganivet llisca amb el gruix exacte. La fermesa de la taula del sopar comença en silenci amb aquesta mà que manté cada dia el mateix lloc."},"ICON-1551":{"nm":"Taulell de peixateria","de":"Un taulell on es barregen l'olor de peix de matinada i el fred del gel. Encara que saltin escates i les mans es glacin, l'ull que tria el més fresc no s'atura mai. Aquí, allò que acaba de pujar del mar troba el seu camí cap a la taula."},"ICON-1552":{"nm":"Salines","de":"Es reté l'aigua de mar i el sol i el vent fan la resta. S'espera uns dies que l'aigua s'assequi, i al fons broten cristalls blancs com estrelles. Un grapat de sal és, de fet, un regal que el mar i el cel han fet plegats a poc a poc."},"ICON-1553":{"nm":"Assecador d'algues","de":"En una llarga corda, algues wakame i kombu pengen l'una al costat de l'altra, gronxant-se al vent. Allò que és carregat d'aigua de mar s'enfosqueix fins a un verd intens en assecar-se. El sabor més sobri del mar, fet plegats pel sol i la brisa salada, penja aquí."},"ICON-1554":{"nm":"Petit moll","de":"Uns taulons de fusta mig submergits es belluguen suaument sota els peus. Just el lloc adequat per amarrar una sola barca petita. Tant marxar lluny com tornar sans i estalvis comencen i acaben en aquest sol tram."},"ICON-1555":{"nm":"Magatzem del port","de":"Obres la porta de fusta curada pel vent de mar, i xarxes, bótes i cordes s'apilen fins al sostre. La càrrega que marxa cap a un llarg viatge i la que just acaba d'arribar reposen una estona sota el mateix sostre. Un lloc com una estació de transbord on la partida i el retorn es creuen un instant."},"ICON-1556":{"nm":"Far","de":"Només quan el mar nocturn es fa més fosc comença per fi la seva feina. La llum que gira travessa la boira i diu: «aquí hi ha un camí». Un vigilant alt que, per al retorn segur d'algú, no s'adorm mai del tot."},"ICON-1557":{"nm":"Drassana","de":"S'alça la quilla i s'hi fixen les costelles, i l'esquelet d'un vaixell pren forma. En un pati on el so dels martells ressona tot el dia, un vaixell que encara no coneix el gust de l'aigua somia el seu primer viatge. Un lloc que primer es fa fort per poder marxar."},"ICON-1558":{"nm":"Cabina d'enregistrament","de":"Quan la porta es tanca, tots els sorolls de fora desapareixen d'un cop. Tot el que se sent més enllà dels auriculars és el propi alè i el compàs. En el silenci d'aquesta petita cambra, neix per fi una veu que pot tremolar sense por."},"ICON-1559":{"nm":"Sala de música","de":"Les harmonies que s'escolen per l'escletxa de la porta omplen el passadís. Algú marca l'escala, algú compta el ritme. Un lloc on sons maldestres i sons madurs es poden barrejar sense problema, una aula amable on cada cançó fa els seus primers passos."},"ICON-1560":{"nm":"Sala de piano","de":"Obres la tapa del teclat i una fina capa de pols descansa sobre les tecles blanques. En l'instant que els dits les toquen, una ressonància clara s'escampa per tota la cambra. Si hi ha vespres que no són solitaris ni estant sol, és probablement per culpa d'aquest sol piano."},"ICON-1561":{"nm":"Sala de ball","de":"Prems amb la punta dels peus i el terra t'empeny cap amunt de nou. Mentre els quatre miralls copien el mateix moviment quatre vegades, el cos memoritza la coreografia mig compàs abans que el ritme. La sala on la suor i l'alè s'hi queden més temps; els moviments criats aquí surten a l'escenari."},"ICON-1562":{"nm":"Gimnàs","de":"El pes mai no menteix. La gent em busca cada matinada perquè estima aquesta honestedat—exactament tant com aixeques s'acredita a les espatlles. El que es va gravant a poc a poc al mirall no és múscul, sinó les hores que has resistit sense rendir-te."},"ICON-1563":{"nm":"Sala de ioga","de":"Respires fondo i tens la sensació que el terra de fusta s'infla amb tu. Una sala on pleguis a poc a poc un dia que ha arribat corrent; sobre una sola estora, tothom torna al ritme del seu propi alè. Fins i tot un cor apressat es deixa aquí una estona."},"ICON-1564":{"nm":"Sala de maquillatge","de":"Just abans de sortir a l'escenari, aquí la gent esdevé per un moment algú altre. Quan les bombetes al voltant del mirall escalfen la cara per igual, el tremolor s'enganxa a la punta de la borla de pólvores i s'esmuny en silenci darrere el coll. El lloc on la transformació comença i també acaba."},"ICON-1565":{"nm":"Sala de vestuari","de":"Fins que un sol vestit d'escenari queda enllestit, la roba que hi penja es posa i es treu desenes de vegades. Un maniquí que gira amb agulles d'embastar clavades, línies de vora marcades amb guix. Darrere la lluentor sempre hi queda la marca de la costura d'algú."},"ICON-1566":{"nm":"Decorat de televisió","de":"Que només calia arreglar amb aparença real la cara que enfoca la càmera, ho vaig aprendre aviat. Vas darrere el contraplacat i només hi ha un armazó buit. Sostenir en silenci l'esplendor de la façana és sempre cosa dels llistons de fusta invisibles."},"ICON-1567":{"nm":"Estudi fotogràfic","de":"El primer secret és llançar la llum des de tres direccions per esborrar les ombres. La llum principal fa lluir la cara, la llum de reompliment les ombres, la contrallum les puntes dels cabells. En l'instant que cau l'obturador, un sol fons blanc atrapa el millor somriure del dia."},"ICON-1568":{"nm":"Sala de concerts","de":"En la foscor d'un sostre alt, jo guardo sempre la mateixa promesa: que quan s'aixequi el teló, fins i tot les butaques buides contindran l'alè com una sola persona. Per aquell únic instant en què cau el primer compàs, resto buida en silenci tot l'any."},"ICON-1569":{"nm":"Cabina de trobada de fans","de":"La distància entre una mà i l'altra és exactament l'amplada d'una taula. Una salutació curta, un autògraf tremolós, una paraula que mai no es va acabar de dir passen en filera. Dins d'aquesta petita cabina, un sentiment estimat criat durant molt de temps es troba cara a cara per primera vegada."},"ICON-1570":{"nm":"Llit","de":"Sempre vaig ser jo qui primer rebia el final del dia. Un cop assossegades del tot les cames pesades pels assajos i el tremolor que quedava rere l'escenari, el matí torna a començar amb les puntes dels peus lleugeres. Dient bona nit, t'abraço sense dir paraula."},"ICON-1571":{"nm":"Llitera","de":"Entre el pis de dalt i el de baix, cinc esglaons d'escala uneixen dues persones. Petites veus compartides amb el llum apagat, estrelles fosforescents enganxades al sostre. L'allotjament estret es fa el més ampli gràcies a les històries que pugen i baixen l'escala cada nit."},"ICON-1572":{"nm":"Prestatge","de":"El que hi poses a sobre mostra qui ets. Una carta rebuda, un primer trofeu, una entrada descolorida fan filera l'una al costat de l'altra. No sóc un moble per exhibir presumpció, sinó un lloc que exposa en silenci records que no s'han pogut llençar."},"ICON-1573":{"nm":"Escriptori","de":"Amb el quadern de lletres obert, es tornen a traçar línies noves sobre marques esborrades. Gots de paper acumulats durant la nit i una sola melodia salvada amb prou feines. La feina lenta de traslladar el cor a paraules sempre té lloc en silenci sobre aquesta superfície plana."},"ICON-1574":{"nm":"Cadira","de":"Dir «seu un moment» és, sorprenentment, una cosa tendra. Per llarga que s'allargui la reunió o s'estiri l'assaig, el respatller aguanta en silenci el pes d'una persona. Com més estona ha estat dreta una persona, més em dona la benvinguda—això ho sé."},"ICON-1575":{"nm":"Sofà","de":"Per convertir l'allotjament de nit tancada en una sala d'estar, jo tota sola en tinc prou. Us hi apinyeu tots plegats mirant un programa d'entreteniment, i abans que us n'adoneu, algú s'ha adormit recolzat al braç. El seient del mig enfonsat és la prova de la calidesa d'aquella llar."},"ICON-1576":{"nm":"Taula","de":"Us hi asseieu al voltant i ningú no ocupa la capçalera. L'estofat acabat de bullir, el xoc de les cullerades, tot el que ha passat avui s'aplega al centre. Quan s'estén una sola superfície rodona, fins i tot un dia dispers torna a asseure's en un sol lloc."},"ICON-1577":{"nm":"Armari","de":"Cada cop que canvia l'estació, de dins en vessen històries velles. Vestits d'escenari i roba de cada dia espatlla contra espatlla, darrere la porta tancada la roba espera el seu proper torn. Només en obrir la porta queda decidit, per fi, el dia que es vestirà avui."},"ICON-1578":{"nm":"Mirall","de":"Tant l'elogi com el defecte els retorno amb la mateixa honestedat. El lloc de l'última revisió abans de sortir a l'escenari; davant meu, la gent tria l'expressió i endreça la postura. L'amic més sincer mai no diu ni una sola paraula."},"ICON-1579":{"nm":"Tocador","de":"A cada calaix petit hi dorm una cara diferent. Un pot per a l'escenari, un pot per al dia a dia, un pot d'edició limitada guardat amb cura. T'asseus davant del mirall, i a poc a poc comences decidint, abans que res, qui seràs quan surtis avui per la porta."},"ICON-1580":{"nm":"Catifa","de":"El tacte que els peus descalços toquen primer decideix la temperatura de l'habitació. Les marques de seure-hi tots plegats a picar i rebolcar-se hi queden com a borrissol. Un moble que treballa des del lloc més baix, escalfant el terra fred un pam més."},"ICON-1581":{"nm":"Cortina","de":"Quant matí deixar entrar el decideixo jo. Si em recullo una mica, el sol entra allargat; si em tanco del tot, fins i tot dormir més estona es torna perdonable. Estar dreta entre la finestra i l'habitació, regulant en silenci la quantitat de llum, és sempre la part que se m'encomana."},"ICON-1582":{"nm":"Làmpada","de":"La mateixa habitació esdevé una hora del dia ben diferent segons el color de la llum. La llum groga allarga el vespre, la llum blanca desperta l'alba amb claredat. Una maga de la mida d'una palma que, amb un sol interruptor, canvia furtivament l'estat d'ànim del dia."},"ICON-1583":{"nm":"Rellotge de paret","de":"El so de la busca dels segons només se sent en una habitació silenciosa. Com més s'aprofundeix l'assaig, més m'oblides, i de sobte alces la vista i, sense adonar-te'n, fora de la finestra ja és de matinada. Sense culpar mai el temps que ha passat, simplement assenyalo en silenci el següent instant."},"ICON-1584":{"nm":"Gerro","de":"Encara que les flors es marceixin, jo no deixo el meu lloc buit. Un recipient que guarda una estona un sentiment rebut; mentre hi hagi una mà que canviï l'aigua, la taula continua lluminosa. Fins i tot quan sóc buit, resto dret amb la forma de qui espera algú."},"ICON-1585":{"nm":"Marc de pòster","de":"Penjar a la paret una cara estimada també requereix cura. Un lloc on el sol no toca de ple, un sol clau perfectament anivellat. Un full de paper ajagut amb compte darrere el vidre és el primer a saludar-me cada matí en entrar a l'habitació."},"ICON-1586":{"nm":"Tauler de fotocards","de":"Si les ordeno alfabèticament o per ordre de llançament—aquest dilema feliç ja és l'inici del fandom. Una sola casella buida és el lloc del o la preferida que encara no s'ha trobat. A mesura que s'omple una targeta rere l'altra, el tauler es converteix en una petita crònica ben meva."},"ICON-1587":{"nm":"Suport per al bastó lluminós","de":"Treu les piles, mànec cap amunt. Fins i tot en l'angle en què s'inclina i es dreça hi ha el seu truc. Esperant el proper crit que ha de venir, el bastó apaga aquí mateix la llum i ajeu el cos endreçat. Descansar bé és el que fa que s'encengui més brillant."},"ICON-1588":{"nm":"Prestatge de trofeus","de":"A la primera fila hi va el més antic. Des de l'estatueta d'un petit concurs fins a la copa d'un gran escenari, s'arrengleren no per alçada sinó per l'ordre del cor. Cada cop que els netejo, el tremolor d'aquell dia dalt l'escenari em torna a la punta dels dits."},"ICON-1589":{"nm":"Cistella de pícnic","de":"Obres la tapa i l'olor del sol de primavera s'escapa primer. Gimbap, un termos i una sola estora s'apilen amb cura, a punt per anar al camp. Els passos de qui em porta són, no sé com, sempre un pam més lleugers que de costum."},"ICON-1590":{"nm":"Testet petit","de":"Un pam d'ampit de finestra em basta. Un petit verd que suporta amb generositat fins i tot quan sovint t'oblides de regar-lo. En un racó de l'escriptori d'algú atrafegat, jo desplego cada dia una fulla més, passant en silenci les salutacions d'avui."},"ICON-1591":{"nm":"Test gran","de":"Mentre creix la meva alçada, la persona creix amb mi. Quan les fulles amples que ocupen un racó de la sala d'estar reben el sol i fan ombra, l'estació entra també, d'amagat, a l'habitació. Una recompensa que només coneix qui no oblida regar."},"ICON-1592":{"nm":"Joc d'espelmes aromàtiques","de":"En l'instant que encens el ble, l'aire de l'habitació s'assossega un graó. L'aroma s'escampa a poc a poc, escalfant i deixant sortir el cansament que ha quedat d'ahir. Amb una sola flama petita, tancar el final d'un dia atrafegat com un ritual silenciós."},"ICON-1593":{"nm":"Mini-nevera","de":"Obres la porta a última hora de la nit i una llauna de beguda freda em dona la benvinguda. Un petit brunzit em fa l'allotjament buit una mica menys solitari. No puc portar una casa gran, però per fer-me càrrec d'una matinada amb gana, no hi ha res com jo."},"ICON-1594":{"nm":"Barret xarxa de libèl·lules","de":"En el moment que te'l poses al cap, un camp d'estiu et segueix per les espatlles. La xarxa rodona filtra amb suavitat la llum del sol, i a cada pas l'olor de l'herba es gronxa suau. Un barret que t'envolta amb tota una estació, vàlid encara que no atrapis ni una sola libèl·lula."},"ICON-1595":{"nm":"Bossa de xarxa de recol·lecció","de":"Penjada a la cintura, esdevé una companya de recol·lecció. Estrènyer una mica l'obertura perquè allò que has atrapat no torni a escapar-se és el primer truc après al camp. Una sola bossa de tela lleugera abraça amb fermesa la collita d'un dia."},"ICON-1596":{"nm":"Pot d'observació d'insectes","de":"Per a un convidat que només s'hi queda una estona, els forats d'aire són el més important—això ho sé. Un petit camí per respirar foradat a la tapa, una sola fulla d'herba estesa al fons. Tornar-lo al bosquet un cop acabada l'observació també forma part del parell."},"ICON-1597":{"nm":"Capsa d'agulles entomològiques","de":"Fins i tot en el sol angle en què es clava una agulla de biaix hi viu una tècnica. Massa fonda es trenca, massa superficial trontolla, així que cal repartir amb precisió la força de la punta dels dits. Una capsa que guarda en silenci la cura de qui vol contemplar llargament una vida petita."},"ICON-1598":{"nm":"Tapa de terrari","de":"Vetllar la frontera entre dins i fora és la meva feina. Tancada massa fort, s'ofega; deixada massa fluixa, es perd el camí, així que sempre deixo un buit com una ratlla obliqua. Protegir és, sens dubte, diferent de tancar."},"ICON-1599":{"nm":"Plat d'alimentació per a papallones","de":"Poses al mig cotó xopat d'aigua ensucrada i les ales s'hi apleguen. El truc és fer-lo poc fondo i ample, a una profunditat on les petites potes no s'enfonsin. Un sol plat convoca en silenci els convidats que s'aturen una estona en un jardí assolellat."},"ICON-1600":{"nm":"Làmpada atrapainsectes","de":"Deixada encesa tènuement en la foscor, petites ales s'apleguen seguint la llum. La claror, suau; el lloc, allunyat de la gent. Un reclamista de la mena més amable, que assossega força la nit d'estiu que brunzia."},"ICON-1601":{"nm":"Etiqueta adhesiva d'insecte","de":"Sis potes i un parell d'antenes: dins un retall de paper no més gran que una ungla, hi dorm una petita vida. Enganxa-la suaument a la cantonada d'una llibreta i, entre les pàgines, s'obre en silenci un pam de prat."},"ICON-1602":{"nm":"Etiqueta de permís de recol·lecció","de":"Abans d'agafar la xarxa per a insectes, la persona gran pregunta primer: quants, i fins on. Aquesta petita etiqueta traça una línia amable entre la curiositat exaltada i una promesa que cal complir."},"ICON-1603":{"nm":"Pot d'esquer","de":"Obre la tapa i puja una olor d'alba, freda i una mica peixatera. El que crida els peixos potser no és l'esquer, sinó un cor que sap esperar en silenci fins que el flotador tremola."},"ICON-1604":{"nm":"Capsa de flotadors de pesca","de":"Un petit armari on dormen flotadors de colors, compartiment rere compartiment. Alguns són el matí d'un llac quiet, altres el migdia d'un corrent brau. Per a cada expressió de l'aigua, hi ha ben plegada la parella adequada."},"ICON-1605":{"nm":"Debanadora de sedal","de":"No cal enrotllar el fil deixat anar als dits. Torna'l a debanar, ordenat, en aquesta eina rodona, i fins i tot els embulls es desfan sense fer soroll. S'assembla al gest que endreça un dia que s'ha anat afluixant."},"ICON-1606":{"nm":"Extractor d'hams","de":"Només qui s'ha punxat traient un ham enganxat amb les mans nues reconeix aquesta eina. Un camí que fa menys mal, tant a la petita criatura com a la punta dels meus dits. La consideració sempre comença en aquests detalls tan petits."},"ICON-1607":{"nm":"Funda de pala de cloïsses","de":"Una capa que embolica la fulla de la pala just desenterrada del fangar. Perquè el fang i l'aigua salada no roseguin el tall, s'hi glissa suau un petit descans, prim i tou, entre el mar i l'eina."},"ICON-1608":{"nm":"Targeta de taula de marees","de":"Quan puja l'aigua i quan es retira, una targeta de la mida d'una mà t'ho explica en silenci. Un petit calendari on algú ha copiat l'antiga promesa que es van fer la lluna i el mar."},"ICON-1609":{"nm":"Raspall netejador d'aquari","de":"Escombra suaument les algues verdes enganxades al vidre, i la llum torna a filtrar-se en el petit món de sota l'aigua. Il·luminar el dia d'algú, sovint, flueix així de callat."},"ICON-1610":{"nm":"Xip de temperatura d'aquari","de":"Un sol número parpelleja i, quan s'atura al grau just, els peixos per fi es queden tranquils. Una escletxa d'escalfor ni massa freda ni massa calenta. La cura arriba fins i tot als llocs que no es veuen."},"ICON-1611":{"nm":"Tub d'observació de vida marina","de":"Un petit convidat s'hi queda una estona, dins el tub transparent. Compta amb calma l'aleta dorsal i torna'l al mar. Observar no és posseir, sinó demanar-lo prestat per un instant."},"ICON-1612":{"nm":"Raspall per a fòssils","de":"El que desperta el gra de la pedra adormida des de fa desenes de milions d'anys no és un martell, sinó la punta suau d'un raspall. Davant d'un temps que s'esmicolaria si t'apressessis, la cura esdevé la cortesia més profunda."},"ICON-1613":{"nm":"Tap de pinzell d'excavació","de":"Quan la punta del pinzell s'asseca del tot, ni la terra cau amb netedat. Un petit capell manté humit l'alè del pinzell. Una mà que estima les seves eines fa el primer pas de l'excavació."},"ICON-1614":{"nm":"Placa de mostres estratigràfiques","de":"En un pam de terra, centenars d'anys s'apilen capa sobre capa. Recull-la amb calma en aquesta placa, i els dibuixos del temps, invisibles fins ara, tracen les seves línies i emergeixen a poc a poc."},"ICON-1615":{"nm":"Safata de fragments d'os","de":"Estén els fragments dispersos, compartiment a compartiment, i una vida un dia escampada pel vent va a les palpentes trobant de nou el seu lloc. Restaurar és el treball de preguntar, amb tendresa, per un ordre perdut."},"ICON-1616":{"nm":"Cinta de restauració","de":"Una tira prima que uneix el lloc trencat. No amaga la cicatriu, sinó que l'abraça amb tendresa i la manté ferma. Demostra, en silenci, que fins i tot allò trencat pot tornar a ser sencer."},"ICON-1617":{"nm":"Cobertor de placa d'exposició","de":"Un full que cobreix suaument, darrere el vidre, l'etiqueta perquè no s'esvaeixi. Hi ha el desig que la breu frase de qui va viure, i on, encara es pugui llegir amb claredat molt més enllà del temps."},"ICON-1618":{"nm":"Etiqueta de magatzem","de":"Una cambra profunda on dormen tresors que mai no han sortit a la llum. Tot allò que hi ha dins porta una petita etiqueta amb el seu nom, perquè, encara que no ocupin un lloc lluminós, mai no siguin oblidats."},"ICON-1619":{"nm":"Sobre de donació al museu","de":"Algú lliura, sense dir res, allò que ha aplegat tota una vida. El que hi ha dins d'aquest sobre no és un objecte, sinó un cor guardat durant molt de temps. Compartir esdevé l'exposició més duradora, i il·lumina algú."},"ICON-1620":{"nm":"Xip de numeració de mostres","de":"Just al lloc on ho vas recollir, hi assignes en silenci un petit número. Quan, i on, ho vas trobar per primera vegada. Un descobriment que no queda anotat s'esvaeix aviat com la boira del matí."},"ICON-1621":{"nm":"Ampolla de fragment de meteorit","de":"Un fragment que va caure travessant el cel nocturn ha quedat atrapat dins una ampolla de vidre. Aquell raig de llum que es va apagar abans que poguessis demanar un desig ara torna a espurnejar, suaument, a la teva mà."},"ICON-1622":{"nm":"Cordó de carilló de petxines","de":"Enfila en un fil les petxines aplegades una a una a la platja i penja-les del ràfec. Cada cop que hi passa el vent, amb un lleuger dringar, el mar d'aquell estiu segueix el seu camí en silenci fins dins de casa."},"ICON-1623":{"nm":"Gota d'arc de Sant Martí","de":"Una sola gota que es forma, arrodonida, a la punta d'una fulla després que hagi parat de ploure. Dins aquesta rodonesa hi cap tot el cel i els set colors, ben arrodonits. Hi ha moments en què la cosa més petita conté el paisatge més ample."},"ICON-1624":{"nm":"Ampolla de recollida de boira","de":"Vaig portar a casa una ampolla plena de la boira de l'alba, dels vessants de la muntanya. Agafa-la amb la mà i és freda, entelada d'un blanc lletós. Una petita, tendra cobdícia de tenir a prop, per un instant, allò que no es pot retenir."},"ICON-1625":{"nm":"Copa recull-rosada","de":"Una petita copa que recull, gota a gota, la rosada que les fulles d'herba han aplegat durant tota la nit. No arriba ni a un glop, però hi reposa, quieta, la part més neta i pura del matí."},"ICON-1626":{"nm":"Agulla de cinta de la brisa","de":"Una cinta lligada exactament a imatge del solc que ha deixat el vent en passar. Posa-te-la als cabells i, a cada pas, una brisa suau et segueix balancejant-se. La lleugeresa d'un dia de primavera, fermada amb calma en una sola agulla."},"ICON-1627":{"nm":"Càpsula del so de les onades","de":"Acosta-la a l'orella amb calma i les onades del mar llunyà arriben rodolant. És com si algú hagués segellat amb cura, dins una petita càpsula, aquell so que de petit guardaves en una closca de cargol de mar."},"ICON-1628":{"nm":"Fragment d'estrella de sorra","de":"Agafa un grapat de sorra a la platja de nit, i s'hi barregen, espurnejant, engrunes d'estrella. Ningú no es molesta a preguntar si van caure del cel o si les onades les van polir fins a fer-les tan fines."},"ICON-1629":{"nm":"Xip de registre meteorològic de l'illa","de":"El cel de l'illa canvia d'humor unes quantes vegades al dia. Anota clar, boira i xàfec, ordenadament, en un petit xip, i podràs tornar a desplegar avui mateix el cel d'ahir."},"ICON-1630":{"nm":"Kit d'escales per a penya-segat","de":"Un graó, i un altre, per pujar i baixar el pendent escarpat. Encaixa les peces disperses i fins i tot un penya-segat esdevé un passeig tranquil. Obrir un camí és deixar preparat, per endavant, el proper pas d'algú."},"ICON-1631":{"nm":"Rotlle de patró de camí de terra","de":"Un rotlle que ha pres el gra mateix d'un tou camí de terra. Desplega'l amb un lleuger xiuxiueig, i un caminet rural que fa venir ganes de caminar-hi descalç queda estès, quiet, sota els teus peus."},"ICON-1632":{"nm":"Xip de patró de camí empedrat","de":"El dibuix de les lloses que un dia van empedrar els carrerons antics queda intacte dins un petit xip. A cada pas, tic-tac, les passes d'un poble antic reviuen sota la punta dels peus."},"ICON-1633":{"nm":"Tros de tanca de platja","de":"Un sol tram de la tanca baixa alçada a la sorra perquè les onades no la puguin travessar. Un petit i callat guardià de frontera, dret allà on traça una línia amable entre el mar i la sorra."},"ICON-1634":{"nm":"Pedaç de restauració de gespa","de":"Un tros de verd que es posa suaument sobre un lloc trepitjat i pelat. En pocs dies, les herbes s'agafen de la mà i omplen el buit. La natura sempre sap com guarir-se ella mateixa."},"ICON-1635":{"nm":"Estaca marcadora de rec","de":"Una estaca que indica, per endavant, el camí que seguirà l'aigua. Perquè l'aigua de pluja no vagi errant sense saber on anar, un petit senyal clavat a terra hi resta dret, en silenci, fins i tot els dies de pluja."},"ICON-1636":{"nm":"Peça de pont petit","de":"Una sola peça d'un pont minúscul que uneix les dues ribes d'un rierol. Entre aquesta banda i l'altra, la promesa que sempre pots travessar comença en silenci amb aquesta petita peça."},"ICON-1637":{"nm":"Tap de barana de mirador","de":"Al punt més alt de l'illa, una peça d'acabat que embolica l'extrem d'aquesta barana. Sosté i protegeix, en silenci, el lloc que toquen més sovint les mans de qui s'ha aplegat per contemplar la llunyania."},"ICON-1638":{"nm":"Base de foguera","de":"Abans de posar-hi la llenya, un lloc que sosté les brases perquè no s'escampin. A sobre, les nits de xerrar tranquil·lament mirant les estrelles hi cremen càlides durant molt, molt de temps."},"ICON-1639":{"nm":"Rotlle de mostres de paper pintat","de":"L'ambient d'una habitació comença en una sola paret. Desplegar un petit rotlle per triar un color és dibuixar amb calma, per endavant, quina mena de dies vols viure d'ara endavant."},"ICON-1640":{"nm":"Xip de mostra de paviment","de":"Calcula primer amb la punta dels dits el tacte del terra que tocaran els peus descalços. Càlid o fresc: en aquest sol petit xip hi penja, en silenci, la calidesa dels dies que hi viuràs d'ara endavant."},"ICON-1641":{"nm":"Joc de ganxos de sostre","de":"En el moment que pengis un sol ganxo a la biga, el sostre buit esdevé un lloc que espera algú. Un carilló de vent, o un test? Aquest petit ganxo de ferro aguanta el pes, però què hi pengis ho decideix el cor de qui hi viu."},"ICON-1642":{"nm":"Làmina tintada per a finestres","de":"La llum del migdia és massa sincera, així que vesteixes la finestra amb una capa fina. La llum del sol entra tal com és, però les vores s'estoven suaument, i tot el que hi ha a l'habitació es torna dòcil en un to d'albercoc. No és tapar, sinó fer que la llum s'escampi amb tendresa."},"ICON-1643":{"nm":"Cobertor de timbre","de":"Dient que fins i tot el timbre que prem un convidat necessita roba, algú li va posar una coberta rodona. Fa de barrera contra la pluja i la pols, i sobretot és la primera i petita boca rodona que ofereix la salutació: «Aquí hi viu algú»."},"ICON-1644":{"nm":"Faristol de llibre de visites","de":"Un faristol alçat perquè cadascú que vingui hi escrigui el seu nom abans de marxar. Abans que s'assequi la tinta, una línia de salutacions raja de la punta de la ploma. A mesura que s'acumulen, línia a línia, les passes de qui hi ha passat, el quadern buit esdevé, sense adonar-se'n, l'àlbum més gruixut de la casa."},"ICON-1645":{"nm":"Agulla de col·locació de mobles","de":"El lloc de l'escriptori sobre el qual dubtaves si moure'l: una sola agulla el clava a terra i ho decideix. Un petit clau que sosté amb suavitat els peus del moble. Un lloc, un cop triat, és un lloc que t'acaba agradant, assenteix en silenci el terra de fusta."},"ICON-1646":{"nm":"Marc d'etiqueta d'emmagatzematge","de":"Què hi ha guardat i on, el calaix mai no ho pot dir. Per això s'encaixa una etiqueta amb un nom en un marc quadrat perquè parli en el seu lloc. En el moment que una sola etiqueta troba el seu lloc, els compartiments desordenats recuperen el seu nom i s'assosseguen."},"ICON-1647":{"nm":"Vareta difusora d'ambient","de":"El perfum que amara la punta de la vareta s'escampa lentament cap amunt. Ara és lavanda, ara un prat després de la pluja. Quan un fil invisible d'olor renova l'aire de l'habitació, el cansament d'un dia sencer es deslliga suaument de les espatlles de qui acaba de tornar a casa."},"ICON-1648":{"nm":"Pinça per a sobres de llavors","de":"Les llavors comprades a la primavera i mai del tot sembrades queden fermament pinçades, sobre inclòs, amb una pinça. Si s'escapa fins i tot un sol gra, la propera temporada creix una fila més curta. Dins d'aquest petit tancament hi dorm sencer l'hort de l'any que ve."},"ICON-1649":{"nm":"Safata de planter","de":"Omple cada compartiment de terra per fer la primera cambra d'un brot jove. Una vida per cada forat, alumnes de primer curs que creixen en fila, ben arrenglerats. Mira-hi dins i un matí de verd que es passa llista, aplegat en petits grups, torna a començar cada dia sobre la safata."},"ICON-1650":{"nm":"Agulla marcadora de reg","de":"«Tinc set.» Com que el test no pot parlar, un petit rètol clavat a la terra envia el senyal en el seu lloc. Quan canvia de color, és hora de regar. El més petit intèrpret entre planta i persona cap sencer en aquest bastonet d'un pam."},"ICON-1651":{"nm":"Lligadura de suport per a plantes","de":"Una tija que creix podria oscil·lar sota el seu propi pes, així que la fermes suaument a un tutor amb un lligam tou. Massa fort i s'ofega, massa fluix i cau, així que la mà que lliga necessita just la tendresa adequada. Fins i tot créixer necessita algú a prop."},"ICON-1652":{"nm":"Xarxa antiinsectes","de":"Una xarxa finament teixida bloqueja en silenci les petites boques que van a la caça de les fulles tendres. Deixa passar el vent i la llum del sol i només desvia el que faria mal, un porter invisible. L'hort es manté en pau gràcies a la cura teixida en aquestes malles atapeïdes."},"ICON-1653":{"nm":"Targeta mesuradora de llum solar","de":"Quant de sol hi arriba? Planta una sola targeta al parterre i pregunta-ho amb calma. Com més fosc es torna el seu color, més llum ha captat avui. Aquest petit tros de paper reparteix un lloc per a l'infant que estima el sol i per al que se sent bé a l'ombra."},"ICON-1654":{"nm":"Tira de prova de pH del sòl","de":"Toca la terra amb una tira de prova i, del rosa al blau, la terra confessa el seu interior en color. On no és ni massa àcida ni massa amarga, les arrels respiren més tranquil·les. Els sentiments amagats de la terra es llegeixen, quadre a quadre."},"ICON-1655":{"nm":"Etiqueta de cistella de collita","de":"El que has collit avui, és enciam o tomàquets cirerol? Penges una etiqueta amb el nom a cada cistella. En un matí de collita carregat d'olor de terra i de verd, en el moment que s'hi enganxa una etiqueta, aquella cistella esdevé el primer senyal del camí cap a la taula."},"ICON-1656":{"nm":"Pot de conservació de llavors","de":"Guardes les llavors collides aquest any en un pot de vidre i les envies a la primavera que ve. Tanca la tapa i el temps s'atura un instant, mentre els petits grans esperen el seu torn en la foscor. És un pot com una carta enviada a través de tota una estació."},"ICON-1657":{"nm":"Cinta d'empelt","de":"Ajunta una branca tallada i una de nova, embolica-les amb cinta, i a poc a poc les dues esdevenen un sol cos. La saba torna a fluir a través del punt trencat, la ferida es va guarint a poc a poc. Unir, al capdavall, és l'acte d'acceptar el gra de l'altre."},"ICON-1658":{"nm":"Funda de tisores de podar","de":"Poses un petit capell a la punta esmolada de les tisores. Mentre descansa la mà que ha aclarit les branques, la fulla no perd el tall i la mà no es fa mal. Dient que fins i tot una eina que ha acabat la feina necessita pijama, l'hort adorm les seves eines amb cura."},"ICON-1659":{"nm":"Classificador de llavors de flors","de":"Balsamina, portulaca, flor de les quatre: llavors diferents de nom i de color obtenen cadascuna la seva pròpia cambra, compartiment a compartiment. Si es barregen, a la primavera no sabràs qui és qui. Els petits separadors dins la caixa dibuixen per endavant el plànol d'un jardí que encara no ha florit."},"ICON-1660":{"nm":"Safata amb rodes per a test","de":"Posa-hi quatre rodes i fins i tot un test pesant surt a passejar seguint el sol. A l'est de bon matí, a l'ombra al migdia. El verd que abans quedava fixat pel seu pes ara rodola i, tot el dia, va a la recerca del millor racó, seguint la llum."},"ICON-1661":{"nm":"Lligam guia per a enfiladisses","de":"Un circell palpa l'aire buit, sense saber on anar, i el lligam el guia suaument pel camí correcte. Amunt, i més amunt encara. Dona-li un lloc on agafar-se i, sorprenentment, la planta agafa aquesta mà. Fins i tot créixer necessita un guia."},"ICON-1662":{"nm":"Suport de targeta de llenguatge floral","de":"La targeta clavada al costat d'una flor porta les paraules que aquella flor ofereix. L'hortènsia diu sinceritat, la margarida diu innocència. Perquè caminar pel parterre esdevingui un passeig de lectura de cartes, un petit suport presta amb calma una veu a la flor muda."},"ICON-1663":{"nm":"Tap de rètol de jardí","de":"Perquè el vent i la pluja no esborrin la lletra, poses un capell transparent sobre el rètol del jardí. «Aquí, tomàquets», «aquí, alfàbrega». Els noms que podrien haver-se esvaït es mantenen nítids, i així, encara que passi un any, l'hort no oblida ni un sol membre de la seva família."},"ICON-1664":{"nm":"Cullera per a fertilitzant","de":"Quan afegeixes nutrients a la terra, la cobdícia només crema les arrels. Per això, una cullerada, exactament aquesta quantitat. La petita cullera n'agafa la quantitat justa i et recorda: un cor que fa créixer bé les coses sempre ve de dits que saben ser mesurats."},"ICON-1665":{"nm":"Broquet de boira","de":"Gira el broquet i el raig es dispersa cap avall com boira. Una fulla tendra, abans maltractada per un doll violent, ara alça suaument el cap sota gotes com de rosada. La mateixa aigua esdevé una salutació ben diferent segons com se li dona."},"ICON-1666":{"nm":"Got mesurador de menjar","de":"Un got, dos gots. Mesures l'àpat d'un amic amb cura, no a ull. Massa i el deixarà, massa poc i es quedarà trist, així que calcules just la quantitat justa. L'amor, de vegades, arriba en la forma d'un mesurament acurat."},"ICON-1667":{"nm":"Funda de raspall de muda","de":"En temporada de muda, una funda embolica amb cura la pelussa suau enredada al raspall. Posa un capell al raspall un cop acabat el raspallat i l'endemà comença fresc i sedós també. La lluentor d'un company de casa creix, en silenci, a partir d'aquests petits endreçaments."},"ICON-1668":{"nm":"Tap de tallaungles","de":"Poses una petita tapa a la punta esmolada del tallaungles, perquè l'eina, un cop acabada la feina, no arany les altres coses del calaix. Un cop passat el temps de cures, arrupir l'eina i deixar-la a descansar completa un cicle sencer de cura."},"ICON-1669":{"nm":"Penjoll de collar","de":"Penja un sol penjoll brillant al collar i el mateix camí de sempre es torna una mica més especial. Un petit ornament que llueix al sol. No és vistós, però ja és senyal suficient que aquest petit és un membre estimat de la família d'algú."},"ICON-1670":{"nm":"Targeta de salut de mascota","de":"Ha menjat bé avui? Li fa mal res? Anotes cada dia una línia sobre la jornada del teu company a la targeta. Quan l'estat d'un membre de la família que no pot parlar queda escrit, el cor que en té cura també es fa més minuciós i ferm."},"ICON-1671":{"nm":"Funda de coixí per dormir","de":"Vesteixes el coixí de dormir amb roba nova i suau. Treu la tela gastada de rodolar-hi i fregar-s'hi i puja una olor de pelussa assecada al sol. Mantenir net el lloc on més sovint es jeu és una devoció diària per a qui viu amb tu."},"ICON-1672":{"nm":"Agulles de tanca petita","de":"Claves petites agulles al llarg de la vora del parterre per alçar una tanca baixa. No és un «no passis» sever, sinó una frontera amable que diu que aquí és on pertanyen les flors. Amb una línia a respectar, poden créixer tranquil·les dins d'ella."},"ICON-1673":{"nm":"Pot de llaminadures per fer amistat","de":"Fins i tot un petit vergonyós dreça les orelles al soroll d'aquest pot en sacsejar-lo. A dins hi ha un grapat de llaminadures que obren el cor. Com que les petites promeses guanyen a les paraules a l'hora d'apropar-se, el so de dringar avança primer."},"ICON-1674":{"nm":"Etiqueta de registre de passejades","de":"Quin camí avui, i fins on? Anota el registre a l'etiqueta com si fos un punt de sutura. Les passes aplegades esdevenen un mapa, i els mapes aplegats esdevenen records. Cada dia caminat junts s'apila, ordenat, en aquesta petita placa."},"ICON-1675":{"nm":"Plat de menjar per a ocells","de":"Deixa el plat al marc de la finestra, escampa-hi uns quants grans de mill, i convidats sense nom hi arriben volant un rere l'altre. El toc-toc del picotejar, l'aleteig sobtat. És una taula ben petita on un sol grapat ofert porta un petit concert cada matí."},"ICON-1676":{"nm":"Pot d'observació d'esquirols","de":"Dins el pot transparent et trobes amb els ulls rodons d'un esquirol. Amb les galtes plenes d'aglans, i el cap decantat: quin espectacle. Sota la promesa de mirar-hi un instant i deixar-lo anar de seguida, intercanvies una breu salutació amb un petit tros de vida salvatge."},"ICON-1677":{"nm":"Motlle de guix per a petjades","de":"Vesses guix tou per emmotllar una petita petjada. Mentre esperes que endureixi, el temps del pati també s'atura un instant. Aquella petjada d'un pam, destinada a desaparèixer quan creixi, el motlle blanc l'alça com per sempre i te la posa, quieta, entre les dues mans."},"ICON-1678":{"nm":"Tap d'objectiu per a observació nocturna","de":"Tanques una petita tapa sobre l'objectiu que mira dins la nit. Perquè el vidre que ha vist estrelles i nius esperi la propera nit sense ni un gra de pols. Fins i tot els ulls que veuen clar en la foscor necessiten una coma de repòs durant el dia."},"ICON-1679":{"nm":"Senyal de protecció de niu","de":"Si descobreixes un niu entre les branques, en comptes d'acostar-t'hi, hi plantes un senyal. «Aquí hi viu una família d'ocells, si us plau, silenci.» Observar sense envair: aquell tendre pas enrere és el que manté el niu més segur de tot."},"ICON-1680":{"nm":"Xip enregistrador de sons animals","de":"El cant del matoll d'herba, el refilet sota el ràfec, els insectes de la nit: no els atrapes dins el xip, sinó que els demanes prestats un instant. Una petita capsa de so que, en reproduir-se, reviu fins i tot l'aire d'aquell moment. Perquè tot allò que un dia es va sentir mai no acabi de desaparèixer."},"ICON-1681":{"nm":"Funda de telescopi d'observació","de":"Just abans que un ocell aixequi el vol, el bosc conté l'alè un instant. En aquell moment de silenci, un sol tros de tela estès sobre l'objectiu protegeix la claredat de la llunyania, intocada ni per una empremta."},"ICON-1682":{"nm":"Corretja de càmera per a camí de bosc","de":"Cada cop que puges el corriol escarpat del bosc, la càmera toca lleugerament el pit. El batec del cor i el so de l'obturador oscil·len al mateix ritme, i aquesta sola corretja aguanta amb fermesa aquells moments contra el pit."},"ICON-1683":{"nm":"Targeta de guia natural","de":"Fins i tot una simple mata d'herba té un nom, la targeta t'ho fa saber amb calma. Un cop allò que passaves per alt sense conèixer rep un nom, el camí de muntanya de sobte s'omple, amablement, de cares conegudes."},"ICON-1684":{"nm":"Pedaç de reparació de vela","de":"Fins i tot la tela que rep el vent amb tot el cos guarda cicatrius. Amb un sol petit pedaç posat suaument sobre l'estrip, la vela torna a guanyar-se el dret d'abraçar la mar oberta."},"ICON-1685":{"nm":"Tauler de pràctica de nusos","de":"Amunt, avall, un cop més al voltant: l'ordre que les mans han memoritzat esdevé un nus. En una nit en què la tempesta colpeja la coberta, aquell únic procediment lliga persona i vaixell com una sola cosa."},"ICON-1686":{"nm":"Tap de cadena d'àncora","de":"No et prenguis a la lleugera aquest petit capell que es posa a l'extrem de la cadena. Com que el rovell creix en secret per dins, un sol tap plantat contra el vent del mar allarga, en silenci, la vida de l'àncora."},"ICON-1687":{"nm":"Bandera marcadora de rumb","de":"Un dia en què la boira és tan espessa que esborra el camí, una sola bandera parla el trajecte en el seu lloc. Un punt de color ondejant al vent afluixa, per fi, les espatlles encarcarades del timoner perdut."},"ICON-1688":{"nm":"Clauer de cabina","de":"Sobre el mar que es gronxa, una petita anella penja a la porta estreta de la cabina. Mentre la clau guarda el seu lloc, una cambra on tornar mai no queda tancada per a tu."},"ICON-1689":{"nm":"Estoig impermeable per a mapes","de":"Sota la pluja, un mapa de paper esborra primer el camí. Mentre un full es manté eixut a dins de l'estoig transparent, fins i tot un trajecte xop no acaba mai de perdre el rumb."},"ICON-1690":{"nm":"Ble de llàntia de vaixell","de":"L'oli que el ble absorbeix lentament floreix, finalment, en flama. Un punt de llum sobre la coberta, i en aquell petit tremolor la distància immensa de la mar nocturna s'acosta, discreta."},"ICON-1691":{"nm":"Tela de senyal de socors","de":"A una distància on la veu no arriba, la mà que agita ben amunt una tela vermella va més lluny que les paraules. Aquest sol tros de roba talla el vent i crida, en el teu lloc, que aquí hi ha algú viu."},"ICON-1692":{"nm":"Agulla indicadora del vent marí","de":"Qui sap d'on bufa el vent decideix el rumb. En la sola direcció que assenyala amb calma una petita agulla, el destí de tota la navegació d'avui hi ve a recolzar-se."},"ICON-1693":{"nm":"Funda de pala plegable","de":"Plega el tall i cobreix-lo, i fins i tot la pala diligent recupera l'alè un instant. L'última cosa que fa la mà que ha remogut tota la terra és tenir cura del tall de demà perquè no perdi el fil."},"ICON-1694":{"nm":"Estoig de brúixola de butxaca","de":"L'agulla sempre apunta cap al nord sense tremolar, però el que protegeix aquesta agulla és l'estoig robust. Com més sovint s'ha perdut el camí algú, més cara guarda el sentit de la direcció."},"ICON-1695":{"nm":"Xarxa d'estris de càmping","de":"Penges els plats rentats a la xarxa perquè s'assequin al sol del matí. Un dia de càmping comença amb el so de l'aigua eixugant-se, i aquesta petitesa omple la tenda de tranquil·litat."},"ICON-1696":{"nm":"Targeta de permís de càmping","de":"El permís per quedar-se una nit en aquesta muntanya. En el moment que un sol full de paper és a la teva mà, fins i tot el bosc desconegut esdevé el teu aliat per un instant i acull amb calma la teva petita tenda."},"ICON-1697":{"nm":"Cordó de banderoles de camí","de":"Lliga una bandera a cada cruïlla i el camí de tornada no s'escamparà en la foscor. Un petit senyal deixat per qui ha anat al davant empeny suaument l'esquena de les passes que segueixen."},"ICON-1698":{"nm":"Pot impermeable per a llumins","de":"Un llumí es nega amb una sola gota i calla per sempre. Segellat dins un pot on no hi entra ni una gota d'aigua, la guspira espera eixuta i quieta, només per a la nit més freda."},"ICON-1699":{"nm":"Filtre portàtil d'aigua","de":"Fins i tot l'aigua tèrbola que fa dubtar s'aclareix un cop passa per aquest filtre. Un petit dispositiu que deixa de banda el dubte abans que la set: la certesa que es pot beure ja és, per si sola, un glop de pau."},"ICON-1700":{"nm":"Paquet de manta d'emergència","de":"Plegada, cap a la palma de la mà; desplegada, esdevé l'escalfor d'una persona. Perquè la paraula «emergència» pesi una mica menys, la manta espera en un racó de la motxilla, sempre a punt per escalfar-se."},"ICON-1701":{"nm":"Braçalet de senyal nocturn","de":"En un camí de muntanya caigut en la foscor, un canell escampa una llum callada. Aquella petita banda que anuncia el lloc de cadascú lliga amb dolcesa, amb un fil invisible, els qui caminen junts."},"ICON-1702":{"nm":"Adhesiu de casc de miner","de":"L'adhesiu enganxat al casc és l'altre nom del miner. En la galeria profunda on fins i tot la llum és preciosa, reconeixes amb afecte un company per aquell petit dibuix atrapat a la llum del llum."},"ICON-1703":{"nm":"Agulla de senyal de veta","de":"Allà on has trobat una veta, hi claves suaument una agulla. Un sol punt que brilla tot sol en la foscor diu amb amabilitat a qui vingui després que comenci a excavar des d'aquí."},"ICON-1704":{"nm":"Regle mesurador d'esquerdes","de":"Mesurar l'escletxa que parteix la paret és una paciència lenta i tenaç. S'ha eixamplat un pam més des d'ahir? El petit número que indica el regle detecta un enfonsament abans que arribi."},"ICON-1705":{"nm":"Paper de calc de motiu antic","de":"Poses el paper sobre el motiu gravat a la pedra i hi piques la tinta amb molta suavitat. En el moment que el tacte d'una mà de fa mil anys sorgeix en gra negre, el calc asseu per un instant el temps passat davant teu."},"ICON-1706":{"nm":"Estoig de moneda antiga","de":"Aquest petit tros de metall, adormit i preservat del rovell, guarda l'última veu d'una nació desapareguda. Tota una època habita en una sola moneda, envellint lentament dins l'estoig transparent."},"ICON-1707":{"nm":"Suport per a fragment de cristall","de":"Fins i tot un cristall que tanca la llum al seu interior necessita on recolzar-se. En el moment que reposa suaument sobre un petit suport, allò fràgil desplega per fi tota la seva resplendor."},"ICON-1708":{"nm":"Fragment de mapa de cova","de":"Un mapa esquinçat mostra només, de reüll, la meitat del seu secret. Fins al dia que trobis el tros que falta, aquest full manté mig amagada, en algun lloc de la cova, la resta del camí."},"ICON-1709":{"nm":"Mosquetó de descens amb corda","de":"Per confiar el teu cos al buit d'un penya-segat, primer has de confiar del tot en aquest mosquetó. Penjar el teu pes d'un sol tros d'acer fred: la confiança, per naturalesa, és així de feixuga."},"ICON-1710":{"nm":"Permís d'excavació","de":"Un sol full de paper amb el segell ben clar que autoritza a cavar la terra. Per despertar allò enterrat, primer cal demanar permís: l'excavació ensenya en silenci que tot comença amb cortesia."},"ICON-1711":{"nm":"Paravent portàtil","de":"Desplegat d'esquena al vent, s'obre un tros de quietud enmig de la plana atapeïda de ràfegues. Darrere aquesta capa fina es resguarda una petita espurna, i el cansat troba un moment de repòs."},"ICON-1712":{"nm":"Funda d'ulleres per a tempesta de sorra","de":"Per molt ferotgement que giri la sorra, cal preservar la vista fins al final. Una fina funda sobre les ulleres es converteix en el coratge d'obrir els ulls i seguir caminant, fins i tot enmig de la tempesta."},"ICON-1713":{"nm":"Safata per a visites de pluja","de":"L'aigua de pluja regalima de les puntes de les sabates del convidat que ha arribat. Una safata posada quietament vora l'entrada acull, en silenci i amb calidesa, uns peus freds i xops."},"ICON-1714":{"nm":"Etiqueta refrescant per a onades de calor","de":"Una petita etiqueta que refreda amb suavitat la calor del migdia. Penjada de la bossa, guarda la seva frescor i, just quan comencen a perlar les gotes de suor, ofereix d'amagat un grapat d'ombra."},"ICON-1715":{"nm":"Cinturó escalfamans per a onades de fred","de":"Un cinturó càlid que s'enrotlla un cop al voltant de la cintura. Quan la calor de l'escalfamans s'escampa per la part baixa de l'esquena, fins i tot la plana crua del ple hivern es fa una mica més suportable."},"ICON-1716":{"nm":"Bosseta absorbeix-humitat","de":"La humitat rosega les coses sense fer soroll. Mentre una petita bosseta dins la capsa xucla en silenci la humitat, allò que estimes conserva la seva forma, sec i intacte."},"ICON-1717":{"nm":"Funda de sabata per al fang","de":"Hi ha moments en què les sabates, tot i travessar el fangar, han de quedar netes. Aquesta fina cobertura que atura el fang fa més lleugers els passos que creuen el llindar de casa en tornar."},"ICON-1718":{"nm":"Funda de fanal per a boira marina","de":"Quan la boira de mar intenta engolir el fanal sencer, aquesta funda recull amb calma el gra de llum que s'escampa. Fins i tot en un alba boirosa, una llum del port es nega, fins al final, a apagar-se."},"ICON-1719":{"nm":"Agulla d'avís de llamps","de":"Quan els núvols negres es fan baixos, una sola agulla dona l'avís primer. La paraula d'ajupir-se abans que caigui el llamp: la humilitat davant la natura sempre val més aprendre-la abans d'hora."},"ICON-1720":{"nm":"Punt de llibre per a receptari","de":"Un petit punt de llibre que es posa entre les pàgines obertes d'un llibre de cuina. Quan busques a les palpentes la línia que has perdut davant del foc, el gust de la mare també es desperta en aquella pàgina."},"ICON-1721":{"nm":"Pal dosificador de condiments","de":"La mare sempre deia només \"un pessic\". Calcular a ull mai no podia ser exacte, i tanmateix aquell gust de mà mai no va vacil·lar. Mesurant la sal amb aquest pal, arribes a veure que el que havia madurat més que cap mesura no era el càlcul, sinó l'amor."},"ICON-1722":{"nm":"Banda per a tapa de fermentació","de":"Sabies que el gerro també respira? Quan aquesta banda abraça bé la tapa, el dedins i el defora comencen a parlar-se a poc a poc. Només després d'aquells dies sense pressa, l'espera guanya finalment el nom de sabor."},"ICON-1723":{"nm":"Fitxa d'etiqueta per a maduració","de":"Una petita fitxa amb la data en què es va fer, escrita amb pulcritud. La lletra es va esvaint mentre el que hi ha a dins, al contrari, s'aprofundeix. Anotar-ho com si volguessis oblidar-ho, i un dia treure-ho de sobte: la maduració és una promesa que es compleix així."},"ICON-1724":{"nm":"Colador de brou","de":"Un brou clar arriba només després de colar-lo, i tornar-lo a colar. Mires com el sedàs reté els trossos i deixa passar només l'essència en silenci, i l'antiga dita de cuina—que la profunditat s'acumula allà on has tret alguna cosa—et arriba a través dels dits."},"ICON-1725":{"nm":"Drap de llevat per a massa","de":"Estens amb suavitat un drap sobre la massa. Mentre el llevat s'infla afanyosament sota aquella penombra, aprens per primera vegada la tendresa de les coses que creixen en silenci allà on ningú les veu."},"ICON-1726":{"nm":"Agulla per netejar ingredients","de":"Una petita agulla que separa les fibres del porro i subjecta bé l'all. Netejar és com una primera salutació als ingredients, així que com més acuradament els despulles, més s'il·lumina un to la taula del vespre."},"ICON-1727":{"nm":"Pinces d'emplatat","de":"On col·locar l'últim mos del plat: al final, ho decideixen aquestes pinces. En aquell breu instant en què una mà experta dubta mig temps en l'aire, un àpat es converteix, de sobte, en un quadre."},"ICON-1728":{"nm":"Funda tèrmica per a carmanyola","de":"La carmanyola que rebies a la porta de l'escola havia d'estar calenta fins que sonés la campana del migdia. La calidesa retinguda dins aquesta funda no es refreda, tan profunda com el cor de qui havia estat dret davant el fogó des de la matinada."},"ICON-1729":{"nm":"Val d'invitació a sopar","de":"\"Vine a menjar a casa un dia d'aquests.\" Hi ha res més dolç que dir això? Sense cap promesa grandiosa, només seure a la mateixa taula: la invitació més antiga que es pot fer en coreà cap en aquesta única targeta."},"ICON-1730":{"nm":"Fitxa de reserva de taula","de":"Escrius el nom i reserves el lloc. Mentre una petita fitxa lliga per un temps una taula buida a algú, l'hora acordada s'acosta a poc a poc, lenta com passes."},"ICON-1731":{"nm":"Targeta de valoració de tast","de":"Cares que fan una mossegada i, amb tota seriositat, atorguen estrelles. La línia sincera escrita amb pulcritud en aquesta targeta és el renyament més càlid que existeix per fer el pròxim plat encara més bo."},"ICON-1732":{"nm":"Cinta d'agraïment per a carmanyola","de":"Enrotlles una cinta al voltant de la carmanyola buidada del tot i la retornes. Fins i tot qui mai no va aconseguir dir gràcies lliga, almenys en aquest nus, el sentiment que no va poder pronunciar."},"ICON-1733":{"nm":"Etiqueta d'avís d'al·lèrgens","de":"Aquesta petita etiqueta guarda en silenci la taula d'algú. Explicitar amb claredat què conté és un altre nom per a l'hospitalitat: una cura que arriba fins i tot allà on no es veu."},"ICON-1734":{"nm":"Cullera del record de gust","de":"Aquell gust que va quedar molt de temps a la punta de la llengua era, en realitat, el paisatge d'aquell dia. Quan una cullerada et porta d'un cop a la cuina de la infància, sembla que la memòria és una cosa que recull i guarda el cor, no l'estómac."},"ICON-1735":{"nm":"Fitxa del menú d'avui","de":"Què menjo avui. Davant la pregunta més difícil del món, sempre perdem. Gires aquesta fitxa i deixes el menú en mans del destí, i el cor, sorprenentment, es fa lleuger i content."},"ICON-1736":{"nm":"Campaneta de taula comuna","de":"Toca la campana un cop i la família escampada per les habitacions es reuneix en un sol lloc. Aquell so de campana sobre la taula rodona és la traducció més entranyable de les paraules \"Ja està a punt, veniu de pressa.\""},"ICON-1737":{"nm":"Targeta de l'ordre de postres","de":"El dolç sempre arriba l'últim. Aquesta targeta manté aquella promesa que ningú sap qui va fer. Un petit i tendre amfitrió de la taula, que guarda el cim de la gana per a una mossegada de postres."},"ICON-1738":{"nm":"Fitxa de regateig","de":"Al bell mig del mercat, \"faci'm una mica de rebaixa\" i \"ja hi perdo diners\" xoquen amb afecte. Aquesta fitxa és el rebut d'un client de tota la vida, on el regateig acaba, al capdavall, en rialles."},"ICON-1739":{"nm":"Agulla de control d'existències","de":"Repasses en silenci els prestatges del magatzem, trobes els buits i hi claves una agulla. Saber què queda i què s'ha exhaurit: la gran feina de portar una casa sempre comença amb aquesta petita revisió."},"ICON-1740":{"nm":"Raspall de neteja de parada","de":"Al vespre, quan el mercat ja ha tancat, el so baix d'escombrar una parada buida s'estén per la botiga. En els dits que netegen per endavant el lloc que demà tornaran a omplir hi ha una diligència que tanca el dia amb pulcritud."},"ICON-1741":{"nm":"Targeta de la recomanació d'avui","de":"\"Avui aquest és bo.\" Una targeta que el propietari treu d'amagat. En aquella recomanació que empeny amb suavitat l'espatlla del client que dubta què triar, hi cap, ordenat, l'orgull de tot un dia."},"ICON-1742":{"nm":"Targetó de segells per a clients habituals","de":"Omple'n deu i el següent va de franc. Aquest targetó, amb les caselles de segells omplint-se a poc a poc, és una altra cara de la paraula \"habitual\", perquè venir sovint vol dir, al final, que t'agrada."},"ICON-1743":{"nm":"Clip de llibre de bescanvis","de":"Un clip que aplega i reté els registres de les coses bescanviades i retornades. Com més ha anat i vingut, més gruixut es fa el llibre, i amb aquell gruix també s'engreixa la confiança bastida amb els veïns."},"ICON-1744":{"nm":"Etiqueta de venut","de":"En el moment que aquesta etiqueta es posa a l'últim que queda, el cor s'omple d'una manera estranya. És un petit comiat, com un \"adéu\", per a una cosa que se'n va cap a la taula d'algú, cap a un racó d'una habitació."},"ICON-1745":{"nm":"Cistella d'article reservat","de":"Una cistella amb el teu nom hi ocupa una casella del prestatge. Aquell únic lloc reservat per endavant et diu, en silenci, quan entres: \"T'he estat esperant tota l'estona.\""},"ICON-1746":{"nm":"Estora de taulell d'embolicar","de":"L'estora estesa sobre el taulell d'embolicar és un escenari per a mans afeinades. En el breu temps que es plega el paper i es lliga el cordill amb pulcritud, una cosa corrent es transforma, de sobte, en el regal d'algú."},"ICON-1747":{"nm":"Nota de promesa de visita","de":"\"Demà passaré.\" Una nota escrita en una línia i encaixada suaument a l'escletxa de la porta. Fins i tot quan no us heu vist les cares, la promesa viatja en un sol full, i arriba abans que la persona, per esperar en silenci."},"ICON-1748":{"nm":"Cistella de regal per al veïnat","de":"La cistella que passa per damunt del mur sempre porta l'excusa \"n'he fet una mica massa.\" L'afecte coreà travessa cap a aquest costat així, fent veure que és abundància, com si no hi donés importància."},"ICON-1749":{"nm":"Bústia de notícies del poble","de":"Les notícies del poble, grans i petites, s'acumulen amb pulcritud dins aquesta caixa. Qui s'ha traslladat de nou, quina casa organitza una festa: uns quants fulls de paper es reuneixen per transmetre el pols tranquil del veïnat."},"ICON-1750":{"nm":"Segell d'agraïment per visita","de":"Prems fermament, amb un sol segell, la gratitud per algú que ha vingut. Aquella única taca de tinta escampada al paper roman al seu lloc més temps que les paraules \"no ho oblidaré.\""},"ICON-1751":{"nm":"Targeta d'elogi a l'amabilitat","de":"Una targeta on anotes en silenci l'amabilitat que algú t'ha ofert avui i la retornes. En un poble que es pren la molèstia de posar per escrit petites tendreses, les coses bones no paren de fer voltes i tornar."},"ICON-1752":{"nm":"Segell per a carta de disculpa","de":"Com una poma ben vermella i madura, unes disculpes només es poden oferir després d'haver madurat prou. Aquest segell premut fermament al sobre és la marca del coratge que va sostenir fins al final un \"ho sento\" que costava de dir."},"ICON-1753":{"nm":"Quadre de tasques compartides","de":"Un sol full escrit en columnes de qui s'encarrega de què. Una feina massa feixuga per fer sol es fa molt més lleugera quan se n'hi reparteixen els noms: qui ha treballat colze a colze ho sap."},"ICON-1754":{"nm":"Cinta de gustos del veïnat","de":"Marques en silenci amb cintes de colors diversos allò que li agrada a un veí. Recordar els gustos d'algú és la confessió més silenciosa que existeix del fet que l'aprecies, sense necessitat de dir-ho mai."},"ICON-1755":{"nm":"Anella de placa d'invitació","de":"Una sola anella penjada a la placa anuncia \"avui rebem visita.\" És un senyal de la mida d'una palma, però hi penja un cor obert de bat a bat, ja a punt per acollir algú."},"ICON-1756":{"nm":"Braçalet d'entrada al festival","de":"Una banda descolorida que vas portar posada dies i dies, massa preuada per treure-te-la. Només quan et la van fermar al canell va començar de veritat el festival. A dins hi dorm, sencer, un dia que mai no va acabar de acabar-se ni després d'acabar."},"ICON-1757":{"nm":"Portaentrades per a focs artificials","de":"Just abans que el cel nocturn esclati, l'entrada dins aquest portaentrades reté fort el batec del cor. És una promesa agafada fins que la palma sua, tot per aquell instant en què el primer foc s'obre amb un esclat."},"ICON-1758":{"nm":"Plat de contemplació de la lluna","de":"Hi va haver nits que semblava que havies recollit la lluna plena sencera en un plat. Poses fruita fresca i songpyeon amb primor en aquest plat i fas una reverència a la lluna, i un cor rodó arriba fins a l'extrem del cel."},"ICON-1759":{"nm":"Agulla de guant per a festival d'hivern","de":"Encara que les mans se't quedin balbes a la neu, els guants no paren de lliscar-te dels canells. Només quan aquesta agulla queda ben fixada al puny, pots finalment córrer pel festival d'hivern a plaer."},"ICON-1760":{"nm":"Targeta de llavors de primavera","de":"Unes quantes llavors adormides dins la targeta esperen, cadascuna, la seva primavera. Les enterres a la terra i germinen sense falta, com una promesa: sembla que tot començament brolla d'un sol punt petit i sòlid."},"ICON-1761":{"nm":"Segell de platja d'estiu","de":"Una onada estampa fermament la seva marca a la sorra i es retira lliscant. Sabent que aviat s'esborrarà, hi deixa igualment un petit senyal que algú ha estat aquí. L'estiu sempre s'estampa un cop, ben clar, i després se'n va amb l'olor salada."},"ICON-1762":{"nm":"Cinta de collita de tardor","de":"La mà que lligava els grans acaba fermant, al final, una cinta amb primor. Un únic nus que recull amb cura la suor de tot un any. Encara que els camps es buidin, la tardor ofereix una salutació més, en el seu color més bell, com una posta de sol."},"ICON-1763":{"nm":"Bafarada de foto commemorativa","de":"\"Gràcies per haver vingut fins aquí.\" Una salutació que mai no va arribar a dir-se en veu alta s'infla en rodó sobre el paper. Un petit tros de cor rodó, que presta amb suavitat una veu al silenci congelat en una fotografia."},"ICON-1764":{"nm":"Agulla de mapa de festival","de":"Un senyal que algú va clavar perquè no et perdessis en el gran recinte. Encara que els peus corrin primer cap al so de la música popular, aquesta única agulla porta amb suavitat el tu que et perdies fins al lloc acordat."},"ICON-1765":{"nm":"Clau mestra de l'àlbum","de":"El que queda tancat no és el disc, sinó el temps segellat dins seu. El tremolor de la primera gravació, l'alba de l'última mescla. Fas girar la clau lentament i la porta d'aquella cambra, coneguda només per qui la va fer, s'obre amb un grinyol."},"ICON-1766":{"nm":"Targeta de llista de cançons","de":"L'ordre de les cançons en un sol full és, en realitat, l'ordre del cor. On es farà un nus a la gola, on caldrà agafar aire: el paper ja ho sap tot. Una emoció que puja abans fins i tot de sentir la primera nota."},"ICON-1767":{"nm":"Etiqueta de revisió d'àudio","de":"Només qui ha rebobinat el mateix passatge un centenar de vegades enganxa aquesta etiqueta. Un cop més, només un cop més. Vora el segell d'aprovació s'hi amaga la nit d'algú que va dubtar de les seves pròpies orelles fins a la matinada."},"ICON-1768":{"nm":"Etiqueta de reserva anticipada","de":"Una promesa d'esperar quelcom que encara ni tan sols ha sortit al món. En el moment que l'etiqueta s'hi enganxa, un lloc buit queda reservat en silenci sota el nom d'algú. Fins i tot una espera plena d'il·lusió té el seu número de torn."},"ICON-1769":{"nm":"Adhesiu de segell de primera edició","de":"S'assembla al vell gest de cobrir un gerro amb hanji i segellar-lo amb cola. Un únic full que jura mantenir les coses tal com eren al principi. Sabent que desapareixerà en el moment de despegar-lo, no pares de mirar-ne l'acabat cada vegada més estona."},"ICON-1770":{"nm":"Fitxa de calendari de retorn","de":"Afegeix un cercle al calendari i les nits que falten fins aquell dia s'escurcen una casella. La data del retorn és nítida a la petita fitxa que tens a la mà. Per a qui espera, el temps es compta així, amb la mà."},"ICON-1771":{"nm":"Funda de foto de concepte","de":"Abans que el proper concepte n'esborri el color, un full transparent en desa el gra amb cura. Perquè no caigui en l'oblit quan canviï l'estació, guarda amb suavitat el color d'aquells dies, cantonades incloses."},"ICON-1772":{"nm":"Fitxa de revelació de teaser","de":"Just abans d'aixecar el vel, una petita moneda agafada a la palma. En el moment que la treus, la primera escena tancada s'obre un pam cap al món. Revelar, al final, és una qüestió de qui allarga la mà primer."},"ICON-1773":{"nm":"Suport d'exposició d'àlbum","de":"En el moment que un suport baix aixeca lleugerament un disc, un exemplar corrent es converteix en la protagonista de l'exposició. Un tendre secundari que sosté per darrere, en silenci, l'angle on la llum toca de manera més bella."},"ICON-1774":{"nm":"Passi per a showcase de debut","de":"Un únic passi amb les paraules \"us ho presentem per primera vegada\" gravades. Des del llarg passadís del darrere de l'escenari fins al primer aplaudiment del públic, aquest passi et fa travessar el llindar tremolós del debut."},"ICON-1775":{"nm":"Fitxa de marca escènica de debut","de":"Palpes amb la punta del peu, en silenci, la fitxa enganxada al terra. Una casella que el cos coneix primer, fins i tot sense mirar. En el moment que arribes exactament al punt memoritzat, el tremolor de les puntes dels dits es converteix, per fi, en un moviment nítid."},"ICON-1776":{"nm":"Targeta de discurs d'agraïment","de":"Fins i tot la frase corrent \"tot és gràcies a vosaltres\" deixa de ser corrent quan es escriu amb una lletra tremolosa. Unes quantes línies apuntades per endavant, per por que l'emoció les faci oblidar. La sinceritat, de vegades, es recolza en una sola targeta."},"ICON-1777":{"nm":"Full de reserva de sessió de fotos","de":"Un full amb la data en què cal posar-se davant l'objectiu, escrita amb pulcritud. Un horari per preparar a poc a poc la millor cara possible. A mesura que s'omple cada casella, també s'allarguen les nits passades davant del mirall."},"ICON-1778":{"nm":"Full d'inscripció al fan club","de":"Un full d'entrada on escrius, tímidament, el teu nom i el teu cor en una sola línia. Dir que t'agrada alguna cosa sempre és difícil, però aquest full escriu aquelles paraules per tu, amb pulcritud. Una primera signatura en decidir estar junts."},"ICON-1779":{"nm":"Full de revisió de regal de debut","de":"Un tacte que repassa un per un, imaginant la persona que el rebrà. Que no s'hagin fet malbé les cantonades, que no hi falti cor. Un regal ja és estimat un cop, abans fins i tot de lliurar-lo, quan es posa en marxa."},"ICON-1780":{"nm":"Marca de final d'escenari","de":"Just abans que caigui el teló, una marca posada al lloc on reposa la darrera pose. No tant un senyal de final com un petit punt que en lliga la fi amb primor. Només un escenari ben tancat n'obre un altre."},"ICON-1781":{"nm":"Agulla d'espera per a entrevista","de":"Una agulla que guarda en silenci la calma abans que comencin les preguntes. Durant el breu silenci d'escollir les respostes al cap, aquest petit senyal diu amb amabilitat, en el teu lloc: \"Encara no, però ja falta poc.\""},"ICON-1782":{"nm":"Sobre commemoratiu de debut","de":"Com aquell vell gest de posar una carta preciosa, sobre inclòs, a la mà de qui emprenia camí, una sola capa guarda amb cura el registre d'un primer escenari. El dia que l'obris, molt més endavant, també vessarà, de cop, el tremolor d'aquell dia."},"ICON-1783":{"nm":"Palleta d'entrenament de respiració vocal","de":"Un exercici per treure l'aire llarg, en un sol raig, per la punta d'un tub prim. Cantar, al capdavall, és respirar ben governat: aquesta petita palleta t'ho recorda en silenci cada matí. Abans del so, el vent."},"ICON-1784":{"nm":"Fitxa de clic per a entrenament de ritme","de":"Tic, tic, tic: l'amic més honest del món. Et refrena quan t'apresses i t'empeny l'esquena quan t'endarrereixes. Gravar el ritme al cos és com una llarga conversa amb aquesta fitxa robusta."},"ICON-1785":{"nm":"Cinta de comprovació de línia de dansa","de":"On s'aturen les puntes dels dits, on s'obre l'espatlla: amb una sola cinta resegueixes en silenci la línia del moviment. Una línia de dansa ben traçada es manté recta i polida fins i tot allà on el públic no pot veure."},"ICON-1786":{"nm":"Targeta de retroalimentació d'expressió","de":"Aquella dita que fins i tot somriure s'ha d'aprendre. Un full que anota, a poc a poc, l'angle de les parpelles i l'alçada de les comissures. L'expressió que el mirall no va saber ensenyar, aquesta targeta te la diu amb amabilitat en el seu lloc."},"ICON-1787":{"nm":"Nota de flow de rap","de":"\"Aquí reposa un moment, allà ho aboca tot\": una nota que dibuixa per endavant el corrent de les paraules. Com més ràpid és el passatge, més clar ha de ser el camí de l'alè. Dins les fletxes traçades a corre-cuita hi viu i respira el ritme d'una estrofa."},"ICON-1788":{"nm":"Adhesiu de temperatura vocal","de":"La veu també té dies càlids i dies freds. Un petit senyal que tries pel color i enganxes per al gra d'avui. Escalfant i refredant per torns, el so es desperta cada dia a una temperatura una mica diferent."},"ICON-1789":{"nm":"Fitxa de rutina de descans","de":"Una moneda posada a la mà amb les paraules que descansar bé també és una destresa. La treus i pots aturar-te un moment sense culpa. Per a qui ha corregut sense parar, aturar-se és la decisió més valenta."},"ICON-1790":{"nm":"Agulla d'objectiu de creixement","de":"Una petita agulla clavada amb un \"provem d'arribar fins aquí.\" Encara que sembli lluny, a l'abast de la mà, creixes cada dia un pas cap allà. Un objectiu és com una tendra promesa que et fa senyals des de lluny."},"ICON-1791":{"nm":"Sobre d'avaluació setmanal","de":"Reculls la suor i les llàgrimes d'una setmana amb pulcritud dins un sol sobre i el lliures. El que has fet bé i el que et sap greu hi són, l'un al costat de l'altre. Obrir-lo és un petit deure lliurat al jo de la setmana vinent."},"ICON-1792":{"nm":"Llauna de peces decoratives d'escenari","de":"Darrere l'escenari resplendent hi viuen peces sense nom. Un cargol, una anella s'ajunten per fer surar les estrelles del sostre. Obre la llauna i és plena de la petita i pacient dedicació que sosté en silenci tota l'esplendor."},"ICON-1793":{"nm":"Tauler de concepte de vestuari","de":"Enganxant retalls de teixit i colors un a un, et proves per endavant una roba que encara no existeix al món. Un vestit d'escenari que es completa primer sobre el tauler. La imaginació sempre camina un pas per davant de l'agulla de cosir."},"ICON-1794":{"nm":"Fitxa de prova de color","de":"La mateixa roba fa una cara completament diferent segons la llum. Quin color somriu més radiant amb aquella persona, ho trobes provant fitxes una per una. L'harmonia és un descobriment al final d'una llarga comparació."},"ICON-1795":{"nm":"Tauler de mostres de cordons","de":"El que respon d'un pas ferm dalt de l'escenari és, sorprenentment, un petit cordó. Que no es desfaci, però tampoc que no molesti. La cavil·lació més tendra, feta al lloc més baix, triant entre cordons estesos segons el seu gra."},"ICON-1796":{"nm":"Sobre de revisió d'accessoris","de":"Com més brilla una cosa, més gran sembla un sol defecte. Un tacte que sosté els complements del sobre a la llum i els examina amb calma. Un cor que mira les coses petites fins al final és el que protegeix l'escenari."},"ICON-1797":{"nm":"Pegat de color per a cabell","de":"Una petita mostra per provar-se per endavant una nova estació als cabells. El color que tenyeix d'amagat un sol mèxol xiuxiueja en silenci la primera impressió del pròxim concepte. El canvi sempre comença en un lloc de la mida d'una palma."},"ICON-1798":{"nm":"Targeta de concepte d'ungles","de":"Un full que decideix per endavant els petits dibuixos que es pintaran a les deu puntes dels dits. Perquè el concepte transpiri, tènue, fins i tot en un gest, es vesteix amb cura fins el detall més insignificant amb una història."},"ICON-1799":{"nm":"Val de canvi d'estil","de":"\"I si avui em convertís en una mica diferent de la d'ahir?\"—un únic val que fa possible aquella línia. Cabell, roba o ambient, aquest val obre la porta plena d'il·lusió cap a una imatge nova."},"ICON-1800":{"nm":"Etiqueta d'ajust de talla","de":"Una etiqueta que anota amb cura els llocs a estrènyer i eixamplar fins que quedi just com cal. Com el vell gest que arreglava puntada a puntada la roba d'un fill, aquest petit ajust fa l'escenari un pam més còmode."},"ICON-1801":{"nm":"Targeta d'esbós de miniatura","de":"Un full que el color encara no ha tocat. Per sobre dels traços rugosos de llapis, intenta endevinar, en silenci, cap a on fluirà la pròxima escena. Més emocionant que l'obra acabada és sempre aquesta primera línia inacabada, com recorda la sala de muntatge silenciosa."},"ICON-1802":{"nm":"Adhesiu de consentiment de gravació","de":"«Puc sortir aquí?» En lloc de paraules, t'enganxes una petita marca rodona al pit. Un simple adhesiu estableix una promesa amable entre la càmera i el cor."},"ICON-1803":{"nm":"Xinxeta de posició per al mur de fotos","de":"Una petita xinxeta clavada en un racó de la paret. Marca per endavant qui s'hi posarà i on. Allà on es clava una xinxeta, un somriure s'atura i es converteix en una fotografia."},"ICON-1804":{"nm":"Fitxa de selecció de plans","de":"Un dit que assenyala un sol pla entre centenars. Quan aquesta fitxa es deixa caure, totes les expressions descartades han viscut, en certa manera, per a aquest únic fotograma. Triar sempre s'assembla a un comiat silenciós."},"ICON-1805":{"nm":"Sobre del rodatge","de":"Tot allò que passa darrere la càmera es guarda aquí. Tanca la solapa i les rialles, els errors i els badalls de son s'adormen junts. Sovint, el que acabes estimant més que l'obra final és el que hi ha dins."},"ICON-1806":{"nm":"Nota de petició d'edició","de":"«Un segon més aquí, i baixa una mica la música.» Una nota plena de tinta vermella. L'exigència d'algú ajusta el ritme del vídeo un compàs. La qualitat creix damunt d'aquests petits retocs."},"ICON-1807":{"nm":"Etiqueta de publicació programada","de":"Una petita marca en un vídeo que sortirà al món tot sol demà a les set del matí. Mentre tothom dorm, només la promesa roman desperta. El temps fixat per endavant mai sap arribar tard."},"ICON-1808":{"nm":"Funda del fotograma de miniatura","de":"Una funda que embolcalla la millor escena inicial. Plega bé les vores perquè cap empremta ni pols hi arribi. Fins que es mostra, la primera impressió es guarda amb aquesta cura."},"ICON-1809":{"nm":"Fitxa de durada del metratge","de":"Una petita fitxa que calcula quants minuts s'han filmat avui. Llarg no vol dir millor, ni curt vol dir lleuger. Saber trobar la llargada justa és el primer botó del muntatge."},"ICON-1810":{"nm":"Full de revisió de lemes d'ànim","de":"Un paper per repassar un cop més abans de cridar amb totes les forces. Una sola lletra equivocada i mil veus es dispersen. Darrere de l'aclamació, una mà invisible de correcció ha passat primer."},"ICON-1811":{"nm":"Funda de conservació per a fan art","de":"Un dibuix que algú ha fet tota la nit. Se li ofereix una petita casa transparent perquè no s'arrugui. Com si allò dibuixat amb el cor només pogués durar si es guarda amb el cor, la funda l'abraça sense dir res."},"ICON-1812":{"nm":"Cordill de classificació de cartes de fans","de":"Un cordill que lliga amb ordre les cartes acumulades segons qui les envia. En cada nus s'ordena l'enyor d'un dia. Encara que no es puguin respondre totes, aquí hi ha una mà que no vol deixar-ne perdre ni una."},"ICON-1813":{"nm":"Full d'inscripció per a l'intercanvi de productes","de":"«Hi ha algú que vulgui bescanviar amb la meva?» Un paper on hi escrius el cor tremolós i l'ofereixes. Pel simple fet de compartir el mateix gust, dues persones desconegudes es fan amigues per un moment."},"ICON-1814":{"nm":"Fitxa de seient per a l'animació en grup","de":"Una fitxa que assigna el lloc on s'asseuran, l'un al costat de l'altre, els qui vesteixen del mateix color. Quan els cors dispersos s'apleguen en una mateixa zona, el públic comença a cantar com una sola persona immensa."},"ICON-1815":{"nm":"Rebut de l'anunci d'aniversari","de":"Un únic rebut que es guarda després de penjar l'amor a la pantalla gegant. El que no hi consta, al costat de l'import, és la dedicació acumulada tota la nit. Aquest paper roman com a prova d'una celebració adreçada a una sola persona."},"ICON-1816":{"nm":"Coberta del llibre de missatges","de":"Una coberta que embolcalla un llibre fet de la lletra de moltes mans. Obre'l i les cal·ligrafies diferents es superposen en un sol cor. Per fora és pulcra, però per dins és plena d'un enrenou càlid."},"ICON-1817":{"nm":"Xapa de membre del club de fans","de":"Una petita xapa que només es dona a qui crida el mateix nom. En el moment de posar-se-la al pit, un afecte solitari es transforma en una promesa compartida per molts. La pertinença té aquesta forma rodona."},"ICON-1818":{"nm":"Fitxa d'ànim en línia","de":"Un punt de llum que unes mans llunyanes agiten a l'altra banda de la pantalla. La distància és immensa, però el ritme és exactament el mateix. És la prova que l'ànim arriba sense falta, fins i tot des d'un seient invisible."},"ICON-1819":{"nm":"Fragment de clau vella","de":"Un tros de metall amb la dent trencada. Ja ningú no recorda quina porta obria. El que sobreviu més temps que el lloc tancat és sempre aquesta meitat inútil d'una clau."},"ICON-1820":{"nm":"Mapa del passatge secret","de":"Un paper vell que dibuixa un camí amagat darrere l'heura. Les dreceres només les coneix qui les coneix. Quan es desplega, l'illa que semblava ordinària canvia de cara en secret i es converteix en escenari d'aventura."},"ICON-1821":{"nm":"Targeta de desxiframent de codis","de":"Una targeta que torna al seu lloc les lletres disperses i barrejades. Quan una línia encaixa, el següent secret fa un gest de crida. Fins i tot el nus que semblava impossible de desfer comença, al capdavall, per la primera lletra."},"ICON-1822":{"nm":"Cordill de la caixa segellada","de":"Un cordill lligat amb força, com dient que no s'obri. Només qui l'ha lligat sap què dorm dins del nus. El desig de deslligar-lo i el desig de protegir-lo queden lligats, l'un al costat de l'altre, en aquest únic fil."},"ICON-1823":{"nm":"Peça de trencaclosques de ruïnes","de":"Un petit fragment desprès d'un antic mur de pedra. Encaixa'l al seu lloc i l'habilitat d'algú de fa mil anys reviu a la punta dels dits. Aplegar allò que està dispers és la feina de tornar a unir el temps."},"ICON-1824":{"nm":"Retall de la llegenda de l'illa","de":"Un paper on s'han copiat a mà les històries antigues que voltaven per l'illa. Si són certes o no, poc importa. Una història que ha passat de boca en boca esdevé, per si mateixa, un anell de creixement de l'illa."},"ICON-1825":{"nm":"Pedra marcadora amagada","de":"Una pedra que sembla deixada a la vora del camí sense cap intenció. Només als ulls de qui la coneix indica, en silenci, la direcció. Com més profund vol amagar-se un secret, amb una cara més senzilla s'hi presenta."},"ICON-1826":{"nm":"Sobre de l'enigma","de":"Al defora no hi ha res escrit. Aquest instant just abans de trencar el segell és el més emocionant de tots. Fins que la resposta no és a les mans, totes les possibilitats encara viuen dins del sobre."},"ICON-1827":{"nm":"Tapa de la lupa del detectiu","de":"Una petita tapa que es col·loca amb cura a la punta de la lupa. Quan no s'hi mira a través, deixa que la lent descansi en silenci. Per veure bé, primer cal saber protegir bé; és una lliçó que el detectiu aprèn ben aviat."},"ICON-1828":{"nm":"Bitllet del bus circular de l'illa","de":"Un sol bitllet per pujar al bus que fa la volta a l'illa. L'última parada torna a ser el punt de partida. En un camí que, tot voltant, torna al mateix lloc, el paisatge sembla una mica nou cada vegada."},"ICON-1829":{"nm":"Etiqueta de lloguer de bicicleta","de":"Una etiqueta penjada del manillar d'una bicicleta llogada. S'atorga una llibertat breu fins que es torni. Quan s'acaba el temps de tallar el vent, aquesta etiqueta recull en silenci aquella promesa."},"ICON-1830":{"nm":"Passi d'embarcament per a un vaixell petit","de":"Un passi d'embarcament per pujar a un vaixell petit. Sobre la coberta que es gronxa, l'illa i l'illa s'apropen. Travessar el pas d'aigua sempre porta, alhora, un xic d'il·lusió i un xic de mareig."},"ICON-1831":{"nm":"Passador de la roda del carretó","de":"Un passador que subjecta amb fermesa la roda del carretó. Aquest petit tros de metall és el que fa rodar una càrrega pesant. La peça menys vistosa és sovint la que suporta, en silenci, més pes."},"ICON-1832":{"nm":"Fitxa del telefèric","de":"Una fitxa rodona que es deixa caure dins el telefèric que travessa l'aire. Quan els peus s'aixequen de terra, tota l'illa s'abraça d'un sol cop d'ull. Com més amunt es puja, més generós es torna el paisatge."},"ICON-1833":{"nm":"Braçalet d'embarcament per al globus aerostàtic","de":"Un braçalet que es posa al canell abans de pujar a la cistella. Quan la flama s'infla i la terra s'allunya, el cor també s'alleugereix. Enlairar-se vol dir deixar de banda el pes, encara que només sigui per un instant."},"ICON-1834":{"nm":"Fitxa de crida per al taxi aquàtic","de":"Una petita fitxa per cridar un taxi que circula sobre l'aigua. Alça la mà i un vaixell s'acosta tallant el corrent. Obrir un camí allà on no n'hi ha és, al capdavall, el coratge de qui crida primer."},"ICON-1835":{"nm":"Passi d'accés a l'inici del sender","de":"Un passi que es rep a la primera porta d'entrada a la muntanya. A partir d'aquí, les puntes dels peus decideixen el camí. Encara que el cim quedi lluny, només a qui travessa l'entrada se li promet aquell paisatge."},"ICON-1836":{"nm":"Clau de la taquilla del port","de":"Una petita clau que obre una taquilla al costat dels molls. Amb les mans alleugerides després de deixar la càrrega, contemples el mar. Tenir un lloc on deixar-ho tot per un moment és el que et presta el coratge per anar lluny."},"ICON-1837":{"nm":"Tapa del pot d'encurtits","de":"Una tapa de pot que tanca dins tot allò àcid. Ben tancada, els cogombres de l'estiu conserven el cruixent fins a l'hivern. El secret per vèncer el temps comença, al capdavall, per tancar bé les coses."},"ICON-1838":{"nm":"Etiqueta de l'assecador","de":"Una etiqueta que s'enganxa a les coses esteses per assecar-se en un sedàs. Si s'anota què s'ha estès i quan, l'espera no perd l'ordre. Fins i tot en el temps del sol i el vent, cal que hi hagi un torn."},"ICON-1839":{"nm":"Sobre d'encenalls per fumar","de":"Un sobre que conté trossos de fusta aromàtica. Obre la boca i una olor com de foguera saluda primer el nas. Un gust aprofundit pel fum s'obre lentament, només per a qui sap esperar."},"ICON-1840":{"nm":"Adhesiu d'aliment conservat","de":"Un adhesiu que s'enganxa al pot desitjant-li que aguanti bé tot l'any. El dia que es va fer i la dedicació hi queden escrits. Els aliments que es guarden llarg temps sempre van acompanyats d'una petita nota que vol recordar el gust d'aquell dia."},"ICON-1841":{"nm":"Etiqueta del rellotge de fermentació","de":"La fermentació no es refia del rellotge, perquè mesura el temps amb l'olor i no amb la busca dels minuts. En l'instant que una flaire agra arriba al nas, l'etiqueta assenteix en silenci: «ja està a punt». Fins i tot l'espera té la seva pròpia escala de marques."},"ICON-1842":{"nm":"Xinxeta de classificació del prestatge de la nevera","de":"Aquí hi ha el petit agent de trànsit de la nevera. Les verdures a dalt, els acompanyaments a baix, les sobres d'ahir a la primera fila. Planta-hi una sola xinxeta i la mà que sempre s'hi perdia en obrir la porta ja sap el camí."},"ICON-1843":{"nm":"Cinta escalfadora de la carmanyola","de":"La mare envoltava la carmanyola amb una cinta perquè l'escalfor no fugís abans del migdia. En deslligar la cinta, sota la tapa entelada, la cura del matí encara jeia calenta esperant-me."},"ICON-1844":{"nm":"Ampolla de maduració de salsa","de":"Un bon condiment mai no s'apressa. Concedeix, en silenci, temps perquè la salsa de soia i l'all es deixin amarar l'un a l'altre. En la foscor de l'ampolla, el gust s'aprofundeix a poc a poc, i la saviesa lenta del terrat dels gerres es trasllada a una petita ampolla."},"ICON-1845":{"nm":"Etiqueta de melmelada de temporada","de":"Maduixa a la primavera, albercoc a l'estiu, figa a la tardor. Una sola etiqueta escriu la temporada amb pulcritud sobre el pot. Obre la tapa en ple hivern i el sol de l'any passat es fon lentament, cullerada a cullerada."},"ICON-1846":{"nm":"Tauler d'insígnies de percentatge de col·lecció","de":"No cal comptar quantes n'has aplegat, perquè el tauler d'insígnies ja se n'encarrega d'ostentar-ho per tu. Cada casella buida que s'omple fa alçar una mica les espatlles: no és un número, és un rastre gravat de puntetes."},"ICON-1847":{"nm":"Targeta de casella no descoberta","de":"Un lloc que encara no s'ha trobat. La silueta de la targeta ofereix una promesa amb el contorn tan sols difuminat. Estar buit vol dir que aviat s'omplirà, així que la il·lusió sempre t'espera amb la forma d'un interrogant."},"ICON-1848":{"nm":"Segell de catàleg complet","de":"Aquell so del segell que cau amb un cop sec sobre l'última casella. Tanca el catàleg, obre la palma de la mà, i un punt de tinta vermella hi queda com una medalla de finalització. Aquell alleujament profund que només coneix qui ha col·leccionat fins al final."},"ICON-1849":{"nm":"Fitxa de color de raresa","de":"Encara que tinguin la mateixa forma, si el color canvia, la història canvia. Una sola fitxa traça, en silenci, la línia entre el que és corrent i el que és preciós. L'ull del col·leccionista sempre s'atura llarg temps davant aquesta subtil diferència de matís."},"ICON-1850":{"nm":"Val de bescanvi de duplicats","de":"Un altre cop, un altre. El dia que vas recollir per tercera vegada allò que ja tenies, aquest val et va allargar discretament la mà. Com un consol amable: els duplicats, si s'acullen en lloc de llençar-los, algun dia tornaran convertits en alguna cosa preciosa."},"ICON-1851":{"nm":"Placa numerada de caixa de col·lecció","de":"Numera cada caixa i el magatzem es converteix en una petita biblioteca. La número 17 guarda el que vas aplegar a la primavera, la número 23 el que vas recollir a la platja. Sóc un índex silenciós que ordena, línia a línia, els records dispersos."},"ICON-1852":{"nm":"Guia de disposició d'exposició","de":"Una exposició es construeix a mitges pel lloc. Els alts al fons, els brillants al centre. Segueix la guia i mou les peces amb la mà, i el prestatge desendreçat aviat recobra l'alè com una petita galeria."},"ICON-1853":{"nm":"Plomall per a peces de col·lecció","de":"Com més s'estima una cosa, més s'hi acumula la pols. Amb la punta suau del pinzell, amb suavitat, s'escombra fins i tot el remordiment d'haver-la deixat massa temps sense mirar. Mentre es neteja, els records adormits també brillen un instant de nou."},"ICON-1854":{"nm":"Val d'ampliació de capacitat d'emmagatzematge","de":"Si es col·lecciona prou, quedar-se sense lloc esdevé fins i tot una preocupació feliç. L'alleujament silenciós de veure un prestatge més afegit: no és cobdícia, sinó la prova que hi ha tantes coses que t'agraden."},"ICON-1855":{"nm":"Targeta de codi d'invitació d'amic","de":"Entregar aquest codi és la invitació més amable de totes, com dir «vine a jugar amb mi». El cor guardat en uns quants dígits. Només quan l'amic que l'ha rebut posa el peu a l'illa, comença, per fi, una història només per a vosaltres dos."},"ICON-1856":{"nm":"Clau del magatzem compartit","de":"La porta del magatzem mai no s'obre tota sola. Un pany que només gira quan dues mans, la teva i la meva, s'ajunten. Un espai compartit sempre porta penjada, amb forma de clau, una promesa compartida."},"ICON-1857":{"nm":"Etiqueta d'avís d'objecte perdut","de":"Un objecte perdut també és preciós per a algú. Escriure una sola línia, «és aquí», i penjar-la. L'etiqueta és un petit cordill que torna a unir, en silenci, un cor momentàniament perdut amb el seu amo."},"ICON-1858":{"nm":"Bandera de petició d'ajuda","de":"Demanar ajuda no és feblesa, és coratge. Quan la bandera s'alça, algú corre des d'algun lloc. El que es propaga més ràpid en aquesta illa no és el rumor, sinó les mans que s'estenen les unes cap a les altres."},"ICON-1859":{"nm":"Braçalet de contacte d'emergència","de":"Una petita tranquil·litat que es porta al canell. Passi el que passi, el número escrit aquí acudirà abans que ningú. Un company silenciós, oblidat en els dies corrents, que es torna el més fiable en el moment de necessitat."},"ICON-1860":{"nm":"Fitxa de repartiment de tasques","de":"Qui va a comprar i qui cuina: repartiu-vos les fitxes i no hi haurà res a discutir. El primer pas per fer alguna cosa junts comença decidint, amb amabilitat, la part de cadascú."},"ICON-1861":{"nm":"Full de creació col·lectiva","de":"El que sol no gosaries ni intentar es torna possible, com per art de màgia, quan molts s'apleguen. A mesura que els noms omplen el full un per un, les caselles buides es redueixen i els somriures creixen. La cooperació creix en silenci entre casella i casella."},"ICON-1862":{"nm":"Targeta de bones maneres en visita","de":"En entrar a casa d'algú altre, un es torna prudent des de la punta dels peus. El que hi ha escrit a la targeta no són grans normes, només petites promeses càlides com «alinea't les sabates, saluda primer»."},"ICON-1863":{"nm":"Campaneta de fi de festa","de":"Fins i tot l'alegria necessita un final perquè la següent es pugui esperar amb ganes. Quan sona la campana amb un dring, tothom recull les coses amb cara de recança. Una festa que sap acomiadar-se bé és la que roman més temps al cor."},"ICON-1864":{"nm":"Cinta de cantonada per a matalàs","de":"Per molt que allisis els llençols, les cantonades sempre acaben aixecant-se. Gràcies a una cinta que agafa amb fermesa les quatre cantonades, el llit obre els ulls cada matí ben polit, com una habitació d'hotel."},"ICON-1865":{"nm":"Cordill de botó del coll de l'edredó","de":"Sóc el cordill de botó que subjecta el coll de l'edredó. Per molt que et remenis tota la nit, l'aguanto ben fort perquè el coll no s'escapi. Un llit sense una sola arruga en despertar: aquesta és la recompensa del meu torn de nit."},"ICON-1866":{"nm":"Clip fixador de sobrematalàs","de":"El sobrematalàs prova d'esmunyir-se de seguida que en té l'ocasió. Cada cop, el clip mossega fort la cantonada i en manté el lloc. Un tossut silenciós que, des d'un racó invisible, manté el llit en ordre."},"ICON-1867":{"nm":"Allisador d'arrugues del llençol","de":"Les petites arrugues que el llençol acumula durant la nit s'assemblen, no se sap com, als plecs del cor. Igual que la roba que torna llisa amb un sol passi de l'allisador, voldria que un dia arrugat es planxés amb la mateixa suavitat."},"ICON-1868":{"nm":"Base de ventilació per a matalàs","de":"Fins i tot un matalàs necessita un espai per respirar. Quan la base obre a sota un camí per a l'aire, la humitat s'escapa i la sequedat s'hi filtra. Un bon son comença, en silenci, des de l'aire mateix que sosté l'esquena."},"ICON-1869":{"nm":"Solapa de la cremallera de la funda nòrdica","de":"Aquell aldarull de mitjanit quan el farciment no para de sortir mentre canvies la funda nòrdica. Cobreix un cop la cremallera amb la solapa i ja no et despertaràs enganxant-hi el peu. Una pau enorme, portada per una petita solapa."},"ICON-1870":{"nm":"Coixinet antiapilotament","de":"El farciment del coixí aviat s'amuntega cap a un costat i forma un petit turó. Quan el coixinet aguanta fermament l'espai, la planor es manté fins al final. Gràcies a això, cada nit torna sense falta una tou com de nou."},"ICON-1871":{"nm":"Ganxo elàstic de llençol de llit","de":"Un llençol sempre prova d'anar despenjant-se lentament cap a un costat. Enganxa els ganxos a les cantonades i estira'l ben tibant, i no es mourà per molt que et remenis tota la nit. La tibantor esdevé així, en silenci, el fonament del son profund."},"ICON-1872":{"nm":"Etiqueta de canvi de coixinera","de":"Quan de sobte no recordes si avui has rentat la coixinera, una simple etiqueta t'ho respon amb claredat. Un calendari que s'oblida sense parar de tant dormir i tornar a dormir; aquesta petita marca el recorda per tu amb diligència."},"ICON-1873":{"nm":"Punt de llibre per al diari de somnis","de":"Un somni que es dispersa entre els dits just en despertar-te, el punt de llibre el reté a la pàgina on el va marcar. Obre-la i el mar i el cel d'anit hi són encara: un petit pont posat suaument entre el son i l'escriptura."},"ICON-1874":{"nm":"Còdol de soroll blanc","de":"Una nit massa silenciosa sovint acaba despertant-te. Quan el còdol deixa anar un so suau com de pluja, el cor s'assossega lentament seguint-ne la textura. Una petita pedra que consola en silenci el silenci."},"ICON-1875":{"nm":"Xip de son amb detecció de temperatura","de":"Si el front està calent o els peus freds mentre dorms, el xip ho vetlla en silenci al teu costat. Gràcies a un guardià nocturn que troba amb suavitat la temperatura justa per al teu cos, el son flueix sense interrupció fins a l'alba."},"ICON-1876":{"nm":"Pinça de cortina opaca","de":"El sol del matí és tan diligent que no para de colar-se per l'escletxa de la cortina. Mossega fort els dos extrems amb la pinça i l'habitació torna a enfosquir-se com a plena nit. Un còmplice de confiança per a una dormida més."},"ICON-1877":{"nm":"Làmpada projectora de llum de lluna","de":"Apaga el llum i una lluna s'alça pel sostre. La llum suau que projecta la làmpada transforma l'habitació en un petit cel nocturn. El sentiment d'adormir-se contemplant la lluna, guardat just a la capçalera del llit."},"ICON-1878":{"nm":"Penjador de bosseta d'aromes per dormir","de":"Una bosseta amb lavanda i olor d'herba es balanceja suaument a la capçalera. Seguint la fragància que arriba al nas, les espatlles s'afluixen a poc a poc, i una sola bosseta convoca el son abans que el coixí."},"ICON-1879":{"nm":"Passador de capsa de música de bressol","de":"Roda la corda amb suavitat i una petita melodia se'n desprèn. La cançó de bressol que surt girant de la punta del passador s'assembla molt al ritme amb què l'àvia et donava copets a l'esquena. Cada nota fa una mica més pesades les parpelles."},"ICON-1880":{"nm":"Got de planta d'hidratació","de":"Sóc un got que fa créixer plantes amb aigua clara en lloc de terra. Mirar les arrels fines surant dins l'aigua fa que fins i tot l'aire de l'habitació es torni una mica més humit. Un petit pou verd, aturat damunt l'escriptori."},"ICON-1881":{"nm":"Ampolla de recol·lecció de fragments de somni","de":"Els somnis vessats en el son no tenen forma, i un cop et despertes s'escolen entre els dits. Aturar amb la tapa un fragment a punt de desaparèixer i retenir-lo fins al matí: el desig de recordar comença en un lloc així de petit."},"ICON-1882":{"nm":"Safata d'ulleres de capçalera","de":"En el moment de treure't les ulleres i deixar-les, curiosament, també baixa amb elles el cansament del dia. Aquest petit racó de la capçalera hi és per rebre aquell gest únic. Una safata que, abans de dormir, difumina en silenci el món."},"ICON-1883":{"nm":"Anella posavasos de tauleta de nit","de":"Una simple marca rodona que deixa un got d'aigua pot semblar insignificant, però a la veta de fusta de la tauleta li deixa una tara. Una petita anella que s'hi posa per evitar-ho. El cor que estima sempre treballa en silenci en aquests llocs invisibles."},"ICON-1884":{"nm":"Escaire per plegar l'edredó","de":"Fins i tot plegar un edredó ben quadrat i pulcre té la seva manera. Ajusta les cantonades seguint aquesta eina que marca l'angle i, fins i tot un cor esvalotat, s'allisa una mica. Un lloc endreçat és la salutació més correcta per obrir el dia."},"ICON-1885":{"nm":"Ganxo de capçalera per al cable de càrrega","de":"Un ganxo penjat a la capçalera perquè odiava com el cable de càrrega llenegava fins a terra durant la nit. El cable que s'ha anat carregant en silenci mentre dormies espera, ben ple, la punta dels teus dits al matí."},"ICON-1886":{"nm":"Cistella de berenar de capçalera","de":"Una cistella que aplega els queviures preferits a l'abast de la mà. Una preparació amable, prevista per a la gana que arriba tard a la nit. El cruixit de triar-ne un a les fosques resulta, sense saber ben bé per què, entranyable."},"ICON-1887":{"nm":"Ala suport de llibre per adormir-se","de":"Una ala que sosté amb suavitat la pàgina oberta perquè no perdis la línia encara que et venci la son. La pàgina que vas tancar just abans que se't tanquessin els ulls t'espera, demà a la nit, al mateix lloc."},"ICON-1888":{"nm":"Base de pedra per al despertador de capçalera","de":"Fins i tot el despertador que desperta el matí necessita un lloc propi que no trontolli. La base de pedra rodona en rep el pes amb fermesa i manté el seu lloc com una promesa que no llisca ni quan arriba l'alba."},"ICON-1889":{"nm":"Clau penjador d'antifaç de son","de":"Un clau per penjar l'antifaç que ha tapat la llum tota la nit, perquè de dia pugui respirar. Donar un lloc eixut a una tela que ja ha complert la seva feina: la petita cura s'hi filtra així, sense taca."},"ICON-1890":{"nm":"Pinça de llanterna de capçalera","de":"Una pinça que subjecta cap a on vulguis la petita llum que necessites a mitjanit. Mossega la llanterna a la vora del llit i la mà que buscava a les palpentes en la foscor es torna molt més tranquil·la. Un gest que decideix la direcció de la llum."},"ICON-1891":{"nm":"Cordill de subjecció de la cortina separadora","de":"Un cordill que sosté la cortina que divideix un espai compartit. Només és un full prim de tela, però a l'altra banda hi ha la nit privada d'algú. Una frontera amable que vetlla el son de l'altre en una habitació compartida."},"ICON-1892":{"nm":"Tauló repartidor d'endoll compartit","de":"Un tauló de fusta fet perquè molts es reparteixin l'únic endoll. Distribueix l'electricitat de manera equitativa perquè la nit de ningú no quedi a les fosques. Viure junts comença, al capdavall, compartint coses tan petites com aquesta."},"ICON-1893":{"nm":"Pedra de cessió de llum","de":"Quan la llum és massa forta, en lloc de paraules, li allargues discretament una pedra. «Podries baixar-la una mica?» Aquesta petita cosa transmet aquella frase per tu. La petició més suau d'una habitació compartida."},"ICON-1894":{"nm":"Fitxa de cessió d'hora de despertar","de":"Una petita fitxa que es passa a la palma de qui s'aixecarà primer. Qui dorm una mica més a trenc d'alba i qui es desperta abans, aquesta fitxa ho decideix sense discussions. El cor que decideix, amb la punta dels dits, l'ordre de la cessió."},"ICON-1895":{"nm":"Anella numerada de penjador compartit","de":"Anelles numerades assignades a penjadors que fan servir molts alhora. Perquè ningú es confongui sobre de qui és cada lloc, un simple número posa ordre en silenci. Una línia amable traçada en una vida quotidiana fàcil de barrejar."},"ICON-1896":{"nm":"Tapa de graó de llitera","de":"Una tapa que es col·loca sobre el graó que puja al pis de dalt. Perquè un peu descalç no la trobi ni freda ni relliscosa, vetlla per la seguretat d'un sol esglaó. Aquesta petita cura al final de l'escala sosté amb fermesa els somnis de dalt."},"ICON-1897":{"nm":"Braç penjador de paper higiènic compartit","de":"Un penjador en forma de braç per penjar el paper higiènic del bany compartit. Està col·locat perquè qualsevol pugui estirar-ne un tros amb una sola mà. Pot semblar insignificant, però és un gest que allisa el matí de molts."},"ICON-1898":{"nm":"Fitxa de torn de l'ambientador","de":"Una fitxa que anota a qui toca omplir de nou l'ambientador. Fins i tot un lleu fil de fragància és una promesa de fer-se'n càrrec per torns. Una bona olor no arriba de franc: floreix en el torn d'algú."},"ICON-1899":{"nm":"Interruptor del llum de nit compartit","de":"L'interruptor d'un llum de nit que molts encenen i apaguen junts. La mà que ha romàs desperta fins més tard és la que recull la llum en darrer lloc. Una promesa silenciosa de qui comparteix habitació, repartint-se una claror suau."},"ICON-1900":{"nm":"Encaix per a got al braç del sofà","de":"Un espai rodó excavat al braç del sofà. Pots deixar-hi el got un moment sense por que es vessi. Un lloc de descans necessita un lloc on posar un got perquè el cor, per fi, es pugui estirar tranquil."},"ICON-1901":{"nm":"Tirador de la Cremallera del Coixí","de":"Un petit tirador enganxat a la cremallera que obre i tanca el farciment del coixí. Una anella estalvia la feina de canviar la roba per rentar-la. Uns dits que tenen cura fins i tot de l'interior invisible: la tendresa de la llar sempre s'hi amaga."},"ICON-1902":{"nm":"Coixí Encaixat del Respatller","de":"Un coixí que omple el buit del respatller i sosté la zona lumbar. Ompl l'espai buit perquè l'esquena no es ressenti encara que hi seguis molta estona. El confort que el cos reconeix primer, sospirant «ah, això és», just quan et reclines."},"ICON-1903":{"nm":"Cinta Antilliscant per a Cantonades de Coixí","de":"Una cinta que subjecta el coixí per les cantonades, aquell que abans s'anava escorrent cada vegada que t'hi asseies. El fixa en un sol lloc perquè no llisqui. L'endreça comença precisament en aquesta mena de fixació petita i tenaç."},"ICON-1904":{"nm":"Cinta Protectora de la Costura del Coixí","de":"El primer lloc que es desgasta d'un coixí és sempre la costura de la cantonada. Una cinta protectora que l'envolta per endavant, evitant que s'esquinci. Un cor que vol tenir-lo a prop molt de temps, ferm com un punt de cosir."},"ICON-1905":{"nm":"Butxaca per al Comandament del Sofà","de":"El comandament que sempre desapareixia entre els coixins per fi té casa pròpia. Una petita butxaca encaixada a la clivella del sofà. Saber que allò que creies perdut sempre és allà és un consol més gran del que sembla."},"ICON-1906":{"nm":"Cordill per Enrotllar la Manta","de":"Un cordill per enrotllar i lligar la manta de falda. La calidesa que es dispersa quan la deixes desplegada es guarda amb pulcritud per a la nit següent. Si guardes així fins i tot la calidesa, demà la podràs tornar a treure i a posar-te-la."},"ICON-1907":{"nm":"Botó de la Funda del Reposapeus","de":"Un botó que cordona la funda del reposapeus, la part que es desgasta més ràpid pel contacte dels peus, perquè sigui fàcil de canviar. Aquell simple clic allarga la vida de la tela. El cor que vol fer durar les coses és minuciós fins en els petits detalls."},"ICON-1908":{"nm":"Tap Lliscant per a la Pota del Sofà","de":"Fins i tot un sofà pesat no ha de ratllar el terra. Un tap tou que cobreix les quatre potes s'esmuny de puntetes per estalviar el parquet. Un moble curós fins a la punta dels peus guanya, no se sap com, més afecte."},"ICON-1909":{"nm":"Suport per a Comandaments","de":"Un suport que alinia, un al costat de l'altre, els comandaments que abans rodolaven i es dispersaven cap a tot arreu. Quan els bastons llargs i curts s'arrenglen ben nets en filera, això ja n'hi ha prou perquè l'aire de l'habitació s'assossegui un to."},"ICON-1910":{"nm":"Penjador de Càrrega del Comandament de Joc","de":"Un ganxo per penjar i carregar el comandament de joc després d'una bona estona de partida. Mentre hi penja i recupera la seva energia en silenci, les mans també descansen un moment. Aquesta breu pausa prepara amb fermesa la propera partida."},"ICON-1911":{"nm":"Bossa de Fitxes de Joc de Taula","de":"Una petita bossa que guarda fitxes de tots els colors. Les peces que esperen dins d'una bossa la propera ronda dringuen cada vegada que la remens. Amb aquest so, desperta primer l'emoció d'un «una altra partida?»."},"ICON-1912":{"nm":"Plat per Tirar els Daus","de":"Un plat pensat exclusivament per tirar els daus. La sort que abans rebotava fora de la taula i desapareixia, ara la vora la reté a dins. En aquell instant breu en què roden i s'aturen, l'alè de tots s'atura un moment alhora."},"ICON-1913":{"nm":"Cinta per a la Baralla de Cartes","de":"Una cinta que lliga una baralla de cartes perquè no es dispersin. Fins que no es barregen, aquest ordre és, en si mateix, una promesa. En el gest de treure la cinta i escampar les cartes, per fi comença la història d'una partida."},"ICON-1914":{"nm":"Clip Endreçador de Cables de la Consola","de":"Un clip que agafa i pentina els cables enredats darrere la consola. Endreça en silenci el desori d'un racó que amb prou feines es veu. La pulcritud sempre s'acaba, així, en silenci, per darrere."},"ICON-1915":{"nm":"Comptador de Punts","de":"Una petita roda que gires per marcar el punt. Clic, cada vegada que el número puja una osca, l'acompanyen els visques. Sense ni haver de comptar de cap, els dits ja recorden primer el resultat del dia."},"ICON-1916":{"nm":"Peu per al Tauler de Joc","de":"Un peu que aixeca el tauler en pendent, ajustant l'angle perquè tots els asseguts al voltant vegin el tauler d'un sol cop d'ull. Perquè ningú hagi d'estirar el coll, hi estén en silenci una visió justa per a tothom."},"ICON-1917":{"nm":"Got per Sortejar el Torn","de":"Un got on fiques la mà per sortejar l'ordre del joc. El bastó que agafes a les palpentes decideix qui comença. En aquell breu instant de confiar una mica en la sort, tothom batega junt dins del got rodó."},"ICON-1918":{"nm":"Plat Compartimentat per a Aperitius","de":"Un plat dividit per servir aperitius separats per tipus. Amb els espais separats, pots triar el teu preferit sense que xoquin les mans. La cura que va pensar en qui ho compartiria s'amaga en cada compartiment."},"ICON-1919":{"nm":"Escalfador de Tetera","de":"Un escalfador que embolcalla les espatlles de la tetera per conservar-ne la calidesa. L'abriga perquè el te no es refredi mentre s'infusiona a poc a poc. El desig, des de la punta dels dits, de servir calenta una tassa calenta fins al final."},"ICON-1920":{"nm":"Suport per a la Bosseta de Te","de":"Un suport on treus la bosseta de te ja infusionada i la deixes reposar una estona. Recull fins i tot l'última gota perquè no en caigui ni una. Un lloc que ofereix, fins i tot a una fulla que ja ha complert la seva feina, un final endreçat."},"ICON-1921":{"nm":"Anella Identificadora de Tassa Compartida","de":"Sis tasses idèntiques al prestatge de l'office. En comptes de preguntar de qui és cadascuna, hi vam posar anelles de colors diferents. Una petita marca lliga en silenci sis persones, cadascuna amb el seu gust, a un mateix lloc a la mateixa taula."},"ICON-1922":{"nm":"Cistella per Compartir Crispetes","de":"Mentre passa de mà en mà, el vapor saborós saluda primer. Si hi ha res que, per estrany que sembli, no minva per molt que en treguis grapats, deu ser el sentiment d'un vespre compartit tots asseguts junts."},"ICON-1923":{"nm":"Pot de Pinces per a Terrossos de Sucre","de":"Amb les pinces, deixes caure un terròs de sucre a la tassa amb un toc. Mirar com les cantonades blanques es dissolen a poc a poc fins a desaparèixer: una etiqueta pausada de la dolçor, apresa per primer cop a la taula de te de l'àvia."},"ICON-1924":{"nm":"Estora Antilliscant per a la Safata","de":"Encara que la safata s'inclini, les tasses mantenen el seu lloc. Com sempre fan les coses que sostenen sense fer soroll des de baix, l'estora suporta ella sola el moment del gairebé-lliscament i, al final, se'l calla."},"ICON-1925":{"nm":"Got amb Suport per a Palletes","de":"Deixa la palleta dreta i ni la beguda ni el cor es desordenen. En una tarda en què la taula queda endreçada per una simple verticalitat, el got acull una petita columna i sosté en silenci les hores mandroses."},"ICON-1926":{"nm":"Recull-molles per a Galetes","de":"Cruixent, just quan la galeta es trenca, els trossets que cauen s'apleguen aquí. Recollir fins i tot el rastre que deixa la mossegada més bona: el toc final silenciós de la taula, tendre fins amb l'última molla."},"ICON-1927":{"nm":"Cordill amb Pinces per a Fotos","de":"Amb pinces, pengen una a una les polaroids en un cordill estès com un estenedor. Mentre els somriures d'avui s'assequen bressolant-se amb la brisa, un tros de paret esdevé una petita i lluminosa exposició de records."},"ICON-1928":{"nm":"Bobina de Records","de":"Una bobina amb el fil enredat desfet i enrotllat amb cura. Les coses que van continuar, nuades a cada punt trencat. Si així vas rebobinant a poc a poc el record, volta rere volta, un camí que et semblava escurçat torna a fer-se llarg."},"ICON-1929":{"nm":"Tapa per al Forat del Clau","de":"Una petita tapa rodona que amaga el forat d'un clau. Cobreix amb suavitat fins i tot la petita cicatriu que queda després de despenjar allò que hi havia estat penjat, i la paret torna a una cara llisa com si no hagués passat res."},"ICON-1930":{"nm":"Marc per a Foto de Grup","de":"Una foto de grup de sis persones, fetes amb les espatlles ben juntes. En el moment en què la fiques al marc, el somriure i la calidesa d'aquell dia queden segellats junts. Un marc és la mà que atura més silenciosament un dia que passa."},"ICON-1931":{"nm":"Tauler de Suro per a Notes","de":"Un tauler marró ple de marques de xinxetes. Una promesa que no es pot oblidar, una nota d'ànim que algú hi va enganxar, les tasques d'avui, tot s'hi va clavant en capes. Una paret de confiança al costat de l'escriptori que recorda en lloc del cap."},"ICON-1932":{"nm":"Nus per Penjar la Corona","de":"Fins i tot per a una corona penjada a la porta cal la traça dels dits. El nus s'ha de fer ben fort perquè no caigui ni en l'estació dels vents. El cor que dona la benvinguda a algú sempre es fa fort primer des d'un lloc invisible."},"ICON-1933":{"nm":"Funda per al Pèndol del Rellotge de Paret","de":"Una funda de tela que embolcalla el pèndol que fa tic-tac per protegir-lo de la pols. Fins i tot la feina de mesurar el temps rep així cura. Si el protegeixes amb suavitat perquè no es faci vell, el rellotge de paret es queda al nostre costat una mica més de temps."},"ICON-1934":{"nm":"Tauler per a Col·lecció d'Adhesius","de":"Els adhesius que abans es dispersaven per tots els calaixos ara s'apleguen en un sol tauler i es posen en filera. Un personatge preferit, una estrella brillant, un full escrit a mà. Quan la petita joia de col·leccionar queda ben ordenada, fins i tot el cor s'hi endreça."},"ICON-1935":{"nm":"Cordill de Banderoles","de":"Un cordill que uneix banderoles de colors en una sola filera. Sigui aniversari o benvinguda, en el moment en què el cordill travessa el sostre, una habitació corrent es converteix en casa de festa. Celebrar és la feina d'unir i recosir un cor trencat."},"ICON-1936":{"nm":"Base de Suro per al Bullidor Elèctric","de":"Un full de suro que sosté la base del bullidor calent. Perquè la taula no es cremi, abraça ella sola aquesta calor. Una petita atenció que el sosté sense fer soroll perquè la calidesa de ningú no hi deixi marca."},"ICON-1937":{"nm":"Safata de Molles de la Torradora","de":"Les molles que deixa caure el pa torrat i daurat rodolen fins a la safata. Només cal treure-la i sacsejar-la, i ja està. Rep sense dir res el matí atrafegat, i es prepara neta de nou per al proper àpat."},"ICON-1938":{"nm":"Anell Giratori del Microones","de":"Sobre l'anell que gira i gira, el plat dibuixa lentament una volta sencera. Aquell gir, fet perquè s'escalfi de manera uniforme, torna a la vida l'arròs fred d'ahir convertint-lo de nou en un àpat que fumeja."},"ICON-1939":{"nm":"Tapa per a Placa d'Inducció","de":"Per molt que l'oli esquitxi en totes direccions, el fogó es manté sempre net. Una sola tapa separa la calor intensa de les mans. Les coses que s'interposen sense veure's mantenen la cuina com un lloc on no et cremes."},"ICON-1940":{"nm":"Tap de Vapor de l'Arrossera","de":"El so d'un xiulet quan surt el vapor. Gràcies a un petit tap que allibera amb suavitat la pressió acumulada, l'arròs acabat de fer obre la tapa amb la cara més tova. En el temps de reposar, no hi ha pressa."},"ICON-1941":{"nm":"Suport Vertical per al Cullerot","de":"Deixa dret el cullerot amb què remenaves la sopa. Un petit gest per no vessar ni una taca a l'encimera. La pulcritud de la cuina sempre comença en aquests racons petits i discrets."},"ICON-1942":{"nm":"Funda de Silicona per a Nansa de Cassola","de":"Posa la silicona a la nansa roent de la cassola i la mà no es crema. Una capa que s'interposa entre la calor i el palmell. Protegeix, des del lloc més proper, qui cuina un àpat calent."},"ICON-1943":{"nm":"Filtre Anticalç del Bullidor Elèctric","de":"Fins i tot en l'aigua que es bull cada dia s'hi va acumulant un rastre lleuger. Una malla fina filtra la calç en silenci i només aboca una tassa clara. Una mà diligent que protegeix el primer glop del te des d'un lloc invisible."},"ICON-1944":{"nm":"Temporitzador de Cuina amb Potes de Pinça","de":"«Tres minuts més», diu el temporitzador mentre mossega ben fort la vora de la taula amb les seves potes de pinça. Mentre es couen els fideus, aguanta dret sobre les seves petites potes, comptant fent tic-tac el moment més esperat del dia."},"ICON-1945":{"nm":"Got Escorreplats per a Coberts","de":"L'aigua rellisca gota a gota des dels coberts tot just esbandits. Quan el got recull amb calma aquella humitat, la taula de seguida queda eixuta. La netedat és una diligència amable que té cura fins de la darrera gota d'aigua."},"ICON-1946":{"nm":"Prestatgeria Divisora per a Plats","de":"Els plats es dreçen verticals, separats en compartiments. Els plats que abans es ratllaven entre si en apilar-se ara tenen cadascun el seu propi espai. Endreçar és, al capdavall, donar a tothom el seu compartiment on no xoquin."},"ICON-1947":{"nm":"Anella per Aparellar Bastonets","de":"Enfila a l'anella els bastonets que havien quedat sols sense parella i torna a ajuntar-los. Perquè un bastonet sol de seguida perd la utilitat, aquesta petita anella manté l'ordre al calaix lligant-los costat per costat."},"ICON-1948":{"nm":"Penjador Ramificat per a Tasses","de":"Penja les tasses una per una en un suport que s'estén en branques com les d'un arbre. Mentre s'asseca la humitat de cada got capgirat, un racó de la cuina resta dret en silenci com un arbret petit i endreçat."},"ICON-1949":{"nm":"Safata de Coberts amb Nansa","de":"Una safata on cullera, bastonets i forquilla reposen l'un al costat de l'altre en compartiments. Agafa la nansa i aixeca-ho tot d'una peça, i parar taula es fa molt més lleuger. L'estètica de l'ordre també viu, sense falta, dins del calaix."},"ICON-1950":{"nm":"Escorreplats per a Gots","de":"Deixa els gots rentats de cap per avall i les gotes d'aigua cauen, degoteig rere degoteig. Mentre s'assequen a poc a poc vora una finestra assolellada, el got recupera amb calma la transparència inicial per al proper glop."},"ICON-1951":{"nm":"Raspall Netejapues de Forquilla","de":"Les seves pues fines pentinen amb delicadesa el menjar que queda entre les puntes de la forquilla. Gràcies a un toc que té cura fins de les escletxes més estretes, el proper àpat sempre comença amb una primera mossegada impecable i neta."},"ICON-1952":{"nm":"Feltre Antilliscant per Apilar Bols","de":"Apila els bols i la porcellana grinyola l'una contra l'altra. Un sol full de feltre glaçat entre elles apaga aquesta fricció. El secret d'una llarga vida junts consisteix a deixar-se l'un a l'altre una mica més tous."},"ICON-1953":{"nm":"Cordill Penjador per a Cullereta de Te","de":"Penja la cullereta de te, tan mona, de l'anella i fixa-la a la paret. Mai enterrada en un calaix, brilla sempre a l'abast de la mà: una eina petita que reclama amb orgull el seu propi lloc. Fins i tot les feines de la llar tenen el seu lloc fix."},"ICON-1954":{"nm":"Safata Compartimentada per a la Nevera","de":"Divideix el compartiment de la nevera en seccions i cada ingredient guanya la seva petita casa. Les coses que abans quedaven barrejades i oblidades troben el seu lloc, i cada cop que obres la porta veus d'un cop d'ull ben clar què hi ha i on."},"ICON-1955":{"nm":"Pinça Dreçadora per a Bosses de Congelador","de":"Agafa amb la pinça una bossa de congelats mig buida i posa-la dreta. Perquè no bolqui i vessi, perquè sigui fàcil de trobar la propera vegada. Fins i tot dins del congelador fred hi habita la saviesa hàbil i endreçada d'una bona mestressa de casa."},"ICON-1956":{"nm":"Ajustador de Tap d'Ampolla","de":"Una ampolla mal tancada de seguida perd el gas. Aquell únic gir de canell que estreny fort el tap manté intactes l'aroma i el gas fins l'endemà al matí. La destresa brilla en les coses petites."},"ICON-1957":{"nm":"Estora Antilliscant per a Ous","de":"Un folre que acull els ous rodons en compartiments perquè no rodolin ni es trenquin. El desig de tractar amb la màxima cura allò més fràgil s'instal·la petit i tendre en un racó de la porta de la nevera."},"ICON-1958":{"nm":"Extensor de Butxaca per a Porta de Nevera","de":"Estira lleugerament de costat la butxaca de la porta de la nevera per fer-hi un espai més. Perquè quan creix la llar, també ha de créixer aquell espai. En la destresa d'eixamplar un lloc estret, s'hi reflecteix el cor d'una mestressa de casa hàbil."},"ICON-1959":{"nm":"Tapa Premedora per a Sobres","de":"Una tapa que es prem amb suavitat sobre les restes de menjar. Les protegeix en silenci perquè no s'assequin ni agafin altres olors. Una mà curosa desa amb cura fins i tot allò que sobra d'un sol àpat."},"ICON-1960":{"nm":"Aleta Direccional de l'Aire Fred","de":"Cap a on fluirà l'aire fred? Una petita aleta en decideix en silenci la direcció. Desvia una mica amb la punta del dit el camí invisible de l'oratge, i el fred arriba fins al racó més profund de dins."},"ICON-1961":{"nm":"Coixinet Absorbent del Calaix de Verdures","de":"Al racó més fosc del calaix de verdures de la nevera, jo absorbeixo en silenci la humitat. El petit miracle de la fulla marcida d'ahir que al matí torna a estar ferma. Encara que ningú no me'n reconegui el mèrit, la frescor sempre és cosa meva."},"ICON-1962":{"nm":"Vora Aturadora per a Llaunes","de":"Enganxada en silenci a la vora de la taula, atura el peu d'una llauna que estava a punt de rodolar. Una beguda a punt de vessar-se, una taula a punt de necessitar un drap. La tranquil·litat de la llar comença en aquesta petita vora que passa desapercebuda."},"ICON-1963":{"nm":"Roda de Torns de Feines","de":"Avui, qui renta els plats, qui separa el reciclatge. Un sol gir de la fletxa i qualsevol baralla es resol rodona. En una casa on cinc persones conviuen apinyades, fer torns és la mena de pau més amable."},"ICON-1964":{"nm":"Cinta de Silicona Identificadora de Tassa","de":"Cinc tasses gairebé idèntiques, i un matí de dubtes sobre de qui és cadascuna. Posa't una cinta de color de la mida d'un canell i la petita promesa d'«aquesta és la meva» queda clara, i a la taula de l'esmorzar s'hi instal·la amb delicadesa un ordre amable."},"ICON-1965":{"nm":"Anell Racionador per a Bol","de":"En un dia atrafegat, les marques dins del bol es converteixen en una amiga de confiança. Un espai per a l'arròs, un altre per als acompanyaments. Ni massa poc ni massa, una línia amable que t'indica en silenci just quant menjar avui."},"ICON-1966":{"nm":"Pot amb Pinces per Compartir Aperitius","de":"Si passes la bossa sencera, queda el lloc que ha tocat la mà, i fa un cert respecte. Si el reparteixes un a un amb pinces, només llavors la part de tothom surt igual. Al compartir hi escau més una mà endreçada que un grapat."},"ICON-1967":{"nm":"Suport de Nom per al Torn de la Tetera","de":"Bullir l'aigua sempre havia recaigut en les mateixes mans. Des que vam començar a penjar per torns les etiquetes amb els noms al suport del costat de la tetera, una tassa calenta de te es va convertir en afecte que s'infusiona per torns."},"ICON-1968":{"nm":"Xip de Paleta «No Deixis Res»","de":"Un petit «no deixis res» penja de la punta de la paleta. Encara que soni a renyina, no hi ha res de desagradable: perquè hi habita l'esperit de la taula d'abans, quan cada àpat es tenia per preciós."},"ICON-1969":{"nm":"Penjador de Bosseta Personal de Coberts","de":"Els coberts ja no rodolen dins del calaix. En el moment en què cada joc va a la seva pròpia bosseta i queda penjat a la paret, el lloc de cadascun dels cinc membres de la família s'arrengla costat per costat. Una petita endreça sosté la pau de cada dia."},"ICON-1970":{"nm":"Xip de Suro Assenyalador de Lloc","de":"Posa trossets de suro a la taula i queda clar qui seu on. El lloc que sempre ocupes, el perfil que sempre tens al davant. Un lloc assignat és la prova més silenciosa de les paraules «vivim junts»."},"ICON-1971":{"nm":"Ganxo Enrotllador de Davantal de Torn","de":"El davantal acabat de fer servir per rentar els plats no es llança de qualsevol manera. Enrotllat i penjat al ganxo, l'endemà al matí és a l'abast fresc de nou. Un cor que pensa en la propera persona viu en aquest petit nus."},"ICON-1972":{"nm":"Bossa Plegable de Xancletes d'un Sol Ús","de":"El dia que arriben visites, jo em desplego amb tota la bossa. Les xancletes d'un sol ús ben endreçades a dins donen la benvinguda tova als peus acabats d'arribar. L'hospitalitat sempre comença en silenci des de l'entrada."},"ICON-1973":{"nm":"Butxaca per a les Cues de Paper dels Bastonets","de":"Quan s'acaben els bastonets d'orella i només en queden les cues de paper, jo en recullo l'extrem amb cura. Fer lloc fins i tot al que s'hauria de llençar. Sé que el secret d'un escriptori net és aquesta mena de tendresa petita."},"ICON-1974":{"nm":"Lligat de Bobines del Costurer","de":"Lliga els fils de colors junts perquè les bobines no es desfilin i s'enredin. Un botó caigut, un puny descosit: amb aquest sol lligat es tornen bons de seguida. Una costura a mà que salva en silenci la vetlla d'un dia important."},"ICON-1975":{"nm":"Peça de Sabó Embolicada Individualment","de":"Un tros de sabó embolicat amb cura, un per un, es col·loca a cada habitació de convidats. Un cos de la mida d'un palmell renta amb una sola escuma la pols del dia. La netedat sempre comença en llocs així de petits."},"ICON-1976":{"nm":"Càpsula Plegable de Casquet de Dutxa","de":"Plega els plecs i cap dins del palmell; obre'l i embolcalla el cabell ben ajustat. Perquè un pentinat cuidat no s'ensorri amb una sola dutxa. Aquesta única capa protegeix la pulcritud del matí de demà."},"ICON-1977":{"nm":"Funda Protectora per a Raspall de Dents","de":"Les cerres són més delicades del que sembla. Una funda que en cobreix la punta impedeix que fins i tot la pols de la bossa hi arribi. Protegir els llocs invisibles: la vertadera feina de la higiene, apresa en cada viatge."},"ICON-1978":{"nm":"Pinces Extractores de Discos Desmaquillants","de":"Els discos de cotó només surten bé si es prenen d'un en un. Si els vesses tots de cop, se'n malbaraten més. «Un per un, amb cura»: aquesta és la regla silenciosa sobre el tocador."},"ICON-1979":{"nm":"Calçador Plegable de Butxaca","de":"Plegat, cap a la butxaca; obert, cap al taló. M'enorgulleixo de fer, amb el meu cos petit, una feina força gran. Fins i tot en un matí de dormir més del compte, sempre vaig ser jo qui et va deixar calçar-te les sabates sense fer-les malbé."},"ICON-1980":{"nm":"Bobinador Individual de Fil Dental","de":"Enrotlla amb cura una sola tira de fil dental i talla just el que et cal quan arribi el moment. Un bobinador no més gran que una ungla, però mai absent en la feina de protegir un somriure lluminós. Fins i tot un somriure té preparatius invisibles."},"ICON-1981":{"nm":"Nansa de la Tapa del Bullidor","de":"Perquè el vapor de l'aigua bullent no et cremi la mà, m'encaixo damunt la tapa. Un pam de distància entre la calor i el palmell. Aquesta petita distància escalfa amb seguretat el matí atrafegat d'algú."},"ICON-1982":{"nm":"Base de Silicona per a la Planxa","de":"El moment més perillós és quan deixes la planxa un instant a mig planxar. Posa-la dreta damunt de la base de silicona i ni la taula ni la roba es cremen. Allisar les arrugues només s'acaba de veritat sobre aquest suport."},"ICON-1983":{"nm":"Ganxo Antifurt de Penjador","de":"Perquè la roba penjada no llisqui de qualsevol manera, el ganxo tanca la boca amb fermesa. Un petit sentinella que vigila la peça preferida dins l'armari. Protegir és, així, una feina silenciosa."},"ICON-1984":{"nm":"Colador Anticalç per al Bullidor","de":"La meva feina és filtrar en silenci la calç que sura dins l'aigua bullent. Només després de filtrar fins i tot els residus invisibles, una tassa de te esdevé clara. La dedicació sempre s'infusiona en els llocs que ningú no veu."},"ICON-1985":{"nm":"Cinta Antilliscant per a Penjador","de":"Un penjador embolicat amb una cinta antilliscant no deixa caure ni la seda més lleugera. Qui hagi vist un cop una peça caiguda a terra i arrugada sap l'agraïment que es deu a aquesta simple línia prima."},"ICON-1986":{"nm":"Clip Endreçador de Cable de la Planxa","de":"Un cable deixat anar enganxa el peu d'algú i el fa ensopegar. Un sol gest de la mà per lligar-lo net amb un clip. Evitar accidents sempre comença amb aquesta mena d'endreça petita i insignificant."},"ICON-1987":{"nm":"Encaix de la Base del Bullidor","de":"Assec el bullidor ben encaixat al meu forat perquè no trontolli. Ser al lloc propi vol dir, també, estar tranquil. Hi ha una raó per la qual l'aigua calenta s'escalfa cada matí al mateix lloc."},"ICON-1988":{"nm":"Penjador de Pantalons amb Potes de Pinça","de":"Quan les potes de pinça mosseguen fermes la vora del pantaló, no s'hi forma ni una sola arruga. Una peça ben planxada rep bon tracte des del moment que queda penjada. Un tall net s'acaba de completar dins de l'armari."},"ICON-1989":{"nm":"Ganxo Penjador per a l'Assecador","de":"Deixa l'assecador a qualsevol lloc i el cable de seguida s'enreda. Penja'l bé al ganxo i el lavabo s'eixampla, i el matí de demà es fa més lleuger. Un lloc endreçat alleugereix una mica un dia atrafegat."},"ICON-1990":{"nm":"Sotagot del Minibar","de":"Posa'l amb calma sota el got i les gotes no s'escampen per la taula. L'atenció d'un sol sotagot no deixa cap cercle marcat. La netedat és l'amabilitat de no deixar cap rastre."},"ICON-1991":{"nm":"Cartell de No Molestar","de":"Un cartell penjat al pom de la porta xiuxiueja en silenci «ara estic descansant». Vetlla per un sospir de migdiada al final d'un dia llarg. Fins i tot una pausa necessita algú que la protegeixi amb cura."},"ICON-1992":{"nm":"Tapa del Botó de Servei d'Habitacions","de":"Gràcies a la tapa que envolta el botó, ni un roçament de màniga el prem sense voler. Perquè només truquis amb claredat quan realment cal. Una petita coberta fa que una habitació atrafegada sigui una mica més endreçada."},"ICON-1993":{"nm":"Pinces per a Gel del Minibar","de":"Agafar gel amb la mà nua és fred i sempre s'escapa. Aquesta feina la fan amb fermesa les potes de la pinça en el seu lloc. Al començament d'una beguda fresca s'hi amaga sempre una mà que ningú no veu."},"ICON-1994":{"nm":"Ranura per a la Clau-Targeta","de":"Fica la targeta a la ranura i els llums de l'habitació s'encenen d'un toc. Jo només sóc una petita escletxa, però sóc el primer gest que obre un espai on deixar anar el cansament del dia. Al lloc on tornes, el llum torna a encendre's."},"ICON-1995":{"nm":"Anella de Segellat del Coll de l'Ampolla","de":"Si l'anella de segellat del coll de l'ampolla és intacta, vol dir que encara ningú l'ha tocada. Una petita promesa que demostra que continua tal com era al principi. La confiança comença en un segell no trencat."},"ICON-1996":{"nm":"Suport per a Fullets","de":"Posa el fullet dret i lleugerament inclinat, i les mirades de pas s'hi aturen tot sol. La posició reservada de la informació que espera ser oberta. Només amb deixar-lo ben visible, el camí d'algú es fa una mica més fàcil."},"ICON-1997":{"nm":"Xip Pla Obreampolles del Minibar","de":"En un racó del seu cos pla s'hi amaga discretament una osca per obrir taps d'ampolla. Per petit que sigui, fa la seva feina impecablement. El primer glop fresc d'una ampolla sempre s'obre amb aquest petit xip."},"ICON-1998":{"nm":"Coberta del Regulador de Llum","de":"Gira amb suavitat la maneta coberta i la lluminositat de l'habitació canvia a poc a poc. Brillant, i després suau. Triar la llum a l'hora d'anar a dormir és un ritual que tanca el dia amb tendresa."},"ICON-1999":{"nm":"Falca Aturadora per a Rodes de Maleta","de":"Fica-la lleugerament sota la roda i la maleta no rodolarà pel seu compte. Fins i tot en una andana inclinada de l'estació, l'equipatge manté el seu lloc. La tranquil·litat d'un camí de sortida es fa ferma en aquesta petita falca."},"ICON-2000":{"nm":"Tauler Plegador per a l'Equipatge","de":"Desplega'l i posa-hi a sobre una camisa o uns pantalons, i es plegaran nets i perfectes. Perquè l'interior de la maleta no s'ensorri, perquè puguis sortir sense arrugues a la ciutat d'arribada. Un equipatge ben fet ajuda el viatge fins i tot abans de marxar."},"ICON-2001":{"nm":"Pom del pany de la caixa forta","de":"Es gira el pom i un petit forrellat llisca cap endins. Confiar els objectes de valor és la promesa de deixar el cor completament tranquil, encara que només sigui per una nit. El pany no hi és com a angoixa, sinó com un altre nom per a la pau interior."},"ICON-2002":{"nm":"Fundeta per al mànec de la maleta","de":"A cada racó gastat i tacat per les mans hi ha gravada la partida d'algú. Agafa aquesta funda, gastada tant com els quilòmetres que ha arrossegat, i saps en silenci que marxar és, al capdavall, una paraula que porta dins el retorn."},"ICON-2003":{"nm":"Clip penjador per a la neceser de viatge","de":"Penja el necesser a la vora del lavabo i l'habitació estreta guanya un pam d'amplada. Que l'ordre dins la bossa comença amb una petita pinça, la mà que ha viatjat lluny ja ho sap."},"ICON-2004":{"nm":"Pinça organitzadora de cables del carregador","de":"Reuneix diversos cables en un sol endoll. En una nit esperant que la càrrega s'ompli, aquí hi ha una petita mà que sosté amb tendresa els fils dispersos en un mateix lloc."},"ICON-2005":{"nm":"Cinta anella per a l'etiqueta de la maleta","de":"Entre bosses negres idèntiques, un sol cordó et permet reconèixer la teva. Penjar-hi un nom és una marca tendra que aquest equipatge té un camí de tornada cap a algú."},"ICON-2006":{"nm":"Suport de paret per al cable de càrrega","de":"Una petita placa a la paret, al capçal del llit, sosté el cable de càrrega ben endreçat. La primera nit en una habitació desconeguda, quan s'encén un llum familiar, fins i tot aquell lloc esdevé casa per un instant."},"ICON-2007":{"nm":"Potes plegables del suport per a maletes","de":"Desplega les potes plegades i la bossa s'aixeca un pam de la pols del terra. El bagul deixat encara sense desfer sosté en silenci un viatge inacabat, tot esperant el matí següent."},"ICON-2008":{"nm":"Ranura per a la targeta clau","de":"Cal inserir la targeta perquè s'encenguin els llums de l'habitació. Una llum que brilla només mentre hi ets: el dia d'un viatger s'escalfa exactament amb la claror que aquesta petita ranura permet."},"ICON-2009":{"nm":"Anella de cordó per a la targeta clau","de":"Penja't la targeta al coll i les dues mans queden lliures. Lligar la por de perdre-la a un sol cordó és una petita astúcia transmesa des de fa temps pels viatgers carregats d'equipatge."},"ICON-2010":{"nm":"Botó del timbre de recepció","de":"Prem-lo i, en algun racó de la recepció, sona un dring clar i rodó. Perquè demanar ajuda mai no faci vergonya, el timbre sempre hi és, col·locat amb tendresa a l'abast d'una mà."},"ICON-2011":{"nm":"Pinça per al número de torn de facturació","de":"Agafa i fixa el paperet amb el número rebut al final de la cua. Que fins i tot l'espera té el seu torn: l'ordre creix d'una petita promesa de respectar en silenci el temps de l'altre."},"ICON-2012":{"nm":"Borla per a la clau de l'habitació","de":"Una borla penjada de l'extrem de la clau es gronxa suaument a cada pas. El cor que afegeix un toc d'elegància a la utilitat només el mostren els qui coneixen el plaer de les puntes dels dits."},"ICON-2013":{"nm":"Tapa del timbre de recepció","de":"Posa la tapa sobre el timbre i el silenci del migdia no es trenca. Una petita atenció per vetllar la son profunda d'algú: fins i tot la quietud és una cosa que algú ha creat amb cura."},"ICON-2014":{"nm":"Etiqueta amb el número d'habitació","de":"Una nota penjada al pom de la porta duu escrit, ben clar, el número de l'habitació. Uns quants dígits fixen el lloc on tornaré aquesta nit, i en un passadís desconegut esdevé un petit far."},"ICON-2015":{"nm":"Banda magnètica de la targeta clau","de":"Acosta la banda negra a la juntura de la porta i el pany se solta suaument. Una època en què un senyal invisible obre una porta: allò que un dia semblava màgia ara s'ha instal·lat com a quotidianitat al palmell de la mà."},"ICON-2016":{"nm":"Tampó per al segell de facturació","de":"Cada vegada que cau el segell, el tampó n'absorbeix la tinta de manera uniforme. Perquè el traç de la confirmació quedi ben nítid, hi ha una mà que, des d'un lloc invisible, sosté en silenci."},"ICON-2017":{"nm":"Barra penjadora del carro d'equipatge","de":"Una sola barra al carro d'equipatge sosté la bossa de vestits sense fer-hi cap arruga. A les coses que carreguen un dia feixuc en el nostre lloc, de vegades un voldria dir-los, senzillament, gràcies."},"ICON-2018":{"nm":"Etiqueta per al mànec del bagul","de":"Penja una petita etiqueta al mànec del bagul. Mentre el camp del nom quedi en blanc, hi resta un pessic d'il·lusió: la pròxima destinació d'aquesta bossa encara no està decidida."},"ICON-2019":{"nm":"Falca de bloqueig per a la roda del carro","de":"Encaixa una falca sota la roda perquè el carro no llisqui en un pendent. Vetllar la quietud és, de vegades, l'altra cara, la més fiable, de la seguretat."},"ICON-2020":{"nm":"Sivella per a la corretja d'equipatge","de":"Estreny bé la corretja perquè la bossa inflada de coses de viatge no rebenti. Encara que el camí s'acabi, el volum dels records no minva, i per això la sivella en sosté el pes fins al final."},"ICON-2021":{"nm":"Funda per al ganxo del carro d'equipatge","de":"La funda que cobreix el ganxo del carro no deixa ni una marca a la roba. Un cor que preveu fins i tot els cops invisibles: la bona hospitalitat es completa en aquests petits detalls."},"ICON-2022":{"nm":"Butxaca per a l'etiqueta d'identificació de la maleta","de":"Una petita butxaca al costat de la bossa acull l'etiqueta amb el nom. Escriure-hi de qui és és com gravar per endavant el dret a retrobar-se, encara que es perdi."},"ICON-2023":{"nm":"Pinça per a guants de mosso d'equipatge","de":"Quan es traslladen càrregues pesades, la pinça agafa els guants amb fermesa perquè no rellisquin. Protegir les mans i fer bé la feina neixen, al capdavall, d'un mateix cor."},"ICON-2024":{"nm":"Xarxa cobridora per a l'equipatge","de":"Cobreix-ho amb la xarxa i els bultets menuts no s'escampen en totes direccions. Cada malla estreta reté les coses petites perquè no es perdin enmig del trànsit atrafegat."},"ICON-2025":{"nm":"Portanotes del carro d'equipatge","de":"Una nota clavada al mànec del carro porta escrit el número de l'habitació. L'hàbit d'apuntar on cal anar: com més atrafegades les mans, més es recolzen, en silenci, en una sola ratlla escrita."},"ICON-2026":{"nm":"Cúpula cobreplats de safata","de":"Aixeca la cúpula platejada i el vapor s'enlaira tot d'una. El cor que cobreix el menjar perquè no es refredi és la devoció mateixa, el desig d'oferir la calidesa tal com és."},"ICON-2027":{"nm":"Plaqueta de \"No molesteu\" per al pom","de":"Penja aquesta plaqueta al pom i fins i tot les passes del passadís es fan curoses. Una sola frase, \"no em desperteu\": també el descans només és complet quan algú el vetlla."},"ICON-2028":{"nm":"Anella per a tovalló de paper del servei d'habitacions","de":"Passa el tovalló de paper per l'anella rodona i dona-li una forma polida. L'elegància d'un àpat comença en aquest petit cèrcol: la cura es revela més clarament en les coses més petites."},"ICON-2029":{"nm":"Estora antilliscant de safata","de":"Posa una estora sobre la safata i els plats no rellisquen. Mantenir-los al seu lloc fins i tot enmig del balanceig: fins la quietud més estable amaga un disseny curós de qualcú."},"ICON-2030":{"nm":"Etiqueta de comanda d'esmorzar per al pom","de":"Penja l'etiqueta de la comanda d'esmorzar al pom i el matí de demà queda promès per endavant. Escriure aquesta nit el primer àpat és una altra cara de l'espera tendra."},"ICON-2031":{"nm":"Suport amb potes per a safata de llit","de":"Desplega les potes de la safata i, fins i tot damunt el llit, esdevé una taula digna. Un esmorzar servit allà on jeus: un petit suport transforma una habitació corrent en una escena luxosa."},"ICON-2032":{"nm":"Funda tèrmica per a tetera","de":"Cobreix la tetera amb la funda tèrmica i l'escalfor de l'aigua perdura més temps. Com en aquelles nits antigues reunits al voltant del foc, el desig de preservar la calidesa no coneix època."},"ICON-2033":{"nm":"Etiqueta cua de sol·licitud de neteja per al pom","de":"Penja al pom l'etiqueta-cua de sol·licitud de neteja per deixar-hi un senyal mut. Una petició transmesa sense obrir els llavis: darrere una habitació endreçada hi ha la promesa d'una mà invisible."},"ICON-2034":{"nm":"Suport per a saleres i pebreres de safata","de":"El suport aferra amb fermesa perquè els pots de condiments no bolquin. Mantenir l'equilibri del gust fins i tot sobre una safata que es gronxa: aquesta és la tasca silenciosa d'una petita fixació."},"ICON-2035":{"nm":"Peu suport per a notes de reserva","de":"Dreça les notes de reserva i l'ordre es llegeix d'una sola ullada. Perquè ni les mans més atrafegades s'hi confonguin, és una petita eina d'ordre que sosté dreta i clara una sola fulla."},"ICON-2036":{"nm":"Tauler de mapa amb agulles per a punts turístics","de":"Clava agulles al mapa i marca, un a un, els llocs on vols anar. Cada agulla, una emoció encara no visitada: el viatge ja comença en el mateix instant que despleguem el mapa."},"ICON-2037":{"nm":"Pinça amb bandereta per cridar taxis","de":"Quan es crida un taxi, una pinça manté la petita bandera ben dreta. Un senyal que la bandera crida en lloc d'una mà alçada: també al carrer, una crida ha de ser clara perquè arribi."},"ICON-2038":{"nm":"Pom del timbre de consergeria","de":"Prem el pom i un dring clar arriba al taulell de consergeria. Un senyal de benvinguda que diu que pots preguntar el que vulguis: en una ciutat desconeguda, la crida més reconfortant."},"ICON-2039":{"nm":"Tauler amb pinça per al número de reserva","de":"Subjecta el paper amb el número de reserva al tauler perquè es vegi ben clar. Perquè el lloc promès no es confongui, és una petita constància que reté amb polidesa una ratlla de xifres."},"ICON-2040":{"nm":"Expositor de fullets turístics","de":"Disposa els fullets d'excursions i la mà d'un viatger s'atura sola. En cada full que s'agafa, un a un, el paisatge d'un camí encara no recorregut hi jeu plegat en silenci."},"ICON-2041":{"nm":"Suport per al segell del plànol","de":"Per als primers passos a l'entrada, sosté ferm el tampó de segell damunt el plànol. Quan la tinta no es corre, el camí tampoc no es confon. Un lloc que aguanta el pes en silenci perquè una petita guia es mantingui dreta."},"ICON-2042":{"nm":"Etiqueta per guardar paraigües","de":"En una tarda en què les gotes de pluja degotaven de la teulada, es penja un número a cada paraigua. Quan qui ha tornat després de la pluja ve a reclamar el seu, l'etiqueta evoca amb claredat aquell record humit."},"ICON-2043":{"nm":"Suport del timbre d'informació","de":"Dring, sona una vegada, i algú ve corrents amb un somriure des de l'altre costat. La petita campana penjada a la cantonada del taulell és el traductor més tendre, que transmet fins i tot les paraules que no has pogut dir del tot."},"ICON-2044":{"nm":"Broc del dispensador de xampú","de":"Obre la mà i prem suaument, i l'escuma esclata en un pof. Aquell únic doll mentre la fragància s'escampa per tot el bany. La melodia que desperta un matí somnolent més dolçament comença precisament aquí."},"ICON-2045":{"nm":"Safata escorredora per a la sabonera","de":"Una safata que deixa escolar en silenci l'aigua acumulada sota la sabó. Perquè no s'estovi, perquè no es desfaci. Una petita atenció tendra per mantenir més temps al costat allò que cada dia es va gastant una mica."},"ICON-2046":{"nm":"Culleró per a sals de bany","de":"Agafa una cullerada de pols i dissol-la en aigua tèbia, i el color i l'aroma s'escampen lentament. Mentre remenes amb el canell, la banyera esdevé un petit llac, i el cansament d'un dia hi queda submergit en silenci."},"ICON-2047":{"nm":"Xarxeta per fer escuma de sabó","de":"Atrapa un tros de sabó a la xarxa i frega'l, i una escuma suau s'infla fins a omplir-te els palmells. Un alquimista silenciós en un racó del bany, que transforma allò aspre en tendresa."},"ICON-2048":{"nm":"Tapa esterilitzadora per al raspall de dents","de":"El desig que allò que toca la boca sigui sempre net. Una petita tapa que embolcalla suaument les puntes de les cerres té cura fins i tot d'allò que no es veu. La netedat és feta d'aquestes petiteses acumulades."},"ICON-2049":{"nm":"Tapa per al pot de bastonets d'orelles","de":"Un pot on descansen, ben endreçats, els bastonets blancs, i una tapa que el cobreix arrodonida. S'obre amb un toc, es tanca amb un clic. Un punt final tendre a l'ordre del bany, acabat amb un so petit."},"ICON-2050":{"nm":"Flascó comptagotes d'oli de bany","de":"Inclina'l lleugerament i, gota a gota, cau l'oli perfumat. La lluïssor i l'aroma suau que s'escampen per la banyera. Massa senzill per ser luxe, massa tendre per ser quotidià: una única gota."},"ICON-2051":{"nm":"Separador de safata d'amenities","de":"A la safata dividida en compartiments, els petits flascons troben cadascun el seu lloc. Coses que, escampades, són desordre, i reunides, esdevenen polidesa. Un simple separador manté l'ordre d'un matí atrafegat."},"ICON-2052":{"nm":"Suport de rellotge de sorra per a sauna","de":"És una promesa tendra: escalfar l'esquena, com a mínim, mentre duri la sorra que cau. Mentre el rellotge, inclinat sobre el seu suport, va comptant el temps gota a gota, entre el vapor espès la persona descansa un instant sense ser res en particular."},"ICON-2053":{"nm":"Tovallola d'orelles de xai per a sauna","de":"Cargola les puntes de la tovallola i alça-les com dues orelles dretes, i el rostre al mirall es distreu suaument. Enmig del vapor calent, un petit ritual del bany de vapor on tothom torna, per un instant, a la infantesa."},"ICON-2054":{"nm":"Cullerot d'aigua per a sauna","de":"Omple el cullerot d'aigua i aboca'l sobre les pedres roents: un xiulet, i el vapor s'enlaira fins al sostre. En aquell instant, tot el cos s'enfonsa en una boira càlida, i el cansament vell es desfà lentament en gotes de suor."},"ICON-2055":{"nm":"Vareta de temperatura per a peduncle","de":"Submergeix la vareta a l'aigua i les marques parlen fluixet. Ni massa calenta ni ja freda, exactament aquella temperatura. Abans de submergir els dits dels peus, el dit que primer pregunta com es troba l'aigua."},"ICON-2056":{"nm":"Pinces per a pedres de sauna","de":"Una pedra just escalfada no es pot agafar amb les mans nues. Quan les pinces l'agafen amb fermesa i l'alcen, l'escalfor es trasllada a una distància segura. La cura també és un ofici, diu en silenci el bany de vapor."},"ICON-2057":{"nm":"Coixinet per seure a la sauna","de":"Estén-ne un sobre el terra roent i el lloc on toca l'esquena es torna més suau. Un coixinet que acull sense paraules un dia amarat de suor. El descans, al capdavall, ve de la distància justa amb el terra."},"ICON-2058":{"nm":"Bosseta de sal per a peduncle","de":"Agafa un grapat de sal grossa, dissol-la en aigua tèbia, i el cansament es fon suaument des de la punta dels peus. Quan el vapor salabrós envolta els turmells, un dia sencer de caminar s'atura, finalment."},"ICON-2059":{"nm":"Platet de perfum per a pedra de sauna","de":"Deixa caure unes gotes de perfum sobre la pedra escalfada i l'aroma càlida s'escampa lentament per la sauna. Tanca els ulls: és un bosc, o un camp de flors? El viatge més curt, fet a través del nas."},"ICON-2060":{"nm":"Funda tèrmica per a compresa calenta","de":"Un teixit que embolcalla la compresa escalfada per retenir-ne l'escalfor durant més temps. Igual que un cor que l'abraça fort perquè no es refredi, la calidesa reposada sobre el ventre et fa companyia tota la nit."},"ICON-2061":{"nm":"Vaguetes per a difusor d'aromes","de":"Uns bastonets prims xuclen l'aroma i el deixen anar lentament per l'habitació. Una fragància tènue que s'escola amb cada inspiració. La manera com un espai habitat va assemblant-se, a poc a poc, a l'olor d'aquella persona."},"ICON-2062":{"nm":"Manovella d'inclinació per a gandula","de":"Gira la manovella lentament i el respatller s'inclina suaument. Una mica cap al sol, una mica cap a l'ombra. Trobar l'angle més còmode a les palpentes és un càlcul ben propi de cadascú."},"ICON-2063":{"nm":"Banda antilliscant per a la vora de la piscina","de":"Una banda antilliscant que envolta tota la vora de l'aigua. Perquè els peuets que arriben xipollejant i corrent amb alegria s'aturin sans i estalvis, és una línia de meta de seguretat, oculta en silenci fora de la vista."},"ICON-2064":{"nm":"Anella per al tap de vàlvula de flotador","de":"Una anella lligada amb cura al petit tap que reté l'aire. Perquè el tap, un cop tret del flotador, no s'endugui l'aigua flotant. Una saviesa que evita per endavant una petita pèrdua d'un migdia d'estiu."},"ICON-2065":{"nm":"Tapa protectora per a graó d'entrada a la piscina","de":"Una tapa que embolcalla suaument l'extrem del graó que baixa cap a l'aigua. Perquè les plantes dels peus nus no s'esgarrapin, acull tou el primer pas d'entrada. Perquè tot començament sempre hauria de ser curós."},"ICON-2066":{"nm":"Anella per lligar la corretja del coixí de gandula","de":"Una anella on es lliga la corretja perquè el coixí no llisqui. Una petita promesa de mantenir-se al lloc encara que bufi el vent. Un sol nus fixa allà mateix la mandra d'una tarda."},"ICON-2067":{"nm":"Tauler porta-begudes per a piscina","de":"Un tauler on encaixar just una copa de beguda a la vora de la piscina. Un únic lloc que no es belluga ni amb les esquitxades més animades. Deixar la frescor a l'abast de la mà allarga una tarda d'estiu."},"ICON-2068":{"nm":"Pinça per estendre el banyador mullat","de":"Agafa el banyador degotant i deixa'l tranquil·lament a mercè de la brisa. Mentre s'asseca sota el sol, la pinça hi resta ferma en silenci. Una espera tranquil·la i tendra per al pròxim bany."},"ICON-2069":{"nm":"Pes de base per a para-sol","de":"Un pes feixuc col·locat a la base del pal perquè el para-sol no vaci amb el vent. Que l'ombra romangui llarga estona en un mateix lloc és gràcies, tot, a aquest pes. La fiabilitat sovint s'amaga en el lloc més baix."},"ICON-2070":{"nm":"Xip flotant indicador de temperatura","de":"Un petit xip que sura sobre l'aigua i n'anuncia, fluixet, la temperatura. Es torna vermellós si fa massa fred, es torna suau si és just. Un endevinaire simpàtic que llegeix l'estat d'ànim de l'aigua amb un sol color."},"ICON-2071":{"nm":"Borla per a la cremallera de la tenda","de":"Estira suaument la petita borla penjada a l'extrem de la cremallera i la porta de la tenda s'obre lliscant. Un tirador que es troba a l'instant fins i tot quan els dits van a les palpentes. Guia amb tendresa les anades i vingudes de la nit fosca."},"ICON-2072":{"nm":"Agulla papallona per fixar cordills de tenda","de":"Una agulla que mossega el cordill en forma de papallona i el reté ferm. El teixit que onejava amb el vent, finalment, es calma. Una nit d'acampada la vetllen, en silenci, aquests nusos petits i hàbils."},"ICON-2073":{"nm":"Vàlvula d'aire per a matalàs de glamping","de":"Hi acostes la boca i bufes, bufes, i el matalàs es va inflant a poc a poc. Un cop ple, tanca bé la vàlvula, el terra es torna tou, i un lloc per estirar el cos sota la llum de les estrelles queda, per fi, enllestit."},"ICON-2074":{"nm":"Ganxo penjador per al sostre de la tenda","de":"Un ganxo penjat del sostre de la tenda per penjar-hi un fanal o un mocador. La saviesa domèstica que aprofita amb cura fins i tot el petit espai de sobre el cap. És com penjar una estrella al sostre en lloc del cel."},"ICON-2075":{"nm":"Cinta subjectora per a sac de dormir enrotllat","de":"Una cinta cargolada i cordada perquè el sac de dormir enrotllat no es desfaci. Un llit que, al matí, torna a fer-se petit. Preparar la marxa és plegar amb polidesa l'escalfor de la nit passada."},"ICON-2076":{"nm":"Tauler per a calçat a l'entrada de la tenda","de":"Un tauler col·locat a l'entrada de la tenda per sostenir les sabates ben endreçades. La terra a fora, l'interior net. Amb un sol llindar, separa amb tendresa el dins del fora: una petita cortesia de l'acampada."},"ICON-2077":{"nm":"Ganxo corbat per penjar el fanal de glamping","de":"Un ganxo corbat per penjar-hi el fanal. Penja-l'hi i la llum s'escampa en rodó dins la lona. Aquell lloc on es penja una única llum enmig de la foscor esdevé, aquesta nit, el nostre saló."},"ICON-2078":{"nm":"Pinça per enrotllar la finestreta de ventilació","de":"Una pinça que enrotlla i subjecta la finestreta de ventilació. Obre una mica el camí de l'aire i l'ambient dins la tenda es torna molt més fresc. Una petita escletxa crea, en silenci, l'espai per respirar tota la nit."},"ICON-2079":{"nm":"Estora de terra per a tenda","de":"Una estora estesa al terra de la tenda per aturar la terra i la humitat. Una capa que estén un jaç sec fins i tot sobre l'herba. Perquè et quedis dins la natura sense mullar-t'hi, t'ajuda en silenci al teu costat."},"ICON-2080":{"nm":"Anella subjectadora per a barra de pes","de":"Una anella fixada a cada extrem de la barra perquè els discos no llisquin. Un petit tancament que confia plenament en el pes de qui aixeca. Només quan la seguretat sosté amb fermesa, el límit s'actualitza, per fi, un graó més."},"ICON-2081":{"nm":"Tapa per al mànec de la kettlebell","de":"A l'última sèrie, quan el ferro rosegava el palmell, aquesta petita tapa fa desaparèixer el dolor. Que aguantar fins al final és més difícil que aixecar el pes, la mà ho sap primer, en aquell punt final."},"ICON-2082":{"nm":"Falca d'encaix per a discos de pes","de":"Si el disc vacil·la encara que sigui mínimament, la postura s'esfondra abans fins i tot d'alçar-lo. Una falca fina clavada a l'escletxa sosté el centre sense fer soroll. La fermesa sempre comença en silenci, en un lloc invisible."},"ICON-2083":{"nm":"Pinça de fixació per a barra de pes","de":"Els dits que tanquen la fixació no han de tenir dubtes. Aquell petit clic de tancament sosté tot el moviment següent. El cos aprèn primer com dipositar la confiança en una sola pinça."},"ICON-2084":{"nm":"Xip de color indicador de pes de disc","de":"Un xip amb un color diferent per a cada pes: la mà el reconeix primer, encara que no sàpigues llegir el número. Vermell és pesant, blau és lleuger; recordar el pes pel color. El cos, sorprenentment, calibra la seva força a través dels ulls."},"ICON-2085":{"nm":"Suport de terra per a kettlebell","de":"Gràcies al suport que amplia la superfície de contacte amb el terra, el parquet no queda foradat. Les marques d'un entrenament només han de quedar en la suor i el múscul. Aquí hi ha, dipositat, un petit cor que no vol deixar ferides ni sota els peus."},"ICON-2086":{"nm":"Marca central de la barra de pes","de":"La marca gravada al mig de la barra és el punt de referència de l'equilibri esquerre-dreta. Una mà que agafa el centre amb exactitud redueix a la meitat el vacil·lament. En el moment que se sap on és el centre, per fi es pot alçar amb seguretat."},"ICON-2087":{"nm":"Prestatgeria per guardar discos de pes","de":"Els discos usats tornen al seu lloc. La imatge d'ells penjats ben endreçats per ordre de pes al prestatge és una atenció silenciosa per a la persona següent. Un espai endreçat és el dispositiu de seguretat més fiable, algú ho creu."},"ICON-2088":{"nm":"Topall antirodament per a discos de pes","de":"L'accident d'un disc al terra que rodola i cau sobre l'empenya del peu sempre arriba en un instant de descuit. El topall bloqueja en silenci aquell instant. Les grans desgràcies no vénen de grans llocs, sinó que roden des d'una petita escletxa."},"ICON-2089":{"nm":"Coixí de respatller per a banc d'entrenament","de":"Si el coixí que sosté l'esquena és massa dur, fins i tot la respiració es torna superficial. Aquella frontera entre suficientment ferm i suficientment tou és un punt d'equilibri que només qui hi ha segut molt temps pot trobar a les palpentes."},"ICON-2090":{"nm":"Passador d'alçada per a rack","de":"Amb un sol passador que fixa l'alçada, la barra s'ajusta just a les espatlles de qualsevol. Persones d'alçades diferents compartint amigablement el mateix estri: un petit forat d'ajust crea aquesta tendra igualtat."},"ICON-2091":{"nm":"Tapa de politja per a màquina de gimnàs","de":"Dins la tapa que embolcalla la politja, el cable gira i gira sense fer soroll. Una peça que amaga la fricció a dins i només ofereix suavitat a la mà. Un bon mecanisme mai no revela, al final, l'esforç que ha suportat."},"ICON-2092":{"nm":"Peus antilliscants per a banc d'entrenament","de":"Els peus antilliscants encaixats als quatre extrems de les potes fixen el banc ben ferm al terra. Només quan no vacil·la es pot posar-hi tota la força amb tranquil·litat. L'estabilitat, al capdavall, comença en una petita fricció a la punta del peu."},"ICON-2093":{"nm":"Ganxo suport per a barra de pes en rack","de":"El ganxo on es penja la barra sempre ha d'estar a una alçada a l'abast de la mà. El lloc on un braç cansat deixa, finalment i amb calma, la barra: aquella posició d'un pam tanca amb seguretat l'entrenament d'avui."},"ICON-2094":{"nm":"Nansa del passador de pes de màquina","de":"La nansa per inserir el passador i triar el pes ha de ser llisa perquè no faci mal a les ungles. Fins i tot en aquell breu gest de canviar el pes, se sent que hi ha, amagat en silenci, un acabat que ha tingut en compte les puntes dels dits humans."},"ICON-2095":{"nm":"Palanca de bloqueig d'angle per a banc","de":"Si la palanca que bloqueja l'angle del respatller és fluixa, la postura s'esfondra sense fer soroll. La certesa d'aquell instant en què es fixa amb un clic. L'encarregat, cada matí en obrir les portes, comprova primer, amb calma, precisament aquest so."},"ICON-2096":{"nm":"Suport de barra de seguretat per a rack","de":"En el pitjor moment, quan la barra de pes es desprèn de les mans, el suport de la barra de seguretat n'acull el pes en el seu lloc. Amb un suport invisible sempre a punt a sota, la persona pot, per fi, empènyer fins al seu límit."},"ICON-2097":{"nm":"Tapa d'extrem per a cable de màquina","de":"La petita tapa que tanca l'extrem del cable és el darrer nus contra el descordament. Lligar amb polidesa perquè les fibres no s'escampin: la dignitat d'un acabat sempre resideix en aquell punt final que passa desapercebut."},"ICON-2098":{"nm":"Bosseta de magnesi","de":"Un grapat de pols blanca que s'unta a les mans per esborrar el lliscament. Invisible com el maquillatge de darrere l'escenari, però l'estabilitat de tots els moviments d'avui comença, precisament, en aquest grapat. La preparació sempre comença per la punta dels dits."},"ICON-2099":{"nm":"Pinça d'entrenament per a la força de la mà","de":"Una petita pinça que repeteix en silenci obrir i tancar el puny enforteix la força de l'agafada. La força de la mà creix més a poc a poc que els músculs grans, així que això és també un exercici per deixar anar, en silenci, la impaciència."},"ICON-2100":{"nm":"Banda separadora de dits","de":"Una banda que s'encaixa entre els dits i els separa lentament cap enfora. Una mà que només usava els músculs d'agafar recupera la força d'obrir-se. Tant com estrènyer fort, deixar anar amb calma també requereix pràctica, diu la mà."},"ICON-2101":{"nm":"Tapa del pot de pols de guix","de":"Si la tapa del pot de pols de guix queda una mica fluixa, tota la bossa acaba tenyida de blanc. Una tapa petita que tanca just com cal evita per endavant aquest petit desastre. L'èxit de contenir-ho tot sempre depèn del tap."},"ICON-2102":{"nm":"Banda de suport per al genoll","de":"La banda que embolica el genoll per sostenir-lo ha d'aturar-se just en la pressió adequada. Si prem massa, talla la circulació; si va massa fluixa, no serveix de res, per això una mà experimentada calibra amb calma aquest delicat punt intermedi des de la memòria."},"ICON-2103":{"nm":"Cinta elàstica de resistència","de":"La cinta elàstica que s'estira i torna a encongir-se desperta els músculs adormits sense necessitat de cap pes. La resistència no cal que sigui sempre pesant. Fins i tot davant d'una estrebada suau, el cos sempre respon amb honestedat."},"ICON-2104":{"nm":"Sac de sorra per al turmell","de":"El sac de sorra que es cenyeix al turmell fa que cada pas caigui amb un pes satisfactori. Afegir-hi una mica de pes converteix fins i tot un passeig corrent en un entrenament de debò. És una petita saviesa que afegeix, d'amagat, un toc d'esforç a la vida quotidiana."},"ICON-2105":{"nm":"Barra enrotlladora per al canell","de":"Una barra que es va enrotllant a poc a poc per alçar un pes penjat d'una corda. El canell és l'articulació més petita i la que més s'obliden, i aquesta eina tan senzilla revifa amb calma aquella força oblidada."},"ICON-2106":{"nm":"Pilota de goma per enfortir l'agafada","de":"Una pilota de goma que estrenys i deixes anar manté l'entrenament viu fins i tot asseguts a l'escriptori. La força que es guanya a estones soltes dura més que la que es bolca tota de cop. La constància sempre creix a partir de coses tan petites com aquesta."},"ICON-2107":{"nm":"Sivella de la cinta de freqüència cardíaca","de":"Si la sivella de la cinta que es porta al pit es desplaça encara que sigui una mica, les xifres es disparen. Fins i tot l'acte d'escoltar el propi cor comença amb una subjecció ferma. Tota mesura, al capdavall, comença amb un ajust prou cenyit i sense escletxes."},"ICON-2108":{"nm":"Pinça de pols","de":"Una pinça que mossega suaument la punta del dit i compta el pols en silenci. Te la poses, calmes la respiració, i el ritme del cor s'enlaira clar en una pantalla diminuta. El cos sempre informa amb sinceritat del seu veritable estat."},"ICON-2109":{"nm":"Estoig per al monitor de canell","de":"L'estoig que guarda el monitor de canell és petit, però reconeix la seva família. Com més fàcil és perdre un aparell diminut, més necessita una llar on tornar. Guardar bé les coses també és una forma de tendresa."},"ICON-2110":{"nm":"Banderí de ritme","de":"Un petit banderí que marca el punt objectiu d'un corredor. Un sol punt fixat per endavant, fins aquí, acompanya uns peus feixucs fins al final del camí. La línia de meta del cor sempre te la plantes tu mateix."},"ICON-2111":{"nm":"Tapa lluminosa de batec","de":"Una llumeta diminuta que parpelleja en silenci al ritme del batec del cor. Contemplant amb calma aquest ritme que s'encén i s'apaga, el cor se't commou en pensar que estar viu podia ser una cosa tan constant."},"ICON-2112":{"nm":"Cordó comptador de voltes amb boletes","de":"Comptes les repeticions amb boletes que vas empenyent d'una en una. No cal que et guardis el número al cap: els dits el recorden per tu. Quan deixes el compte a les mans, la ment pot quedar-se del tot en el moviment."},"ICON-2113":{"nm":"Pinça de saturació d'oxigen","de":"Una pinça que es posa a la punta del dit llegeix en silenci l'oxigen que porta la sang. Quan la profunditat invisible de l'alè s'enlaira convertida en xifra, t'adones un cop més que cuidar el cos és, al capdavall, senzillament mirar-lo de prop."},"ICON-2114":{"nm":"Cinta de colors per zones de freqüència cardíaca","de":"Una cinta que divideix la intensitat de l'exercici per colors t'indica d'un cop d'ull com d'exigent és el que fas ara mateix. El blau és calma, el vermell és el límit. És una promesa silenciosa en què el color mateix esdevé un llenguatge senzill i amable."},"ICON-2115":{"nm":"Càpsula de gelatina de mesura","de":"Una petita càpsula de gelatina que mesura l'estat del cos guarda en un sol gra la informació de tot un dia. Sigui el que sigui el que amaga dins la seva closca transparent, hi ha també, ben endins, el desig de conèixer-te una mica millor."},"ICON-2116":{"nm":"Ganxo per a la tovallola de suor","de":"El petit costum de penjar-la sempre al seu ganxo, en lloc de deixar-la tirada a qualsevol lloc, manté ordenada tota una sala. Com aquest ganxo, que reserva un lloc perquè la tovallola hi torni, l'ordre sempre brilla en els detalls més petits."},"ICON-2117":{"nm":"Cordó de la tapa de l'ampolla d'aigua","de":"El cordó curt que penja de la tapa de l'ampolla evita l'ensurt que la tapa rodoli i s'escapi. La saviesa de lligar al cos allò que es perd amb facilitat: un simple cordó s'endú, amb calma, el destorb de tot un dia."},"ICON-2118":{"nm":"Vareta de ventall","de":"Una vareta de ventall que aixeca un cop d'aire quan s'obre del tot. Com aquells ventalls antics que refrescaven la suor els dies de calor, l'eina més senzilla ofereix el consol més fresc. Un sol bufit d'aire sempre floreix des de la punta dels dits."},"ICON-2119":{"nm":"Bosseta per a tovallola refrescant","de":"Una petita bosseta que guarda una tovallola que es refreda quan es mulla. Un sol tros de tela que calma la calor hi dorm arreglat, fins que es posa suaument sobre un clatell cansat i s'endú, en silenci, la xafogor del migdia."},"ICON-2120":{"nm":"Platet recollidor de gotes","de":"Un platet preparat per endavant per recollir el lloc on cauran les gotes acumulades. Fer un espai per recollir allò que degota, en lloc de retreure-li que caigui. La tendresa d'una cuina sempre s'hi queda així, sense fer soroll."},"ICON-2121":{"nm":"Aleta orientadora del ventilador","de":"En el moment en què un raig d'aire de cara es desvia lleugerament seguint una petita aleta, l'aire sufocant de la sala d'assaig respira per fi. Canviar el corrent sempre va ser qüestió d'un angle tan petit com aquest."},"ICON-2122":{"nm":"Cinta per al front","de":"Si el serrell es mulla mentre et rentes la cara, tot el dia queda desfet. Aquesta cinta, que aixeca suaument els cabells per damunt del front, regala a la persona del mirall cinc minuts eixuts. Només te n'adones quan hi falta."},"ICON-2123":{"nm":"Suport amb pinça per al got","de":"Quan el got trontolla perillosament a la vora de l'escriptori, aquesta pinça n'agafa amb calma un costat. Un dia que passa sense vessar-se, un glop d'aigua et recorda que és gràcies a algú que t'ha subjectat la vora en el teu lloc."},"ICON-2124":{"nm":"Ganxo per a finestra d'aeració","de":"Una finestra ben tancada ofega, una d'oberta de bat a bat refreda massa. Aquest ganxo recorda just l'escletxa adequada entremig. Ventilar és, al capdavall, cosa del cor: deixar les coses obertes just el que cal."},"ICON-2125":{"nm":"Protector de cantonada de suro","de":"Sempre és la cantonada punxeguda la que fa mal quan hi topes. Per això es talla un tros de suro i se'n cobreix cada racó. Un lloc embolcallat amb suavitat ja no fa mal a cap genoll."},"ICON-2126":{"nm":"Nansa per a coixí cilíndric","de":"Traslladar un coixí llarg és més feixuc del que sembla. Amb una simple nansa, hi cap perfectament en una mà. El truc per aixecar amb lleugeresa allò que pesa depèn d'on hi poses la nansa."},"ICON-2127":{"nm":"Sivella de cinturó","de":"Hi ha dies que cenyeixes la cintura un forat més i dies que l'afluixes un forat. La que coneix amb més honestedat com estàs avui és aquesta petita sivella. Un tros de metall que enregistra en silenci la franquesa del cos."},"ICON-2128":{"nm":"Suport de bloc en quart","de":"Un bloc tallat en quatre parts sosté amb fermesa el terra. Ni massa alt ni massa baix, amb just aquest equilibri. Mostra, sense dir res, que sostenir és rebaixar-se un mateix per aixecar el que hi ha al damunt."},"ICON-2129":{"nm":"Funda per a coixí en forma d'ou","de":"Vesteixes amb una peça ben ajustada un coixí en forma d'ou. Encara que s'impregni de suor, només cal treure-la i rentar-la. La llar sap que com més contacte diari té una cosa amb la pell, més necessita una peça de recanvi."},"ICON-2130":{"nm":"Falca anivelladora per a blocs","de":"Si el terra s'inclina encara que sigui una mica, tot el que has apilat amb cura trontolla. Fica una falca prima en aquell buit i el món recupera l'horitzontalitat. Redreçar les coses no requereix res de grandiós."},"ICON-2131":{"nm":"Bola de nus per a la punta de la corretja","de":"Fas un nus ben fet perquè la punta de la corretja no es desfili ni pengi. Un cordó amb l'extrem rematat amb pulcritud dura molt de temps. Un sol nusset ensenya que acabar bé és més difícil que començar."},"ICON-2132":{"nm":"Coixinet plegable per als genolls","de":"Aquell dolor punyent cada cop que el genoll toca un terra dur. Un sol coixinet, que es plega i es desplega, s'esmuny suaument entre el genoll i el terra. És una tendresa que sosté el genoll d'algú en el seu lloc."},"ICON-2133":{"nm":"Base antilliscant per a blocs","de":"Per fort que sigui un bloc, si llisca, no serveix de res. Els solcs diminuts gravats a la base s'aferren fort al terra. El secret de mantenir-se ferm sempre s'amaga a la cara inferior, la que no es veu."},"ICON-2134":{"nm":"Pinça per alinear tiges","de":"Alinees les tiges ben rectes i les subjectes amb una pinça. Qui està avesat a posar les coses en filera ho sap: aquella satisfacció estranya i petita que sorgeix de deixar en ordre allò que estava tort."},"ICON-2135":{"nm":"Baga per a estirament d'isquiotibials","de":"Quan la part posterior de la cuixa estira tant que se t'escapa un gemec, aquesta baga arriba en lloc teu fins a la punta del peu que la mà no toca. Allà on no arribaves sol, un simple cordó tendeix un pont per a la cama."},"ICON-2136":{"nm":"Coixinet separador de dits del peu","de":"Fins i tot els dits del peu, tancats tot el dia dins la sabata, necessiten un respir. Sobre un coixinet que els separa, el peu s'estira per fi. Un vespre que et deslliga a partir del lloc més llunyà."},"ICON-2137":{"nm":"Regle mesurador d'angle postural","de":"A ull, no hi ha manera de saber quants graus s'ha desviat la teva postura. Quan el regle t'indica en silenci l'angle, el cos per fi es posa dret. Una escala que mostra la inclinació que no podies veure."},"ICON-2138":{"nm":"Falca d'alineació pèlvica","de":"Una tarda pesant, amb la pelvis encarcarada i inclinada cap a un costat. Hi recolzes una falca i, a poc a poc, recuperes el centre. No és forçar-ho a redreçar-se, sinó ajudar-lo a retrobar el seu lloc just."},"ICON-2139":{"nm":"Sivella de banda obridora d'espatlles","de":"Una banda que redreça amb suavitat les espatlles encongides. Estrenys la sivella i l'esquena corbada s'obre a poc a poc. Respires fondo amb les espatlles ben obertes, i només aleshores apareix la postura de la salutació a l'escenari."},"ICON-2140":{"nm":"Falca de suport per a la columna","de":"T'ajeus d'esquena i la columna dibuixa la seva corba natural. Una falca que sosté amb calma aquella corba sense contrariar-la. Saber descansar bé comença per acceptar la corba amb què el cos ha nascut."},"ICON-2141":{"nm":"Falca d'estirament per a l'empenya","de":"Estirar l'empenya sempre quedava una mica curt. Amb la falca adequada de suport, t'estires de gust fins a una profunditat que abans no arribaves. Una petita rampa que t'ajuda a arribar una mica més lluny."},"ICON-2142":{"nm":"Reposacanells alineador","de":"Quan un canell doblegat davant del teclat comença a formiguejar, el reposacanells s'hi enfila per sota amb suavitat. Els primers a tenir cura de les mans que treballen llargues hores són objectes humils i de terra baixa com aquest."},"ICON-2143":{"nm":"Benda de suport per al canell","de":"Abans d'aixecar alguna cosa pesant, et cenyeixes una benda al canell donant-hi una volta. Una tranquil·litat que creix amb cada volta. El costum d'embenar-se abans de fer-se mal és el secret silenciós de qui s'entrena a llarg termini."},"ICON-2144":{"nm":"Braçalet portamòbil","de":"On deixar el mòbil mentre corres sempre havia estat un maldecap. Aquesta bosseta cenyida a l'avantbraç se n'endú la preocupació. Corre amb la teva cançó preferida cenyida al braç, i el camí es fa molt més curt."},"ICON-2145":{"nm":"Tapa de molla per a l'aparell d'agafada","de":"Una tapa que cobreix l'extrem de la molla d'un aparell d'agafada perquè no clavi la palma de la mà. Mentre repeteixes obrir i tancar la mà, aquest petit tap manté la pau entre la mà i el metall. Una atenció en un lloc que no es veu."},"ICON-2146":{"nm":"Didal protector per a guant","de":"Els dits de l'àvia, avesats a cosir, sempre duien un didal. Aquest didal encaixat a la punta del guant protegeix la punta del dit. El desig d'estalviar patiment a unes mans que han treballat molt s'assembla, sorprenentment, generació rere generació."},"ICON-2147":{"nm":"Coixinet per a caleres de l'agafada","de":"Les caleres formades a la palma són l'empremta que hi deixa l'esforç. Un coixinet que s'hi posa al damunt fa possible la propera repetició. Embolcallant de nou el lloc endurit, la persona torna a penjar-se."},"ICON-2148":{"nm":"Cinta antilliscant per a la palma","de":"Si la palma no para de lliscar, acabes deixant anar allò que has agafat amb tant d'esforç. Envolques la cinta aspra i la mà i l'eina esdevenen un sol cos. La força de no deixar anar ve, sorprenentment, de la fricció."},"ICON-2149":{"nm":"Suador per a l'avantbraç","de":"Abans que la suor vessada durant l'entrenament arribi al canell, aquest suador de l'avantbraç la xucla primer. Que la suor no és cap vergonya, ho testimonia sense paraules una tela ben xopa."},"ICON-2150":{"nm":"Penjador assecador de guants","de":"Deixar-los tirats de qualsevol manera fa que l'endemà al matí sigui un suplici, però penjats amb cura, la brisa els asseca sols i tous durant la nit. L'olor neta d'uns guants ben eixuts obre el dia de demà fresc i net."},"ICON-2151":{"nm":"Tirador de cremallera esportiva","de":"Amb les mans xopes, és impossible agafar una cremallera tan petita. Amb un sol tirador afegit, n'hi ha prou amb una estirada neta. Un aro insignificant salva de cop tot un minut d'atabalament."},"ICON-2152":{"nm":"Pegat de ventilació antisuor","de":"Poses un pegat de ventilació al punt més calent del cos. La calor atrapada s'escapa a poc a poc pels seus forats. L'acte d'obrir un petit respirador just al mig d'allò que ofegava."},"ICON-2153":{"nm":"Peça de coixí per a plantilla","de":"Retalles només la part gastada d'una plantilla vella i hi encaixes una peça nova. Una mà que no ho llença tot, sinó que substitueix només allò que fa mal. Una petita reparació sota el peu alleugereix cada pas del dia."},"ICON-2154":{"nm":"Número tèrmic per a roba esportiva","de":"Marques el número del darrere a la roba prement-lo amb la planxa. Mentre la calor es refreda, el número s'assenta ferm sobre el teixit. El segell inicial pel qual les persones que porten el mateix número esdevenen un sol equip."},"ICON-2155":{"nm":"Puntera reforçada per a sabata","de":"Una puntera reforçada aplicada a la punta atura amb calma el destí d'una sabata que no para de picar amb el dit del peu. El lloc que primer es gasta, fet el més resistent. Com més duradora la sabata, més sòlida és des de la punta."},"ICON-2156":{"nm":"Nus del cordó de cintura esportiu","de":"En el moment en què estires el cordó de la cintura i el lligues, la roba que anava folgada s'ajusta cenyida al cos. Aquest nus ferm, que no es desfà, manté tot en ordre durant els moviments més intensos."},"ICON-2157":{"nm":"Banda antilliscant per a mitjó curt","de":"Aquell destorb d'un mitjó curt que no para de rebregar-se cap dins de la sabata. Una simple banda atura aquest lliscament. Un mitjó tan petit que ningú n'havia fet cas manté per fi el seu lloc."},"ICON-2158":{"nm":"Coixinet antisuor per a l'aixella","de":"Un coixinet col·locat per endavant on més brolla la suor. Encara que s'amari del tot, no es nota ni un rastre a la superfície de la roba. Les coses que treballen en silenci fora de la vista mantenen net l'escenari."},"ICON-2159":{"nm":"Baga tiradora del taló","de":"Un cop calçada la sabata, estires la baga del taló i el peu hi entra de seguida. Aquella breu comoditat que t'estalvia haver-te d'ajupir. Un matí atrafegat, una simple baga com aquesta fa un favor de fill."},"ICON-2160":{"nm":"Capçal per a pistola de massatge","de":"Canvies el capçal segons la zona que vols percudir. Cada múscul tens té la seva forma adequada. Un vespre que tria, per a unes espatlles que han aguantat el dia, la intensitat de consol exacta."},"ICON-2161":{"nm":"Base de càrrega per a pistola de massatge","de":"Fins i tot la mà que et destensarà el cos tot el dia només es desperta un cop carregada. Mentre el llum vermell canvia a verd, pots descansar una estona. Quan el parpelleig s'atura, el torn de tornar a acariciar unes espatlles encarcarades arriba en silenci."},"ICON-2162":{"nm":"Dial d'intensitat per a pistola de massatge","de":"Fluix, una mica més, fins aquí. Girant el dial, la punta dels dits negocia en calma amb el seu propi cos. La promesa d'avui, enfortir-se només tant com fa mal, queda escrita amb precisió entre les petites marques."},"ICON-2163":{"nm":"Anell de suport per a bola vibratòria","de":"Fins i tot una bola que rodola bé necessita un lloc on aturar-se un moment. Aquest suport rodó acull amb calma el desig de rodolar i marxar, mantenint-li el lloc fins que arribi el proper torn. Descansar també forma part de l'exercici."},"ICON-2164":{"nm":"Capçal de nansa per a bastó d'acupressió","de":"Amb una sola tapa petita posada a la punta, el dolor de la palma s'esvaeix suaument. Entre la duresa i la pell sempre cal una capa suau. Un petit gest amable que primer arrodoneix el punt que farà contacte."},"ICON-2165":{"nm":"Bosseta per a rodet de cacauet","de":"Una petita bossa que guarda un rodet en forma de cacauet. Quan surt rodolant d'un racó de la bossa, arriba amb ell també el propòsit d'ahir de cuidar-se una mica avui. Una bosseta petita que recorda una promesa."},"ICON-2166":{"nm":"Suport per al rodet de peus","de":"Si el lloc on confies els peus trontolla, també trontolla el descans. Aquest suport que manté dret el rodet s'agafa ferm al terra, i crea un lloc on dos peus cansats poden recolzar-s'hi tranquils. La confiança ve de no trontollar."},"ICON-2167":{"nm":"Tap per al nucli del rodet","de":"Un petit tap que tanca un nucli buit. L'interior invisible ha d'estar ple perquè l'exterior no es desfaci. Aquell lloc que ningú veurà mai mentre rodola, aquesta peça silenciosa el sosté sense dir res."},"ICON-2168":{"nm":"Tap per a bastó de massatge","de":"Una tapa arrodonida a l'extrem del bastó. Perquè no es gasti, perquè no ratlli: protegir la punta és, al capdavall, la manera de conservar-lo molt de temps a prop teu. El desig d'embolcallar amb la màxima suavitat el primer lloc que rep un cop."},"ICON-2169":{"nm":"Tallador de rotlle de cinta","de":"Estires amb una sola mà i la cinta es talla neta. Fins i tot en lligar i acabar hi ha un petit truc, i aquesta fulla coneix el tacte d'un final endreçat. Un bon acabat fa més lleugera la propera cosa."},"ICON-2170":{"nm":"Tapa adhesiva per a la punta de la cinta","de":"Una tapa que prem amb calma la punta perquè no es desfaci. Tothom sap començar, però mantenir-se enganxat fins al final sempre és difícil. Aquesta petita mà que subjecta el darrer tram es fa càrrec, en silenci, de l'acabat d'avui."},"ICON-2171":{"nm":"Màniga de compressió per al canell","de":"Envoltes amb una sola capa un canell sobreexigit, i el dolor arriba amb un compàs de retard. Com una mà que et sosté en silenci, la compressió esdevé de vegades la protecció més tendra. No és estrènyer: és sostenir."},"ICON-2172":{"nm":"Sivella de suport per al turmell","de":"El clic breu de tancar la sivella tranquil·litza l'esperit. Embolcalles el turmell amb fermesa i sorgeix, poc a poc, un coratge que diu que potser està bé fer una passa més lluny. Un so petit esdevé un inici sòlid."},"ICON-2173":{"nm":"Sivella per a corretja de compressió del genoll","de":"El genoll es fa més ferm com més estrenys la corretja. Que no es desfaci, però que no faci mal: enmig hi ha una marca que hi encaixa perfectament. La sivella no oblida mai aquell punt, cada vegada."},"ICON-2174":{"nm":"Tisores per a cinta dels dits","de":"Unes tisores petites que tallen amb precisió la cinta enrotllada al voltant d'un nus del dit. Amb la punta rodona, no fereixen la pell. Com més pensada és una eina per tenir cura, més tendrament s'esmola la seva fulla: aquestes tisores ho mostren en silenci."},"ICON-2175":{"nm":"Enrotllador per a banda de compressió","de":"Un motllo que torna a enrotllar amb pulcritud una banda de compressió desfeta. Una mà que enrotlla amb cura allò que ja ha usat evita que es faci un embolic la propera vegada. En cada capa enrotllada amb ordre hi ha impregnada la pulcritud d'avui."},"ICON-2176":{"nm":"Corretja per a canyellera","de":"Una corretja que lliga la canyellera que protegeix el davant de la tíbia. La ment que primer es fixa en el punt que podria rebre un cop és, ella mateixa, preparació. Entrar al camp amb les cames ben lligades redueix a la meitat la por que hi ha al cor."},"ICON-2177":{"nm":"Pinça per a protector de colze","de":"Una petita pinça que mossega amb fermesa perquè el protector no llisqui avall. Tan trivial com agafar un full de paper, però si això es desferma, tot es fa fluix. Una petita fixació manté ferma la tranquil·litat de tot un dia."},"ICON-2178":{"nm":"Nansa d'anella per a estiraments","de":"Agafes l'anella i estires el cos ben llarg, i veus la punta dels dits arribar un pam més lluny que ahir. No és només el múscul allò que s'allarga en estirar. Un cor encarcarat, mentrestant, també es va desplegant a poc a poc."},"ICON-2179":{"nm":"Separador de dits del peu","de":"Separes els dits del peu, tancats tot el dia dins la sabata, i una brisa s'esmuny en aquell espai estret. Al món hi ha algunes coses que només es tornen còmodes quan han estat una estona separades. Fins i tot la punta del peu necessita un espai per respirar."},"ICON-2180":{"nm":"Falca relaxant per a la panxell","de":"Encaixada com una falca sota la panxell, la cama es va destensant a poc a poc. Un sol angle inclinat deixa escapar en calma el pes de tot un dia. Reclinar-se amb una lleugera inclinació és, de vegades, la postura més còmoda de totes."},"ICON-2181":{"nm":"Reposacoll relaxant","de":"Hi deixes el coll penjat i tanques els ulls una estona. Que ja pots deixar reposar un moment el cap feixuc, aquest petit suport ho xiuxiueja fluixet a les espatlles, sempre des del mateix lloc. Fins i tot recolzar-se requereix coratge."},"ICON-2182":{"nm":"Tapa per a pal d'estirament","de":"Una sola tapa que cobreix l'extrem d'un pal que s'allarga. Amb la punta suau, toqui on toqui, es queda tranquil. Arrodonir primer les cantonades, sigui cap a qui es dirigeixi: la consideració sempre comença així, en silenci."},"ICON-2183":{"nm":"Coixí de picons d'acupressió","de":"T'ajeus sobre els picons rugosos i, a cada punt premut, se n'escapa una mica del dia. En aquella frontera entre el dolor i l'alleujament, les espatlles encarcarades de tot el dia es van deslliurant a poc a poc, com si es rendissin."},"ICON-2184":{"nm":"Rellotge de sorra per a la respiració","de":"Una promesa silenciosa d'allargar l'alè fins que caigui l'últim gra de sorra. El fil prim de sorra compta amb calma el ritme de l'inspir i l'expir. Una ment atrafegada, mentrestant, també s'assossega una estona."},"ICON-2185":{"nm":"Suport de bola d'acupressió per a la planta del peu","de":"Recolzes una bola al mig de la planta del peu i hi premes amb constància. Als peus que han sostingut tot el cos tot el dia, aquest petit suport els cedeix el seu lloc en silenci, dient-los que ara els toca a ells ser sostinguts. Fins i tot allò que sosté té moments de descans."},"ICON-2186":{"nm":"Cordó d'anella relaxant per a l'espatlla","de":"Un cordó amb anella que es penja a l'espatlla i s'estira. Allargues la corda cap al punt encarcarat, i una articulació engarrotada s'afluixa lliure, marca a marca. Mostra que fins i tot fer-se lliure necessita alguna cosa que et doni la mà."},"ICON-2187":{"nm":"Disc de la corda de carrer","de":"Un únic gra rodó de la corda que separa els carrers de la piscina. Una frontera amable traçada sobre l'aigua perquè no topis amb el nedador del costat. Les petites separacions que vetllen pel camí de cadascú fan avançar tothom, en paral·lel, fins al final."},"ICON-2188":{"nm":"Ganxo de tensió per a la corda de carrer","de":"Un ganxo que estira ben tibant la corda de carrer i la subjecta. Si va massa fluixa, es corba amb l'onatge; si s'estira massa, es trenca. Trobar la tensió justa s'assembla a assossegar l'esperit: sempre cal tantejar en algun punt entremig."},"ICON-2189":{"nm":"Tapa de color per a carrer","de":"Un petit tap pintat d'un color diferent per a cada carrer. Un senyal acolorit perquè reconeguis el teu camí d'un cop d'ull, fins i tot de lluny. Evitar que algú s'esgarriï amb un sol color: l'orientació, al fons, comença amb amabilitats tan petites com aquesta."},"ICON-2190":{"nm":"Tauler penjador per a cordes de carrer","de":"Un tauler on penjar amb ordre les cordes de carrer quan no s'usen. En la mà que arregla amb cura les cordes per a la propera sortida, hi ha, en silenci, la calma voluntat de tancar bé el dia d'avui."},"ICON-2191":{"nm":"Nansa d'enrotllador per a corda de carrer","de":"Fas girar la nansa una vegada i una altra per recollir la corda llargament desplegada. Aplegar allò que s'ha escampat sempre demana paciència. Una volta, i una altra: un final es completa així, a poc a poc, sense pressa."},"ICON-2192":{"nm":"Pinça per al nus de la corda de carrer","de":"Una pinça que mossega amb fermesa perquè el nus de l'extrem de la corda no es desfaci. No deixa escapar ni un sol tros solt. Cal una mà que vigili fins al final perquè una corda llarga conservi la seva forma polida sense desfer-se."},"ICON-2193":{"nm":"Boia de la corda de carrer","de":"La boia de la corda de carrer que sura sobre l'aigua. Per no enfonsar-se, ha acumulat tant d'aire com pot al seu interior. Que certa lleugeresa ve d'un buit omplert amb esforç, ho fa surar, cada vegada, l'aigua que oneja."},"ICON-2194":{"nm":"Banderola de número de carrer","de":"Una petita banderola que anuncia el número del carrer. Un tros de tela que oneja al vent et diu clarament: «aquest és el teu lloc». Un senyal petit però inequívoc que et fa entrar directament al teu camí sense esgarriar-te."},"ICON-2195":{"nm":"Ganxo connector per a corda de carrer","de":"Un ganxo que uneix una corda de carrer amb la següent. Amb un sol ganxo que torna a enllaçar un camí trencat, el camí de l'aigua queda per fi complet. Connectar és, al capdavall, la feina d'un petit tros de metall que allarga en silenci una mà entre coses que s'han separat."},"ICON-2196":{"nm":"Trepitjador del bloc de sortida","de":"El trepitjador sobre la línia de sortida rep tot el pes del primer salt. Aquell 0,1 segon d'impulsar-se amb força: la fermesa on trepitgen els dits del peu empeny l'inici de tota una cursa. Tot enlairament comença en un lloc on trepitjar amb fermesa."},"ICON-2197":{"nm":"Barra d'agafada de sortida","de":"La barra que les mans agafen fort just abans del senyal de sortida. Cal ancorar en algun lloc el cor tremolós perquè la sortida no es tambalegi. Només el fet de tenir on agafar-se fa que el proper moviment sigui molt més clar i ferm."},"ICON-2198":{"nm":"Línia de banderoles d'esquena","de":"Una línia de banderoles que avisa qui neda mirant el sostre que la paret ja és a prop. Una amabilitat que anuncia per endavant allò que no es pot veure. Amb un sol senyal que vetlla amb cura per la teva esquena, l'última braçada es torna segura."},"ICON-2199":{"nm":"Coixí de la paret de virada","de":"Un coixí suau afegit a la paret on es canvia de direcció. Perquè no faci mal encara que s'hi topi fort, encoixina tou el punt on es gira. Al camí de tornada sempre hi ha, primer, la consideració silenciosa d'algú."},"ICON-2200":{"nm":"Placa tàctil d'arribada","de":"En el moment en què la punta dels dits hi toca, tot s'acaba. El final d'un camí llarg i sense alè es redueix, al capdavall, a aquest únic cop lleuger. Arribar no és res de grandiós, sinó tocar exactament el punt just, respon en calma la placa."},"ICON-2201":{"nm":"Franja de sortida del tobogan","de":"Quan es planta al capdamunt del pendent, tothom conté l'alè almenys una vegada. Si supera aquest breu moment de por i es deixa lliscar avall, esclat—les rialles esclaten junt amb l'esquitxada d'aigua. La sortida sempre comença just més enllà d'un petit racó de por."},"ICON-2202":{"nm":"Con senyalitzador de gir","de":"Quan dubtes en una cruïlla, aquest petit punt és el primer a parlar-te. Gira aquí, diu, no et perdis. Algú veu aquest sol color i torna a trobar el seu rumb, i continua caminant."},"ICON-2203":{"nm":"Falca angular del bloc de sortida","de":"Aquell mig temps en què el cos s'arrupeix més baix, just abans del salt. Un petit recolzament hi és, sostenint l'angle perquè les puntes dels peus no relliscin. Cada instant que s'enlaira neix d'aquest pendent."},"ICON-2204":{"nm":"Protector de cantonada de paret","de":"Perquè no faci mal encara que hi topis mentre jugues, la cantonada ha cedit la seva aresta i s'ha arrodonit. El desig que no et facis mal s'ha anat llimant fins a quedar enganxat a la paret. La protecció més tendra sol ser així de silenciosa."},"ICON-2205":{"nm":"Ganxo penjador del salvavides","de":"Normalment és només un lloc on penja alguna cosa. Però en el moment en què algú cau a l'aigua, és aquí on una mà s'estén primer. Al món també hi ha una mena de fiabilitat que és millor que no s'utilitzi mai."},"ICON-2206":{"nm":"Perxa de rescat amb ganxo","de":"Un braç llarg que escurça d'un sol cop una distància inabastable. Quan la mà no arriba, aquest ganxo fa de mà en el seu lloc. Rescatar és, al capdavall, l'acte d'oferir les puntes dels dits a algú que és lluny."},"ICON-2207":{"nm":"Dutxa de vora de piscina","de":"\"Assegura't d'esbandir-te abans d'entrar.\" Com la frase habitual del socorrista, un doll d'aigua cau sobre el cap. Amb un sol raig fred, la pols del dia s'esmuny i cau."},"ICON-2208":{"nm":"Rajola antilliscant","de":"Fines textures en relleu perquè els peus descalços no relliscin. Des d'un racó invisible, sostenen amb calma les plantes dels peus. La seguretat més ferma sempre s'amaga en els llocs menys vistosos."},"ICON-2209":{"nm":"Rètol de profunditat de l'aigua","de":"Abans de posar-hi el peu, el número indica primer la profunditat. Un lloc que faria por si hi entressis sense saber-ho, un cop llegit, calma la ment. El que fa aquest rètol és ajudar amb una petita preparació."},"ICON-2210":{"nm":"Corda de boies de seguretat","de":"Cordes de colors que suren a l'aigua i marquen les zones. Fins aquí és segur, prometen les boies agafades de la mà. Gràcies al límit, per fi es pot nedar lliurement amb el cor tranquil."},"ICON-2211":{"nm":"Banyera desinfectant per als peus","de":"Una petita banyera on els peus descalços s'aturen un instant abans d'entrar a l'aigua. Hi ha un breu ritual de netedat que comença pels peus. La netedat sempre comença amb aquest petit gest de cura."},"ICON-2212":{"nm":"Con d'avís de terra mullat","de":"Un con groc alenteix suaument els passos. \"Aquí està mullat, compte.\" Una atenció que es dona amb color en lloc de paraules. Aquest petit avís vetlla en silenci pel dia d'algú que gairebé llisca."},"ICON-2213":{"nm":"Armari de primers auxilis de paret","de":"L'armari blanc de la paret gairebé mai s'obre. Però just en el moment en què s'obre, es converteix en l'alleujament d'algú. L'emergència sempre espera en silenci al lloc més proper."},"ICON-2214":{"nm":"Sedàs escumador de superfície","de":"Recull amb calma les fulles i la pols que suren a la superfície. La claredat no arriba sola, cal que cada dia una mà la reculli. Darrere l'aigua tranquil·la hi ha un sedàs diligent."},"ICON-2215":{"nm":"Mànega del robot netejador de fons","de":"Fins i tot en una nit en què tothom dorm, es passeja lentament palpant el fons. El treballador més fidel en les hores en què ningú no mira. Aquella transparència del matí és el traçat que aquesta mànega ha dibuixat tota la nit."},"ICON-2216":{"nm":"Dosificador de clor","de":"Fins i tot mantenir l'aigua neta té la seva quantitat exacta. Massa i es torna agressiva, massa poc i es torna tèrbola—l'equilibri entremig. Una mà invisible ajusta cada dia aquesta mesura amb calma."},"ICON-2217":{"nm":"Ampolla d'anàlisi de l'aigua","de":"Recull un glop d'aigua en una petita ampolla i pregunta com es troba avui. A ull sembla igual, però els números no menteixen. La tranquil·litat és una cosa que es comprova un cop al dia, així."},"ICON-2218":{"nm":"Rascle recollidor de taules flotants","de":"Un rascle llarg que arreplega taules i objectes que suren a l'aigua. Una mà que replega el que està escampat s'assembla, d'alguna manera, al cor. Fins i tot el desordre, escombrat una vegada, queda endreçat."},"ICON-2219":{"nm":"Reixeta de desguàs","de":"Una malla fina que vigila el pas per on surt l'aigua. Tria en silenci què deixar anar i què retenir. Fins i tot per deixar anar les coses cal un filtre, diu sense paraules aquesta petita malla."},"ICON-2220":{"nm":"Boia termòmetre","de":"Un petit explorador que sura a l'aigua i llegeix la temperatura. Freda o adequada, una amabilitat que t'ho diu abans que el teu cos hi toqui. El primer alleujament d'entrar a l'aigua sempre comença amb aquesta boia."},"ICON-2221":{"nm":"Barra enrotlladora de lona de piscina","de":"Un mànec que enrotlla una lona ampla i la guarda a un costat. Una eina que sap quan estendre's i quan recollir-se resulta, d'alguna manera, fiable. En les hores de descans, és com tapar l'aigua amb un edredó."},"ICON-2222":{"nm":"Cistella del skimmer","de":"La cistella on finalment s'aplega la brutícia que ha anat surant per la superfície. Perquè hi ha un recipient que recull les deixalles en un racó invisible, l'aigua de dalt sempre és clara. Darrere la netedat s'acumula l'esforç."},"ICON-2223":{"nm":"Penjador assecador de gorres de bany","de":"Es penja una gorra de bany xopa cap per avall. Mentre cau gota a gota, la gorra recupera l'alè a poc a poc. Assecar-se és, al capdavall, un altre nom per a l'espera."},"ICON-2224":{"nm":"Anella de tirant de banyador","de":"Una petita anella que sosté el tirant perquè no llisqui de l'espatlla. Des d'un racó invisible, manté amb calma l'aspecte en ordre. L'elegància sempre s'acaba de completar sobre suports tan petits com aquest."},"ICON-2225":{"nm":"Bossa organitzadora de gorres de bany","de":"Una bossa on les gorres de bany mullades van trobant el seu lloc, una a una. Un petit refugi que aplega en una sola abraçada les coses fàcils de perdre. Endreçar és un costum tendre per no perdre les coses."},"ICON-2226":{"nm":"Copa de banyador","de":"Un sol coixinet col·locat suaument a l'interior de la peça. Encara que no es vegi per fora, redreça amb dolçor les espatlles de qui el porta. Certa seguretat s'omple en silenci des de dins, no des de fora."},"ICON-2227":{"nm":"Clip per etiquetar gorres de bany","de":"Un petit clip que subjecta una etiqueta amb el nom a la vora d'una gorra de bany. Entre coses idèntiques, diu ben clar: \"aquesta és la meva.\" Amb una sola marca, les confusions s'acaben de cop."},"ICON-2228":{"nm":"Anella de cremallera de banyador","de":"\"Em pots pujar la cremallera de l'esquena?\" Aquell punt que sol no arribes a tocar, aquesta petita anella el puja en lloc d'una mà. Un gest tendre que et fa costat en aquell darrer tram."},"ICON-2229":{"nm":"Suport antiplecs per a gorres de bany","de":"Redreça i sosté una gorra de bany que s'ha acostumat a enrotllar-se. Un suport que ajuda amb calma que allò torçat recuperi la seva forma. Cal que hi hagi una mà que ho redreci perquè qualsevol cosa torni a quedar plana i com cal."},"ICON-2230":{"nm":"Ajustador de cintura de banyador","de":"Un ajustador que embolcalla la cintura just com cal i evita que llisqui avall. Ni massa prieto ni massa fluix, exactament el punt just. La comoditat sempre viu en algun lloc entremig."},"ICON-2231":{"nm":"Pinça per girar gorres de bany","de":"Una pinça que agafa una gorra de bany del revés i la posa dreta d'un sol gest. El plaer de tornar les coses girades al seu lloc just és força satisfactori. El petit gust d'endreçar ve de coses tan insignificants com aquesta."},"ICON-2232":{"nm":"Corretja de la taula de natació","de":"Una corretja que s'enrotlla a la mà perquè no perdis la taula. Fins i tot empès pel corrent, tenir alguna cosa a què agafar-se és un gran consol. El tremolor d'aquell dia en què vas aprendre a batre cames encara hi és, en aquesta corretja."},"ICON-2233":{"nm":"Corretja de subjecció del pull buoy","de":"Una corretja que sosté fermament la boia encaixada entre les dues cames. Només quan no es deslliga et pots concentrar del tot en la postura. Sobre allò ben subjectat, l'entrenament d'aquell dia s'aprofundeix pam a pam."},"ICON-2234":{"nm":"Penjador de peülles de paret","de":"Quan les peülles pengen arrenglerades a la paret, semblen tot just un estol d'ànecs descansant a la vora de l'aigua. Uns peus que han acabat de nedar espolsen l'aigua i esperen el demà. Fins i tot la pausa és, d'alguna manera, rodona i entranyable."},"ICON-2235":{"nm":"Protector de cantonada de la taula de natació","de":"Un petit protector que cobreix la cantonada de la taula de natació. Perquè no faci mal si hi toca ni s'espatlli amb el desgast, embolcalla la punta. El secret per conservar-la molt de temps rau a tenir cura de les cantonades primer."},"ICON-2236":{"nm":"Xarxa d'emmagatzematge de peülles","de":"Les peülles, que s'assemblen a peus palmats, prenen el sol dins la xarxa. Com ànecs que acaben de sortir de l'aigua eixugant-se les plomes, s'assequen a poc a poc dins la malla. Una migdiada tranquil·la abans de la propera nedada."},"ICON-2237":{"nm":"Etiqueta organitzadora de pull buoy","de":"S'enganxa una etiqueta a cada boia per deixar clar de qui és. Com més compartit és un lloc, més tranquil·litza saber ben clar de qui és cada cosa. Una petita etiqueta posa ordre."},"ICON-2238":{"nm":"Suport d'escorriment per a taules de natació","de":"Un lloc inclinat perquè l'aigua acumulada a la taula de natació rellisqui i s'escoli. Cal buidar el que s'ha absorbit per fer-se lleuger, diu en silenci el suport. El primer pas per assecar-se és sostenir bé les coses."},"ICON-2239":{"nm":"Ajustador de corretja de peülles","de":"Una petita peça que ajusta la corretja de la peülla perquè encaixi bé al peu. Massa fluix i es despenja, massa prieto i fa mal—aquell punt just i delicat. Per avançar amb lleugeresa com un ànec de peus palmats, cal aquest petit marge."},"ICON-2240":{"nm":"Xip de ritme de batuda de cames","de":"Un petit xip que marca el compàs cada vegada que batega el peu. Un, dos, tres—quan el ritme s'incorpora al cos, l'aigua es converteix, sense adonar-te'n, en cançó. Aquest xip ensenya amb suavitat que nedar també té el seu compàs."},"ICON-2241":{"nm":"Bossa per a banyador mullat","de":"Dins la bossa que surt de la piscina, la primera a reclamar un lloc sempre soc jo. Que la resta d'equipatge em miri de reüll, què hi puc fer, allò mullat s'ha de tenir a part perquè tots plegats quedem eixuts. La cambra de quarantena de la humitat, aquest és el càrrec tendre que ocupo."},"ICON-2242":{"nm":"Tauler premsador escorredor d'aigua","de":"L'aigua té la mania de fugir en el moment en què la premses. Un cop ferm, i un altre—només es rendeix quan hi poses el pes al damunt de la taula. Per a qui mai no havia tingut ús per a la força del canell, poques vegades hi ha un escenari com aquest."},"ICON-2243":{"nm":"Separador de bossa de natació","de":"Si ho fiques tot en un sol compartiment, el mullat i el sec s'encomanen l'un a l'altre. La feina de ficar-s'hi de puntetes entremig i traçar-hi una línia amb calma. Si un sol separador porta la pau, potser la reconciliació és, sorprenentment, una cosa senzilla."},"ICON-2244":{"nm":"Bossa impermeable per a sabates","de":"Empassa senceres unes sabates plenes de sorra sense canviar ni un bri l'expressió. Passi el que passi a dins, que per fora quedi eixut—aquesta és la cortesia que manté la impermeabilitat. Una bossa discreta és benvinguda a tot arreu."},"ICON-2245":{"nm":"Tap de desguàs de bossa de natació","de":"Gira el tap i el dia que s'havia acumulat al fons de la bossa se n'escola de cop. Endreçar després d'una bona estona de joc sempre depèn d'aquest petit forat. Fins i tot saber deixar anar les coses requereix disseny."},"ICON-2246":{"nm":"Estora eixugapeus","de":"Jeu en silenci davant l'entrada, recollint la humitat de cada peu que arriba. Encara que ningú no ho reconegui, el terra ho sap—avui tampoc ha relliscat ningú. En un lloc callat hi habita una recompensa callada."},"ICON-2247":{"nm":"Platet per a gorres de bany mullades","de":"Quan una gorra de bany llançada de qualsevol manera es queda sense lloc on anar, jo la sostinc. Encara que em diguin platet i aculli gotes d'aigua en comptes de menjar, si la feina és fer un lloc per a algú, fins i tot un suport pot alçar el cap amb orgull."},"ICON-2248":{"nm":"Pinça d'estendre tovalloles","de":"La feina de mossegar amb força una tovallola damunt el fil d'estendre. El meu orgull és una tossuderia que no afluixa per molt que el vent m'provoqui. Fins que no s'asseca ben tova al sol, una mà que ha agafat no deixa anar mai primer."},"ICON-2249":{"nm":"Penjador per a bossa impermeable","de":"En el moment que penja del ganxo, la bossa que anava a la deriva per fi té una adreça. Encara que només sigui penjar-hi, tot llogant un pam de paret, hi ha alguna cosa tan reconfortant com un lloc on no cal témer perdre's?"},"ICON-2250":{"nm":"Braçalet d'accés al tobogan","de":"L'emoció de qui esperava pacientment el seu torn queda tota lligada en aquest petit braçalet. Fins que no es tanca al canell, la cua del tobogan no comença a ondular, així que potser entrar és l'acte de fermar-se una promesa al canell."},"ICON-2251":{"nm":"Peça d'estora del tobogan aquàtic","de":"La gent hi corre alegrement al damunt, sense adonar-se mai de l'escletxa sota els peus. Col·locada perquè ningú no relliscui, només revela la seva existència quan falta aquesta peça. Al món hi ha força coses que es recorden només pel buit que deixen."},"ICON-2252":{"nm":"Braçalet impermeable per a clau de tàquilla","de":"Vigilar una clau de tàquilla de l'aigua és la meva feina de tota la vida. Enrotllat al canell, també esquitxo amb tu, però la clau la mantinc del tot eixuta. Perd-me i ni tan sols trobaràs la roba, així que, ben mirat, soc un funcionari amb una gran responsabilitat."},"ICON-2253":{"nm":"Panell de semàfor de sortida del tobogan","de":"En aquell breu instant en què el vermell canvia a verd, tots els cors dalt del tobogan bateguen alhora. L'autoritat de donar permís per sortir—qui diria que un panell de senyals tan petit podia contenir tanta emoció."},"ICON-2254":{"nm":"Sivella de l'armilla salvavides del riu lent","de":"La sivella que subjecta fermament el cos de qui flota pel riu lent. Només després d'aquell clic et pots relaxar per fi i lliurar el cos al corrent. De vegades, la tranquil·litat comença amb un petit tancament com aquest."},"ICON-2255":{"nm":"Bandera de senyalització de la piscina d'onades","de":"Avisa tothom amb antelació de quan arribaran les onades. Bandera amunt, aplaudiments; bandera avall, un moment per agafar alè. Curiosament, el que marca el compàs vora la piscina bombollejant és un simple tros de tela."},"ICON-2256":{"nm":"Collaret amb número per al tobogan","de":"Porta al coll a quina cua estàs i no hi haurà cap confusió. Una sola etiqueta numerada decideix a qui toca—l'ordre, sembla, sovint comença amb un petit collaret com aquest."},"ICON-2257":{"nm":"Fitxa de recàrrega per a braçalet","de":"Toca'l lleugerament al braçalet i la recàrrega està feta. En una època de moure's per l'aigua sense diners ni targetes, aquesta petita fitxa fa tot el paper d'una cartera. Com més lleuger el canell, més lleuger el cor."},"ICON-2258":{"nm":"Tap d'agafador de canó d'aigua","de":"L'agafador d'un canó d'aigua és millor com més fort s'aferra. Perd un tap i oblida't d'apuntar, tan sols giravolta a la mà, i el desenllaç d'una batalla d'aigua d'estiu depèn d'aquesta petita peça final."},"ICON-2259":{"nm":"Motlle de torre per a castells de sorra","de":"Omple'l de sorra mullada, prem fort, capgira'l, i s'alça una petita torre. Ningú no coneix millor que jo el cor que segueix construint tot i saber que s'ensorrarà. Per a un arquitecte de sorra, el motlle és el plànol."},"ICON-2260":{"nm":"Pues de rasclet de sorra","de":"Arrossega'l com si pentinessis la sorra i queden solcs endreçats. Sabent que les onades esborraran aviat el dibuix, les pues tracen igualment les seves ratlles amb diligència. Hi ha un cert encant a construir amb esment coses destinades a desaparèixer."},"ICON-2261":{"nm":"Pes ancorador per a para-sol","de":"Es planta en silenci als peus perquè el para-sol no s'emporti el vent. Mantenir l'ombra no és tasca de la tela vistosa, sinó del pes feixuc i clavat a terra. El pes invisible és sempre el més fiable."},"ICON-2262":{"nm":"Mànec de sedàs per a sorra","de":"Sacseja per garbellar la sorra i només queden a la mà petxines i petits tresors. Agafa el mànec i belluga'l endavant i endarrere—la meitat de la cerca de tresors a la platja es decideix amb aquest sol sedàs."},"ICON-2263":{"nm":"Motlle de sorra en forma de petxina","de":"Omple'l de sorra mullada, dona-hi copets, i petxines de la mida d'una mà floreixen en filera per la platja. Encara que no et puguis menjar una petxina de veritat, aquesta forma la pot fer qualsevol. Una humil màgia d'estiu."},"ICON-2264":{"nm":"Passador d'ajust d'angle de para-sol","de":"Cada cop que es mou el sol, el para-sol també ha de girar el cap per seguir-lo. Treu el passador, torna'l a posar, i l'ombra es desplaça en silenci. El nucli de l'art d'esquivar la llum és en aquest petit angle."},"ICON-2265":{"nm":"Tap de punta de pala de sorra","de":"Posa'l a la punta esmolada de la pala i l'interior de la bossa queda segur. Deixa de banda per un moment la bravura de cavar sorra, i amb un sol tap es torna una joguina dòcil. Saber amagar el tall també és una atenció."},"ICON-2266":{"nm":"Pinça de cantonada per a estora de platja","de":"Quan el vent intenta aixecar la cantonada de l'estora, jo la mossego fort. Mantenir un sol lloc a la sorra depèn, al final, de la tossuderia de les quatre cantonades. Una tarda sense onejar és obra de petites pinces."},"ICON-2267":{"nm":"Ganxo per penjar roba a l'ombra del para-sol","de":"Penja-hi al pal del para-sol i la roba mullada s'asseca a l'ombra. Lluny del sol, dins la brisa, un estenedor improvisat fet per un sol ganxo. Fins i tot a la platja hi ha lloc per a la saviesa de la llar."},"ICON-2268":{"nm":"Bossa impermeable de coll per a mòbil","de":"Bressola el mòbil, penja-te'l al coll, i trobes el coratge de fer fotos fins i tot sota l'aigua. Mantenir a resguard i eixut aquell desig de guardar una foto més. Com a guardaespatlles dels records, és força competent."},"ICON-2269":{"nm":"Bossa impermeable per a roba mullada","de":"Acull sencera, sense cap queixa, la roba mullada que t'has canviat. No deixar caure ni una gota sobre la resta de l'equipatge és el seu orgull, així que manté la boca ben tancada i vigila un racó de la bossa. Un final net comença per mi."},"ICON-2270":{"nm":"Tira d'empenya per a sandàlies d'aigua","de":"Embolcalla amb suavitat l'empenya perquè la sandàlia de peu descalç no es despengi. Corre pel sorral tant com vulguis, amb una sola tira n'hi ha prou per estar tranquil. Un company fiable dels teus passos, discret però sempre al costat."},"ICON-2271":{"nm":"Estoig impermeable de coll per a targetes","de":"Amb entrades i targetes a dins, penja del coll i s'uneix al bany. Esquitxa tant com vulguis sense por de perdre res, perquè fa servir el propi cos com a escut per protegir les targetes. La postura d'un guardaespatlles de confiança."},"ICON-2272":{"nm":"Estoig de tela antibafarada per a ulleres de natació","de":"Neteja amb el drap l'interior entelat de les ulleres una sola vegada, i el món sota l'aigua torna a ser nítid. Un petit estoig de tela és, doncs, la clau que obre una visió tèrbola cap a la claredat."},"ICON-2273":{"nm":"Raspall per treure sorra","de":"Escombra amb suavitat fins i tot la sorra entre els dits dels peus. L'última mà que endreça, just a la porta de casa, les traces d'un capbussó alegre a la mar. Un sol passi del raspall, i la sorra d'un dia sencer diu adeu per fi."},"ICON-2274":{"nm":"Moneder impermeable amb cremallera","de":"Tanca ben bé unes quantes monedes darrere una cremallera. Mullat o no, el dring segueix sonant igual, així que els diners d'emergència per al quiosc queden custodiats fins al final. Una bossa petita, però estalviadora i capaç."},"ICON-2275":{"nm":"Cinta per enrotllar tovalloles","de":"Enrotlla una tovallola, lliga-la amb una sola cinta, i queda penjada de dret a la corretja de la bossa. Les mans lliures, la tovallola a l'espatlla. El secret de banyar-se lleuger d'equipatge s'amaga en aquest petit lligam."},"ICON-2276":{"nm":"Tap del portaclaus del braçalet impermeable","de":"El botó final del braçalet que protegeix una clau de l'aigua. Només quan el tap tanca amb un clic et llences per fi tranquil a la piscina. Un punt final petit però impecable que es fa càrrec de segellar el tancament."},"ICON-2277":{"nm":"Boquilla de tub de respiració","de":"Mossega-la i s'obre el camí de l'aire, i el paisatge marí s'acosta fins als teus ulls. Un petit tap que et deixa respirar fins i tot sota l'aigua. Qui diria que prestar un alè podia ser tan emocionant."},"ICON-2278":{"nm":"Coixinet antibaf per a màscara","de":"Quan l'interior de la màscara s'entela, l'espectacle sota l'aigua també perd la gràcia. Un sol coixinet aguanta aquella boira, així que una visió nítida és obra d'aquesta capa invisible."},"ICON-2279":{"nm":"Clip d'ajust de la punta de la peülla","de":"Cenyeix la punta de la peülla perquè encaixi just al peu, sense marge, per batre l'aigua. Perquè la força d'una sola batuda no s'escapi, el clip lliga en silenci un nus ben ajustat a la punta."},"ICON-2280":{"nm":"Funda de corretja per a màscara","de":"Embolcalla amb suavitat la corretja de la màscara perquè no estiri els cabells. Una sola capa d'atenció que esborra aquell picor de cada vegada que te la treus. El que cuida una petita funda és, sorprenentment, la tendresa."},"ICON-2281":{"nm":"Tap de la vàlvula de purga del tub","de":"Fins i tot en l'acte de retenir l'alè hi ha una escletxa per on l'aigua s'escola en silenci. Una petita vàlvula desvia amb suavitat aquell rajolí cap enfora i custodia fins al final l'espai per inspirar. El mar recorda amb la gratitud més gran aquesta petita cura."},"ICON-2282":{"nm":"Ganxo per guardar peülles","de":"Quan les peülles pengen endreçades d'un sol ganxo clavat a la paret, una calma ordenada s'assenta fins i tot en el magatzem desendreçat. Deixar les coses al seu lloc és la promesa més silenciosa cap a la propera immersió."},"ICON-2283":{"nm":"Coixinet nasal de màscara","de":"Un sol coixinet que prem suaument el nas. Gràcies a aquesta petita tendresa que impedeix que l'aigua entri de cop, la cara no perd la seva expressió ni tan sols dins el mar fred."},"ICON-2284":{"nm":"Protector superior del tub de respiració","de":"El protector que envolta en rodó la punta del tub empeny amb calma l'aigua enrere quan una onada passa per sobre. Com més invisible és la feina d'una peça, més sosté en profunditat la seguretat d'un sol alè."},"ICON-2285":{"nm":"Tira antilliscant de sola de peülla","de":"Una tira prima enganxada a la sola de la peülla. És l'única línia de fricció a què s'aferren les puntes dels peus per no relliscar en una coberta mullada. La seguretat sempre comença en silenci en petites textures com aquesta."},"ICON-2286":{"nm":"Tap de vàlvula d'ampolla d'oxigen","de":"Un tap que cobreix la vàlvula d'una ampolla plena d'aire. Perquè la pols no s'hi assenti, perquè el camí de l'aire no es taqui. Cobrir-la és tenir cura per endavant, fins i tot del primer alè de la propera persona."},"ICON-2287":{"nm":"Tap de boquilla del regulador","de":"El lloc que toca els llavis sempre ha de ser el més net. Aquest sol tap sobre la boquilla protegeix en silenci la porta de l'alè del vent salat i la sorra."},"ICON-2288":{"nm":"Anella tiradora de la cremallera del vestit de busseig","de":"Una petita anella lligada a la cremallera del vestit de busseig. És un detall pensat perquè fins i tot mans entumides per l'aigua freda la puguin estirar amunt d'un sol cop. Fins i tot en el fet de cordar-se la roba s'hi filtra la cura de qualcú."},"ICON-2289":{"nm":"Tap protector del manòmetre d'aire","de":"El tap protector que embolcalla el vidre del manòmetre que indica l'aire restant. Perquè aquells números no s'han d'entelar mai. Com més llegeix un dial la vida mateixa, amb més cura es neteja i es cobreix."},"ICON-2290":{"nm":"Sivella del cinturó de llast","de":"Gent que es cenyeix pesos a la cintura per baixar cap a les profunditats. En l'instant en què una sola sivella es desclou i es tanca, l'elecció entre pujar i enfonsar-se s'aplega en silenci a la punta dels dits."},"ICON-2291":{"nm":"Corretja de canell per a llanterna de busseig","de":"A l'aigua fosca com la boca d'un llop, una sola tira lligada al canell aferra fort la llanterna. Encara que deixis anar la mà, la llum et segueix. No perdre una petita llum enmig de la foscor és, per això, reconfortant."},"ICON-2292":{"nm":"Clip endreçador de mànega de respiració","de":"Un petit clip que aplega en un sol lloc les mànegues escampades. Evita els embolics per endavant i les mans no es perdran ni en un moment de pressa. Endreçar és una amabilitat silenciosa cap al jo del futur."},"ICON-2293":{"nm":"Reforç de dits per a guants de busseig","de":"Tela de reforç afegida a cada punta de dit. Els llocs que estiren cordes i s'agafen a roques són sempre els primers a desgastar-se, així que s'hi ha posat una capa extra per abraçar per endavant aquell desgast."},"ICON-2294":{"nm":"Anella de suport per a ampolla d'aire","de":"Una sola anella de suport que manté dreta una ampolla feixuga. Abraça en rodó un pes que d'altra manera cauria, i li dona equilibri. Sostenir és el gest de deixar el propi costat perquè alguna cosa no caigui."},"ICON-2295":{"nm":"Tap de quilla de taula de surf","de":"Un tap que embolcalla la punta esmolada de la quilla sota la taula. Perquè no et facis mal en caminar per la sorra, adorm per una estona aquell fil que tallava les onades. Mentre descansa, tothom es pot permetre estar una mica esmussat."},"ICON-2296":{"nm":"Tap protector de pala de rem","de":"Un tap protector que vigila la punta de la pala del rem. Impedeix que les esgarrapades de les roques trenquin el flux de l'aigua. Si cuides la punta, una sola remada et porta més lluny."},"ICON-2297":{"nm":"Empunyadura de rem de caiac","de":"Una empunyadura enrotllada allà on la palma i el rem es troben. Encoixina amb suavitat el lloc on abans es formaven butllofes, perquè les mans no acabin avorrint el rem ni tan sols mentre remuntes el riu."},"ICON-2298":{"nm":"Llauna de cera de surf","de":"Una petita llauna que guarda un tros de cera. Aquella màgia que enganxa els peus a la taula sempre es treu d'aquest estoig de la mida d'una mà. La preparació d'avui comença amb una sola llauna endreçada."},"ICON-2299":{"nm":"Anella de subjecció del turmell per a leash","de":"L'anella que cenyeix el leash que uneix turmell i taula. Un sol nus que promet no deixar-te anar ni quan t'endugui una onada grossa. Connectar és una promesa de retenir perquè no t'allunyis massa surant."},"ICON-2300":{"nm":"Tap d'aire de taula de paddle surf","de":"Una taula que s'enforteix quan es plena d'aire, i el tap que en tanca l'alè. Obre'l i es plega plana, tanca'l i s'aguanta dreta sobre l'aigua. Un sol tap petit guarda un dia que s'infla i es desinfla."},"ICON-2301":{"nm":"Corretja de coixí del seient de caiac","de":"Una corretja que lliga el coixí al seient. Per a l'esquena i la cintura que reman assegudes durant hores, manté la tovor al seu lloc perquè no llisqui. Fins i tot la comoditat necessita un nus ferm."},"ICON-2302":{"nm":"Protector de morro de taula de surf","de":"Un protector que embolcalla la proa de la taula. És un coixinet afegit al morro, on els cops són freqüents, perquè s'esmussi ell primer. Posar tovor al lloc que va al capdavant és una promesa d'usar-la molt de temps."},"ICON-2303":{"nm":"Fivella de tancament de bossa impermeable","de":"Una fivella que es plega i es cordona dues, tres vegades, perquè no hi entri ni una gota. Mantenir seques les coses precioses sempre demana un toc més de la mà. Aquell únic estrenyiment ferm es converteix en tranquil·litat."},"ICON-2304":{"nm":"Tros de xarxa de porteria de futbol sala","de":"Un tros de la xarxa que un dia va fer tremolar la porteria. Recorda, fil a fil, els crits d'alegria de l'instant en què una pilota l'omplia. En cada nus hi vivia un gol, i en cada racó desfilat encara hi viu el partit d'aquell dia."},"ICON-2305":{"nm":"Broquet d'inflador de pilota de futbol","de":"Un broquet d'inflador que insufla aire a una pilota desinflada. El cuir que rodolava, pla i desanimat, torna a saltar i botar. Omplir-la és tornar a posar dret un joc aturat."},"ICON-2306":{"nm":"Base de banderola de córner","de":"Una base que manté dreta la banderola a la cantonada del camp. És una petita marca del límit, però amb aquest sol punt, la terra nua pren per fi la forma d'un estadi."},"ICON-2307":{"nm":"Corretja de canyellera","de":"Una corretja que lliga la canyellera al panxell. Subjecta fermament el lloc que rep els cops més sovint, perquè cada pas es mantingui valent fins i tot enmig d'un joc dur."},"ICON-2308":{"nm":"Passador de recanvi de tacs","de":"Un passador per canviar un tac gastat per un de nou. Les petites dents de la puntera que s'agafen a la gespa. Per no relliscar, de vegades cal reconstruir des de sota mateix."},"ICON-2309":{"nm":"Tap de vàlvula de pilota de futbol","de":"Un petit tap que segella el forat d'alè de la pilota. Vigila l'entrada perquè l'aire que hi vas ficar no s'escapi. Mantenir-la tibant s'assembla molt a no perdre l'embranzida fins al proper partit."},"ICON-2310":{"nm":"Con marcador de línies","de":"Un con que traça línies a terra per dividir el camí. Fins aquí som nosaltres, des d'allà són ells. Un sol con petit converteix un solar desendreçat en un pati de jocs amb regles."},"ICON-2311":{"nm":"Raspall de pols per a botes de futbol sala","de":"Un raspall que escombra la pols i la terra encallades a les ranures de les botes de futbol sala. Quan acaba el partit, també a les sabates s'hi acumula la terra d'un dia sencer. La mà que la treu és un gràcies silenciós als peus que han corregut tan bé."},"ICON-2312":{"nm":"Penjador de guants de porter","de":"Un penjador que asseca i sosté els guants del porter. És on descansen una estona les mans xopes de suor, tantes com les aturades que han fet. Per al proper partit, el que és mullat s'asseca i el cor endurit s'afluixa a poc a poc."},"ICON-2313":{"nm":"Ganxos de xarxa de cistella","de":"Els petits ganxos que pengen la xarxa de l'aro. Gràcies a ells, la pilota fa aquell so suau en passar-hi. Aquell so cristal·lí d'una cistella comença, en realitat, en aquests petits ganxos."},"ICON-2314":{"nm":"Eina de desinflament de pilota de bàsquet","de":"Una eina que deixa sortir una mica d'aire d'una pilota massa dura. Massa tibantor fa el bot salvatge. Alleugerir-la just al punt. Una pilota de bon tacte sempre neix d'aquest equilibri precís."},"ICON-2315":{"nm":"Placa sensora del tauler","de":"Una placa sensora enganxada darrere el tauler. Llegeix l'instant en què la pilota el toca, clarament, en xifres. Fins i tot l'instant que l'ull s'ha perdut, aquest petit sentit el recorda, i així la decisió es fa una mica més justa."},"ICON-2316":{"nm":"Cons d'obstacles per al regat","de":"Cons obstacle alineats al llarg del camí de dribling. Esquivant-los d'una banda i de l'altra, creix la traça dels peus. Posar-se pel mig també és una amabilitat, que ensenya a escapolir-se encara millor."},"ICON-2317":{"nm":"Raspall de vàlvula de pilota de bàsquet","de":"Un petit raspall que neteja el forat de la vàlvula de la pilota. Si la pols l'obstrueix, l'agulla no hi entra, així que primer es neteja aquesta entrada invisible. Abans d'omplir, sempre cal buidar i eixugar."},"ICON-2318":{"nm":"Rotlle d'esparadrap per a dits","de":"Un rotlle d'esparadrap que s'enrotlla al voltant dels dits. Subjecta fermament una articulació torçuda, i dona el coratge d'agafar la pilota de nou. Embenar una ferida és una petita declaració de no aturar-se."},"ICON-2319":{"nm":"Clip de dorsal","de":"Un clip que fixa el número a la samarreta. En lloc del teu nom, un número recorre la pista. En aquell únic pessic ferm perquè no caigui, hi queda escrit clarament qui juga avui."},"ICON-2320":{"nm":"Anella de puntaria per a llançaments","de":"Una anella diana encaixada dins l'aro per estrènyer el blanc. Redueix el punt on ha d'entrar la pilota, ensenyant-te a suportar els errors. Llança prou vegades cap a aquella porta estreta i, sense adonar-te'n, els dits aprenen la precisió."},"ICON-2321":{"nm":"Eixugador de sola per a sabatilles de bàsquet","de":"Abans d'entrar a la pista, t'ajups i eixugues primer les soles. Perquè no vols deixar ni un sol relliscó al parquet. Planta aquest primer pas amb la puntera neta, i el tu d'avui és una mica més ferm que el d'ahir."},"ICON-2322":{"nm":"Ganxo tensor de xarxa de voleibol","de":"La tibantor no es veu. Només en l'instant en què el ganxo estira la corda fins al final i s'atura, la xarxa divideix la pista en dues amb un pam de tensió. Un equilibri sostingut per una mà invisible desperta el joc."},"ICON-2323":{"nm":"Clip fixador d'antena","de":"L'antena que no parava de tremolar amb el vent es manté dreta amb un sol clip. Una cosa petita que atura un gran balanceig. La mà que fixa en silenci un sol cable rere l'escenari es mou amb exactament aquest mateix cor."},"ICON-2324":{"nm":"Penjador de la samarreta de líbero","de":"L'armilla d'un altre color de l'especialista en defensa penja a la paret, esperant el proper partit. Sense ser vistosa, és un nom que sosté tota la pista: el líbero. Allà, en el lloc més baix, hi ha els ulls que veuen més lluny."},"ICON-2325":{"nm":"Bossa per a genolleres","de":"Com més rodoles pel terra, més sovint els genolls reben un cop. Aquesta petita bossa que guarda amb cura les genolleres ho sap: només qui aprèn primer a caure bé, al final, vola més lluny."},"ICON-2326":{"nm":"Manòmetre de pilota de voleibol","de":"No es pot saber amb un simple copet dels dits. L'agulla del manòmetre tremola fluixament i assenyala una sola marca. Mesurar l'alè d'una pilota és el primer botó del partit. D'una pressió honesta neix una trajectòria honesta."},"ICON-2327":{"nm":"Cinta de línia del joc de matar","de":"Un sol cercle dibuixat amb cinta a la terra del pati. El seu dins i el seu fora divideixen un univers de joc d'agafar-se de mig dia. La mà que traça la línia ho sap: les regles són el mateix començament del joc."},"ICON-2328":{"nm":"Suport de xiulet d'àrbitre","de":"Quan el so agut del xiulet calla, torna a reposar tranquil al seu lloc sobre el suport. El lloc que sent més de prop l'alè de l'àrbitre. La justícia sempre comença amb la petita tasca de mantenir cadascú el seu lloc."},"ICON-2329":{"nm":"Diana de paret per a pràctica de tocs","de":"En l'alba sense ningú per rebre, alces els dits milers de vegades cap a la diana enganxada a la paret. La paret és la companya més indulgent. La pilota que et retorna alça de nou un tu cansat."},"ICON-2330":{"nm":"Vara mesuradora d'alçada de xarxa","de":"Si la xarxa és tan sols un dit més baixa, el joc es desvia. En l'instant que alces la vara mesuradora, la justícia esdevé no un número sinó un hàbit diari. Una precisió invisible vetlla per la pista."},"ICON-2331":{"nm":"Passador d'angle del taco de sortida","de":"Des de la postura ajupida, l'angle on la puntera toca el taco, aquell únic grau decideix la sortida. Amb un sol passador fixes el taco i calmes l'alè. La postura de l'inici et segueix en silenci fins a la línia de meta."},"ICON-2332":{"nm":"Banderola de número de carrer","de":"Una petita banderola clavada a cada carrer fa onejar el seu número al vent. Tots corren en la mateixa direcció, però cadascú té el seu propi camí. La pista acull alhora la igualtat costat a costat i la diferència."},"ICON-2333":{"nm":"Tap de testimoni de relleus","de":"Per a l'instant en què tocarà la mà de l'últim corredor, el tap arrodoneix les vores. En una cursa de relleus, el més preciós no és la velocitat, sinó la mà que passes al següent."},"ICON-2334":{"nm":"Penjador de cinta mètrica de rècords","de":"Pengeu a la paret la cinta mètrica que va anotar les marques, perquè no s'embolici. El lloc on la distància d'ahir i la d'avui pengen l'una al costat de l'altra. El creixement sempre arriba primer com una petita diferència en xifres."},"ICON-2335":{"nm":"Con marcador de corba de pista","de":"Un petit con situat a l'interior de la corba t'indica la intenció del camí. No et fiquis massa endins, ni et dispersis massa enfora. Qui gira bé, al final, va sempre al capdavant."},"ICON-2336":{"nm":"Clip de cinta de meta","de":"Aquella cinta que serà la primera a tocar un pit, el clip la manté tibant i espera. Una línia que existeix per ser trencada. Aguanta el vent tot el dia per l'únic segon d'algú."},"ICON-2337":{"nm":"Funda de pistola de sortida","de":"Fins que ressona el tret del senyal, el canó dorm sota la seva funda. Un vas de so que guarda a dins la sortida. Com més profund el silenci, més lluny arriba l'eco del primer tret."},"ICON-2338":{"nm":"Passador d'ajust d'alçada de tanca","de":"Cada cop que puges l'alçada un graó, el lloc del passador canvia per seguir-la. I la por creix exactament d'aquesta mateixa mesura. Tot i així, els peus calculen cada cop un punt una mica més alt i continuen corrent."},"ICON-2339":{"nm":"Comptador de voltes giratori","de":"Quan perds el compte de quantes voltes queden, gires el disc un graó. El petit clic d'un número que minva torna a donar força a les cames. La mà que compta la distància que queda et manté el ritme."},"ICON-2340":{"nm":"Suport per guardar pèrtigues","de":"Una pèrtiga llarga i flexible necessita el seu propi racó on recolzar-se. Perquè és una eina que ha de corbar-se per enlairar-se, la col·loques amb més cura encara. Una flexibilitat ben guardada sosté el salt més alt."},"ICON-2341":{"nm":"Rasclet aplanador de fossa de sorra","de":"Amb calma allises amb el rasclet fins i tot les petjades que ha deixat l'atleta anterior. La fossa de sorra torna a quedar plana, com la primera vegada, cada volta. La mà que esborra les traces pel salt d'algú és allà, silenciosa i fidel."},"ICON-2342":{"nm":"Cinta marcadora de distància de la cursa d'impuls","de":"Un pas de menys no serveix, i un pas de més tampoc. La cinta marcadora de distància a terra t'indica honestament on plantar el peu. Una bona cursa d'impuls no és una avarícia temerària, sinó que neix d'un càlcul serè."},"ICON-2343":{"nm":"Empunyadura de disc","de":"Si els dits llisquen, el llançament ja s'ha llançat abans fins i tot de llançar-lo. La textura rugosa de l'empunyadura que envolta el disc reté el gir. El moment d'amollar sempre comença en la sensació de com s'agafa."},"ICON-2344":{"nm":"Anella suport de pes","de":"Una anella suport acull en silenci la pesada bola de ferro perquè no rodoli. Un petit niu que guarda la quietud just abans del llançament. Com més explosiva la força, més ferm ha de ser el lloc on reposa."},"ICON-2345":{"nm":"Tap protector de punta de javelina","de":"Un tap posat sobre la punta esmolada de la javelina la cobreix d'un silenci suau. Quan una eina feta per volar lluny jeu quieta, el perill es doma amb consideració. La seguretat també viu dins l'emmagatzematge."},"ICON-2346":{"nm":"Grapa suport de barra de salt d'alçada","de":"Perquè la barra no caigui ni amb un toc lleuger, la grapa la sosté amb un equilibri exquisit. El lloc responsable d'aquella línia tremolosa entre superar-la o no. La justícia habita en els petits detalls."},"ICON-2347":{"nm":"Ancoratge de cantonada de la catifa d'aterratge","de":"Si la cantonada de la catifa d'aterratge s'aixeca, algú es fa mal. L'ancoratge prem fermament les quatre cantonades. Perquè el cos que ha volat més amunt aterri amb la màxima seguretat, l'aguanta, invisible."},"ICON-2348":{"nm":"Cinta de límit del cercle de llançament","de":"El límit del lloc de llançament es traça amb una sola línia de cinta. Trepitjar aquella línia o no fa que un rècord visqui o mori. La línia prima on es troben la llibertat i les regles, una promesa."},"ICON-2349":{"nm":"Peu de goma de la barra d'equilibris","de":"Perquè la barra estreta d'equilibris no oscil·li, el peu de goma mossega el terra amb força. L'equilibri sense tremolor que es desplega a sobre és, en realitat, obra de la fermesa invisible de sota."},"ICON-2350":{"nm":"Embenat d'empunyadura de barra fixa","de":"Perquè la palma no llisqui, enrotlles un embenat a l'empunyadura de la barra fixa. El secret del gir voltejant no rau en la lluïdesa, sinó en una mà ben tancada. La suor caiguda sobre la catifa ho sap."},"ICON-2351":{"nm":"Grapa d'alçada de corretja d'anelles","de":"Si l'alçada de les dues corretges difereix encara que sigui l'amplada d'una palma, l'exercici s'ensorra. La grapa sosté aquell equilibri en silenci. Només sobre una alçada exactament igualada comença per fi un vol lliure."},"ICON-2352":{"nm":"Funda d'ansa de cavall amb arçons","de":"La funda que embolcalla l'ansa evita les bufes a la palma. Sota l'exercici de girs i voltes hi ha una mà que s'ha esgarrapat i guarit incomptables vegades. La protecció és una promesa amable cap a la propera pràctica."},"ICON-2353":{"nm":"Passador d'espai de barres asimètriques","de":"Ajustes amb precisió, amb un passador, l'espai entre les dues barres. Aquell espai buit que el cos travessarà esdevé l'escenari. Els dits ja ho saben abans que ningú: sobre una distància precisa neix el salt més audaç."},"ICON-2354":{"nm":"Tap de molla de trampolí de salt","de":"En l'instant que empenys el trampolí, la molla impulsa el cos cap al cel. El tap embolcalla amb pulcritud la força d'aquell rebot. La cursa d'impuls més curta crea el vol per l'aire més llarg."},"ICON-2355":{"nm":"Bosseta de magnesi","de":"La pols blanca que et poses a les mans és un petit amulet que esborra els relliscons. El breu ritual de ficar i treure la mà de la bosseta apaivaga la por. Fins i tot els nervis, al final, es dominen a la punta dels dits."},"ICON-2356":{"nm":"Embenat de canell per a gimnàstica","de":"Enrotllar la banda al canell estreny alhora els fils del cor. Subjectar per endavant una articulació que trontollaria. Un sol canell ben lligat permet, en silenci, un gir més audaç."},"ICON-2357":{"nm":"Anella de seguretat de trapezi","de":"Just abans de llançar el cos a l'aire, l'anella de seguretat esdevé una mà invisible. Només quan desapareix la por de caure es pot volar més lluny. La confiança completa el vol."},"ICON-2358":{"nm":"Tap de pot de pilotes de tennis","de":"Sota el tap que segella la boca del pot, les pilotes noves dormen retenint la seva pressió. El petit espetec d'obrir una llauna desperta l'emoció del partit. Un segell és una promesa que preserva la frescor."},"ICON-2359":{"nm":"Grapa de tensió de corda de raqueta","de":"La grapa mossega fermament la tibantor de la corda i no l'amolla fins al final. Perquè la tensió d'una sola corda decideix el rebot de la pilota. Aquell tacte invisible comença en aquesta petita grapa."},"ICON-2360":{"nm":"Escombra de línies de pista de tennis","de":"Quan acaba el partit, escombres a poc a poc seguint les línies blanques de la pista. En retirar la pols i la terra, les línies tornen a ser nítides. Obrir el camí per al proper partit, aquesta darrera cura, dona vida a la pista."},"ICON-2361":{"nm":"Cinta protectora de capçal de raqueta","de":"Enrotlla't una volta al voltant de la vora de la raqueta i fins i tot els cops bruscos es reben arrodonits. Sé que la vora és el lloc que es desgasta primer. Com que el meu paper és assumir en el seu lloc aquest desgast, avui també em quedo al costat de fora de tot."},"ICON-2362":{"nm":"Xip de temperatura ambient interior","de":"El vent fred de l'alba que irromp quan s'obre la porta, un xip de la mida d'una palma el llegeix abans que cap persona. Sentir-lo abans fins i tot que el nas es refredi, és la salutació més silenciosa que obre el dia en un gimnàs buit."},"ICON-2363":{"nm":"Placa de peu de la línia de fons","de":"Per a l'atleta que dubta on posar la puntera, una sola línia traçada a terra n'hi ha prou. Que la línia que no s'ha de creuar esdevingui la mateixa línia de sortida per al salt més llarg, la placa t'ho diu sense paraules."},"ICON-2364":{"nm":"Penjador de cistella de pilotes de tennis","de":"Sosté desenes de pilotes d'una glopada i no en deixa caure ni una de sola. Recollir el que s'ha escampat per la pista i lliurar-ho a la propera pràctica, una mà atrafegada en silenci al racó penja avui també aquí."},"ICON-2365":{"nm":"Tap final d'ansa de raqueta","de":"En l'instant que l'encaixes al final de l'ansa, la raqueta finalment s'acomoda a la palma. Un sol tap petit separa el relliscar de la seguretat. Tanca bé l'extrem, i el primer cop de raqueta es fa ferm."},"ICON-2366":{"nm":"Clip de tovallola de vora de pista","de":"Encara que el vent bufi fort, es queda callat i resisteix al costat de la pista perquè la tovallola escorreguda amb cura no s'emporti el vent. Fins i tot en guardar un breu respir per recobrar l'alè, hi ha la punta dels dits diligent d'algú."},"ICON-2367":{"nm":"Pinces per redreçar plomes de volant","de":"Amb una sola ploma desordenada, ja trontolla el vol. Redreça amb cura l'ala arrugada, i el volant es prepara per volar recte de nou. Anar lluny sempre comença amb aquesta mena de petit arranjament."},"ICON-2368":{"nm":"Tap de tub de volants","de":"Perquè els volants alineats a dins no es reblaneixin, tanques fermament l'extrem del tub. He vist prou temps per saber que un sol toc d'humitat enfonsa una ploma. Guardar bé les coses ja forma part del partit."},"ICON-2369":{"nm":"Suport per fer rodar pilotes de tennis taula","de":"La petita pilota que venia rodolant recobra l'alè un moment sobre meu. Sostenir-la en silenci perquè no caigui rodolant, és la consideració de forma més rodona que s'ofereix al costat de la taula."},"ICON-2370":{"nm":"Corró de goma per a pala de tennis taula","de":"Fes rodar el corró suaument sobre la cara de goma i la pols vella s'aixeca mentre l'enganxina reviu. El gir ha de viure perquè la pilota es corbi. La condició d'avui de la pala es desperta amb aquesta única cura tendra."},"ICON-2371":{"nm":"Vareta mesuradora d'alçada de xarxa","de":"Si la xarxa és tan sols un pam més alta, la textura del joc canvia. Els qui no acaben de fiar-se de l'ull m'apropen a ella. Sembla que la justícia només arriba d'una alçada mesurada amb precisió pel regle."},"ICON-2372":{"nm":"Xip mesurador de velocitat de volant","de":"La velocitat del volant que talla l'aire, jo la calculo en silenci. Quan la velocitat abans invisible es posa en una xifra clara, la propera paraula de l'entrenador es fa una mica més precisa. És la feina de convertir una intuïció en un fet."},"ICON-2373":{"nm":"Càpsula per guardar pilotes de tennis taula","de":"Ajeu suaument una pilota rodona dins la càpsula, i les ratllades i la pols es retiren lluny. Desitjant que estigui a salvo fins al proper partit, és el cor que cedeix tota una petita cambra."},"ICON-2374":{"nm":"Penjador de cordes de raqueta de bàdminton","de":"Penja endreçades les cordes fluixes, i la propera mà en el torn no s'hi perd. Endreçar és, al capdavall, com una nota amable escrita per endavant al tu de demà. Avui fa més fàcil el demà."},"ICON-2375":{"nm":"Cinta protectora de vora de pala de tennis taula","de":"La vora on la goma s'aixeca fàcilment, jo l'abraço en silenci amb una sola línia. Si l'extrem s'obre, fins i tot la textura de la pilota es desordena. Protegir la vora esdevé, al final, protegir un sol punt."},"ICON-2376":{"nm":"Bosseta escalfadora de pilota de squash","de":"Una pilota freda a penes bota. Abans del partit, una bosseta que l'escalfa i l'acull càlida com una palma. Aquella petita calor transmesa a la mà fixa per endavant l'alè i el ritme d'una ronda."},"ICON-2377":{"nm":"Grapa de malla de xarxa de lacrosse","de":"Quan un nus de la malla comença a afluixar-se sense fer soroll, jo mossego aquell únic punt sense dir res. La malla ha d'estar tibant perquè la pilota s'hi quedi. Aquí hi ha la mà que sosté tot el joc des d'un lloc invisible."},"ICON-2378":{"nm":"Cinta protectora de punta de raqueta de squash","de":"Com més fort colpeges la paret, més plora la raqueta, primer per la punta. Embolica amb cura aquella punta que plora, i jugarà amb tu una temporada més. Qui sap estalviar la punta, al final, sosté la raqueta molt de temps."},"ICON-2379":{"nm":"Funda de fulla d'estic d'hoquei","de":"Posa la funda sobre la fulla esmolada, i per fi tant la bossa com la punta dels dits queden tranquil·les. Adormir en silenci una cosa perillosa, és la vella cortesia que s'observa primer en preparar un estic."},"ICON-2380":{"nm":"Drap per abrillantar pilota de críquet","de":"Frega la pilota vermella amb el drap, i un costat reté la llum com un mirall. El llançador sap, per la sensació dels dits, que la pilota es corba quan la brillantor viu. Una estratègia silenciosa habita fins i tot en el fet de polir amb cura."},"ICON-2381":{"nm":"Tap de tub per guardar pilotes de lacrosse","de":"Perquè les pilotes dures no rodolin a la seva aire, tanques ben fort la boca del tub. Reunir amb amabilitat en un sol lloc les coses propenses a escampar-se, els fonaments de gestionar les coses són sempre així de petits."},"ICON-2382":{"nm":"Peça diana de paret de squash","de":"Una petita diana clavada a la paret aplega en un sol punt els ulls vacil·lants de l'atleta. L'únic punt que et diu on apuntar, fins i tot aquella paret tan ampla s'estreny en una diana clara davant d'aquesta petita peça."},"ICON-2383":{"nm":"Màniga d'empunyadura d'estic d'hoquei","de":"Trasllada l'empunyadura que la teva mà coneix a un estic nou i desconegut, i en aquell instant l'eina es fa teva a l'acte. Una petita màniga que et permet posar-te la familiaritat com qui es canvia de roba, aquesta és la drecera cap a l'adaptació."},"ICON-2384":{"nm":"Penjador de xarxa de porteria de camp","de":"Cal penjar la xarxa a la porteria perquè un gol per fi sembli un gol. Sempre ha estat la xarxa qui ha retingut fins al final aquell breu instant en què una pilota l'omplia. Al lloc que recull la forma dels crits d'alegria que esclaten, hi soc jo."},"ICON-2385":{"nm":"Funda de fulla de patí","de":"Amb la fulla al descobert, no pots fiar-te de ni un pas fora del gel. Quan deixis el gel, si us plau, posa'm. Adormir en silenci l'esmolat també és una etiqueta que els patinadors han preservat des de fa molt."},"ICON-2386":{"nm":"Penjador de cordons de patí","de":"Els llargs cordons de les botes que t'has tret, els penges endreçats, un a un. Uns cordons deslligats perquè no s'embolici obren amb suavitat la propera vegada sobre el gel. L'acabament d'avui esdevé, així, la preparació per a demà."},"ICON-2387":{"nm":"Tovallola de fulla de patí","de":"Sobre una fulla just sortida del gel, hi perlegen petites gotes. Eixuga aquella humitat amb delicadesa i el rovell passa de llarg. Recollir en silenci les traces que ha deixat el fred, aquest és el meu dia."},"ICON-2388":{"nm":"Coixinet de turmell de bota de patí","de":"Que el turmell trontolli una sola vegada, i tot el lliscament s'ensorra. Un coixinet que l'embolcalla amb fermesa i manté ferm el punt de suport. Aquell equilibri elegant sobre el gel sempre comença primer, en un lloc invisible."},"ICON-2389":{"nm":"Bossa de protectors de fulla de patí","de":"Hi ha una petita bossa en un racó de la bossa per desar amb cura els protectors de fulla. L'hàbit de preparar tot el necessari, sense deixar-se res, manté l'equipament viu molt de temps. Una bossa endreçada és la primera escena d'un bon lliscament."},"ICON-2390":{"nm":"Grapa de plantilla de bota de patí","de":"Perquè la plantilla de dins la bota no llisqui sense fer soroll, la subjecta fermament sota el peu. Si el punt de suport es desvia, el salt també es desvia. La mà que agafa el lloc més baix, al final, ajuda el salt més alt."},"ICON-2391":{"nm":"Anella de la funda de fulla de patí","de":"Perquè la funda no es desllisqui, la tanques ben fermada amb una anella. Sé que una protecció fluixa no és, al final, cap protecció. Una sola anella ben tancada guarda aquella fulla fins al final."},"ICON-2392":{"nm":"Tap d'estrenyiment de cordons de patí","de":"Estira fort els cordons i tanca'ls amb el tap, i ara ja mai més es deslligaran. Cordar-se amb pulcritud i sense escletxes des de la mateixa puntera, és el nus més ferm que es lliga abans del primer pas sobre el gel."},"ICON-2393":{"nm":"Drap eixugador de fulla de patí","de":"D'una fulla que just ha acabat un lliscament, recull en silenci la humitat acumulada. Sé que una fulla deixada mullada plora. Només una fulla ben eixugada dibuixa amb nitidesa la propera corba sobre el gel."},"ICON-2394":{"nm":"Tap d'empunyadura de bastó d'esquí","de":"Embolcalla suaument l'extrem de l'empunyadura del bastó, i la palma que l'agafa es fa molt més còmoda. La força que talla el camp nevat neix, al capdavall, d'aquell lloc fermament agafat. Un sol tap petit sosté fins al final una llarga baixada."},"ICON-2395":{"nm":"Passador de fixació de snowboard","de":"En l'instant que surt el petit passador que unia la taula i el peu, la muntanya que tens davant s'atura. Una peça que cal revisar primer encara que sigui difícil de veure, aquesta connexió ferma esdevé la llibertat sobre la neu."},"ICON-2396":{"nm":"Grapa protectora de punta d'esquí","de":"Perquè la vora esmolada no ratlli l'interior de la bossa, mossega amb suavitat la punta. Apaivagar l'esmolat fins a adormir-lo, és l'amable acabament que ofereixes després d'una bona baixada per la muntanya."},"ICON-2397":{"nm":"Protector de morro de snowboard","de":"Embolcalla bé el morro de la taula, i fins i tot un cop frontal es dispersa amb suavitat. Guardar en silenci el lloc que colpeja primer, el coratge per encarar una baixada abrupta comença precisament aquí."},"ICON-2398":{"nm":"Funda de sivella de bota d'esquí","de":"Perquè la sivella no es faci malbé xocant amb la neu freda, la cobreixes amb cura. Un altre tancament més que guarda el mecanisme de tancament, aquesta petita funda allarga discretament una mica més la temporada de la bota."},"ICON-2399":{"nm":"Anella de corretja de snowboard","de":"Perquè la taula no pugui fugir gaire lluny encara que se t'escapi de la mà, jo uneixo el turmell i la taula en una sola línia. Perquè, encara que la perdis d'agafar, no la perdis del tot, és una anella silenciosa de tranquil·litat penjada a l'extrem d'una corda llarga."},"ICON-2400":{"nm":"Punta rascadora de base d'esquí","de":"La cera vella endurida sobre la base, la retires amb un rasclet suau i llis. Només retirant bé el vell reviu el nou lliscament. Una base tractada amb cura obre el proper camp nevat encara més ràpid."},"ICON-2401":{"nm":"Topall de punta de snowboard","de":"Abans que la taula talli la neu, és la punta qui toca primer el món. Cada impacte el rep primer aquest petit tros de goma. Al capdavant, desgastant-se sense fer-ne mai ostentació: la baixada d'algú llisca sobre aquesta devoció discreta."},"ICON-2402":{"nm":"Anella de la cistella del bastó d'esquí","de":"Just quan el bastó és a punt d'enfonsar-se en la neu profunda, aquesta vora rodona tempteja el terra en el seu lloc. Un cercle que sosté en silenci un pas que gairebé ha relliscat. Encara que no es vegi, es queda a prop com una mà que t'evita relliscar."},"ICON-2403":{"nm":"Tapa del raspall d'encerar el cantell","de":"Quan acaba l'arranjament, cobreix suaument les cerres abans que la pols s'assequi. Segellar la suavitat d'avui perquè cap fibra es desviï. Perquè, quan la tornis a obrir, la cura d'ahir hi sigui esperant tal com era."},"ICON-2404":{"nm":"Penjador d'orelleres","de":"Te'n recordes? Les orelleres oblidades una estona al costat de la motxilla quan arribava la primavera. Però la nit que arriba la notícia de la primera nevada, són les primeres a ser cridades. Hi ha un lloc especial per penjar l'estació, i aquest ganxo mai oblida aquesta promesa."},"ICON-2405":{"nm":"Estoig de la pedra d'esmolar","de":"Per esmolar un ganivet, primer cal mullar la pedra: una seqüència amarada com el tacte de l'àvia. Fins i tot una eina que doma l'esmussament necessita un lloc on descansar, així que aquesta petita casa acull la pedra i espera el proper arranjament."},"ICON-2406":{"nm":"Bossa del bloc de cera","de":"El mateix material que fa una baixada brillant jeu compacte i adormit al seu interior. Un pes ferm que sosté un bloc endurit. La lliscada sempre es desplega des d'aquest pes silenciós i s'escampa pel camp de neu."},"ICON-2407":{"nm":"Anella de la bossa de l'escalfamans","de":"En un passeig d'hivern, el lloc que els dits busquen primer dins la butxaca. Dona una llar fixa a aquesta petita calidesa que desglaça les mans gelades. Com més fred fa el dia, més amable es torna aquesta petita anella."},"ICON-2408":{"nm":"Suport de la pedra d'esmolar el cantell","de":"Si trontolla, el tall surt tort, així que ella mateixa es fixa ferma primer. Un suport que mai es mou, tot per ser responsable de la precisió d'algú altre. El tall recte d'algú es manté dret sobre aquesta fermesa silenciosa."},"ICON-2409":{"nm":"Clip de l'escalfacoll","de":"En un camí fred i ventós cap a l'escola, just quan l'escalfacoll comença a relliscar: clic, al coll de l'abric. Fins i tot l'escalfor ha de mantenir el seu lloc per poder escalfar de veritat. Un sol petit so reté l'escalfor del matí."},"ICON-2410":{"nm":"Funda de la planxa d'encerar","de":"Mentre la superfície que ha treballat tan calenta es refreda, un sol drap la protegeix en silenci de la pols. Una eina que en cuida una altra que ha preparat la lliscada. La cura continua així, en silenci."},"ICON-2411":{"nm":"Tapa del retolador d'oli per al cantell","de":"Un cop obert, si s'asseca, no es pot traçar la línia següent. Així que tancar-lo és el mateix que obrir el següent: aquesta petita tapa segella la humitat de la punta, tot prometent per endavant el traç de demà."},"ICON-2412":{"nm":"Capçal del pompó d'animació","de":"Centenars de fils parteixen d'aquest únic punt i s'escampen a l'uníson seguint el ritme. L'esplendor del balanceig sempre comença en un lloc fermament lligat. Sota l'escenari, el primer nus que fa onejar el públic."},"ICON-2413":{"nm":"Corretja de mà del bastó lluminós","de":"Després de dues hores animant, just quan la vareta lluminosa gairebé se t'escapa de les mans, aquesta corretja la torna a la teva mà. El desig de no perdre-la ni tan sols quan cau. Aquesta tendra inquietud ha fet un llaç sobre el teu canell."},"ICON-2414":{"nm":"Clip plegable del coixí de graderia","de":"Aixecar-se d'un salt i seure de nou desenes de vegades mentre animes. Mentrestant, aquest petit clip plega bé el coixí i et guarda el lloc. Fins i tot en una graderia eufòrica, hi ha un tacte discret que vetlla pel seient d'algú."},"ICON-2415":{"nm":"Anella del mocador d'animació","de":"El dia que el mateix estampat s'estén per tota la graderia, un sol tros de tela lliga desenes de milers de cors en un únic color. El primer punt on comença aquesta onada és aquesta petita anella: el lloc on una animació solitària es converteix en un nosaltres."},"ICON-2416":{"nm":"Meitat de la paleta d'aplaudir","de":"Sol, l'aplaudiment és un so petit; reunit a la graderia, es converteix en una onada. L'única meitat que coneix, més honestament que cap altra cosa, la veritat que només ressona quan troba l'altra. En el moment en què el teu aplaudiment troba el meu, l'ànim creix."},"ICON-2417":{"nm":"Protector de cantonada del cartell d'animació","de":"Embolica la cantonada punxeguda perquè la persona del costat no es faci mal. Fins i tot en un balanceig fervent, hi ha consideració cap als altres amagada dins. L'ànim es torna més càlid com més arrodonit és."},"ICON-2418":{"nm":"Suport de l'asta de la cinta d'animació","de":"Fins i tot quan l'oneig s'atura, l'asta es manté dreta, esperant el proper clam. Un lloc que descansa quiet un moment perquè pugui tornar a onejar. Entre un clam i el següent, un breu silenci on la cinta recupera l'alè."},"ICON-2419":{"nm":"Ventall megàfon d'animació","de":"Perquè el crit d'una sola persona arribi fins al final de l'escenari, la forma de ventall n'estreny el camí del so. Una boca que sempre pensa més en com fer arribar la veu que no pas en la mida del cor. Una forma creada pel desig d'arribar una mica més lluny."},"ICON-2420":{"nm":"Estoig del pin posterior de la insígnia","de":"Abans de posar-se al pit i després de treure's-la, el descans de la insígnia comença i acaba aquí. Una petita casa que ajoca amb seguretat el pin punxegut de darrere. Fins i tot un punt lluent necessita un lloc on ajaure's i descansar una estona."},"ICON-2421":{"nm":"Placa numèrica del marcador","de":"Porta impregnada la cura d'una època en què cada gol es canviava a mà. Abans de l'era digital, el resultat es gravava, casella a casella, amb la punta dels dits humans. Una placa on fins i tot un sol número portava l'emoció d'algú."},"ICON-2422":{"nm":"Fitxa magnètica de la pissarra tàctica","de":"Seguint la punta dels dits de l'entrenador, la defensa i l'atac intercanvien llocs. Cada imatge que hi ha al cap abans del partit es dibuixa primer en el moviment d'aquests petits punts. El resultat es juga un cop, per endavant, sobre la pissarra."},"ICON-2423":{"nm":"Visera antireflectant del marcador","de":"Perquè els números enlluernadors no entelin la vista d'un jugador, la visera talla la llum. Fins i tot la claror ha de tapar-se just la mesura adequada per complir la seva funció. En el lloc més lluminós, una ombra que treballa amb més silenci."},"ICON-2424":{"nm":"Anella de gir del marcador de fulles","de":"Cada vegada que un full es gira, el número canvia i el clam puja al darrere. Un vestigi de l'era analògica, quan els resultats es renovaven amb el tacte d'una mà. Una època en què, al so del punt que girava, el cor també girava."},"ICON-2425":{"nm":"Estoig del retolador de línies tàctiques","de":"Tot recorregut dibuixat a la pissarra blanca del vestidor surt d'aquest retolador. Un petit estoig robust que acull l'esbós del partit. En el silenci previ a l'enfrontament, el lloc que guarda més paraules."},"ICON-2426":{"nm":"Comptador de punts de clic","de":"Cada pressió afegeix una casella, el compte puja amb un clic clar. Deixa els números a càrrec dels dits, i el cor podrà girar-se del tot cap al joc. Un petit ritme que alleugereix la càrrega de comptar."},"ICON-2427":{"nm":"Cobertor de cables del marcador","de":"Darrere la llum brillant sempre hi ha cables enredats i desendreçats. La feina de cobrir amb pulcritud aquest desori. Només quan els llocs invisibles es mantenen endreçats, els llocs visibles finalment brillen."},"ICON-2428":{"nm":"Raspall esborrador de la pissarra tàctica","de":"Quan acaba una ronda, buida bé la superfície per a la imatge següent. Una nova estratègia només pot començar sobre un espai buit. El raspall que esborra és, en realitat, el primer traç de la propera jugada."},"ICON-2429":{"nm":"Pinça de la bandera del marcador","de":"Aferra una bandera a punt de volar amb el vent i no la deixa anar. Perquè la tela onejant mantingui el seu lloc. Fins i tot la feina d'anunciar els resultats al món necessita primer una mà que la sostingui ferma."},"ICON-2430":{"nm":"Pinça del cordó del xiulet de l'àrbitre","de":"A un sol xiulet, el partit s'atura i torna a fluir. Un petit nus que lliga aquesta autoritat ferma al coll. Fins que sona el xiulet, mantenir el silenci ben lligat també és feina d'aquesta pinça."},"ICON-2431":{"nm":"Bobina del metre","de":"Recull cap a dins seu la longitud que ha mesurat. Mesurar és, al capdavall, la repetició de desplegar i tornar a enrotllar. Una maneta que ajuda aquest simple anar i tornar sense queixar-se, girant cada cop darrere la precisió."},"ICON-2432":{"nm":"Estoig plegable de la bandera d'arbitratge","de":"La bandera que dividia amb fermesa el dins i el fora, quan acaba el partit, es plega amb pulcritud i descansa. Fins i tot aquest senyal tan clar recupera l'alè un moment per al que vindrà. Fins i tot la fermesa té el seu repòs silenciós."},"ICON-2433":{"nm":"Anella per penjar el cronòmetre","de":"Penja el temps que flueix en un sol lloc, no al canell. Aturat abans de mesurar, i corrent de seguida quan el criden: una estació per al temps. Una petita llar per als segons, amb l'alè contingut, esperant el senyal de sortida."},"ICON-2434":{"nm":"Roda marcadora de línies de camp","de":"Allà on rodola, hi queda un camí blanc ben clar. Els límits de les regles es graven així sobre el terra, volta a volta, amb pulcritud. Abans que comenci el partit, la roda que deixa la primera petjada al terreny de joc."},"ICON-2435":{"nm":"Butxaca de la targeta arbitral","de":"En el moment de la decisió, la targeta que es treu del pit dorm aquí. La sala d'espera d'un veredicte que roman en silenci fins al final, fins que es mostra. Una butxaca sempre a punt i expectant, desitjant no haver de ser mai treta."},"ICON-2436":{"nm":"Suport del pes de la balança","de":"La feina de pesar només és honesta sobre un terra que no trontolla. Un suport que sosté el pes tot oferint el seu propi cos ben pla. El primer pas d'una mesura precisa sempre comença des d'un lloc quiet."},"ICON-2437":{"nm":"Polsador de sortida","de":"A un sol so, tots els peus empenyen el terra alhora. La sortida és brevíssima, però la mà que crea aquesta brevetat és més serena que ningú. Una mà que allibera el tremolor de la línia de sortida amb un sol clic."},"ICON-2438":{"nm":"Base del con de camp","de":"El nom pot ser desconegut, però la seva feina és clara: sosté amb pes el centre d'un camp com si fos un escenari. Al centre on tothom brilla, sempre hi ha una cama invisible que aguanta en silenci."},"ICON-2439":{"nm":"Sivella del cinturó de respiració diafragmàtica","de":"Un bon so no ve de la gola sinó d'una respiració profunda, i la cintura ho sap primer. Una sivella que deixa sentir al palmell com el ventre s'infla i es desinfla. El punt de partida d'una cançó sempre és sota aquest sol alè."},"ICON-2440":{"nm":"Placa de ploma per practicar la respiració","de":"Quan la ploma es balanceja amb l'alè, és un senyal que la respiració és regular. Donant forma suau a un alè invisible, ensenya el fonament del cant. Una pràctica que aprèn, amb els ulls, l'alè d'abans de la primera nota."},"ICON-2441":{"nm":"Rellotge de sorra de la inspiració","de":"Dins el vidre, la sorra flueix com un alè. Inspira, atura't un instant, expira lentament: els grans compten el ritme per tu. Mira una estona la sorra que cau sense soroll, i sense adonar-te'n, la respiració que s'havia desordenat torna a alinear-se."},"ICON-2442":{"nm":"Suport per practicar amb espelma","de":"Encén el ble, i la veu tremola juntament amb la flama que oscil·la. Algú va tallar aquest lloc amb cura, per sostenir una estona aquest petit tremolor. Tan gruixuda com la cera endurida acumulada, aquí hi reposen les nits en què es cantava en solitari."},"ICON-2443":{"nm":"Cinta del coixí de pressió abdominal","de":"En comptes de posar la mà sobre el ventre, una sola cinta en prem aquest punt en silenci. S'estira tensa quan l'alè s'infla i s'afluixa suaument quan es buida del tot. Una petita companya silenciosa al teu costat, que ajuda el cos a memoritzar primer el ritme."},"ICON-2444":{"nm":"Tapa del globus de retenció de l'alè","de":"No bufis el globus tot de cop. Llarg, lent, empeny-lo fins al final. Mentre mossegues la tapa i deixes anar l'aire, aquest arriba fins al punt més profund dels pulmons. Una cançó, al final, vola tan lluny com la durada de l'alè que has aguantat."},"ICON-2445":{"nm":"Nansa per regular la respiració","de":"Com més trontolla el cor, més vol la mà aferrar-se a alguna cosa. Agafa aquesta nansa i les espatlles baixen a poc a poc, la inspiració s'allarga un pam més. Aprendre a aferrar-se és aprendre a compondre's, el palmell ho sap primer."},"ICON-2446":{"nm":"Anella de la banda vibratòria abdominal","de":"Enganxa la banda a l'anella i una suau vibració s'escampa cap al centre del ventre. La força es concentra en silenci just al lloc que tremola quan rius fort. Un centre ferm sempre creix així, lentament, en un lloc que ningú veu."},"ICON-2447":{"nm":"Disc comptador d'inspiracions","de":"U, dos, tres: cada vegada que el disc gira una posició, es grava la profunditat de l'alè inspirat. Suma una posició més i la cançó aguanta una frase més. En aquest petit dial, la capacitat pulmonar que has fet créixer avui hi queda inscrita en silenci."},"ICON-2448":{"nm":"Placa de cullera per a exercicis de llengua","de":"Els punts on la punta de la llengua ha d'arribar hi són marcats amb claredat sobre la placa. Com fer-la rodar, com fer-la petar, com aturar-se un instant. Darrere una pronunciació que flueix amb suavitat s'amaguen incomptables matinades en què la llengua va memoritzar el seu camí."},"ICON-2449":{"nm":"Pinça del mirall per a la forma de la boca","de":"La pinça sosté suaument la forma de la boca reflectida al mirall. L'«a» és rodona, la «i» s'estira ampla cap als costats. Una lliçó silenciosa de tu sol amb el mirall, perfeccionant la forma del so mentre encares directament la teva pròpia cara."},"ICON-2450":{"nm":"Foca de suro per a la dicció","de":"Una petita foca tallada de suro seu a la cantonada de l'escriptori, escoltant la pronunciació. Les nits en què la erra no para de relliscar i l'ànim s'ensorra, els ulls rodons de la foca diuen en silenci: no passa res, provem-ho un cop més."},"ICON-2451":{"nm":"Agulla marcadora de respiració a la lletra","de":"On respirar dins la lletra: aquesta agulla t'ho diu primer. Clava-la al final d'una línia, i aquest punt es converteix en la tendra pausa de la cançó. Per cantar amb llibertat, fins i tot una frase necessita un espai per recuperar l'alè."},"ICON-2452":{"nm":"Reposabarbes per practicar la dicció","de":"Amb només sostenir lleugerament la barbeta, la pronunciació que estava a punt de dispersar-se troba el seu lloc. Una parla clara no és feina només de la boca, sinó que la construeixen junts la barbeta, la gola i l'alè. Aquest petit suport ajuda en silenci aquest equilibri tan delicat."},"ICON-2453":{"nm":"Suport de motlles bucals per a les vocals","de":"A, e, i, o, u: un motlle que fixa, tal com són, els camins que aquestes cinc vocals prenen en sortir de la boca. Posa'l tranquil·lament al costat del mirall i modela cada dia l'esquelet del so. L'estructura de qualsevol cançó comença, al capdavall, en aquestes cinc vocals."},"ICON-2454":{"nm":"Targeta de trencallengües","de":"Una targeta tan embullada que, en llegir-la, la llengua s'entrebanca i finalment esclata el riure. No passa res si t'equivoques, equivocar-se és justament la pràctica. Cada cop que superes aquesta frase entremaliada, un so més es desperta nítid i clar."},"ICON-2455":{"nm":"Tap per relaxar els llavis","de":"Un escalfament que fa vibrar els llavis per despertar una boca rígida. Mossega el tap i deixa anar l'aire llargament, i els llavis adormits s'afluixen tous. El més petit i tendre dels escalfaments per obrir amb suavitat la primera frase."},"ICON-2456":{"nm":"Goma elàstica del fragment de la lletra","de":"Cargola una goma elàstica per marcar el fragment que sempre et fa entrebancar. Cada cop que veus aquest punt al canell, et ve al cap la muntanya d'avui per superar. Com més difícil és el compàs, més sovint el mires i més temps el guardes al cor."},"ICON-2457":{"nm":"Anella de la bufanda escalfacoll","de":"Perquè la gola no es refredi amb l'aire de la matinada del canvi d'estació, la bufanda es penja ferma a l'anella. Només d'una gola ben embolicada i càlida s'allibera finalment un so clar. Protegir la veu sempre comença per tenir cura primer de la gola."},"ICON-2458":{"nm":"Punta de rodet vibratori per a les cordes vocals","de":"Quan la punta del rodet rodola a poc a poc pel costat del coll, les cordes vocals adormides tota la nit desperten suaument. Una lleugera vibració afluixa la tensió rígida, i la primera nota vacil·lant s'estova. Un tacte que escalfa el cos abans de cantar."},"ICON-2459":{"nm":"Sotagot per a l'escalfament tararejant","de":"Amb els llavis junts, taral·lejant fluixet, embolcalla amb les dues mans una tassa calenta que fumeja i la gola també s'escalfa. Un tararareig baix s'escampa en cercles sobre el sotagot. Una cançó comença així, amb un sol glop d'una tebiror suau."},"ICON-2460":{"nm":"Càpsula per guardar caramels per a la gola","de":"Per als dies en què la gola s'ensorra àspera i rasposa, els caramels es guarden en silenci dins la càpsula. Fes-ne rodar un a la boca just abans de pujar a l'escenari, i la menta refrescant desembussa la gola. Un petit consol d'emergència, guardat en un estoig ben propi."},"ICON-2461":{"nm":"Bossa de vapor per a la gola","de":"Embolica al coll aquesta bossa, ben amarada de vapor calent, i els punts que s'havien enrigidit per una llarga pràctica es desfan suaument. Amb la mateixa calidesa d'una tovallola tot just escalfada, ofereix en silenci un compàs de repòs a unes cordes vocals cansades i abatudes."},"ICON-2462":{"nm":"Rellotge de sorra per al repòs de la veu","de":"La promesa silenciosa de no parlar avui és comptada amb calma per grans prims de sorra. Tancar la boca una estona i estalviar la veu. Aquest temps quiet, que també és la millor cura de totes, flueix aquí a poc a poc."},"ICON-2463":{"nm":"Tap per a l'escalfament de vibració labial","de":"Un vibrat de llavis que puja i baixa per les notes mentre els llavis tremolen lleugerament. Mossega el tap suaument i el tremolor descontrolat es fixa en una cosa molt més regular. Una petita eina, de la mida d'un palmell, que cordona amb suavitat el primer botó de la vocalització."},"ICON-2464":{"nm":"Tapa polvoritzadora d'hidratació per a la gola","de":"Perquè la gola no s'assequi en un escenari sec, prem la tapa i polvoritza un fi núvol d'aigua. Fes una inspiració profunda d'aquest aire humidificat, i la veu ressecada recupera de nou la seva lluentor clara."},"ICON-2465":{"nm":"Pilota vibratòria per relaxar la veu","de":"Sostén quieta al palmell la pilota que tremola finament, i aquesta vibració puja suaument pel braç fins a la gola. Una amiga rodona i amable de l'escalfament que sacseja suaument i desperta els òrgans vocals enrigidits per la tensió."},"ICON-2466":{"nm":"Marcador de posició per a la formació","de":"Un petit marcador clavat al terra de l'escenari. Aquí és el teu lloc, allà lluny és el meu. Quan molts es reuneixen per dibuixar una sola imatge, manté a tothom en el seu lloc en silenci: una promesa invisible que ningú es dispersi."},"ICON-2467":{"nm":"Fitxa de punta de fletxa per al recorregut","de":"Una fitxa en forma de punta de fletxa assenyala amb claredat la direcció del proper pas. On girar, on aturar-se: el terra t'ho indica primer perquè no perdis el camí. Un recorregut és un mapa que les puntes dels peus han memoritzat trepitjant-lo incomptables vegades."},"ICON-2468":{"nm":"Agulla del punt central de la formació","de":"L'únic punt que esdevé, en silenci, la referència quan molts es reuneixen. Al voltant d'aquesta agulla es dibuixa un cercle rodó, i la formació s'obre de bat a bat. Fins i tot els moviments dispersos troben el seu ordre amb un sol punt central."},"ICON-2469":{"nm":"Falca del punt de creuament","de":"On dos camins es troben en un sol lloc, s'hi clava una falca amb fermesa. Perquè no xoquin, perquè no s'encreuin i topin. Fins i tot en aquell instant fugaç i sense alè de passar-hi pel costat, que ningú perdi el camí."},"ICON-2470":{"nm":"Bandera de direcció de sortida","de":"Quan s'esvaeix el ressò de l'última nota, un se n'ix en silenci cap on assenyala la bandera. Sortir no pot ser més desordenat que entrar. Fins i tot el final de l'escenari té una direcció promesa per endavant."},"ICON-2471":{"nm":"Pinça del metre per mesurar distàncies","de":"Agafa fort la punta del metre amb la pinça, i un pam, i un altre, surten exactes sense falla. Fins i tot la distància entre una persona i una altra s'ajusta amb pulcritud, com si es mesurés amb un regle. Una escena que fa goig de veure sempre neix d'unes puntes de dits tan curoses."},"ICON-2472":{"nm":"Anella de cordó de referència per a l'alineació","de":"Enganxa el cordó a l'anella i estira'l tibant en una sola línia, i aquesta línia prima esdevé l'estàndard perquè tothom es col·loqui en fila. Una filera es veu tan endreçada gràcies a aquesta única línia recta i invisible."},"ICON-2473":{"nm":"Peça de línia de punts per al recorregut","de":"Peces que dibuixen en silenci un camí de línia de punts al terra. Camina seguint aquestes marques tènues i no et perdràs ni en la foscor. Mentre uneixes punt a punt amb cura, les passes disperses s'enllacen en un únic flux."},"ICON-2474":{"nm":"Xinxeta de posició al terra","de":"Una xinxeta clavada al terra perquè no oblidis el teu lloc. Fins i tot en la foscor més tancada, les puntes dels peus tanteugen aquell petit bony i el troben sense falla. Només quan et pares exactament en aquell punt, la llum finalment cau al damunt del cap."},"ICON-2475":{"nm":"Banda de concentració per aïllar el coll","de":"Si la barbeta es balanceja alhora, la veu també tremola i es desordena. Per dominar com moure només el coll mentre el cap es queda quiet, et cargoles aquesta banda. Darrere un moviment que semblava tan lliure hi ha aquesta pràctica silenciosa d'aïllament."},"ICON-2476":{"nm":"Pinça del coixí per fixar l'espatlla","de":"Perquè les espatlles no s'aixequin pel seu compte, el coixí es manté quiet amb una pinça. Perquè el cos distingeixi amb claredat on ha de balancejar-se i on ha de quedar-se quiet. Una línia contenguda sempre neix d'aquests petits actes de mantenir-se ferm."},"ICON-2477":{"nm":"Sivella del cinturó de percepció costal","de":"El cinturó llegeix en silenci el fi gra de les costelles que s'obren i tornen a ajuntar-se. Corda la sivella, i el moviment de l'alè es transmet amb claredat fins a la punta dels dits. Una vocalització profunda i ferma neix d'aquest moviment invisible dels ossos."},"ICON-2478":{"nm":"Pèndol de balanceig de malucs","de":"El pèndol es balanceja lentament d'un costat a l'altre, indicant en silenci el ritme que dibuixen els malucs. Com el centre del cos desplaça el seu pes, un petit pes de la mida d'un palmell ho ensenya sense paraules. Que fins i tot el balanceig té el seu gra."},"ICON-2479":{"nm":"Anella de rotació del canell","de":"Enganxa l'anella al canell i gira'l a poc a poc cap endins, després cap enfora, i les articulacions enrigidides tota la nit s'afluixen suaument. Perquè un moviment arribi viu fins a la punta dels dits, primer el canell ha de tornar-se flexible. Aquesta petita rotació obre una expressió més gran."},"ICON-2480":{"nm":"Cordó amb anella de resistència per al turmell","de":"Posa l'anella al turmell i estira el cordó, i a cada pas que fas, una suau resistència s'enganxa a la punta del peu. Com més fort trepitges, més força es va sumant en silenci a les cames. Un salt lleuger com una ploma sempre es basa en una pràctica tan feixuga."},"ICON-2481":{"nm":"Sac de sorra de concentració al centre","de":"Només després de posar-te'l al voltant del ventre saps finalment on era realment el centre del teu cos. Mentre el pes estira les espatlles, el centre vacil·lant troba a poc a poc el seu lloc, i on es desfà, hi queda una postura ben dreta."},"ICON-2482":{"nm":"Tapa de la barra d'alineació de la columna","de":"Quan una petita tapa toca una esquena que ha viscut encorbada tot el dia, sembla que algú et redreci les espatlles amb discreció. Es pot viure encorbat, però estar-se dret és una habilitat tendra que cal reaprendre a poc a poc."},"ICON-2483":{"nm":"Bola d'acupressió per relaxar els músculs","de":"Prem fort un punt encarcarat i al principi punxa, però de seguida alleuja. Com la calidesa de la mà de l'àvia fregant l'esquena de petit, afluixar és patir una mica més una estona mentre es queda al teu costat."},"ICON-2484":{"nm":"Cargol regulador de l'angle del mirall","de":"Girant-lo tan sols la mida d'un palmell, el mirall reflecteix una cara ben diferent. Amb una volta de cargol el món s'inclina i es torna a redreçar, així que sembla que fins i tot encarar-se un mateix necessita una punteria tranquil·la."},"ICON-2485":{"nm":"Baieta per netejar el baf del mirall","de":"Davant un mirall entelat pel vapor calent, una persona perd per un instant la seva pròpia cara. Un sol frec i la cara torna. Gràcies a aquest tacte que eixuga la boira, cada matí em torno a trobar amb mi mateix."},"ICON-2486":{"nm":"Goma de peu del trípode de càmera","de":"A la punta del peu del trípode, un petit tros de goma de la mida d'una ungla decideix el destí de la imatge. La seva força de mossegar fort el terra apaivaga el tremolor, així que una imatge estable sempre comença en silenci des d'una fricció invisible."},"ICON-2487":{"nm":"Film de reixeta de referència d'angle","de":"Les línies fines de la reixeta sobre el film són com rodetes d'entrenament per als ulls. Com més s'acostuma la mà a la composició, més s'esvaeixen discretament les línies, i només queda l'instint. Els rastres de l'aprenentatge es tornen invisibles com més madurs es fan."},"ICON-2488":{"nm":"Pedal d'inici de gravació","de":"Per a algú amb les dues mans plenes de coses, l'últim dit sempre era la punta del peu. Prem-lo lleugerament i comença la gravació: darrere l'escenari, la feina de casa es fa amb destresa fins a la punta del peu."},"ICON-2489":{"nm":"Clip de direcció de la il·luminació","de":"On caurà la llum depèn de la punta dels dits d'aquest clip de la mida d'una ungla. La feina de desplaçar una ombra un pam i realçar un contorn: per aquesta petita diferència, algú dubta llargament i pensarós."},"ICON-2490":{"nm":"Pantalla de comparació de gravacions","de":"Posa ahir i avui l'un al costat de l'altre, i només llavors el canvi obre la boca. En el moment en què la pantalla llisca cap avall, la distància del temps travessat entremig es revela honestament sobre la imatge."},"ICON-2491":{"nm":"Corretja de canell del comandament","de":"Cargola un sol cordó al canell i el neguit de deixar-lo caure s'afluixa. Un petit dispositiu de seguretat allibera la mà en comptes de subjectar-la: una tendra paradoxa on estar lligat allibera la ment."},"ICON-2492":{"nm":"Tapa d'objectiu","de":"Mentre la càmera descansa, l'objectiu també tanca els ulls en silenci. En un món on una sola partícula de pols deixa una cicatriu a la imatge, cobrir-lo amb suavitat és el desig de conservar-lo estimat durant molt de temps."},"ICON-2493":{"nm":"Banda per aixecar les comissures dels llavis","de":"Alça una mica les comissures dels llavis i una expressió enrigidida s'afluixa a poc a poc. Un somriure, al capdavall, també és múscul: al principi es demana prestada la força de l'eina, i un matí acabes somrient radiant amb la teva pròpia força."},"ICON-2494":{"nm":"Rodet de massatge per als músculs de la galta","de":"Fes rodar lentament l'interior de la galta i les paraules flueixen molt més suaument. Una preparació silenciosa que desperta amb dolçor la cara abans de cantar. L'expressió, un cop escalfada, també es torna més càlida."},"ICON-2495":{"nm":"Calibre d'angle del somriure","de":"La càmera sap que fins i tot un somriure té el seu angle just. Mesurant amunt i avall amb el calibre, finalment t'adones que el somriure més bonic floreix d'una sinceritat que no es pot mesurar de cap manera."},"ICON-2496":{"nm":"Pinça de moviment de les celles","de":"Si una cella es mou tan sols un mil·límetre, tot el gra del cor canvia sencer. Una pinça que sosté en silenci la peça més petita d'una expressió: actuar és la feina de la punta dels dits que domina aquesta finor."},"ICON-2497":{"nm":"Adhesiu per realçar els pòmuls","de":"Alça una mica els pòmuls i enganxa'l, i apareix a la cara un punt on la llum s'hi queda. La sensació de volum que crea un sol adhesiu de la mida d'una ungla: el maquillatge d'escenari amaga secrets invisibles com aquest."},"ICON-2498":{"nm":"Pedaç d'ull per practicar la picada d'ullet","de":"Tapa un ull i el cor es concentra del tot en el que queda. Practicar l'ullet és, al capdavall, aprendre a amagar amb gràcia la meitat. Sens dubte, hi ha expressions que es tornen més clares per allò que s'ha tapat."},"ICON-2499":{"nm":"Pinça del motlle de forma bucal","de":"Ga, gya, geo... ajusta la forma de la boca al motlle i la pronunciació borrosa es torna nítida. Que cada vocal és una postura de la cara, ho graves a poc a poc al cos davant del mirall."},"ICON-2500":{"nm":"Bossa d'escalfament per a l'expressió","de":"Just abans de pujar a l'escenari, una bossa càlida que escalfa suaument la cara. Igual que unes mans fredes enrigideixen una interpretació, també ho fa l'expressió. Una petita veritat de rere l'escenari: fins i tot un somriure necessita preescalfament."},"ICON-2501":{"nm":"Banda allisa-arrugues del front","de":"Si et poses la banda al front, les arrugues profundes s'allisen a poc a poc. És un objecte que dona un respir a les arrugues gravades per la preocupació. Sota un front allisat, la persona sembla una mica més jove."},"ICON-2502":{"nm":"Didal passa-pàgines de guió","de":"Un petit didal que es posa a la punta del dit per passar les pàgines. El ritme de passar full a full un guió gruixut esdevé, sense adonar-te'n, el compàs de la història. Fins i tot llegir amaga un gest tendre de la mà."},"ICON-2503":{"nm":"Bandera per pintar emocions","de":"L'alegria és groga, la tristesa és blava. Si pintes el cor amb color i alces la bandera, l'emoció invisible pren forma i oneja al vent. Els sentiments també es poden dibuixar així, amb les mans."},"ICON-2504":{"nm":"Pinça per marcar l'èmfasi del diàleg","de":"«Posa el pes en aquesta paraula», diu la pinça en silenci. La mateixa frase canvia tot el seu sentit amb un sol accent, així que és un petit senyal que sosté el centre de gravetat de la parla."},"ICON-2505":{"nm":"Bloc de coma per a la lectura","de":"Un bloc que es col·loca per dir «fes una pausa d'un compàs, aquí». Una coma dins del text no és una aturada, sinó un alè que es pren per a les paraules següents. Qui sap descansar bé, al final, parla bé."},"ICON-2506":{"nm":"Cinta amb pinça per marcar la respiració","de":"La cinta puja i baixa seguint la pinça, dibuixant davant els ulls la durada de l'alè. Observar i seguir el ritme d'inspirar i expirar: el començament d'una cançó sempre s'obre dominant la respiració."},"ICON-2507":{"nm":"Bosseta de daus de les emocions","de":"Un dau surt rodolant de la bosseta i decideix l'emoció d'avui. Si surt alegria, prova de sentir-te alegre; si surt ràbia, prova d'enfadar-te. La pràctica d'actuació esdevé un joc de confiar el cor a l'atzar."},"ICON-2508":{"nm":"Faristol inclinat per al guió","de":"Posa el guió sobre el suport inclinat i no caldrà que ajupis el cap. Aquest petit pendent, que et manté a l'alçada dels ulls, cuida en silenci el clatell adolorit després d'un assaig llarg."},"ICON-2509":{"nm":"Panell per xiuxiuejar","de":"Un senyal que indica: a partir d'aquí, xiuxiueja. Si abaixes la veu darrere el panell, el públic, al contrari, conté l'alè i s'inclina per escoltar. La paradoxa tendra de l'escenari: com més fluix parles, més lluny arriba."},"ICON-2510":{"nm":"Capsa de fitxes per intercanviar papers","de":"Gira lleugerament la fitxa i el paper que fas canvia. Avui protagonista, demà l'amic que acompanya. A l'illa on tots creixen junts, arriba per a tothom el torn de plantar-se al mig de l'escenari."},"ICON-2511":{"nm":"Adhesiu per fixar la mirada","de":"Deixa els ulls quiets sobre un petit punt al costat de la càmera. En l'instant en què la mirada errant s'atura en un sol lloc, la mirada de la pantalla cobra vida amb claredat. Mirar fixament, al final, comença per quedar-se quiet."},"ICON-2512":{"nm":"Escaire per mesurar l'angle","de":"Quan un racó de la pantalla sembla, per alguna raó, inclinat, apropa-hi l'escaire i la resposta apareix. La feina de redreçar allò tort. Abans de confiar en els teus ulls, prova de confiar un instant en el regle."},"ICON-2513":{"nm":"Suport per posar la lent a l'alçada dels ulls","de":"Posa la lent a l'alçada dels ulls d'una persona i la pantalla menteix menys. Ni des de dalt ni des de baix: només quan et mires amb els mateixos ulls es capta una expressió veritable, sense artifici."},"ICON-2514":{"nm":"Plomall fletxa per guiar la mirada","de":"La mirada llisca suaument cap on apunta el plomall. Una petita fletxa que condueix, gairebé sense fer-se notar, els ulls de qui mira. Un bon pla assenyala amablement cap on cal mirar."},"ICON-2515":{"nm":"Xip de terra per marcar el recorregut","de":"Trepitja en silenci un punt del recorregut après de memòria, i el següent lloc apareix a l'instant a l'abast de la mà. Els passos que recorren l'escenari són un camí invisible fet enllaçant petits senyals com aquests, clavats aquí i allà al terra."},"ICON-2516":{"nm":"Cinta mètrica de distància de càmera","de":"Mesura amb la cinta la distància entre el subjecte i la càmera. En un món on un pam separa el lluny del prop, la cinta esdevé una sentinella silenciosa que vigila la frontera entre el difús i el nítid."},"ICON-2517":{"nm":"Guia per inclinar el cap","de":"Quant cal inclinar el cap perquè sembli el més tendre possible? Seguint la guia, ho vas descobrint a poc a poc: l'angle de la inclinació s'assembla molt, al final, al grau en què s'obre el cor."},"ICON-2518":{"nm":"Pinça de mirall de mà per al contacte visual","de":"Posa un mirall de mà al costat de la càmera amb la pinça, i mires els teus propis ulls mentre et trobes amb els teus. Un petit giny que estén, amb suavitat, un pont de mirada entre el jo del mirall i el tu de la pantalla."},"ICON-2519":{"nm":"Llum indicadora de gravació","de":"Quan el llum s'encén, és el senyal que ara mateix s'està gravant. Un sol petit llum reuneix en un punt la tensió eufòrica del plató. Des del moment que la llum s'encén, l'alè de tothom s'ordena en un mateix compàs."},"ICON-2520":{"nm":"Botó de campaneta de reacció","de":"Prem el botó i una campaneta clara ressona nítida i lluminosa. Com els aplaudiments que esclaten després d'una bona escena, unes paraules càlides de «ben fet» queden guardades dins aquesta petita campana."},"ICON-2521":{"nm":"Tub de sorteig d'agilitat","de":"Si l'agites, els bastonets de fusta repiquen i desperten l'ambient abans que res. Qui obre l'escenari es decideix amb un sol gest de canell: qui és triat somriu avergonyit, la resta respira alleujada. Fins i tot repartir la sort té les seves regles amables."},"ICON-2522":{"nm":"Campaneta d'efectes sonors","de":"Amb un lleuger moviment del canell, dring, una interjecció s'hi cola. Aquesta petita campana omple l'escletxa abans que el silenci esdevingui incòmode. Comptar el compàs del riure, aquí sempre es va un pas per davant."},"ICON-2523":{"nm":"Tapa de la capsa sorpresa","de":"Fins que no s'obre, ningú no pot endevinar què hi ha a dins. Aquesta és l'única tasca que té aquesta tapa. Perquè crits i rialles esclatin junts en l'instant que s'obre de sobte, penja tota l'emoció d'una sola frontissa."},"ICON-2524":{"nm":"Ventall plegable de reacció","de":"El clic d'obrir-se esdevé, ell mateix, una resposta. Les varetes del ventall ventegen l'admiració que les paraules no van saber dir. Entre els gestos de plegar i obrir, l'entusiasme va i ve, i un fragment del cor es gronxa amb el vent."},"ICON-2525":{"nm":"Ruleta de penyores","de":"Ningú no sap per endavant en quina casella s'aturarà l'agulla. Com més s'alenteix la roda, més ràpid batega el cor a l'inrevés: clic, i al lloc on s'atura queda escrit el destí ridícul d'avui. Uns segons on fins i tot el tremolor és divertit."},"ICON-2526":{"nm":"Cartell de bafarada d'exclamació","de":"Alça'l ben amunt sobre el cap i un «uau» s'enlaira convertit en lletres. Un sol full de paper es bescanvia amb el cor, cridant allò que la boca no ha pogut seguir. Perquè fins i tot una reacció necessita una mica de posada en escena."},"ICON-2527":{"nm":"Bandera de mà per aturar l'instant","de":"En el moment que la bandera s'alça, tothom queda immòbil, congelat allà mateix. Un senyal que tanca fins i tot el sospir dins d'una imatge fixa. Quan torna a baixar, el riure que estava aturat vessa tot de cop."},"ICON-2528":{"nm":"Pot de pinces per a respostes disbaratades","de":"Com més disbaratada és la resposta, més fermament es penja. Quan les respostes errònies esteses al fil es gronxen al vent, l'escenari esdevé un lloc on el desencert es vol més que l'encert. Un paisatge d'un dia on equivocar-se també va bé."},"ICON-2529":{"nm":"Falca de respatller correctora de postura","de":"En l'instant que hi recolzes l'esquena, la columna encorbada troba a poc a poc, en silenci, el seu propi camí. Una petita falca que sosté sense dir res. Una bona postura, diu suaument des de darrere, només es fa còmoda quan algú et sosté."},"ICON-2530":{"nm":"Bloc de suport per alinear la pelvis","de":"Una petita fermesa que es cala sota els peus quan el centre de gravetat trontolla. L'equilibri del cos puja, al final, lentament des del terra. Un actor secundari sense nom, que sosté la postura des d'un lloc invisible."},"ICON-2531":{"nm":"Pilota d'equilibri per tensar l'abdomen","de":"Cala-te-la al ventre i estreny suaument, i el centre dispers es concentra en un sol punt. Com més profund reguli l'alè, més ferma es torna la pilota, i el cos recupera, alè a alè, el seu propi eix oblidat."},"ICON-2532":{"nm":"Regle per comprovar la corba de la columna","de":"Posa el regle al llarg de l'esquena i la corba invisible apareix sobre l'escala. Estar dret no vol dir esborrar la corba, sinó llegir amb tendresa fins i tot aquell petit revolt."},"ICON-2533":{"nm":"Anella elàstica per obrir les espatlles","de":"Penja'l a les espatlles i estira'l a poc a poc, i el pit encongit s'obre de bat a bat. L'elàstic sempre murmura: torna al teu lloc, i l'esquena, encorbada tot el dia, s'endreça mica en mica amb aquesta trucada gentil."},"ICON-2534":{"nm":"Sac de sorra estimulant del centre","de":"Cenyeix-te'l a la cintura i els grans de sorra feixucs desperten el centre adormit. Fins i tot un moviment lleuger es torna sincer a l'instant davant d'aquest pes. Que et fas més fort com més resisteixes, cada gra ho diu en silenci."},"ICON-2535":{"nm":"Etiqueta del coixí de suport del còccix","de":"Un coixí que sosté amb suavitat sota el còccix, amb una petita etiqueta penjada de la vora. Un giny com una nota tendra, escrita i enganxada per a un dia esgotat de seure tanta estona: «Aquí et pots recolzar una estona»."},"ICON-2536":{"nm":"Trípode d'angle de suport lumbar","de":"Plantat sobre tres potes, sosté en silenci l'angle en què l'esquena es pot recolzar. Un suport que s'esmuny dins d'una postura a punt de desfer-se. Per aguantar allò que trontolla, tres punts, sorprenentment, ja en tenen prou."},"ICON-2537":{"nm":"Pinça de postura per replegar la barbeta","de":"Replega la barbeta i sosté-la una mica, i la línia del coll, desfeta, retroba el seu lloc. El renyar d'una pinça de la mida d'un dit resulta ser, d'alguna manera, tendre. Com mantenir el cap ben dret, aquesta eina petita ho ensenya."},"ICON-2538":{"nm":"Cinta escala per als passos","de":"La cinta estesa a terra dibuixa, un rere l'altre, els quadres on han de trepitjar els peus. Trepitja'ls honestament, quadre a quadre, i sense adonar-te'n, els passos queden gravats al cos. Un camí, com més es trepitja, més clar es torna."},"ICON-2539":{"nm":"Con de canvi de direcció","de":"Dret, és un petit senyal que et diu «gira aquí». Regala un racó als peus que sempre havien corregut en línia recta. Fins i tot el camí de girar té amagat el seu propi ritme."},"ICON-2540":{"nm":"Plataforma oscil·lant per aguantar-se sobre un peu","de":"En l'instant que et poses de peu sobre una sola cama, la plataforma s'inclina suaument. Aquells pocs segons en què t'esforces al màxim per vèncer el balanceig són la lliçó més sincera de l'equilibri. Les puntes dels peus que lluiten per no caure ho diuen tot."},"ICON-2541":{"nm":"Llum intermitent de velocitat de reacció","de":"En l'instant que el senyal s'encén, la mà i l'ull competeixen per arribar primer. La llum intermitent no dona marge per dubtar. Una mà ràpida sempre es mou mig compàs abans que el pensament."},"ICON-2542":{"nm":"Marcador de passos en zig-zag","de":"Petits punts enganxats obliquament al terra que fan ballar els peus en zig-zag. Més difícil que una línia recta és, sempre, l'entrecreuament. Segueix els punts errant una mica, i el joc de cames ràpid madura amb destresa."},"ICON-2543":{"nm":"Barra plana d'equilibri de funàmbul","de":"Posa els peus sobre la barra prima i el món s'estreny com una corda tibant. Com un funàmbul caminant per l'aire, hi carregues tota la concentració del cos en un pam d'ample. L'equilibri, com més s'estreny, més clar es torna."},"ICON-2544":{"nm":"Braçalet de pilota rebot per a l'agilitat","de":"Posa-te'l al canell i una pilota petita rebota amb un toc. En l'instant de llançar i agafar, la velocitat de reacció queda gravada a les puntes dels dits. La rapidesa és, al final, no deixar escapar allò que torna."},"ICON-2545":{"nm":"Aro de hula per a peus àgils","de":"Penja-te'l al peu i fes-lo voltar, i l'aro no para d'incitar la cama. En l'instant que s'atura, cau, així que el peu no deixa de bellugar-se. Mentre et mous com si juguessis, el joc de cames madura àgil i ràpid."},"ICON-2546":{"nm":"Baldufa de fusta de l'equilibri de la puntera","de":"Una baldufa que gira sobre la palma s'atura en sec en l'instant que perd el centre. Com aquells dies d'infància fuetejant una baldufa al pati, l'equilibri és una cosa que només es pot mantenir dreta si gira sense parar."},"ICON-2547":{"nm":"Cordó protector del turmell","de":"Embolica i cenyeix el turmell, i la trepitjada insegura es torna molt més ferma. Com més propens és un lloc a fer-se mal, més tendrament cal subjectar-lo. Un sol cordó esdevé la tranquil·litat d'un pas."},"ICON-2548":{"nm":"Cinta enrotllable escalfa-genolls","de":"Enrotlla-la al voltant d'un genoll fred i l'escalfor s'escola entre les articulacions. Una articulació rígida només s'estova quan s'escalfa. Abans de moure't, la salutació més càlida que li pots oferir al teu propi cos aquest matí."},"ICON-2549":{"nm":"Bola d'acupressió per relaxar músculs","de":"Prem amb fermesa un punt entortolligat i els granets acaronen suaument el nus. El consol estrany que et deslliures tant com et fa mal. Fins i tot les tensions que la mà no arribava a tocar, aquesta petita bola les calma en el seu lloc."},"ICON-2550":{"nm":"Roda de l'ordre d'escalfament","de":"Desperta el cos des de la casella on s'atura la roda. Coll, espatlles, turmells: deixa l'ordre a l'atzar i mantén el cor lleuger. Quan el joc s'esmuny dins l'escalfament, el cos rígid somriu suaument primer."},"ICON-2551":{"nm":"Bossa d'escalfor per a les articulacions","de":"Posa una bossa d'escalfor fumejant sobre les articulacions i s'escampa un alleujament com el d'un terra càlid d'hivern. És el moment en què les articulacions rígides es deixen anar amb una calma somnolenta. Només un cop escalfat, el cos es prepara, a poc a poc, per moure's."},"ICON-2552":{"nm":"Anella d'agafador per estirar-se","de":"Agafa l'anella i estira, i els músculs rígids s'allarguen. Una conversa tibant passa entre la mà que aguanta i el cos que es desplega. Com més s'estira, més lleugers seran els moviments de demà."},"ICON-2553":{"nm":"Tauler de picons per estimular la planta del peu","de":"Posa't dret descalç sobre els picons i les plantes adormides es desperten de sobte. Com la punxada intensa de caminar descalç per un camí de còdols, la sensació del terra puja des de la punta dels dits del peu."},"ICON-2554":{"nm":"Xinxeta magnètica per a notes de lesió","de":"Escriu «no forcis» i enganxa-ho a la planxa de metall. Els records dolorosos s'obliden fàcilment, així que els pengem davant els ulls amb un imant. Cuidar el propi cos també comença, al final, amb una sola línia escrita."},"ICON-2555":{"nm":"Massejador nodós per alliberar la fàscia","de":"Fes rodar lentament la barra nodosa i la fàscia enganxada s'allibera secció a secció. Un tacte que empeny suaument els nusos. Un dia entortolligat, allisat així nus a nus, també es fa molt més lleuger."},"ICON-2556":{"nm":"Cinta de terra per marcar la línia de caminada","de":"Estesa recta a terra, dona als peus una sola línia a seguir. Fins i tot un pas desendreçat, un cop posat sobre aquesta línia, s'endreça de seguida. Dibuixa el camí, i els peus ja no s'esgarrien."},"ICON-2557":{"nm":"Barra horitzontal d'espatlles","de":"Posada travessera sobre les espatlles, revela en silenci un equilibri inclinat cap a un costat. Anar anivellat sempre vol dir abaixar un costat i alçar l'altre. Una sola barra assenyala amb suavitat un hàbit tort."},"ICON-2558":{"nm":"Pes d'equilibri per al cap","de":"Perquè el pes posat al cap no caigui, tot el cos ha d'estar recte com una sola línia. Com aquella vella imatge de caminar amb una gerra d'aigua al cap, el centre es fixa des del punt més alt i baixa cap avall."},"ICON-2559":{"nm":"Suport per a l'angle de la barbeta","de":"Recolza suaument la barbeta i el cap que no para de caure recupera el seu angle just. Un breu descans recolzat en un sol suport. Una línia recta només es completa quan algú la sosté des de baix."},"ICON-2560":{"nm":"Estaca per mesurar la gambada","de":"L'estaca clavada al terra mesura per endavant on han de caure els peus. Una gambada ni massa ampla ni massa estreta, aquella distància honesta. L'equilibri del pas comença en silenci en aquest petit senyal."},"ICON-2561":{"nm":"Falca de direcció per a la puntera","de":"El primer pas dubtós: la puntera del peu és la primera a vacil·lar sobre cap a on anar. Quan aquesta petita falca marca la direcció, el cor també s'inclina suaument cap allà. Triar el camí no és una gran resolució, sinó el pam que assenyala la punta del peu."},"ICON-2562":{"nm":"Cinturó per redreçar l'esquena","de":"Aquella veu que sempre deia «redreça't, redreça't» sembla que encara viu dins d'aquest cinturó. Redreça amb suavitat un dia encorbat, i el pes que pesava sobre les espatlles es torna, curiosament, una mica més lleuger. Una sola postura alça fins i tot el cor."},"ICON-2563":{"nm":"Plataforma per repartir el pes","de":"Set al peu esquerre, tres al dret. Segons on carreguis el pes, es decideix l'equilibri. La plataforma pregunta en silenci: cap a quin costat estàs inclinat, ara mateix? Fins i tot estar dret és, en realitat, un ajust constant."},"ICON-2564":{"nm":"Barra objectiu per a l'alçada de la mirada","de":"Els ulls no paren de caure cap a la punta dels peus. En aquells moments, una sola barra plantada lluny alça a poc a poc la mirada. Practicar mirar lluny és practicar anar lluny, així que en l'instant que alces el cap, fins i tot un lloc que semblava inabastable s'apropa."},"ICON-2565":{"nm":"Pinça de targeta amb l'angle de reverència","de":"Quinze graus, trenta graus, quaranta-cinc graus. El cor s'inclina tan profundament com es plega la cintura. L'angle escrit a la targeta no és només un número, sinó una petita escala que mesura la sinceritat oferta a l'altra persona."},"ICON-2566":{"nm":"Anella de bones maneres per juntar les mans","de":"Junta les dues mans amb cura i fins i tot un cor esverat s'assossega en un sol lloc. Aquesta petita anella captura amb tendresa els dits desendreçats i insegurs, i fixa en silenci la primera postura d'una salutació."},"ICON-2567":{"nm":"Imant de fletxa de recorregut","de":"El que un peu perdut busca primer, mirant al voltant, és una fletxa. Una sola direcció enganxada amb un imant talla la vacil·lació i estira suaument els passos cap a on cal anar. Fins i tot un cor errant troba, al final, una sola direcció."},"ICON-2568":{"nm":"Xinxeta marcadora de la direcció de sortida","de":"El camí de sortida sempre és més difícil que el d'entrada. Fins i tot en la foscor amb els llums apagats, aquesta xinxeta que brilla clarament assenyala en silenci l'últim recorregut. Que marxar bé també forma part de l'escenari, només s'aprèn al final."},"ICON-2569":{"nm":"Cinta amb l'ordre de la reverència formal","de":"Hi va haver una època en què l'ordre de qui saludava primer i qui saludava després era ben clar. Abaixa't seguint l'ordre escrit a la cinta, i fins i tot la cortesia guanya un gra, i les bones maneres guanyen un flux. És mantenir l'ordre del cor."},"ICON-2570":{"nm":"Xip magnètic per alinear els passos","de":"Si una sola persona es desajusta, tota la filera trontolla. Com un xip que encaixa amb un clic quan les puntes dels peus s'alineen, estar junts vol dir cedir amb suavitat la teva gambada a qui tens al costat. Els passos que cauen en el mateix compàs són els més reconfortants."},"ICON-2571":{"nm":"Ferradura de posició per a la reverència d'escenari","de":"Fins i tot una sola reverència d'escenari té el seu lloc on parar-se. Posa els peus sobre les marques esteses en cercle com una ferradura, i una primera salutació que sempre sortia malament pels nervis troba per fi la seva forma. Saber el teu lloc també calma una mica el tremolor."},"ICON-2572":{"nm":"Targeta de gestos d'agraïment","de":"L'agraïment que les paraules no van poder contenir del tot flueix per les puntes dels dits. Dibuixar un cor, posar-se la mà al pit: cada gest escrit a la targeta esdevé una traducció del cor posada en moviment. La sinceritat que vol arribar sempre té una forma."},"ICON-2573":{"nm":"Estaca de targeta per a l'espai de la cua","de":"Fins i tot fer cua té una cortesia amable. Com una estaca que manté exactament un pam de distància amb la persona del davant, l'espera comença amb la petita consideració de no empènyer-se mútuament. Estar-se una mica apartat també és una manera de tenir cura."},"ICON-2574":{"nm":"Anella de targetes de senyal per canviar de frase","de":"Quan la propera frase no para de rondar als llavis, un dit gira suaument una pàgina. Els petits papers enfilats a l'anella premen amb suavitat el cor que batega, i obren amb calma la casella del que cal dir a continuació. Per molt que tremolis, el fil no es trenca."},"ICON-2575":{"nm":"Rellotge de sorra de l'ordre del programa","de":"Mira en silenci els granets de sorra que llisquen, i el proper pas s'ordena amb calma dins del cap. Fins que no cau l'últim gra, aquest petit rellotge ensenya a llegir el temps amb els ulls, sense pressa."},"ICON-2576":{"nm":"Barra de pràctica per agafar el micròfon","de":"Abans que es faci natural, una barra buida pesa com mil quilos. L'angle amb què s'agafa, la distància fins a la boca, la força que es dona al canell: la pràctica, agafant i deixant anar innombrables vegades, floreix un dia, de sobte, en un sol gest natural."},"ICON-2577":{"nm":"Bastonet de dicció per parlar clar","de":"Ga, na, da, ra. Mossega el bastonet i fes rodar la pronunciació fins que la punta de la llengua es torni clara. Una paraula que arriba nítida i clara és com una flor que floreix en silenci sobre centenars d'hores balbucejades i confuses."},"ICON-2578":{"nm":"Bandera de mà de senyal d'entrada","de":"Comença, atura't, descansa un compàs. Una sola bandera sense cap paraula dirigeix l'alè de l'escenari. Des d'un lloc invisible per al públic, una mà que oneja en silenci sosté cada compàs sense cap escletxa."},"ICON-2579":{"nm":"Campaneta de canvi de secció","de":"Dring, un so clar, i l'escena canvia. Com el so de les campanetes que s'escampava pel mercat al capvespre, aquest petit tint porta amb lleugeresa un cor vacil·lant cap a la propera secció. Una transició sempre comença amb un so."},"ICON-2580":{"nm":"Pèndol de compàs per a la respiració del parlar","de":"Inspira: un, dos; expira a poc a poc. Regula l'alè seguint el pèndol que es balanceja a dreta i esquerra, i les paraules que sortien massa de pressa retroben aviat el seu compàs. La velocitat de parlar era, al final, la velocitat de l'alè."},"ICON-2581":{"nm":"Tauler plegable del guió de conducció","de":"En un sol gest de plegar i obrir, hi queda tot l'ordre del dia. En l'instant que despleguis el tauler ben gastat, la ment desconcertada sobre què treure primer s'alinea amb calma. Amb un sol desplegament, el dia s'ordena."},"ICON-2582":{"nm":"Rellotge de sorra del ritme respiratori","de":"Inspira tres, aguanta quatre, expira sis. Mentre la sorra flueix, el teu alè flueix en silenci amb ella. Comptar cada alè un a un és la manera més antiga i tendra de tenir cura, a poc a poc, d'un tu enfeinat."},"ICON-2583":{"nm":"Borla de coixí de meditació","de":"La borla penjada de la vora del coixí es gronxa en silenci, sense ni un bri de vent. Asseu-te en posició de lotus, i la quietud d'un ancià apaivagant el cor assegut a la galeria de fusta ve amb suavitat al teu costat, s'hi queda un moment, i marxa."},"ICON-2584":{"nm":"Campaneta de vent de mà per regular l'alè","de":"Quan passa un sol buf de vent, un so clar canta en silenci. Penjada com una campaneta de vent al ràfec, deixa caure una gota fresca i clara sobre un cor bullent de confusió. Fins i tot el so té el poder de refredar."},"ICON-2585":{"nm":"Plat per recollir el fum de l'encens","de":"El fum que queda després de cremar l'encens es posa lentament sobre el plat. Com aquell aroma que s'enlairava davant la taula un matí de festa, un sol filet de fum calma en silenci l'aire agitat i omple l'estança de quietud."},"ICON-2586":{"nm":"Pes oscil·lant d'inspiració i expiració","de":"El meu alè cavalca sobre un sol pes que puja a poc a poc i torna a baixar. Surant quan inspiro, enfonsant-se quan expiro: en un dia que el cos oblida com respirar, aquest petit rellotge ho torna a ensenyar tot des del principi."},"ICON-2587":{"nm":"Batall de campana de meditació","de":"Toca la campana un cop, amb suavitat, i el ressò s'escampa llargament. Com el so d'una campaneta de vent que ressona en un temple de muntanya, el simple fet d'escoltar en quietud fins que aquell so desapareix del tot en l'aire renta net un racó del cor."},"ICON-2588":{"nm":"Ploma guia del camí de la respiració","de":"Deixa la ploma quieta davant el nas i el camí de l'alè que no es veia es fa per fi visible. Un lleuger tremolor vol dir que respires bé; la quietud vol dir que l'has aguantat massa. La cosa més lleugera és, de vegades, la guia més honesta."},"ICON-2589":{"nm":"Còdol per assossegar la ment","de":"El còdol que tens a la palma és fred i llis. Com una pedra que ha rodat molt de temps per la vora d'un riu fins a cedir totes les seves arestes, no paris de tocar-la amb els dits i les parts esmolades d'un cor bullent es van desgastant, a poc a poc, fins a arrodonir-se."},"ICON-2590":{"nm":"Pinça de temperatura per a la respiració nasal","de":"La temperatura a la punta del nas revela en silenci la profunditat de l'alè. La pinça llegeix en silenci l'aire que entra fred i surt càlid, i mostra amb claredat davant els ulls una respiració que normalment ni tan sols se sent. Fins i tot l'alè té una expressió."},"ICON-2591":{"nm":"Tauler d'adhesius del temps de l'ànim","de":"Avui el meu cor és clar, o núvol? En l'instant que tries un petit adhesiu i l'enganxes al tauler, un estat d'ànim difícil de posar en paraules es converteix en una mena de temps meteorològic i pren una forma clara. El cor també necessita una previsió."},"ICON-2592":{"nm":"Segell de mà de colors de les emocions","de":"L'alegria és groga, la tristesa és blava. Tria un color i prem-lo fermament sobre el paper, i el color del cor hi queda com una marca. Fins i tot un sentiment que semblava impossible d'anomenar, el color s'hi acosta primer i el reconeix en silenci."},"ICON-2593":{"nm":"Xip de pètal del cor d'avui","de":"Posa suaument el cor de tot el dia sobre un sol pètal. Com les flors d'azalea que voleien en un dia de primavera, un xip lleuger i tendre pregunta en veu baixa, al final d'un dia que s'apaga, com t'ha anat."},"ICON-2594":{"nm":"Imant de bafarada d'ànims","de":"Les paraules que vols dir no paren de rondar als llavis. En l'instant que enganxes l'imant de bafarada, una paraula d'ànim que no vas gosar dir en veu alta arriba en silenci al dia esgotador d'algú. Així és com es transmet el cor."},"ICON-2595":{"nm":"Segell de sobre del cor íntim","de":"Les paraules que no vas arribar a dir es guarden amb cura dins un sobre i es segellen. Com un ancià que, amb la punta dels dits, tancava una carta amb engrut, un sol segell manté el cor íntim a resguard. Esperant en silenci el dia que el treguis i el desplegui."},"ICON-2596":{"nm":"Poncella de temperatura de l'emoció","de":"Una poncella tancada, en tocar l'escalfor, s'obre amb cura una capa rere l'altra. Florint a mesura que puja la temperatura del cor: com de calent m'he tornat avui, aquesta flor ho sap abans que les paraules. La primavera també arriba al cor."},"ICON-2597":{"nm":"Corretja de mirall de mà per elogiar-se un mateix","de":"Alça el mirall i troba't en silenci amb els teus propis ulls reflectits. El que mostra la petita cara penjada de la corretja no és la teva cara, sinó el tu d'ahir, que es mereix unes paraules per haver resistit tan bé. El consol mai no havia estat lluny."},"ICON-2598":{"nm":"Joc de segells de cares d'estat d'ànim","de":"Un somriure radiant, llàgrimes a punt de vessar, uns llavis enfurrunyats. Prem amb força els segells d'expressions i escriu el diari del cor. Un dia massa aclaparador per posar-lo en paraules, una petita cara diu en silenci, en el meu lloc, l'estat d'ànim d'aquell dia."},"ICON-2599":{"nm":"Anella per desfer el cabdell de les emocions","de":"Per molt embolicat que estigui el cabdell, si es desfà fil a fil amb calma, torna a ser un sol fil al final. Penja un a un a l'anella els sentiments barrejats i asfixiants, i fins i tot un cor que no acabaves d'entendre troba un fil prim per seguir."},"ICON-2600":{"nm":"Cordó de la bosseta perfumada per dormir","de":"De la bosseta perfumada penjada al capçal, s'escampa en silenci una lleu fragància d'herbes. Com aquella olor de l'àvia que guardava perfum ben endins de l'armari, mentre acarones el cordó amb els dits, la tensió que ha estat tibant tot el dia s'adorm a poc a poc."},"ICON-2601":{"nm":"Tauleta giradora de postures del son","de":"Una nit en què vas donar voltes i voltes i no vas aconseguir adormir-te fins a trenc d'alba. Gira suaument la postura de jeure, i el neguit d'ahir es transforma silenciosament en la frescor d'aquest matí. Descansar també és una pràctica, diu aquesta petita tauleta sense dir ni un mot."},"ICON-2602":{"nm":"Penjador de llum de lluna per al capçal","de":"Penja un bri de llum que ha entrat per l'escletxa de la cortina, just al capçal del llit. Un riu tènue flueix sobre el rostre adormit, i fins i tot les nits d'una aprenent a qui la foscor espantava es van suavitzar per fi. Va ser el primer petit consol que va conèixer."},"ICON-2603":{"nm":"Xip de capoll floral de l'estat físic","de":"L'estat d'avui està tancat com un capoll de flor. Prem lleugerament el xip i s'obre a poc a poc: si has dormit bé o no, el cos ho sap primer. Fins i tot aquesta vacil·lació abans de florir del tot resulta tranquil·lament adorable."},"ICON-2604":{"nm":"Capsa apagallums per al ble del llum de nit","de":"\"No apaguis el llum.\" Per a la més petita, que tenia por de la foscor, algú va posar suaument una capsa sobre el ble. Ni massa clar ni massa fosc, és una promesa petita i tendra que vetlla al seu costat només fins que arriba el son."},"ICON-2605":{"nm":"Agulla de gira-sol per despertar-se al matí","de":"Clava-la a la capçalera i girarà suaument el cap, com un gira-sol, cap al primer raig de sol. Fins i tot els dies que no vols llevar-te, hi ha una raó per la qual la llum et crida, i s'endú el matí en una sola direcció."},"ICON-2606":{"nm":"Raspall d'herbes per al coixí del son","de":"Impregna la punta del raspall amb lavanda i camamilla i passa'l una vegada pel coixí. Mentre l'aroma s'infiltra a la funda, la tensió acumulada durant el dia es va deslligant lentament de les espatlles. Un bon son comença amb aquesta petita fragància."},"ICON-2607":{"nm":"Pinça per a la cantonada del llit","de":"A trenc d'alba, els dits dels peus no paren d'escapar-se de sota el llençol. Subjecta bé la cantonada amb la pinça i la calidesa no podrà fugir en tota la nit. És un petit tancament que es col·loca en lloc d'un \"que dormis bé\"."},"ICON-2608":{"nm":"Cistella de còdols de bon dia","de":"Una cosa bona cada dia, un còdol de la mida de la palma. Com més es carreguen les pedres a la cistella, més tranquil se sent el cor, discretament. Recollir moments senzills a la mà: així s'ha comptat sempre la felicitat."},"ICON-2609":{"nm":"Gerra per recollir estrelles de propòsits","de":"Cada nit, dona forma d'estrella al propòsit del dia i deixa'l caure suaument dins la gerra. Quan es vessa de plena, la gerra es converteix en un petit cel nocturn. La boca, abans buida, ho sap: les promeses només brillen quan es guarden juntes."},"ICON-2610":{"nm":"Penjador de caramels de petita recompensa","de":"Un caramel que et regales a tu mateixa al final d'un dia esgotador. En el moment de treure'n un del penjador i posar-te'l a la boca, tot està bé encara que ningú no ho noti. Perquè una petita recompensa és l'ànim més honest."},"ICON-2611":{"nm":"Segell de \"avui ho he aconseguit\"","de":"Sucar-lo en tinta i prémer fort sobre el quadern. \"Avui ho he fet.\" Un dia ben fet i un dia simplement suportat omplen igual una casella. No cal que cada dia sigui perfecte; només cal no deixar mai de prémer el segell."},"ICON-2612":{"nm":"Base per plantar la bandera d'ànim","de":"Planta-la ben ferma a terra, i com més fort bufa el vent, més amb força oneja la bandera. Fins allò que trontolla necessita una mà que el sostingui. El cor que anima algú aguanta així, des de baix."},"ICON-2613":{"nm":"Test per plantar la llavor de l'objectiu","de":"Un objectiu no s'aprèn de memòria, s'enterra a la terra. Mentre plantes una llavor, la regues i esperes, la impaciència es va transformant lentament en arrels. Dins del test no creix només un brot."},"ICON-2614":{"nm":"Tauler d'enganxines d'elogi","de":"Un adhesiu per cada cosa ben feta. Com més s'omple de colors el tauler, més tornen a la vida, plens de color, els dies que havien passat desapercebuts. De petits ja ho sabíem: l'elogi es fa més vívid com més se n'enganxa."},"ICON-2615":{"nm":"Anella per lligar el llaç del propòsit","de":"Una mà que passa el llaç per l'anella i en fa un nus. Ferm perquè no es desfaci, però no massa fort. Un propòsit és exactament com aquest nus: si l'estrenys massa, es trenca; si el deixes fluix, s'escola en silenci."},"ICON-2616":{"nm":"Xip de petxina de petit assoliment","de":"Escriu un petit assoliment en una petxina recollida a la platja. Com un fragment que ha arribat fins aquí polit i suavitzat per les onades, també el teu dia ha rodolat molt de temps i ara lluu bruny. Tot allò que resisteix el temps acaba brillant."},"ICON-2617":{"nm":"Ganxo per penjar la medalla de recompensa","de":"Una medalla guanyada amb esforç no es guarda en un calaix, sinó que es penja a l'alçada dels ulls. El pes que penja del ganxo redreça les espatlles cada matí. Una recompensa no és per amagar-la, sinó per penjar-la allà i mirar-la."},"ICON-2618":{"nm":"Got recollidor per al paraigua de pluges","de":"La pluja del monsó regalima gota a gota per la punta del paraigua. Posa-hi un got a sota i l'entrada es manté eixuta. No pots aturar el que cau, però pots decidir on va a parar."},"ICON-2619":{"nm":"Bossa freda per refrescar la calor","de":"Rere l'escenari, en ple estiu, una bossa freda es posa lleugerament al clatell. La calor encesa que pujava s'assossega un instant. \"Fes una pausa.\" És reconfortant tenir una mà que et cuida abans que la calor mateixa."},"ICON-2620":{"nm":"Clip fixador de les pales del ventilador","de":"Fins i tot les pales que giraven amb força s'aturen en silenci amb un sol clip. Com més fort el vent, més cal quelcom que el subjecti ferm. Les coses que giren de pressa acaben sent segures gràcies a qui les reté."},"ICON-2621":{"nm":"Barra assecadora per a sabates mullades","de":"Les sabates xopes de pluja deixen humit fins i tot el cor durant la nit. Posa-hi la barra a dins i al matí ja estaran prou seques per tornar a calçar-les. Allò que és mullat no es llença, es asseca amb cura."},"ICON-2622":{"nm":"Estora rascadora de fang per a botes","de":"Botes cobertes del fang de l'arrossar. Només després de fregar-les bé sobre l'estora es puja al terra. Deixar el fangar de fora a la porta abans d'entrar és una antiga cortesia que manté endreçada la llar."},"ICON-2623":{"nm":"Rajola freda per trepitjar a l'estiu","de":"Els peus descalços ho saben primer. Posa la planta del peu sobre la rajola posada al terra a l'estiu i la calor del migdia s'esvaeix suaument en un grapat de frescor. Amb un sol petit fred, una llarga estació es fa suportable."},"ICON-2624":{"nm":"Cinta tallabarreres per al llindar","de":"Amb només una cinta posada al llindar, l'aigua de pluja ja no pot passar cap a dins. Una línia prima que separa dins i fora. Un lloc que val la pena protegir queda millor amb una frontera senzilla i ben ajustada que amb un mur imponent."},"ICON-2625":{"nm":"Plat suport per a l'espiral antimosquits","de":"En una nit d'estiu, posa l'espiral antimosquits sobre el seu plat i s'alça un fum picant però familiar. Igual que l'espiral que es consumeix fent-se cada cop més petita, la nit també s'aprofundeix a poc a poc. És l'olor d'aquells dies estirats al banc de fusta comptant estrelles."},"ICON-2626":{"nm":"Anella per a la maniga refrescant","de":"Cobreix els avantbraços cremats pel sol amb una maniga. Corda-la ben ajustada al puny amb l'anella i fins i tot la feina del migdia es fa suportable. La frescor és la petita amabilitat de fer ombra en un pam de pell just on toca."},"ICON-2627":{"nm":"Escombra de mà per a fulles caigudes","de":"Aplega amb l'escombra de mà les fulles caigudes que omplen el pati. Tota una estació cruix sota els peus. Endreçar alguna cosa és també acomiadar amb cura el que s'ha de deixar marxar."},"ICON-2628":{"nm":"Barra de suport per airejar la finestra","de":"Encaixa una barra a la finestra d'una habitació carregada i deixa-la entreoberta. La brisa de tardor s'esmuny a dins i s'endú l'aire ranci. Airejar és aquell petit respirador que intercanvia amb calma allò que s'ha estancat a dins amb el de fora."},"ICON-2629":{"nm":"Tap per a la bossa de glans","de":"Com un esquirol, omple la bossa de glans i tanca'n la boca amb el tap. Ben fort, perquè no en rodoli cap. La voluntat de protegir el que s'ha aplegat és el vell instint de les coses petites que passen l'hivern."},"ICON-2630":{"nm":"Espolsador per als edredons de tardor","de":"Estén al pati l'edredó usat tot l'estiu i espolsa'l bé amb l'espolsador. L'olor del sol s'escampa entre la pols. El canell recorda primer que cal espolsar l'estació vella per poder-se cobrir amb la nova."},"ICON-2631":{"nm":"Cordó tallavents per a l'escletxa de la finestra","de":"Tanca ben ajustat, amb un sol cordó, el vent fred que s'esmuny per l'escletxa de la finestra. Una línia prima guarda fins al final la calidesa de l'habitació. Un fred gran sempre comença per una escletxa petita: els preparatius d'hivern ho saben."},"ICON-2632":{"nm":"Coberta filtradora per a fulles caigudes","de":"Un filtre col·locat sobre el desguàs de la canaleta. Retén nítidament les fulles i deixa passar només l'aigua. Per fluir sense obstacles, cal decidir què deixar passar i què retenir, diuen els ràfecs de tardor."},"ICON-2633":{"nm":"Pinça per a feixos d'herba seca","de":"Cenyeix ben fort amb la pinça un feix d'herba ben seca. Una mà que lliga en un sol feix allò que amenaça d'escampar-se. Fins i tot on el verd de l'estiu s'ha esgotat del tot, si s'aplega, la utilitat hi roman intacta."},"ICON-2634":{"nm":"Balanceig de tardor per mesurar la temperatura","de":"Quan bufa el vent, el balancí es gronxa. Per l'amplitud d'aquest moviment es calcula com de profunda s'ha fet la tardor avui. La temperatura no és un número; arriba primer a la mà com alguna cosa que es gronxa suaument."},"ICON-2635":{"nm":"Estoig d'escalfamans per a la butxaca de l'abric","de":"\"Que fred que tens les mans.\" L'estoig d'escalfamans guardat a la butxaca de l'abric escalfa suaument els dits gelats. El cor que pensa primer en el fred d'algú altre sempre és allà, quiet, dins la butxaca."},"ICON-2636":{"nm":"Rebaix recollidor de la condensació de la finestra","de":"El rebaix recull en silenci les llàgrimes que la finestra d'hivern ha vessat tota la nit. Un petit rierol format per la diferència de temperatura entre dins i fora. Com més gran és la diferència, més flueix: la finestra de l'alba ho mostra cada dia."},"ICON-2637":{"nm":"Reixa protectora per a l'estufa","de":"Col·loca una reixa protectora davant l'estufa encesa. La calidesa a prop, el perill just a un pam. Mantenir el foc a la vora sense fer-se mal és la distància més bàsica de tenir cura d'algú."},"ICON-2638":{"nm":"Pinça subjectadora per a l'edredó d'hivern","de":"Quan l'edredó gruixut d'hivern no para de lliscar, la pinça el prem i el manté al seu lloc, en silenci. Una calidesa pesant s'ha de subjectar ben fort perquè valgui la pena. Així es guarda, amb cura, la placidesa d'una nit d'hivern."},"ICON-2639":{"nm":"Espàtula rascadora de gebre","de":"Rasca amb l'espàtula el gebre que floreix blanc al parabrisa a trenc d'alba. La visió tèrbola s'aclareix línia a línia. Fins i tot allò que està gelat es pot rascar al final, diuen els dits d'un matí d'hivern."},"ICON-2640":{"nm":"Funda tèrmica per a la tapa de l'ampolla d'aigua calenta","de":"Posa una funda sobre l'ampolla plena d'aigua calenta. Perquè no es refredi durant la nit, embolica la calidesa amb una capa més. La manera de retenir la calidesa molt de temps és, al final, abraçar-la amb cura amb alguna cosa."},"ICON-2641":{"nm":"Barra premedora per al paper de porta","de":"El vent tallant que s'esmunyia per l'escletxa de la porta vacil·la just quan et troba. Una sola barra prem la vora del paper de la porta corredissa. La calidesa de l'habitació protegeix per fi els seus, i l'hivern s'escalfa amb aquesta petita tossuderia."},"ICON-2642":{"nm":"Plat suport per a l'escalfapeus","de":"El plat rodó posat sota l'escalfapeus. Rep tota la calor tot sol i no deixa ni una marca cremada al terra. Quan els dits dels peus d'algú s'escalfen fins a un dolç son, la meva part del dia s'acaba en silenci."},"ICON-2643":{"nm":"Anella per al drap eixugador de condensació","de":"Perquè el drap que ha eixugat les gotes de la finestra de matinada no perdi el seu lloc, una anella penja de la paret i espera. Més que estar xop, esperar sec fins al matí següent és el veritable esperit de l'absorció."},"ICON-2644":{"nm":"Penjador assecador per a guants d'hivern","de":"Els guants, acabada una batalla de boles de neu, obren els dits ben oberts al costat del radiador. L'escena de veure'ls penjats al penjador, exhalant vapor suau. Al final d'una tarda amb el nas vermell, és la bugada més tranquil·la de l'hivern."},"ICON-2645":{"nm":"Recanvi de plomes per al plomall","de":"Quan les plomes es gasten, se'n col·loquen de noves. El moment en què la punta que caçava pols torna a ser suau. Que fins i tot les eines de neteja tenen les seves estacions de canvi, aquest petit recanvi t'ho fa saber, quiet, a la palma de la mà."},"ICON-2646":{"nm":"Mànec escorredor de baieta","de":"Un mànec afegit per estalviar-te força al canell. Un sol gir i la baieta escup l'aigua tota sola. Adéu als temps de patir davant la tauleta de rentar. En les feines de casa, un grapat d'enginy es converteix en pura tendresa."},"ICON-2647":{"nm":"Capçal de recanvi per al raspall de terra","de":"Quan el raspall de terra s'ha gastat del tot, només se'n canvia el capçal. El mànec es queda igual, i també el pes que la mà ja coneix. En les coses que fem servir molt de temps hi habita una tendresa petita i ferma que no vol llençar-ho tot sencer."},"ICON-2648":{"nm":"Nucli de recanvi per al rodet antipèl·lusca","de":"Quan s'arrenca l'última fulla del rodet, queda una estranya sensació de buit. Aleshores s'hi col·loca un nucli nou. És la promesa tenaç i amable d'un recanvi que es fa càrrec, fins al final, de fins i tot un sol borrissol enganxat al jersei."},"ICON-2649":{"nm":"Rascador de pols per a racons","de":"Fins i tot als racons on l'escombra no arriba, la pols s'hi instal·la en silenci. Rascar el racó amb una punta prima. El cor que cuida fins allò que no es veu és precisament l'orgull de portar bé una casa."},"ICON-2650":{"nm":"Pinta netejadora per a l'escombra","de":"Fins i tot una escombra que ha estat escombrant necessita un toc de descans. Pentina amb aquesta pinta els cabells enredats entre les cerdes, i l'escombra, acabada la seva tanda de feina, es prepara per fi per a la propera escombrada."},"ICON-2651":{"nm":"Tampó de cera per a la fusta del terra","de":"Aplica una capa de cera seguint el veta de la fusta, i la fusta recorda a poc a poc una lluentor que feia temps que havia oblidat. Les plantes dels peus a punt de lliscar i a punt de no fer-ho: una tarda en què tota la casa somriu, lluent i satisfeta."},"ICON-2652":{"nm":"Escombreta per a pols de l'escletxa de la porta","de":"Vaig a la caça de la pols que viu a les escletxes de les portes. Recullo amb el meu cos prim tot allò que s'acumula d'amagat cada cop que la porta s'obre i es tanca. Com més estreta i profunda l'escletxa, més segur que em toca el torn."},"ICON-2653":{"nm":"Tap de malla per a l'estora de l'entrada","de":"Perquè la pols que ha engolit l'estora de l'entrada no torni a escapar cap enfora, un tap de malla es manté com a últim porter. La pols que les sabates enfangades han portat del món de fora té permès arribar només fins aquí, i no més enllà."},"ICON-2654":{"nm":"Raspall antical per a l'aixeta","de":"El raspallet petit gira i grata les incrustacions de calç que s'han assentat en silenci al coll de l'aixeta. Com més toquen les mans un lloc cada dia, més ha de brillar. Aquesta és la cortesia del bany que aquest petit raspall protegeix."},"ICON-2655":{"nm":"Tap de malla per als cabells del desguàs","de":"Atrapo en silenci els cabells que anaven a la deriva cap al desguàs. Evitar el petit desastre d'un embós amb una sola tapa. El dia d'un heroi petit, rodó i tenaç, flueix sempre en silenci, sota els peus."},"ICON-2656":{"nm":"Rascador de junts de rajola","de":"La juntura enfosquida entre les rajoles blanques: rasca-la amb suavitat i posa fi a aquest temps vell. Quan els estrets interstici queden nets, tot el bany respira lleuger, com nou."},"ICON-2657":{"nm":"Agulla netejadora per al capçal de dutxa","de":"Destapa amb la punta de l'agulla els forats obstruïts del capçal de dutxa, i l'aigua que només degotava torna a brollar fresca. El so triomfal de l'aigua del matí, quan un petit embós es desfà."},"ICON-2658":{"nm":"Got portador per al raspall del vàter","de":"Fins i tot el raspall del vàter només és realment higiènic quan reposa en un lloc sec. Ben col·locat dins un got petit que recull els degotalls, espera el proper torn. La dignitat d'una eina no es veu en l'ús, sinó en com es guarda."},"ICON-2659":{"nm":"Esponja netejadora de floridura","de":"La floridura negra escampada per les cantonades de les rajoles: a aquest hoste tossut, l'esponja li suggereix cortesament la sortida. Un sol passat i el bany torna, lluminós, al seu blanc original."},"ICON-2660":{"nm":"Rasqueta per al baf del mirall","de":"Davant un mirall entelat després de la dutxa, la rasqueta traça una línia i el teu rostre nítid torna a aparèixer. El moment de tornar a trobar l'expressió d'avui que s'havia amagat un instant rere el baf."},"ICON-2661":{"nm":"Penjador de xancletes de bany","de":"Penja les xancletes mullades cap per avall i l'aigua regalima gota a gota mentre l'interior s'asseca ben eixut. Perquè els peus de la propera persona no passin fred. L'atenció d'un petit penjador sempre surt un pas endavant a rebre't."},"ICON-2662":{"nm":"Estoig per al raspallet d'ungles","de":"Fins i tot el raspallet petit que neteja la brutícia sota les ungles té casa pròpia. Encaixat dins l'estoig, s'asseca sec i eixut, esperant el proper lavabo. La netedat sempre comença, en silenci, amb l'ordre."},"ICON-2663":{"nm":"Tapa per al got esterilitzador del raspall de dents","de":"Fins i tot el raspall de dents, que et troba amb la boca dues vegades al dia, necessita un petit refugi. En el moment que la tapa del got esterilitzador es tanca amb un clic, es protegeix en silenci un racó de netedat davant la humitat que ronda pel bany."},"ICON-2664":{"nm":"Càpsula de viatge per a bastonets d'orelles","de":"Perquè els bastonets a la bossa de viatge no es trenquin ni s'escampin, una càpsula els abraça bé arrenglerats al seu interior. Com més petita és una cosa, més cal preparar-la per endavant, perquè no et sorprengui en un camí desconegut."},"ICON-2665":{"nm":"Tauleta mini per comprovar l'alè","de":"Bufa a la palma de la mà i acosta-la lleugerament a la tauleta mini, i l'alè hi toca i s'entela de blanc lletós. La prova més adorable que sóc viva aquí en un dia fred, aquesta petita tauleta la registra sense dir ni un mot."},"ICON-2666":{"nm":"Casa d'emmagatzematge per al netejador d'orelles","de":"Quan un netejador d'orelles viatja dins d'una bossa, la punta s'esmussa fàcilment. Per això es va fer una petita casa. A dins, on la punta no pateix cap dany encara que es porti a sobre, l'eina delicada dorm plàcidament."},"ICON-2667":{"nm":"Clip plegador de mocador","de":"El clip mossega suaument un mocador ben plegat per les quatre puntes, evitant que es desfaci dins la bossa. Un full ben plegat i endreçat ofereix una elegància tranquil·la cada vegada que el treus."},"ICON-2668":{"nm":"Estoig de tiretes","de":"El dia que et fas un tall al genoll, obre l'estoig i tota mena de tiretes s'arrengleren esperant-te. La tendresa de saber fer un rebombori fins i tot per una ferida petita. Una farmaciola sempre s'ha de tenir a l'abast de la mà."},"ICON-2669":{"nm":"Netejador d'empremtes per a la palma","de":"Frega el vidre i esborra les empremtes que hi queden, i el rastre de mans vacil·lants desapareix. Una petita màgia de la mida d'una palma, en què el món més enllà de la finestra, tèrbol a cada toc, torna a fer-se transparent."},"ICON-2670":{"nm":"Separador per a la recollida selectiva","de":"El paper aquí, les llaunes allà. Un sol separador parteix un destí que gairebé s'havia barrejat. Reciclar és, al capdavall, el cor de separar amb cura, i aquest compartiment ben ajustat en traça la primera línia amb claredat."},"ICON-2671":{"nm":"Espàtula per despegar adhesius","de":"Fins i tot un adhesiu enganxat amb força se sotmet en silenci davant meu. Introdueix lleugerament la fulla plana per una cantonada i es desprèn net, sense deixar ni una marca: un comiat triomfal."},"ICON-2672":{"nm":"Dentat tallador per a cinta de carrossatge","de":"No cal buscar unes tisores només per fer servir cinta de carrossatge. Apropa-la a les dents i estira, i es talla net seguint el veta. La millor amiga, petita i àgil, de les puntes dels dits que estimen decorar el diari."},"ICON-2673":{"nm":"Ferramenta angular adhesiva per a cantonades","de":"Una petita ferramenta que subjecta ferm, des de dins, una cantonada aixecada. Des d'un lloc invisible, manté l'angle recte en silenci. Rere les coses que semblen rectes per fora, sol haver-hi un suport amagat com aquest."},"ICON-2674":{"nm":"Tub protector de fulls de pegatines","de":"Perquè els preuats fulls de pegatines no s'arruguin ni s'humitegin, dormen dins el tub al costat d'una pel·lícula protectora. Al costat de la joia de col·leccionar, sempre hi va acompanyada la cura de protegir-ho amb tendresa."},"ICON-2675":{"nm":"Raspall netejador per a segells de tinta","de":"El raspall escombra suaument, seguint el veta, les escletxes del segell xop de tinta, despullant-lo del color vell. Un toc petit i diligent que neteja per endavant perquè la propera impressió surti nítida."},"ICON-2676":{"nm":"Aleta subjectadora per a fulls transparents de carpeta","de":"Perquè els fulls de recanvi de la carpeta no llisquin i s'escapin, les aletes els subjecten fermament per ambdós costats. Gràcies a que cada full es queda al seu lloc, la punta del dit que passa pàgines mai no es desordena."},"ICON-2677":{"nm":"Pala recollidora per a peces de decoració","de":"Recull d'una sola passada, amb la petita pala, les diminutes peces de decoració escampades. Quan desapareix la molèstia de recollir-les una a una amb els dits, el temps de crear alguna cosa amb cura es fa molt més gustós."},"ICON-2678":{"nm":"Fixador per a la borla del punt de llibre","de":"Perquè la borla de l'extrem del punt de llibre no s'afluixi, el fixador la lliga amb fermesa. Fins i tot un guia que et torna a la pàgina a mitges de llegir descansa més tranquil quan el seu propi aspecte és polit."},"ICON-2679":{"nm":"Pinça per a la tapa del retolador decoratiu","de":"Una pinça que estreny bé la tapa perquè la punta del retolador decoratiu no s'assequi. Evita el contratemps que un retolador deixat obert s'endureixi, així el color sempre raja humit com el primer dia."},"ICON-2680":{"nm":"Punta intercanviable per a tornavís","de":"Deixa el mànec del tornavís tal com és i canvia només la punta de l'extrem. En creu o pla, sense cap problema. L'enginy de fer moltes feines amb una sola eina hi cap, ben ajustat, en aquesta petita punta."},"ICON-2681":{"nm":"Embolcall per a cantonada de paper de vidre","de":"Enrotlla la superfície rugosa per agafar-la, i la palma es converteix en eina. Frec, frec: a cada passada seguint el veta, la cantonada aspra s'arrodoneix, i la suavitat final sempre la reconeixen les puntes dels dits d'una persona."},"ICON-2682":{"nm":"Embut classificador de cargols","de":"Els cargols escampats travessen el coll estret i s'apleguen, rodolant, en un sol lloc. El so de les coses petites que rodaven per la taula trobant el seu lloc fa sentir com si fins i tot un cor desendreçat es posés ordenat."},"ICON-2683":{"nm":"Ganxo de l'extrem de la cinta mètrica","de":"El ganxo de l'extrem de la cinta mètrica és la segona mà de qui treballa tot sol. Enganxa'l a una cantonada i la cinta no trontollarà, i tant la mà com el cor es tornen tan honestos com la longitud mesurada."},"ICON-2684":{"nm":"Funda per al mànec de la clau anglesa","de":"Una capa afegida sobre el mànec fred de metall. En el moment d'agafar-lo, en lloc del fred hi toca una calidesa suau. Una eina roman més temps al teu costat quan pensa primer en qui la subjecta."},"ICON-2685":{"nm":"Con protector per a la punta del punxó","de":"Un petit con es col·loca sobre cada punta esmolada. La tranquil·litat de furgar dins un calaix sense punxar-se: com més esmolada és una cosa, si s'embolica amb cura, ningú no es fa mal."},"ICON-2686":{"nm":"Fulla pelacables","de":"Pela només el revestiment, prim, sense fer mal al fil de dins. En el moment que deslliga suaument una capa i un filament de coure brilla a la vista, una bona fulla sap exactament on s'ha d'aturar."},"ICON-2687":{"nm":"Netejador de la finestreta de bombolla del nivell","de":"Només quan una única bombolla s'atura exactament al mig hi ha veritable horitzontalitat. Netejar la finestreta petita s'assembla a la preparació silenciosa d'agafar aire abans de traçar una línia."},"ICON-2688":{"nm":"Funda protectora de dit per clavar claus","de":"Una petita funda que embolica bé el dit que sosté el clau. Diu: colpeja sense por, encara que el martell falli tot està bé, ja està a punt, ben ajustada, per rebre el cop en lloc del teu dit."},"ICON-2689":{"nm":"Estora antilliscant per al bol de menjar","de":"Una capa de goma que sosté el bol perquè no rellisqui per terra. Sense que el bol fugi en ple àpat animat, la calma d'un menjar comença des d'un lloc que no trontolla."},"ICON-2690":{"nm":"Penjador per al cassó de pinso","de":"Penja el cassó de servir pinso a la paret perquè s'assequi lleugerament. Un petit ordre que rep la mà cada àpat des del mateix lloc: tenir una boca de qui tenir cura és una cosa tan tendra com aquesta."},"ICON-2691":{"nm":"Plat recollidor de vessaments del bol d'aigua","de":"Recull en silenci el glop que ha vessat per la vora del bol d'aigua. Gràcies al plat ample que l'acull per endavant perquè el terra no es mulli, sota els peus sempre es manté sec i eixut."},"ICON-2692":{"nm":"Pinces distribuïdores de llaminadures","de":"Unes pinces que agafen exactament un tros de llaminadura per oferir-lo. Fins i tot davant d'una boqueta petita que espera amb el nas endavant, en el compartir hi ha una punta de dit tendra que mai no perd la mesura."},"ICON-2693":{"nm":"Clip enrotllador per a bosses de pinso","de":"Una petita pinça que enrotlla i mossega la boca d'una bossa de pinso ja oberta. Amb un sol clic tancat, es bloqueja la humitat, i el grapat cruixent de demà al matí es preserva intacte."},"ICON-2694":{"nm":"Tap per al broc del dipòsit d'aigua","de":"Un tap que encaixa perfectament al broc del dipòsit d'aigua. Toc, toc: les gotes que degotaven paren i la vora s'asseca. Allò que es tanca bé no vessa, i es manté clar i quiet durant molt de temps."},"ICON-2695":{"nm":"Got graduat per a la ració de menjar","de":"Aboca exactament una tassa seguint la marca. Ni massa ni massa poc: en la mà que calcula amb justícia l'àpat d'avui, s'hi conté, ben mesurat, el dia d'un petit membre de la família."},"ICON-2696":{"nm":"Vora de l'estora contra vessaments de menjar","de":"Una vora que evita que el menjar vessat surti fora de l'estora. Un sol rivet, aixecat només un pèl, recull amb fermesa les engrunes que estaven a punt d'escampar-se."},"ICON-2697":{"nm":"Anella separadora per a bols apilats","de":"Una petita anella que separa suaument dos bols encaixats. La mà que forcejava perquè estaven ben enganxats es fa lleugera. Separar bé, resulta que també és una cura tendra."},"ICON-2698":{"nm":"Embut recollidor de pilotes del pati","de":"Un embut que aplega en un sol lloc les pilotes que han rodolat pel pati. Després d'un vespre de jugar sense parar, ve de manera natural al cap la mà que recull tot allò escampat aquí i allà."},"ICON-2699":{"nm":"Barret per a estaques de tanca","de":"Posa un barret rodó a cada estaca de la tanca. Perquè les puntes no s'esquerdin amb el vent i la pluja, un cor que cuida i cobreix fins i tot la cosa més petita ha impregnat tot el pati."},"ICON-2700":{"nm":"Ganxo plegable per al túnel de joc","de":"Un ganxo per plegar amb cura el túnel de joc ben jugat i penjar-lo. Si recolliràs bé un dia tacat de terra i el penges, un joc ben endreçat sempre promet un demà."},"ICON-2701":{"nm":"Coixinet de l'Empunyadura d'Estirar","de":"Un coixí que embolcalla tovament l'empunyadura de la corda d'estirar. Per molt fort que s'estiri, el palmell mai no s'escorxa. Com més temps s'hi aferra la mà, més còmoda es queda, i això és gràcies a la petita atenció d'algú."},"ICON-2702":{"nm":"Gafet de la Tela d'Ombra del Pati","de":"Un gafet que subjecta amb fermesa la tela d'ombra estesa pel pati. Fins i tot la frescor del migdia s'ha de mantenir fixada perquè perduri. Sota l'ombra que el gafet manté tibant, una tarda mandrosa s'estira llarga i descansa."},"ICON-2703":{"nm":"Funda per a la Fulla de la Pala","de":"Una funda que es posa suaument sobre la fulla de la pala de cavar. Deixeu-la descansar després d'una dura jornada de feina, i es manté esmolada, a punt per retrobar la terra de la propera primavera."},"ICON-2704":{"nm":"Rampa Rodadora de Pilota","de":"Una simple rampa on la pilota rodola avall tota contenta. Pel pendent lleugerament inclinat, la pilota corre amb alegria. Un petit desnivell basta per fer tot un dia de diversió."},"ICON-2705":{"nm":"Anella del Baldó de la Tanca","de":"Una anella de baldó que tanca la porta de la tanca. El clic petit en tancar-se tranquil·litza el cor. Una porta ben tancada manté un petit pati a resguard, com un món a part."},"ICON-2706":{"nm":"Cordó de Joc amb Cascavell","de":"Sacsegeu suaument el cordó amb el cascavell lligat i un so clar s'escampa. Dring, dring: una habitació que era silenciosa es desperta, i amb un sol petit ressò tot el cor para l'orella."},"ICON-2707":{"nm":"Safata Recollidora del Test","de":"Una safata que recull tranquil·lament l'aigua que s'escola per sota del test. Manté l'ampit de la finestra sec absorbint el sobrant. Fins i tot la dedicació, quan vessa, necessita un lloc on ser recollida."},"ICON-2708":{"nm":"Plantador de Planters","de":"Una petita pala per traslladar planters tendres a la terra i clavar-los suaument. Sota els dits que col·loquen amb cura cada brot, una primavera verda alça el cap fins i tot en un hortet de mida palmell."},"ICON-2709":{"nm":"Agulla Marcadora de Solc","de":"Una agulla marcadora on s'escriu i es clava a cada solc per indicar què s'ha plantat. Sobre una terra on encara no ha brotat res, una petita etiqueta recorda tranquil·lament què hi creixerà."},"ICON-2710":{"nm":"Malla per al Broc de la Regadora","de":"Una malla fina que es col·loca al broc de la regadora. L'aigua que abans queia en un sol raig s'escampa ara en molts fils com una plujeta suau. Només un raig tendre evita que les fulles delicades es facin mal."},"ICON-2711":{"nm":"Pinça de Subjecció al Tutor","de":"Una pinça que lliga amb cura una tija vacil·lant al seu tutor. Un simple suport prestat fins que allò encara tendre pugui mantenir-se dret: créixer necessita un recolzament així."},"ICON-2712":{"nm":"Clip Segellador de Llavors","de":"Un clip que tanca ben fort la bossa de llavors que ha sobrat. Un cop fixat, ni un sol gra s'escapa. Una petita promesa a la propera primavera hi resideix en aquest únic pessic."},"ICON-2713":{"nm":"Culleró Mesurador de Terra i Adob","de":"Un petit culleró per agafar la quantitat justa de terra i adob. Ni de més ni de menys, una sola cullerada: només amb la mesura exacta la terra pot fer per fi la seva feina."},"ICON-2714":{"nm":"Ganxo Penjador de Test","de":"Un ganxo que suspèn lleugerament el test enlaire. Alçat, el verd s'apropa un pam més al sol i a la brisa. Un petit jardí floteja suau vora la finestra."},"ICON-2715":{"nm":"Malla Protectora de Brots","de":"Una malla protectora que cobreix suaument els brots acabats de néixer. Fins que les fulles encara tendres puguin resistir el primer fred i el sol punxent, el més fràgil és el primer a rebre cura."},"ICON-2716":{"nm":"Penjador de la Pinta","de":"Un racó on es sacseja el pèl solt de la pinta i es penja endreçada. La pinta, tova i buidada, espera la propera carícia. La pulcritud sempre comença amb el petit hàbit de tenir cura de les eines."},"ICON-2717":{"nm":"Anell Antilliscant per a la Palangana","de":"Un anell que sosté la palangana de rentar peus perquè no llisqui. Amb la palangana ferma sota els peuets que xipollegen, ni les mans que renten ni el cor que és rentat trontollen."},"ICON-2718":{"nm":"Ganxo Penjador de la Corretja de Passeig","de":"Un simple ganxo per penjar la corretja de passeig a l'entrada. Des del seu lloc vora la porta, la disposició per sortir sempre espera. En el moment en què la corretja baixa, un pas il·lusionat surt també al seu costat."},"ICON-2719":{"nm":"Tap Protector per Tallar les Ungles","de":"Un tap protector que resguarda la carn tendra mentre es tallen les ungles. Només amb un límit segur marcat fins aquí, la mà que sosté les tisores es manté tranquil·la i ferma."},"ICON-2720":{"nm":"Tira Termòmetre per al Bany","de":"Una tira que sura a l'aigua del bany i n'indica la temperatura. Aquell gest antic de submergir la mà per calcular la calidesa justa ara hi sura, traduït amb claredat en una simple franja de color."},"ICON-2721":{"nm":"Rodet Enganxós per a la Roba","de":"Un sol pèl blanc sobre roba negra sembla el més gran de tots just abans de sortir a l'escenari. Seguint el so del rodet que gira, les engrunes d'un dia sencer es van enganxant, ordenades, al paper enganxós. La pulcritud es completa així, un tros cada vegada, tant com se n'arrenca."},"ICON-2722":{"nm":"Pinces per a Bosses d'Excrements","de":"Al final del passeig hi ha un moment tendre d'ajupir-se. Subjecteu la bossa amb la punta de les pinces i les mans es mantenen netes, el cor lleuger. Passejar junts porta també una petita cortesia de netejar el que queda enrere, i aquestes pinces ho saben abans que ningú."},"ICON-2723":{"nm":"Vora de l'Estora de la Porta","de":"La vora de l'estora davant la porta és la primera benvinguda que rep el peu. Si els dits humits s'aturen aquí un instant, el terra de dins es manté eixut. El racó més humil de tots, que neteja i saluda en silenci tots els qui entren."},"ICON-2724":{"nm":"Cordó amb Nus per al Cascavell","de":"Fins i tot penjar un sol cascavell té el seu ordre. Enrotlleu el cordó dues voltes i passeu-lo un cop, i un so clar acompanya cada pas amb un dring rodolant. Arreglar-se és, al capdavall, el cor que mai no s'oblida d'aquest petit toc final."},"ICON-2725":{"nm":"Bosseta Recollidora d'Aigua per al Paraigua","de":"En un vestíbul just després de la pluja, les gotes de la punxa del paraigua plegat taquen el terra a poc a poc. Una bossa les recull en silenci, i ningú no relliscarà. La gentilesa, sovint, es queda a prop així, sense fer soroll."},"ICON-2726":{"nm":"Pinça per a la Corretja de la Bossa","de":"Una bossa penjada a la cadira no para de relliscar cap avall. Subjecteu-la un cop amb la pinça i les dues mans queden lliures del neguit que caigui. La comoditat de sortir comença quan es pot oblidar l'equipatge per un moment."},"ICON-2727":{"nm":"Bosseta de Roba per a l'Escalfador de Mans","de":"En un carreró de vent fred, una bosseta de roba dins la butxaca porta discretament la calidesa fins al palmell. Una capa suau que embolcalla allò calent i l'escalfa just al punt. La tendresa de l'hivern sempre arriba passant per un tros de tela."},"ICON-2728":{"nm":"Peu per al Mirall Plegable","de":"Desplegueu-lo i un petit mirall inclina el seu propi angle. Perquè pugueu mirar-vos la cara sense sostenir-lo amb la mà, el peu es queda dret al vostre lloc. Fins i tot en el breu instant d'arreglar-se, un fidel actor secundari és al vostre costat."},"ICON-2729":{"nm":"Tapa per a Tovalloletes de Viatge","de":"El primer full de tovalloletes sempre s'anava assecant. Tanqueu la tapa amb un clic i fins i tot l'últim full es manté humit. Fer que duri fins al final: el secret d'una llar duradora s'amaga en detalls tan petits com aquest."},"ICON-2730":{"nm":"Separador de Monedes per a la Cartera","de":"Quan les monedes s'escampen entre els bitllets, la caixa registradora sempre es fa un embolic. Un separador aplega les coses rodones a un costat i els dits ja no van a les palpentes. Endreçar és la feina de donar a cada cosa un lloc i un nom."},"ICON-2731":{"nm":"Estoig Plegable per a la Mascareta","de":"Plegada, la mascareta no s'arruga ni dins la bossa. Un estoig que guarda net un full que s'ha tret per un moment. Aquí hi cap un hàbit tendre: desar-la amb cura per fer-la servir de nou."},"ICON-2732":{"nm":"Funda per a les Pues de la Pinta","de":"Les pues de la pinta dins la bossa solien esgarrapar altres coses. Poseu-hi la funda i la pinta queda segura, i també ho estan els altres objectes que hi van junts. Qualsevol que ha cuidat les seves coses sap que una petita capa de protecció manté totes dues parts a resguard."},"ICON-2733":{"nm":"Clip Divisor de Calaix","de":"Cada cop que s'obria el calaix, els objectes barrejats s'abocaven com un sospir. Dividiu-lo en seccions amb un clip i les coses petites troben per fi la seva zona. Un calaix endreçat canvia en silenci l'estat d'ànim de cada matí."},"ICON-2734":{"nm":"Peanya per Exposar Monedes","de":"Poseu dreta una moneda antiga i es converteix per si sola en una petita exposició. La peanya la sosté inclinada per mostrar clarament el dibuix de la cara. Alçar un temps ple de tacte fins a l'altura dels ulls: aquí és on s'aprofundeix el plaer de col·leccionar."},"ICON-2735":{"nm":"Anella per Enrotllar Auriculars","de":"Hi ha hagut matins mig perduts desenredant el cable dels auriculars. Enrotlleu-lo ordenat a l'anella i, la propera vegada que el traieu, llisca suau. Un petit ordre es converteix en un regal discret que es passa al jo de demà."},"ICON-2736":{"nm":"Ganxo de Paret per al Cable de Càrrega","de":"El cable de càrrega escampat pel terra sempre acabava trepitjat. Enganxeu un ganxo a la paret per penjar-lo i l'escriptori queda molt més ampli. Domar el desordre no és res de grandiós: només un racó no més gran que un clau."},"ICON-2737":{"nm":"Suport per al Comandament a Distància","de":"El comandament que sempre desapareixia entre els coixins del sofà per fi té una casa on tornar. Poseu-lo dret al suport i s'acaben les cerques i els cops de seure-hi a sobre. Tenir un lloc propi es converteix també en un petit descans, fins i tot per a un objecte."},"ICON-2738":{"nm":"Pinça Penjadora per a les Ulleres","de":"Les ulleres, un cop deixades, sempre relliscaven cap a algun lloc discretament. Pengeu una barra amb suavitat a la pinça i les lents mai no toquen el terra. El desig de mantenir-les sense ratllar per a demà s'amaga en aquest petit penjador."},"ICON-2739":{"nm":"Clip Classificador de Claus","de":"Com més pesa un manat de claus, més es confon quina obre quina porta. Lligueu-les amb un clip classificador i els dits, tots sols, sabran reconèixer cada parella. Un guia silenciós que porta ordre, sense dir res, a les portes que s'obren i es tanquen cada dia."},"ICON-2740":{"nm":"Clip Suport per a Notes","de":"Les notes escrites sovint queien de cara avall sobre l'escriptori. Quan el clip sosté el paper dret, les paraules et miren directament als ulls. Una manera de fer que la línia que no s'ha d'oblidar visqui sempre a la vista."},"ICON-2741":{"nm":"Suport per al Bolígraf","de":"Quantes vegades t'has hagut de doblegar per recollir un bolígraf que ha rodolat pel terra? Poseu-lo dret amb la punta cap avall al suport i la distància fins a la propera línia s'escurça un pam. Una petita estació d'espera, sempre desperta al costat de qui escriu."},"ICON-2742":{"nm":"Base Giratòria del Rellotge de Sorra","de":"Quan un rellotge de sorra s'acaba, algú l'ha de girar perquè torni a viure. La base recull el moment de l'últim gra i el fa girar suaument cap amunt. La carícia que retorna el temps al seu inici descansa aquí, sobre un petit tros de fusta."},"ICON-2743":{"nm":"Patata al Forn amb Mantega","de":"La mantega es fon a poc a poc sobre una patata coberta amb la seva pell. Quan el vellut daurat s'escola amb el vapor, la carn esponjosa acull en silenci la sabor torrada. El moment precís en què una arrel amb olor de terra es fa la més càlida de totes."},"ICON-2744":{"nm":"Panotxa a la Graella amb Mantega","de":"Els grans grocs alineats en fileres cruixen sobre la planxa. Llisqueu-hi un tros de mantega i la fragància dolça puja de sobte. La dolçor d'un camp d'estiu es trasllada, tal qual, dins d'un sol mos."},"ICON-2745":{"nm":"Gofre","de":"A cada quadrat de la reixa, el xarop espera tranquil que s'hi acumuli. Cruixent per fora, esponjós per dins: mossegueu-lo i en surt un vapor calent. Els compartiments quadrats semblen un plat que reparteix petites felicitats."},"ICON-2746":{"nm":"Pancakes","de":"Recordo aquella olor de la massa que s'inflava daurada sobre la paella. Sobre els discos rodons apilats capa rere capa, la mantega s'esllavissa i es fon poc a poc. Un plat tou que només es permet suaument en un matí sense pressa."},"ICON-2747":{"nm":"Xocolata","de":"Sostingut un tros a la boca, es va desfent lentament amb la calor del cos. La dolçor que s'escampa al final de l'amargor allibera de sobte la tensió del cor. En un dia esgotador, un petit tros marró de consol tret de la butxaca."},"ICON-2748":{"nm":"Pastís de Maduixes","de":"Maduixes vermelles s'asseuen damunt la nata blanca, anunciant la primavera abans que ningú. Quan la forquilla parteix el tall suau, una fragància àcida floreix discretament. En un dia amb alguna cosa a celebrar, la tendra protagonista al centre de la taula."},"ICON-2749":{"nm":"Pastís de Formatge","de":"Un tros feixuc s'ensorra dens sobre la llengua. El regust salat agafa de la mà la dolçor i demana, sense parar, un mos més. Una postres que els amants de la densitat sadollant saboregen en silenci."},"ICON-2750":{"nm":"Galetes de Plàtan","de":"L'olor del plàtan aixafat madura groga dins el forn. Mossegueu-ne un tros i una dolçor suau s'escampa per tota la boca. El moment càlid en què una fruita ben madura torna a néixer com a galeta."},"ICON-2751":{"nm":"Galetes amb Xocolata","de":"Els trossos de xocolata dins la massa es fonen densos en coure's. Partiu-la mentre encara és calenta i un marró intens us queda als dits. Amb un got de llet, el tros que fa una tarda una mica més amable."},"ICON-2752":{"nm":"Galetes amb Puntes de Cacau","de":"Trossets de cacau ben esmicolats cruixen entre la massa. Un amargor profund i sense sucre calma amb suavitat un paladar adult. Una galeta una mica seriosa que conserva intacta l'aroma original d'abans de ser processat."},"ICON-2753":{"nm":"Torrada de Formatge","de":"El formatge s'estira llarg com un fil sobre el pa torrat daurat. El cruixent de fora i el saborós de dins es fonen en un sol mos. L'àpat més senzill i alhora més entranyable que omple una tarda tardana de sadollament."},"ICON-2754":{"nm":"Entrepà","de":"Entre dues llesques de pa s'hi acumula, capa a capa, la cura d'un dia sencer. Mossegueu-lo i tots els sabors apilats saluden alhora. Una petita taula al palmell de la mà, a punt per emportar-se a qualsevol lloc."},"ICON-2755":{"nm":"Torrada Francesa","de":"El pa ben remullat en ou es va enrossint sobre la paella. Les vores, inflades amb l'aroma de mantega, són les primeres a tornar-se cruixents. Amb un raig de xarop, fins i tot un pa senzill esdevé un luxe de festa."},"ICON-2756":{"nm":"Ramen de Bolets","de":"L'aroma profunda dels bolets s'alça amb el vapor sobre el brou bullent. Traieu-ne un barret sucós i una dolçor terrosa s'escampa per la boca. Un bol una mica especial que omple abans amb la fragància que amb els fideus."},"ICON-2757":{"nm":"Ramen Saltejat","de":"Sobre els fideus saltejats sense brou, una salsa picant s'enrotlla en una brillantor lluent. Alceu-los amb els bastonets i una aroma saborosa i fumada s'escampa entre el vapor. Quan es té ganes d'un àpat ràpid i intens, el millor amic."},"ICON-2758":{"nm":"Ramen amb Formatge","de":"Poseu una llesca de formatge sobre els fideus calents i s'ensorra i es fon a poc a poc. El brou picant i la suavitat saborosa es troben i arrodoneixen les vores. Un bol perfecte per a una nit en què es vol suavitzar una mica el picant."},"ICON-2759":{"nm":"Ramen amb Curri","de":"Una aroma intensa de curri envolta els fideus, alçant un vapor groc. Feu un glop sorollós i una calidesa picant us escalfa per dins. Uns fideus amb una variació divertida, que afegeixen una aroma una mica desconeguda a un brou familiar."},"ICON-2760":{"nm":"Ramen de Marisc","de":"Sobre un brou ple d'olor de mar, gambes i musclos suren rodons i grassonets a la superfície. Un gust profund i alhora refrescant s'infiltra entre els fideus. Una petita màgia que porta l'olor de la marea a un sol bol sense haver d'anar lluny."},"ICON-2761":{"nm":"Gimbap de Rave Encurtit","de":"Amb el rave groc encurtit al centre i l'arròs assegut al voltant, un sol full d'alga ho lliga tot en un rotlle amb tendresa. A l'alba d'una excursió, l'àpat més honest, nascut damunt una taula de tallar."},"ICON-2762":{"nm":"Gimbap de Tonyina","de":"En el moment en què una cullerada de tonyina amanida amb maionesa s'infiltra entre l'arròs, un àpat s'escalfa prou fins i tot sota la llum d'una botiga oberta les 24 hores en plena nit. El consol que les mans enfeinades agafen més sovint."},"ICON-2763":{"nm":"Amanida de Fruites","de":"Colors recollits de temporada es troben per primera vegada en un sol bol. Com el vermell, el verd i el groc s'avenen sense discutir: la fruita només ho mostra un cop tallada i reunida junta."},"ICON-2764":{"nm":"Amanida de Pollastre","de":"Pit de pollastre lleugerament a la graella, col·locat endreçat sobre fulles verdes. A la taula de qui es prepara per a l'escenari de demà, sempre hi ha un plat tan pulcre com aquest."},"ICON-2765":{"nm":"Amanida de Tomàquet i Cogombre","de":"Tomàquets ben madurs i cogombres cruixents amanits amb un toc àcid. Enmig d'un migdia espès de cants de cigala, un mos amb els bastonets i l'estiu es refreda un compàs per dins."},"ICON-2766":{"nm":"Amanida d'Enciam","de":"Rentar fulles acabades de collir de l'hort amb aigua freda desperta els dits amb un fred agradable. El moment en què la verdura més comuna ocupa el lloc més verd i fresc de la taula."},"ICON-2767":{"nm":"Amanida de Blat de Moro","de":"Cada cop que un gra dolç esclata, un camp de ple estiu banyat de sol s'obre davant els ulls. Fins i tot dins un bol d'amanida, el blat de moro groc no oblida mai el seu propi sol."},"ICON-2768":{"nm":"Coleslaw","de":"Quan la col tallada fina absorbeix una salsa agredolça, el seu cruixent s'estova un punt més. La virtut d'un acompanyament: al costat de qualsevol plat principal, mai no li disputa el protagonisme i compleix la seva part."},"ICON-2769":{"nm":"Amanida de Gambes amb Llima","de":"Un raig lleuger de llima i la dolçor de la gamba es desperta encara més clara. Una gota àcida que insufla vida a tot el plat: un toc final petit però decisiu."},"ICON-2770":{"nm":"Bistec Hamburg","de":"Una massa de carn gruixuda es cou daurada sobre una planxa calenta. El suc que s'escola just quan la punta del ganivet hi toca: l'àpat més estimat des de sempre, a mig camí entre el menjar de casa i la cuina occidental."},"ICON-2771":{"nm":"Pizza","de":"Aquell mos on el formatge s'estira llarg es passa de mà en mà entre molts asseguts al voltant. Quan es reparteix junts un disc rodó en trossos, una trobada esdevé per fi una trobada de veritat."},"ICON-2772":{"nm":"Pasta amb Crema de Bolets","de":"L'olor profunda de terra dels bolets i la suavitat de la crema abracen cada fil de pasta un per un. En un vespre amb el so tranquil de la pluja, l'aroma intensa s'escampa lentament fins al fons del plat."},"ICON-2773":{"nm":"Pasta amb Gambes","de":"Gambes grasses lleugerament saltejades amb oli d'oliva i barrejades amb la pasta. Quan la salinitat del mar troba la senzillesa dels fideus, una tarda sense res d'especial esdevé una mica especial."},"ICON-2774":{"nm":"Pasta a l'Oli","de":"All, oli i pasta: només tres coses. Hi ha un gust que es fa més clar com més se'n treu, i l'aglio e olio ho demostra en silenci, sense cap sobrer."},"ICON-2775":{"nm":"Pasta amb Cloïsses","de":"El brou que les cloïsses deixen anar en obrir la closca s'infiltra profundament en cada fil de pasta. L'aroma d'un glop de vi blanc perdura llarga sobre el plat, com un dia de primavera que no s'esvaeix."},"ICON-2776":{"nm":"Pasta amb Nata","de":"Quan la nata espessa abraça amb calma la pasta, un racó del cor s'escalfa des del primer mos. El consol que ofereix la suavitat es fa més profund com més fred fa fora."},"ICON-2777":{"nm":"Pasta amb Tomàquet","de":"Una salsa de tomàquet cuita llargament s'escampa vermella sobre la pasta. Quan la dolçor i l'acidesa es redueixen a poc a poc i troben per fi l'equilibri, el plat més bàsic és el més fiable."},"ICON-2778":{"nm":"Omurice","de":"Un ou tou cobreix l'arròs calent com un edredó, ben arrupit al seu voltant. Escriviu-hi tan sols un nom amb quètxup i la taula d'aquell dia esdevé una petita carta que algú us ha lliurat."},"ICON-2779":{"nm":"Salmó a la Graella","de":"Es cou lentament davant la flama fins que la pell queda cruixent. Un fil de vapor s'alça quan la carn rosada s'esfulla seguint la seva veta: la paciència sempre és recompensada amb honestedat pel salmó."},"ICON-2780":{"nm":"Bruschetta","de":"Tomàquet picat i alfàbrega s'apilen generosos sobre pa torrat i cruixent. Aquella lleugeresa d'agafar-lo amb els dits i fer-hi un mos obre amb calidesa la primera salutació d'una trobada."},"ICON-2781":{"nm":"Batut de Mango","de":"Es tritura un mango ben madur fins que queda fi i es barreja fresc amb gel. Quan les gotes es formen sobre el got groc, una tarda mandrosa de ple estiu puja fins a la punta de la palleta."},"ICON-2782":{"nm":"Llimonada","de":"Afegiu-hi llimona acabada d'esprémer, sucre i aigua freda, i sacsegeu-ho tot dins el got. Quan l'acidesa groga baixa fresca per la gola, fins i tot la calor més ferotge es rendeix per un instant."},"ICON-2783":{"nm":"Llet de Maduixa","de":"Bateu maduixes aixafades dins la llet i un núvol rosa s'assenta a poc a poc dins el got. L'emoció dels dits d'infant obrint de bat a bat la porta de la nevera queda tota sencera dins una sola tassa."},"ICON-2784":{"nm":"Llet de Plàtan","de":"Una beguda que ja és tot un record d'una època només per la forma rodona de la seva petita ampolla. El record groc de clavar-hi una palleta en un banc dels banys públics reviu amb tendresa a cada glop."},"ICON-2785":{"nm":"Llet de Nabius","de":"Afegiu-hi grans porpres i aixafeu-los, i la llet blanca es tenyeix d'un blau cel suau. Aquell grapat de fruita petita converteix tota una tassa en un color completament nou."},"ICON-2786":{"nm":"Suc de Fruites","de":"Premeu diverses fruites juntes i esdevé un gust que el nom de cap sola no pot anomenar. Un petit cor de dolçors, barrejant-se i inflant-se encara més ric."},"ICON-2787":{"nm":"Cacau","de":"Vora una finestra on neva, s'abraça tranquil·lament amb les dues mans una tassa calenta. Una tassa marró amb el vapor cargolant-se amunt escalfa a poc a poc, des de la punta dels dits fins al cor."},"ICON-2788":{"nm":"Cafè","de":"Sempre és aquesta única tassa la que encén els llums de la sala d'assaig de matinada. Quan l'aroma amarg empeny suaument la son, comença així, en silenci, l'escenari d'un altre dia."},"ICON-2789":{"nm":"Sushi de Salmó","de":"Es prem l'arròs a la mà, calculant aquella línia subtil entre fermesa i suavitat. En l'instant en què una fina llesca de salmó s'hi ajeu al damunt amb dolçor, un mos esdevé la culminació d'una petita dedicació."},"ICON-2790":{"nm":"Farinetes de Carbassa","de":"Es bull la carbassa groga fins que és tova i s'aixafa fina. A cada cullerada, la llum del sol de tardor es fon càlida dins la boca. Les farinetes que primer venen al cap quan un està malalt."},"ICON-2791":{"nm":"Curri de Peix","de":"La carn de peix, lleugerament cuita a foc lent amb espècies, es desfà tendra dins el curri. Afegiu la textura del mar a un bol familiar i una tarda ordinària emprèn un viatge un pam més lluny."},"ICON-2792":{"nm":"Gambes Arrebossades","de":"L'instant breu d'agafar-la per la cua, arrebossar-la i deixar-la caure a l'oli bullent és on es decideix tot. La gamba vestida d'un abric daurat brilla més quan es menja abans que el cruixent es refredi."},"ICON-2793":{"nm":"Calamars Arrebossats","de":"Anelles rodones s'inflen grasses dins l'oli calent. Aquell mos on el cruixent embolcalla la textura tendra escau millor sota els llums grocs d'una parada de menjar al carrer."},"ICON-2794":{"nm":"Pollastre a la Graella","de":"Amb l'adob ben untat, coure lentament davant la flama fa que la pell brilli amb lluïssor. Un plat on el gust depèn d'un sol ajust del foc: el més senzill i, per això mateix, el més honest."},"ICON-2795":{"nm":"Saltat de Porc amb Kimchi","de":"Saltar junts kimchi ben madur i porc fa que l'acidesa maduri en dolçor. Un plat que per si sol reclama un bol d'arròs blanc: la parella més fiable de la taula coreana."},"ICON-2796":{"nm":"Saltat de Porc","de":"Es salteja ràpid a foc fort perquè l'exterior quedi ben torrat. Quan l'olor saborosa de l'oli omple la cuina, el menú d'aquest vespre ja està decidit sense necessitat de preguntar més."},"ICON-2797":{"nm":"Saltat de Vedella i Bolets","de":"Saltar junts bolets aromàtics i vedella fa que els gustos d'ambdós s'aprofundeixin encara més. Un àpat pulcre de tardor on la terra i el camp s'agafen tranquil·lament de la mà sobre un sol plat."},"ICON-2798":{"nm":"Dak-galbi amb Formatge","de":"Es fon formatge generosament sobre el dak-galbi picant i s'estira ben llarg. Quan molts s'asseuen al voltant d'una planxa calenta al centre, fins i tot el picant que pica es desfà en riallades."},"ICON-2799":{"nm":"Estofat de Kimchi","de":"Com més vell és el kimchi, més profund i intens és el brou que dona. Asseieu-vos cara a cara davant una olla de fang que bull a poc a poc i la paraula «família» torna a escalfar-se."},"ICON-2800":{"nm":"Estofat de Doenjang","de":"Es dissol pasta de soja saborosa, s'hi afegeixen tofu i carbassó, i es couen lentament. Aquell so que continua bombollejant fins al final dins l'olla de fang és el senyal més segur que has tornat a casa."},"ICON-2801":{"nm":"Sopa de vedella i rave","de":"Mig dia esperant en silenci davant el foc baix, fins que el rave es torna transparent. Quan una cullerada del brou clar toca els llavis, torna a la memòria la taula senzilla d'aquells temps. El més sobri és el que perdura més."},"ICON-2802":{"nm":"Sopa de cloïsses","de":"En l'instant que les cloïsses obren la boca, la primavera s'aprofundeix dins l'olla. Quan un grapat d'olor de mar puja amb el vapor, ve al cap la cuina d'un poble costaner a trenc d'alba. En cada closca oberta hi ha estancada una mica de mar salabrosa."},"ICON-2803":{"nm":"Moniato caramel·litzat","de":"Camí de tornada de l'escola, grumolls grocs agafats en un got de paper com un escalfamans. En mossegar la crosta daurada, el vapor s'escapa de dins de cop. La closca dolçament caramel·litzada i l'interior calent: el gust de l'hivern en el seu moment més tendre."},"ICON-2804":{"nm":"Albergínia saltada","de":"L'instant en què el color porpra troba l'oli i s'estova a poc a poc. La verdura que criticaven per tova és, en realitat, la que millor acull el condiment. Amb la primera mossegada, el toc suau i amarat de la mà que cuina és el primer que arriba."},"ICON-2805":{"nm":"Patates guisades amb salsa de soja","de":"Un vespre en què l'olor dolça s'escampava per tota la cuina mentre la salsa de soja es reduïa. La mà que omplia el compartiment de la carmanyola amb un tros brillant i marró. Una cura que no apareix en cap recepta impregna cada petit tros."},"ICON-2806":{"nm":"Fulles de perilla en escabetx","de":"La feina d'adobar tota la flaire de l'estiu per portar-la fins a la taula d'hivern. Traieu-ne una fulla i poseu-la sobre l'arròs, i l'estació passada torna a florir dins la boca. Entre les fulles apilades capa rere capa dorm el sol d'aquell any."},"ICON-2807":{"nm":"Kimchi fresc de col xinesa","de":"Mans que no han pogut esperar el kimjang ho amaneixen tot just aquell mateix dia. La frescor que només es pot gaudir en el moment en què el condiment just comença a amarar les fulles cruixents. La verdor d'abans de la fermentació és un luxe només d'avui."},"ICON-2808":{"nm":"Bolets saltats","de":"Coses que van sorgir en silenci a l'ombra del bosc després que parés de ploure. Mentre es sofregeixen amb oli de perilla, l'olor de terra es converteix en un gust saborós. Com més silenciosament creix una cosa en la foscor, més profunda i intensa és la seva fragància."},"ICON-2809":{"nm":"Espinacs amanits","de":"Una verdura de fulla que, escaldada, es redueix a un simple grapat, amanida a poc a poc amb les puntes dels dits. Aquest volum humil és la virtut de les verdures de primavera. Un plat verd i un pam més de sol de primavera entra a la taula."},"ICON-2810":{"nm":"Algues amanides","de":"Fils llisos tot just pescats del mar es barregen amb un adob agredolç de gochujang. Un esclat salat que espurneja a cada mossegada. Un plat que trasllada directament al bol la textura ondulant, com d'onades."},"ICON-2811":{"nm":"Carbassó saltat","de":"Hi ha verdures la dolçor de les quals augmenta com més velles es fan. Tallat fi i saltat amb gambetes salades, fins i tot el carbassó més sobri revela discretament la seva dolçor. Un groc que s'estova suaument a la boca fins al final."},"ICON-2812":{"nm":"Arròs saltat amb kimchi","de":"Quan el kimchi vell arriba al seu punt, es troba amb l'arròs fred en una mateixa paella. Un bol que es torna el més reconfortant quan allò que sobra es troba amb allò que sobra. Sota la llum d'una habitació de lloguer a altes hores de la nit, la salvació més tendra."},"ICON-2813":{"nm":"Curri de pollastre","de":"Quan el brou groc cobreix l'arròs blanc, la taula s'il·lumina. En una època en què les espècies eren estranyes, el primer gust del món de fora amb què vam fer amistat. Un diumenge migdia en què la carn de pollastre es desfeia tova i esponjosa."},"ICON-2814":{"nm":"Arròs saltat","de":"Les sobralles del fons de la nevera s'entenen amistosament en una mateixa paella. Una generositat que acull qualsevol cosa sense reserves. Reunir allò dispers en un sol lloc: així comença la cura d'una llar."},"ICON-2815":{"nm":"Bol d'arròs amb bulgogi","de":"La carn marinada en una salsa dolça llisca suaument sobre l'arròs fumejant. Quan la protagonista de la taula dels convidats es converteix en un simple bol de cada dia, allò especial esdevé encara més tendre."},"ICON-2816":{"nm":"Bibimbap","de":"Sobre l'arròs esponjós, cinc colors de namul s'asseuen formant un cercle. En les puntes dels dits que en disposen els colors flueix una vella estètica de cura minuciosa. El gust de l'harmonia, que només es completa quan tot es barreja junt."},"ICON-2817":{"nm":"Arròs saltat amb gambes","de":"Gambes rodanxones ressalten en rosa entre els grans d'arròs. Amb un grapat de mar saltat, fins i tot un àpat corrent imita un banquet. La dolçor que s'escampa en l'instant que espeteguen entre les dents és sempre benvinguda."},"ICON-2818":{"nm":"Bol d'arròs amb porc picant","de":"Porc ben amarat d'un condiment picant es troba amb l'arròs fumejant. El bol que sempre era el primer a buidar-se a l'hora de dinar. El consol d'un àpat que acarona i alleuja un dia atrafegat."},"ICON-2819":{"nm":"Arròs amb tonyina i maionesa","de":"Una llauna, un raig de maionesa i un bol d'arròs calent. Els ingredients són senzills, però el consol és abundant. El gust d'aquella nit, barrejat d'amagat en un pupitre de classe després de l'estudi nocturn."},"ICON-2820":{"nm":"Arròs amb curri","de":"Un daurat espès omple tot el plat. La cura d'una llarga remenada fins que les patates i les pastanagues s'estoven del tot. Recorda la calidesa d'aquell vespre en què tota la família mirava dins la mateixa olla."},"ICON-2821":{"nm":"Bibimbap d'algues","de":"Fils amb aroma de mar es troben amb el gochujang i es barregen amb moviments ràpids. Quan la textura llisa i agredolça embolcalla els grans d'arròs, el mar que una bussejadora va pujar amb l'alè aguantat s'estén dins d'un sol bol."},"ICON-2822":{"nm":"Verat a la graella","de":"Una esquena platejada es va coent daurada sobre la graella. La mà que en treia les espines i posava la carn sobre l'arròs. En un sol tros de peix de dors blau hi ha impregnat un amor silenciós, el de qui va alimentar i criar així."},"ICON-2823":{"nm":"Coca de patata","de":"Allò que, els dies de pluja, es ratllava i es fregia en una cuina de muntanya de Gangwon. La vora sucosa i l'extrem cruixent conviuen l'un al costat de l'altre en una mateixa peça. La massa que millor s'avé amb el so de la pluja que repica al vidre."},"ICON-2824":{"nm":"Coca de kimchi","de":"En l'instant que el kimchi agre toca la paella untada d'oli, tota la casa s'omple d'un xiuxiueig cruixent. Un rodó daurat que convida per si sol a un bol de makgeolli. Un plat habitual que fa parella amb el so de la pluja sota la teulada."},"ICON-2825":{"nm":"Coca de ceballot","de":"Es posen els ceballots ben arrenglerats, s'hi vessa la massa i es fregeix a poc a poc. Una peça que oscil·la entre el cruixent i el tou. Exactament com aquella escena entranyable del vapor pujant d'una parada al dia de mercat."},"ICON-2826":{"nm":"Coca de carbassó","de":"El carbassó tallat fi es cobreix de massa i es fregeix fins a daurar-lo. Un cercle verd pàl·lid que custodiava, endreçat, un racó de la taula de rituals ancestrals. Aquesta mena de formalitat curosa que només s'aconsegueix amb moltes mans."},"ICON-2827":{"nm":"Calamar saltat picant","de":"Els tentacles vestits de condiment vermell brillen i lluen amb un vernís lluent. Encara que el picant faci perlejar el front de suor, els bastonets no poden parar. Aquell plat on la suor i el plaer s'entrellacen."},"ICON-2828":{"nm":"Tteokbokki","de":"Els pastissets d'arròs i les postes de peix s'enfonsen ben endins en un brou vermell reduït de gochujang. Hi ha tota sencera una tarda de botiga de menjar ràpid, compartida entre dos amb monedes estalviades. El gust del record que fa venir la saliva només de sentir-ne el nom."},"ICON-2829":{"nm":"Sopa de pastís de peix","de":"Una parada de carrer on els pastissos de peix oneja dins el brou, i el vapor entela de blanc el vidre. Agafant un broquet i recollint una mica de brou en un got de paper per fer-lo un glop, una nit d'hivern gèlida es torna molt més càlida."},"ICON-2830":{"nm":"Tofu amb kimchi saltat","de":"Al costat del tofu suau, s'asseu el kimchi saltat i picant. Fred i calent, suau i intens, es fonen en un sol plat. Una parella que ha vetllat durant molt de temps les nits dels adults."},"ICON-2831":{"nm":"Salsitxes amb verdures saltades","de":"Salsitxes vermelles i verdures es fonen xiuxiuejant en un to de ketchup. El compartiment que es buidava el primer quan s'obria la tapa de la carmanyola del dia d'esport. El color d'aquell dia continua sempre viu, per molt de temps que passi."},"ICON-2832":{"nm":"Latte de moniato","de":"Moniato ben triturat es desfà suaument en llet calenta. Una dolçor autòctona escrita en hangul a la carta. Un dia amb les puntes dels dits gelades, si l'agafeu amb totes dues mans, la calidesa s'escampa a poc a poc per tota la tassa."},"ICON-2833":{"nm":"Maionesa","de":"Una salsa que encara no ha arribat a la cuina de l'illa Espurna. Aviat es dibuixarà com una icona de color crema. (en preparació)"}};